	[TypeConverter("NinjaTrader.NinjaScript.Indicators.aiDuplicateAccountActionsConverter")]
	// HIDE_FROM_INDICATORS_LIST: uncomment the Browsable attribute below to hide this indicator
	// from NT8's Indicators dialog (users would then only be able to launch via
	// Control Center > New > Affordable Indicators > Accounts Dashboard). Left visible so
	// legacy users who add it to charts directly can still find it.
	//[System.ComponentModel.Browsable(false)]
	public class aiDuplicateAccountActions : Indicator
	{

		// --- Static instance registry for cross-window duplicate conflict detection ---
		// Each running instance registers its config here. Other instances check for conflicts.
		private static readonly object _registryLock = new object();
		private static readonly Dictionary<int, DashboardInstanceInfo> _instanceRegistry = new Dictionary<int, DashboardInstanceInfo>();
		private int _instanceId;
		private bool _isRegistered = false;
		private string _conflictMessage = string.Empty;
		private DateTime _lastConflictCheckTime = DateTime.MinValue;
		private bool _isExactDuplicate = false; // set by RegisterInstance when this is the newest exact-duplicate window
		private bool _hadConflict = false; // tracks previous conflict state so we can show "resolved" banner on transition
		private bool _wasBlockedByPeers = false; // true while we've been blocked from enabling by a peer that was ON; cleared with a "ready to enable" nudge once the peer disables
		private readonly List<int> _lastConflictPeerIds = new List<int>(); // peer instance IDs we conflicted with on the last RegisterInstance() call — used to tell if any of them are currently enabled
		private DateTime _lastEnableBlockTime = DateTime.MinValue; // timestamp of last failed enable attempt — a second click within OverrideWindowSeconds is interpreted as "override, turn off blocking peers and enable this"
		private const int OverrideWindowSeconds = 10; // how long the second-click-to-override window stays open
		private bool _pendingEnableAfterOverride = false; // set when user confirmed override; timer polls until blocking peers are actually off, then flips pCopierIsEnabled on

		// Cross-instance conflict notification: when a conflict is detected, ALL
		// conflicting instance IDs are added here so their timer tick auto-disables them.
		private static readonly HashSet<int> _conflictNotifications = new HashSet<int>();

		// Total open instance count — read by the AddOn for menu display
		public static int OpenInstanceCount { get { lock (_registryLock) { return _instanceRegistry.Count; } } }

		// ── Cross-indicator shared registry ─────────────────────────────
		// Published to AppDomain so other indicators (e.g. Enhanced Chart
		// Trader) can discover which ADA windows have a given account as
		// Master, which instruments each window applies to, read the
		// copier on/off state, and toggle it. Slots hold live getter
		// delegates — no polling cadence to tune, values are always fresh
		// because the closures capture `this`. Entries are removed in
		// UnregisterInstance (which is called from Terminated). Other
		// indicators must tolerate the registry being absent (ADA may
		// not be installed on a given user's setup).
		//   Slot layout (object[8]):
		//     [0] Func<string>          — master account name
		//     [1] Func<bool>            — copier enabled
		//     [2] Func<object, bool>    — IsInstrumentTracked(Instrument)
		//     [3] Action<bool>          — set copier enabled
		//     [4] Func<int>             — follower (duplicate) account count
		//     [5] Func<string>          — last toggle-blocker message (read+clear)
		//     [6] Func<bool>            — current cross-window conflict state
		//     [7] Func<string>          — last conflict-resolved message (read+clear)
		private const string CopierSharedRegistryKey = "aiADACopierRegistryV1";
		// Captures the most recent ADA-side message that blocked a toggle from
		// reaching its target state (e.g. conflict banner, master account not
		// connected). Slot [5] reads and clears. Exposed to ECT so it can show
		// the reason at the bottom of its own panel.
		private string _lastCopierBlockerMessage = string.Empty;
		// Parallel "conflict resolved" notification — surfaced via slot [7].
		// Populated from HandleConflictResult when the conflict flag transitions
		// true → false. Separate field from the blocker so ECT can display a
		// green "you can now enable copying" toast after the user fixes config.
		private string _lastCopierResolvedMessage = string.Empty;
		private static System.Collections.Concurrent.ConcurrentDictionary<int, object[]> GetCopierSharedRegistry()
		{
			var existing = AppDomain.CurrentDomain.GetData(CopierSharedRegistryKey)
				as System.Collections.Concurrent.ConcurrentDictionary<int, object[]>;
			if (existing != null) return existing;
			var created = new System.Collections.Concurrent.ConcurrentDictionary<int, object[]>();
			AppDomain.CurrentDomain.SetData(CopierSharedRegistryKey, created);
			// Re-read in case two instances raced — AppDomain data is last-write-wins
			// so the winner's dictionary is canonical and both should use it.
			return (AppDomain.CurrentDomain.GetData(CopierSharedRegistryKey)
				as System.Collections.Concurrent.ConcurrentDictionary<int, object[]>) ?? created;
		}
		private bool _copierSharedPublished = false;
		// Captured on ADA's own UI thread during publish — used from the setter
		// closure to marshal cross-thread calls from ECT back onto this ADA
		// instance's dispatcher. ChartControl.Dispatcher itself is thread-affine
		// (accessing the property from another thread throws), so we read it
		// once at publish time and store the raw Dispatcher reference.
		private System.Windows.Threading.Dispatcher _capturedDispatcher;
		private void PublishCopierSharedState()
		{
			if (_copierSharedPublished) return;
			try
			{
				if (_capturedDispatcher == null)
				{
					try { if (ChartControl != null) _capturedDispatcher = ChartControl.Dispatcher; } catch { }
					try { if (_capturedDispatcher == null) _capturedDispatcher = System.Windows.Threading.Dispatcher.CurrentDispatcher; } catch { }
				}
				var reg = GetCopierSharedRegistry();
				reg[_instanceId] = new object[]
				{
					(Func<string>)(() => pThisMasterAccount ?? string.Empty),
					(Func<bool>)(() => pCopierIsEnabled),
					(Func<object, bool>)(o => { var ii = o as Instrument; return ii != null && IsInstrumentTracked(ii); }),
					// Route through CopierMainButton() — the same code path ADA's
					// own toggle button uses. Ensures conflict-check, validation
					// messages, ResetMasterExecutionState, build-mode exit, and
					// diagnostic logging all fire. CopierMainButton is a toggle,
					// not a setter, so only call it when the state actually needs
					// to flip.
					(Action<bool>)(v =>
					{
						// The caller (ECT) invokes this on ITS OWN chart's UI dispatcher.
						// CopierMainButton + AddMessage touch WPF objects owned by THIS
						// indicator's chart dispatcher. Marshal via Invoke (blocking) so
						// _lastCopierBlockerMessage is populated before we return and the
						// caller can immediately read slot [5].
						Action doToggle = () =>
						{
							try
							{
								if (pCopierIsEnabled == v) return;

								int before = AllMessages != null ? AllMessages.Count : 0;
								bool wasEnabled = pCopierIsEnabled;

								CopierMainButton();

								int after = AllMessages != null ? AllMessages.Count : 0;

								// Case 1: toggle refused AND a brand-new message was added
								if (pCopierIsEnabled == wasEnabled && AllMessages != null && after > before)
								{
									try
									{
										var snap = AllMessages.ToArray();
										string msg = string.Empty;
										for (int k = snap.Length - 1; k >= before; k--)
										{
											if (snap[k] != null && !string.IsNullOrEmpty(snap[k].Name))
											{
												msg = snap[k].Name;
												break;
											}
										}
										_lastCopierBlockerMessage = msg ?? string.Empty;
									}
									catch { }
								}
								// Case 2: toggle refused, no new count — message was either
								// refreshed via AddMessage's dedupe path, or no message was
								// added (conflict banner already up from periodic check).
								else if (pCopierIsEnabled == wasEnabled && AllMessages != null)
								{
									string found = null;
									try
									{
										var snap = AllMessages.ToArray();
										DateTime cutoff = DateTime.Now.AddSeconds(-2);
										for (int k = snap.Length - 1; k >= 0; k--)
										{
											var mm = snap[k];
											if (mm == null || !mm.Switch || string.IsNullOrEmpty(mm.Name)) continue;
											if (mm.StartTime >= cutoff) { found = mm.Name; break; }
										}
									}
									catch { }

									if (!string.IsNullOrEmpty(found))
										_lastCopierBlockerMessage = found;
									else
									{
										string fb = _conflictMessage;
										if (string.IsNullOrEmpty(fb) && _hadConflict)
											fb = "Cross-window conflict — check Accounts Dashboard panel for details";
										if (string.IsNullOrEmpty(fb))
											fb = "Copier could not be enabled — check Accounts Dashboard panel for details";
										_lastCopierBlockerMessage = fb;
									}
								}
								// Rebuild the account-row performance table — without this,
								// ADA's next render uses its cached layout from before the
								// toggle and the visual appears "one frame behind". ADA's
								// own button click handler sets a local `RedoAccountsTable`
								// flag that triggers two GetAllPerformanceStats() calls
								// (line ~42072); we invoke the same function directly here
								// since the flag is a local inside another method.
								try { GetAllPerformanceStats(); } catch { }
								try { GetAllPerformanceStats(); } catch { }

								// Defensive — InvalidateVis touches ChartControl which may be
								// thread-affine to a different chart window. Swallow any access
								// exception; the 1s poll will still refresh the visuals.
								try { if (ChartControl != null) InvalidateVis(900); } catch { }
							}
							catch { }
						};

						try
						{
							// Use the dispatcher captured at publish time (on ADA's own
							// thread). Reading ChartControl.Dispatcher here would itself
							// throw the cross-thread exception. Invoke (blocking) so the
							// blocker message is ready in slot [5] when the caller reads it.
							var disp = _capturedDispatcher;
							if (disp != null && !disp.CheckAccess())
								disp.Invoke(doToggle);
							else
								doToggle();
						}
						catch { }
					}),
					(Func<int>)(() => AllDuplicateAccounts != null ? AllDuplicateAccounts.Count : 0),
					(Func<string>)(() =>
					{
						// Read-and-clear — subsequent reads return empty until the next
						// blocked toggle populates the field again.
						string s = _lastCopierBlockerMessage ?? string.Empty;
						_lastCopierBlockerMessage = string.Empty;
						return s;
					}),
					(Func<bool>)(() => _hadConflict),
					(Func<string>)(() =>
					{
						string s = _lastCopierResolvedMessage ?? string.Empty;
						_lastCopierResolvedMessage = string.Empty;
						return s;
					})
				};
				_copierSharedPublished = true;
			}
			catch { }
		}
		private void UnpublishCopierSharedState()
		{
			try
			{
				object[] removed;
				GetCopierSharedRegistry().TryRemove(_instanceId, out removed);
			}
			catch { }
			_copierSharedPublished = false;
		}
		// ── End cross-indicator shared registry ─────────────────────────

		// Version string — read by the AddOn to set the window caption before the indicator loads
		public static readonly string DashboardVersion = "26. 5. 25. 11";

		// ── WPF brush freezing helpers ────────────────────────────────
		// NT 8.1.x flags an "unfrozen brush" error when any indicator-exposed
		// Brush property holds a WPF brush whose .IsFrozen == false. Pattern
		// proven in aiEnhancedChartTrader.cs:
		//   - field-init brushes:  FrozenRgbBrush(r, g, b)
		//   - live setters:        set { pX = FreezeBrush(value); }
		//   - deserializer setters: set { pX = FreezeBrush(Serialize.StringToBrush(value)); }
		// Brushes.X built-ins are already frozen, no wrapping needed for those.
		private static System.Windows.Media.Brush FreezeBrush(System.Windows.Media.Brush b)
		{
			if (b != null && b.CanFreeze && !b.IsFrozen)
			{
				try { b.Freeze(); } catch { /* non-fatal — just return unfrozen */ }
			}
			return b;
		}

		private static System.Windows.Media.Brush FrozenRgbBrush(byte r, byte g, byte b)
		{
			var br = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromRgb(r, g, b));
			br.Freeze();
			return br;
		}

		// ── Diagnostic Logger ────────────────────────────────────────────
		// Always-on, buffered, file-based logger for troubleshooting.
		// Writes to NinjaTrader 8\Affordable Indicators\Accounts Dashboard\log\
		// One file per calendar day (diag_YYYY-MM-DD.txt), shared across every
		// ADS instance on the machine via FileShare.ReadWrite + FileMode.Append.
		// Each line carries an instance tag in column 2 so you can grep one
		// window's entries out of the combined stream.
		private DiagnosticLogger _diagLog;

		// Dedupe state — drops repeat values that NT8 emits on every price tick
		// (overnight margin/liquidation pings, unchanged position snapshots).
		private Dictionary<string, double> _diagLastAccountItemValue = new Dictionary<string, double>();
		private Dictionary<string, string> _diagLastPositionState = new Dictionary<string, string>();
		// Time-based dedupe for MESSAGE|SHOW. Many callers do RemoveMessage("X")
		// immediately followed by AddMessage("X", ...) every second or two
		// (e.g. periodic conflict re-check), which defeats any dedupe that
		// looks at AllMessages because the old entry is removed before we're
		// called. Remember the last-logged time per message text instead.
		private Dictionary<string, DateTime> _diagLastMessageLogTime = new Dictionary<string, DateTime>();
		private const int MsgLogDedupeWindowSec = 30; // only re-log a given message every 30s
		private Dictionary<string, string> _lastTopButtonRectLogged = new Dictionary<string, string>();
		// Dedupe ORDER|UPDATE — NT8 raises duplicate (Accepted/Working) callbacks
		// for the same OrderState. Key: OrderId|OrderState — only log a transition
		// the first time we see it.
		private Dictionary<string, byte> _diagLoggedOrderStates = new Dictionary<string, byte>();
		// Per-session set of (Account|Instrument) tuples that have already logged
		// a static SKIP reason (SameAsMaster, Disconnected). Each tuple logs once.
		private HashSet<string> _diagLoggedFollowerStaticSkip = new HashSet<string>();
		// Session-membership tracker for OnExecutionUpdate3. Replaces the prior
		// timezone-dependent staleness check, which compared e.Execution.Time
		// (broker-zone) against DateTime.UtcNow on the user's clock and broke
		// for any user whose OS zone didn't match the broker. Master-account
		// OrderIds observed transitioning through any post-Initialized state
		// in OnOrderUpdate3 are added here; OnExecutionUpdate3 only acts on
		// executions whose OrderId is in this set. Replays from feed reconnects
		// or workspace reloads carry IDs originated before the indicator armed,
		// so they are absent and the execution is rejected without any clock
		// comparison. Lock-protected; OnOrderUpdate / OnExecutionUpdate can
		// fire on different provider threads.
		private readonly HashSet<string> _sessionLiveOrderIds = new HashSet<string>();
		// Master "Close" orders produced by a Flatten All / goal-loss flatten.
		// An execution or order-copy of one of these is the master flattening
		// ITSELF, never a tradeable signal, and must be skipped for the order's
		// entire life. The fixed flatten-time window (pMilliSFE) misses partials
		// of a large/slow close, which were being copied to the already-flat
		// followers as a fresh opposite position (reversal — Michael Weprin
		// 2026-05-21). Reference-keyed; lock-protected (OnOrderUpdate3 adds on a
		// provider thread, the copy paths read on the drainer thread).
		private readonly HashSet<Order> _masterFlattenCloseOrders = new HashSet<Order>();
		// Timestamp captured each time the copier is armed (main-button toggle
		// or override-completed). Logged on SKIP_NOT_IN_SESSION so we can see
		// at a glance whether a rejected execution predates this session.
		private DateTime _copierArmedUtc = DateTime.MinValue;

		private sealed class DiagnosticLogger
		{
			// One calendar day = one file, shared across every ADS instance on the machine.
			// Filename: diag_YYYY-MM-DD.txt   (or diag_YYYY-MM-DD_N.txt after a 50MB runaway rollover)
			// Every instance opens the file with FileMode.Append + FileShare.ReadWrite so concurrent
			// dashboards can all append cleanly. The instance tag moves into each log line (column 2)
			// so `grep inst-XXXX` filters one window's entries out of the combined stream.
			// Pattern matches ECT's logger (aiEnhancedChartTrader.cs ~line 40729).

			private readonly string _logDir;
			private readonly string _instanceTag;   // e.g. "inst-12345678"
			private readonly object _lock = new object();
			private StreamWriter _writer;
			private string _currentFilePath;
			private DateTime _currentDate;
			private int _rollIndex;                 // 0 = base filename; increments only on 50MB safety-net rollover
			private const long MaxFileBytes = 50L * 1024 * 1024; // 50 MB — runaway-bug safety net, not normal rotation
			private const int MaxAgeDays = 30;
			private const int FlushEveryN = 40;
			private int _pendingCount;
			private bool _disposed;
			private bool _cleanedThisSession;

			public DiagnosticLogger(string logDir, string instanceTag)
			{
				_instanceTag = string.IsNullOrEmpty(instanceTag) ? "inst-unknown" : instanceTag;
				_logDir = logDir;
				try
				{
					if (!Directory.Exists(_logDir))
						Directory.CreateDirectory(_logDir);
				}
				catch { }
			}

			/// <summary>
			/// Primary logging method. Line format:
			///   YYYY-MM-DD HH:MM:SS.fff|instanceTag|category|action|details
			/// </summary>
			public void Log(string category, string action, string details)
			{
				if (_disposed) return;
				try
				{
					string line = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss.fff")
						+ "|" + _instanceTag
						+ "|" + category
						+ "|" + action
						+ "|" + details;

					lock (_lock)
					{
						EnsureWriter();
						if (_writer == null) return;
						_writer.WriteLine(line);
						_pendingCount++;
						if (_pendingCount >= FlushEveryN)
						{
							_writer.Flush();
							_pendingCount = 0;
							// After flushing, probe the real on-disk size. With multiple concurrent
							// writers, our own counter is unreliable — only the shared file size is.
							CheckSafetyNetRollover();
						}
					}
				}
				catch { }
			}

			public void Flush()
			{
				if (_disposed) return;
				try
				{
					lock (_lock)
					{
						if (_writer != null)
						{
							_writer.Flush();
							_pendingCount = 0;
							CheckSafetyNetRollover();
						}
					}
				}
				catch { }
			}

			public void Dispose()
			{
				if (_disposed) return;
				_disposed = true;
				try
				{
					lock (_lock)
					{
						if (_writer != null)
						{
							try { _writer.Flush(); } catch { }
							try { _writer.Close(); } catch { }
							_writer = null;
						}
					}
				}
				catch { }
			}

			public string LogDirectory { get { return _logDir; } }

			// Base filename for today (no roll index). If a rollover has already occurred today,
			// the live file is diag_YYYY-MM-DD_N.txt; we detect that in EnsureWriter by scanning.
			private string BaseFileName(DateTime d)  { return "diag_" + d.ToString("yyyy-MM-dd") + ".txt"; }
			private string RolledFileName(DateTime d, int n) { return "diag_" + d.ToString("yyyy-MM-dd") + "_" + n + ".txt"; }

			private void EnsureWriter()
			{
				DateTime today = DateTime.Now.Date;

				if (_writer != null && _currentDate == today)
				{
					// Same-day, same handle: still verify the file we hold is the current live one.
					// Another instance may have rotated under us — in which case our handle points
					// at a now-archived file. Detect by comparing _currentFilePath to the expected
					// live path for today.
					string expected = GetLiveFilePath(today);
					if (expected == _currentFilePath)
						return;
					// Live file changed — close and reopen against the new one.
					try { _writer.Flush(); } catch { }
					try { _writer.Close(); } catch { }
					_writer = null;
				}

				// Day rolled over, or first open this session.
				if (_writer != null)
				{
					try { _writer.Flush(); } catch { }
					try { _writer.Close(); } catch { }
					_writer = null;
				}
				_currentDate = today;
				_rollIndex = 0;

				string livePath = GetLiveFilePath(today);
				OpenWriter(livePath);
				CleanOldLogsOnce();
			}

			// The "live" file is diag_YYYY-MM-DD.txt UNLESS a previous runaway rollover already
			// renamed it aside, in which case it's diag_YYYY-MM-DD_N+1.txt where N is the highest
			// suffix currently on disk. After rollover the base filename always re-appears (we
			// recreate it), so under normal operation this just returns the base name.
			private string GetLiveFilePath(DateTime d)
			{
				string basePath = Path.Combine(_logDir, BaseFileName(d));
				if (File.Exists(basePath))
				{
					_rollIndex = 0;
					return basePath;
				}
				// Base is missing — either we haven't written today yet (fine, we'll create it),
				// or a rotation happened and the winner is about to recreate it. Scan for the
				// highest roll suffix so we know where we stand.
				int maxSuffix = 0;
				try
				{
					string prefix = "diag_" + d.ToString("yyyy-MM-dd") + "_";
					foreach (string f in Directory.GetFiles(_logDir, prefix + "*.txt"))
					{
						string name = Path.GetFileNameWithoutExtension(f);
						int under = name.LastIndexOf('_');
						if (under <= 0) continue;
						int n;
						if (int.TryParse(name.Substring(under + 1), out n) && n > maxSuffix)
							maxSuffix = n;
					}
				}
				catch { }
				_rollIndex = maxSuffix;
				return basePath; // still target the base name — we'll create it fresh
			}

			private void OpenWriter(string path)
			{
				try
				{
					bool fileExistedBefore = File.Exists(path);
					_currentFilePath = path;
					// FileMode.Append + FileShare.ReadWrite matches ECT's logger — lets every
					// ADS instance on the machine append to the same file concurrently.
					var fs = new FileStream(path, FileMode.Append, FileAccess.Write, FileShare.ReadWrite);
					_writer = new StreamWriter(fs, Encoding.UTF8);
					_writer.AutoFlush = false;
					if (!fileExistedBefore)
					{
						_writer.WriteLine("# Accounts Dashboard Diagnostic Log — " + DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss"));
						_writer.WriteLine("# Format: Timestamp|InstanceTag|Category|Action|Details");
						_writer.WriteLine("# ──────────────────────────────────────────");
					}
				}
				catch { _writer = null; }
			}

			// Called only after a flush, so the on-disk size reflects all buffered data from us.
			// If the live file has crossed 50MB (across ALL writers combined), try to acquire the
			// global rotation mutex and rename the file aside. The first instance to win renames
			// and recreates; other instances will notice the rename on their next flush via the
			// _currentFilePath mismatch check in EnsureWriter and reopen against the fresh file.
			private void CheckSafetyNetRollover()
			{
				if (_writer == null || _currentFilePath == null) return;
				long size;
				try { size = new FileInfo(_currentFilePath).Length; }
				catch { return; }
				if (size < MaxFileBytes) return;

				string mutexName = "Global\\ADSLogRotate_" + _currentDate.ToString("yyyy-MM-dd");
				System.Threading.Mutex mtx = null;
				bool owned = false;
				try
				{
					mtx = new System.Threading.Mutex(false, mutexName);
					try { owned = mtx.WaitOne(250); } catch (System.Threading.AbandonedMutexException) { owned = true; }
					if (!owned) return; // another instance is handling it — we'll pick up the new file on our next write

					// Re-check after acquiring: winner may have already rotated between our first size check and now.
					long sizeAfter;
					try { sizeAfter = new FileInfo(_currentFilePath).Length; }
					catch { return; }
					if (sizeAfter < MaxFileBytes) return;

					// Close our handle so the rename can proceed on Windows.
					try { _writer.Flush(); } catch { }
					try { _writer.Close(); } catch { }
					_writer = null;

					// Find next available suffix and rename the oversized base file aside.
					string basePath = Path.Combine(_logDir, BaseFileName(_currentDate));
					if (File.Exists(basePath))
					{
						int n = 1;
						while (true)
						{
							string candidate = Path.Combine(_logDir, RolledFileName(_currentDate, n));
							if (!File.Exists(candidate))
							{
								try { File.Move(basePath, candidate); } catch { }
								break;
							}
							n++;
							if (n > 9999) break; // safety
						}
					}

					// Reopen against the (now-missing) base path; OpenWriter creates it fresh with header.
					_rollIndex = 0;
					OpenWriter(basePath);
				}
				catch { }
				finally
				{
					if (mtx != null)
					{
						try { if (owned) mtx.ReleaseMutex(); } catch { }
						try { mtx.Dispose(); } catch { }
					}
				}
			}

			private void CleanOldLogsOnce()
			{
				if (_cleanedThisSession) return;
				_cleanedThisSession = true;
				try
				{
					DateTime cutoff = DateTime.Now.AddDays(-MaxAgeDays);
					// "diag_*.txt" matches both the new one-per-day scheme AND any legacy
					// per-instance files (diag_YYYY-MM-DD_inst-XXX_N.txt) left over from
					// earlier versions. Files older than 30 days are purged regardless of schema.
					string[] files = Directory.GetFiles(_logDir, "diag_*.txt");
					foreach (string f in files)
					{
						try
						{
							if (File.GetLastWriteTime(f) < cutoff)
								File.Delete(f);
						}
						catch { }
					}
				}
				catch { }
			}
		}
		// ── End DiagnosticLogger ─────────────────────────────────────────

		internal class DashboardInstanceInfo
		{
			public string MasterAccount;
			public List<string> FollowerAccounts;
			public bool AllInstruments;
			public string SpecificInstrument;
			public int InstanceId;
			public DateTime RegisteredAt;
			public bool IsCopierEnabled; // live copier state — used to decide whether a conflict is "active" (both sides on) or latent (dormant while edit-only)
			public bool DisableRequested; // set by another window when the user has chosen to override; this window's next timer tick will read the flag, turn its copier off, and clear the flag
		}

		/// <summary>
		/// Registers or updates this instance in the static registry.
		/// Returns a conflict message if a duplicate config is detected, or empty string if clean.
		/// When a conflict is found, ALL conflicting instances are flagged via _conflictNotifications
		/// so they auto-disable on their next timer tick.
		///
		/// Checks three conflict types:
		///   1. Master-as-Follower: this window's Master is a Follower in another window (or vice versa)
		///   2. Duplicate config: same Master + overlapping Followers + overlapping instruments
		///   3. (Both can be detected in the same pass)
		/// </summary>
		private string RegisterInstance()
		{
			lock (_registryLock)
			{
				// Preserve original registration time if already registered
				DateTime regTime = DateTime.UtcNow;
				DashboardInstanceInfo existing;
				if (_instanceRegistry.TryGetValue(_instanceId, out existing))
					regTime = existing.RegisteredAt;

				// Source of truth for followers: read directly from pAllAccountData (NT's persisted
				// property, always populated by deserialization before DataLoaded runs). Early in
				// DataLoaded, AllDuplicateAccounts may not yet reflect the Slave entries because the
				// populate path (SetAccountData name="") runs inside a conditional that doesn't
				// always fire on reload. Falling back to the persisted data prevents the "conflict
				// not detected until Reload NinjaScript" issue — that bug was caused by the first
				// RegisterInstance call on startup creating a registry entry with zero followers,
				// so peers scanning for overlap found nothing.
				List<string> followers;
				if (AllDuplicateAccounts != null && AllDuplicateAccounts.Count > 0)
				{
					followers = new List<string>(AllDuplicateAccounts);
				}
				else if (pAllAccountData != null)
				{
					followers = new List<string>();
					for (int i = 0; i < pAllAccountData.Length; i++)
					{
						string s = pAllAccountData[i];
						if (string.IsNullOrEmpty(s)) continue;
						// Format: "accountname|status|multiplier|crossover|fade|hide|..."
						// A follower has status "Slave" in slot [2] (checked via Contains in existing code).
						if (s.Contains("Slave"))
						{
							int pipe = s.IndexOf('|');
							if (pipe > 0) followers.Add(s.Substring(0, pipe));
						}
					}
				}
				else
				{
					followers = new List<string>();
				}

				DashboardInstanceInfo myInfo = new DashboardInstanceInfo
				{
					MasterAccount = pThisMasterAccount ?? string.Empty,
					FollowerAccounts = followers,
					AllInstruments = (pInstrumentMode == "All"),
					SpecificInstrument = (pInstrumentMode == "All") ? "" : (pInstrumentMode == "Single" ? pSingleInstrument : pSelectedInstrumentList),
					InstanceId = _instanceId,
					RegisteredAt = regTime,
					IsCopierEnabled = pCopierIsEnabled
				};

				_instanceRegistry[_instanceId] = myInfo;
				_isRegistered = true;
				_lastConflictPeerIds.Clear(); // reset — populated below by each conflict pass

				// Publish to cross-indicator shared registry (idempotent;
				// subsequent calls are no-ops since closures read live state).
				PublishCopierSharedState();

				// Refresh every peer's cached IsCopierEnabled from live state via the shared
				// registry closure. This fixes cases where a peer's Publish was missed or
				// delivered late — the cached flag in DashboardInstanceInfo could be stale
				// for minutes, masking real conflicts. Now every conflict scan sees live truth.
				var sharedForRefresh = GetCopierSharedRegistry();
				if (sharedForRefresh != null)
				{
					foreach (var kvp in _instanceRegistry)
					{
						if (kvp.Key == _instanceId) continue;
						object[] slots;
						if (sharedForRefresh.TryGetValue(kvp.Key, out slots) && slots != null && slots.Length > 1)
						{
							var liveEnabled = slots[1] as Func<bool>;
							if (liveEnabled != null)
							{
								try { kvp.Value.IsCopierEnabled = liveEnabled(); } catch { }
							}
						}
					}
				}

				if (myInfo.MasterAccount == string.Empty)
					return string.Empty;

				_isExactDuplicate = false;

				// --- Pass 0: Exact-duplicate window detection ---
				// When another window has the exact same Master AND exact same Follower set,
				// this is a duplicated window. Only the NEWEST window gets flagged — its
				// master and followers will be cleared by the caller.
				if (myInfo.FollowerAccounts.Count > 0)
				{
					foreach (var kvp in _instanceRegistry)
					{
						if (kvp.Key == _instanceId)
							continue;

						DashboardInstanceInfo other = kvp.Value;

						if (other.MasterAccount != myInfo.MasterAccount)
							continue;

						// Check exact follower match (same count, same members)
						if (other.FollowerAccounts.Count != myInfo.FollowerAccounts.Count)
							continue;
						bool allMatch = true;
						foreach (string f in myInfo.FollowerAccounts)
						{
							if (!other.FollowerAccounts.Contains(f))
							{ allMatch = false; break; }
						}
						if (!allMatch)
							continue;

						// Exact duplicate found — flag the NEWEST window (this one if newer)
						if (myInfo.RegisteredAt >= other.RegisteredAt)
						{
							_isExactDuplicate = true;
							int totalWindows = 1;
							foreach (var kvp2 in _instanceRegistry)
							{
								if (kvp2.Key == _instanceId) continue;
								if (kvp2.Value.MasterAccount == myInfo.MasterAccount
									&& kvp2.Value.FollowerAccounts.Count == myInfo.FollowerAccounts.Count)
								{
									bool match2 = true;
									foreach (string f in myInfo.FollowerAccounts)
										if (!kvp2.Value.FollowerAccounts.Contains(f)) { match2 = false; break; }
									if (match2)
									{
										totalWindows++;
										if (!_lastConflictPeerIds.Contains(kvp2.Key))
											_lastConflictPeerIds.Add(kvp2.Key);
									}
								}
							}
							totalWindows++; // include self

							string followerSummary;
							if (myInfo.FollowerAccounts.Count <= 5)
								followerSummary = string.Join(", ", myInfo.FollowerAccounts);
							else
								followerSummary = string.Join(", ", myInfo.FollowerAccounts.GetRange(0, 5))
									+ " (+" + (myInfo.FollowerAccounts.Count - 5) + " more)";

							return "DUPLICATE WINDOW DETECTED (" + totalWindows + " windows with identical config): "
								+ "Master: " + myInfo.MasterAccount + ", "
								+ myInfo.FollowerAccounts.Count + " Follower(s): " + followerSummary + ". "
								+ "This window's Master and Follower accounts have been cleared to prevent duplicate orders. "
								+ "To resolve: configure this window with a different Master or different Follower accounts, then re-enable.";
						}
					}
				}

				// --- Pass 1: Master-as-Follower check ---
				// My Master must not be a Follower anywhere, and my Followers must not be a Master anywhere.
				List<int> masterFollowerConflictIds = new List<int>();
				List<string> masterAsFollowerDetails = new List<string>();

				foreach (var kvp in _instanceRegistry)
				{
					if (kvp.Key == _instanceId)
						continue;

					DashboardInstanceInfo other = kvp.Value;

					// My Master is their Follower?
					if (other.FollowerAccounts.Contains(myInfo.MasterAccount))
					{
						if (!masterFollowerConflictIds.Contains(kvp.Key))
							masterFollowerConflictIds.Add(kvp.Key);
						masterAsFollowerDetails.Add("'" + myInfo.MasterAccount + "' is Master here but Follower in another window");
					}

					// Their Master is my Follower?
					if (!string.IsNullOrEmpty(other.MasterAccount) && myInfo.FollowerAccounts.Contains(other.MasterAccount))
					{
						if (!masterFollowerConflictIds.Contains(kvp.Key))
							masterFollowerConflictIds.Add(kvp.Key);
						masterAsFollowerDetails.Add("'" + other.MasterAccount + "' is Master in another window but Follower here");
					}
				}

				if (masterFollowerConflictIds.Count > 0)
				{
					foreach (int cid in masterFollowerConflictIds)
					{
						_conflictNotifications.Add(cid);
						if (!_lastConflictPeerIds.Contains(cid)) _lastConflictPeerIds.Add(cid);
					}

					int totalWindows = masterFollowerConflictIds.Count + 1;
					string detail = masterAsFollowerDetails.Count <= 2
						? string.Join("; ", masterAsFollowerDetails)
						: string.Join("; ", masterAsFollowerDetails.GetRange(0, 2)) + " (+" + (masterAsFollowerDetails.Count - 2) + " more)";

					return "CONFLICT (" + totalWindows + " windows affected): An account is configured as both Master and Follower across windows. "
						+ detail + ". "
						+ "All copiers have been disabled. "
						+ "To resolve: (1) Ensure no account is set as Master in one window and Follower in another. "
						+ "(2) Re-enable each copier after fixing the configuration.";
				}

				// --- Pass 2: Duplicate config check (same Master + overlapping Followers + overlapping instruments) ---
				List<int> dupeConflictIds = new List<int>();
				List<string> allOverlappingFollowers = new List<string>();
				string overlappingInstruments = null;

				foreach (var kvp in _instanceRegistry)
				{
					if (kvp.Key == _instanceId)
						continue;

					DashboardInstanceInfo other = kvp.Value;

					if (other.MasterAccount != myInfo.MasterAccount)
						continue;

					// Collect ALL overlapping followers (not just first)
					List<string> theseOverlapping = new List<string>();
					foreach (string f in myInfo.FollowerAccounts)
					{
						if (other.FollowerAccounts.Contains(f))
							theseOverlapping.Add(f);
					}
					if (theseOverlapping.Count == 0)
						continue;

					// Check instrument overlap (handles partial overlap for Selected mode)
					bool hasInstrumentConflict = false;
					string theseInstruments = null;
					if (myInfo.AllInstruments || other.AllInstruments)
					{
						hasInstrumentConflict = true;
						theseInstruments = "All Instruments";
					}
					else if (!string.IsNullOrEmpty(myInfo.SpecificInstrument) && !string.IsNullOrEmpty(other.SpecificInstrument))
					{
						string[] myInstruments = myInfo.SpecificInstrument.Split(new char[] { ';' }, StringSplitOptions.RemoveEmptyEntries);
						string[] otherInstruments = other.SpecificInstrument.Split(new char[] { ';' }, StringSplitOptions.RemoveEmptyEntries);
						List<string> shared = new List<string>();
						foreach (string inst in myInstruments)
						{
							foreach (string otherInst in otherInstruments)
							{
								if (inst.Trim() == otherInst.Trim())
								{
									// Store base name only (e.g. "ES" not "ES 06-26")
									string baseName = inst.Trim();
									int sp = baseName.IndexOf(' ');
									if (sp > 0) baseName = baseName.Substring(0, sp);
									if (!shared.Contains(baseName))
										shared.Add(baseName);
									break;
								}
							}
						}
						if (shared.Count > 0)
						{
							hasInstrumentConflict = true;
							theseInstruments = string.Join(", ", shared);
						}
					}

					if (hasInstrumentConflict)
					{
						if (!dupeConflictIds.Contains(kvp.Key))
							dupeConflictIds.Add(kvp.Key);
						foreach (string f in theseOverlapping)
						{
							if (!allOverlappingFollowers.Contains(f))
								allOverlappingFollowers.Add(f);
						}
						if (overlappingInstruments == null)
							overlappingInstruments = theseInstruments;
					}
				}

				if (dupeConflictIds.Count > 0)
				{
					foreach (int cid in dupeConflictIds)
					{
						_conflictNotifications.Add(cid);
						if (!_lastConflictPeerIds.Contains(cid)) _lastConflictPeerIds.Add(cid);
					}

					int totalWindows = dupeConflictIds.Count + 1;

					// Follower summary: show up to 5 names, then count remainder
					string followerSummary;
					if (allOverlappingFollowers.Count <= 5)
						followerSummary = string.Join(", ", allOverlappingFollowers);
					else
						followerSummary = string.Join(", ", allOverlappingFollowers.GetRange(0, 5))
							+ " (+" + (allOverlappingFollowers.Count - 5) + " more)";

					string followerCountPrefix = allOverlappingFollowers.Count == 1
						? "1 overlapping Follower: " : allOverlappingFollowers.Count + " overlapping Followers: ";

					return "CONFLICT (" + totalWindows + " windows affected): Duplicate configuration detected. "
						+ "Master: " + myInfo.MasterAccount + ". "
						+ followerCountPrefix + followerSummary + ". "
						+ "Instrument(s): " + overlappingInstruments + ". "
						+ "All copiers have been disabled. "
						+ "To resolve: (1) Remove the duplicate Follower accounts from one window, or change the instrument scope so they don't overlap. "
						+ "(2) Re-enable each copier after fixing the configuration.";
				}
			}
			return string.Empty;
		}

		private void UnregisterInstance()
		{
			lock (_registryLock)
			{
				_instanceRegistry.Remove(_instanceId);
				_conflictNotifications.Remove(_instanceId);
				_isRegistered = false;
			}
			UnpublishCopierSharedState();
		}

		// Copies the NinjaTrader Machine ID to the clipboard. Must run on the UI (STA)
		// thread — Clipboard APIs throw on worker threads. Call site may be any thread.
		private void CopyMachineIdToClipboard()
		{
			try
			{
				string id = NinjaTrader.Cbi.License.MachineId ?? "";
				if (string.IsNullOrEmpty(id)) return;

				var dispatcher = System.Windows.Application.Current != null
					? System.Windows.Application.Current.Dispatcher : null;
				if (dispatcher == null) return;

				if (dispatcher.CheckAccess())
					System.Windows.Clipboard.SetText(id);
				else
					dispatcher.BeginInvoke(new Action(() =>
					{
						try { System.Windows.Clipboard.SetText(id); } catch { }
					}));
			}
			catch { }
		}

		// Force the conflict detection timer to rescan on the next tick (bypasses 5-sec throttle)
		// and ping every other instance so they also rescan. Call after any change to this
		// window's Master / Followers / Instrument scope so conflicts surface — and clear — immediately
		// rather than waiting up to 5 seconds for the periodic tick.
		private void ForceConflictRecheck()
		{
			_lastConflictCheckTime = DateTime.MinValue;
			lock (_registryLock)
			{
				foreach (var kvp in _instanceRegistry)
				{
					if (kvp.Key == _instanceId) continue;
					_conflictNotifications.Add(kvp.Key);
				}
			}
		}

		// Returns true if any peer we conflicted with on the last RegisterInstance() call is currently
		// running with its copier enabled. This is the "is the conflict actually ACTIVE" test — while
		// all involved peers sit with their copier OFF, no duplicate-order risk exists yet, so we stay
		// silent (no banner, no auto-disable). The moment a peer is enabled (or we try to enable while
		// a peer already is), the conflict becomes active and we act.
		//
		// Reads LIVE state via the cross-indicator shared registry's Func<bool> closure first — that
		// reads the peer's real pCopierIsEnabled directly, bypassing the cached IsCopierEnabled flag
		// on DashboardInstanceInfo that can go stale if a Publish was missed. Falls back to the
		// cached flag when the shared-registry closure isn't available.
		private bool IsAnyConflictingPeerEnabled()
		{
			var shared = GetCopierSharedRegistry();
			lock (_registryLock)
			{
				for (int i = 0; i < _lastConflictPeerIds.Count; i++)
				{
					int pid = _lastConflictPeerIds[i];
					// Prefer live state from shared registry
					object[] slots;
					if (shared != null && shared.TryGetValue(pid, out slots) && slots != null && slots.Length > 1)
					{
						var liveEnabled = slots[1] as Func<bool>;
						if (liveEnabled != null)
						{
							try { if (liveEnabled()) return true; } catch { }
							continue; // we trust the live reading; skip cache
						}
					}
					// Fallback: cached flag in DashboardInstanceInfo
					DashboardInstanceInfo peer;
					if (_instanceRegistry.TryGetValue(pid, out peer) && peer.IsCopierEnabled)
						return true;
				}
			}
			return false;
		}

		// Builds a user-facing message naming the ENABLED peer window(s) currently blocking this
		// window from enabling. Lists each peer's master and follower summary so the user can
		// identify which window to turn off — or which config to change here. Message is IDENTICAL
		// whether produced by the enable-click path or the timer refresh path, so AddMessage dedupes
		// instead of flashing between two different banners. The triedToEnable flag is accepted for
		// caller-site readability only.
		private string BuildBlockedByPeersMessage(bool triedToEnable)
		{
			List<string> peerLines = new List<string>();
			lock (_registryLock)
			{
				for (int i = 0; i < _lastConflictPeerIds.Count; i++)
				{
					DashboardInstanceInfo peer;
					if (!_instanceRegistry.TryGetValue(_lastConflictPeerIds[i], out peer)) continue;
					if (!peer.IsCopierEnabled) continue;

					string fSummary;
					if (peer.FollowerAccounts == null || peer.FollowerAccounts.Count == 0)
						fSummary = "no Followers";
					else if (peer.FollowerAccounts.Count <= 4)
						fSummary = string.Join(", ", peer.FollowerAccounts);
					else
						fSummary = string.Join(", ", peer.FollowerAccounts.GetRange(0, 4))
							+ " (+" + (peer.FollowerAccounts.Count - 4) + " more)";

					peerLines.Add("Master '" + (string.IsNullOrEmpty(peer.MasterAccount) ? "(none)" : peer.MasterAccount)
						+ "' with " + (peer.FollowerAccounts != null ? peer.FollowerAccounts.Count : 0) + " Follower(s): " + fSummary);
				}
			}

			string list = peerLines.Count == 0
				? "(unable to identify blocking window)"
				: (peerLines.Count == 1 ? "Blocking window: " : "Blocking windows: ") + string.Join("; ", peerLines);

			return "CONFLICT — this window cannot be enabled while another Dashboard window is ON with an overlapping configuration. "
				+ list + ". "
				+ "To continue: (1) Turn OFF the blocking window, or (2) change this window's Master / Followers / Instrument scope so they no longer overlap. "
				+ "[OVERRIDE] Click this window's ON/OFF button twice in quick succession (second click within " + OverrideWindowSeconds + " seconds of the first) to FORCE turn off the blocking window(s) and enable this one. "
				+ "A 'Ready to enable' nudge will appear here as soon as the conflict clears on its own.";
		}

		// Updates this instance's registry entry with the current pCopierIsEnabled state and pings
		// every peer so they can re-evaluate their blocked/active status. Call whenever
		// pCopierIsEnabled flips so peers see the change immediately (instead of waiting up to 5s).
		//
		// Self-heals: if our registry entry is missing (e.g. UnregisterInstance ran, or this is the
		// first publish before any RegisterInstance), falls back to a full RegisterInstance so the
		// entry is guaranteed present with correct IsCopierEnabled. Without this, a missing entry
		// meant peers couldn't see we were ON, and they'd enable without blocking — a race the user
		// observed as "conflict not detected until I Reload NinjaScript".
		private void PublishEnabledStateAndPingPeers()
		{
			bool entryExists;
			lock (_registryLock)
			{
				DashboardInstanceInfo existing;
				entryExists = _instanceRegistry.TryGetValue(_instanceId, out existing);
				if (entryExists)
					existing.IsCopierEnabled = pCopierIsEnabled;

				foreach (var kvp in _instanceRegistry)
				{
					if (kvp.Key == _instanceId) continue;
					_conflictNotifications.Add(kvp.Key);
				}
			}
			if (!entryExists)
				RegisterInstance(); // full registration as a safety net
		}

		// Rebuilds the account-row performance table so the visible rows reflect the new copier
		// state — specifically, enabling the copier should immediately hide accounts that aren't
		// configured as Master/Follower. The button click handler in the render loop does this via
		// a local `RedoAccountsTable` flag, but state changes driven from OnTimerTick3 (override
		// completion, peer-forced disable) don't go through that flag. Calling this helper from
		// those paths keeps the UI in sync. Mirrors the pattern at line ~43055.
		private void RebuildAccountsTableAfterStateChange()
		{
			AdjustmentRows = 0;
			try { GetAllPerformanceStats(); } catch { }
			try { GetAllPerformanceStats(); } catch { }
			try { if (ChartControl != null) InvalidateVis(901); } catch { }
		}

		// Marks every conflicting peer for shutdown. Each peer's OnTimerTick3 polls its own
		// DisableRequested flag and disables itself on the next tick (skipping the action if the
		// peer happens to already be off). Previously we only flagged peers whose registry entry
		// reported IsCopierEnabled=true, but that made override brittle — a stale/missed Publish
		// would silently skip a peer that was actually running. Now we flag every peer whose config
		// overlaps with ours; harmless if the peer is already off, essential if the cache is stale.
		// Returns the number of peers scheduled to disable.
		private int RequestPeerDisable()
		{
			int scheduled = 0;
			int stillEnabled = 0;
			lock (_registryLock)
			{
				for (int i = 0; i < _lastConflictPeerIds.Count; i++)
				{
					DashboardInstanceInfo peer;
					if (!_instanceRegistry.TryGetValue(_lastConflictPeerIds[i], out peer)) continue;
					if (peer.IsCopierEnabled) stillEnabled++;
					if (peer.DisableRequested) continue;
					peer.DisableRequested = true;
					_conflictNotifications.Add(peer.InstanceId); // wake the peer so it sees the flag immediately
					scheduled++;
				}
			}
			if (_diagLog != null)
				_diagLog.Log("UI", "REQUEST_PEER_DISABLE", "PeerIds=" + _lastConflictPeerIds.Count + "|Scheduled=" + scheduled + "|StillEnabled=" + stillEnabled);
			return scheduled;
		}

		// Processes the return value of RegisterInstance() from timer / startup paths.
		// Semantics:
		//   - Latent conflict (config overlap but no involved window is enabled): stay silent. No
		//     banner, no auto-disable. The user may be editing; duplicate orders aren't possible
		//     while both sides are OFF.
		//   - Active conflict with THIS window ON (a peer is also ON or we became a duplicate at
		//     workspace restore): auto-disable THIS window and show the "blocked by peers" banner.
		//   - Refresh case: we were previously blocked by an enabled peer and still are — re-show
		//     the banner in case peer config changed.
		//   - Transition blocked → clear (peer turned off or config resolved): show the LimeGreen
		//     "Ready to enable" nudge for 10 sec.
		//   - Transition self-disabled-due-to-conflict → clear: show "Window conflict resolved".
		private void HandleConflictResult(string conflictMsg, string diagReasonOnDisable)
		{
			bool hasConfigConflict = !string.IsNullOrEmpty(conflictMsg);
			bool peerEnabled = hasConfigConflict && IsAnyConflictingPeerEnabled();
			bool bothOn = hasConfigConflict && pCopierIsEnabled && peerEnabled;

			bool wasConflict = _hadConflict;
			bool wasBlocked = _wasBlockedByPeers;

			if (bothOn)
			{
				// Both sides actually running — only state where duplicate orders can fire. Disable
				// THIS window (newest wins the disable on exact-duplicate rule inside RegisterInstance).
				// Don't clear user config unless it's a true exact duplicate.
				if (_isExactDuplicate)
				{
					DisableMasterAccount();
					DisableFollowerAccounts();
					RegisterInstance();
				}
				else
				{
					pCopierIsEnabled = false;
					if (!string.IsNullOrEmpty(diagReasonOnDisable) && _diagLog != null)
						_diagLog.Log("UI", "COPIER_DISABLED", "Reason=" + diagReasonOnDisable);
					ResetMasterExecutionState();
				}
				_wasBlockedByPeers = true;
				PublishEnabledStateAndPingPeers();
				string msg = BuildBlockedByPeersMessage(false);
				RemoveMessage("CONFLICT");
				RemoveMessage("DUPLICATE WINDOW");
				RemoveMessage("Window conflict resolved");
				RemoveMessage("Ready to enable");
				AddMessage(msg, 60, Brushes.Goldenrod);
				_lastCopierBlockerMessage = msg;
				_hadConflict = true;
				InvalidateVis(99);
			}
			else if (peerEnabled && wasBlocked)
			{
				// We're off, peer still on, we'd been blocked previously — keep banner fresh
				// (peer's config may have changed; re-render names).
				string msg = BuildBlockedByPeersMessage(false);
				RemoveMessage("CONFLICT");
				RemoveMessage("DUPLICATE WINDOW");
				RemoveMessage("Window conflict resolved");
				RemoveMessage("Ready to enable");
				AddMessage(msg, 60, Brushes.Goldenrod);
				_lastCopierBlockerMessage = msg;
				_hadConflict = true;
				InvalidateVis(99);
			}
			else
			{
				// Not both-on and not currently blocked-by-peer-still-on. Three sub-cases:
				_hadConflict = false;

				if (wasBlocked)
				{
					// Peer that was blocking us has turned off (or config resolved) — nudge user.
					_wasBlockedByPeers = false;
					RemoveMessage("CONFLICT");
					RemoveMessage("DUPLICATE WINDOW");
					AddMessage("Ready to enable — the window conflict has cleared. You can enable this window now.", 10, Brushes.LimeGreen);
					string master = pThisMasterAccount ?? string.Empty;
					if (!string.IsNullOrEmpty(master))
						_lastCopierResolvedMessage = "Window conflict resolved for '" + master + "' — trade copying can now be enabled";
					InvalidateVis(99);
				}
				else if (wasConflict)
				{
					// Was actively showing a conflict (both-on case) and it's now resolved.
					RemoveMessage("CONFLICT");
					RemoveMessage("DUPLICATE WINDOW");
					AddMessage("Window conflict resolved", 10, Brushes.LimeGreen);
					string master = pThisMasterAccount ?? string.Empty;
					if (!string.IsNullOrEmpty(master))
						_lastCopierResolvedMessage = "Window conflict resolved for '" + master + "' — trade copying can now be enabled";
					InvalidateVis(99);
				}
				// else: everything's quiet — nothing to show, nothing to clear.
			}
		}


