	private string ProcessDoubleNumber(double sssss)
	{
	    if (sssss == DefaultForZero || sssss == 0)
	        return "";

	    // Check if whole number
	    if (sssss % 1 == 0)
	        return sssss.ToString("F0");  // Whole: 4534
	    else
	        return sssss.ToString("F2");  // Decimal: 24356.30
	}

	// Formats a signed dollar distance for cell-tooltip summary lines:
	// +$123.45  /  -$87.00
	private string FormatSignedMoney(double v)
	{
		string s = Math.Abs(v).ToString("N2");
		return (v >= 0 ? "+$" : "-$") + s;
	}

	// True if any tracked account currently has an open position.
	// Used to flip the Daily Goal / Daily Loss cell tooltips from the generic
	// explanation text to a column-wide distance summary when trades are live.
	private bool AnyAccountInPosition()
	{
		foreach (KeyValuePair<string, PNLStatistics> kvp in FinalPNLStatistics)
		{
			if (kvp.Value == null) continue;
			if (kvp.Value.PositionLong != 0 || kvp.Value.PositionShort != 0)
				return true;
		}
		return false;
	}

	// Builds a multi-account distance summary for the Daily Goal column tooltip.
	// distance = CurrentDailyGoal - PNLTotal (positive = still to go, negative = past goal).
	// Only includes accounts with a goal configured.
	private string BuildDailyGoalDistanceTooltip()
	{
		System.Text.StringBuilder sb = new System.Text.StringBuilder(256);
		sb.Append("Distance to Daily Goal:");
		int shown = 0;
		foreach (KeyValuePair<string, PNLStatistics> kvp in FinalPNLStatistics)
		{
			if (kvp.Value == null || kvp.Value.Acct == null) continue;
			string nm = kvp.Value.Acct.Name;
			double goal = GetAccountSavedData(nm, pAllAccountDailyGoal);
			if (goal == DefaultForZero) continue;
			double dist = goal - kvp.Value.PNLTotal;
			sb.Append("\n  ").Append(nm).Append(": ").Append(FormatSignedMoney(dist));
			shown++;
		}
		if (shown == 0)
			return "No Daily Goal configured on any account.";
		return sb.ToString();
	}

	// Builds a multi-account distance summary for the Daily Loss column tooltip.
	// daily loss threshold is negative (e.g. -500). distance = PNLTotal - CurrentDailyLoss
	// (positive = still room before hitting loss; negative = past the loss cap).
	private string BuildDailyLossDistanceTooltip()
	{
		System.Text.StringBuilder sb = new System.Text.StringBuilder(256);
		sb.Append("Distance to Daily Loss:");
		int shown = 0;
		foreach (KeyValuePair<string, PNLStatistics> kvp in FinalPNLStatistics)
		{
			if (kvp.Value == null || kvp.Value.Acct == null) continue;
			string nm = kvp.Value.Acct.Name;
			double loss = GetAccountSavedData(nm, pAllAccountDailyLoss);
			if (loss == DefaultForZero) continue;
			double dist = kvp.Value.PNLTotal - loss;
			sb.Append("\n  ").Append(nm).Append(": ").Append(FormatSignedMoney(dist));
			shown++;
		}
		if (shown == 0)
			return "No Daily Loss configured on any account.";
		return sb.ToString();
	}
	
	private double ProcessStringNumber(string sssss)
	{
		
		double ffffff = 0;
		
		if (sssss == string.Empty)
			ffffff = 0;
		else
			ffffff = Convert.ToDouble(sssss);

		if (ffffff == 0)
			ffffff = DefaultForZero;		
		
		return ffffff;
	}
	
