		// Freeze-diagnostic instrumentation. When _freezeDebugEnabled is true the
		// indicator prints to the NT Output window:
		//   - OnMouseDown entry every time (lets us see if events reach us)
		//   - Before/after each ShowDialog() call (catches stuck modals)
		//   - A 2-second heartbeat with picker flags, modal-dialog flag, Mouse.Captured,
		//     AllMessages count, _mouseIsDown — if the heartbeat STOPS the UI thread
		//     is blocked (confirms modal dialog). If the heartbeat continues but no
		//     OnMouseDown lines appear on click, events aren't reaching the indicator
		//     and the problem is upstream (NT input layer or a capturing WPF element).
		// Flip to true to re-enable the noisy FreezeDbg Print stream
		// (heartbeat, OnMouseDown entry, 6x ShowDialog wrappers, 3x
		// PreviewMouseDown observers, subscribed-line at install time).
		// Kept as a property — not a const — so we don't have to rebuild
		// in order to toggle; flip the getter and deploy.
		// The retry-install machinery and _diagLog file entries stay active
		// regardless, so the important bug-catching telemetry is always on.
		private bool _freezeDebugEnabled { get { return false; } }
		private string _freezeDialogOpenSite = null; // human-readable name of the dialog currently inside ShowDialog()
		private System.Windows.Threading.DispatcherTimer _freezeDebugTimer;
		private int _freezeMouseDownCount = 0;
		private int _freezePreviewPanelCount = 0;
		private int _freezePreviewCtlCount = 0;
		private int _freezePreviewWinCount = 0;
		private int _freezeChartPanelHash = 0;
		private int _freezeWindowHash = 0;
		private bool _freezeHandlersSubscribed = false;
		private bool _panelHandlersSubscribed = false;
		private int _panelInstallAttempts = 0;
		// References captured at subscribe time so State.Terminated can cleanly
		// unsubscribe. Without these we'd leak handlers every workspace reload —
		// a chart window would accumulate dead indicator instances still listening
		// to PreviewMouseDown, growing the handler chain indefinitely.
		private System.Windows.UIElement _freezeSubscribedPanel = null;
		private NinjaTrader.Gui.Chart.ChartControl _freezeSubscribedCtl = null;
		private System.Windows.Window _freezeSubscribedWindow = null;

		// Idempotent — installs the REAL ChartPanel mouse handlers
		// (OnMouseMove, OnMouseDown, OnMouseUp, OnMouseDoubleClick,
		// OnPanelMouseLeave, right-click preview handlers, context-menu
		// suppressor). These were previously only installed in State.DataLoaded
		// and if ChartPanel was null at that moment the whole block silently
		// skipped — leaving the chart unresponsive to clicks. The heartbeat
		// timer also calls this so subscription will eventually stick.
		private void TryInstallChartPanelHandlers()
		{
			if (_panelHandlersSubscribed) return;
			_panelInstallAttempts++;
			if (this.ChartPanel == null)
			{
				// Log the first few null attempts so persistent freezes leave a
				// trace in the diagnostic log (users can ship us the file).
				if (_panelInstallAttempts <= 5 || (_panelInstallAttempts % 30) == 0)
				{
					try { if (_diagLog != null) _diagLog.Log("UI", "MOUSE_SUBSCRIBE_PENDING",
						"Attempt=" + _panelInstallAttempts + "|Reason=ChartPanelNull"); } catch { }
				}
				return;
			}
			try
			{
				this.ChartPanel.MouseMove += new System.Windows.Input.MouseEventHandler(this.OnMouseMove);
				this.ChartPanel.MouseDown += new MouseButtonEventHandler(this.OnMouseDown);
				this.ChartPanel.MouseUp += new MouseButtonEventHandler(this.OnMouseUp);
				this.ChartPanel.MouseDoubleClick += new MouseButtonEventHandler(this.OnMouseDoubleClick);
				this.ChartPanel.MouseLeave += new System.Windows.Input.MouseEventHandler(this.OnPanelMouseLeave);
				this.ChartPanel.PreviewMouseRightButtonDown += new MouseButtonEventHandler(this.OnPreviewRightButtonDown);
				this.ChartPanel.PreviewMouseRightButtonUp   += new MouseButtonEventHandler(this.OnPreviewRightButtonUp);
				this.ChartPanel.ContextMenuOpening          += new System.Windows.Controls.ContextMenuEventHandler(this.OnChartContextMenuOpening);
				_panelHandlersSubscribed = true;
				// Telemetry only (_diagLog file). Output window print removed —
				// "Attempt=N" in the diag log still distinguishes retry saves
				// from the happy path when we need to investigate.
				try { if (_diagLog != null) _diagLog.Log("UI", "MOUSE_SUBSCRIBE_OK",
					"Attempt=" + _panelInstallAttempts); } catch { }
			}
			catch (Exception _ex)
			{
				try { if (_diagLog != null) _diagLog.Log("UI", "MOUSE_SUBSCRIBE_ERR",
					"Attempt=" + _panelInstallAttempts + "|Error=" + _ex.Message); } catch { }
			}
		}

		// Idempotent — called from both State.DataLoaded and from the heartbeat
		// timer Tick. Handles the case where ChartPanel was null during
		// DataLoaded and became non-null later in Realtime.
		private void TryInstallFreezeHandlers()
		{
			if (_freezeHandlersSubscribed) return;
			if (this.ChartPanel == null || ChartControl == null) return;
			try
			{
				this.ChartPanel.AddHandler(System.Windows.UIElement.PreviewMouseDownEvent,
					new MouseButtonEventHandler(this.OnPreviewMouseDownDiag), true);
				_freezeSubscribedPanel = this.ChartPanel;
			}
			catch { }
			try
			{
				ChartControl.AddHandler(System.Windows.UIElement.PreviewMouseDownEvent,
					new MouseButtonEventHandler(this.OnPreviewMouseDownDiagCtl), true);
				_freezeSubscribedCtl = ChartControl;
			}
			catch { }
			try
			{
				var win = System.Windows.Window.GetWindow(ChartControl);
				if (win != null)
				{
					win.AddHandler(System.Windows.UIElement.PreviewMouseDownEvent,
						new MouseButtonEventHandler(this.OnPreviewMouseDownDiagWin), true);
					_freezeSubscribedWindow = win;
					_freezeWindowHash = win.GetHashCode();
				}
			}
			catch { }
			try { _freezeChartPanelHash = this.ChartPanel.GetHashCode(); } catch { }
			_freezeHandlersSubscribed = true;
		}

		// Counterpart to TryInstallFreezeHandlers — removes the AddHandler
		// subscriptions so dead indicator instances stop receiving events.
		// Called from State.Terminated.
		private void RemoveFreezeHandlers()
		{
			try
			{
				if (_freezeSubscribedPanel != null)
					_freezeSubscribedPanel.RemoveHandler(System.Windows.UIElement.PreviewMouseDownEvent,
						new MouseButtonEventHandler(this.OnPreviewMouseDownDiag));
			}
			catch { }
			try
			{
				if (_freezeSubscribedCtl != null)
					_freezeSubscribedCtl.RemoveHandler(System.Windows.UIElement.PreviewMouseDownEvent,
						new MouseButtonEventHandler(this.OnPreviewMouseDownDiagCtl));
			}
			catch { }
			try
			{
				if (_freezeSubscribedWindow != null)
					_freezeSubscribedWindow.RemoveHandler(System.Windows.UIElement.PreviewMouseDownEvent,
						new MouseButtonEventHandler(this.OnPreviewMouseDownDiagWin));
			}
			catch { }
			_freezeSubscribedPanel = null;
			_freezeSubscribedCtl = null;
			_freezeSubscribedWindow = null;
			_freezeHandlersSubscribed = false;
		}

