		// Per-account progress toward Daily Goal / Daily Loss thresholds, clamped to
		// [0, 1]. Populated during data population and consumed during the per-cell
		// render as an inline horizontal bar behind the cell text.
		private Dictionary<string, float> _goalProgress = new Dictionary<string, float>(64);
		private Dictionary<string, float> _lossProgress = new Dictionary<string, float>(64);

		// Per-account PnLTotal sparkline ring buffer. Sampled at most every
		// SparklineSampleIntervalMs to keep memory bounded; the cell renderer paints
		// the most recent SparklineLen points as a polyline behind the progress bar.
		private struct SparklineRing
		{
			public double[] Data;
			public int WriteIdx;
			public int Count;
			public void Add(double v)
			{
				if (Data == null) Data = new double[SparklineLen];
				Data[WriteIdx] = v;
				WriteIdx = (WriteIdx + 1) % SparklineLen;
				if (Count < SparklineLen) Count++;
			}
			public double Get(int i)
			{
				return Data[((WriteIdx - Count + i) % SparklineLen + SparklineLen) % SparklineLen];
			}
		}
		private Dictionary<string, SparklineRing>  _pnlSparkline      = new Dictionary<string, SparklineRing>(64);
		private Dictionary<string, DateTime>       _pnlSparklineStamp = new Dictionary<string, DateTime>(64);
		private const int SparklineLen                = 16;
		private const int SparklineSampleIntervalMs   = 500; // ~8s window at 16 samples

