		// Position drift watchdog — periodically compare master signed qty to each
		// follower's signed qty and log a single line when drift is detected, plus
		// a periodic heartbeat (every 30s) when in-position. Off when master flat
		// AND all followers flat.
		private DateTime _nextPositionDriftCheck = DateTime.MinValue;
		private DateTime _lastPositionDriftHeartbeat = DateTime.MinValue;
		private string _lastPositionDriftSignature = string.Empty;

