		private bool IsPendingEntryOrder(Order or)
		{
			
			
			bool istvtarget = or.Oco.Contains(pTVOCOPrefix);
	
			if (!or.Name.Contains("Target") && !or.Name.Contains("Stop") && !istvtarget)
			{
				return true;
			}
			else if (or.Account.GetPosition(or.Instrument.Id) == null)
			{
				return true;
			}
			else
			{
				return false;
			}
			
			
			
		}
			
		private bool IsServerVersionNewer(string server, string local)
		{
			if (string.IsNullOrEmpty(server) || string.IsNullOrEmpty(local)) return false;
			string[] sp = server.Replace(" ", "").Split('.');
			string[] lp = local.Replace(" ", "").Split('.');
			int n = Math.Max(sp.Length, lp.Length);
			for (int i = 0; i < n; i++)
			{
				int sv = 0, lv = 0;
				if (i < sp.Length) int.TryParse(sp[i], out sv);
				if (i < lp.Length) int.TryParse(lp[i], out lv);
				if (sv > lv) return true;
				if (sv < lv) return false;
			}
			return false;
		}

		private void AddMessage (string msg, int sec, Brush be, bool forceShow = false)
		{
			// Log MESSAGE|SHOW at most once per 30s per distinct message text.
			// Many paths (periodic conflict check, risk-filter loops) call
			// RemoveMessage(key) + AddMessage(text) every 1-2s; the old
			// structural dedupe was defeated because the removed toast wasn't
			// present when we checked. Time-based dedupe keyed on the full
			// message text works regardless of the remove/add pattern.
			if (_diagLog != null && msg != null)
			{
				DateTime now = DateTime.Now;
				DateTime last;
				bool shouldLog = !_diagLastMessageLogTime.TryGetValue(msg, out last)
					|| (now - last).TotalSeconds >= MsgLogDedupeWindowSec;
				if (shouldLog)
				{
					_diagLastMessageLogTime[msg] = now;
					// Truncate long toast text — 500+ char CONFLICT messages
					// were blowing up the log without adding diagnostic value.
					// 120 chars is enough to identify the message.
					string logText = msg.Replace("|", ";");
					if (logText.Length > 120)
						logText = logText.Substring(0, 120) + "...(truncated " + (msg.Length - 120) + " chars)";
					_diagLog.Log("MESSAGE", "SHOW", "Text=" + logText + "|Duration=" + sec);
				}

				// Keep the dedupe dictionary from growing unbounded. Stale
				// entries (no AddMessage call in >10 minutes) get pruned once
				// the dictionary crosses a threshold.
				if (_diagLastMessageLogTime.Count > 200)
				{
					try
					{
						var cutoff = now.AddMinutes(-10);
						var stale = new List<string>();
						foreach (var kv in _diagLastMessageLogTime)
							if (kv.Value < cutoff) stale.Add(kv.Key);
						foreach (var k in stale) _diagLastMessageLogTime.Remove(k);
					}
					catch { }
				}
			}

			//Print(msg);

			RemoveMessage("have been successfully");


			if (!forceShow && !pShowStatusMessages)
					return;
					
					
				MessageAlerts Z = new MessageAlerts();

						
							Z = new MessageAlerts();
				            Z.Name = msg;
							DateTime nowMsg = DateTime.Now;
							Z.StartTime = nowMsg;
							Z.ExpireTime = nowMsg.AddSeconds(sec);
							Z.BrushE = be;
							Z.Switch = true;
							Z.Url = "";


			//Print("Addmess 1");

				bool DuplicateMessage = false;


				foreach (MessageAlerts D in AllMessages.ToArray())
				{

					if (D.Name == msg && D.Switch)
					{
						DuplicateMessage = true;
						// Refresh the existing toast's expire time AND bump its count so the
						// rendered label can show "(xN)" instead of stacking duplicates.
						D.StartTime = nowMsg;
						D.ExpireTime = nowMsg.AddSeconds(sec);
						D.DuplicateCount = D.DuplicateCount + 1;
					}

				}
				
				//Print("Addmess 2");
				
				
				if (!DuplicateMessage)
				{
					AllMessages.Add(Z);
				}
				else
				{
					
						
				}
				//Print("Addmess 3");					

				bool refresh = true;
				
				
				
				if (msg.Contains("Daily Goal") || msg.Contains("Daily Loss") || msg.Contains("Funded Goal") || msg.Contains("was moved back") || msg.Contains("Rejected") || msg.Contains("rejection") || msg.Contains("are both disabled") || msg.Contains("all orders have been cancelled") || msg.Contains("will be reset in a moment"))   
					refresh = false;
				
				 if (msg.Contains("You can't update the '"))
					refresh = false;
				
										
									
				
				
				//Print("Addmess 4");
				
				if (refresh)
				if (ChartControl != null)
					InvalidateVis(1);
				
				//Print("Addmess 5");

		}

		private void AddMessageWithUrl(string msg, int sec, Brush be, string url, bool forceShow = false)
		{
			if (!forceShow && !pShowStatusMessages)
				return;

			MessageAlerts Z = new MessageAlerts();
			Z.Name = msg;
			DateTime nowMsg = DateTime.Now;
			Z.StartTime = nowMsg;
			Z.ExpireTime = nowMsg.AddSeconds(sec);
			Z.BrushE = be;
			Z.Switch = true;
			Z.Url = url ?? "";

			bool DuplicateMessage = false;

			foreach (MessageAlerts D in AllMessages.ToArray())
			{
				if (D.Name == msg && D.Switch)
				{
					DuplicateMessage = true;
					D.StartTime = nowMsg;
					D.ExpireTime = nowMsg.AddSeconds(sec);
					D.DuplicateCount = D.DuplicateCount + 1;
				}
			}

			if (!DuplicateMessage)
				AllMessages.Add(Z);

			if (ChartControl != null)
				InvalidateVis(1);
		}

	private void RemoveMessage (string msg)
		{



				foreach (MessageAlerts D in AllMessages.ToArray())
				{

					if (D.Name.Contains(msg))
						D.Switch = false;

				}
				
				
			
			
		}

				
		
		
		
