		/// <summary>True if multiplier is one of the fractional presets (1/2x, 1/3x, 1/4x, 1/5x).</summary>
		private static bool IsFractionalMultiplier(double mult)
		{
			double tol = 0.02;
			return (Math.Abs(mult - 0.50) < tol) || (Math.Abs(mult - 0.33) < tol) || (Math.Abs(mult - 1.0/3) < tol)
				|| (Math.Abs(mult - 0.25) < tol) || (Math.Abs(mult - 0.20) < tol);
		}
		
		/// <summary>True if masterQty * mult is not a whole number (fractional result that doesn't divide out).</summary>
		private static bool FractionalDoesNotDivideOut(int masterQty, double mult, out int roundedQty)
		{
			double exact = masterQty * mult;
			roundedQty = (int)Math.Round(exact, MidpointRounding.AwayFromZero);
			return Math.Abs(exact - Math.Round(exact)) > 0.001;
		}
		
		/// <summary>Rounds follower quantity. In Executions mode uses 'Executions Mode - Rounding' setting; otherwise rounds at 0.5 (unchanged).</summary>
private int RoundFollowerQtyForExecutionsMode(double exactQty)
{
   // Print(exactQty);

    bool isNegative = exactQty < 0;
    exactQty = Math.Abs(exactQty);

    int result;

    if (pCopierMode != "Executions")
        result = (int)Math.Round(exactQty, MidpointRounding.AwayFromZero);
    else if (pExecutionsRoundingMode == "Round Down")
    {
        const double tol = 0.1;
        int nearest = (int)Math.Round(exactQty);
        if (Math.Abs(exactQty - nearest) <= tol)
            result = nearest;
        else
            result = (int)Math.Floor(exactQty);
    }
    else
        result = (int)Math.Round(exactQty, MidpointRounding.AwayFromZero);

    return isNegative ? -result : result;
}
		
		private static string FractionalMultiplierLabel(double mult)
		{
			double tol = 0.02;
			if (Math.Abs(mult - 0.50) < tol) return "1/2x";
			if (Math.Abs(mult - 0.33) < tol || Math.Abs(mult - 1.0/3) < tol) return "1/3x";
			if (Math.Abs(mult - 0.25) < tol) return "1/4x";
			if (Math.Abs(mult - 0.20) < tol) return "1/5x";
			return mult.ToString("0.##") + "x";
		
		}
			
		
	
		private void SetAccountData (string id, string name, string status, string multiplier, string crossover, string fade, string hide, string peak, string autoclose, string atm)
		{
