				if (multiplier != "") parts += "|Multiplier=" + multiplier;
				if (crossover != "") parts += "|Type=" + crossover;
				if (fade != "") parts += "|Fade=" + fade;
				if (hide != "") parts += "|Hide=" + hide;
				if (autoclose != "") parts += "|AutoClose=" + autoclose;
