		private const string QRG_HARDCODED_PUB_ID = "2PACX-1vQXGDm7PRKl8QDCwKUAMz4Pow_QvVYaVyozdb3sHCTS-SYfIqMVp0Ua5RzidiqG06HpPbyfCi9omvuK";
		private void BeginFetchQrgDoc() { BeginFetchQrgDoc(false); }
		private void BeginFetchQrgDoc(bool force)
		{
			if (_qrgFetchInProgress) return;
			if (!force && (DateTime.Now - _qrgLastFetch).TotalMinutes < 5) return;

			_qrgFetchInProgress = true;
			System.Threading.Tasks.Task.Run(() =>
			{
				try
				{
					// Cache-busting query param defeats Google's CDN / shared
					// HTTP caches; the NoCacheNoStore policy + Cache-Control /
					// Pragma headers stop .NET's WinINet cache from serving a
					// stale copy.
					string url = "https://docs.google.com/document/d/e/"
						+ QRG_HARDCODED_PUB_ID
						+ "/pub?_cb=" + DateTime.UtcNow.Ticks;
					HttpWebRequest req = (HttpWebRequest)WebRequest.Create(url);
					req.Timeout = 10000;
					req.ReadWriteTimeout = 10000;
					// Browser-like User-Agent — Google sometimes returns different
					// content (or HTML redirects to a login page) for non-browser UAs.
					req.UserAgent = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 "
						+ "(KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36";
					req.Accept = "text/plain, text/*;q=0.8, */*;q=0.5";
					// The 307 redirect from docs.google.com to googleusercontent.com
					// sets a session cookie that must travel with the auto-follow.
					// Without a CookieContainer, HttpWebRequest drops the cookie and
					// the signed URL fails.
					req.CookieContainer = new CookieContainer();
					req.AllowAutoRedirect = true;
					req.MaximumAutomaticRedirections = 10;
					req.CachePolicy = new System.Net.Cache.RequestCachePolicy(
						System.Net.Cache.RequestCacheLevel.NoCacheNoStore);
					req.Headers[HttpRequestHeader.CacheControl] = "no-cache, no-store, must-revalidate";
					req.Headers[HttpRequestHeader.Pragma] = "no-cache";
					string body;
					string finalUri;
					int statusCode;
					string contentType;
					using (var resp = (HttpWebResponse)req.GetResponse())
					using (var stream = resp.GetResponseStream())
					using (var sr = new System.IO.StreamReader(stream, System.Text.Encoding.UTF8))
					{
						body = sr.ReadToEnd();
						finalUri = resp.ResponseUri != null ? resp.ResponseUri.ToString() : "(null)";
						statusCode = (int)resp.StatusCode;
						contentType = resp.ContentType ?? "(none)";
					}
					string[] parsed = ExtractQrgLinesFromPublishedHtml(body);
					if (parsed == null || parsed.Length == 0)
					{
						return;
					}
					// Trim trailing blank lines so overlay height is tight.
					int _lastNonBlank = parsed.Length - 1;
					while (_lastNonBlank >= 0 && string.IsNullOrWhiteSpace(parsed[_lastNonBlank])) _lastNonBlank--;
					if (_lastNonBlank < parsed.Length - 1)
					{
						string[] tight = new string[_lastNonBlank + 1];
						Array.Copy(parsed, tight, tight.Length);
						parsed = tight;
					}
					_qrgRemoteLines = parsed;
					_qrgLastFetch = DateTime.Now;
					// Persist to the hidden QrgCache property so the next load
					// has a valid offline copy even before the network lands.
					// Join with U+0001 so we survive NT's XML serialization
					// without newline / entity quirks.
					try
					{
						pQrgCache = string.Join("\u0001", parsed);
					}
					catch { }
					// Marshal redraw back to the UI thread. If the user pressed
					// '?' while the fetch was running, promote the pending state
					// to an actual open now that content is ready.
					try
					{
						if (ChartControl != null && ChartControl.Dispatcher != null)
							ChartControl.Dispatcher.InvokeAsync(() => {
								if (_qrgOpenPending)
								{
									_qrgOpenPending = false;
									_cheatSheetOpen = true;
									_csScrollOffset = 0;
								}
								InvalidateVis(128);
							});
					}
					catch { }
				}
				catch
				{
					// Swallow network / parse errors silently — the overlay
					// keeps using the previous cache or hardcoded defaults.
				}
				finally
				{
					_qrgFetchInProgress = false;
				}
			});
		}

		// Extracts the visible document text from Google Docs' Publish-to-web
		// HTML. Structure is:
		//     <div id="contents">
		//         <div class="... doc-content">
		//             <p class="...">...line text...</p>
		//             <p class="...">...blank or next line...</p>
		//             ...
		// Each <p> becomes one output line. Tags inside (spans for styling) are
		// stripped, &nbsp;/&amp;/&lt;/&gt;/numeric entities are decoded, and
		// <br> tags inside a paragraph turn into "\n" so multi-line paragraphs
		// still render correctly.
		private string[] ExtractQrgLinesFromPublishedHtml(string html)
		{
			if (string.IsNullOrEmpty(html)) return null;

			// Scope to the contents div so we skip the publish-banner title and
			// Google's script/style blocks outside the document body.
			int _contentsAt = html.IndexOf("<div id=\"contents\"", StringComparison.OrdinalIgnoreCase);
			if (_contentsAt < 0) return null;
			string _content = html.Substring(_contentsAt);

			// Walk every <p ...>...</p> block inside the contents region.
			List<string> _out = new List<string>();
			int _pos = 0;
			while (_pos < _content.Length)
			{
				int _pStart = _content.IndexOf("<p", _pos, StringComparison.OrdinalIgnoreCase);
				if (_pStart < 0) break;
				// Make sure this is actually a <p> tag (next char is space or '>').
				if (_pStart + 2 >= _content.Length
					|| (_content[_pStart + 2] != ' ' && _content[_pStart + 2] != '>' && _content[_pStart + 2] != '\t' && _content[_pStart + 2] != '\n' && _content[_pStart + 2] != '\r'))
				{
					_pos = _pStart + 2;
					continue;
				}
				int _pTagEnd = _content.IndexOf('>', _pStart);
				if (_pTagEnd < 0) break;
				int _pEnd = _content.IndexOf("</p>", _pTagEnd, StringComparison.OrdinalIgnoreCase);
				if (_pEnd < 0) break;
				string _inner = _content.Substring(_pTagEnd + 1, _pEnd - _pTagEnd - 1);

				// Convert <br>/<br/> inside the paragraph to line breaks so
				// Shift+Enter in the Doc becomes a real newline in the overlay.
				_inner = System.Text.RegularExpressions.Regex.Replace(
					_inner, @"<br\s*/?>", "\n", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
				// Strip every remaining tag (spans for styling, anchors, etc.).
				_inner = System.Text.RegularExpressions.Regex.Replace(_inner, @"<[^>]*>", "");
				// Decode HTML entities including &nbsp;, &amp;, numeric forms.
				_inner = System.Net.WebUtility.HtmlDecode(_inner);
				// Normalize non-breaking spaces (U+00A0) to regular spaces so
				// the render-time indent check (_ln[0] != ' ') and the
				// command/description gap detector below work consistently.
				_inner = _inner.Replace('\u00A0', ' ');
				// A paragraph may now contain embedded newlines from <br> —
				// emit each as its own line so the existing render code treats
				// them as separate body rows.
				string[] _subLines = _inner.Split('\n');
				foreach (string _sub in _subLines)
					_out.Add(_sub.TrimEnd('\r'));

				_pos = _pEnd + 4; // len("</p>")
			}

			return NormalizeQrgLines(_out.ToArray());
		}

		// Normalizes raw Quick-Reference lines to our canonical formatting:
		// 2 blank lines above each non-first section header, 1 blank below
		// each header, and per-section command/description alignment.
		// Applied to BOTH the remote Doc content and the hardcoded defaults
		// so first-open renders identically to subsequent renders (no flash).
		private string[] NormalizeQrgLines(string[] input)
		{
			if (input == null || input.Length == 0) return input;
			List<string> _spaced = new List<string>(input.Length + 16);
			bool _seenTitle = false;
			bool _seenFirstHeader = false;
			bool _justEmittedBlankAfterHeader = false;
			for (int _li = 0; _li < input.Length; _li++)
			{
				string _ln = input[_li];
				if (!_seenTitle)
				{
					_spaced.Add(_ln);
					if (!string.IsNullOrWhiteSpace(_ln)) _seenTitle = true;
					continue;
				}
				bool _isHeader = _ln.Length > 0 && _ln[0] != ' ' && _ln == _ln.ToUpperInvariant();
				if (_isHeader)
				{
					if (_seenFirstHeader)
					{
						// Strip any trailing blanks, then emit exactly 2 above.
						while (_spaced.Count > 0
							&& string.IsNullOrWhiteSpace(_spaced[_spaced.Count - 1]))
							_spaced.RemoveAt(_spaced.Count - 1);
						_spaced.Add("");
						_spaced.Add("");
					}
					_seenFirstHeader = true;
					_spaced.Add(_ln);          // the header itself
					_spaced.Add("");            // exactly 1 blank below header
					_justEmittedBlankAfterHeader = true;
					continue;
				}
				// Swallow source-side blank lines immediately after our
				// injected post-header blank so we don't double-space.
				if (_justEmittedBlankAfterHeader && string.IsNullOrWhiteSpace(_ln))
					continue;
				_justEmittedBlankAfterHeader = false;
				_spaced.Add(_ln);
			}

			// Re-align "command <big gap> description" rows per section.
			string[] _spacedArr = _spaced.ToArray();
			int _ai = 0;
			while (_ai < _spacedArr.Length)
			{
				int _gapStart = FindQrgCommandGap(_spacedArr[_ai]);
				if (_gapStart < 0) { _ai++; continue; }
				int _groupStart = _ai;
				int _maxCmdLen = 0;
				while (_ai < _spacedArr.Length)
				{
					int _gs = FindQrgCommandGap(_spacedArr[_ai]);
					if (_gs < 0) break;
					if (_gs > _maxCmdLen) _maxCmdLen = _gs;
					_ai++;
				}
				int _groupEnd = _ai;
				int _target = _maxCmdLen + 4;
				for (int _j = _groupStart; _j < _groupEnd; _j++)
				{
					string _line = _spacedArr[_j];
					int _gs = FindQrgCommandGap(_line);
					string _cmd = _line.Substring(0, _gs);
					string _desc = _line.Substring(_gs).TrimStart(' ');
					int _padLen = Math.Max(4, _target - _cmd.Length);
					_spacedArr[_j] = _cmd + new string(' ', _padLen) + _desc;
				}
			}
			return _spacedArr;
		}

		// Returns the start index of the "alignment gap" — a run of 4+
		// consecutive spaces that separates a command from its description —
		// or -1 if the line doesn't fit the pattern.
		private int FindQrgCommandGap(string s)
		{
			if (string.IsNullOrEmpty(s)) return -1;
			int i = 0;
			// Line must be indented (leading space) to qualify.
			while (i < s.Length && s[i] == ' ') i++;
			if (i == 0) return -1;
			// Walk looking for a run of 4+ spaces followed by more content.
			while (i < s.Length)
			{
				if (s[i] == ' ')
				{
					int _runStart = i;
					while (i < s.Length && s[i] == ' ') i++;
					int _runLen = i - _runStart;
					if (_runLen >= 4 && i < s.Length) return _runStart;
				}
				else
				{
					i++;
				}
			}
			return -1;
		}

		// Detects whether a single line is a hyperlink of the form
		// "[display text](https://url) optional trailing description". The
		// link portion becomes clickable; anything after the closing ) is
		// returned in `trailing` and renders inline as plain body text.
		private bool TryParseQrgLinkLine(string ln, out string indent, out string linkText, out string linkUrl, out string trailing)
		{
			indent = ""; linkText = null; linkUrl = null; trailing = "";
			if (string.IsNullOrEmpty(ln)) return false;
			int _i = 0;
			while (_i < ln.Length && (ln[_i] == ' ' || ln[_i] == '\t')) _i++;
			if (_i >= ln.Length || ln[_i] != '[') return false;
			int _rb = ln.IndexOf(']', _i + 1);
			if (_rb < 0 || _rb + 1 >= ln.Length || ln[_rb + 1] != '(') return false;
			int _rp = ln.IndexOf(')', _rb + 2);
			if (_rp < 0) return false;
			indent = ln.Substring(0, _i);
			linkText = ln.Substring(_i + 1, _rb - _i - 1);
			linkUrl = ln.Substring(_rb + 2, _rp - _rb - 2);
			// Everything after the closing ) is trailing body text.
			if (_rp + 1 < ln.Length)
				trailing = ln.Substring(_rp + 1);
			return true;
		}

