		SortedDictionary<string, string> AccountNameToRandom = new SortedDictionary<string, string>();

		/// <summary>
		/// Safe lookup for AccountNameToRandom. The dictionary is populated once from Account.All
		/// at indicator start; any account added later (or a null/empty name from a broker glitch)
		/// would throw KeyNotFoundException on the raw indexer. Returns a stable fallback derived
		/// from the name so OCO strings stay unique even when we miss the cache.
		/// </summary>
		private string GetAccountRandomSuffix(string acctName)
		{
			if (string.IsNullOrEmpty(acctName)) return "XXXX";
			string val;
			if (AccountNameToRandom.TryGetValue(acctName, out val) && !string.IsNullOrEmpty(val))
				return val;
			// Lazy-fill so the next lookup is a hit. Use a short hash of the name so the same
			// account always gets the same suffix across the session.
			string fallback = (Math.Abs(acctName.GetHashCode()) % 10000).ToString("D4");
			try { AccountNameToRandom[acctName] = fallback; } catch { }
			return fallback;
		}



