		public void CopierMainButton()
		{
			if (_diagLog != null)
				_diagLog.Log("UI", "COPIER_MAIN_BUTTON", "CopierEnabled=" + pCopierIsEnabled);

			RemoveMessage(AllKorean);
			RemoveMessage("You must add at");
			RemoveMessage("카피트레이딩 작업을 활성화하려면 최소한 하나의 팔로워 계정을 추가해야 합니다. 계좌 이름을 클릭하여 팔로워 계정으로 설정하십시오.");

			// Currently ON → turn OFF
			if (pCopierIsEnabled)
			{
				pCopierIsEnabled = false;
				if (_diagLog != null)
					_diagLog.Log("UI", "COPIER_DISABLED", "Reason=MainButtonToggle");
				ResetMasterExecutionState();
				PublishEnabledStateAndPingPeers(); // peers currently blocked by us should re-evaluate and show "Ready to enable"
				RemoveMessage("CONFLICT");
				RemoveMessage("DUPLICATE WINDOW");
				return;
			}

			// Currently OFF → validate + turn ON
			string enddddd = "enable Duplicate Account Actions";

			if (!AccountsAreConfigured())
			{
				if (AllDuplicateAccounts.Count == 0 && pThisMasterAccount == string.Empty)
				{
					if (TotalAccounts != 0)
					{
						if (!IsKorean)
							AddMessage("You must set the Master account and add at least one Follower account to " + enddddd + ". Double click the connected status dot to set the Master account. Click the account name to set it as a Follower account.", 20, Brushes.Red);
						else
							AddMessage(AllKorean, 20, Brushes.Red);
					}
					else
					{
						if (!IsKorean)
							AddMessage("No accounts are connected. Please connect to a data feed to " + enddddd + ".", 20, Brushes.Red);
						else
							AddMessage("연결된 계좌가 없습니다. 데이터 피드에 연결하세요.", 20, Brushes.Red);
					}
				}
				else if (pThisMasterAccount == string.Empty)
				{
					if (!IsKorean)
						AddMessage("You must set the Master account to " + enddddd + ". Double click the connected status dot to set the Master account.", 20, Brushes.Red);
					else
						AddMessage(AllKorean, 20, Brushes.Red);
				}
				else if (AllDuplicateAccounts.Count == 0)
				{
					if (!IsKorean)
						AddMessage("You must add at least one Follower account to " + enddddd + ". Click the account name to set it as a Follower account.", 20, Brushes.Red);
					else
						AddMessage("카피트레이딩 작업을 활성화하려면 최소한 하나의 팔로워 계정을 추가해야 합니다. 계좌 이름을 클릭하여 팔로워 계정으로 설정하십시오.", 20, Brushes.Red);
				}
				else
				{
					AddMessage("Your Master account '" + pThisMasterAccount + "' must be connected to " + enddddd + ".", 10, Brushes.Red);
				}
				return;
			}

			// Accounts are configured. Trip affiliate-link flags on first enable.
			if (!pAffiliateLinkDone1 && HasAPEXAccounts)
				pAffiliateLinkDone1 = true;
			if (!pAffiliateLinkDone2 && HasLeeLooAccounts)
				pAffiliateLinkDone2 = true;

			SetScrollImmediate(0);

			// Refresh registry with current config and compute peer conflicts.
			// Block the enable when a peer window with an overlapping configuration is currently
			// ON. If the overlap is with peers that are all OFF, allow the enable — no duplicate-
			// order risk until a second conflicting window comes online.
			_conflictMessage = RegisterInstance();
			DateTime nowForOverride = DateTime.Now;
			bool withinOverrideWindowAtCheck = (nowForOverride - _lastEnableBlockTime).TotalSeconds <= OverrideWindowSeconds;
			bool anyPeerEnabled = IsAnyConflictingPeerEnabled();
			bool hasConfigConflict = !string.IsNullOrEmpty(_conflictMessage);
			// Block if (a) there's a config conflict AND a peer is currently enabled, OR
			// (b) there's a config conflict AND we're already within the override cooldown
			// (covers stale-cache case where peer state hasn't propagated yet). Case (b) means
			// the second click still triggers override even if IsAnyConflictingPeerEnabled
			// transiently reads false due to race or missed update.
			bool blockedByEnabledPeer = hasConfigConflict && (anyPeerEnabled || withinOverrideWindowAtCheck);
			if (_diagLog != null)
				_diagLog.Log("UI", "COPIER_ENABLE_CHECK",
					"HasConflict=" + hasConfigConflict
					+ "|PeerIds=" + _lastConflictPeerIds.Count
					+ "|AnyPeerEnabled=" + anyPeerEnabled
					+ "|WithinOverrideWindow=" + withinOverrideWindowAtCheck
					+ "|Blocked=" + blockedByEnabledPeer);

			if (blockedByEnabledPeer)
			{
				// A conflicting peer is currently ON. Two possibilities:
				//   (a) First click — show block message with an "Click again within Ns to override"
				//       hint, remember the timestamp, return without enabling.
				//   (b) Second click within the override window — the user really does want to take
				//       over. Request each blocking peer to disable itself, mark ourselves as
				//       pending-enable, and let the timer flip us ON once the peers are actually off.
				DateTime now = DateTime.Now;
				bool withinOverrideWindow = (now - _lastEnableBlockTime).TotalSeconds <= OverrideWindowSeconds;
				_lastEnableBlockTime = now;

				if (withinOverrideWindow)
				{
					int scheduled = RequestPeerDisable();
					_pendingEnableAfterOverride = true;
					RemoveMessage("CONFLICT");
					RemoveMessage("DUPLICATE WINDOW");
					RemoveMessage("Window conflict resolved");
					RemoveMessage("Ready to enable");
					AddMessage("Override confirmed — turning off " + scheduled + " blocking window(s). This window will enable automatically once they are off.", 8, Brushes.Orange);
					_conflictMessage = string.Empty;
					if (_diagLog != null)
						_diagLog.Log("UI", "COPIER_OVERRIDE_REQUESTED", "PeersToDisable=" + scheduled);
					return;
				}

				string blockMsg = BuildBlockedByPeersMessage(true);
				RemoveMessage("CONFLICT");
				RemoveMessage("DUPLICATE WINDOW");
				RemoveMessage("Window conflict resolved");
				RemoveMessage("Ready to enable");
				AddMessage(blockMsg, 60, Brushes.Goldenrod);
				_lastCopierBlockerMessage = blockMsg;
				_hadConflict = true;
				_wasBlockedByPeers = true;
				_conflictMessage = string.Empty;
				return;
			}

			// Clear any stale banners — either from a previous block that's now resolved, or from
			// the conflict-resolved path.
			if (_hadConflict || _wasBlockedByPeers)
			{
				_hadConflict = false;
				_wasBlockedByPeers = false;
				RemoveMessage("CONFLICT");
				RemoveMessage("DUPLICATE WINDOW");
				AddMessage("Window conflict resolved", 10, Brushes.LimeGreen);
			}
			_conflictMessage = string.Empty;
			_lastEnableBlockTime = DateTime.MinValue; // clear override timer so a later block doesn't immediately trip it

			// Re-seed tracked master position from live BEFORE flipping the enable
			// flag. Handles the "toggle OFF → toggle ON mid-trade" case where
			// ResetMasterExecutionState cleared TrackedMasterPosition. Without
			// this, the first execution after re-enable is treated as a brand new
			// instrument, the delta math goes negative, IsFinalExit=false, and
			// followers never flatten when the master closes.
			SeedTrackedMasterPositionFromLive();

			pCopierIsEnabled = true;
			_copierArmedUtc = DateTime.UtcNow;
			PublishEnabledStateAndPingPeers(); // peers need to know we're now ON so they block at their own enable attempt
			if (_diagLog != null)
				_diagLog.Log("UI", "COPIER_ENABLED", "Reason=MainButtonToggle|Mode=" + pCopierMode + "|Master=" + pThisMasterAccount + "|Followers=" + AllDuplicateAccounts.Count);
			LogTimezoneSnapshot("CopierEnable.MainButtonToggle");
			RemoveMessage("You are placing trades on the Master account,");
			RemoveMessage("CONFLICT");
			RemoveMessage("DUPLICATE WINDOW");
			RemoveMessage("Ready to enable");
			RemoveMessage("This window was turned OFF"); // clear the peer-override notice if still showing
		}
		
		
		
					private void CopierOnOff()
					{
						if (_diagLog != null)
							_diagLog.Log("UI", "COPIER_MODE_TOGGLE", "CurrentMode=" + pCopierMode);

							string instending = "before changing the Duplicate Account Actions mode.";
					
							if (TotalPendingOrders != 0 && TotalPositions != 0)
							{
								RemoveMessage(instending);
								AddMessage("Please flatten all accounts " + instending, 10, Brushes.Red);
								
							}
							else if (TotalPendingOrders != 0)
							{
								RemoveMessage(instending);
								AddMessage("Please cancel all pending orders " + instending, 10, Brushes.Red);
							}
							else if (TotalPositions != 0)
							{
								RemoveMessage(instending);
								AddMessage("Please close all positions " + instending, 10, Brushes.Red);
							}	
							else
							{
								
									
								
								if (pCopierMode == "Executions")
								{
									pCopierMode = "Orders";
									
									RemoveMessage("The 'Fade' column cannot");
									RemoveMessage("카피트레이딩 작업'이 '주문모드'에서 실행 중일 때는 '반대진입' 기능을 사용할 수 없습니다. '반대진입' 기능을 사용하려면 모드를 '체결모드' 로 설정해 주세요.");
									
									
									if (pIsFadeEnabled)
									{
										if (!IsKorean)
											AddMessage("The 'Fade' column cannot be used when Duplicate Account Actions is running in 'Orders' mode. Please set the mode to 'Executions' for using the 'Fade' column.", 30, Brushes.Red);
										else
											AddMessage("카피트레이딩 작업'이 '주문모드'에서 실행 중일 때는 '반대진입' 기능을 사용할 수 없습니다. '반대진입' 기능을 사용하려면 모드를 '체결모드' 로 설정해 주세요.", 30, Brushes.Red);

									
										pIsFadeEnabled = false;
									
									}
									
									
									
	
								}
								else
								{

									pCopierMode = "Executions";
									
								}					
								
								if (IsKorean)
								{
									RemoveMessage("카피트레이딩 창이 '주문모드'로 업데이트되었습니다. 자세한 내용은 Members Area의 사용자 매뉴얼을 참조하십시오!");
									RemoveMessage("카피트레이딩 창이 '체결모드'로 업데이트되었습니다. 자세한 내용은 Members Area의 사용자 매뉴얼을 참조하십시오!");
									
									if (pCopierMode == "Orders")
										AddMessage("카피트레이딩 창이 '주문모드'로 업데이트되었습니다. 자세한 내용은 Members Area의 사용자 매뉴얼을 참조하십시오!", 15, Brushes.Red);
									if (pCopierMode == "Executions")
										AddMessage("카피트레이딩 창이 '체결모드'로 업데이트되었습니다. 자세한 내용은 Members Area의 사용자 매뉴얼을 참조하십시오!", 15, Brushes.Red);									
								}
								else
								{
								
									RemoveMessage("Duplicate Account Actions has been updated");									
									AddMessage("Duplicate Account Actions has been updated to '" + pCopierMode + "' mode. Please see the user manual, in Members Area, for more information!", 15, Brushes.Goldenrod);
																	
									
								}

							
									
							}
							
					
					
					
						
						
						
						
						
						//btnDrawObjs.Content = pCopierMode;
				
					}
						
					
					
					
