		private bool pAllowBothFeaturesToBeOff = true;

		// True when the brush is null, a SolidColorBrush with A == 0, or has
		// Opacity <= 0. Used so "Transparent" in the color picker falls through
		// to the skin-detection path in ThisChartBackground().
		private static bool IsBrushTransparent(Brush b)
		{
			if (b == null) return true;
			if (b.Opacity <= 0.0) return true;
			var scb = b as SolidColorBrush;
			if (scb != null && scb.Color.A == 0) return true;
			return false;
		}

		public Brush ThisChartBackground()
		{
			// Treat null or a transparent brush as "use the chart skin" so the
			// default (Transparent) auto-detects the skin color and a user
			// can restore skin-follow behavior by picking Transparent.
			if (pDashboardBackground != null && !IsBrushTransparent(pDashboardBackground))
				return pDashboardBackground;

			if (myProperties == null)
				return Brushes.Black;

			if (myProperties.ChartBackground.ToString().Contains("GradientBrush"))
			{
						
				
				
				//return myProperties.ChartBackground;
			
				string skinname = NinjaTrader.Core.Globals.GeneralOptions.Skin.ToString();
				if (skinname == "NinjaTrader Dark" || skinname == "Dark" || skinname == "Slate Dark" || skinname == "Slate Gray")
						{
							//Print("setting b");
							
							return FrozenRgbBrush(30, 30, 30);
							
							//return Brushes.Silver;
						}
						else
						{
							
							return Brushes.White;
						}
				
			}
			else
			{
				
				return myProperties.ChartBackground;
			}
			
			
			
			
