		private bool IsDashboardToolbarItem(object item)
		{
			return ReferenceEquals(item, btnDrawObjs)
				|| ReferenceEquals(item, btnShowTrades)
				|| ReferenceEquals(item, btnIndicators)
				|| ReferenceEquals(item, atmStrategySelector);
		}

		private bool IsChartHeaderToolbarItem(object item)
		{
			if (item == null || IsDashboardToolbarItem(item))
				return false;

			if (item is System.Windows.Controls.Button
				|| item is System.Windows.Controls.Menu
				|| item is NinjaTrader.Gui.Tools.IntervalSelector
				|| item is NinjaTrader.Gui.Tools.InstrumentSelector)
				return true;

			System.Windows.FrameworkElement fe = item as System.Windows.FrameworkElement;
			if (fe == null)
				return false;

			string automationId = string.Empty;
			try { automationId = System.Windows.Automation.AutomationProperties.GetAutomationId(fe); } catch { }
			return !string.IsNullOrEmpty(automationId) && automationId.StartsWith("ChartWindow", StringComparison.Ordinal);
		}

		// Force-show every chart header item (used on Terminated so leaving the
		// dashboard tab never strands the user with hidden NT toolbar buttons).
		// Mirrors the RestoreHiddenChartMenuItems pattern used for the right-click menu.
		private void RestoreChartWindowHeader()
		{
			try
			{
				if (chartWindow == null || chartWindow.MainMenu == null)
					return;

				foreach (object item in chartWindow.MainMenu)
				{
					if (!IsChartHeaderToolbarItem(item))
						continue;

					System.Windows.Controls.Menu menu = item as System.Windows.Controls.Menu;
					if (menu != null)
					{
						menu.Visibility = System.Windows.Visibility.Visible;
						foreach (object menuItem in menu.Items)
						{
							System.Windows.Controls.ItemsControl ii = menuItem as System.Windows.Controls.ItemsControl;
							if (ii != null) ii.Visibility = System.Windows.Visibility.Visible;
						}
						continue;
					}

					System.Windows.FrameworkElement fe = item as System.Windows.FrameworkElement;
					if (fe != null) fe.Visibility = System.Windows.Visibility.Visible;
				}
			}
			catch { }
			_chartHeaderOriginalVisibility.Clear();
		}

		// Idempotent: every call explicitly sets each header item to Visible or
		// Collapsed based on the current setting. No stored "original" state to
		// drift out of sync, no skip-if-already-applied path — same pattern the
		// right-click context menu uses and which the user confirmed works.
		// Not gated on TabSelected() — when "Remove Chart Window Header" is on,
		// the items stay hidden across tab switches in this window, which
		// eliminates the flash that occurred when the SelectionChanged handler
		// ran AFTER WPF had already rendered the new tab with the header shown.
		private void ApplyChartWindowHeaderState()
		{
			try
			{
				if (chartWindow == null || chartWindow.MainMenu == null)
					return;

				bool shouldHideHeader = pRemoveIcons;
				System.Windows.Visibility hidden  = System.Windows.Visibility.Collapsed;
				System.Windows.Visibility visible = System.Windows.Visibility.Visible;

				foreach (object item in chartWindow.MainMenu)
				{
					if (!IsChartHeaderToolbarItem(item))
						continue;

					System.Windows.Controls.Menu menu = item as System.Windows.Controls.Menu;
					if (menu != null)
					{
						if (shouldHideHeader && pChartTraderNeedsDisabled)
						{
							// Keep the menu host visible but only the Chart Trader sub-item.
							menu.Visibility = visible;
							foreach (object menuItem in menu.Items)
							{
								System.Windows.Controls.ItemsControl ii = menuItem as System.Windows.Controls.ItemsControl;
								if (ii == null) continue;
								ii.Visibility = (ii.Name == "miChartTrader") ? visible : hidden;
							}
						}
						else if (shouldHideHeader)
						{
							menu.Visibility = hidden;
						}
						else
						{
							// Restore: show the menu and every direct child.
							menu.Visibility = visible;
							foreach (object menuItem in menu.Items)
							{
								System.Windows.Controls.ItemsControl ii = menuItem as System.Windows.Controls.ItemsControl;
								if (ii != null) ii.Visibility = visible;
							}
						}
						continue;
					}

					System.Windows.FrameworkElement fe = item as System.Windows.FrameworkElement;
					if (fe != null)
						fe.Visibility = shouldHideHeader ? hidden : visible;
				}
			}
			catch { }
		}

		private void CheckTab()
		{
			ApplyChartWindowHeaderState();

			bool selected = TabSelected();
			bool showDashboardToolbar = selected && pRemoveIcons && pUseToolbarButtons && !pChartTraderNeedsDisabled;
			if (btnDrawObjs != null)
				btnDrawObjs.Visibility = showDashboardToolbar && pIsCopyBasicFunctionsChecked ? Visibility.Visible : Visibility.Collapsed;
			if (btnShowTrades != null)
				btnShowTrades.Visibility = showDashboardToolbar ? Visibility.Hidden : Visibility.Collapsed;

			// Refresh the Selected Accounts count immediately so a tab click shows
			// the correct number right away, without waiting for the next OnRender
			// or periodic pass.
			if (btnDrawObjs != null)
			{
				int _vsa = VisibleSelectedAccounts;
				btnDrawObjs.Content = IsKorean
					? (_vsa > 0 ? _vsa + " 지정된 계좌" : "지정된 계좌 없음")
					: (_vsa > 0 ? _vsa + " Selected Accounts" : "No Selected Accounts");
			}

			// Re-apply bar/data-series/global-draw-object hiding on every tab change.
			// NT can reset these when the user changes data series or when the
			// workspace re-binds the bars instance — FirstRender2 only runs once.
			EnsureDashboardChartHidden();
		}

		// Idempotent re-application of the dashboard's "no bars / no globals" chart
		// styling. Called from FirstRender2 (initial setup) AND from CheckTab plus
		// the periodic toolbar pass so anything that resets these properties (data
		// series change, workspace restore, NT recreating the bars instance) gets
		// corrected automatically.
		private void EnsureDashboardChartHidden()
		{
			try
			{
				if (ChartBars != null && ChartBars.Properties != null)
				{
					ChartBars.Properties.PlotExecutions = ChartExecutionStyle.DoNotPlot;
					if (ChartBars.Properties.ChartStyle != null)
					{
						ChartBars.Properties.ChartStyle.DownBrush = Brushes.Transparent;
						ChartBars.Properties.ChartStyle.UpBrush   = Brushes.Transparent;
						if (ChartBars.Properties.ChartStyle.Stroke  != null) ChartBars.Properties.ChartStyle.Stroke.Brush  = Brushes.Transparent;
						if (ChartBars.Properties.ChartStyle.Stroke2 != null) ChartBars.Properties.ChartStyle.Stroke2.Brush = Brushes.Transparent;
					}
					ChartBars.Properties.PaintPriceMarker        = false;
					ChartBars.Properties.TradingHoursVisibility  = TradingHoursBreakLineVisible.Off;
					ChartBars.Properties.ShowGlobalDrawObjects   = false;
					ChartBars.Properties.DisplayInDataBox        = false;
					ChartBars.Properties.AutoScale               = false;
					ChartBars.Properties.ScaleJustification      = ScaleJustification.Overlay;
				}
			}
			catch { }
		}

