		// ============================================================
// ATM STRATEGY REFLECTION DISCOVERY
// ============================================================
// Paste this into a method in your indicator (e.g. a button click handler)
// or call it from OnBarUpdate with a one-time flag.
// Output goes to NinjaTrader's Output window (Ctrl+O).
//
// This dumps ALL non-public methods, properties, fields, and events
// on AtmStrategy and related classes to find hidden scale-in methods.
// ============================================================

private void DumpAtmStrategyInternals()
{
    // Print("========================================");
    // Print("ATM STRATEGY REFLECTION DISCOVERY");
    // Print("========================================");
    // Print("");
    
    // 1. AtmStrategy class itself
    DumpType(typeof(NinjaTrader.NinjaScript.AtmStrategy), "AtmStrategy");
    
    // 2. Walk the base class chain
    Type baseType = typeof(NinjaTrader.NinjaScript.AtmStrategy).BaseType;
    int depth = 0;
    while (baseType != null && baseType != typeof(object) && depth < 5)
    {
        DumpType(baseType, "AtmStrategy BASE: " + baseType.Name);
        baseType = baseType.BaseType;
        depth++;
    }
    
    // 3. Bracket class
    try
    {
        Type bracketType = typeof(NinjaTrader.NinjaScript.AtmStrategy).Assembly.GetType("NinjaTrader.NinjaScript.Bracket");
        if (bracketType != null)
            DumpType(bracketType, "Bracket");
        else
            ; // Print("Bracket type not found in AtmStrategy assembly");
    }
    catch { }
    
    // 4. Look for Chart Trader related types
    // Print("");
    // Print("========================================");
    // Print("SEARCHING FOR CHART TRADER TYPES");
    // Print("========================================");
    try
    {
        foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
        {
            try
            {
                foreach (var t in asm.GetTypes())
                {
                    string name = t.FullName ?? "";
                    if (name.Contains("ChartTrader") || name.Contains("chartTrader"))
                    {
                        // Print("FOUND TYPE: " + t.FullName + " in " + asm.GetName().Name);
                        DumpType(t, "ChartTrader: " + t.Name);
                    }
                }
            }
            catch { } // some assemblies throw on GetTypes()
        }
    }
    catch { }
    
    // 5. Search ALL types for methods containing "ScaleIn", "AddEntry", "AssociateEntry", etc.
    // Print("");
    // Print("========================================");
    // Print("SEARCHING ALL ASSEMBLIES FOR SCALE-IN RELATED METHODS");
    // Print("========================================");
    string[] keywords = new string[] { "ScaleIn", "ScaleOut", "AddEntry", "AssociateEntry", "AddToPosition", "IncreasePosition", "MergeEntry", "CombineEntry", "AttachEntry", "SelectActive" };
    try
    {
        foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
        {
            string asmName = asm.GetName().Name;
            if (!asmName.Contains("NinjaTrader")) continue;
            try
            {
                foreach (var t in asm.GetTypes())
                {
                    var allMethods = t.GetMethods(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.Static);
                    foreach (var m in allMethods)
                    {
                        foreach (string kw in keywords)
                        {
                            if (m.Name.IndexOf(kw, StringComparison.OrdinalIgnoreCase) >= 0)
                            {
                                string parms = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                                // Print("MATCH: " + t.FullName + "." + m.Name + "(" + parms + ") [" + (m.IsPublic ? "public" : "non-public") + (m.IsStatic ? " static" : "") + "]");
                            }
                        }
                    }
                }
            }
            catch { }
        }
    }
    catch { }
    
    // 6. Dump live ATM instance data if one exists
// Print("========================================");
// Print("LIVE ATM INSTANCE FIELD VALUES");
// Print("========================================");

// Get master account reference
Account masterAcct = null;
foreach (Account acct in Account.All.ToList())
{
    if (acct.Name == CurrentMasterAccount.Name) // or hardcode "Sim101" etc.
    {
        masterAcct = acct;
        break;
    }
}

bool foundAtm = false;
if (masterAcct != null)
{
    foreach (Order ord in masterAcct.Orders)
    {
        if (ord.OrderState == OrderState.Working || ord.OrderState == OrderState.Accepted)
        {
            var owner = ord.GetOwnerStrategy();
            if (owner != null)
            {
                // Print("Order '" + ord.Name + "' owned by: " + owner.DisplayName + " type=" + owner.GetType().FullName);
                if (owner is NinjaTrader.NinjaScript.AtmStrategy liveAtm)
                {
                    DumpInstanceFields(liveAtm, "LIVE ATM via Order");
                    foundAtm = true;
                    break;
                }
            }
        }
    }
}

if (!foundAtm)
    ; // Print("No live ATM found via order ownership on account " + (masterAcct != null ? masterAcct.Name : "NULL"));
    
    // 7. Search for methods on Account class related to ATM
    // Print("");
    // Print("========================================");
    // Print("ACCOUNT CLASS ATM-RELATED METHODS");
    // Print("========================================");
    try
    {
        Type accountType = typeof(Account);
        var methods = accountType.GetMethods(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.Static);
        foreach (var m in methods)
        {
            string mName = m.Name.ToLower();
            if (mName.Contains("atm") || mName.Contains("strategy") || mName.Contains("scale") || mName.Contains("bracket") || mName.Contains("protect"))
            {
                string parms = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                // Print(accountType.Name + "." + m.Name + "(" + parms + ") → " + m.ReturnType.Name + " [" + (m.IsPublic ? "public" : "non-public") + (m.IsStatic ? " static" : "") + "]");
            }
        }
    }
    catch { }
    
    // 8. Search for methods on Order class related to ATM
    // Print("");
    // Print("========================================");
    // Print("ORDER CLASS ATM-RELATED METHODS");
    // Print("========================================");
    try
    {
        Type orderType = typeof(Order);
        var methods = orderType.GetMethods(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.Static);
        foreach (var m in methods)
        {
            string mName = m.Name.ToLower();
            if (mName.Contains("atm") || mName.Contains("strategy") || mName.Contains("owner") || mName.Contains("parent") || mName.Contains("attach"))
            {
                string parms = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                // Print(orderType.Name + "." + m.Name + "(" + parms + ") → " + m.ReturnType.Name + " [" + (m.IsPublic ? "public" : "non-public") + (m.IsStatic ? " static" : "") + "]");
            }
        }
        // Also check properties
        var props = orderType.GetProperties(System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
        foreach (var p in props)
        {
            string pName = p.Name.ToLower();
            if (pName.Contains("atm") || pName.Contains("strategy") || pName.Contains("owner") || pName.Contains("parent"))
                ; // Print(orderType.Name + "." + p.Name + " → " + p.PropertyType.Name + " [property]");
        }
    }
    catch { }
    
    // Print("");
    // Print("========================================");
    // Print("DISCOVERY COMPLETE");
    // Print("========================================");
}

private void DumpType(Type t, string label)
{
    // Print("");
    // Print("--- " + label + " (" + t.FullName + ") ---");
    
    // Non-public methods
    var methods = t.GetMethods(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.Static | System.Reflection.BindingFlags.DeclaredOnly);
    if (methods.Length > 0)
    {
        // Print("  METHODS (" + methods.Length + "):");
        foreach (var m in methods.OrderBy(m => m.Name))
        {
            string vis = m.IsPublic ? "public" : m.IsPrivate ? "private" : m.IsFamily ? "protected" : "internal";
            string stat = m.IsStatic ? " static" : "";
            string parms = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
            // Print("    " + vis + stat + " " + m.ReturnType.Name + " " + m.Name + "(" + parms + ")");
        }
    }
    
    // Non-public fields
    var fields = t.GetFields(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.Static | System.Reflection.BindingFlags.DeclaredOnly);
    if (fields.Length > 0)
    {
        // Print("  FIELDS (" + fields.Length + "):");
        foreach (var f in fields.OrderBy(f => f.Name))
        {
            string vis = f.IsPublic ? "public" : f.IsPrivate ? "private" : f.IsFamily ? "protected" : "internal";
            string stat = f.IsStatic ? " static" : "";
            // Print("    " + vis + stat + " " + f.FieldType.Name + " " + f.Name);
        }
    }
    
    // Non-public properties
    var props = t.GetProperties(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.Static | System.Reflection.BindingFlags.DeclaredOnly);
    if (props.Length > 0)
    {
        // Print("  PROPERTIES (" + props.Length + "):");
        foreach (var p in props.OrderBy(p => p.Name))
        {
            string get = p.CanRead ? "get" : "";
            string set = p.CanWrite ? "set" : "";
            // Print("    " + p.PropertyType.Name + " " + p.Name + " { " + get + (get != "" && set != "" ? "; " : "") + set + " }");
        }
    }
    
    // Events
    var events = t.GetEvents(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.Static | System.Reflection.BindingFlags.DeclaredOnly);
    if (events.Length > 0)
    {
        // Print("  EVENTS (" + events.Length + "):");
        foreach (var e in events.OrderBy(e => e.Name))
            ; // Print("    " + e.EventHandlerType.Name + " " + e.Name);
    }
}

private void DumpInstanceFields(object obj, string label)
{
    // if (obj == null) { Print(label + " is null"); return; }
    Type t = obj.GetType();
    // Print("  Instance fields for " + label + " (" + t.Name + "):");
    
    var fields = t.GetFields(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);
    foreach (var f in fields.OrderBy(f => f.Name))
    {
        try
        {
            object val = f.GetValue(obj);
            string valStr = val == null ? "null" : val.ToString();
            if (valStr.Length > 120) valStr = valStr.Substring(0, 120) + "...";
            // Print("    " + f.Name + " (" + f.FieldType.Name + ") = " + valStr);
        }
        catch
        {
            // Print("    " + f.Name + " (" + f.FieldType.Name + ") = <error reading>");
        }
    }
    
    var props = t.GetProperties(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);
    foreach (var p in props.OrderBy(p => p.Name))
    {
        if (!p.CanRead) continue;
        try
        {
            object val = p.GetValue(obj);
            string valStr = val == null ? "null" : val.ToString();
            if (valStr.Length > 120) valStr = valStr.Substring(0, 120) + "...";
            // Print("    " + p.Name + " (" + p.PropertyType.Name + ") = " + valStr);
        }
        catch
        {
            // Print("    " + p.Name + " (" + p.PropertyType.Name + ") = <error reading>");
        }
    }
}



				
		
