			// Swallow so the indicator keeps running and log for post-mortem.
			try
			{
				if (_diagLog != null)
				{
					string _stackFirst = "";
					try
					{
						string _stack = _oscex.StackTrace ?? "";
						var _lines = _stack.Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
						int _take = Math.Min(3, _lines.Length);
						var _buf = new System.Text.StringBuilder();
						for (int _i = 0; _i < _take; _i++) { if (_i > 0) _buf.Append(" // "); _buf.Append(_lines[_i]); }
						_stackFirst = _buf.ToString().Replace('|', ';');
					}
					catch { }
					_diagLog.Log("SYSTEM", "ONSTATECHANGE_ERR", "State=" + State + "|Msg=" + (_oscex.Message != null ? _oscex.Message.Replace('|', ';') : "") + "|Stack=" + _stackFirst);
				}
			}
			catch { }
		}
