								//continue;
							
								double movep = 0;
								
								
								if (or.Instrument.MarketData.Last.Price != null)									
									movep = or.Instrument.MarketData.Last.Price;
						
								
								if (movep != 0)
								if (orderprice == price)
								{
									
									if (or.IsLong) // above last price
										movep = movep + or.Instrument.MasterInstrument.TickSize*ticksabovemarket;
									else // below last price
										movep = movep - or.Instrument.MasterInstrument.TickSize*ticksabovemarket;
								
								
									MoveOrder(or, movep, 0, acct, 0);
									
								}
								
								
							}
							
							//acct.Cancel(new[] { or });	
						}

						
					}
				}
			
							
		}	
		
		
