			/// <summary>True if two ATM names refer to the same strategy for sync/move (exact match or normalized match so master/follower name variation still syncs).</summary>
			private bool AtmNamesMatchForSync(string nameA, string nameB)
			{
				if (string.IsNullOrEmpty(nameA) || string.IsNullOrEmpty(nameB)) return false;
				if (nameA == nameB) return true;
				try { return RemoveEndOfLiveATM(nameA) == RemoveEndOfLiveATM(nameB); } catch { return false; }
			}

			
		bool PrintScaleIn = false;
			
		
		/// <summary>True if order state should be counted when totalling ATM exit orders (avoids flicker during move/cancel).</summary>
		private static bool OrderStateCountedForATMTotal(OrderState state, bool includeTransitional)
		{
			if (state == OrderState.Working || state == OrderState.Accepted) return true;
			if (!includeTransitional) return false;
			return state == OrderState.ChangePending || state == OrderState.ChangeSubmitted
				|| state == OrderState.PartFilled || state == OrderState.TriggerPending;
		}

		/// <summary>
		/// Signed quantity of follower market orders that are live at the broker but
		/// not yet reflected in the account Position — entries/exits the copier just
		/// submitted that are still mid broker round-trip. The drift guard folds this
		/// into the live position so ordinary fill latency is not mistaken for tracker
		/// drift. Mirrors the in-flight accounting in FlattenInstrument.
		/// </summary>
		private static int GetInFlightFollowerQty(Account account, Instrument instrument)
		{
			if (account == null || instrument == null) return 0;
			int signed = 0;
			try
			{
				DateTime now = DateTime.Now;
				foreach (Order o in account.Orders.ToList())
				{
					// Compare by Instrument.Id, not reference: after a connection drop
					// NT can hand back a fresh Instrument instance for the same
					// contract, and reference-inequality here would hide a genuine
					// in-flight order from the drift guard - reintroducing the
					// stranded-follower bug on the next reconnect.
					if (o == null || o.Instrument == null || o.Instrument.Id != instrument.Id) continue;
					if (o.OrderType != OrderType.Market) continue;

					int qty = 0;
					if (o.OrderState == OrderState.Submitted
						|| o.OrderState == OrderState.Accepted
						|| o.OrderState == OrderState.Working
						|| o.OrderState == OrderState.PartFilled)
					{
						// Accepted by the broker, not yet (fully) filled.
						qty = o.Quantity - o.Filled;
					}
					else if (o.OrderState == OrderState.Filled
							&& o.Time != DateTime.MinValue
							&& (now - o.Time).TotalMilliseconds < 750)
					{
						// Just filled: NT can drop an order from its Working/Accepted
						// buckets a hair before the matching Position update lands.
						qty = o.Filled;
					}

					if (qty <= 0) continue;
					if (o.OrderAction == OrderAction.Sell || o.OrderAction == OrderAction.SellShort)
						signed -= qty;
					else
						signed += qty;
				}
			}
			catch { return 0; }
			return signed;
		}
		
		/// <summary>Sum total quantity of all target orders for this ATM on the master account.</summary>
		/// <param name="includeChangeStates">If true, also count ChangePending, ChangeSubmitted, PartFilled, TriggerPending.</param>
		private int GetMasterATMTotalTargetQty(AtmStrategy masterATM, bool includeChangeStates = false)
		{
			if (masterATM == null || CurrentMasterAccount == null) return 0;
			int total = 0;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				if (!OrderStateCountedForATMTotal(or.OrderState, includeChangeStates)) continue;
				if (!or.Name.Contains("Target")) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				total += or.Quantity;
			}
			return total;
		}
		
