		/// <param name="includeChangeStates">If true, also count ChangePending, ChangeSubmitted, PartFilled, TriggerPending.</param>
		private int GetMasterATMTotalStopQty(AtmStrategy masterATM, bool includeChangeStates = false)
		{
			if (masterATM == null || CurrentMasterAccount == null) return 0;
			int total = 0;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
