				if (!or.Name.Contains("Stop") || or.Name.Contains("Target")) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				total += or.Quantity;
			}
			return total;
		}
		
		/// <summary>True if master has any target order for this ATM in any non-terminal state (Initialized, Submitted, Working, etc.). Used so we don't cancel follower targets while master's are still being submitted.</summary>
		private bool MasterATMHasAnyTargetOrderInNonTerminalState(AtmStrategy masterATM)
		{
			if (masterATM == null || CurrentMasterAccount == null) return false;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				if (or.OrderState == OrderState.Cancelled || or.OrderState == OrderState.Rejected || or.OrderState == OrderState.Filled) continue;
				if (!or.Name.Contains("Target") || or.Name.Contains("Stop")) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				return true;
			}
			return false;
		}
		
