		/// <summary>True if master has any order with this bracket name in Initialized or Submitted (not yet Working). Used to avoid cancelling follower during race at entry.</summary>
		private bool MasterATMHasOrderInPendingState(AtmStrategy masterATM, string orderName)
		{
			if (masterATM == null || CurrentMasterAccount == null || string.IsNullOrEmpty(orderName)) return false;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				if (or.OrderState != OrderState.Initialized && or.OrderState != OrderState.Submitted) continue;
				if (or.Name != orderName) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				return true;
			}
			return false;
		}
		
		/// <summary>True if master has (or had) any order with this bracket name for this ATM in any state (Working, Cancelled, Filled, etc.). Used to tell scale-out (cancel follower) from "master hasn't submitted this bracket yet" (don't cancel).</summary>
		private bool MasterATMHasAnyOrderWithBracketName(AtmStrategy masterATM, string bracketName)
		{
			if (masterATM == null || CurrentMasterAccount == null || string.IsNullOrEmpty(bracketName)) return false;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				if (or.Name != bracketName) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				return true;
			}
			return false;
		}
		
		/// <summary>Distinct bracket order names (Target 1, Target 2, Stop 1, etc.) for this ATM on the master account.</summary>
		private List<string> GetMasterATMBracketOrderNames(AtmStrategy masterATM, bool includeTransitional = true)
		{
			var names = new HashSet<string>();
			if (masterATM == null || CurrentMasterAccount == null) return new List<string>();
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				if (!OrderStateCountedForATMTotal(or.OrderState, includeTransitional)) continue;
				if ((!or.Name.Contains("Target") && !or.Name.Contains("Stop")) || (or.Name.Contains("Target") && or.Name.Contains("Stop"))) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				names.Add(or.Name);
			}
			var list = new List<string>(names);
			list.Sort(StringComparer.Ordinal);
			return list;
		}
		
		/// <summary>Signature of master ATM exit order quantities (bracket name:qty,...). Used to only sync when quantities actually changed (e.g. new entry/scale), not on move.</summary>
		private string GetMasterATMExitOrdersSignature(AtmStrategy masterATM)
		{
			var names = GetMasterATMBracketOrderNames(masterATM, true);
			var parts = new List<string>();
			foreach (string name in names)
			{
				int qty = GetMasterATMTotalQtyForOrderName(masterATM, name, true);
				parts.Add(name + ":" + qty);
			}
			return string.Join(",", parts);
		}
		
		private Dictionary<string, string> LastATMExitOrdersSignature = new Dictionary<string, string>();
		
		/// <summary>Sum quantity of all master ATM orders with the same bracket name (e.g. "Target 1", "Stop 1"). Use for move/sync so follower qty matches this bracket.</summary>
		/// <param name="includeTransitional">If true, count ChangePending, ChangeSubmitted, PartFilled, TriggerPending.</param>
		private int GetMasterATMTotalQtyForOrderName(AtmStrategy masterATM, string orderName, bool includeTransitional = true)
		{
			if (masterATM == null || CurrentMasterAccount == null || string.IsNullOrEmpty(orderName)) return 0;
			int total = 0;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				if (!OrderStateCountedForATMTotal(or.OrderState, includeTransitional)) continue;
				if (or.Name != orderName) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				total += or.Quantity;
			}
			return total;
		}
		
		/// <summary>Sum quantity of all target orders for this ATM at the given price (same price = same limit level).</summary>
		private int GetMasterATMTotalTargetQtyAtPrice(AtmStrategy masterATM, Instrument instrument, double atPrice, bool includeChangeStates = false)
		{
			if (masterATM == null || CurrentMasterAccount == null || instrument == null) return 0;
			double tick = instrument.MasterInstrument.TickSize;
			double tol = Math.Max(tick * 0.5, 1e-10);
			int total = 0;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				if (!OrderStateCountedForATMTotal(or.OrderState, includeChangeStates)) continue;
				if (!or.Name.Contains("Target")) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				if (Math.Abs(or.LimitPrice - atPrice) > tol) continue;
				total += or.Quantity;
			}
			return total;
		}
		
		/// <summary>Sum quantity of all stop orders for this ATM at the given price (same price = same stop level).</summary>
		private int GetMasterATMTotalStopQtyAtPrice(AtmStrategy masterATM, Instrument instrument, double atPrice, bool includeChangeStates = false)
		{
			if (masterATM == null || CurrentMasterAccount == null || instrument == null) return 0;
			double tick = instrument.MasterInstrument.TickSize;
			double tol = Math.Max(tick * 0.5, 1e-10);
			int total = 0;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				if (!OrderStateCountedForATMTotal(or.OrderState, includeChangeStates)) continue;
				if (!or.Name.Contains("Stop") || or.Name.Contains("Target")) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				if (Math.Abs(or.StopPrice - atPrice) > tol) continue;
				total += or.Quantity;
			}
			return total;
		}
		
