		}
		
		/// <summary>Cancel any working/accepted ATM stop and target orders on the account for the instrument. Call when follower position goes flat to avoid lingering exit orders.</summary>
		private void CancelOrphanATMExitOrdersForInstrument(Account account, Instrument instrument)
		{
			if (account == null || instrument == null) return;
			if (_diagLog != null)
				_diagLog.Log("ACTION", "CANCEL_ORPHAN_ATM_EXITS", "Account=" + account.Name + "|Instrument=" + instrument.FullName);
			List<Order> toCancel = new List<Order>();
			foreach (Order or in account.Orders.ToList())
			{
				if (or.Instrument == null || instrument == null || or.Instrument.Id != instrument.Id) continue;
				if (or.OrderState != OrderState.Working && or.OrderState != OrderState.Accepted && or.OrderState != OrderState.TriggerPending) continue;
				if (!or.Name.Contains("Target") && !or.Name.Contains("Stop")) continue;
				if (or.Name.Contains("Target") && or.Name.Contains("Stop")) continue;
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				toCancel.Add(or);
			}
			if (toCancel.Count > 0)
			{
				account.Cancel(toCancel.ToArray());
				//Print("Cancel 2");
			}
		}
		
		/// <summary>Single entry point: sync all followers' ATM exit orders (target + stop) to master totals and prices. Only runs when master bracket quantities have changed (new entry/scale), not when user only moves a target.</summary>
		private void SyncATMStrategyExitOrdersToAllFollowers(Order masterOrder)
		{
			if (masterOrder == null || masterOrder.Account != CurrentMasterAccount) return;
			object atmObj = masterOrder.GetOwnerStrategy();
			if (atmObj == null || atmObj.GetType() != typeof(AtmStrategy)) return;
			AtmStrategy masterATM = (AtmStrategy)atmObj;
			Instrument instrument = masterOrder.Instrument;
			string atmName = masterATM.DisplayNameExtended ?? masterATM.DisplayName ?? "";
			if (string.IsNullOrEmpty(atmName)) return;
			// Key by instrument + atmName so multiple ATM instances (same or different templates) are tracked separately
			string atmSignatureKey = instrument.FullName + "|" + atmName;
			string currentSignature = GetMasterATMExitOrdersSignature(masterATM);
			string lastSignature;
			if (currentSignature.Length > 0 && LastATMExitOrdersSignature.TryGetValue(atmSignatureKey, out lastSignature) && lastSignature == currentSignature)
				return; // Quantities unchanged (e.g. user only moved a target); don't overwrite follower quantities
			LastATMExitOrdersSignature[atmSignatureKey] = currentSignature;
			foreach (string acctName in AllDuplicateAccounts)
			{
				Account follower = AccountFromName(acctName);
				if (follower == null || follower.ConnectionStatus != ConnectionStatus.Connected) continue;
				if (follower == CurrentMasterAccount) continue;
				SyncFollowerExitOrdersToMasterTotals(follower, atmName, masterATM, instrument);
			}
		}

		/// <summary>Get the OCO of any order belonging to this master ATM (used to isolate same-name ATM instances so we only sync the same instance's follower orders).</summary>
		private string GetMasterATMOco(AtmStrategy masterATM)
		{
			if (masterATM == null || CurrentMasterAccount == null) return string.Empty;
			foreach (Order or in CurrentMasterAccount.Orders.ToList())
			{
				object oo = or.GetOwnerStrategy();
				if (oo == null || oo.GetType() != typeof(AtmStrategy)) continue;
				if ((AtmStrategy)oo != masterATM) continue;
				if (!string.IsNullOrEmpty(or.Oco)) return or.Oco;
			}
			return string.Empty;
		}

		/// <summary>Count how many ATM strategies on the master account have the same display name (exact or normalized). Used to apply OCO filter only when multiple same-name instances exist.</summary>
		private int CountMasterATMsWithName(string atmName)
		{
			if (CurrentMasterAccount == null || string.IsNullOrEmpty(atmName)) return 0;
			int count = 0;
			foreach (object aaa in CurrentMasterAccount.Strategies.ToList())
			{
				if (aaa == null || aaa.GetType() != typeof(AtmStrategy)) continue;
				AtmStrategy atm = (AtmStrategy)aaa;
				string name = atm.DisplayNameExtended ?? atm.DisplayName ?? "";
				if (AtmNamesMatchForSync(name, atmName)) count++;
			}
			return count;
		}

		/// <summary>When multiple same-name ATMs exist, match master order to follower order by position (same index in sorted lists). Handles different fill prices between master and follower.</summary>
		private Order GetFollowerOrderByIndexMatch(Account followerAccount, Instrument instrument, Order masterOrder, string masterAtmName, bool orderStateOkForMove)
		{
			if (CurrentMasterAccount == null || followerAccount == null || masterOrder == null || string.IsNullOrEmpty(masterAtmName)) return null;
			string orderName = masterOrder.Name;
			// Build master list: same instrument, same bracket name, same ATM name
			List<Order> masterList = new List<Order>();
			foreach (Order o in CurrentMasterAccount.Orders.ToList())
			{
				if (o.Instrument == null || instrument == null || o.Instrument.Id != instrument.Id || o.Name != orderName) continue;
				object owner = o.GetOwnerStrategy();
				if (owner == null || owner.GetType() != typeof(AtmStrategy)) continue;
				string n = ((AtmStrategy)owner).DisplayNameExtended ?? ((AtmStrategy)owner).DisplayName ?? "";
				if (!AtmNamesMatchForSync(n, masterAtmName)) continue;
				masterList.Add(o);
			}
			masterList.Sort((a, b) => a.Id.CompareTo(b.Id));
			int masterIndex = masterList.IndexOf(masterOrder);
			if (masterIndex < 0) return null;
			// Build follower list: same instrument, same bracket name, same ATM name, acceptable state
			List<Order> followerList = new List<Order>();
			foreach (Order o in followerAccount.Orders.ToList())
			{
				if (o.Instrument == null || instrument == null || o.Instrument.Id != instrument.Id || o.Name != orderName) continue;
				if (orderStateOkForMove && o.OrderState != OrderState.Accepted && o.OrderState != OrderState.Working && o.OrderState != OrderState.TriggerPending && o.OrderState != OrderState.PartFilled) continue;
				object owner = o.GetOwnerStrategy();
				if (owner == null || owner.GetType() != typeof(AtmStrategy)) continue;
				string n = ((AtmStrategy)owner).DisplayNameExtended ?? ((AtmStrategy)owner).DisplayName ?? "";
				if (!AtmNamesMatchForSync(n, masterAtmName)) continue;
				followerList.Add(o);
			}
			followerList.Sort((a, b) => a.Id.CompareTo(b.Id));
			if (masterIndex >= followerList.Count) return null;
			return followerList[masterIndex];
		}
		
		/// <summary>Sync follower's target/stop orders to master totals by bracket name (e.g. "Target 1" → total of all master "Target 1" for this ATM). Only touches follower orders for the same instance (same OCO) when multiple ATMs share the same name.</summary>
		private void SyncFollowerExitOrdersToMasterTotals(Account followerAccount, string atmName, AtmStrategy masterATM, Instrument instrument)
		{
			if (masterATM == null || followerAccount == null || string.IsNullOrEmpty(atmName)) return;
			if (_diagLog != null)
				_diagLog.Log("COPIER", "SYNC_FOLLOWER_EXITS", "Follower=" + followerAccount.Name + "|ATM=" + atmName + "|Instrument=" + (instrument != null ? instrument.FullName : "?"));
			string masterOco = GetMasterATMOco(masterATM);
			bool multipleInstancesSameName = CountMasterATMsWithName(atmName) > 1;
			double mult = Convert.ToDouble(GetAccountMultiplier(followerAccount.Name));
			if (mult == 0) mult = 0.50;
			if (mult == -1) mult = 0.33;
			if (mult == -2) mult = 0.25;
			if (mult == -3) mult = 0.20;
			List<Order> followerTargetOrders = new List<Order>();
			List<Order> followerStopOrders = new List<Order>();
			foreach (Order or in followerAccount.Orders.ToList())
			{
				if (or.Instrument == null || instrument == null || or.Instrument.Id != instrument.Id) continue;
				// Include PartFilled — partially filled exit orders still need qty sync
				if (or.OrderState != OrderState.Working && or.OrderState != OrderState.Accepted && or.OrderState != OrderState.PartFilled) continue;
				object aaaa = or.GetOwnerStrategy();
				AtmStrategy slaveATM = null;
				if (aaaa != null && aaaa.GetType() == typeof(AtmStrategy))
					slaveATM = (AtmStrategy)aaaa;
				if (slaveATM == null) continue;
				// Match by ATM name (exact or normalized) so we sync the same strategy; normalized allows master/follower display name variation
				string slaveAtmFullName = slaveATM.DisplayNameExtended ?? slaveATM.DisplayName ?? "";
				if (!AtmNamesMatchForSync(slaveAtmFullName, atmName)) continue;
				// Only filter by OCO when master has multiple ATMs with same name (separate instances); when scaling in, follower orders may have platform OCO so we match by name only
				if (multipleInstancesSameName && !string.IsNullOrEmpty(masterOco) && (string.IsNullOrEmpty(or.Oco) || !or.Oco.StartsWith(masterOco)))
					continue;
				if (or.Name.Contains("Target") && !or.Name.Contains("Stop"))
					followerTargetOrders.Add(or);
				else if (or.Name.Contains("Stop") && !or.Name.Contains("Target"))
					followerStopOrders.Add(or);
			}
			// Group by bracket name (Target 1, Target 2, Target 3, Stop 1, etc.) so each bracket is synced separately — do not collapse multiple targets into one.
			Dictionary<string, List<Order>> targetByBracket = new Dictionary<string, List<Order>>();
			foreach (Order or in followerTargetOrders)
			{
				string name = or.Name;
				if (!targetByBracket.ContainsKey(name)) targetByBracket[name] = new List<Order>();
				targetByBracket[name].Add(or);
			}
			foreach (var kvp in targetByBracket)
			{
				string bracketName = kvp.Key;
				List<Order> orders = kvp.Value;
				int masterTotalForBracket = GetMasterATMTotalQtyForOrderName(masterATM, bracketName, true);
				int followerTargetQty = pMultiplierMode == "Multiplier" ? (int)Math.Round(masterTotalForBracket * mult, MidpointRounding.AwayFromZero) : masterTotalForBracket * (int)mult;
				followerTargetQty = Math.Max(followerTargetQty, 0);
				// When master has position, fractional multiplier (e.g. 1/2x) must not round to 0 and cancel follower's target/stop
				if (masterTotalForBracket >= 1 && followerTargetQty <= 0) followerTargetQty = 1;
				if (followerTargetQty <= 0)
				{
					// Cancel when scale-out: master has 0 qty for this bracket, no Pending order, AND master has/had this bracket (so not "Target 3+ not yet submitted on master")
					if (!MasterATMHasOrderInPendingState(masterATM, bracketName) && MasterATMHasAnyOrderWithBracketName(masterATM, bracketName))
					{
						followerAccount.Cancel(orders.ToArray());
						//Print("Cancel 3");
					}
				}
				else
				{
					MoveOrder(orders[0], 0, 0, followerAccount, followerTargetQty);
					for (int i = 1; i < orders.Count; i++)
					{
						//Print("Cancel 4");
						followerAccount.Cancel(new[] { orders[i] });
					}
				}
			}
			Dictionary<string, List<Order>> stopByBracket = new Dictionary<string, List<Order>>();
			foreach (Order or in followerStopOrders)
			{
				string name = or.Name;
				if (!stopByBracket.ContainsKey(name)) stopByBracket[name] = new List<Order>();
				stopByBracket[name].Add(or);
			}
			foreach (var kvp in stopByBracket)
			{
				string bracketName = kvp.Key;
				List<Order> orders = kvp.Value;
				int masterTotalForBracket = GetMasterATMTotalQtyForOrderName(masterATM, bracketName, true);
				int followerStopQty = pMultiplierMode == "Multiplier" ? (int)Math.Round(masterTotalForBracket * mult, MidpointRounding.AwayFromZero) : masterTotalForBracket * (int)mult;
				followerStopQty = Math.Max(followerStopQty, 0);
				// When master has position, fractional multiplier (e.g. 1/2x) must not round to 0 and cancel follower's target/stop
				if (masterTotalForBracket >= 1 && followerStopQty <= 0) followerStopQty = 1;
				if (followerStopQty <= 0)
				{
					// Cancel when scale-out: master has 0 qty for this bracket, no Pending order, AND master has/had this bracket (so not "Stop 3+ not yet submitted on master")
					if (!MasterATMHasOrderInPendingState(masterATM, bracketName) && MasterATMHasAnyOrderWithBracketName(masterATM, bracketName))
					{
						followerAccount.Cancel(orders.ToArray());
						//Print("Cancel 6");
					}
				}
				else
				{
					MoveOrder(orders[0], 0, 0, followerAccount, followerStopQty);
					for (int i = 1; i < orders.Count; i++)
					{
						followerAccount.Cancel(new[] { orders[i] });
						//Print("Cancel 5");
					}
				}
			}
		}
		
		/// <summary>Set follower target/stop order quantity to match master (for scale-out quantity changes).</summary>
		private void ChangeExitOrderQty (Account accccc, string atmn, Order oooooo, bool setToMasterQuantity)
		{
			if (!setToMasterQuantity) return;
			string thisnn = oooooo.Name;
			double SlaveExMultiplier = Convert.ToDouble(GetAccountMultiplier(accccc.Name));
			if (SlaveExMultiplier == 0) SlaveExMultiplier = 0.50;
			if (SlaveExMultiplier == -1) SlaveExMultiplier = 0.33;
			if (SlaveExMultiplier == -2) SlaveExMultiplier = 0.25;
			if (SlaveExMultiplier == -3) SlaveExMultiplier = 0.20;
			int targetFollowerQty;
			if (pMultiplierMode == "Multiplier")
				targetFollowerQty = (int)Math.Round(oooooo.Quantity * SlaveExMultiplier);
			else
				targetFollowerQty = oooooo.Quantity * (int)SlaveExMultiplier;
			targetFollowerQty = Math.Max(targetFollowerQty, 0);
			foreach (Order or in accccc.Orders.ToList())
			{
				if (or.Name != thisnn) continue;
				if (or.OrderState != OrderState.Working && or.OrderState != OrderState.Accepted) continue;
				object aaaa = or.GetOwnerStrategy();
				AtmStrategy SlaveATM = null;
				if (aaaa != null && aaaa.GetType() == typeof(AtmStrategy))
					SlaveATM = (AtmStrategy)aaaa;
				if (SlaveATM == null) continue;
				// Match ATM (exact or normalized) so we only adjust exit orders for the same strategy
				string slaveAtmFullName = SlaveATM.DisplayNameExtended ?? SlaveATM.DisplayName ?? "";
				if (!AtmNamesMatchForSync(slaveAtmFullName, atmn)) continue;
				if (targetFollowerQty <= 0)
				{
					accccc.Cancel(new[] { or });
					//Print("Cancel 7");
					break;
				}
				MoveOrder(or, 0, 0, accccc, targetFollowerQty);
				break;
			}
		}
		
