		private void CancelOrdersAtPrice (double price)
		{


				foreach (Account acct in Account.All.ToList())
				{
					// Smart Sync Cancel click: only act on copier accounts
					// (master + followers). Do not cancel orders on unrelated
					// NT8 accounts that happen to have an order at the clicked price.
					if (acct != CurrentMasterAccount && !AllDuplicateAccounts.Contains(acct.Name))
						continue;

						foreach (Order or in acct.Orders.ToList())
								{
									if (or.OrderType != OrderType.Market)
									{
										double orderprice = or.LimitPrice;
										
										if (or.StopPrice != 0)
											orderprice = or.StopPrice;
										
										if (orderprice == price)
										{
											acct.Cancel(new[] { or });
											
											//Print("Cancel 9");
										}
									}
									
									
									
									
								}
				}
			
							
		} 
		
