				private string GetAccountPrefix(string accountName)
				{
					if (string.IsNullOrEmpty(accountName))
						return accountName;

					int i = accountName.Length - 1;

					// Strip trailing digits
					while (i >= 0 && char.IsDigit(accountName[i]))
						i--;

					// Strip trailing separators
					while (i >= 0 && (accountName[i] == '-' || accountName[i] == '_' || accountName[i] == ' '))
						i--;

					// If everything was digits, return the full name
					if (i < 0)
						return accountName;

					return accountName.Substring(0, i + 1);
				}

				private const string SimulatedAccountsTotalRowName = "Sim Accounts";

				private bool IsSimulationAccountForTotalRows(PNLStatistics stats)
				{
					return stats != null && stats.Acct != null && stats.Acct.Provider == Provider.Simulator;
				}

				private bool ShouldExcludeAccountFromTotalRows(PNLStatistics stats)
				{
					return pTotalRowsExcludeSimulationAccounts && IsSimulationAccountForTotalRows(stats);
				}

				private string GetTotalRowGroupKey(PNLStatistics stats)
				{
					if (stats == null)
						return string.Empty;

					if (IsSimulationAccountForTotalRows(stats))
					{
						if (pTotalRowsExcludeSimulationAccounts)
							return string.Empty;

						if (pTotalRowsCombineSimulationAccounts)
							return SimulatedAccountsTotalRowName;
					}

					return GetAccountPrefix(stats.PrivateName);
				}

				// Map TotalRowN signal key to its slot index in autoGroupPrefixes / autoGroupGhost.
				// Returns -1 for TotalRow4 (Grand Total) or an unrecognised key.
				private int TotalRowKeyToSlot(string totalRowKey)
				{
					if (totalRowKey == "TotalRow1") return 0;
					if (totalRowKey == "TotalRow2") return 1;
					if (totalRowKey == "TotalRow3") return 2;
					if (totalRowKey == "TotalRow5") return 3;
					if (totalRowKey == "TotalRow6") return 4;
					if (totalRowKey == "TotalRow7") return 5;
					if (totalRowKey == "TotalRow8") return 6;
					if (totalRowKey == "TotalRow9") return 7;
					if (totalRowKey == "TotalRow10") return 8;
					if (totalRowKey == "TotalRow11") return 9;
					if (totalRowKey == "TotalRow12") return 10;
					if (totalRowKey == "TotalRow13") return 11;
					return -1;
				}

				// True when the total row at the given signal key is a "ghost" — a hidden
				// group being surfaced inline while the restore UI is open.
				private bool IsGhostTotalRow(string totalRowKey)
				{
					int slot = TotalRowKeyToSlot(totalRowKey);
					if (slot < 0) return false;
					return slot < autoGroupGhost.Length && autoGroupGhost[slot];
				}

				// Launches the inline "Rename Group" dialog for a given total row signal key.
				// Shared by the Actions-column "edit" hover button and the click-on-name path.
				private void OpenTotalRowRenameDialog(string totalRowKey)
				{
					string _currentLabel = "";
					if      (totalRowKey == "TotalRow1")  _currentLabel = Total1Name;
					else if (totalRowKey == "TotalRow2")  _currentLabel = Total2Name;
					else if (totalRowKey == "TotalRow3")  _currentLabel = Total3Name;
					else if (totalRowKey == "TotalRow4")  _currentLabel = Total4Name2;
					else if (totalRowKey == "TotalRow5")  _currentLabel = Total5Name;
					else if (totalRowKey == "TotalRow6")  _currentLabel = Total6Name;
					else if (totalRowKey == "TotalRow7")  _currentLabel = Total7Name;
					else if (totalRowKey == "TotalRow8")  _currentLabel = Total8Name;
					else if (totalRowKey == "TotalRow9")  _currentLabel = Total9Name;
					else if (totalRowKey == "TotalRow10") _currentLabel = Total10Name;
					else if (totalRowKey == "TotalRow11") _currentLabel = Total11Name;
					else if (totalRowKey == "TotalRow12") _currentLabel = Total12Name;
					else if (totalRowKey == "TotalRow13") _currentLabel = Total13Name;
					else return;

					ChartControl.Dispatcher.InvokeAsync(() =>
					{
						string newName = null;     // null = dialog cancelled; "" = explicit reset
						bool   _submitted = false; // OK / Enter / Reset all set this true
						NTWindow _renameWin = new NTWindow { Caption = "Rename Total Row", Width = 300, Height = 160, WindowStartupLocation = WindowStartupLocation.CenterScreen, ResizeMode = ResizeMode.NoResize, Topmost = true };
						try { _renameWin.Owner = Window.GetWindow(ChartControl.Parent); } catch { }

						StackPanel _sp = new StackPanel { Margin = new Thickness(12) };
						_sp.Children.Add(new TextBlock { Text = "Total Row Label:", Margin = new Thickness(0, 0, 0, 8), Foreground = System.Windows.Media.Brushes.White });
						TextBox _tb = new TextBox { Text = _currentLabel };
						_tb.SelectAll();
						_sp.Children.Add(_tb);

						// Bottom row: italic "reset" link on the left (matches the Prop Firm
						// Configuration window's reset link), OK button on the right.
						Grid _bottom = new Grid { Margin = new Thickness(0, 10, 0, 0) };
						_bottom.ColumnDefinitions.Add(new ColumnDefinition { Width = new GridLength(1, GridUnitType.Star) });
						_bottom.ColumnDefinitions.Add(new ColumnDefinition { Width = GridLength.Auto });

						TextBlock _resetLink = new TextBlock
						{
							FontSize = 12,
							VerticalAlignment = VerticalAlignment.Center,
							HorizontalAlignment = HorizontalAlignment.Left,
							Cursor = Cursors.Hand
						};
						Run _resetRun = new Run("reset") { FontStyle = FontStyles.Italic, Foreground = GetTextColor(Brushes.Transparent) };
						_resetLink.Inlines.Add(_resetRun);
						_resetLink.MouseEnter += (s2, e2) =>
						{
							Brush _tb2 = GetTextColor(Brushes.Transparent);
							Color _sc = (_tb2 is SolidColorBrush) ? ((SolidColorBrush)_tb2).Color : Colors.Gray;
							_resetLink.Effect = new DropShadowEffect { Color = _sc, BlurRadius = 10, ShadowDepth = 0, Opacity = 0.8 };
						};
						_resetLink.MouseLeave += (s2, e2) => { _resetLink.Effect = null; };
						_resetLink.MouseLeftButtonDown += (s2, e2) =>
						{
							// Populate the field with the row's default label and keep the
							// window open — the user still has to click OK / Enter to commit.
							// Default = current auto prefix (auto-group mode), the filter
							// string (non-auto mode), or "Total" for the Grand Total row.
							string _defaultLabel = "";
							int _resetSlot = TotalRowKeyToSlot(totalRowKey);
							if (totalRowKey == "TotalRow4")
							{
								_defaultLabel = "Total";
							}
							else if (pAutoGroupAccounts && _resetSlot >= 0 && _resetSlot < autoGroupPrefixes.Length)
							{
								_defaultLabel = autoGroupPrefixes[_resetSlot];
							}
							else
							{
								if      (totalRowKey == "TotalRow1")  _defaultLabel = pTotal1Filter;
								else if (totalRowKey == "TotalRow2")  _defaultLabel = pTotal2Filter;
								else if (totalRowKey == "TotalRow3")  _defaultLabel = pTotal3Filter;
								else if (totalRowKey == "TotalRow5")  _defaultLabel = pTotal5Filter;
								else if (totalRowKey == "TotalRow6")  _defaultLabel = pTotal6Filter;
								else if (totalRowKey == "TotalRow7")  _defaultLabel = pTotal7Filter;
								else if (totalRowKey == "TotalRow8")  _defaultLabel = pTotal8Filter;
								else if (totalRowKey == "TotalRow9")  _defaultLabel = pTotal9Filter;
								else if (totalRowKey == "TotalRow10") _defaultLabel = pTotal10Filter;
								else if (totalRowKey == "TotalRow11") _defaultLabel = pTotal11Filter;
								else if (totalRowKey == "TotalRow12") _defaultLabel = pTotal12Filter;
								else if (totalRowKey == "TotalRow13") _defaultLabel = pTotal13Filter;
							}
							_tb.Text = _defaultLabel ?? "";
							_tb.SelectAll();
							_tb.Focus();
							e2.Handled = true;
						};
						Grid.SetColumn(_resetLink, 0);
						_bottom.Children.Add(_resetLink);

						Button _okBtn = new Button { Content = "OK", Width = 70 };
						_okBtn.Click += (s2, e2) => { newName = _tb.Text; _submitted = true; _renameWin.Close(); };
						Grid.SetColumn(_okBtn, 1);
						_bottom.Children.Add(_okBtn);

						_tb.KeyDown += (s2, e2) => { if (e2.Key == System.Windows.Input.Key.Enter) { newName = _tb.Text; _submitted = true; _renameWin.Close(); } };

						_sp.Children.Add(_bottom);
						_renameWin.Content = _sp;
						_renameWin.ShowDialog();

						// Only act on explicit submission (OK / Enter / Reset). Closing the
						// window without one of those leaves newName == null and skips the
						// whole block, so accidentally-closed dialogs don't wipe the label.
						if (_submitted && newName != null && newName != _currentLabel)
						{
							string trimmed = newName.Trim();

							if (totalRowKey == "TotalRow4")
							{
								// Grand Total is not auto-grouped; preserve the legacy direct-write
								// path. Blank input resets to the default "Total".
								pTotal4Name = trimmed;
								Total4Name = string.IsNullOrEmpty(trimmed) ? "Total" : trimmed;
							}
							else
							{
								int slot = TotalRowKeyToSlot(totalRowKey);
								if (pAutoGroupAccounts && slot >= 0 && slot < autoGroupPrefixes.Length)
								{
									// Auto-group mode: keyed by prefix so the rename follows the
									// group even when account membership reshuffles slot order.
									string prefix = autoGroupPrefixes[slot];
									if (string.IsNullOrEmpty(trimmed))
										_totalRowRenames.Remove(prefix);  // blank = reset to default (the prefix)
									else
										_totalRowRenames[prefix] = trimmed;
									SerializeTotalRowRenameMap();
									ApplyResolvedSlotName(slot, ResolveAutoSlotName(prefix));
								}
								else
								{
									// Non-auto mode (or slot beyond current prefix count): write
									// directly to the backing field. Blank resets to the filter
									// fallback for immediate display.
									string fallback = trimmed;
									if (string.IsNullOrEmpty(trimmed))
									{
										if      (totalRowKey == "TotalRow1")  fallback = pTotal1Filter;
										else if (totalRowKey == "TotalRow2")  fallback = pTotal2Filter;
										else if (totalRowKey == "TotalRow3")  fallback = pTotal3Filter;
										else if (totalRowKey == "TotalRow5")  fallback = pTotal5Filter;
										else if (totalRowKey == "TotalRow6")  fallback = pTotal6Filter;
										else if (totalRowKey == "TotalRow7")  fallback = pTotal7Filter;
										else if (totalRowKey == "TotalRow8")  fallback = pTotal8Filter;
										else if (totalRowKey == "TotalRow9")  fallback = pTotal9Filter;
										else if (totalRowKey == "TotalRow10") fallback = pTotal10Filter;
										else if (totalRowKey == "TotalRow11") fallback = pTotal11Filter;
										else if (totalRowKey == "TotalRow12") fallback = pTotal12Filter;
										else if (totalRowKey == "TotalRow13") fallback = pTotal13Filter;
									}
									if      (totalRowKey == "TotalRow1")  { pTotal1Name  = trimmed; Total1Name  = fallback; }
									else if (totalRowKey == "TotalRow2")  { pTotal2Name  = trimmed; Total2Name  = fallback; }
									else if (totalRowKey == "TotalRow3")  { pTotal3Name  = trimmed; Total3Name  = fallback; }
									else if (totalRowKey == "TotalRow5")  { pTotal5Name  = trimmed; Total5Name  = fallback; }
									else if (totalRowKey == "TotalRow6")  { pTotal6Name  = trimmed; Total6Name  = fallback; }
									else if (totalRowKey == "TotalRow7")  { pTotal7Name  = trimmed; Total7Name  = fallback; }
									else if (totalRowKey == "TotalRow8")  { pTotal8Name  = trimmed; Total8Name  = fallback; }
									else if (totalRowKey == "TotalRow9")  { pTotal9Name  = trimmed; Total9Name  = fallback; }
									else if (totalRowKey == "TotalRow10") { pTotal10Name = trimmed; Total10Name = fallback; }
									else if (totalRowKey == "TotalRow11") { pTotal11Name = trimmed; Total11Name = fallback; }
									else if (totalRowKey == "TotalRow12") { pTotal12Name = trimmed; Total12Name = fallback; }
									else if (totalRowKey == "TotalRow13") { pTotal13Name = trimmed; Total13Name = fallback; }
								}
							}
							ForceRefresh();
						}
					});
				}

				// Reverse mapping from a slot index (0..11) back to the TotalRowN signal key.
				// Used by the click-on-name path: the Account cell rect stores the prefix,
				// which we look up in autoGroupPrefixes to get the slot, then convert.
				private string SlotToTotalRowKey(int slot)
				{
					switch (slot)
					{
						case 0:  return "TotalRow1";
						case 1:  return "TotalRow2";
						case 2:  return "TotalRow3";
						case 3:  return "TotalRow5";  // slot 3 skips Grand Total
						case 4:  return "TotalRow6";
						case 5:  return "TotalRow7";
						case 6:  return "TotalRow8";
						case 7:  return "TotalRow9";
						case 8:  return "TotalRow10";
						case 9:  return "TotalRow11";
						case 10: return "TotalRow12";
						case 11: return "TotalRow13";
						default: return null;
					}
				}



