private async Task<List<PropFirmAccountConfig>> LoadConfigsFromGoogleSheets()
{
    if (_diagLog != null)
        _diagLog.Log("CONFIG", "GOOGLE_SHEETS_LOAD", "URL=" + (GoogleSheetsUrl ?? "none"));

    List<PropFirmAccountConfig> configs = new List<PropFirmAccountConfig>();

    if (string.IsNullOrEmpty(GoogleSheetsUrl))
    {
        if (PrintGoogleSheet) Print("Google Sheets URL is not configured.");
        return null;
    }
    
    string csvData = null;
    
    if (ShouldReloadFromGoogleSheets())
    {
        try
        {
            // Use handler with system proxy so VPS/corporate setups can reach the internet; TLS set at indicator startup
            var handler = new HttpClientHandler();
            try
            {
                handler.UseProxy = true;
                handler.Proxy = System.Net.WebRequest.GetSystemWebProxy();
                handler.DefaultProxyCredentials = System.Net.CredentialCache.DefaultNetworkCredentials;
            }
            catch { handler.UseProxy = false; }
            using (HttpClient client = new HttpClient(handler))
            {
                client.Timeout = TimeSpan.FromSeconds(45);
                client.DefaultRequestHeaders.TryAddWithoutValidation("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36");
                
                string urlWithCacheBust = GoogleSheetsUrl;
                if (GoogleSheetsUrl.Contains("?"))
                {
                    urlWithCacheBust += "&cachebust=" + DateTime.Now.Ticks;
                }
                else
                {
                    urlWithCacheBust += "?cachebust=" + DateTime.Now.Ticks;
                }
                
                // Create request message with proper headers
                HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Get, urlWithCacheBust);
                
                // Set cache control headers on the request
                request.Headers.CacheControl = new System.Net.Http.Headers.CacheControlHeaderValue
                {
                    NoCache = true,
                    NoStore = true,
                    MaxAge = TimeSpan.Zero,
                    MustRevalidate = true
                };
                request.Headers.Add("Pragma", "no-cache");
                
                if (PrintGoogleSheet) Print("📥 Downloading fresh configurations from Google Sheets...");
                
                // Use SendAsync instead of GetStringAsync. HttpResponseMessage
                // is IDisposable and holds the response stream — wrap in using
                // so each call deterministically releases its handle (drip-leak
                // hygiene from the 2026-04-09 audit).
                using (HttpResponseMessage response = await client.SendAsync(request))
                {
                    response.EnsureSuccessStatusCode();
                    csvData = await response.Content.ReadAsStringAsync();

                    if (string.IsNullOrEmpty(csvData))
                    {
                        if (PrintGoogleSheet) Print("⚠ Downloaded data is empty, using cached data");
                        csvData = pCachedCSVData;
                    }
                    else
                    {
                        pCachedCSVData = csvData;
                        pLastLoadTimestamp = DateTime.Now;
                        if (PrintGoogleSheet) Print($"💾 Saved to cache (Size: {csvData.Length} bytes, Time: {pLastLoadTimestamp:g})");
                    }
                }
            }
        }
        catch (HttpRequestException ex)
        {
            if (PrintGoogleSheet) Print($"❌ Failed to download: {ex.Message}");
            if (PrintGoogleSheet) Print("📂 Using cached data...");
            csvData = pCachedCSVData;
        }
        catch (Exception ex)
        {
            if (PrintGoogleSheet) Print($"❌ Error: {ex.Message}");
            if (PrintGoogleSheet) Print("📂 Using cached data...");
            csvData = pCachedCSVData;
        }
    }
    else
    {
        if (PrintGoogleSheet) Print("📂 Using cached data (no download needed)");
        csvData = pCachedCSVData;
    }
    
    if (string.IsNullOrEmpty(csvData))
    {
        if (PrintGoogleSheet) Print("❌ No CSV data available");
        return null;
    }
    
    // Parse CSV data
    try
    {
        string[] lines = csvData.Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
        
        if (lines.Length < 2)
        {
            if (PrintGoogleSheet) Print("❌ CSV file has no data rows");
            return null;
        }
        
        int successCount = 0;
        int errorCount = 0;
        int skippedCount = 0;
        
for (int i = 1; i < lines.Length; i++)
{
    try
    {
        string[] fields = ParseCSVLine(lines[i]);
        
        if (fields.Length < 12)
        {
            if (PrintGoogleSheet) Print($"WARNING: Row {i + 1} has insufficient columns ({fields.Length}/12 minimum). Skipping.");
            errorCount++;
            continue;
        }
        
        // 1. Skip rows where first two columns (PropFirmName and Pattern1) are both blank
        if (string.IsNullOrWhiteSpace(fields[0]) && string.IsNullOrWhiteSpace(fields[1]))
        {
            skippedCount++;
            continue;
        }
        
        // 2. Skip comment rows (starting with # or //)
        string firstField = fields[0].Trim();
        if (firstField.StartsWith("#") || firstField.StartsWith("//"))
        {
            skippedCount++;
            continue;
        }
        
        // 3. Skip rows where PropFirmName is blank (even if Pattern1 has data)
        if (string.IsNullOrWhiteSpace(fields[0]))
        {
            if (PrintGoogleSheet) Print($"WARNING: Row {i + 1} has blank PropFirmName. Skipping.");
            skippedCount++;
            continue;
        }
        
        // Parse the values before validation
        double accountBeginningValue = ParseDouble(fields[4]);
        double trailingThreshold = ParseDouble(fields[5]);
        double profitToFund = ParseDouble(fields[7]);


		
		// 4. Skip rows with invalid account sizes (0 or negative)
		if (accountBeginningValue <= 0)
		{
		    if (PrintGoogleSheet) Print($"WARNING: Row {i + 1} has invalid account size ({accountBeginningValue}). Skipping.");
		    skippedCount++;
		    continue;
		}
		
		
        
        // 5. Skip rows where account size doesn't match standard sizes
        double standardSize = DetermineStandardAccountSize(accountBeginningValue);
        if (standardSize == 0)
        {
            if (PrintGoogleSheet) Print($"WARNING: Row {i + 1} has non-standard account size ({accountBeginningValue}). Skipping.");
            skippedCount++;
            continue;
        }
        
        // 6. Warn about suspicious trailing threshold (0 for Trailing type)
        string trailType = fields[6].Trim();
        if (trailType.Equals("Trailing", StringComparison.OrdinalIgnoreCase) && trailingThreshold == 0)
        {
            if (PrintGoogleSheet) Print($"WARNING: Row {i + 1} has Trailing type but 0 threshold. Data may be incomplete.");
            // Don't skip, just warn
        }
 
		if (trailType.Equals("EOD", StringComparison.OrdinalIgnoreCase))
		{
		    trailType = "End Of Day";
		}
		
		
		
        // 7. Skip rows with negative profit or drawdown values
        if (trailingThreshold < 0 || profitToFund < 0)
        {
            if (PrintGoogleSheet) Print($"WARNING: Row {i + 1} has negative profit/drawdown values. Skipping.");
            skippedCount++;
            continue;
        }
        
        PropFirmAccountConfig config = new PropFirmAccountConfig
        {
            PropFirmName = fields[0].Trim(),
            AccountNamePattern = fields[1].Trim(),
            AccountNamePattern2 = fields[2].Trim(),
            IsFunded = ParseBool(fields[3]),
            AccountBeginningValue = accountBeginningValue,
            TrailingThreshold = trailingThreshold,
            TrailType = trailType,
            ProfitToFund = profitToFund,
            MaxPayout = ParseDouble(fields[8]),
            Consistency = ParseDouble(fields[9]),
            Extra1 = fields[10].Trim(),
            Extra2 = fields[11].Trim(),
            Priority = fields.Length > 12 ? ParseInt(fields[12]) : 10
        };
        
        if (config.IsFunded)
        {
            config.MaxAutoLiquidate = config.AccountBeginningValue + 100;
        }
        else
        {
            config.MaxAutoLiquidate = 0;
        }
        
        configs.Add(config);
        successCount++;
    }
    catch (Exception ex)
    {
        if (PrintGoogleSheet) Print($"⚠ Error parsing row {i + 1}: {ex.Message}");
        errorCount++;
    }
}
        
        if (PrintGoogleSheet)
        {
            string message = $"✓ Loaded {successCount} configurations";
            if (skippedCount > 0) message += $" ({skippedCount} blank rows skipped)";
            if (errorCount > 0) message += $" ({errorCount} errors)";
            // Print(message);
        }
        
        return configs;
    }
    catch (Exception ex)
    {
        if (PrintGoogleSheet) Print($"❌ Error parsing CSV: {ex.Message}");
        return null;
    }
}




private bool ShouldReloadFromGoogleSheets()
{
    // 1. Force reload checked? → Always download
    if (ForceReloadFromSheets)
    {
        if (PrintGoogleSheet) Print("🔄 Force reload enabled");
        return true;
    }
    
    // 2. No cached data? → Download
    if (string.IsNullOrEmpty(pCachedCSVData))
    {
        if (PrintGoogleSheet) Print("📭 No cached data found");
        return true;
    }
    
    // 3. No timestamp? → Download
    if (LastLoadTimestamp == DateTime.MinValue)
    {
        if (PrintGoogleSheet) Print("⏰ No timestamp found");
        return true;
    }
    
    // 4. Check if cache expired
    TimeSpan timeSinceLastLoad = DateTime.Now - LastLoadTimestamp;
    
    if (timeSinceLastLoad.TotalDays >= pCacheDurationDays)
    {
        if (PrintGoogleSheet) Print($"⌛ Cache expired ({timeSinceLastLoad.TotalDays:F1} days old, limit: {pCacheDurationDays} days)");
        return true;
    }
    
    // Cache is still valid
    if (PrintGoogleSheet) Print($"✓ Cache valid (age: {timeSinceLastLoad.TotalDays:F1} days)");
    return false;
}





// Helper to parse CSV line (handles quoted fields with commas)
private string[] ParseCSVLine(string line)
{
    List<string> fields = new List<string>();
    bool inQuotes = false;
    string currentField = "";
    
    for (int i = 0; i < line.Length; i++)
    {
        char c = line[i];
        
        if (c == '"')
        {
            inQuotes = !inQuotes;
        }
        else if (c == ',' && !inQuotes)
        {
            fields.Add(currentField);
            currentField = "";
        }
        else
        {
            currentField += c;
        }
    }
    
    fields.Add(currentField);
    return fields.ToArray();
}

// Helper parsing methods
private bool ParseBool(string value)
{
    value = value.Trim().ToUpper();
    return value == "TRUE" || value == "1" || value == "YES";
}

private double ParseDouble(string value)
{
    double result;
    if (double.TryParse(value.Trim(), out result))
        return result;
    return 0;
}

private int ParseInt(string value)
{
    int result;
    if (int.TryParse(value.Trim(), out result))
        return result;
    return 0;
}


public class PropFirmAccountConfig
{
    public string PropFirmName { get; set; }
    public string AccountNamePattern { get; set; }
    public string AccountNamePattern2 { get; set; }
    public bool IsFunded { get; set; }
    public double AccountBeginningValue { get; set; }
    public double TrailingThreshold { get; set; }
    public string TrailType { get; set; }
    public double ProfitToFund { get; set; }
    public double MaxPayout { get; set; }
    public double Consistency { get; set; }        // NEW - Consistency percentage (e.g., 20 for 20%, 35 for 35%)
    public string Extra1 { get; set; }             // NEW - For future use
    public string Extra2 { get; set; }             // NEW - For future use
    public int Priority { get; set; }
    public double MaxAutoLiquidate { get; set; }
}
		
public PropFirmAccountConfig FindAccountConfig(string accountName, double standardAccountSize)
{
    // Sort by priority (lower number = higher priority)
    var sortedConfigs = accountConfigs.OrderBy(c => c.Priority).ToList();
    
    foreach (var config in sortedConfigs)
    {
        // Check if account name contains the pattern(s)
        bool nameMatches = accountName.Contains(config.AccountNamePattern);
        
        if (!nameMatches && !string.IsNullOrEmpty(config.AccountNamePattern2))
        {
            nameMatches = accountName.Contains(config.AccountNamePattern2);
        }
        
        if (nameMatches)
        {
            // If standardAccountSize is 0, return first name match
            if (standardAccountSize == 0)
            {
                return config;
            }
            
            // Otherwise, check if size matches
            if (config.AccountBeginningValue == standardAccountSize)
            {
                return config;
            }
        }
    }
    
    return null; // No match found
}
			
		
		private double DetermineStandardAccountSize(double currentAccountValue)
		{
			
			int thres = 0;  // 25000
			int thre1 = 19500;  // 25000
			int thre2 = 44800; // 50000
			int thre3 = 69500; // 75000
			int thre4 = 92000; // 100000
			int thre5 = 139000; // 150000
			int thre6 = 189000; // 200000
			int thre7 = 239000; // 250000
			int thre8 = 286500; // 300000
			int thre9 = 900000; // 300000
			
			
		    int LowEndBuffer = 0; // You can adjust this if needed
		    
		    if (currentAccountValue > thres - LowEndBuffer && currentAccountValue < thre1)
		    {
		        return 10000;
		    }
		    if (currentAccountValue > thre1 - LowEndBuffer && currentAccountValue < thre2)
		    {
		        return 25000;
		    }
		    if (currentAccountValue > thre2 - LowEndBuffer && currentAccountValue < thre3) //
		    {
		        return 50000;
		    }
		    if (currentAccountValue > thre3 - LowEndBuffer && currentAccountValue < thre4)
		    {
		        return 75000;
		    }
		    if (currentAccountValue > thre4 - LowEndBuffer && currentAccountValue < thre5)
		    {
		        return 100000;
		    }
		    if (currentAccountValue > thre5 - LowEndBuffer && currentAccountValue < thre6)
		    {
		        return 150000;
		    }
		    if (currentAccountValue > thre6 - LowEndBuffer && currentAccountValue < thre7)
		    {
		        return 200000;
		    }
		    if (currentAccountValue > thre7 - LowEndBuffer && currentAccountValue < thre8)
		    {
		        return 250000;
		    }
		    if (currentAccountValue > thre8 - LowEndBuffer && currentAccountValue < thre9)
		    {
		        return 300000;
		    }
		    
		    return 0; // No standard size detected
		}


		
private void InitializeAccountConfigs()
{
    // Fallback to empty configs immediately so callers don't block
    if (accountConfigs == null)
        accountConfigs = new List<PropFirmAccountConfig>();

    if (!string.IsNullOrEmpty(GoogleSheetsUrl) && pAutoLoadOnStartup)
    {
        // Run the Google Sheets load on a background thread to avoid blocking the UI thread
        // (previously used loadTask.Wait() which froze the UI for up to 45 seconds on a slow network).
        System.Threading.Tasks.Task.Run(async () =>
        {
            try
            {
                var configs = await LoadConfigsFromGoogleSheets();
                if (configs != null && configs.Count > 0)
                {
                    // Marshal to UI thread to update shared state
                    ChartControl.Dispatcher.InvokeAsync(() =>
                    {
                        accountConfigs = configs;
                        if (PrintGoogleSheet) Print("Loaded " + configs.Count + " configurations (Google Sheets)");
                        BuildLoadedPropFirmsList();
                    });
                }
                else
                {
                    if (PrintGoogleSheet) Print("Failed to load from Google Sheets. Using hardcoded defaults.");
                }
            }
            catch (Exception ex)
            {
                if (PrintGoogleSheet) Print("ERROR loading from Google Sheets: " + ex.Message);
            }
        });
    }

    // Build the prop firms list immediately with whatever we have (empty or previously loaded)
    BuildLoadedPropFirmsList();
}


		private List<PropFirmAccountConfig> accountConfigs;
				

private void BuildLoadedPropFirmsList()
{
    if (accountConfigs == null || accountConfigs.Count == 0)
    {
        pLoadedPropFirmsList = "No prop firms loaded.";
        if (PrintGoogleSheet) Print(pLoadedPropFirmsList);
        return;
    }
    
    // Get unique prop firm names and sort alphabetically
    var uniquePropFirms = accountConfigs
        .Select(c => c.PropFirmName)
        .Distinct()
        .OrderBy(name => name)
        .ToList();
    
    // Get total account count
    int totalAccounts = accountConfigs.Count;
    
    // Build the string
    System.Text.StringBuilder sb = new System.Text.StringBuilder();
    
    sb.AppendLine($"{uniquePropFirms.Count} Prop Firms Loaded ({totalAccounts})");
    sb.AppendLine();  // Blank line after header
    
    foreach (string firmName in uniquePropFirms)
    {
        // Count how many accounts for this firm
        int accountCount = accountConfigs.Count(c => c.PropFirmName == firmName);
        sb.AppendLine($"{firmName} ({accountCount})");
    }
    
    // Save to property (trim the trailing newline at the end)
    pLoadedPropFirmsList = sb.ToString().TrimEnd('\r', '\n');
    
    // Print if enabled
    if (PrintGoogleSheet)
    {
        // Print(pLoadedPropFirmsList);
    }

}



