		// Best-effort broker rejection reason for diagnostics. NinjaTrader exposes
		// the reject text inconsistently across versions, so read it by reflection
		// and never throw. Pipes/newlines stripped to keep the | log format intact.
		private string GetOrderRejectReason(Order or)
		{
			if (or == null)
				return "(none)";
			string reason = "";
			try
			{
				var nativeErr = or.GetType().GetProperty("NativeError")?.GetValue(or) as string;
				if (!string.IsNullOrEmpty(nativeErr)) reason += nativeErr;
				var orderErr = or.GetType().GetProperty("Error")?.GetValue(or);
				if (orderErr != null) reason += (reason.Length > 0 ? "; " : "") + orderErr.ToString();
			}
			catch { }
			return reason.Length > 0 ? reason.Replace("|", ";").Replace("\r", " ").Replace("\n", " ") : "(none)";
		}

		// Resubmit-storm circuit breaker. See the field comments near
		// ResubmittedOrders: each resubmission is a NEW order with a NEW
		// OrderId, so the OrderId dedupe never catches a rejection chain and
		// it loops forever. This caps the chain per logical order
		// (account + instrument + name) inside a rolling window. Returns
		// true while resubmitting is still allowed; on the cap it marks the
		// order id seen so the caller's dedupe short-circuits, logs, and
		// alerts the user once.
		private bool ResubmitGuardAllows(Account acct, Order or, bool ormaster)
		{
			if (acct == null || or == null)
				return true;

			string key = acct.Name + "|"
				+ (or.Instrument != null ? or.Instrument.FullName : "?") + "|"
				+ or.Name;
			DateTime now = DateTime.Now;

			DateTime windowStart;
			if (!_resubmitWindowStart.TryGetValue(key, out windowStart)
				|| (now - windowStart).TotalSeconds > ResubmitWindowSeconds)
			{
				// Fresh window — a genuinely new rejection, not part of a storm.
				_resubmitWindowStart[key] = now;
				_resubmitAttemptCount[key] = 0;
				_resubmitCapAlerted.Remove(key);
			}

			int count;
			_resubmitAttemptCount.TryGetValue(key, out count);

			if (count >= MaxResubmitAttempts)
			{
				// Cap reached — stop. Mark the id seen so the caller's
				// !ResubmittedOrders.Contains() check short-circuits next pass.
				if (!ResubmittedOrders.Contains(or.OrderId))
					ResubmittedOrders.Add(or.OrderId);

				if (_diagLog != null)
				{
					try
					{
						_diagLog.Log("ORDER", "REJECTED_RESUBMIT_CAPPED",
							"Account=" + acct.Name
							+ "|OrderId=" + or.OrderId
							+ "|OrderName=" + or.Name
							+ "|Action=" + or.OrderAction
							+ "|Attempts=" + count
							+ "|IsMaster=" + ormaster
							+ "|Instrument=" + (or.Instrument != null ? or.Instrument.FullName : "?")
							+ "|Reason=" + GetOrderRejectReason(or));
					}
					catch { }
				}

				if (!_resubmitCapAlerted.Contains(key))
				{
					_resubmitCapAlerted.Add(key);
					string instName = (or.Instrument != null && or.Instrument.MasterInstrument != null)
						? or.Instrument.MasterInstrument.Name : "?";
					AddMessage("Stopped resubmitting a repeatedly-rejected " + or.OrderAction
						+ " order (" + or.Name + ", " + instName + ") on "
						+ (ormaster ? "the Master account" : "follower account '" + acct.Name + "'")
						+ " after " + count + " attempts — the broker keeps rejecting it. "
						+ "Check this account's position and orders manually; follower "
						+ "accounts may now be out of sync with the Master.",
						60, Brushes.Red);
				}

				return false;
			}

			_resubmitAttemptCount[key] = count + 1;
			return true;
		}



		private void GetAllPerformanceStats()		
		{
			// When all accounts (master + followers) just went flat, or when they go from having pending orders to zero pending orders, immediately refresh Tradovate API count.
			if (HasTradovateMasterOrFollower())
			{
				bool allFlatNow = AllMasterAndFollowersFlat();
				if (allFlatNow && pAnyMasterOrFollowerHadPositionLastRun)
				{
					RebuildTradovateAPIActionLogFromHistory();
					pAnyMasterOrFollowerHadPositionLastRun = false;
					InvalidateVis(1);
				}
				if (!allFlatNow)
					pAnyMasterOrFollowerHadPositionLastRun = true;
				
				int countPending = CountMasterAndFollowersWithPendingOrders();
				bool hasPendingNow = countPending > 0;
				if (!hasPendingNow && pAnyMasterOrFollowerHadPendingOrdersLastRun)
				{
					RebuildTradovateAPIActionLogFromHistory();
					pAnyMasterOrFollowerHadPendingOrdersLastRun = false;
					InvalidateVis(1);
				}
				if (hasPendingNow)
					pAnyMasterOrFollowerHadPendingOrdersLastRun = true;
				
				// When count of accounts with working orders drops (e.g. move order), then increases, then stops increasing: refresh API count (catches order moves on master).
				if (pPrevCountAccountsWithPendingOrders >= 0)
				{
					if (countPending < pPrevCountAccountsWithPendingOrders)
						pSawDropInPendingCount = true;
					if (pSawDropInPendingCount && countPending > pPrevCountAccountsWithPendingOrders)
						pSawIncreaseAfterDrop = true;
					if (pSawIncreaseAfterDrop && countPending == pPrevCountAccountsWithPendingOrders)
					{
						RebuildTradovateAPIActionLogFromHistory();
						InvalidateVis(1);
						pSawDropInPendingCount = false;
