		private void OnTimerTick4(object sender, EventArgs e)
		{

			DateTime now4 = DateTime.Now;

			// ── Fast-path pending-order X indicator refresh ────────────────────────
			// The yellow "X = cancel pending order" glyph is driven by
			// FinalPNLStatistics[acct].PendingEntry, which is only recomputed by the
			// heavy GetAllPerformanceStats pass on timer3 (250ms). Users saw the X
			// appearing/disappearing visibly late relative to actual order state.
			// This block does a cheap per-account PendingEntry recount every 100ms
			// (just OrderType/OrderState checks on Account.Orders — no other stats,
			// no position scans, no render work unless a value changed). Totals-row
			// X still lags one timer3 cycle; the user-facing complaint was about
			// per-account rows, which this resolves.
			if (FinalPNLStatistics.Count > 0)
			{
				bool _anyPendingChanged = false;
				// Snapshot Account.All — Cbi can add accounts on connect mid-tick (InvalidOperationException otherwise).
				List<Account> _acctsSnapshot;
				try { _acctsSnapshot = Account.All.ToList(); }
				catch { _acctsSnapshot = null; }
				if (_acctsSnapshot != null)
				foreach (Account _acct in _acctsSnapshot)
				{
					if (_acct == null) continue;
					PNLStatistics _st;
					if (!FinalPNLStatistics.TryGetValue(_acct.Name, out _st) || _st == null) continue;

					int _pending = 0;
					try
					{
						foreach (Order _or in _acct.Orders.ToList())
						{
							if (_or == null) continue;
							if (_or.OrderType == OrderType.Market) continue;
							OrderState _s = _or.OrderState;
							bool _ok = _s == OrderState.Working || _s == OrderState.Accepted || _s == OrderState.TriggerPending
								|| _s == OrderState.ChangePending || _s == OrderState.ChangeSubmitted || _s == OrderState.PartFilled;
							if (!_ok) continue;
							if (!IsPendingEntryOrder(_or)) continue;
							_pending += _or.Quantity;
						}
					}
					catch { continue; }

					if (_st.PendingEntry != _pending)
					{
						_st.PendingEntry = _pending;
						_anyPendingChanged = true;
					}
				}
				if (_anyPendingChanged) InvalidateVis(93);
			}

			if (FlattenEverythingClickedTime != DateTime.MinValue)
			if (now4 > FlattenEverythingClickedTime.AddMilliseconds(pMilliSFE))
			{

				InvalidateVis(3);
				//Print("FLATTTTTTT");

				//FlattenEverythingClicked = true;
				//FlattenEverythingClickedTotal = 0;
				//FlattenEverythingClickedOrders = 0;
				//FlattenEverythingClickedTime = DateTime.MinValue;
				//ExpectedFollowerPositions.Clear();

			}
			
				
			if (now4 > SelectedMultiplerTime)
			{

				if (SelectedMultiplerTime != DateTime.MinValue)
				{
					SelectedMultiplierAccount = string.Empty;
					InvalidateVis(3);
				}

				SelectedMultiplerTime = DateTime.MinValue;
			}


			if (now4 > SelectedATMTime)
			{

				if (SelectedATMTime != DateTime.MinValue)
				{
					SelectedATMAccount = string.Empty;
					InvalidateVis(4);
				}

				SelectedATMTime = DateTime.MinValue;
			}




			if (now4 > SelectedDailyGoalTime)
			{

				if (SelectedDailyGoalTime != DateTime.MinValue)
				{
					SelectedDailyGoalAccount = string.Empty;
					InvalidateVis(5);
				}

				SelectedDailyGoalTime = DateTime.MinValue;
			}


			if (now4 > SelectedDailyLossTime)
			{

				if (SelectedDailyLossTime != DateTime.MinValue)
				{
					SelectedDailyLossAccount = string.Empty;
					InvalidateVis(6);
				}

				SelectedDailyLossTime = DateTime.MinValue;
			}

			if (now4 > SelectedPayoutTime)
			{

				if (SelectedPayoutTime != DateTime.MinValue)
				{
					SelectedPayoutAccount = string.Empty;
					InvalidateVis(7);
				}

				SelectedPayoutTime = DateTime.MinValue;
			}




			if (now4 > SelectedResetTime)
			{

				if (SelectedResetTime != DateTime.MinValue)
				{
					SelectedResetColumn = string.Empty;
					SelectedButtonNowPre = string.Empty;
					InvalidateVis(1);
				}

				SelectedResetTime = DateTime.MinValue;
			}

			if (now4 > SelectedButtonTime)
			{

				if (SelectedButtonTime != DateTime.MinValue)
				{
					SelectedButtonNow = string.Empty;
					SelectedButtonNowPre = string.Empty;
					InvalidateVis(8);
				}

				SelectedButtonTime = DateTime.MinValue;
			}




			if (now4 > RemoveMessageTime)
				RemoveDrawObject("error");

			// Fire a single invalidation once the tooltip delay has expired.
			// Only invalidates ONCE per hover session (tracked by HoveredHeaderTooltipShown)
			// so timer4 adds zero performance cost when no tooltip is pending.
			if (HoveredHeaderColumn >= 0 && !HoveredHeaderTooltipShown && HoveredHeaderStartTime != DateTime.MinValue)
			{
				double hoverElapsed = (now4 - HoveredHeaderStartTime).TotalMilliseconds;
				if (hoverElapsed >= 300)
				{
					HoveredHeaderTooltipShown = true;
					InvalidateVis(89);
				}
			}

			// Swap-flash animation: keep invalidating until the 100ms window is over so
			// the flash clears cleanly even when the mouse has stopped moving.
			if (_swapFlashLogical >= 0)
			{
				double _flashAge = (now4 - _swapFlashTime).TotalMilliseconds;
				if (_flashAge <= SwapFlashDurationMs + 20)
					InvalidateVis(101);
				else
					_swapFlashLogical = -1; // expired — stop invalidating
			}

			// Copy-to-clipboard row flash: keep invalidating until the flash expires.
			if (_copyFlashRowI > 0 && now4 < _copyFlashEnd)
			{
				InvalidateVis(112);
			}
			else if (_copyFlashRowI > 0)
			{
				_copyFlashRowI = 0;
			}

			// PnL cell flashes: keep invalidating while any flash is live so the fade
			// completes even when the table data isn't ticking. Also prunes expired
			// entries from the nested (account → column → time) structure so the
			// dicts don't grow without bound across long sessions. Pruning uses
			// deferred-removal lists because C# dictionaries throw if mutated mid-iteration.
			if (_cellFlashEnd.Count > 0)
			{
				bool _anyLive = false;
				_reusableEmptyAccts.Clear();
				foreach (var _acctKv in _cellFlashEnd)
				{
					_reusableExpiredCols.Clear();
					foreach (var _colKv in _acctKv.Value)
					{
						if (now4 < _colKv.Value)
						{
							_anyLive = true;
						}
						else
						{
							_reusableExpiredCols.Add(_colKv.Key);
						}
					}
					if (_reusableExpiredCols.Count > 0)
					{
						Dictionary<string, bool> _upInner;
						bool _haveUp = _cellFlashUp.TryGetValue(_acctKv.Key, out _upInner);
						foreach (string _ck in _reusableExpiredCols)
						{
							_acctKv.Value.Remove(_ck);
							if (_haveUp) _upInner.Remove(_ck);
						}
					}
					if (_acctKv.Value.Count == 0)
					{
						_reusableEmptyAccts.Add(_acctKv.Key);
					}
				}
				if (_reusableEmptyAccts.Count > 0)
				{
					foreach (string _ak in _reusableEmptyAccts)
					{
						_cellFlashEnd.Remove(_ak);
						Dictionary<string, bool> _upInner;
						if (_cellFlashUp.TryGetValue(_ak, out _upInner) && _upInner.Count == 0)
							_cellFlashUp.Remove(_ak);
					}
				}
				if (_anyLive) InvalidateVis(111);
			}

			// COLOST dot pulse: keep invalidating while any lost-connection dot is on
			// screen so the sine-based pulse animates. The render loop sets the flag
			// every frame it draws a COLOST dot; we clear it after re-invalidating.
			if (_needColostPulseInvalidation)
			{
				_needColostPulseInvalidation = false;
				InvalidateVis(115);
			}

			// Deferred bracket verification after scale-in — force re-sync by clearing cached signature
			if (_scaleInVerifyTime != DateTime.MinValue && now4 > _scaleInVerifyTime)
			{
				_scaleInVerifyTime = DateTime.MinValue;
				if (_scaleInVerifyMasterOrder != null)
				{
					// Clear signature cache to bypass the "quantities unchanged" short-circuit
					LastATMExitOrdersSignature.Clear();
					SyncATMStrategyExitOrdersToAllFollowers(_scaleInVerifyMasterOrder);
					_scaleInVerifyMasterOrder = null;
				}
			}

			// Clean up expired OCO ignore entries
			if (IgnoreTheseATMStrategyCancelCommands.Count > 0)
			{
				List<string> expired = null;
				foreach (var kvp in IgnoreTheseATMStrategyCancelCommands)
				{
					if (now4 > kvp.Value)
					{
						if (expired == null) expired = new List<string>();
						expired.Add(kvp.Key);
					}
				}
				if (expired != null)
					foreach (string key in expired)
						IgnoreTheseATMStrategyCancelCommands.Remove(key);
			}

			//Print("tick");
			
			
//			if 
			
		}
			
		
