		DateTime last100msExecution = DateTime.Now;


		private void _noDataTimer_Tick(object sender, EventArgs e)
		{
			// Fire once then stop
			if (_noDataTimer != null)
			{
				_noDataTimer.IsEnabled = false;
				_noDataTimer.Tick -= _noDataTimer_Tick;
				_noDataTimer = null;
			}

			// If OnRender already ran, no overlay needed
			if (!FirstRender2)
				return;

			// Hide the indicator label immediately (same as FirstRender2 does)
			try
			{
				if (ChartControl != null && ChartControl.Properties != null)
				{
					ChartControl.Properties.ChartText = Brushes.Transparent;
					ChartControl.Properties.LabelFont = new SimpleFont("Arial", 1);
				}
			}
			catch { }

			// OnRender never fired — chart has no data. Show a WPF overlay
			// by walking up from ChartControl to find a Grid we can inject into.
			try
			{
				if (ChartControl == null || _noDataOverlay != null)
					return;

				System.Windows.DependencyObject parent = ChartControl;
				System.Windows.Controls.Grid targetGrid = null;

				// Walk up the visual tree to find the first Grid container
				while (parent != null)
				{
					parent = System.Windows.Media.VisualTreeHelper.GetParent(parent);
					if (parent is System.Windows.Controls.Grid g)
					{
						targetGrid = g;
						break;
					}
				}

				if (targetGrid != null)
				{
					// Build a StackPanel with arrow + message
					System.Windows.Controls.StackPanel overlayPanel = new System.Windows.Controls.StackPanel
					{
						VerticalAlignment = VerticalAlignment.Center,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Center,
						Margin = new System.Windows.Thickness(40),
						IsHitTestVisible = false
					};

					// Arrow pinned to top-left, pointing at instrument selector
					// Position based on caption width — "Chart" is short, version text is wide
					double arrowLeft = 150;
					try
					{
						Chart cw = chartWindow ?? (Window.GetWindow(ChartControl.Parent) as Chart);
						if (cw != null && cw.Caption != null && cw.Caption.Length > 10)
							arrowLeft = 350;
					}
					catch { }

					// Vector arrow — renders smooth at any size
					System.Windows.Shapes.Path arrowPath = new System.Windows.Shapes.Path
					{
						// Arrow pointing upper-left: tip at 0,0 -> shaft down-right
						Data = System.Windows.Media.Geometry.Parse("M 0,0 L 0,22 L 5,17 L 14,28 L 20,23 L 11,12 L 17,8 Z"),
						Fill = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromRgb(0xD6, 0x3A, 0x1A)),
						Stretch = System.Windows.Media.Stretch.Uniform,
						Width = 28,
						Height = 28,
						VerticalAlignment = VerticalAlignment.Top,
						HorizontalAlignment = System.Windows.HorizontalAlignment.Left,
						Margin = new System.Windows.Thickness(arrowLeft, 12, 0, 0),
						IsHitTestVisible = false
					};
					System.Windows.UIElement arrowText = arrowPath;

					_noDataOverlay = new System.Windows.Controls.TextBlock
					{
						Text = "No chart data found.\n\n"
							+ "Select an instrument with active data in the top-left selector,\n"
							+ "then make sure a data connection is active in the Control Center\n"
							+ "under the Connections menu.\n\n"
							+ "The Accounts Dashboard will load automatically once data is available.",
						Foreground = Brushes.Silver,
						FontSize = 15,
						TextAlignment = System.Windows.TextAlignment.Center,
						TextWrapping = System.Windows.TextWrapping.Wrap
					};

					overlayPanel.Children.Add(_noDataOverlay);

					System.Windows.Controls.Grid.SetRowSpan(overlayPanel, 100);
					System.Windows.Controls.Grid.SetColumnSpan(overlayPanel, 100);
					System.Windows.Controls.Grid.SetRowSpan(arrowText, 100);
					System.Windows.Controls.Grid.SetColumnSpan(arrowText, 100);

					_noDataArrow = arrowText;
					targetGrid.Children.Add(arrowText);
					targetGrid.Children.Add(overlayPanel);
				}
			}
			catch { }
		}


