		private string RithmicSecondsRemaining = string.Empty; 
		private List<Account> RithmicAccounts = new List<Account>();
		private List<Instrument> RithmicInstruments = new List<Instrument>();
		
		private void GetMinimumSecondsRemaining()
		{
			//RithmicSecondsRemaining = 0;
			RithmicAccounts.Clear();
			RithmicInstruments.Clear();
			
			
			
		    DateTime currentTime = DateTime.Now;
		    double minRemainingMs = double.MaxValue;
		    bool hasItems = false;
		    
			double delayInMilliseconds2 = pRithmic2Seconds * 1000; // Convert to milliseconds
			
		    foreach (KeyValuePair<Instrument, AccountsAndDetails> kvp in RithmicAccountsAndDetails)
		    {
		        Instrument instrument = kvp.Key;
		        AccountsAndDetails allDetails = kvp.Value;
		        DateTime addedTime = allDetails.StartTime;

					
				foreach (Account acct in allDetails.AllAccounts.ToList())
				{
					if (!RithmicAccounts.Contains(acct))
						RithmicAccounts.Add(acct);
					
					
				}	
				
					if (!RithmicInstruments.Contains(instrument))
						RithmicInstruments.Add(instrument);			
				
		        // Calculate elapsed time
		        TimeSpan elapsed = currentTime - addedTime;
		        
		        // Calculate remaining time in milliseconds
		        double remainingMs = delayInMilliseconds2 - elapsed.TotalMilliseconds;
		        
		        // Only consider items that haven't reached the threshold yet
		        if (remainingMs > 0)
		        {
		            minRemainingMs = Math.Min(minRemainingMs, remainingMs);
		            hasItems = true;
		        }
		    }
		    
			//Print(RithmicAccountsAndDetails.Count);
			
		    // If no items are waiting, return "0.0"
		    if (!hasItems || minRemainingMs == double.MaxValue)
		    {
		        RithmicSecondsRemaining = "0.0";
				
		    }
		    else
			{
			    // Convert back to seconds and format as string
			    double minRemainingSeconds = minRemainingMs / 1000.0;
			
			    RithmicSecondsRemaining = minRemainingSeconds.ToString("F1");
			}
	
		}


		
		

