		private bool IsInActiveWorkspace = false;			
					
		private void OnTimerTick3(object sender, EventArgs e)
		{
			DateTime now3 = DateTime.Now;

			// Position drift watchdog — runs every 2s. Compares the master's signed
			// position qty for each instrument to the same instrument on every
			// follower. Logs one line per drifted account on signature change, plus
			// a heartbeat every 30s while any account holds position.
			if (_diagLog != null && State == State.Realtime && CurrentMasterAccount != null && now3 >= _nextPositionDriftCheck)
			{
				_nextPositionDriftCheck = now3.AddSeconds(2);
				try
				{
					System.Text.StringBuilder _drSig = new System.Text.StringBuilder();
					System.Text.StringBuilder _drHB  = new System.Text.StringBuilder();
					bool _anyPos = false;
					foreach (Position mp in CurrentMasterAccount.Positions)
					{
						if (mp == null || mp.Instrument == null) continue;
						int _mSigned = mp.MarketPosition == MarketPosition.Long ? mp.Quantity
									 : mp.MarketPosition == MarketPosition.Short ? -mp.Quantity : 0;
						if (_mSigned != 0) _anyPos = true;
						_drHB.Append(mp.Instrument.MasterInstrument != null ? mp.Instrument.MasterInstrument.Name : mp.Instrument.FullName).Append(":M=").Append(_mSigned);
						foreach (string acctName in AllDuplicateAccounts)
						{
							Account fa = AccountFromName(acctName);
							if (fa == null || fa == CurrentMasterAccount) continue;
							Position fp = fa.GetPosition(mp.Instrument.Id);
							int _fSigned = (fp == null || fp.MarketPosition == MarketPosition.Flat) ? 0
										 : fp.MarketPosition == MarketPosition.Long ? fp.Quantity : -fp.Quantity;
							if (_fSigned != 0) _anyPos = true;
							_drHB.Append("/").Append(acctName).Append("=").Append(_fSigned);
							if (_fSigned != _mSigned)
								_drSig.Append("|").Append(acctName).Append("=").Append(_fSigned).Append("(M=").Append(_mSigned).Append(")");
						}
						_drHB.Append(";");
					}
					string _sigStr = _drSig.ToString();
					if (_sigStr.Length > 0 && _sigStr != _lastPositionDriftSignature)
					{
						_lastPositionDriftSignature = _sigStr;
						_diagLog.Log("POSITION", "DRIFT_DETECTED", "Drift=" + _sigStr.TrimStart('|'));
					}
					else if (_sigStr.Length == 0 && _lastPositionDriftSignature.Length > 0)
					{
						_lastPositionDriftSignature = string.Empty;
						_diagLog.Log("POSITION", "DRIFT_RESOLVED", "Reason=AllAccountsAligned");
					}
					if (_anyPos && (now3 - _lastPositionDriftHeartbeat).TotalSeconds >= 30)
					{
						_lastPositionDriftHeartbeat = now3;
						_diagLog.Log("POSITION", "RECONCILE_HEARTBEAT", "Snapshot=" + _drHB.ToString().TrimEnd(';'));
					}
				}
				catch { }
			}

			// =======================================================================
			// EXECUTIONS-MODE STRANDED-FOLLOWER BACKSTOP - Eric Wilson / Braxton 2026-05-20.
			// The drift-guard in-flight reconciliation (GetInFlightFollowerQty) is the
			// primary fix for a follower left holding a position after the master has
			// exited. This is the catch-all for when that misses: if the master is flat
			// on an instrument, the copier is on, and a follower is STILL holding it
			// with nothing of ours in flight to close it, flatten the follower. The
			// Orders-mode equivalent (OnPositionUpdate3, "master flat after scaling
			// close") is gated to pCopierMode == "Orders", so Executions mode - the
			// mode in the incident - had no backstop at all.
			//
			// Safety: acts only after the master has been flat AND quiet for a settle
			// window, and only when nothing of ours is in flight - so the follower's
			// live position is settled and the stranding unambiguous. A flatten can
			// only close a position, never open or flip one.
			// =======================================================================
			long _bkLastFill = Interlocked.Read(ref _lastMasterFillTicksUtc);
			// The Master must be flat on EVERY instrument before the backstop may
			// act. A per-instrument check (Master.GetPosition(followerInstrument))
			// is wrong for cross-instrument copying - e.g. Master NQ -> follower
			// MNQ: the Master never holds the follower's instrument, so such a
			// check always reads "flat" and the backstop flattens live followers
			// while the Master is still in the trade. Master-flat-on-everything is
			// the only signal that is correct regardless of instrument mapping.
			bool _bkMasterFlat = false;
			try
			{
				if (CurrentMasterAccount != null)
				{
					_bkMasterFlat = true;
					foreach (Position _bkMp in CurrentMasterAccount.Positions.ToList())
					{
						if (_bkMp != null && _bkMp.MarketPosition != MarketPosition.Flat && _bkMp.Quantity != 0)
						{
							_bkMasterFlat = false;
							break;
						}
					}
				}
			}
			catch { _bkMasterFlat = false; }
			if (State == State.Realtime
				&& pCopierIsEnabled
				&& pCopierMode == "Executions"
				&& CurrentMasterAccount != null
				&& _bkMasterFlat
				&& _masterExecutionQueue.IsEmpty
				&& !IgnoreExecutionUntilFlat
				&& !IsRecentFlatten()
				&& _bkLastFill != 0
				&& (DateTime.UtcNow.Ticks - _bkLastFill) >= ExecBackstopMasterQuietTicks)
			{
				try
				{
					foreach (string _bkAcctName in AllDuplicateAccounts)
					{
						Account _bkFa = AccountFromName(_bkAcctName);
						if (_bkFa == null || _bkFa == CurrentMasterAccount) continue;

						foreach (Position _bkFp in _bkFa.Positions.ToList())
						{
							if (_bkFp == null || _bkFp.Instrument == null
								|| _bkFp.MarketPosition == MarketPosition.Flat || _bkFp.Quantity == 0)
								continue;

							Instrument _bkInst = _bkFp.Instrument;

							// The Master is flat on everything (checked above), so any
							// follower still holding is stranded - unless one of our own
							// orders is still in flight: a close already on its way
							// (primary fix worked) or an entry still filling. If so,
							// stand down and re-check next tick.
							if (GetInFlightFollowerQty(_bkFa, _bkInst) != 0) continue;

							int _bkFSigned = _bkFp.MarketPosition == MarketPosition.Long
								? _bkFp.Quantity : -_bkFp.Quantity;

							// Cooldown so a flatten the broker rejects cannot re-fire every tick.
							string _bkKey = _bkFa.Name + "@" + _bkInst.Id;
							DateTime _bkLast;
							if (_execBackstopLastFlatten.TryGetValue(_bkKey, out _bkLast)
								&& (now3 - _bkLast).TotalSeconds < 3)
								continue;
							_execBackstopLastFlatten[_bkKey] = now3;

							if (_diagLog != null)
								_diagLog.Log("COPIER", "MASTER_FLAT_FOLLOWER_BACKSTOP",
									"Account=" + _bkFa.Name
									+ "|Instrument=" + _bkInst.FullName
									+ "|FollowerSigned=" + _bkFSigned
									+ "|MasterSigned=0|InFlight=0"
									+ "|MasterQuietMs=" + ((DateTime.UtcNow.Ticks - _bkLastFill) / TimeSpan.TicksPerMillisecond)
									+ "|Action=FlattenInstrument");

							FlattenInstrument(_bkFa, _bkInst);

							AddMessage("Safety backstop: '" + _bkFa.Name + "' was still holding "
								+ Math.Abs(_bkFSigned) + " " + _bkInst.FullName
								+ " after the Master went flat - the follower has been flattened."
								+ " Review your copier logs.", 60, Brushes.Red);
						}
					}
				}
				catch { }
			}

			// Tracker drift safety net. Once the master has been quiet long enough
			// that live positions are settled — and we're clear of any flatten
			// window — snap TrackedMasterPosition back to the broker's actual
			// positions so stale follower sizing can't persist.
			if (State == State.Realtime
				&& CurrentMasterAccount != null
				&& now3 >= _nextTrackerResync
				&& _masterExecutionQueue.IsEmpty
				&& !IgnoreExecutionUntilFlat
				&& now3 >= FlattenEverythingClickedTime.AddMilliseconds(pMilliSFE)
				&& now3 >= GoalLossFlattenTime.AddMilliseconds(pMilliSFE)
				&& (DateTime.UtcNow.Ticks - Interlocked.Read(ref _lastMasterFillTicksUtc)) >= TrackerResyncIdleTicks)
			{
				_nextTrackerResync = now3.AddSeconds(2);
				ResyncTrackedMasterPositionFromLive();
			}

			// Show any conflict message queued during startup (DataLoaded runs before UI is ready)
			if (_conflictMessage != string.Empty)
			{
				string pending = _conflictMessage;
				_conflictMessage = string.Empty;
				RemoveMessage("CONFLICT");
				RemoveMessage("DUPLICATE WINDOW");
				AddMessage(pending, 60, Brushes.Goldenrod);
				InvalidateVis(99);
			}

			// When master goes flat, schedule Tradovate API log rebuild after 2.5 sec so follower order activity is included
			if (CurrentMasterAccount != null)
			{
				bool masterFlat = IsAccountFlat(CurrentMasterAccount);
				if (masterFlat && !pMasterWasFlatForTradovateRebuild)
				{
					pMasterWasFlatForTradovateRebuild = true;
					pTradovateRebuildAfter = now3.AddSeconds(2.5);
				}
				else if (!masterFlat)
					pMasterWasFlatForTradovateRebuild = false;
			}
			if (pTradovateRebuildAfter != DateTime.MinValue && now3 >= pTradovateRebuildAfter)
			{
				RebuildTradovateAPIActionLogFromHistory();
				pTradovateRebuildAfter = DateTime.MinValue;
			}
			
			// Permanently show warning when usage reaches API Rate Limit Warning (%) and tracker is enabled (re-show every 60 sec while at/above threshold). Caution based on hourly % only.
			if (pApiRateLimitTrackerEnabled && HasTradovateConnectionConnected() && HasTradovateMasterOrFollower() && pApiRateLimitWarningPct > 0)
			{
				int warnHour = (TradovateLimitPerHour * pApiRateLimitWarningPct) / 100;
				int h = GetTradovateCommandsHourCount();
				bool atOrAboveThreshold = h >= warnHour;
				if (atOrAboveThreshold && (pLastTradovateWarningShown == DateTime.MinValue || (now3 - pLastTradovateWarningShown).TotalSeconds >= 60))
				{
					pLastTradovateWarningShown = now3;
					string breakdown = GetTradovateActionBreakdown();
					string warnMsg = "Tradovate API rate limit warning (" + pApiRateLimitWarningPct + "%): " + h + " / " + TradovateLimitPerHour + " (60 min). Action types: " + breakdown + ".";
					int safeMin = GetTradovateCommandsSafeInMinutesForHour();
					if (safeMin > 0)
						warnMsg += " Hourly count below limit in about " + safeMin + " minute(s).";
					AddMessage(warnMsg, 10000, Brushes.Goldenrod);
				}
				if (!atOrAboveThreshold)
					pLastTradovateWarningShown = DateTime.MinValue;
			}

			// --- Cross-window conflict monitoring (checks every 5 seconds, plus event-driven pings) ---
			// Reacts ONLY when the conflict is active — i.e. THIS window is ON and a peer is also
			// ON, or we were previously blocked by a peer that's still ON. Latent overlaps (all
			// involved windows OFF) stay silent: no banner, no auto-disable. Dormant windows
			// aren't surprised by warnings. See HandleConflictResult for full state machine,
			// including the "Ready to enable" nudge when a blocking peer turns off.
			{
				// --- Override-channel: a peer window requested we disable (user clicked override there) ---
				bool externallyDisabled = false;
				lock (_registryLock)
				{
					DashboardInstanceInfo me;
					if (_instanceRegistry.TryGetValue(_instanceId, out me) && me.DisableRequested)
					{
						me.DisableRequested = false;
						externallyDisabled = true;
					}
				}
				if (externallyDisabled && pCopierIsEnabled)
				{
					pCopierIsEnabled = false;
					if (_diagLog != null)
						_diagLog.Log("UI", "COPIER_DISABLED", "Reason=OverrideByPeerWindow");
					ResetMasterExecutionState();
					PublishEnabledStateAndPingPeers();
					RemoveMessage("CONFLICT");
					RemoveMessage("DUPLICATE WINDOW");
					// Persistent (10000s ≈ 2.8h) so a user away from the screen still sees context
					// when they return. Mirrors the long-duration pattern at line ~7185.
					AddMessage("This window was turned OFF because another Dashboard window claimed this configuration via override.", 10000, Brushes.Goldenrod);
					RebuildAccountsTableAfterStateChange(); // show all accounts again now that we're OFF
					_wasBlockedByPeers = false; // peer is now on, not us
				}

				// While an override is in flight on THIS window, bypass the normal conflict checks
				// entirely — otherwise HandleConflictResult briefly flashes CONFLICT → Ready-to-enable
				// between the click and completion (because mid-transition the peer may be reported
				// still enabled one tick, disabled the next, then we flip ON). The pending-enable
				// branch below handles every state change needed for the override path.
				if (!_pendingEnableAfterOverride)
				{
					// Check if another instance flagged us for a conflict
					bool wasNotified = false;
					lock (_registryLock) { wasNotified = _conflictNotifications.Remove(_instanceId); }
					if (wasNotified)
					{
						string crossConflict = RegisterInstance();
						HandleConflictResult(crossConflict, "CrossWindowConflict");
					}

					// Periodic self-check: re-scan registry for new conflicts / resolutions
					if ((now3 - _lastConflictCheckTime).TotalSeconds >= 5)
					{
						_lastConflictCheckTime = now3;
						string periodicConflict = RegisterInstance();
						HandleConflictResult(periodicConflict, "CrossWindowConflict");
					}
				}
				else
				{
					// Drain pings queued for us during the override so they don't stack and fire
					// HandleConflictResult immediately after completion.
					lock (_registryLock) { _conflictNotifications.Remove(_instanceId); }
				}

				// --- Complete a pending override-enable once blocking peers have actually disabled ---
				if (_pendingEnableAfterOverride)
				{
					// Refresh registry state so IsAnyConflictingPeerEnabled sees latest peer IsCopierEnabled.
					RegisterInstance();
					if (!IsAnyConflictingPeerEnabled())
					{
						_pendingEnableAfterOverride = false;
						_wasBlockedByPeers = false;
						_hadConflict = false;
						_lastEnableBlockTime = DateTime.MinValue;
						// Re-seed tracked master position from live before flipping
						// the enable flag. See matching call site in the main button
						// toggle for rationale (follower-close broken after OFF→ON
						// during an open master trade).
						SeedTrackedMasterPositionFromLive();
						pCopierIsEnabled = true;
						_copierArmedUtc = DateTime.UtcNow;
						PublishEnabledStateAndPingPeers();
						if (_diagLog != null)
							_diagLog.Log("UI", "COPIER_ENABLED", "Reason=OverrideCompleted|Master=" + pThisMasterAccount + "|Followers=" + AllDuplicateAccounts.Count);
						LogTimezoneSnapshot("CopierEnable.OverrideCompleted");
						RemoveMessage("CONFLICT");
						RemoveMessage("DUPLICATE WINDOW");
						RemoveMessage("Window conflict resolved");
						RemoveMessage("Ready to enable");
						RemoveMessage("Override confirmed");
						RemoveMessage("This window was turned OFF"); // clear stale peer-override notice from prior session
						AddMessage("Override complete — blocking window(s) disabled, this window is now ON.", 8, Brushes.LimeGreen);
						RebuildAccountsTableAfterStateChange(); // hide non-Master/Follower accounts now that we're ON
					}
					else if ((now3 - _lastEnableBlockTime).TotalSeconds > 15)
					{
						// Safety: if peers haven't disabled within 15 sec of the override click, give up.
						_pendingEnableAfterOverride = false;
						AddMessage("Override aborted — the blocking window(s) did not disable in time. Please toggle them off manually.", 10000, Brushes.Red);
						InvalidateVis(99);
					}
				}
			}
					
		
		
		
		
		
		
			// Expiry sweep runs unconditionally — force-shown messages (e.g. new-version
			// banner) bypass pShowStatusMessages on the way in, so they need expiry too.
			if (AllMessages.Count > 0)
			// Snapshot via ToArray() — AllMessages can be mutated from other
			// threads / handlers during this expiry sweep. Iterating the live
			// list crashed NT8 with "Collection was modified; enumeration
			// operation may not execute." (see 2026-04-17 log).
			foreach (MessageAlerts D in AllMessages.ToArray())
				{

					if (D.Switch)
					if (now3 >= D.ExpireTime)
					{
						//Print("hefdsg");

						D.Switch = false;
						InvalidateVis(9);
					}

				}
				
				
				
			{
				bool _iwaNew = false;
				try { _iwaNew = (WorkspaceOptions.GetActiveWorkspaceFromXml == chartWindow.GetWorkspaceName()); } catch { }
				if (_iwaNew != IsInActiveWorkspace)
				{
					if (_diagLog != null)
					{
						try
						{
							_diagLog.Log("SYSTEM", "ACTIVE_WORKSPACE_CHANGED",
								"From=" + IsInActiveWorkspace + "|To=" + _iwaNew
								+ "|ActiveXml=" + (WorkspaceOptions.GetActiveWorkspaceFromXml ?? "?")
								+ "|WindowName=" + (chartWindow != null ? chartWindow.GetWorkspaceName() : "null")
								+ "|Origin=Timer3");
						}
						catch { }
					}
					IsInActiveWorkspace = _iwaNew;
				}
			}
				
				
				
				
//			Print("WorkspaceOptions " + WorkspaceOptions.GetActiveWorkspaceFromXml);
				
//			Print("chartWindow.GetWorkspaceName() " + chartWindow.GetWorkspaceName());

				
			if (!NoAccountsConnected)
			timer3.Dispatcher.InvokeAsync(() =>
			{
				
				
				GetAllPerformanceStats();
				
				
			});
					
			
			
			// get rid of this refresh

			if (LimitPriceToTimeOutOfSync2.Count > 0)
				InvalidateVis(23);

			// Once a minute, prune account-keyed dicts for accounts no longer
			// in Account.All (e.g. user removed the account) so the dicts don't
			// accumulate ghost entries over long sessions. Also compacts
			// AllMessages and caps ResubmittedOrders to prevent unbounded growth
			// from rejected-order resubmissions and toast tombstones.
			if (now3 >= _nextSoakWatchdogTime)
			{
				_nextSoakWatchdogTime = now3.AddSeconds(60);

				HashSet<string> _liveAccts = new HashSet<string>();
				foreach (Account _aa in Account.All.ToList())
					_liveAccts.Add(_aa.Name);

				// Collect dead account names by scanning _cellLastValue (superset
				// of known dashboard accounts). Any key not in Account.All is dead.
				List<string> _deadAccts = null;
				foreach (var _kv in _cellLastValue)
				{
					if (!_liveAccts.Contains(_kv.Key))
					{
						if (_deadAccts == null) _deadAccts = new List<string>();
						_deadAccts.Add(_kv.Key);
					}
				}
				// Also scan the sparkline/progress/latency dicts — they can hold
				// accounts that never appeared in _cellLastValue (e.g. removed
				// before any cell change).
				Action<string> _collectIfDead = delegate(string _k)
				{
					if (!_liveAccts.Contains(_k))
					{
						if (_deadAccts == null) _deadAccts = new List<string>();
						if (!_deadAccts.Contains(_k)) _deadAccts.Add(_k);
					}
				};
				foreach (var _kv in _pnlSparkline) _collectIfDead(_kv.Key);
				foreach (var _kv in _pnlSparklineStamp) _collectIfDead(_kv.Key);
				foreach (var _kv in _goalProgress) _collectIfDead(_kv.Key);
				foreach (var _kv in _lossProgress) _collectIfDead(_kv.Key);
				foreach (var _kv in _copierLatencyMs) _collectIfDead(_kv.Key);
				foreach (var _kv in _copierLatencyStamp) _collectIfDead(_kv.Key);
				foreach (var _kv in _copierConfirmMs) _collectIfDead(_kv.Key);
				foreach (var _kv in _copierConfirmStamp) _collectIfDead(_kv.Key);
				foreach (var _kv in _copierLatencyHist) _collectIfDead(_kv.Key);
				foreach (var _kv in _copierConfirmHist) _collectIfDead(_kv.Key);

				if (_deadAccts != null)
				{
					foreach (string _dk in _deadAccts)
					{
						_cellLastValue.Remove(_dk);
						_cellFlashEnd.Remove(_dk);
						_cellFlashUp.Remove(_dk);
						_pnlSparkline.Remove(_dk);
						_pnlSparklineStamp.Remove(_dk);
						_goalProgress.Remove(_dk);
						_lossProgress.Remove(_dk);
						_copierLatencyMs.Remove(_dk);
						_copierLatencyStamp.Remove(_dk);
						_copierConfirmMs.Remove(_dk);
						_copierConfirmStamp.Remove(_dk);
						_copierLatencyHist.Remove(_dk);
						_copierConfirmHist.Remove(_dk);
					}
				}

				// Sweep abandoned confirmation-latency entries (follower orders that
				// never reported a live state) on the same periodic cadence.
				SweepStaleLatencyPending();

				// Clear privacy name cache if it has grown large. Entries are
				// keyed by raw account name — a few hundred is fine, but if the
				// user cycles workspaces/accounts it could balloon.
				if (_privacyNameCache.Count > 256)
					_privacyNameCache.Clear();

				// Compact AllMessages: drop tombstones (Switch == false) so
				// AddMessage's dupe-check loop doesn't walk a growing list.
				if (AllMessages.Count > 32)
				{
					int _write = 0;
					for (int _r = 0; _r < AllMessages.Count; _r++)
					{
						if (AllMessages[_r].Switch)
						{
							if (_write != _r) AllMessages[_write] = AllMessages[_r];
							_write++;
						}
					}
					if (_write < AllMessages.Count)
						AllMessages.RemoveRange(_write, AllMessages.Count - _write);
				}

				// Cap ResubmittedOrders — retain only the most recent 500 ids.
				// The list is only used for .Contains() dedupe on rejection
				// resubmissions, so older ids can be safely forgotten.
				if (ResubmittedOrders.Count > 500)
				{
					int _drop = ResubmittedOrders.Count - 500;
					ResubmittedOrders.RemoveRange(0, _drop);
				}
			}

			return;
			
			

						
//				TriggerCustomEvent(o =>
//   				{
					
//						}, null);	
			
			
			
//			if (SoundAlerts.Count > 0)
//			{
				
//				string sss = SoundAlerts[0];
				
//				PlaySound(sss);
				
//				SoundAlerts.Remove(sss);
				
//			}
			
			
			
			
			
			
			
		
			
			
		}
		
	
