		SharpDX.DirectWrite.TextFormat LowerMessagesMainText1;
        SharpDX.DirectWrite.TextFormat LowerMessagesMainText2;
		// Wrap-enabled format for cell tooltips so long tip text flows onto
		// multiple lines instead of spilling off the right edge of the box.
		SharpDX.DirectWrite.TextFormat CellTipFormat;

		
		
		private void CreateTextFormats()
		{
				if (ChartControl == null)
					return;
							
			TopRowText = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+pFontSizeTopRow).ToDirectWriteTextFormat();
            TopRowText.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
            TopRowText.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
            TopRowText.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;
								
			BottomRowText = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+pFontSizeB).ToDirectWriteTextFormat();
            BottomRowText.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
            BottomRowText.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
            BottomRowText.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;
			
			
											

			
			
			BottomRowText2 = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+pFontSizeB+2).ToDirectWriteTextFormat();
            BottomRowText2.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
            BottomRowText2.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
            BottomRowText2.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;			
			
			
			// At high DPI, bump cell font slightly so dashboard text doesn't
			// look small inside its row. 100% DPI: +0 (no change). 125-149%: +0.
			// 150-199%: +1pt. 200%+: +2pt. Floored so low-DPI scenes are untouched.
			// Only applied to the cell formats actually used for dashboard rows
			// (MainTextCenter / MainTextLeft / CellFormat) to keep scope small.
			int _cellFontBump = (dpiScaleY > 1.0)
				? (int)Math.Floor((dpiScaleY - 1.0) * 2.0)
				: 0;
			float _cellFontSz = (float)TextFont3.Size + _cellFontBump;

			MainTextCenter = new SimpleFont(TextFont3.Family.ToString(), _cellFontSz).ToDirectWriteTextFormat();
            MainTextCenter.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center; // leading = left.
            MainTextCenter.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center; // far = bottom.
            MainTextCenter.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

			CellFormat = MainTextCenter;

			MainTextLeft = new SimpleFont(TextFont3.Family.ToString(), _cellFontSz).ToDirectWriteTextFormat();
            MainTextLeft.TextAlignment = SharpDX.DirectWrite.TextAlignment.Leading; // leading = left.
            MainTextLeft.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center; // far = bottom.
            MainTextLeft.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

			// Italic variant of MainTextLeft for affordance hints like the
			// "edit" label in the Actions column on total rows. SimpleFont
			// doesn't expose italic styling, so build the TextFormat directly
			// through the DirectWrite factory.
			MainTextLeftItalic = new SharpDX.DirectWrite.TextFormat(
				NinjaTrader.Core.Globals.DirectWriteFactory,
				TextFont3.Family.ToString(),
				null,
				SharpDX.DirectWrite.FontWeight.Normal,
				SharpDX.DirectWrite.FontStyle.Italic,
				SharpDX.DirectWrite.FontStretch.Normal,
				(float)TextFont3.Size);
			MainTextLeftItalic.TextAlignment = SharpDX.DirectWrite.TextAlignment.Leading;
			MainTextLeftItalic.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			MainTextLeftItalic.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

			// Center-aligned italic — same size/family as TextFont3, used for
			// the row-2 reveal hints.
			MainTextCenterItalic = new SharpDX.DirectWrite.TextFormat(
				NinjaTrader.Core.Globals.DirectWriteFactory,
				TextFont3.Family.ToString(),
				null,
				SharpDX.DirectWrite.FontWeight.Normal,
				SharpDX.DirectWrite.FontStyle.Italic,
				SharpDX.DirectWrite.FontStretch.Normal,
				(float)TextFont3.Size);
			MainTextCenterItalic.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
			MainTextCenterItalic.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			MainTextCenterItalic.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

			// QRG title: 3pt larger than body, semibold, left-aligned.
			QrgTitleFormat = new SharpDX.DirectWrite.TextFormat(
				NinjaTrader.Core.Globals.DirectWriteFactory,
				TextFont3.Family.ToString(),
				null,
				SharpDX.DirectWrite.FontWeight.SemiBold,
				SharpDX.DirectWrite.FontStyle.Normal,
				SharpDX.DirectWrite.FontStretch.Normal,
				(float)TextFont3.Size + 3f);
			QrgTitleFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Leading;
			QrgTitleFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			QrgTitleFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

			// QRG small: 2pt smaller than body for the timestamp row.
			QrgSmallFormat = new SharpDX.DirectWrite.TextFormat(
				NinjaTrader.Core.Globals.DirectWriteFactory,
				TextFont3.Family.ToString(),
				null,
				SharpDX.DirectWrite.FontWeight.Normal,
				SharpDX.DirectWrite.FontStyle.Normal,
				SharpDX.DirectWrite.FontStretch.Normal,
				Math.Max(8f, (float)TextFont3.Size - 2f));
			QrgSmallFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Trailing;
			QrgSmallFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			QrgSmallFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;
			
			MainTextRight = TextFont3.ToDirectWriteTextFormat();
            MainTextRight.TextAlignment = SharpDX.DirectWrite.TextAlignment.Trailing; // leading = left.
            MainTextRight.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center; // far = bottom.
            MainTextRight.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

			CellTipFormat = TextFont3.ToDirectWriteTextFormat();
			CellTipFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Leading;
			CellTipFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Near;
			CellTipFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.Wrap;
			
			
			SyncMainText1 = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+pFontSizeTopRow2).ToDirectWriteTextFormat();
			SyncMainText1.TextAlignment = SharpDX.DirectWrite.TextAlignment.Leading;
			SyncMainText1.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			SyncMainText1.WordWrapping = SharpDX.DirectWrite.WordWrapping.Wrap;

			SyncMainText2 = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+pFontSizeTopRow2).ToDirectWriteTextFormat();
			SyncMainText2.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
			SyncMainText2.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			SyncMainText2.WordWrapping = SharpDX.DirectWrite.WordWrapping.Wrap;
			
			CheckText = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+4).ToDirectWriteTextFormat();
            CheckText.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
            CheckText.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
            CheckText.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

			// CheckBoxTinyFormat — glyph drawn centered in the 9-px checkbox.
			// Sized slightly larger than the box on purpose so the ✓ stroke
			// reads at a normal weight instead of a thin hairline; the
			// overflow beyond the outline is intentional for legibility.
			float _cbFontSize = (float)Math.Max(14, TextFont3.Size + 4);
			CheckBoxTinyFormat = new SharpDX.DirectWrite.TextFormat(
				NinjaTrader.Core.Globals.DirectWriteFactory,
				TextFont3.Family.ToString(),
				null,
				SharpDX.DirectWrite.FontWeight.Bold,
				SharpDX.DirectWrite.FontStyle.Normal,
				SharpDX.DirectWrite.FontStretch.Normal,
				_cbFontSize);
			CheckBoxTinyFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
			CheckBoxTinyFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			CheckBoxTinyFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;

			// XText: middle-size font for the X close-button column. +1 pt sits
			// between MainTextCenter (12pt, too small) and CheckText (16pt, too big)
			// so the X glyph reads at roughly the same visual weight as the
			// checkmarks without looking oversized. Built via SimpleFont (same
			// path as MainTextCenter / CheckText) so the rendering settings stay
			// consistent with the rest of the table — building TextFormat directly
			// produces a visibly different glyph.
			XText = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+1).ToDirectWriteTextFormat();
            XText.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
            XText.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
            XText.WordWrapping = SharpDX.DirectWrite.WordWrapping.NoWrap;
			
				
//			CenterText = new SharpDX.DirectWrite.TextFormat(Core.Globals.DirectWriteFactory,
//	                "Arial",
//	                SharpDX.DirectWrite.FontWeight.Normal,
//	                SharpDX.DirectWrite.FontStyle.Normal,
//	                SharpDX.DirectWrite.FontStretch.Normal,
//	                11.0F);
				
//			CenterText = ChartControl.Properties.LabelFont.ToDirectWriteTextFormat();
			// Message font: pull the family from the chart's LabelFont (matches ECT) with
			// a fixed 16pt size scaled for DPI so the banners render consistently across
			// high-DPI displays.
			float _msgFontSize = (float)Math.Round(16.0 * dpiScaleY, 0);
			CenterText = new SimpleFont(ChartControl.Properties.LabelFont.Family.ToString(), _msgFontSize).ToDirectWriteTextFormat();
			CenterText.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
			CenterText.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			CenterText.WordWrapping = SharpDX.DirectWrite.WordWrapping.Wrap;
			
						
        	LowerMessagesMainText1 = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+pFontSizeTopRow3).ToDirectWriteTextFormat();
            LowerMessagesMainText1.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
            LowerMessagesMainText1.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
            LowerMessagesMainText1.WordWrapping = SharpDX.DirectWrite.WordWrapping.Wrap;
			
       		LowerMessagesMainText2 = new SimpleFont(TextFont3.Family.ToString(), TextFont3.Size+pFontSizeTopRow3).ToDirectWriteTextFormat();
            LowerMessagesMainText2.TextAlignment = SharpDX.DirectWrite.TextAlignment.Trailing;
            LowerMessagesMainText2.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
            LowerMessagesMainText2.WordWrapping = SharpDX.DirectWrite.WordWrapping.Wrap;

			LicenseVerifyFormat = new SimpleFont("Arial", 14).ToDirectWriteTextFormat();
			LicenseVerifyFormat.TextAlignment = SharpDX.DirectWrite.TextAlignment.Center;
			LicenseVerifyFormat.ParagraphAlignment = SharpDX.DirectWrite.ParagraphAlignment.Center;
			LicenseVerifyFormat.WordWrapping = SharpDX.DirectWrite.WordWrapping.Wrap;
			
											
							

						
							
			
			
			
		}

		private void DisposeTF(TextFormat TF)
		{
			// Note: setting the parameter to null doesn't affect the caller's field.
			// DisposeTextFormats() below explicitly nulls each field after disposal.
			TF?.Dispose();
		}


		private void DisposeTextFormats()
		{
			_renderCacheDirty = true; // fonts changed → column widths will differ
			// Dispose AND explicitly null out each field so the `== null` checks
			// in OnRender trigger recreation of the text format. A disposed object
			// is not null, so without this, the fields would reference zombie objects.
			DisposeTF(ButtonText);			ButtonText = null;
			DisposeTF(textFormat2);			textFormat2 = null;
			DisposeTF(CellFormat);			CellFormat = null;

			DisposeTF(TopRowText);			TopRowText = null;
			DisposeTF(BottomRowText);		BottomRowText = null;
			DisposeTF(BottomRowText2);		BottomRowText2 = null;
			DisposeTF(MainTextCenter);		MainTextCenter = null;
			DisposeTF(MainTextLeft);		MainTextLeft = null;
			DisposeTF(MainTextLeftItalic);	MainTextLeftItalic = null;
			DisposeTF(MainTextCenterItalic); MainTextCenterItalic = null;
			DisposeTF(CheckBoxTinyFormat);  CheckBoxTinyFormat  = null;
			DisposeTF(QrgTitleFormat);		QrgTitleFormat = null;
			DisposeTF(QrgSmallFormat);		QrgSmallFormat = null;
			DisposeTF(MainTextRight);		MainTextRight = null;
			DisposeTF(SyncMainText1);		SyncMainText1 = null;
			DisposeTF(SyncMainText2);		SyncMainText2 = null;
			DisposeTF(CheckText);			CheckText = null;
			DisposeTF(XText);				XText = null;
			DisposeTF(CenterText);			CenterText = null;

			DisposeTF(LowerMessagesMainText1); LowerMessagesMainText1 = null;
			DisposeTF(LowerMessagesMainText2); LowerMessagesMainText2 = null;
			DisposeTF(CellTipFormat);		CellTipFormat = null;
			DisposeTF(LicenseVerifyFormat);	LicenseVerifyFormat = null;
		}

		
