        public override void OnRenderTargetChanged()
        {

			AllowRedraw = true;


			//return;

			// Dispose cached tooltip layouts — they reference CellFormat which is about to be disposed
			if (TooltipCachedLayout != null)
			{
				TooltipCachedLayout.Dispose();
				TooltipCachedLayout = null;
				TooltipCachedText = null;
			}
			if (PickerTooltipCachedLayout != null)
			{
				PickerTooltipCachedLayout.Dispose();
				PickerTooltipCachedLayout = null;
				PickerTooltipCachedText = null;
			}
			if (_instModeTooltipLayout != null)
			{
				_instModeTooltipLayout.Dispose();
				_instModeTooltipLayout = null;
				_instModeTooltipText = null;
			}
			if (_profileHoverTipLayout != null)
			{
				_profileHoverTipLayout.Dispose();
				_profileHoverTipLayout = null;
				_profileHoverTipCachedText = null;
			}

			DisposeBrushes();
			DisposeTextFormats();
		   

				
		    if (RenderTarget != null)
		    {
				
				CreateAllBrushes();
				CreateTextFormats();

				
		    }						
				
			
            if (RenderTarget != null)
            {
                pOrderDnOutlineStroke.RenderTarget = RenderTarget;
            }
        }
		
		
		
		private void CreateAllBrushes()
		{
			

			
			//myProperties = ChartControl.Properties;
				
		        // Create brushes once here
		     
				ChartTextBrushDX40 = CreateBrush(GetTextColor(ThisChartBackground()), 40/100f);
				ChartTextBrushDX20 = CreateBrush(GetTextColor(ThisChartBackground()), 20/100f);
				ChartTextBrushDX70 = CreateBrush(GetTextColor(ThisChartBackground()), 70/100f);
				ChartTextBrushDX10 = CreateBrush(GetTextColor(ThisChartBackground()), 10/100f);
				DragTintBrushDX    = CreateBrush(GetTextColor(ThisChartBackground()), 10/100f);
				HelpBackdropBrushDX = CreateBrush(Brushes.Black, 50/100f);
			HelpLinkBrushDX = CreateBrush(Brushes.CornflowerBlue, 100/100f);
			// QRG fade brushes — overlay-background color at decreasing alpha,
			// stacked from outermost edge inward to simulate a gradient fade
			// at the top and bottom of the scrollable body.
			QrgFadeBrush1 = CreateBrush(ThisChartBackground(), 80/100f);
			QrgFadeBrush2 = CreateBrush(ThisChartBackground(), 50/100f);
			QrgFadeBrush3 = CreateBrush(ThisChartBackground(), 25/100f);
				CellFlashUpBrushDX     = CreateBrush(pIsFundedColor, 75/100f);
				CellFlashUpBrushDX66   = CreateBrush(pIsFundedColor, 50/100f);
				CellFlashUpBrushDX33   = CreateBrush(pIsFundedColor, 25/100f);
				CellFlashDownBrushDX   = CreateBrush(pIsLossColor,   75/100f);
				CellFlashDownBrushDX66 = CreateBrush(pIsLossColor,   50/100f);
				CellFlashDownBrushDX33 = CreateBrush(pIsLossColor,   25/100f);
				LatencyWarnBrushDX     = CreateBrush(Brushes.Goldenrod, 90/100f);
				// Five-stop glow gradient: brightest stop sits closest to the
				// overlay rect, then steps down 15% → 11% → 8% → 5% → 3%.
				// (Bumped up from 10/7/5/3/2% — previous version was too subtle
				// to read on darker chart backgrounds.)
				OverlayGlowBrushDX10 = CreateBrush(GetTextColor(ThisChartBackground()), 15/100f);
			PickerHoverGlowBrushDX = CreateBrush(GetTextColor(ThisChartBackground()), 25/100f);
				OverlayGlowBrushDX7  = CreateBrush(GetTextColor(ThisChartBackground()), 11/100f);
				OverlayGlowBrushDX5  = CreateBrush(GetTextColor(ThisChartBackground()),  8/100f);
				OverlayGlowBrushDX3  = CreateBrush(GetTextColor(ThisChartBackground()),  5/100f);
				OverlayGlowBrushDX2  = CreateBrush(GetTextColor(ThisChartBackground()),  3/100f);
				ChartTextBrushDXYellow = CreateBrush(Brushes.Goldenrod, 100/100f);
				// Warm goldenrod — goldenrod (#DAA520) nudged toward orange.
				// Sits between Goldenrod and DarkOrange for a warmer accent that
				// reads as "gold with warmth" rather than pure yellow or coral.
				PickerAccentBrushDX = CreateBrush(
					FrozenRgbBrush(230, 150, 30),
					100/100f);
				ChartTextBrushDXRed = CreateBrush(Brushes.Red, 100/100f);
				TextBuyBrushDX = CreateBrush(pBackBuyColor3, 100/100f);
				TextSellBrushDX = CreateBrush(pBackSellColor3, 100/100f);
				// Soft green halo behind checked boxes — 18% opacity so it reads
				// as a subtle glow rather than a bright fill.
				// Circular halos are dim on purpose — most of the visual
			// "glow" weight comes from the check-shape shadow below, which
			// hugs the check itself. Halos just give a subtle wash.
			CheckGlowBrushDX = CreateBrush(GetTextColor(ThisChartBackground()), 2/100f);    // soft outer halo (theme text color, very faint)
			CheckGlowBrushDX2 = CreateBrush(GetTextColor(ThisChartBackground()), 4/100f);  // inner halo (theme text color, subtle)
			// Darker muted green for the check-shape shadow. Stronger than
			// the circular halos so the "aura" traces the check's outline
			// clearly without making the halo wash feel neon.
			CheckShadowBrushDX = CreateBrush(pCompDNColor, 55/100f);
				
				
				
				ChartTextBrushDXH = CreateBrush(ThisChartBackground(), pButtonHighlightO/100f);
				ChartTextBrushDX = CreateBrush(GetTextColor(ThisChartBackground()), 100/100f);
				
				
				ChartBackgroundBrushDX = CreateBrush(ThisChartBackground(), 100/100f);		
				ThisBrushDX = CreateBrush(Brushes.White, 100/100f);
				
			
				
				
				TableFinalBackgroundBrushDXBuy1 = CreateBrush(pBackBuyColor, (pCompPOSOpacity)/100f);
				TableFinalBackgroundBrushDXBuy2 = CreateBrush(pBackBuyColor, (pCompPOSOpacity+pHighlightAmount)/100f);
				
				TableFinalBackgroundBrushDXSell1 = CreateBrush(pBackSellColor, (pCompPOSOpacity)/100f);
				TableFinalBackgroundBrushDXSell2 = CreateBrush(pBackSellColor, (pCompPOSOpacity+pHighlightAmount)/100f);
				
				ButtonOutline1DX = CreateBrush(pCompDNColor, (6)/100f);
				ButtonOutline2DX = CreateBrush(pCompDNColor, (10)/100f);
			
			
			
			
				
				ChartBackgroundFadeBrushDX = CreateBrush(ThisChartBackground(), 50/100f);
				
				TrailingGoodBrushDX1 = CreateBrush(pTrailingGoodColor, 20/100f);
				TrailingGoodBrushDX2 = CreateBrush(pTrailingGoodColor, (20+pHighlightAmount)/100f);
				
				TrailingWarningBrushDX1 = CreateBrush(pTrailingWarningColor, 20/100f);
				TrailingWarningBrushDX2 = CreateBrush(pTrailingWarningColor, (20+pHighlightAmount)/100f);			
				
				TrailingBadBrushDX1 = CreateBrush(pTrailingBadColor, 20/100f);
				TrailingBadBrushDX2 = CreateBrush(pTrailingBadColor, (20+pHighlightAmount)/100f);
	
				TrailingBlownBrushDX1 = CreateBrush(pTrailingBlownColor, 20/100f);
				TrailingBlownBrushDX2 = CreateBrush(pTrailingBlownColor, (20+pHighlightAmount)/100f);
	
				FundedBrushDX1 = CreateBrush(pIsFundedColor, 20/100f);
				FundedBrushDX2 = CreateBrush(pIsFundedColor, (20+pHighlightAmount)/100f);
				FundedBrushDX3 = CreateBrush(pIsFundedColor, (pCompMinOpacityH+pHighlightAmount)/100f);
				LossBrushDX1 = CreateBrush(pIsLossColor, 20/100f);
				LossBrushDX2 = CreateBrush(pIsLossColor, (20+pHighlightAmount)/100f);
				LossBrushDX3 = CreateBrush(pIsLossColor, (pCompMinOpacityH+pHighlightAmount)/100f);			
				
			
			
		
				TableBackgroundBrushDX = CreateBrush(pCompDNColor, (pCompMinOpacity)/100f);
				TableBackgroundBrushDXO = CreateBrush(pCompDNColor, (pCompMinOpacity)/100f);
				// Alternating row brush — uses text color (not background color) for visibility
