		private void ChartControl_PreviewKeyDown(object sender, KeyEventArgs e)
		{

			// ESC cancels an in-progress column reorder drag, restoring the snapshot taken
			// at mouse-down time. Runs even when pKeyboardEnabled is false — this is a
			// mouse-interaction cancel, not a keyboard shortcut.
			if (e.Key == Key.Escape && _columnDragArmed)
			{
				if (_columnDragActivated && _columnDragOrderSnapshot != null && ColumnDisplayOrderList != null)
				{
					ColumnDisplayOrderList.Clear();
					ColumnDisplayOrderList.AddRange(_columnDragOrderSnapshot);
					SyncColumnDisplayOrderNames();
				}
				_columnDragArmed = false;
				_columnDragActivated = false;
				_draggingColumnLogical = -1;
				_draggingColumnDisplayIdx = -1;
				_columnDragOrderSnapshot = null;
				_pendingSortColumnClick = null; // also cancel the deferred sort click
				InvalidateVis(100);
				e.Handled = true;
				return;
			}

			// Esc closes the latency menu.
			if (e.Key == Key.Escape && _latencyMenuOpen)
			{
				_latencyMenuOpen = false;
				InvalidateVis(133);
				e.Handled = true;
				return;
			}

			// Esc closes the keybinds cheat sheet (when not in a drag).
			if (e.Key == Key.Escape && _profilePickerOpen)
			{
				_profilePickerOpen = false;
				_kbSelectedProfileItem = -1;
				InvalidateVis(134);
				e.Handled = true;
				return;
			}

			// Keyboard navigation in the profile picker: Up/Down/Home/End/Enter.
			if (_profilePickerOpen && (e.Key == Key.Up || e.Key == Key.Down || e.Key == Key.Home || e.Key == Key.End || e.Key == Key.Enter))
			{
				int _nItems = _profilePickerItemNames.Count;
				if (_nItems == 0) return;
				if (e.Key == Key.Enter)
				{
					int _sel = _kbSelectedProfileItem >= 0 ? _kbSelectedProfileItem : _hoveredProfileItem;
					if (_sel >= 0 && _sel < _nItems)
					{
						string _selName = _profilePickerItemNames[_sel];
						if (_selName != "---") ActivateProfileMenuItem(_selName);
					}
					_kbSelectedProfileItem = -1;
					e.Handled = true;
					return;
				}
				int _cur = _kbSelectedProfileItem >= 0 ? _kbSelectedProfileItem : _hoveredProfileItem;
				int _step = (e.Key == Key.Down) ? 1 : (e.Key == Key.Up) ? -1 : 0;
				if (e.Key == Key.Home) _cur = -1;
				if (e.Key == Key.End) _cur = _nItems;
				int _dir = (e.Key == Key.End) ? -1 : 1;
				if (_step != 0)
				{
					_cur = (_cur < 0) ? (_step > 0 ? -1 : _nItems) : _cur;
					_dir = _step;
				}
				for (int _w = 0; _w < _nItems * 2; _w++)
				{
					_cur += _dir;
					if (_cur < 0) _cur = _nItems - 1;
					if (_cur >= _nItems) _cur = 0;
					if (_profilePickerItemNames[_cur] != "---") break;
				}
				_kbSelectedProfileItem = _cur;
				InvalidateVis(136);
				e.Handled = true;
				return;
			}
			if (e.Key == Key.Escape && _cheatSheetOpen)
			{
				_cheatSheetOpen = false;
				InvalidateVis(120);
				e.Handled = true;
				return;
			}

			// Keyboard scrolling inside the Quick Reference Guide overlay —
			// mirrors the account-table keybinds so they feel consistent.
			if (_cheatSheetOpen)
			{
				int _qrgStep = 0;
				if (e.Key == Key.Down)            _qrgStep = 1;
				else if (e.Key == Key.Up)         _qrgStep = -1;
				else if (e.Key == Key.PageDown)   _qrgStep = 10;
				else if (e.Key == Key.PageUp)     _qrgStep = -10;
				else if (e.Key == Key.Home)       { _csScrollOffset = 0; InvalidateVis(130); e.Handled = true; return; }
				else if (e.Key == Key.End)        { _csScrollOffset = int.MaxValue; InvalidateVis(131); e.Handled = true; return; }
				if (_qrgStep != 0)
				{
					_csScrollOffset = Math.Max(0, _csScrollOffset + _qrgStep);
					InvalidateVis(132);
					e.Handled = true;
					return;
				}
			}

			// Table scrolling via keyboard — only when the filter is NOT active.
			// PageUp/PageDown jump by full visible page, Home/End go to top/bottom.
			if (!_filterActive && MaximumAccountRows > 0 && TotalAccounts > MaximumAccountRows)
			{
				if (e.Key == Key.PageUp)
				{
					ScrollBy(-MaximumAccountRows);
					InvalidateVis(116);
					e.Handled = true;
					return;
				}
				if (e.Key == Key.PageDown)
				{
					ScrollBy(MaximumAccountRows);
					InvalidateVis(116);
					e.Handled = true;
					return;
				}
				if (e.Key == Key.Home)
				{
					SetScrollImmediate(0);
					InvalidateVis(116);
					e.Handled = true;
					return;
				}
				if (e.Key == Key.End)
				{
					int _endTarget = Math.Max(0, TotalAccounts - MaximumAccountRows);
					if (pShowFollowersAtTop && AllDuplicateAccounts != null)
						_endTarget = Math.Max(0, _endTarget - AllDuplicateAccounts.Count);
					SetScrollImmediate(_endTarget);
					InvalidateVis(116);
					e.Handled = true;
					return;
				}
			}

			// Filter / search handling — always on, not gated by pKeyboardEnabled.
			//   '/'  : activate filter (or start a fresh one if it was already active)
			//   Esc  : if filter is active, exit filter mode and clear it
			//   BS   : delete last char when filter active
			//   A-Z, 0-9, space, punctuation: append when filter active
			if (_filterActive)
			{
				if (e.Key == Key.Escape)
				{
					_filterActive = false;
					_accountFilter = "";
					InvalidateVis(106);
					e.Handled = true;
					return;
				}
				if (e.Key == Key.Back)
				{
					if (_accountFilter.Length > 0)
						_accountFilter = _accountFilter.Substring(0, _accountFilter.Length - 1);
					InvalidateVis(107);
					e.Handled = true;
					return;
				}
				if (e.Key == Key.Enter)
				{
					_filterActive = false; // keep filter text, just exit edit mode
					InvalidateVis(108);
					e.Handled = true;
					return;
				}
				// Append a visible character: letters, digits, space, common punctuation
				string _appendChar = null;
				if (e.Key >= Key.A && e.Key <= Key.Z)
				{
					bool shift = (Keyboard.Modifiers & ModifierKeys.Shift) == ModifierKeys.Shift;
					char c = (char)('a' + (int)(e.Key - Key.A));
					_appendChar = shift ? char.ToUpper(c).ToString() : c.ToString();
				}
				else if (e.Key >= Key.D0 && e.Key <= Key.D9)
				{
					_appendChar = ((char)('0' + (int)(e.Key - Key.D0))).ToString();
				}
				else if (e.Key >= Key.NumPad0 && e.Key <= Key.NumPad9)
				{
					_appendChar = ((char)('0' + (int)(e.Key - Key.NumPad0))).ToString();
				}
				else if (e.Key == Key.Space)
				{
					_appendChar = " ";
				}
				else if (e.Key == Key.OemMinus || e.Key == Key.Subtract)
				{
					_appendChar = "-";
				}
				if (_appendChar != null)
				{
					_accountFilter += _appendChar;
					InvalidateVis(109);
					e.Handled = true;
					return;
				}
			}
			else if (e.Key == Key.OemQuestion) // '/' or '?' (shift) on US layout
			{
				bool _shiftDown = (Keyboard.Modifiers & ModifierKeys.Shift) == ModifierKeys.Shift;
				if (_shiftDown)
				{
					// Shift+/ = '?' — toggle the keybinds cheat sheet overlay.
					if (_cheatSheetOpen)
					{
						// Closing — always immediate.
						_cheatSheetOpen = false;
						_qrgOpenPending = false;
					}
					else if (_qrgRemoteLines != null && _qrgRemoteLines.Length > 0)
					{
						// Remote already cached — open immediately, refresh in background.
						_cheatSheetOpen = true;
						_csScrollOffset = 0;
						BeginFetchQrgDoc(true);
					}
					else
					{
						// Cold cache — defer opening until the fetch completes
						// (or a safety timeout in OnMouseMove / render). This
						// avoids showing hardcoded defaults that then jump to
						// the remote layout once the network round-trip lands.
						_qrgOpenPending = true;
						_qrgOpenPendingStart = DateTime.Now;
						BeginFetchQrgDoc(true);
					}
					InvalidateVis(119);
				}
				else
				{
					_filterActive = true;
					// Don't clear existing filter — let user refine.
					InvalidateVis(110);
				}
				e.Handled = true;
				return;
			}

			if (!pKeyboardEnabled)
				return;

			// Ctrl+C copies the hovered cell value (or the whole row if no specific column hovered)
			if (e.Key == Key.C && (Keyboard.Modifiers & ModifierKeys.Control) == ModifierKeys.Control)
			{
				if (HoveredRow > 0 && AllColumns != null && AllColumns.Count > 0)
				{
					try
					{
						string clipboardText = string.Empty;
						if (HoveredHeaderColumn >= 0 && ColumnDisplayOrderList != null && HoveredHeaderColumn < ColumnDisplayOrderList.Count)
						{
							int logicalCol = ColumnDisplayOrderList[HoveredHeaderColumn];
							if (logicalCol < AllColumns.Count && HoveredRow < AllColumns[logicalCol].Count)
								clipboardText = AllColumns[logicalCol][HoveredRow];
						}
						else
						{
							// No specific column — copy entire row as tab-separated.
							System.Text.StringBuilder sb = new System.Text.StringBuilder();
							for (int c = 0; c < AllColumns.Count; c++)
							{
								if (HoveredRow < AllColumns[c].Count)
								{
									if (sb.Length > 0) sb.Append('\t');
									sb.Append(AllColumns[c][HoveredRow]);
								}
							}
							clipboardText = sb.ToString();
						}
						if (!string.IsNullOrEmpty(clipboardText))
						{
							System.Windows.Clipboard.SetText(clipboardText);
							AddMessage("Copied to clipboard: " + (clipboardText.Length > 60 ? clipboardText.Substring(0, 60) + "..." : clipboardText), 3, Brushes.Goldenrod);
							// Trigger a brief row flash so the user visually confirms what was copied.
							_copyFlashRowI = HoveredRow;
							_copyFlashEnd  = DateTime.Now.AddMilliseconds(CopyFlashDurationMs);
							InvalidateVis(81);
						}
					}
					catch { }
					e.Handled = true;
					return;
				}
			}
			
			//Print("test");
			
			string LastKey = e.Key.ToString();
			
			
			
			
			// doesn't work for up and down arrows

//			if (e.Key == Key.Up)
//			{
				
//				Print("UP");
				
//			}
			
//			switch (e.KeyCode)
//			{
				
				
//			}
			

			
			if (SelectedMultiplierAccount != string.Empty && pUseNumberForMultiplier)
			{
				SelectedMultiplerTime = DateTime.Now;
				
				//InvalidateVis(1);
			
			
				
				double dddd = KeyNumber(LastKey);
				
				
				if (dddd != -1)
				SetAccountData("",SelectedMultiplierAccount,"",dddd.ToString(),"","","","","","");
			
				
			    e.Handled = true;
				
				SelectedMultiplierAccount = string.Empty;
				
				
				InvalidateVis(11);
					
				
				
			}
			else
			{
						
				bool handled = false;
				
				bool doscrollalso = true;
				
				
				if (LastKey == pKeyScrollUp)
				{
					handled = DoWheel(1, doscrollalso, false);
				}
				if (LastKey == pKeyScrollDn)
				{
					handled = DoWheel(-1, doscrollalso, false);
				}

				// Arrow key navigation — scrolls table up/down (in addition to user keybinds)
				if (e.Key == Key.Up || e.Key == Key.PageUp)
				{
					handled = DoWheel(1, true, false);
					if (e.Key == Key.PageUp)
					{
						// Page up scrolls multiple rows
						for (int step = 0; step < 4; step++)
							DoWheel(1, true, false);
					}
				}
				if (e.Key == Key.Down || e.Key == Key.PageDown)
				{
					handled = DoWheel(-1, true, false);
					if (e.Key == Key.PageDown)
					{
						for (int step = 0; step < 4; step++)
							DoWheel(-1, true, false);
					}
				}
				if (e.Key == Key.Home)
				{
					SetScrollImmediate(0);
					InvalidateVis(82);
					handled = true;
				}
				if (e.Key == Key.End)
				{
					SetScrollImmediate(Math.Max(0, TotalAccounts - MaximumAccountRows));
					InvalidateVis(83);
					handled = true;
				}

				if (handled)
					e.Handled = true;
	
				
				
				
			}
			
			
		
			
			
//			if (pOneClickOrdersEnabled2 && pActivateWithKeys)
//			{
//				IsCTRLNow = Keyboard.IsKeyDown(Key.LeftCtrl);
//				IsALTNow = Keyboard.IsKeyDown(Key.LeftAlt);
				
