		private int AdjustmentRows = 0;
		// Set to true by property setters, column toggles, and text format
		// changes so the column-width and button-measurement caches rebuild.
		// Avoids clearing and refilling them every single frame.
		private bool _renderCacheDirty = true;

		// Scroll helpers — momentum was removed because the dispatcher timer
		// couldn't keep up with NinjaTrader's render loop, making scrolling worse.
		// Both ScrollBy and SetScrollImmediate now apply position changes instantly.
		private void ScrollBy(int rowDelta)
		{
			int _prev = AdjustmentRows;
			SetScrollImmediate(AdjustmentRows + rowDelta);
			// Force AllDrawings cache rebuild when the scroll position actually
			// changed. Without this, the replay cache holds stale entries from
			// the previous scroll position and the render blinks/shows garbage
			// on frames where AllowRedraw is false.
			if (AdjustmentRows != _prev)
				AllowRedraw = true;
			InvalidateVis(91);
		}

		private void SetScrollImmediate(int newPos)
		{
			int maxScroll = Math.Max(0, TotalAccounts - MaximumAccountRows);
			if (pShowFollowersAtTop)
				maxScroll = Math.Max(0, TotalAccounts - MaximumAccountRows - AllDuplicateAccounts.Count);
			AdjustmentRows = Math.Max(0, Math.Min(maxScroll, newPos));
			// Persist to the hidden workspace property so reloads restore this position.
			pSavedScrollPosition = AdjustmentRows;
		}

		// Set from the workspace property setter when NT8 restores the persisted value;
		// applied once TotalAccounts > 0 so we can clamp into the valid range.
		private bool _pendingScrollRestore = false;
		private int  _pendingScrollRestoreValue = 0;
		private void TryRestoreScrollPosition()
		{
			if (!_pendingScrollRestore) return;
			if (TotalAccounts <= 0) return; // wait until account rows exist
			SetScrollImmediate(_pendingScrollRestoreValue);
			_pendingScrollRestore = false;
		}
		private int AdjustmentAmount = 1;
		

	
