		private bool DoWheel (int dirmove, bool scrollwindow, bool ignoreCellValues = false)
		{

//			private string SelectedDailyGoalAccount = string.Empty;
//		private DateTime SelectedDailyGoalTime = DateTime.MinValue;

//		private string SelectedDailyLossAccount = string.Empty;
//		private DateTime SelectedDailyLossTime = DateTime.MinValue;

		//	Print(dirmove);


			bool ehhhhh = false;

			// Post-terminate cooldown: if Size just auto-terminated at 1x or
			// Mode just auto-terminated at Default, swallow wheel events for a
			// brief window so residual wheel spin doesn't start scrolling the
			// account rows (which isn't what the user intended).
			if (_postTerminateBlockTime.Ticks > DateTime.Now.Ticks)
				return true;

			// When ignoreCellValues is true (post-multiplier/ATM cooldown), skip cell-value
			// adjustments but still allow table row scrolling.
			// Throttle: skip table-scroll events within 16ms of the last one (~60fps)
			// so high-resolution mice don't flood the render loop. Cell-value
			// adjustments (multiplier, daily goal, etc.) are NOT throttled.
			if (ignoreCellValues)
			{
				if (scrollwindow)
				{
					DateTime _scrollNow = DateTime.Now;
					if ((_scrollNow - _lastWheelScrollTime).TotalMilliseconds < 16)
						return true; // swallow but report as handled
					_lastWheelScrollTime = _scrollNow;
					int delta = dirmove > 0 ? -AdjustmentAmount : AdjustmentAmount;
					ScrollBy(delta);
					return true;
				}
				return false;
			}

			if (SelectedDailyGoalAccount != string.Empty)
			{
				
				SelectedDailyGoalTime = DateTime.Now.AddSeconds(3);
				
				InvalidateVis(12);

				
				double inc = pAdjustmentDollars;
				double dddd = GetAccountSavedData(SelectedDailyGoalAccount, pAllAccountDailyGoal);
				if (dddd == DefaultForZero)
				{
					SelectedDailyGoalAccount = string.Empty;
					SelectedDailyGoalTime = DateTime.MinValue;
					InvalidateVis(12);
					return true;
				}
				
				if (dirmove > 0)
					dddd = dddd + inc;
				else
					dddd = dddd - inc;
				
				if (pRestrictToZero)
				{
					dddd = Math.Max(0, dddd);
				}

				double CurrentPNL = 0;
				PNLStatistics _goalStats;
				if (FinalPNLStatistics.TryGetValue(SelectedDailyGoalAccount, out _goalStats))
					CurrentPNL = _goalStats.PNLTotal - inc;		
				
				if (dddd < CurrentPNL)
				if (dddd + inc >= CurrentPNL)
				{
					dddd = dddd + inc;
				}
	
				
				if (dddd <= 0)
					SelectedMultiplerTime = DateTime.Now;
	
				LastDailyGoalNumber = dddd;
				
				SetAccountSavedData(SelectedDailyGoalAccount,pAllAccountDailyGoal,dddd.ToString());
			
				
			    ehhhhh = true;
				
				GetAllPerformanceStats();
				InvalidateVis(13);					
				
				
			}
			else if (SelectedDailyLossAccount != string.Empty)
			{
				
				SelectedDailyLossTime = DateTime.Now.AddSeconds(3);
				
				InvalidateVis(14);
		
				
				double inc = pAdjustmentDollars;
				double dddd = GetAccountSavedData(SelectedDailyLossAccount,pAllAccountDailyLoss);
				if (dddd == DefaultForZero)
				{
					SelectedDailyLossAccount = string.Empty;
					SelectedDailyLossTime = DateTime.MinValue;
					InvalidateVis(14);
					return true;
				}
				
				if (dirmove > 0)
					dddd = dddd + inc;
				else
					dddd = dddd - inc;
				
				if (pRestrictToZero)
				{
					dddd = Math.Min(0, dddd);
				}
				
				double CurrentPNL = 0;
				PNLStatistics _lossStats;
				if (FinalPNLStatistics.TryGetValue(SelectedDailyLossAccount, out _lossStats))
					CurrentPNL = _lossStats.PNLTotal + inc;		
				
				if (dddd > CurrentPNL)
				if (dddd - inc <= CurrentPNL)
					dddd = dddd - inc;
				
				
				if (dddd <= 0)
					SelectedMultiplerTime = DateTime.Now;
				
				LastDailyLossNumber = dddd;
				
				SetAccountSavedData(SelectedDailyLossAccount,pAllAccountDailyLoss,dddd.ToString());
			
				
			    ehhhhh = true;
				
				GetAllPerformanceStats();
				InvalidateVis(15);			
				
				
			}
			else if (SelectedPayoutAccount != string.Empty)
			{
				
				SelectedPayoutTime = DateTime.Now.AddSeconds(3);
				
				InvalidateVis(16);
		
				
				double inc = pAdjustmentDollars;
				double dddd = GetAccountSavedData(SelectedPayoutAccount,pAllAccountPayouts);
				
				if (dirmove > 0)
					dddd = dddd + inc;
				else
					dddd = dddd - inc;
				
				if (dddd <= 0)
					SelectedMultiplerTime = DateTime.Now;
				
				dddd = Math.Max(pAdjustmentDollars, dddd);
	
				LastDailyPayoutNumber = dddd;
				
				SetAccountSavedData(SelectedPayoutAccount,pAllAccountPayouts,dddd.ToString());

				
				GetAllPerformanceStats();			
				
			    ehhhhh = true;
				
				InvalidateVis(17);				
				
				
			}			
			
			
			
			
			
			
			else if (SelectedMultiplierAccount != string.Empty)
			{
				SelectedMultiplerTime = DateTime.Now.AddSeconds(3);
				
				InvalidateVis(18);
			
				string ssss = GetAccountMultiplier(SelectedMultiplierAccount);
				
				//Print(ssss);
				
				int variable = 0;

				
				double inc = 1;
				double dddd = 0;
				double.TryParse(ssss, out dddd);
				

				
				if (dirmove > 0)
					dddd = dddd + inc;
				else
					dddd = dddd - inc;

				if (pMultiplierMode == "Quantity")
					dddd = Math.Max(1, dddd);

				dddd = Math.Max(-3, dddd);


				LastSizeNumber = dddd;

				SetAccountData("",SelectedMultiplierAccount,"",dddd.ToString(),"","","","","","");

				// Auto-terminate when Size lands at 1x — from either direction
				// (2x → 1x scrolling down, or 1/2x → 1x scrolling up). Set a
				// brief post-terminate cooldown so residual wheel spin doesn't
				// start scrolling the account rows. A click clears this via
				// ResetAllTimers if the user wants to engage a new cell.
				if (dddd == 1)
				{
					SelectedMultiplierAccount = string.Empty;
					SelectedMultiplerTime = DateTime.Now;
					_postTerminateBlockTime = DateTime.Now.AddMilliseconds(PostTerminateBlockMs);
				}

			    ehhhhh = true;

				InvalidateVis(19);
					
					
			}
			else if (SelectedATMAccount != string.Empty)
			{
				SelectedATMTime	= DateTime.Now.AddSeconds(3);
			 
				string ssss = GetAccountMode(SelectedATMAccount);
				
				
				if (dirmove > 0)
				{
					
					
				}
				
//				Print(SelectedATMAccount);
//				Print(ssss);
//				Print(dirmove);
				
				string newmode = ssss;
				
				if (ssss == "Default")
				{
					if (dirmove > 0)
					{
						if (pMultiplierMode != "Quantity")
							newmode = "Orders";
					}
					else
					{
						// first atm in list
						if (AllATMStrategies.Count > 0)
							newmode = AllATMStrategies[0];
					}
					
				}
				else if (ssss == "Orders")
				{
					if (dirmove > 0)
						newmode = "Executions";
					else
					{
						newmode = "Default";				
					}					
					
				}				
				else if (ssss == "Executions")
				{
					if (dirmove > 0)
						newmode = "Executions";
					else
					{
						newmode = "Orders";
					}					
					
				}	
				else
				{
				
					// up or down list of atms
					int currentatm = GetATMNumber(ssss);
					
					
					if (dirmove > 0)
					{
						// up one atm
						if (currentatm == 0)
						{
							newmode = "Default";
						}
						else
						{
							newmode = AllATMStrategies[currentatm-1];
						}
						
						
					}
					else
					{
						// down one atm
						
						int nexta = Math.Min(currentatm+1,AllATMStrategies.Count-1);
						
 
						
						newmode = AllATMStrategies[nexta];
						
						//newmode = "fakea";
					}	
					
					
					
				}
				

				LastATMSelected = newmode;
	
				
				SetAccountData("",SelectedATMAccount,"","","","","","","",newmode);
				
				if (pMultiplierMode == "Quantity")
				if (newmode != "Default" && newmode != "Orders" && newmode != "Executions")
				{
					
					AtmStrategy ThisOne = null;

					DefaultAtmStrategy.TryGetValue(newmode, out ThisOne);
					
					
									
					SetAccountData("",SelectedATMAccount,"",ThisOne.EntryQuantity.ToString(),"","","","","","");
					
				}
				
					
												
													
				if (newmode != "Executions")
				{
					if (pIsFadeEnabled)	
						SetAccountData("",SelectedATMAccount,"","","","No","","","","");	
				}													
				
				
				
				// Auto-terminate when Mode lands back on "Default" (scrolling up
				// from Orders, Executions, or an ATM). Set a brief
				// post-terminate cooldown so residual wheel spin doesn't start
				// scrolling the account rows. A click clears this via
				// ResetAllTimers if the user wants to engage a new cell.
				if (newmode == "Default")
				{
					SelectedATMAccount = string.Empty;
					SelectedATMTime = DateTime.Now;
					_postTerminateBlockTime = DateTime.Now.AddMilliseconds(PostTerminateBlockMs);
				}


				InvalidateVis(19);
				
				
			}
			else if (scrollwindow)
			{
				// Throttle table scrolling (same as the ignoreCellValues path above)
				DateTime _scrollNow2 = DateTime.Now;
				if ((_scrollNow2 - _lastWheelScrollTime).TotalMilliseconds >= 16)
				{
					_lastWheelScrollTime = _scrollNow2;
					int delta = dirmove > 0 ? -AdjustmentAmount : AdjustmentAmount;
					ScrollBy(delta);
				}
				ehhhhh = true;
			}
			else
			{
				
				
			}
			
			
			
			return ehhhhh;
			
			
		}
		
		
		
