		private string GetColumnNameByDisplayIndex(int displayIdx)
		{
			if (ColumnDisplayOrderList == null || AllColumns == null || displayIdx < 0 || displayIdx >= ColumnDisplayOrderList.Count) return "";
			int colIdx = ColumnDisplayOrderList[displayIdx];
			if (colIdx < 1 || colIdx >= AllColumns.Count || AllColumns[colIdx].Count <= 1) return "";
			return AllColumns[colIdx][1];
		}
		private void SyncColumnDisplayOrderNames()
		{
			if (_diagLog != null)
				_diagLog.Log("UI", "COLUMN_VISIBILITY_SYNC", "ColumnCount=" + (ColumnDisplayOrderList != null ? ColumnDisplayOrderList.Count.ToString() : "0"));
			if (ColumnDisplayOrderList == null || AllColumns == null || ColumnDisplayOrderList.Count == 0) return;
			if (AllColumns.Count <= 1) return;
			var names = new List<string>();
			for (int i = 0; i < ColumnDisplayOrderList.Count; i++)
			{
				int colIdx = ColumnDisplayOrderList[i];
				if (colIdx >= 1 && colIdx < AllColumns.Count)
				{
					var col = AllColumns[colIdx];
					if (col != null && col.Count > 1)
						names.Add(col[1]);
				}
			}
			pColumnDisplayOrderNames = string.Join(",", names);
			pColumnDisplayOrder = string.Join(",", ColumnDisplayOrderList);
		}
		private List<int> GetBlock1DisplayIndices()
		{
			var list = new List<int>();
			if (ColumnDisplayOrderList == null || AllColumns == null) return list;
			for (int i = 0; i <= ColumnDisplayOrderList.Count - 3; i++)
			{
				if (GetColumnNameByDisplayIndex(i) == "Daily Loss" && GetColumnNameByDisplayIndex(i + 1) == "Daily Goal" && GetColumnNameByDisplayIndex(i + 2) == "Auto Exit")
				{
					list.Add(i); list.Add(i + 1); list.Add(i + 2);
					return list;
				}
			}
			return list;
		}
		private List<int> GetBlock2DisplayIndices()
		{
			var list = new List<int>();
			if (ColumnDisplayOrderList == null || AllColumns == null) return list;
			for (int i = 0; i <= ColumnDisplayOrderList.Count - 2; i++)
			{
				if (GetColumnNameByDisplayIndex(i) == "From Funded" && GetColumnNameByDisplayIndex(i + 1) == "Auto Close")
				{
					list.Add(i); list.Add(i + 1);
					return list;
				}
			}
			return list;
		}
		private bool IsDisplayIndexInBlock1(int displayIdx) { var b = GetBlock1DisplayIndices(); return b.Contains(displayIdx); }
		private bool IsDisplayIndexInBlock2(int displayIdx) { var b = GetBlock2DisplayIndices(); return b.Contains(displayIdx); }
		private bool IsDisplayIndexFree(int displayIdx) { return !IsDisplayIndexInBlock1(displayIdx) && !IsDisplayIndexInBlock2(displayIdx); }
		private bool IsColumnLockedNoScroll(string colName) { return colName == "–" || colName == "Connected Status" || colName == "Auto Exit" || colName == "Auto Close"; }
		private bool IsLeftmostOfBlock1(int displayIdx) { var b = GetBlock1DisplayIndices(); return b.Count == 3 && b[0] == displayIdx; }
		private bool IsRightmostOfBlock1(int displayIdx) { var b = GetBlock1DisplayIndices(); return b.Count == 3 && b[2] == displayIdx; }
		private bool IsLeftmostOfBlock2(int displayIdx) { var b = GetBlock2DisplayIndices(); return b.Count == 2 && b[0] == displayIdx; }
		private bool IsRightmostOfBlock2(int displayIdx) { var b = GetBlock2DisplayIndices(); return b.Count == 2 && b[1] == displayIdx; }

		private DateTime _lastWheelScrollTime = DateTime.MinValue;
		private void ChartControl_PreviewMouseWheel(object sender, MouseWheelEventArgs e)
		{
			int directionmove = e.Delta;

			// NOTE: scroll throttle moved into DoWheel's table-scroll path so
			// cell-value adjustments (multiplier, daily goal, etc.) are NOT
			// throttled — they need to respond to every wheel tick.

			// Cheat sheet overlay scroll — consumes wheel events when open so the
			// main table doesn't scroll underneath.
			if (_cheatSheetOpen && _csBgRect.Width > 0 && _csBgRect.Height > 0)
			{
				int _csDelta = directionmove > 0 ? -3 : 3;
				_csScrollOffset = Math.Max(0, _csScrollOffset + _csDelta);
				InvalidateVis(123);
				e.Handled = true;
				return;
			}

			// IgnoreNextTime blocks cell-value scrolling (multiplier, ATM mode, daily goal/loss)
			// but should NOT block table row scrolling or column reordering
			bool ignoreActive = IgnoreNextTime.Ticks > DateTime.Now.Ticks;

			// Ctrl+wheel changes row density (adds/removes vertical cell padding).
			// Clamped to a sane range so the user can't accidentally zero out the rows.
			if ((Keyboard.Modifiers & ModifierKeys.Control) == ModifierKeys.Control)
			{
				int _delta = directionmove > 0 ? 1 : -1;
				int _newBoost = Math.Max(-3, Math.Min(10, _rowDensityBoost + _delta));
				if (_newBoost != _rowDensityBoost)
				{
					_rowDensityBoost = _newBoost;
					InvalidateVis(117);
				}
				e.Handled = true;
				return;
			}

			// Note: scroll-wheel column reordering is intentionally disabled —
			// replaced by click-and-drag in OnMouseMove. Actual row scrolling is
			// handled by DoWheel below.
			bool handled = DoWheel(directionmove, true, ignoreActive);

			// ALWAYS consume the wheel event on the dashboard chart. Without
			// this, the event bubbles to the chart's own handler, which scrolls
			// the (transparent) bars horizontally — moving the bottom scrollbar
			// and triggering chart redraws that replay stale AllDrawings frames
			// before our InvalidateVis rebuild lands. That's what was making
			// Size/Mode cell values appear to lag on scroll.
			e.Handled = true;
		}

		
		
		
		
		
