		protected override void OnRender(ChartControl chartControl, ChartScale chartScale)
		{
			//Print("OnRender " + AllowRedraw);

			// Fail-fast null guards BEFORE the outer try so the happy-path null
			// case (still loading) doesn't pay any try-frame cost. Only the
			// deeper body is wrapped.
		    if (chartControl == null || chartScale == null || RenderTarget == null)
		        return;

		    if (ChartPanel == null || !IsVisible)
		        return;

		    // Your existing IsInHitTest check
		    if (IsInHitTest)
		        return;

			// Outer try/catch guards against NREs during chart reload / data-feed
			// reconnect when brushes, TextFormats, or cached state may be half-
			// initialized. Swallowing is correct here: the next frame will retry
			// once initialization completes. Without this, NT logs a banner error
			// ("Error on calling OnRender method on bar N") that freezes the
			// chart for several seconds. Zero happy-path cost — .NET JIT does not
			// penalize non-throwing try frames.
			try
			{

			// Cell tooltip stickiness: dismiss only when the mouse has drifted
			// further than _cellTipStickyRadius pixels from the anchor position
			// (captured while the mouse was in a tooltip-enabled cell). Prevents
			// per-frame flicker from data updates that shift cell rects by a
			// pixel and gives the user time to read.
			if (_cellTipText != null && _cellTipAnchorX >= 0 && _cellTipAnchorY >= 0)
			{
				double _dx = FinalXPixel - _cellTipAnchorX;
				double _dy = FinalYPixel - _cellTipAnchorY;
				if (_dx * _dx + _dy * _dy > _cellTipStickyRadius * _cellTipStickyRadius)
				{
					_cellTipText = null;
					_cellTipAnchorX = -1;
					_cellTipAnchorY = -1;
				}
			}

			// Expire click-suppression once the mouse has left the clicked
			// cell rect, OR after a hard timeout (1.5s). The timeout covers
			// the case where resize / rerender shifts the cell such that the
			// mouse never appears to cross the old rect boundary and would
			// otherwise suppress tooltips forever.
			if (_cellTipSuppressRect.Width > 0)
			{
				bool _expireByMove = FinalXPixel < _cellTipSuppressRect.X || FinalXPixel > _cellTipSuppressRect.Right
					|| FinalYPixel < _cellTipSuppressRect.Y || FinalYPixel > _cellTipSuppressRect.Bottom;
				bool _expireByTime = _cellTipSuppressExpiry != DateTime.MinValue && DateTime.Now > _cellTipSuppressExpiry;
