						// Compute progress-bar fractions for Daily Goal / Daily Loss cells.
						// Goal: PNLTotal / DailyGoal, clamped to [0,1]. No bar if goal is 0.
						// Loss: |min(PNLTotal,0)| / |DailyLoss|, clamped. No bar if loss is 0
						// or if total is positive (nothing to lose toward).
						if (!string.IsNullOrEmpty(thisrowacct))
						{
							float _gp = 0f;
							if (CurrentDailyGoal > 0.0001 && thisdata.PNLTotal > 0)
								_gp = (float)Math.Max(0.0, Math.Min(1.0, thisdata.PNLTotal / CurrentDailyGoal));
							_goalProgress[thisrowacct] = _gp;

							float _lp = 0f;
							double _lossMag = Math.Abs(CurrentDailyLoss);
							if (_lossMag > 0.0001 && thisdata.PNLTotal < 0)
								_lp = (float)Math.Max(0.0, Math.Min(1.0, Math.Abs(thisdata.PNLTotal) / _lossMag));
							_lossProgress[thisrowacct] = _lp;

							// Sparkline ring buffer — sample PNLTotal at most once per
