									// MaxWidth is set to a large value (10000) to prevent DirectWrite from
									// wrapping/clipping the layout — we want the natural text width.
									// Adds CellPaddingX + 2 to match the TextRect inset used during rendering.
									int _measuredWidth;
									if (!_columnWidthMeasureCache.TryGetValue(text, out _measuredWidth))
									{
										if (textLayout2 != null) textLayout2.Dispose();
										textLayout2 = new SharpDX.DirectWrite.TextLayout(NinjaTrader.Core.Globals.DirectWriteFactory, text, textFormat2, 10000, textFormat2.FontSize);
										// Use Math.Ceiling so we never round down and clip text by a partial pixel
										_measuredWidth = (int)Math.Ceiling(textLayout2.Metrics.Width) + CellPaddingX + 2;
										_columnWidthMeasureCache[text] = _measuredWidth;
