										int sretcg = 3; // size (px) of top and bottom horizontal scroll indicator bars — reduced from 6 to make them 2px shorter
										
										sretcg = (int) Math.Round(sretcg*dpiScaleY, 0);
										
										int asadfgh = 3 + AdjustmentRows;
