//										}
										
										
												
																			
										// highlight for master and follower accounts
										
										//if (i != 1)
										
										
										int l1 = 1;
										int b1 = 0;
										
										
										if (TableFinalBackgroundBrushDX != TableBackgroundBrushDX)
										{
											//FillRectBoth(chartControl, chartScale, ExpandRect(rect2,0,-1,0,-1), ChartBackgroundBrushDX);
											//FillRectBoth(chartControl, chartScale, ExpandRect(rect2,0,-1,0,-1), TableFinalBackgroundBrushDX);

											FillRectBoth(chartControl, chartScale, ExpandRect(rect2,0,0,0,0), ChartBackgroundBrushDX); // makes grid lines less bright
											FillRectBoth(chartControl, chartScale, ExpandRect(rect2,l1,1,1,b1), TableFinalBackgroundBrushDX);


										}
										else
										{

											FillRectBoth(chartControl, chartScale, ExpandRect(rect2,0,0,0,0), ChartBackgroundBrushDX);
											FillRectBoth(chartControl, chartScale, ExpandRect(rect2,l1,1,1,b1), TableBackgroundBrushDX);
										}

										// Alternating row overlay — applies to all account rows AND total rows
										// so the alt-row contrast carries through the totals section.
										// Skipped when pAltRowPct == 0 (user disabled the effect).
										if (isAltRow && (IsAnyAccountRow || IsTotalRow) && TableBackgroundAltBrushDX != null && pAltRowPct > 0)
										{
											FillRectBoth(chartControl, chartScale, ExpandRect(rect2,l1,1,1,b1), TableBackgroundAltBrushDX);
										}

										// (Ghost-row whole-cell tint removed — user wants only the count
										// column and the Account label dimmed, not the entire row.)

										// Copy-to-clipboard row flash — brief whole-row highlight after
										// Ctrl+C so the user sees what was captured. Uses DragTintBrushDX
										// (neutral) so it layers cleanly on any row background.
										if (_copyFlashRowI > 0 && i == _copyFlashRowI && DragTintBrushDX != null
											&& _renderNow < _copyFlashEnd)
										{
											FillRectBoth(chartControl, chartScale, ExpandRect(rect2, l1, 1, 1, b1), DragTintBrushDX);
										}

										// Daily Goal / Daily Loss inline progress bar — 4 px bevel at the
										// bottom of the cell with an outer 1-px halo (low alpha) giving
										// the bar a soft modern "glow" instead of a flat rectangle.
										// Fill layers, bottom to top:
										//   - Halo     : 6 px tall rect at 33% stepped brush for soft glow
										//   - Shadow   : 1 px row below main fill at 33% brush (dark edge)
										//   - Main fill: 3 px rows at 100% + 66% + 33% stepped brushes,
										//                top → bottom (bright top edge, fading body)
										//   - Highlight: 1 px top-most row at 66% brush (lit edge gloss)
										// All four stepped brushes (CellFlashUpBrushDX / UpBrushDX66 /
										// UpBrushDX33 and the Down variants) already exist — no new
										// allocations. Gated by pShowProgressBarTicks for the ticks.
										if (IsAnyAccountRow && !IsTotalRow && i != 1
											&& !string.IsNullOrEmpty(ThisRowAccount) && !string.IsNullOrEmpty(ColumnTitle)
											&& (ColumnTitle == "Daily Goal" || ColumnTitle == "Daily Loss"))
										{
											Dictionary<string, float> _progDict = ColumnTitle == "Daily Goal" ? _goalProgress : _lossProgress;
											SharpDX.Direct2D1.Brush _progBrush    = ColumnTitle == "Daily Goal" ? CellFlashUpBrushDX    : CellFlashDownBrushDX;
											SharpDX.Direct2D1.Brush _progBrush66  = ColumnTitle == "Daily Goal" ? CellFlashUpBrushDX66  : CellFlashDownBrushDX66;
											SharpDX.Direct2D1.Brush _progBrush33  = ColumnTitle == "Daily Goal" ? CellFlashUpBrushDX33  : CellFlashDownBrushDX33;
											float _progFrac;
											if (_progBrush != null && _progDict.TryGetValue(ThisRowAccount, out _progFrac))
											{
												float _barH = (float)Math.Max(2.0, Math.Round(2.0 * dpiScaleY, 0));
												float _barFull = rect2.Width - 2f;
												float _barBaseY = rect2.Bottom - _barH - 1;
												// Reference tick marks at 25/50/75/100% (drawn first so the
												// progress fill paints over them on the "filled" side).
												// Kept faint (20% text brush) so they're a subtle ruler
												// rather than a competing foreground element.
												// Tick height is the same as the bar so they read clearly.
												// Hidden when the account has no Daily Goal / Daily Loss
												// threshold configured — without a rule there's nothing to
												// be a ruler for, and the empty ticks were misleading.
												// Gated by pShowProgressBarTicks.
												bool _hasThreshold = false;
												if (ThisBOTChart != null && ThisBOTChart.Acct != null)
												{
													double _thrCheck = (ColumnTitle == "Daily Goal")
														? GetAccountSavedData(ThisBOTChart.Acct.Name, pAllAccountDailyGoal)
														: GetAccountSavedData(ThisBOTChart.Acct.Name, pAllAccountDailyLoss);
													_hasThreshold = (_thrCheck != DefaultForZero) && (Math.Abs(_thrCheck) > 0.0001);
												}
												if (pShowProgressBarTicks && _hasThreshold && ChartTextBrushDX20 != null && _barFull >= 8f)
												{
													float _tickH = _barH;
													// Only interior ticks — 0% (left edge) and 100% (right
													// edge) were visually redundant with the bar endpoints.
													for (int _tk = 0; _tk < _progressBarTicks.Length; _tk++)
													{
														float _tickX = rect2.X + 1 + _barFull * _progressBarTicks[_tk] - 1f;
														SharpDX.RectangleF _tickRect = new SharpDX.RectangleF(
															_tickX, _barBaseY, 1f, _tickH);
														FillRectBoth(chartControl, chartScale, _tickRect, ChartTextBrushDX20);
													}
												}
												if (_progFrac > 0f && _progBrush66 != null && _progBrush33 != null)
												{
													float _barW = _barFull * _progFrac;
													float _barX = rect2.X + 1;
													// Outer soft halo: 1 px above / 2 px below the main bar
													// using the 25% stepped brush. Extends slightly past the
													// bar's filled width for a trailing-edge glow. Top was
													// trimmed from 2 px to 1 px so the bright highlight row
													// reads more clearly as the top of the bar.
													SharpDX.RectangleF _haloRect = new SharpDX.RectangleF(
														_barX - 1, _barBaseY - 1, _barW + 2, _barH + 3);
													FillRectBoth(chartControl, chartScale, _haloRect, _progBrush33);
													// Bevel fill — 2 stacked 1-px rows at a 2 px bar height:
													//   row 0 (top)    = highlight at 66% — lit gloss edge
													//   row 1 (bottom) = shadow at 33%    — dark base
													// The bright 75% core was dropped when bar height fell
													// from 3 px to 2 px — there's no room for a middle row
													// that renders as a crisp integer-pixel slice.
													float _rowH = _barH / 2f;
													SharpDX.RectangleF _rowTop = new SharpDX.RectangleF(_barX, _barBaseY,         _barW, _rowH);
													SharpDX.RectangleF _rowBot = new SharpDX.RectangleF(_barX, _barBaseY + _rowH, _barW, _rowH);
													FillRectBoth(chartControl, chartScale, _rowTop, _progBrush66);
													FillRectBoth(chartControl, chartScale, _rowBot, _progBrush33);
												}
												// Sparkline of the recent PNLTotal samples — drawn ABOVE the
												// progress bar in the upper portion of the cell.
												// Rendered as a 2px-thick connected polyline approximated
												// by 1x2 fill rects stepped along each segment.
												// HIDDEN when:
												//   - pShowPnlSparkline is false (user toggle)
												//   - account has no open position (not "in a trade")
												//   - there are fewer than 2 samples yet
												//   - a Daily Goal / Daily Loss threshold is configured —
												//     the progress bar already visualizes distance to
												//     target and the sparkline on top reads as clutter.
												bool _inTrade = ThisBOTChart != null
													&& (ThisBOTChart.PositionLong != 0 || ThisBOTChart.PositionShort != 0);
												SparklineRing _spSamples;
												if (pShowPnlSparkline && _inTrade && !_hasThreshold
													&& ChartTextBrushDX40 != null && _barFull >= 16f
													&& _pnlSparkline.TryGetValue(ThisRowAccount, out _spSamples)
													&& _spSamples.Count >= 2)
												{
													float _sparkH = (float)Math.Max(4.0, Math.Round(7.0 * dpiScaleY, 0));
													float _sparkY = rect2.Top + 1;
													float _sparkLeft = rect2.X + 1;
													float _sparkW = _barFull;
													double _smin = _spSamples.Get(0), _smax = _spSamples.Get(0);
													for (int _si = 1; _si < _spSamples.Count; _si++)
													{
														if (_spSamples.Get(_si) < _smin) _smin = _spSamples.Get(_si);
														if (_spSamples.Get(_si) > _smax) _smax = _spSamples.Get(_si);
													}
													double _srange = _smax - _smin;
													if (_srange < 0.0001) _srange = 1; // avoid div0
													float _stepX = _sparkW / (float)(_spSamples.Count - 1);
													// Draw each segment (p_i → p_i+1) as a rasterized polyline:
													// step 1px in X, linearly interpolate Y, paint a 1×2 rect.
													for (int _si = 0; _si < _spSamples.Count - 1; _si++)
													{
														float _x1 = _sparkLeft + _si * _stepX;
														float _x2 = _sparkLeft + (_si + 1) * _stepX;
														float _n1 = (float)((_spSamples.Get(_si)     - _smin) / _srange);
														float _n2 = (float)((_spSamples.Get(_si + 1) - _smin) / _srange);
														float _y1 = _sparkY + _sparkH - 1f - (_n1 * (_sparkH - 1f));
														float _y2 = _sparkY + _sparkH - 1f - (_n2 * (_sparkH - 1f));
														int _steps = Math.Max(1, (int)Math.Ceiling(_x2 - _x1));
														for (int _s = 0; _s <= _steps; _s++)
														{
															float _t = (float)_s / (float)_steps;
															float _px = _x1 + (_x2 - _x1) * _t;
															float _py = _y1 + (_y2 - _y1) * _t;
															SharpDX.RectangleF _lineSeg = new SharpDX.RectangleF(
																_px, _py, 1f, 2f);
															FillRectBoth(chartControl, chartScale, _lineSeg, ChartTextBrushDX40);
														}
													}
												}
											}
										}

										// PnL cell flash indicator — thin 3px vertical bar on the RIGHT edge
										// of the cell when the displayed value has just changed. Row-level
										// dict lookup was done ONCE before the column loop; here we just do
										// a cheap null-test + single inner lookup per cell.
										// Fade decay is achieved by selecting one of THREE pre-created brushes
										// (75% / 50% / 25% opacity) based on time remaining — never mutating
										// brush.Opacity at draw time, to stay safe with the AllDrawings cache.
										// Gated by pShowPnlFlash — user can turn the whole effect off.
										if (pShowPnlFlash && _rowFlashEnd != null && !string.IsNullOrEmpty(ColumnTitle)
											&& CellFlashUpBrushDX != null && CellFlashDownBrushDX != null
											&& (ColumnTitle == "Unrealized" || ColumnTitle == "Realized"
												|| ColumnTitle == "Gross Realized" || ColumnTitle == "Total PNL"))
										{
											DateTime _cfEnd;
											if (_rowFlashEnd.TryGetValue(ColumnTitle, out _cfEnd))
											{
												double _msLeft = (_cfEnd - _renderNow).TotalMilliseconds;
												if (_msLeft > 0)
												{
													bool _cfUp = false;
													if (_rowFlashUp != null) _rowFlashUp.TryGetValue(ColumnTitle, out _cfUp);
													// Map ms-left to a 3-step fade: >200 full, >100 mid, else low.
													SharpDX.Direct2D1.Brush _flashB;
													if (_cfUp)
													{
														if (_msLeft > 200)       _flashB = CellFlashUpBrushDX;
														else if (_msLeft > 100)  _flashB = CellFlashUpBrushDX66;
														else                     _flashB = CellFlashUpBrushDX33;
													}
													else
													{
														if (_msLeft > 200)       _flashB = CellFlashDownBrushDX;
														else if (_msLeft > 100)  _flashB = CellFlashDownBrushDX66;
														else                     _flashB = CellFlashDownBrushDX33;
													}
													float _flashBarW = (float)Math.Max(2.0, Math.Round(3.0 * dpiScaleY, 0));
													SharpDX.RectangleF _flashBar = new SharpDX.RectangleF(
														rect2.Right - _flashBarW - 1,
														rect2.Top + 1,
														_flashBarW,
														rect2.Height - 1);
													FillRectBoth(chartControl, chartScale, _flashBar, _flashB);
												}
											}
										}
										
										
										
										
										
										if (HoveredRow != 2)
										if (!TopAccountIsVisible && i == 2)
										{
											FillRectBoth(chartControl, chartScale, ExpandRect(rect2,1,1,sretcg-rect2.Height+2,0), TableFinalBackgroundBrushDX);
								
											
										}
										
										//Print("TotalAccounts " + TotalAccounts);
										
										if (!BottomAccountIsVisible && i == 3 + TotalAccounts + add)
										{
											FillRectBoth(chartControl, chartScale, ExpandRect(rect2,1,1,1,sretcg-rect2.Height+1), TableFinalBackgroundBrushDX);
											
										}
											
										if ((pSelectedColumn == ColumnTitle || (scrollingneed && j == 1) || (pForceAllSelectedAccountsToTop && j == 1)))
										{

											// Suppress the accent strip while the cursor is in row 2
											// (the reset/select-all reveal row). The row-2 hover ring
											// draws across this same cell and the accent underneath
											// was reading as a stray clipped line.
											if (i == 2 && HoveredRow != 2)
											{
