					// Latency column: adaptive coloring. Each follower cell is judged
					// against that follower own rolling baseline (LatencyBaseline) -- amber
					// at LatencyAmberRatio of baseline, red at LatencyRedRatio; always green
					// below LatencyAbsFloorMs; the fixed Slow Threshold is the fallback
					// before a baseline exists. A stale sample shows its last value dimmed.
										if (ColumnTitle == "Latency" && _rowHasLatency && !IsTotalRow)
										{
											if ((_renderNow - _rowLatencyStamp).TotalSeconds >= CopierLatencyStaleAfterSec)
											{
												if (ChartTextBrushDX40 != null) textBrushDx = ChartTextBrushDX40;
											}
											else if (_rowLatencyMs <= LatencyAbsFloorMs)
											{
												if (CellFlashUpBrushDX != null) textBrushDx = CellFlashUpBrushDX;
											}
											else if (_rowLatencyBaseline > 0)
											{
												// Adaptive: judge against this follower own rolling average.
												double _ratio = _rowLatencyMs / _rowLatencyBaseline;
												if (_ratio >= LatencyRedRatio) { if (CellFlashDownBrushDX != null) textBrushDx = CellFlashDownBrushDX; }
												else if (_ratio >= LatencyAmberRatio) { if (LatencyWarnBrushDX != null) textBrushDx = LatencyWarnBrushDX; }
												else { if (CellFlashUpBrushDX != null) textBrushDx = CellFlashUpBrushDX; }
											}
											else
											{
												// No baseline yet -- fall back to the fixed Slow Threshold.
												if (_rowLatencyMs >= pLatencySlowThresholdMs) { if (CellFlashDownBrushDX != null) textBrushDx = CellFlashDownBrushDX; }
												else if (_rowLatencyMs >= pLatencySlowThresholdMs * 0.5) { if (LatencyWarnBrushDX != null) textBrushDx = LatencyWarnBrushDX; }
												else { if (CellFlashUpBrushDX != null) textBrushDx = CellFlashUpBrushDX; }
