											{
												SharpDX.Direct2D1.Ellipse _r4 = new SharpDX.Direct2D1.Ellipse(
													new SharpDX.Vector2(_cx, _cy), _rMax * 1.00f, _rMax * 1.00f);
												FillEllipseBoth(chartControl, chartScale, _r4, CheckGlowBrushDX);
												SharpDX.Direct2D1.Ellipse _r3 = new SharpDX.Direct2D1.Ellipse(
													new SharpDX.Vector2(_cx, _cy), _rMax * 0.82f, _rMax * 0.82f);
												FillEllipseBoth(chartControl, chartScale, _r3, CheckGlowBrushDX);
											}
											if (CheckGlowBrushDX2 != null)
											{
												SharpDX.Direct2D1.Ellipse _r2 = new SharpDX.Direct2D1.Ellipse(
													new SharpDX.Vector2(_cx, _cy), _rMax * 0.65f, _rMax * 0.65f);
												FillEllipseBoth(chartControl, chartScale, _r2, CheckGlowBrushDX2);
												SharpDX.Direct2D1.Ellipse _r1 = new SharpDX.Direct2D1.Ellipse(
													new SharpDX.Vector2(_cx, _cy), _rMax * 0.48f, _rMax * 0.48f);
												FillEllipseBoth(chartControl, chartScale, _r1, CheckGlowBrushDX2);
