							// Capture the top Y of each total row (we're past the column loop so
							// this runs once per row) for the post-render accent overlay.
							if (IsTotalRow && _totalRowTops != null && _totalRowTops.Count < 8)
								_totalRowTops.Add(RectY);

							// Explicit first-SUB-total tracker for the "+ N hidden" pill.
							// Skips the grand total (TotalRow4) so the pill never lands on it
							// when all sub-totals are hidden. Set once per frame.
							if (IsTotalRow && ThisTotalRow != "TotalRow4" && _firstSubTotalRowY < 0)
							{
								_firstSubTotalRowY = RectY;
								_firstSubTotalRowHeight = RectHeight;
							}

							// Capture the Grand Total row bottom so the post-render overlay
							// can stroke a matching accent beneath it.
							if (IsTotalRow && ThisTotalRow == "TotalRow4")
								_grandTotalBottomY = RectY + RectHeight;

							RectY = RectY + RectHeight;

						}
						// Commit filter visibility counters for the overlay label.
						_lastFilterTotalCount   = _filterTotalThisFrame;
						_lastFilterVisibleCount = _filterVisibleThisFrame;
						
						
						
//						Print("MaximumAccountRows   " + MaximumAccountRows);
//						Print("MaximumRows   " + MaximumRows);
//						Print("NotAccountRows   " + NotAccountRows);
//						Print("TotalAccounts   " + TotalAccounts);
						
					
						
					}
						
					
					TableFinalBackgroundBrushDX = TableBackgroundBrushDX;
						rect2			= new SharpDX.RectangleF(MinX, MinY, MaxX - MinX+1, MaxY - MinY+1);
						// Capture for the cell tooltip block, which sits outside this scope.
						_tableMaxX = MaxX;
						_tableMinX = MinX;
						DrawRectBoth(chartControl, chartScale, rect2, TableFinalBackgroundBrushDX, 1);

						// Draw header accent line (thin bright underline below header row)
						if (headerBottomY > 0 && TableHeaderBorderBrushDX != null)
						{
							SharpDX.RectangleF headerAccent = new SharpDX.RectangleF(headerLeftX, headerBottomY - 1, headerRightX - headerLeftX + 1, 1);
							FillRectBoth(chartControl, chartScale, headerAccent, TableHeaderBorderBrushDX);
						}

						// Bottom + right edges: 1px accents to close the table border. The
						// outer DrawRectangle stroke gets painted over by the final row's
						// cell fills and the right-most column's right-gridline, so re-
						// stroke just those two edges at the same weight (1px). Bottom
						// uses ChartTextBrushDX10 (10 % muted) so it reads as a quiet
						// terminator; the right edge already has the outer DrawRect stroke
						// under it, so an even fainter brush (OverlayGlowBrushDX5 at ~8 %)
						// brings the right edge up to visual parity with the bottom
						// without making it appear doubled/brighter.
						if (MaxY > MinY)
						{
							SharpDX.Direct2D1.Brush _bottomEdgeBrush = ChartTextBrushDX10 ?? ChartTextBrushDX20;
							if (_bottomEdgeBrush != null)
							{
								SharpDX.RectangleF bottomEdge = new SharpDX.RectangleF(MinX, MaxY, MaxX - MinX + 1, 1);
								FillRectBoth(chartControl, chartScale, bottomEdge, _bottomEdgeBrush);
							}
							SharpDX.Direct2D1.Brush _rightEdgeBrush = OverlayGlowBrushDX5 ?? ChartTextBrushDX10 ?? ChartTextBrushDX20;
							if (_rightEdgeBrush != null)
							{
								SharpDX.RectangleF rightEdge = new SharpDX.RectangleF(MaxX, MinY, 1, MaxY - MinY + 1);
								FillRectBoth(chartControl, chartScale, rightEdge, _rightEdgeBrush);
							}
						}

						// Right-edge cutoff fade — runs whenever the table extends past
						// the chart panel's right edge, regardless of whether the
						// scrollbar is shown. Draws multi-layer fade flush to the panel
						// right so cutoff cell content isn't visually tangent with the
						// bezel / scrollbar track. Scrollbar (if drawn) paints on top
						// of this so the fade sits behind it. See full commentary on
						// layer ordering at the old draw site inside the scrollbar block.
						if (MaxX > (ChartPanel.X + ChartPanel.W - 1f)
							&& ChartBackgroundBrushDX != null && QrgFadeBrush1 != null
							&& QrgFadeBrush2 != null && QrgFadeBrush3 != null
							&& ChartBackgroundFadeBrushDX != null && MinY > 0 && MaxY > MinY)
						{
							float _fadeRight = ChartPanel.X + ChartPanel.W + 1f;
							float _fadeTop = MinY - 1f;
							float _fadeBottom = MaxY + 1f;
							_scrollFadeBrushes[0] = ChartBackgroundFadeBrushDX;
							_scrollFadeBrushes[1] = QrgFadeBrush3;
							_scrollFadeBrushes[2] = QrgFadeBrush3;
							_scrollFadeBrushes[3] = QrgFadeBrush2;
							_scrollFadeBrushes[4] = QrgFadeBrush2;
							_scrollFadeBrushes[5] = QrgFadeBrush1;
							_scrollFadeBrushes[6] = QrgFadeBrush1;
							_scrollFadeBrushes[7] = ChartBackgroundBrushDX;
							for (int _fI = 0; _fI < _scrollFadeWidths.Length; _fI++)
							{
								float _fW = _scrollFadeWidths[_fI];
								SharpDX.RectangleF _fRect = new SharpDX.RectangleF(
									_fadeRight - _fW, _fadeTop, _fW, _fadeBottom - _fadeTop);
								FillRectBoth(chartControl, chartScale, _fRect, _scrollFadeBrushes[_fI]);
							}
						}

						// Total-row drag-reorder visual: mirrors the column-header drag.
						// Source row gets tinted full-width; a 2px white bar marks the
						// insertion target wherever the cursor currently hovers.
						if (_draggingTotalRowPrefix != null && _totalRowDragActivated
							&& ChartTextBrushDX20 != null && ChartTextBrushDX != null
							&& _totalRowDragRects.Count > 0)
						{
							// Find source rect (the row being dragged).
							int _srcK = -1;
							for (int _dk = 0; _dk < _totalRowDragPrefixes.Count; _dk++)
							{
								if (_totalRowDragPrefixes[_dk] == _draggingTotalRowPrefix)
								{
									_srcK = _dk;
									break;
								}
							}
							if (_srcK >= 0 && _srcK < _totalRowDragRects.Count)
							{
								SharpDX.RectangleF _srcRect = _totalRowDragRects[_srcK];
								SharpDX.RectangleF _srcTint = new SharpDX.RectangleF(
									MinX, _srcRect.Y, MaxX - MinX, _srcRect.Height);
								// Brighter than the column drag — total-row cells sit on a
								// brighter table background so a stronger white (~20%) is
								// needed to match the perceived contrast of the column tint.
								FillRectBoth(chartControl, chartScale, _srcTint, ChartTextBrushDX20);
							}

							// Insertion marker — horizontal 2px bar on the top edge of
							// the target row (or bottom edge if dragging past the last).
							int _tgtK = -1;
							for (int _dk = 0; _dk < _totalRowDragRects.Count; _dk++)
							{
								if (MouseIn(_totalRowDragRects[_dk], 0, 0))
								{
									_tgtK = _dk;
									break;
								}
							}
							if (_tgtK >= 0 && _tgtK != _srcK && _tgtK < _totalRowDragRects.Count)
							{
								SharpDX.RectangleF _tgtRect = _totalRowDragRects[_tgtK];
								// Marker above target if dragging upward, below if downward.
								float _markerY = (_tgtK < _srcK)
									? _tgtRect.Y
									: _tgtRect.Y + _tgtRect.Height - 2f;
								SharpDX.RectangleF _marker = new SharpDX.RectangleF(
									MinX, _markerY, MaxX - MinX, 2f);
								FillRectBoth(chartControl, chartScale, _marker, ChartTextBrushDX);
							}
						}

						// Hidden-groups pill: small badge on the left edge of the gap between
						// the account rows and the totals. Shows "+ N hidden" or, when
						// expanded, "− N hidden". Click toggles inline restore mode. Only
						// shown when auto-grouping is on and at least one group is hidden.
						// Auto-collapse check: if the restore drawer was expanded and its
						// idle deadline has passed, collapse it before rendering so this
						// frame already shows the collapsed "+" state.
						if (_hiddenRowsExpanded && _hiddenRowsExpireAt != DateTime.MaxValue
							&& DateTime.Now > _hiddenRowsExpireAt)
						{
							_hiddenRowsExpanded = false;
							_hiddenRowsExpireAt = DateTime.MaxValue;
							try { GetAllPerformanceStats(); } catch { }
							IsSorted = false;
							ForceRefresh();
							InvalidateVis(208);
						}
						_hiddenGroupsPillRect = new SharpDX.RectangleF();
						// Hide the pill when the copier is ON — ghost/total rows aren't visible in
						// that state, so there's nothing for +/- to expand to.
						if (pAutoGroupAccounts && hiddenAutoGroups.Count > 0
							&& !pCopierIsEnabled
							&& _firstSubTotalRowY > 0
							&& ChartTextBrushDX40 != null && TableHeaderBorderBrushDX != null)
						{
							// Compact pill: just "+" or "−". Width matches the connected-status
							// ("–") column so the badge aligns neatly under that column.
							string _hgTxt = _hiddenRowsExpanded ? "\u2212" : "+";
							float _hgH = (float)Math.Round(14 * dpiScaleY, 0);
							// Look up the "–" column width for this frame. Fall back to a
							// reasonable default if the column isn't known yet.
							float _hgW = 22f * (float)dpiScaleY;
							if (ColumnNumberToName != null && ColumnNumberToWidth != null)
							{
								foreach (var _kv in ColumnNumberToName)
								{
									if (_kv.Value == "\u2013")
									{
										int _dashW;
										if (ColumnNumberToWidth.TryGetValue(_kv.Key, out _dashW) && _dashW > 0)
											_hgW = _dashW;
										break;
									}
								}
							}
							// Position: pill sits in the separator row ABOVE the first sub-total
							// row — bottom flush with the top of the first sub-total cell.
							float _hgY = _firstSubTotalRowY - _hgH;
							if (_hgY < MinY + 1) _hgY = MinY + 1;
							// X: aligned with the main table's left edge (no inset).
							float _hgX = MinX;
							SharpDX.RectangleF _hgR = new SharpDX.RectangleF(_hgX, _hgY, _hgW, _hgH);
							_hiddenGroupsPillRect = _hgR;

							bool _hgHov = MouseIn(_hgR, 0, 0);
							// Idle = lighter background; Hover = slightly darker. Border stays
							// constant so only the fill / text changes on hover.
							SharpDX.Direct2D1.Brush _hgBgBrush = _hgHov
								? (TableHeaderBackgroundBrushDX ?? TableHighlight15BrushDX)
								: (TableHighlight15BrushDX ?? TableHeaderBackgroundBrushDX);
							if (_hgBgBrush != null)
								FillRectBoth(chartControl, chartScale, _hgR, _hgBgBrush);
							DrawRectBoth(chartControl, chartScale, _hgR, TableHeaderBorderBrushDX, 1);

							SharpDX.Direct2D1.Brush _hgTxtBrush = _hgHov ? ChartTextBrushDX : ChartTextBrushDX40;
							if (_hgTxtBrush == null) _hgTxtBrush = ChartTextBrushDX20;
							DrawTextBoth(chartControl, chartScale, _hgTxt,
								MainTextCenter ?? CellFormat, _hgR, _hgTxtBrush);

							// Hover tooltip surfaces the count that's no longer shown inline.
							if (_hgHov)
							{
								string _n = hiddenAutoGroups.Count == 1 ? "1 total row is" : hiddenAutoGroups.Count + " total rows are";
								_cellTipText = _hiddenRowsExpanded
									? (_n + " hidden — click to collapse the restore view.")
									: (_n + " hidden — click to expand and restore.");
								_cellTipRect = _hgR;
								_cellTipAnchorX = FinalXPixel;
								_cellTipAnchorY = FinalYPixel;
							}
						}

						// Sort-column indicator: small anti-aliased triangle primitive in the
						// top-right corner of the currently-sorted header cell. Built from
						// many thin horizontal bars at sub-pixel precision (no integer rounding
						// on internal steps), wrapped in a temporary PerPrimitive AA block so
						// the tapered edges blend smoothly. Rendered at 40% opacity.
						// Ascending = wide top / narrow bottom; descending = narrow top / wide bottom.
						// Uses HeaderColumnLogicalIds (parallel list) to resolve column name
						// per rect — HeaderColumnRects is compacted to visible columns only,
						// so index-based lookups via ColumnDisplayOrderList are out of sync
						// whenever a column has been hidden.
						if (!string.IsNullOrEmpty(pSelectedColumn) && HeaderColumnRects != null
							&& HeaderColumnLogicalIds != null && ColumnNumberToName != null
							&& ChartTextBrushDX40 != null)
						{
							int _sortCount = Math.Min(HeaderColumnRects.Count, HeaderColumnLogicalIds.Count);
							for (int _si = 0; _si < _sortCount; _si++)
							{
								string _sortColName;
								if (!ColumnNumberToName.TryGetValue(HeaderColumnLogicalIds[_si], out _sortColName)) continue;
								if (_sortColName != pSelectedColumn) continue;
								SharpDX.RectangleF _sortHdr = HeaderColumnRects[_si];
								// Triangle metrics — 7px wide × 5px tall. Padding kept at 3px so
								// it sits comfortably in the corner.
								float _triW = (float)(7.0 * dpiScaleY);
								float _triH = (float)(5.0 * dpiScaleY);
								float _triPad = (float)(3.0 * dpiScaleY);
								float _triX = _sortHdr.Right - _triW - _triPad;
								float _triY = _sortHdr.Top + _triPad;
								// 12 sub-pixel slices — D2D's PerPrimitive AA blends the tapered edges.
								int _slices = 12;
								float _sliceH = _triH / (float)_slices;
								AntialiasMode(chartControl, chartScale, "PerPrimitive");
								for (int _r = 0; _r < _slices; _r++)
								{
									// Fraction along the triangle (0 at top, 1 at bottom).
									float _frac = (_r + 0.5f) / (float)_slices;
									// Convention: ascending = ▲ (narrow top, wide bottom);
									// descending = ▼ (wide top, narrow bottom).
									float _widthFrac = pSelectedAscending ? _frac : (1f - _frac);
									float _barW = _triW * _widthFrac;
									if (_barW < 0.5f) continue; // skip degenerate slices
									float _barX = _triX + (_triW - _barW) * 0.5f;
									float _barY = _triY + _r * _sliceH;
									SharpDX.RectangleF _barRect = new SharpDX.RectangleF(_barX, _barY, _barW, _sliceH + 0.5f);
									FillRectBoth(chartControl, chartScale, _barRect, ChartTextBrushDX40);
								}
								AntialiasMode(chartControl, chartScale, "Aliased");
								break;
							}
						}

						// Locked-column pin marker: a small 4x4 dot in the top-right corner of
						// each non-draggable header cell. Uses HeaderColumnLogicalIds for
						// rect→name lookup (see sort triangle comment above for why).
						if (HeaderColumnRects != null && HeaderColumnRects.Count > 0
							&& HeaderColumnLogicalIds != null && ColumnNumberToName != null
							&& headerBottomY > 0 && ChartTextBrushDX40 != null)
						{
							float pinSz = (float)Math.Round(4f * dpiScaleY, 0);
							float pinPad = (float)Math.Round(3f * dpiScaleY, 0);
							int _lockCount = Math.Min(HeaderColumnRects.Count, HeaderColumnLogicalIds.Count);
							for (int _lockIdx = 0; _lockIdx < _lockCount; _lockIdx++)
							{
								string _lockColName;
								if (!ColumnNumberToName.TryGetValue(HeaderColumnLogicalIds[_lockIdx], out _lockColName)) continue;
								if (string.IsNullOrEmpty(_lockColName) || !IsColumnLockedNoScroll(_lockColName))
									continue;
								// Skip pin marker on narrow lock columns — the 4x4 dot is
								// disproportionately large and reads as a "mini square" in
								// the tight header cells for X / Auto Exit / Auto Close.
								if (_lockColName == "Auto Exit" || _lockColName == "Auto Close" || _lockColName == "–" || _lockColName == "Connected Status")
									continue;
								SharpDX.RectangleF _lockHdr = HeaderColumnRects[_lockIdx];
								SharpDX.RectangleF _pinRect = new SharpDX.RectangleF(
									_lockHdr.Right - pinSz - pinPad,
									_lockHdr.Top + pinPad,
									pinSz, pinSz);
								FillRectBoth(chartControl, chartScale, _pinRect, ChartTextBrushDX40);
							}
						}

						// Draw column resize divider highlight when hovered or actively resizing.
						// 2px wide vertical bar at the column's right edge spanning the full table height.
						int _highlightLogical = (_resizingColumnLogical >= 0) ? _resizingColumnLogical : _hoveredResizeColumnLogical;
						if (_highlightLogical >= 0 && HeaderColumnBorderRects != null && HeaderColumnBorderRects.Count > 0 && ChartTextBrushDX != null)
						{
							for (int _hlIdx = 0; _hlIdx < HeaderColumnBorderLogicalIds.Count; _hlIdx++)
							{
								if (HeaderColumnBorderLogicalIds[_hlIdx] == _highlightLogical)
								{
									SharpDX.RectangleF border = HeaderColumnBorderRects[_hlIdx];
									float dividerX = border.X + (border.Width / 2f) - 1f;
									SharpDX.RectangleF dividerLine = new SharpDX.RectangleF(dividerX, MinY, 2f, MaxY - MinY);
									FillRectBoth(chartControl, chartScale, dividerLine, ChartTextBrushDX);
									break;
								}
							}
						}

						// Column swap flash: brief highlight on the column that was just
						// displaced by a drag-reorder swap, so the user visually registers
						// that "something moved here." Lasts SwapFlashDurationMs milliseconds
						// after the swap, then clears itself.
						// HeaderColumnRects is COMPACTED to visible columns only, so
						// indexing it by a ColumnDisplayOrderList position is wrong
						// whenever any column is hidden. Resolve via
						// HeaderColumnLogicalIds.IndexOf to get the correct rect slot.
						if (_swapFlashLogical >= 0 && HeaderColumnRects != null
							&& HeaderColumnLogicalIds != null && DragTintBrushDX != null)
						{
							double _flashMs = (_renderNow - _swapFlashTime).TotalMilliseconds;
							if (_flashMs >= 0 && _flashMs <= SwapFlashDurationMs)
							{
								int _flashRectIdx = HeaderColumnLogicalIds.IndexOf(_swapFlashLogical);
								if (_flashRectIdx >= 0 && _flashRectIdx < HeaderColumnRects.Count)
								{
									SharpDX.RectangleF _flashHdr = HeaderColumnRects[_flashRectIdx];
									SharpDX.RectangleF _flashRect = new SharpDX.RectangleF(
										_flashHdr.X, MinY, _flashHdr.Width, MaxY - MinY);
									FillRectBoth(chartControl, chartScale, _flashRect, DragTintBrushDX);
								}
							}
							else
							{
								_swapFlashLogical = -1; // expire
							}
						}

						// Column drag-to-reorder visuals: subtle tint over the dragged column's
						// full-height strip + a bright 2px insertion marker on its left edge.
						// Only drawn after the drag activation threshold is crossed so a simple
						// click doesn't flash the overlay. Uses a dedicated DragTintBrushDX so
						// the AllDrawings replay cache sees a stable brush reference and never
						// flickers between fresh and replayed frames.
						//
						// HeaderColumnRects is COMPACTED to visible columns only — hidden
						// columns are skipped in the main cell loop. _draggingColumnDisplayIdx
						// is an index into ColumnDisplayOrderList (full, includes hidden), so
						// resolve via _draggingColumnLogical → HeaderColumnLogicalIds.IndexOf
						// to get the correct rect index. Without this, dragging any column
						// past a hidden column highlights the wrong rect.
						if (_columnDragArmed && _columnDragActivated
							&& _draggingColumnLogical >= 0 && HeaderColumnRects != null
							&& HeaderColumnLogicalIds != null
							&& DragTintBrushDX != null && ChartTextBrushDX != null)
						{
							int _drawRectIdx = HeaderColumnLogicalIds.IndexOf(_draggingColumnLogical);
							if (_drawRectIdx >= 0 && _drawRectIdx < HeaderColumnRects.Count)
							{
								SharpDX.RectangleF draggedHeaderRect = HeaderColumnRects[_drawRectIdx];
								SharpDX.RectangleF dragTintRect = new SharpDX.RectangleF(
									draggedHeaderRect.X, MinY,
									draggedHeaderRect.Width, MaxY - MinY);
								FillRectBoth(chartControl, chartScale, dragTintRect, DragTintBrushDX);
								// Insertion marker: 2px vertical bar on the left edge of the dragged column.
								SharpDX.RectangleF insMarker = new SharpDX.RectangleF(
									draggedHeaderRect.X, MinY, 2f, MaxY - MinY);
								FillRectBoth(chartControl, chartScale, insMarker, ChartTextBrushDX);
							}
						}

						// Filter indicator: shows the current search string when the filter is
						// active or populated. Rendered as a small overlay at the top-RIGHT of
						// the table, just under the header accent line, so it doesn't cover the
						// first column (Connected Status / Account). "/" activates/focuses,
						// Esc clears, Backspace deletes, letters/digits append. Label shows
						// "(N of M shown)" when a filter is applied.
						if ((_filterActive || !string.IsNullOrEmpty(_accountFilter))
							&& headerBottomY > 0 && ChartBackgroundBrushDX != null
							&& TableHeaderBackgroundBrushDX != null && TableHeaderBorderBrushDX != null
							&& ChartTextBrushDX != null)
						{
							// Build filter label and faded suffix
							string _fLabel;
							string _fFaded = null;
							string _fCountStr = (_lastFilterTotalCount > 0) ? _lastFilterVisibleCount + " / " + _lastFilterTotalCount + " accounts" : "";

							if (_accountFilter.Length == 0)
							{
								_fLabel = "Filter Accounts";
								if (_lastFilterTotalCount > 0)
									_fFaded = "(type to search)   " + _fCountStr;
								else
									_fFaded = "(type to search)";
							}
							else
							{
								_fLabel = "Filter Accounts  " + _accountFilter;
								if (_lastFilterTotalCount > 0)
									_fFaded = _lastFilterVisibleCount + " / " + _lastFilterTotalCount + " accounts";
							}

							// Size box to fit both label + faded text
							string _fFullText = _fLabel + "  " + (_fFaded ?? "");
							float _fCharW = (float)Math.Round(7.0f * dpiScaleY, 0);
							float _fBoxH = (float)Math.Round(22f * dpiScaleY, 0);
							float _fBoxW = Math.Max(240f, _fFullText.Length * _fCharW + 20);
							if (_fBoxW > (MaxX - MinX - 20)) _fBoxW = MaxX - MinX - 20;
							float _chartRightEdge = (float)(ChartPanel.W);
							float _fBoxX;
							if (MaxX > _chartRightEdge)
								_fBoxX = _chartRightEdge - _fBoxW - 5;
							else
								_fBoxX = MaxX - _fBoxW - 4;
							if (_fBoxX < MinX + 4) _fBoxX = MinX + 4;
							// Match the header-tooltip / picker gap below the header row
							// (ButtonTooltipGapPx, DPI-scaled), then nudge up 1 px so the
							// filter box visually balances a bit tighter to the header.
							float _fBoxY = headerBottomY + (float)(ButtonTooltipGapPx * dpiScaleY) - 1f;
							if (_fBoxY + _fBoxH > MaxY) _fBoxY = MaxY - _fBoxH - 2;
							SharpDX.RectangleF _fBoxRect = new SharpDX.RectangleF(_fBoxX, _fBoxY, _fBoxW, _fBoxH);
							DrawOverlayGlow(chartControl, chartScale, _fBoxRect);
							FillRectBoth(chartControl, chartScale, _fBoxRect, ChartBackgroundBrushDX);
							FillRectBoth(chartControl, chartScale, _fBoxRect, TableHeaderBackgroundBrushDX);
							DrawRectBoth(chartControl, chartScale, _fBoxRect, TableHeaderBorderBrushDX, 1);

							// Draw main label in normal text
							SharpDX.RectangleF _fTxtRect = new SharpDX.RectangleF(_fBoxX + 6, _fBoxY + 2, _fBoxW - 12, _fBoxH - 4);
							DrawTextBoth(chartControl, chartScale, _fLabel, MainTextLeft ?? CellFormat, _fTxtRect,
								_filterActive ? ChartTextBrushDX : (ChartTextBrushDX40 ?? ChartTextBrushDX));

							// Draw faded suffix after the label
							if (_fFaded != null)
							{
								float _prefixW = (_fLabel.Length + 1) * (float)Math.Round(6.2f * dpiScaleY, 0);
								SharpDX.RectangleF _fPhRect = new SharpDX.RectangleF(_fBoxX + 6 + _prefixW, _fBoxY + 2, _fBoxW - 12 - _prefixW, _fBoxH - 4);
								DrawTextBoth(chartControl, chartScale, _fFaded, MainTextLeft ?? CellFormat, _fPhRect,
									ChartTextBrushDX40 ?? ChartTextBrushDX);
							}
						}

						// Column visibility picker popup — a dark panel anchored at the
						// right-click location, one row per column, with a small 8x8 checkbox
						// glyph (empty square / filled square) indicating visibility. Locked
						// columns are rendered dimmed and can't be toggled. Click rects are
						// captured in _colPickerItemRects for the next mouse down.
						if (_colPickerOpen && ColumnNumberToName != null && ColumnNumberToName.Count > 0
							&& ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
							&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null)
						{
							_colPickerItemRects.Clear();
							_colPickerItemNames.Clear();
							_presetSlotRects.Clear();
							_hoveredPickerItem = -1;
							// On every fresh open, default the picker back to canonical
							// (dashboard-mirroring) order — the alphabetical toggle is
							// per-session-and-per-open-only by design.
							if (_colPickerJustOpened)
							{
								_pickerSortAlphabetical = false;
								_colPickerJustOpened = false;
							}

							// Build the picker list from a STABLE canonical column order that
							// matches the default layout from AllColumnsAddReuse calls in
							// the data-build pass (~line 19318+). This way:
							//  (a) the order doesn't change when the user drags columns
							//  (b) feature-toggle columns (Size/Type/Mode/Fade) keep their
							//      default position even when their pIs*ColumnEnabled is
							//      false and they're not in ColumnNumberToName yet
							// We accept a name into the picker if it's currently registered
							// in ColumnNumberToName (column exists this frame) OR it's a
							// feature-toggle column (always shown so user can enable it).
							// Canonical picker order — mirrors the AllColumnsAddReuse sequence
							// in the data-build pass (~line 19359 onward) AND the observed
							// default column layout on the dashboard. Kept in this exact
							// order so the picker reads top-down the same way the columns
							// appear on the dashboard by default.
							string[] _canonicalOrder = new string[]
							{
								"Connected Status",                         // TempRow3 (dot column "–" — locked)
								"Account",                                  // TempRow6
								"X",                                        // TempRow14 — right after Account in the dashboard
								"Latency",                                  // TempRow31 - always offered; ticking it turns the latency feature on
								"Actions",                                  // TempRow26
								"Size", "Type", "Mode", "Fade",             // TempRow17/18/29/2 — feature columns
								"Pos",                                      // TempRow19 (LongColumnName, ~line 19434)
								"Avg Price",                                // TempRow30
								"Unrealized", "Realized", "Gross Realized", // TempRow10/13/11
								"Cash Value", "Net Liquidation",            // TempRow8/16
								"From Funded", "Auto Close",                // TempRow23/22
								"Auto Liquidate", "From Closed",            // TempRow20/21
								"DD",                                       // TempRow5
								"Payout",                                   // TempRow28
								"Daily Loss", "Daily Goal", "Auto Exit",    // TempRow25/24/27 (Loss first per pShowLossOnLeft default)
								"Qty",                                      // TempRow4 — late (after Auto Exit, before Commissions)
								"Commissions", "Total PNL"                  // TempRow7/15
							};
							List<string> _pickerNames = new List<string>(_canonicalOrder.Length);
							// Include EVERY canonical column unconditionally. The picker is
							// the authoritative surface for "which columns exist at all" —
							// users need to be able to re-enable columns they previously
							// turned off (Avg Price, Payout, Realized, Cash Value, etc.),
							// which means those entries MUST be present even when the
							// master property is currently false and the column isn't in
							// AllColumns this frame.
							for (int _ci = 0; _ci < _canonicalOrder.Length; _ci++)
							{
								string _cn = _canonicalOrder[_ci];
								if (_cn == "–") continue;
								_pickerNames.Add(_cn);
							}
							// Tolerate columns we didn't anticipate in the canonical list:
							// append any registered name we haven't already added so the
							// picker still represents reality.
							foreach (var _kv in ColumnNumberToName)
								if (!string.IsNullOrEmpty(_kv.Value) && _kv.Value != "–"
									&& !_pickerNames.Contains(_kv.Value))
									_pickerNames.Add(_kv.Value);

							// Sizing: row height = ~18px scaled. Each column is sized by the
							// longest name it will hold; the picker goes into two-column
							// layout when the list gets long enough to be unwieldy.
							float _rowH = (float)Math.Round(18f * dpiScaleY, 0);
							float _padL = (float)Math.Round(8f * dpiScaleY, 0);
							float _padR = (float)Math.Round(10f * dpiScaleY, 0);
							float _cbSz = (float)Math.Round(9f * dpiScaleY, 0);
							float _cbGap = (float)Math.Round(6f * dpiScaleY, 0);
							float _colGap = (float)Math.Round(10f * dpiScaleY, 0);
							float _charW = (float)Math.Round(7f * dpiScaleY, 0);

							// Two-column layout kicks in past 15 items. The "Reset Layout"
							// footer row sits below both columns, spanning the full width.
							const int PickerColSplitThreshold = 15;
							bool _twoCol = _pickerNames.Count > PickerColSplitThreshold;
							int _itemsPerCol = _twoCol
								? (int)Math.Ceiling(_pickerNames.Count / 2.0)
								: _pickerNames.Count;

							// Compute each column's content width from the longest name in
							// THAT column (not the global longest). In two-column mode, this
							// can make the right column narrower than the left.
							float _leftColW = ComputePickerColWidth(_pickerNames, 0, _itemsPerCol, _charW, _padL, _cbSz, _cbGap, _padR);
							float _rightColW = _twoCol
								? ComputePickerColWidth(_pickerNames, _itemsPerCol, _pickerNames.Count, _charW, _padL, _cbSz, _cbGap, _padR)
								: 0f;
							// Sort toggle button size (drawn in the top-right of the picker bg)
							float _sortBtnSz = (float)Math.Round(16f * dpiScaleY, 0);
							// Add room for the sort button so the right column's text never
							// overlaps it: the button sits at (_bgW - _sortBtnSz - 4) from
							// the left, so the right column needs _sortBtnSz + 8 extra px.
							if (_twoCol)
								_rightColW += _sortBtnSz + 8;
							else
								_leftColW += _sortBtnSz + 8;
							float _bgW = _twoCol ? (_leftColW + _colGap + _rightColW) : _leftColW;

							// Alphabetical sort — applied AFTER width computation so the
							// picker bg doesn't resize when toggling between canonical and
							// alphabetical order (which redistributes names across columns).
							if (_pickerSortAlphabetical)
								_pickerNames.Sort(StringComparer.OrdinalIgnoreCase);

							// Footer: two side-by-side buttons ("Reset Widths" / "Reset All")
							// plus the preset slot row above them.
							float _footerH = _rowH + 4f + 3f;
							// Preset row: one extra row of four slot buttons. Extra 8px above
							// the divider (vs 4 before) + 4 for the divider-to-row gap.
							float _presetRowH = _rowH + 8f;
							float _bgH = (_rowH * _itemsPerCol) + 6f + _presetRowH + 6f + _footerH;

							// Clamp the popup inside the chart bounds.
							float _bgX = _colPickerX;
							float _bgY = _colPickerY;
							if (_bgX + _bgW > MaxX) _bgX = MaxX - _bgW - 2;
							if (_bgX < MinX) _bgX = MinX + 2;
							if (_bgY + _bgH > MaxY) _bgY = MaxY - _bgH - 2;
							if (_bgY < MinY) _bgY = MinY + 2;

							_colPickerBgRect = new SharpDX.RectangleF(_bgX, _bgY, _bgW, _bgH);
							DrawOverlayGlow(chartControl, chartScale, _colPickerBgRect);
							FillRectBoth(chartControl, chartScale, _colPickerBgRect, ChartBackgroundBrushDX);
							FillRectBoth(chartControl, chartScale, _colPickerBgRect, TableHeaderBackgroundBrushDX);
							DrawRectBoth(chartControl, chartScale, _colPickerBgRect, TableHeaderBorderBrushDX, 1);

							for (int _ri = 0; _ri < _pickerNames.Count; _ri++)
							{
								string _rn = _pickerNames[_ri];
								// Figure out which column + row slot this item goes in.
								int _colIdx = (_twoCol && _ri >= _itemsPerCol) ? 1 : 0;
								int _rowIdx = (_colIdx == 0) ? _ri : (_ri - _itemsPerCol);
								float _colX = _bgX + (_colIdx == 0 ? 0f : (_leftColW + _colGap));
								float _colW = (_colIdx == 0) ? _leftColW : _rightColW;
								float _ry = _bgY + 3 + _rowIdx * _rowH;
								SharpDX.RectangleF _itemRect = new SharpDX.RectangleF(_colX + 2, _ry, _colW - 4, _rowH);
								_colPickerItemRects.Add(_itemRect);
								_colPickerItemNames.Add(_rn);

								bool _isLocked = IsColumnLockedNoScroll(_rn);
								bool _isFeatureCol = IsFeatureToggleColumn(_rn);
								bool _isAccented = IsFeatureColumnAccented(_rn);
								bool _hasMaster = HasColumnMasterProperty(_rn);
								bool _isVisible;
								if (_isLocked)
									_isVisible = true; // locked columns are always visible by definition
								else if (_isFeatureCol)
									_isVisible = GetFeatureToggleState(_rn);
								else if (_hasMaster)
									_isVisible = GetColumnMasterPropertyState(_rn);
								else
									_isVisible = !_hiddenColumns.Contains(_rn);

								// Hover tint on the item the mouse is over. Also record the
								// hovered index so the inline tooltip below the picker can
								// look up the right description string.
								bool _isHovered = MouseIn(_itemRect, 0, 0);
								if (_isHovered) _hoveredPickerItem = _ri;
								if (_isHovered && DragTintBrushDX != null)
									FillRectBoth(chartControl, chartScale, _itemRect, DragTintBrushDX);

								// Checkbox: empty square outline for hidden, filled for visible.
								float _cbX = _colX + _padL;
								float _cbY = _ry + (_rowH - _cbSz) * 0.5f;
								SharpDX.RectangleF _cbRect = new SharpDX.RectangleF(_cbX, _cbY, _cbSz, _cbSz);
								// Outline always
								DrawRectBoth(chartControl, chartScale, _cbRect, ChartTextBrushDX40 ?? ChartTextBrushDX, 1);
								// Fill when visible — accented columns use the coral picker
								// accent so the checkbox matches the label color. Two
								// render styles: solid inner-inset block (default) or
								// ✓ glyph via CheckBoxTinyFormat.
								if (_isVisible)
								{
									SharpDX.Direct2D1.Brush _cbBrush = ChartTextBrushDX;
									if (_isLocked) _cbBrush = ChartTextBrushDX40 ?? ChartTextBrushDX;
									else if (_isAccented && PickerAccentBrushDX != null) _cbBrush = PickerAccentBrushDX;

									if (pCheckboxCheckmarkStyle && CheckBoxTinyFormat != null)
									{
										// clipToRect: false — glyph is intentionally larger than
										// the 9-px box so the ✓ extends past the outline on all
										// sides for a bolder read. Rect nudged up 1 px so the
										// glyph sits visually centered on the outline.
										SharpDX.RectangleF _cbGlyphRect = new SharpDX.RectangleF(
											_cbRect.X, _cbRect.Y - 1f, _cbRect.Width, _cbRect.Height);
										DrawTextBoth(chartControl, chartScale, checkmark,
											CheckBoxTinyFormat, _cbGlyphRect, _cbBrush, false);
									}
									else
									{
										SharpDX.RectangleF _cbInner = new SharpDX.RectangleF(
											_cbRect.X + 2, _cbRect.Y + 2, _cbRect.Width - 4, _cbRect.Height - 4);
										FillRectBoth(chartControl, chartScale, _cbInner, _cbBrush);
									}
								}

								// Label text — accented columns use the coral picker accent so
								// they read as "this changes a feature, not just a column".
								SharpDX.RectangleF _txtRect = new SharpDX.RectangleF(
									_cbX + _cbSz + _cbGap, _ry, _colW - (_padL + _cbSz + _cbGap + _padR), _rowH);
								SharpDX.Direct2D1.Brush _labelBrush = ChartTextBrushDX;
								if (_isLocked) _labelBrush = ChartTextBrushDX40 ?? ChartTextBrushDX;
								else if (_isAccented && PickerAccentBrushDX != null) _labelBrush = PickerAccentBrushDX;
								DrawTextBoth(chartControl, chartScale, _rn, MainTextLeft ?? CellFormat, _txtRect, _labelBrush);
							}

							// ── Alphabetical sort toggle ──
							// Same size, margin, border brush, and hover tint as the cheat
							// sheet X button so all top-right overlay buttons look uniform.
							float _sortCloseMargin = (float)Math.Round(6f * dpiScaleY, 0);
							_pickerSortToggleRect = new SharpDX.RectangleF(
								_bgX + _bgW - _sortBtnSz - _sortCloseMargin,
								_bgY + _sortCloseMargin,
								_sortBtnSz, _sortBtnSz);
							if (_pickerSortAlphabetical && DragTintBrushDX != null)
								FillRectBoth(chartControl, chartScale, _pickerSortToggleRect, DragTintBrushDX);
							if (DragTintBrushDX != null && MouseIn(_pickerSortToggleRect, 0, 0))
								FillRectBoth(chartControl, chartScale, _pickerSortToggleRect, DragTintBrushDX);
							DrawRectBoth(chartControl, chartScale, _pickerSortToggleRect, TableHeaderBorderBrushDX, 1);
							DrawTextBoth(chartControl, chartScale, "A\u2195",
								MainTextCenter ?? CellFormat, _pickerSortToggleRect, ChartTextBrushDX);

							// ── Preset slot row ──
							// 4 buttons aligned to the same left/right inset as the
							// checkboxes (_padL from each edge). The gap between buttons
							// is the SAME as the margin on each side, so visual spacing
							// is uniform everywhere.
							float _presetRowY = _bgY + 3 + (_rowH * _itemsPerCol) + 8;

							float _contentL = _bgX + _padL;             // left edge aligned with checkboxes
							float _contentR = _bgX + _bgW - _padL;      // right edge mirrored
							float _contentW = _contentR - _contentL;
							float _presetGap = _padL;                    // same as left/right margin
							int _numSlots = 4;
							float _slotW = (_contentW - _presetGap * (_numSlots - 1)) / (float)_numSlots;
							int _hoveredSlot = -1;
							for (int _ps = 0; _ps < _numSlots; _ps++)
							{
								SharpDX.RectangleF _slotRect = new SharpDX.RectangleF(
									_contentL + _ps * (_slotW + _presetGap),
									_presetRowY, _slotW, _rowH);
								_presetSlotRects.Add(_slotRect);

								bool _filled = !string.IsNullOrEmpty(GetPresetSlotString(_ps));
								bool _slotHovered = MouseIn(_slotRect, 0, 0);
								if (_slotHovered) _hoveredSlot = _ps;
								if (_slotHovered && PickerHoverGlowBrushDX != null)
									FillRectBoth(chartControl, chartScale, _slotRect, PickerHoverGlowBrushDX);
								DrawRectBoth(chartControl, chartScale, _slotRect,
									_filled ? ChartTextBrushDX : (ChartTextBrushDX40 ?? ChartTextBrushDX), 1);
								string _slotLabel = (_ps + 1).ToString();
								DrawTextBoth(chartControl, chartScale, _slotLabel,
									MainTextCenter ?? CellFormat, _slotRect,
									_filled ? ChartTextBrushDX : (ChartTextBrushDX40 ?? ChartTextBrushDX));
							}

							// ── Footer: "Reset Widths" / "Reset All" side-by-side ──
							// Same left/right inset as presets, same gap between the two.
							float _footerY = _presetRowY + _rowH + 7; // +1px extra below presets
							SharpDX.RectangleF _dividerRect = new SharpDX.RectangleF(
								_bgX + _padL, _footerY - 1, _contentW, 1f);
							FillRectBoth(chartControl, chartScale, _dividerRect, ChartTextBrushDX40 ?? ChartTextBrushDX);

							float _footerBtnW = (_contentW - _presetGap) / 2f; // same gap as between preset buttons
							// "Reset Widths" — left button. The clickable area is the full
							// rect but the hover effect is text-only: we draw the label in
							// a brighter brush when the mouse is inside the rect, no bg fill.
							_resetWidthsRect = new SharpDX.RectangleF(
								_contentL, _footerY + 3, _footerBtnW, _rowH);
							bool _rwHover = MouseIn(_resetWidthsRect, 0, 0);
							DrawTextBoth(chartControl, chartScale, "Reset Widths",
								MainTextCenter ?? CellFormat, _resetWidthsRect,
								_rwHover ? ChartTextBrushDX : (ChartTextBrushDX40 ?? ChartTextBrushDX));
							// Thin vertical divider between the two reset buttons
							SharpDX.RectangleF _resetDivRect = new SharpDX.RectangleF(
								_contentL + _footerBtnW + _presetGap * 0.5f - 0.5f,
								_footerY + 5, 1f, _rowH - 4);
							FillRectBoth(chartControl, chartScale, _resetDivRect, ChartTextBrushDX40 ?? ChartTextBrushDX);
							// "Reset All" — right button. Same text-only hover glow.
							_resetAllRect = new SharpDX.RectangleF(
								_contentL + _footerBtnW + _presetGap, _footerY + 3, _footerBtnW, _rowH);
							bool _raHover = MouseIn(_resetAllRect, 0, 0);
							DrawTextBoth(chartControl, chartScale, "Reset All",
								MainTextCenter ?? CellFormat, _resetAllRect,
								_raHover ? ChartTextBrushDX : (ChartTextBrushDX40 ?? ChartTextBrushDX));

							// ── Inline tooltip ──
							// Fires on hover of a column row OR a preset slot button.
							string _picTipText = null;

							// Column row tooltip — from ColumnHeaderTooltips dict
							string _picRowName = (_hoveredPickerItem >= 0 && _hoveredPickerItem < _colPickerItemNames.Count)
								? _colPickerItemNames[_hoveredPickerItem]
								: null;
							if (!string.IsNullOrEmpty(_picRowName)
								&& _picRowName != "__RESET_LAYOUT__")
								_picTipText = GetColumnHeaderTooltip(_picRowName);

							// Reset button tooltips
							if (_rwHover)
								_picTipText = IsKorean
									? "모든 컬럼 너비를 기본 자동 계산 값으로 초기화합니다."
									: "Reset all column widths to their default auto-computed values";
							else if (_raHover)
								_picTipText = IsKorean
									? "컬럼 순서, 너비, 표시/숨기기, 정렬, 모든 기능 토글을 초기화합니다."
									: "Reset everything: column order, widths, visibility, sort, and all feature toggles";

							// Preset slot tooltip — build dynamic text
							if (_hoveredSlot >= 0)
							{
								string _slotData = GetPresetSlotString(_hoveredSlot);
								if (string.IsNullOrEmpty(_slotData))
								{
									_picTipText = "Click to save current layout to slot " + (_hoveredSlot + 1);
								}
								else
								{
									// Parse the snapshot to build a summary
									int _numCols = 0;
									string _sortCol = "Account";
									string _sortDir = "asc";
									try
									{
										foreach (string _sec in _slotData.Split(';'))
										{
											int _eq = _sec.IndexOf('=');
											if (_eq <= 0) continue;
											string _key = _sec.Substring(0, _eq).Trim();
											string _val = _sec.Substring(_eq + 1);
											if (_key == "flags")
											{
												foreach (string _f in _val.Split('|'))
												{
													if (_f.StartsWith("pSelectedAscending:"))
														_sortDir = _f.EndsWith(":1") ? "asc" : "desc";
												}
												_numCols = _val.Split('|').Length;
											}
											else if (_key == "sort")
												_sortCol = string.IsNullOrEmpty(_val) ? "Account" : _val;
										}
									}
									catch { }
									_picTipText = "Click to load \u2014 sorted by " + _sortCol + " " + _sortDir;
								}
							}

							if (!string.IsNullOrEmpty(_picTipText))
							{
								if (PickerTooltipCachedLayout == null || PickerTooltipCachedText != _picTipText)
								{
									if (PickerTooltipCachedLayout != null) PickerTooltipCachedLayout.Dispose();
									PickerTooltipCachedLayout = new SharpDX.DirectWrite.TextLayout(
										Core.Globals.DirectWriteFactory, _picTipText, CellFormat, 280, 1000);
									PickerTooltipCachedText = _picTipText;
								}

								float _picTipW = PickerTooltipCachedLayout.Metrics.Width + 14;
								float _picTipH = PickerTooltipCachedLayout.Metrics.Height + 8;
								float _picTipX = _colPickerBgRect.Left;
								float _picTipY = _colPickerBgRect.Bottom + ButtonTooltipGapPx;
								if (_picTipY + _picTipH > MaxY)
									_picTipY = _colPickerBgRect.Top - _picTipH - 6;
								if (_picTipX + _picTipW > MaxX) _picTipX = MaxX - _picTipW;
								if (_picTipX < MinX) _picTipX = MinX;
								if (_picTipY < MinY) _picTipY = MinY;

								SharpDX.RectangleF _picTipRect = new SharpDX.RectangleF(_picTipX, _picTipY, _picTipW, _picTipH);
								SharpDX.RectangleF _picTipTextRect = new SharpDX.RectangleF(_picTipX + 7, _picTipY + 4, _picTipW - 14, _picTipH - 8);

								DrawOverlayGlow(chartControl, chartScale, _picTipRect);
								FillRectBoth(chartControl, chartScale, _picTipRect, ChartBackgroundBrushDX);
								FillRectBoth(chartControl, chartScale, _picTipRect, TableHeaderBackgroundBrushDX);
								DrawRectBoth(chartControl, chartScale, _picTipRect, TableHeaderBorderBrushDX, 1);
								DrawTextBoth(chartControl, chartScale, _picTipText, CellFormat, _picTipTextRect, ChartTextBrushDX);
							}
						}

						// Draw scroll bar — thin visual (2px) flush to the right table edge.
						// Hit area is 12px wide, extending left of the bar for easy click/drag (right-side
						// extension isn't possible because MaxX is at/near the chart panel edge).
						// Scrollbar spans only the account rows area, not the total rows below.
						if (TotalAccounts > MaximumAccountRows && MaximumAccountRows > 0 && firstAccountTopY > 0 && lastAccountBottomY > firstAccountTopY && TableHeaderBorderBrushDX != null)
						{
							// Bar grows 3px wider (inward) when hovered or dragged,
							// leaving the right edge flush with the table. Each hover
							// pixel is its own opacity stop so the fade to the left
							// reads as a smooth gradient instead of two big bands.
							bool _sbActive = IsHoveringScrollbar || IsDraggingScrollThumb;
							float visualW = _sbActive ? 4f : 2f;
							// Clamp to chart panel right edge so the scrollbar stays visible
							// when the window is narrower than the table.
							float rightEdge = Math.Min(MaxX, ChartPanel.X + ChartPanel.W - 1f);
							float visualX = rightEdge - visualW - 1f;
							float hitX = rightEdge - 12f - 1f;
							float hitW = 12f;
							// Track extends +1 px at the top and +2 px at the bottom relative
							// to the raw account-rows span (net 3 px taller, asymmetric — 1 px
							// extra at the bottom so the track grounds visually against the
							// total-rows divider below).
							float trackY = firstAccountTopY;
							float trackH = lastAccountBottomY - firstAccountTopY + 1;
							if (trackH > 20)
							{
								// Hit rects — wider than visuals so clicking is easy
								ScrollTrackRect = new SharpDX.RectangleF(hitX, trackY, hitW, trackH);

								// Thumb position and size. +2 px padding at the top and
								// +2 px added on top of the existing bottom padding so the
								// thumb breathes symmetrically inside the track: starts 2 px
								// below the top, ends 4 px above the bottom at max scroll.
								float visibleFrac = (float)MaximumAccountRows / (float)TotalAccounts;
								float thumbH = Math.Max(20f, trackH * visibleFrac);
								float maxScroll = TotalAccounts - MaximumAccountRows;
								float scrollFrac = maxScroll > 0 ? (float)AdjustmentRows / maxScroll : 0f;
								float _thumbTopPad = 1f;
								float _thumbBotPad = 3f;
								float _thumbTravel = Math.Max(0f, trackH - thumbH - _thumbTopPad - _thumbBotPad);
								float thumbY = trackY + _thumbTopPad + _thumbTravel * scrollFrac;
								ScrollThumbRect = new SharpDX.RectangleF(hitX, thumbY, hitW, thumbH);

								// Visual rects — thin bar, drawn on top of wider hit zone
								SharpDX.RectangleF scrollTrackVisual = new SharpDX.RectangleF(visualX, trackY, visualW, trackH);

								// Cutoff fade moved earlier in the render path (near the
								// outer-rect close) so it draws whether or not the
								// scrollbar is shown.

								// Track background (always same)
								FillRectBoth(chartControl, chartScale, scrollTrackVisual, TableBackgroundAltBrushDX);

								// Thumb rendered as stacked 1-px vertical strips with
								// descending opacity from the right edge leftward. Each
								// hover column gets its own stop so the falloff reads as
								// a smooth gradient.
								//   Rest (2px):  [40 %] [40 %]
								//   Hover (4px): [20 %] [40 %] [70 %] [100 %]
								if (_sbActive)
								{
									SharpDX.Direct2D1.Brush[] _sbStops =
									{
										ChartTextBrushDX20 ?? ChartTextBrushDX40,   // leftmost — softest
										ChartTextBrushDX40 ?? ChartTextBrushDX,
										ChartTextBrushDX70 ?? ChartTextBrushDX,
										ChartTextBrushDX                             // rightmost — bright core
									};
									for (int _sbK = 0; _sbK < _sbStops.Length; _sbK++)
									{
										if (_sbStops[_sbK] == null) continue;
										FillRectBoth(chartControl, chartScale,
											new SharpDX.RectangleF(visualX + _sbK, thumbY, 1f, thumbH), _sbStops[_sbK]);
									}
								}
								else
								{
									// Rest state: 2 px at 40 % on both columns, unchanged.
									FillRectBoth(chartControl, chartScale,
										new SharpDX.RectangleF(visualX + visualW - 1f, thumbY, 1f, thumbH), ChartTextBrushDX40);
									FillRectBoth(chartControl, chartScale,
