						// Draw column header tooltip after 300ms delay — no fade, no per-frame allocations.
						// TextLayout is cached and only re-measured when tooltip text actually changes.
						// Suppressed when a column divider is hovered or being dragged, when the
						// user has clicked a header and is dragging it to reorder, or when the
						// right-click column visibility picker is open.
						// NOTE: the fade-in was removed — mutating Brush.Opacity around a draw leaks
						// into the AllDrawings replay cache (brushes stored by reference). See
						// alldrawings-cache-brush-gotcha memory.
						if (HoveredHeaderColumn >= 0 && HeaderColumnRects != null && HoveredHeaderColumn < HeaderColumnRects.Count
							&& ColumnDisplayOrderList != null
							&& _hoveredResizeColumnLogical < 0 && _resizingColumnLogical < 0
							&& !_columnDragArmed
							&& !_colPickerOpen)
						{
							double hoverMs = (_renderNow - HoveredHeaderStartTime).TotalMilliseconds;
							// 300ms delay on the FIRST header hover. Once a tooltip is
							// already showing (HoveredHeaderTooltipShown == true), skip
							// the delay when moving between columns so the tooltip
							// follows the cursor instantly across the header row.
							if (pTooltipsColumnHeaders && (hoverMs > 300 || HoveredHeaderTooltipShown))
