								// (compacted to visible columns only). Convert via the
								// parallel logical-id list, not ColumnDisplayOrderList.
								string tooltipCol = null;
								if (HoveredHeaderColumn >= 0 && HoveredHeaderColumn < HeaderColumnLogicalIds.Count)
									ColumnNumberToName.TryGetValue(HeaderColumnLogicalIds[HoveredHeaderColumn], out tooltipCol);
								string tooltipText = !string.IsNullOrEmpty(tooltipCol) ? GetColumnHeaderTooltip(tooltipCol) : null;
								if (!string.IsNullOrEmpty(tooltipText))
								{
									// Only rebuild the TextLayout when the tooltip text changes (different column hovered)
									// DPI-scaled padding so the tooltip keeps proportional
									// insets at 125/150/200% Windows scaling.
									float _hdrPadX = (float)(7.0 * dpiScaleY);
									float _hdrPadY = (float)(4.0 * dpiScaleY);
									float _hdrGap  = (float)(ButtonTooltipGapPx * dpiScaleY);
									float _hdrMaxW = (float)(280.0 * dpiScaleY);
									if (TooltipCachedLayout == null || TooltipCachedText != tooltipText)
									{
