										// Use CellTipFormat (wrap-enabled) so long header tooltips
										// break onto multiple lines instead of spilling off the edge.
										TooltipCachedLayout = new TextLayout(Core.Globals.DirectWriteFactory, tooltipText, CellTipFormat != null ? CellTipFormat : CellFormat, _hdrMaxW, 1000);
										TooltipCachedText = tooltipText;
