									float tipW = TooltipCachedLayout.Metrics.Width  + _hdrPadX * 2;
									float tipH = TooltipCachedLayout.Metrics.Height + _hdrPadY * 2;
									float tipX = headerCellRect.Left;
									float tipY = headerCellRect.Bottom + _hdrGap;
									// Table's outer border draws at MaxX + 1 (rect width MaxX - MinX + 1);
									// line the tooltip's right edge up with that — but never past
									// the visible chart panel edge, and leave a 6-px glow inset
									// (DPI-scaled, matches DrawOverlayGlow) so the tooltip's
									// drop-shadow/halo isn't clipped at the right edge.
									float _hdrGlowInset = (float)(6.0 * dpiScaleY);
