							string[] _csDefaultLines = {
								"Accounts Dashboard - Quick Reference Guide",
								"",
								"ACCOUNTS",
								"  Double-click connection dot     Set as Master (double-click again to unset)",
								"  Click account name              Toggle as Follower",
								"",
								"COLUMN HEADERS",
								"  Click header                   Sort by column (click again to reverse)",
