							// blow out the overlay width.
							int _csMaxChars = 0;
							for (int _ci = 0; _ci < _csLines.Length; _ci++)
							{
								string _visLine = _csLines[_ci];
								string _vI, _vT, _vU, _vR;
								if (TryParseQrgLinkLine(_visLine, out _vI, out _vT, out _vU, out _vR))
