									// Draw link text.
									DrawTextBoth(chartControl, chartScale, _linkDisplay,
										MainTextLeft ?? CellFormat, _linkRect, _linkBrush);
									// Underline covers only the link text, not its indent.
									SharpDX.RectangleF _linkUnderline = new SharpDX.RectangleF(
										_clR.X + _indentPxW,
										_clR.Bottom - 2f,
										_textOnlyPxW,
										1f);
									FillRectBoth(chartControl, chartScale, _linkUnderline, _linkBrush);
									// Draw trailing plain-text, if any, immediately after the link.
									if (!string.IsNullOrEmpty(_lkTrail))
									{
										SharpDX.RectangleF _trailRect = new SharpDX.RectangleF(
											_linkRect.Right, _clR.Y,
											_clR.Right - _linkRect.Right, _clR.Height);
										DrawTextBoth(chartControl, chartScale, _lkTrail,
											MainTextLeft ?? CellFormat, _trailRect, ChartTextBrushDX);
									}
									_qrgLinkRects.Add(_linkRect);
									_qrgLinkUrls.Add(_lkUrl);
									continue;
								}

								bool _isSectionHeader = _csLine.Length > 0 && _csLine[0] != ' '
									&& _csLine == _csLine.ToUpperInvariant();
								// Section headers render at full brightness (not the dim
								// 40-alpha brush) with a thin underline immediately below
								// so the section structure reads at a glance.
								SharpDX.Direct2D1.Brush _csLineBrush = ChartTextBrushDX;
								DrawTextBoth(chartControl, chartScale, _csLine,
									MainTextLeft ?? CellFormat, _clR, _csLineBrush);
								if (_isSectionHeader)
								{
									float _hdrUnderlineW = 60f;
									try
									{
										var _tfmt = MainTextLeft ?? CellFormat;
										if (_tfmt != null)
										{
											using (var _hl = new SharpDX.DirectWrite.TextLayout(
												NinjaTrader.Core.Globals.DirectWriteFactory,
												_csLine, _tfmt, 10000f, _tfmt.FontSize))
											{ _hdrUnderlineW = _hl.Metrics.Width; }
										}
									}
									catch { }
									SharpDX.RectangleF _hdrUnderline = new SharpDX.RectangleF(
										_clR.X, _clR.Bottom - 2f,
										_hdrUnderlineW, 1f);
									FillRectBoth(chartControl, chartScale, _hdrUnderline,
										ChartTextBrushDX40 ?? ChartTextBrushDX);
								}
							}

							// Scrollbar — same thin 2px visual + wider hit area as main table.
							// Grows 2px wider (inward) while hovered or dragged.
							if (_csNeedsScroll && _csMaxScroll > 0)
							{
								// Same hover-expansion + gradient feather as the main
								// table scrollbar above — 4 px grab slab with per-pixel
								// opacity stops.
								bool _csSbActive = _csDraggingThumb || MouseIn(_csScrollTrackRect, 0, 0);
								float _sbVisualW = _csSbActive ? 4f : 2f;
								float _sbVisualX = _csRect.Right - _sbVisualW - 3f;
								float _sbHitX = _csRect.Right - 12f;
								float _sbHitW = 12f;
								float _sbTrackY = _csContentTop;
								float _sbTrackH = _csContentBot - _csContentTop;
								_csScrollTrackRect = new SharpDX.RectangleF(_sbHitX, _sbTrackY, _sbHitW, _sbTrackH);
								float _sbVisibleFrac = (float)_csVisibleBodyLines / (float)_csBodyCount;
								float _sbThumbH = Math.Max(20f, _sbTrackH * _sbVisibleFrac);
								float _sbScrollFrac = _csMaxScroll > 0 ? (float)_csScrollOffset / _csMaxScroll : 0f;
								float _sbThumbY = _sbTrackY + (_sbTrackH - _sbThumbH) * _sbScrollFrac;
								_csScrollThumbRect = new SharpDX.RectangleF(_sbHitX, _sbThumbY, _sbHitW, _sbThumbH);
								// Visual track
								SharpDX.RectangleF _sbTrackVisual = new SharpDX.RectangleF(_sbVisualX, _sbTrackY, _sbVisualW, _sbTrackH);
								FillRectBoth(chartControl, chartScale, _sbTrackVisual, TableBackgroundAltBrushDX);
								// Thumb rendered as stacked 1-px strips with per-pixel
								// opacity stops for a smooth feather.
								//   Rest (2px):  [40 %] [40 %]
								//   Hover (4px): [20 %] [40 %] [70 %] [100 %]
								if (_csSbActive)
								{
									SharpDX.Direct2D1.Brush[] _csSbStops =
									{
										ChartTextBrushDX20 ?? ChartTextBrushDX40,
										ChartTextBrushDX40 ?? ChartTextBrushDX,
										ChartTextBrushDX70 ?? ChartTextBrushDX,
										ChartTextBrushDX
									};
									for (int _csK = 0; _csK < _csSbStops.Length; _csK++)
									{
										if (_csSbStops[_csK] == null) continue;
										FillRectBoth(chartControl, chartScale,
											new SharpDX.RectangleF(_sbVisualX + _csK, _sbThumbY, 1f, _sbThumbH), _csSbStops[_csK]);
									}
								}
								else
								{
									SharpDX.Direct2D1.Brush _sbRest = ChartTextBrushDX40 ?? ChartTextBrushDX;
									FillRectBoth(chartControl, chartScale,
										new SharpDX.RectangleF(_sbVisualX + _sbVisualW - 1f, _sbThumbY, 1f, _sbThumbH), _sbRest);
									FillRectBoth(chartControl, chartScale,
										new SharpDX.RectangleF(_sbVisualX + _sbVisualW - 2f, _sbThumbY, 1f, _sbThumbH), _sbRest);
								}
							}
							else
							{
								_csScrollTrackRect = new SharpDX.RectangleF(0, 0, 0, 0);
								_csScrollThumbRect = new SharpDX.RectangleF(0, 0, 0, 0);
							}

							// Close (X) button in the upper-right corner.
							float _csCloseMargin = (float)Math.Round(6f * dpiScaleY, 0);
							_cheatSheetCloseRect = new SharpDX.RectangleF(
								_csRect.Right - _csCloseSz - _csCloseMargin,
								_csRect.Y + _csCloseMargin,
								_csCloseSz, _csCloseSz);
							if (DragTintBrushDX != null && MouseIn(_cheatSheetCloseRect, 0, 0))
								FillRectBoth(chartControl, chartScale, _cheatSheetCloseRect, DragTintBrushDX);
							DrawRectBoth(chartControl, chartScale, _cheatSheetCloseRect, TableHeaderBorderBrushDX, 1);
							DrawTextBoth(chartControl, chartScale, "X",
								MainTextCenter ?? CellFormat, _cheatSheetCloseRect, ChartTextBrushDX);

							// "Updated HH:MM" timestamp just left of the X button so the
							// user can confirm the remote content is recent. Uses the
							// dim 40-alpha brush and the smaller QrgSmallFormat so it's
							// visibly secondary.
							if (_qrgLastFetch > DateTime.MinValue)
							{
								string _tsText = "Updated " + _qrgLastFetch.ToString("h:mmtt").ToLower();
								float _tsW = (float)Math.Round(90f * dpiScaleY, 0);
								SharpDX.RectangleF _tsRect = new SharpDX.RectangleF(
									_cheatSheetCloseRect.Left - _tsW - 6f,
									_csRect.Y + _csCloseMargin,
									_tsW, _csCloseSz);
								DrawTextBoth(chartControl, chartScale, _tsText,
									QrgSmallFormat ?? MainTextCenter ?? CellFormat,
									_tsRect, ChartTextBrushDX40 ?? ChartTextBrushDX);
							}
						}

						// --- Latency menu popup ---
						// Opened from the latency (stopwatch) button — tunes the latency
						// feature in-chart. Button-anchored panel of toggle rows plus a
						// Slow Threshold stepper. Mirrors the profile picker's layout.
						if (_latencyMenuOpen && pLatencyColumn
							&& ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
							&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null)
						{
							_latencyMenuItemRects.Clear();
							_latencyMenuItemNames.Clear();
							_latencyThreshMinusRect = new SharpDX.RectangleF(0, 0, 0, 0);
							_latencyThreshPlusRect  = new SharpDX.RectangleF(0, 0, 0, 0);

							string[] _lmRows = (pCopierMode == "Executions") ? new[] { "__TITLE__", "Dispatch Latency", "Confirmation Latency", "__THRESH__", "__STAT:Execution__", "__STAT:Flatten__", "__RESET__" } : new[] { "__TITLE__", "Dispatch Latency", "Confirmation Latency", "__THRESH__", "__STAT:Place__", "__STAT:Move__", "__STAT:Cancel__", "__STAT:Flatten__", "__RESET__" };

							float _lmRowH  = (float)Math.Round(20f  * dpiScaleY, 0);
							float _lmPad   = (float)Math.Round(8f   * dpiScaleY, 0);
							float _lmCbSz  = (float)Math.Round(10f  * dpiScaleY, 0);
							float _lmCbGap = (float)Math.Round(6f   * dpiScaleY, 0);
							float _lmBgW   = (float)Math.Round(212f * dpiScaleY, 0);
							float _lmBgH   = _lmRowH * _lmRows.Length + 6f;

							// Anchored above the button, right-aligned (like the profile picker).
							float _lmBgX = _latencyMenuX - _lmBgW + 30;
							float _lmBgY = _latencyMenuY - _lmBgH;
							if (_lmBgX + _lmBgW > ChartPanel.W - 6) _lmBgX = ChartPanel.W - _lmBgW - 6;
							if (_lmBgX < MinX + 6) _lmBgX = MinX + 6;
							if (_lmBgY < MinY + 6) _lmBgY = MinY + 6;

							_latencyMenuBgRect = new SharpDX.RectangleF(_lmBgX, _lmBgY, _lmBgW, _lmBgH);
							DrawOverlayGlow(chartControl, chartScale, _latencyMenuBgRect);
							FillRectBoth(chartControl, chartScale, _latencyMenuBgRect, ChartBackgroundBrushDX);
							FillRectBoth(chartControl, chartScale, _latencyMenuBgRect, TableHeaderBackgroundBrushDX);
							DrawRectBoth(chartControl, chartScale, _latencyMenuBgRect, TableHeaderBorderBrushDX, 1);

							for (int _lri = 0; _lri < _lmRows.Length; _lri++)
							{
								string _lr = _lmRows[_lri];
								float _lry = _lmBgY + 3 + _lri * _lmRowH;
								SharpDX.RectangleF _lrRect = new SharpDX.RectangleF(_lmBgX + 2, _lry, _lmBgW - 4, _lmRowH);
								_latencyMenuItemRects.Add(_lrRect);
								_latencyMenuItemNames.Add(_lr);

								if (_lr == "__TITLE__")
								{
									DrawTextBoth(chartControl, chartScale, "Latency", MainTextCenter ?? CellFormat, _lrRect, ChartTextBrushDX40 ?? ChartTextBrushDX);
									SharpDX.RectangleF _ulRect = new SharpDX.RectangleF(_lmBgX + _lmPad, _lry + _lmRowH - 1, _lmBgW - _lmPad * 2, 1);
									FillRectBoth(chartControl, chartScale, _ulRect, ChartTextBrushDX40 ?? ChartTextBrushDX);
									continue;
								}

								bool _lrHov = MouseIn(_lrRect, 0, 0);
								if (_lrHov && DragTintBrushDX != null)
									FillRectBoth(chartControl, chartScale, _lrRect, DragTintBrushDX);

								if (_lr == "__THRESH__")
								{
									float _stBtn = _lmRowH - 6;
									_latencyThreshPlusRect = new SharpDX.RectangleF(_lmBgX + _lmBgW - _lmPad - _stBtn, _lry + 3, _stBtn, _stBtn);
									float _stValW = (float)Math.Round(46f * dpiScaleY, 0);
									SharpDX.RectangleF _stVal = new SharpDX.RectangleF(_latencyThreshPlusRect.X - 4 - _stValW, _lry, _stValW, _lmRowH);
									_latencyThreshMinusRect = new SharpDX.RectangleF(_stVal.X - 4 - _stBtn, _lry + 3, _stBtn, _stBtn);
									DrawRectBoth(chartControl, chartScale, _latencyThreshMinusRect, ChartTextBrushDX, 1);
									DrawRectBoth(chartControl, chartScale, _latencyThreshPlusRect,  ChartTextBrushDX, 1);
									DrawTextBoth(chartControl, chartScale, "−", MainTextCenter ?? CellFormat, _latencyThreshMinusRect, ChartTextBrushDX);
									DrawTextBoth(chartControl, chartScale, "+", MainTextCenter ?? CellFormat, _latencyThreshPlusRect,  ChartTextBrushDX);
									DrawTextBoth(chartControl, chartScale, pLatencySlowThresholdMs + "ms", MainTextCenter ?? CellFormat, _stVal, ChartTextBrushDX);
									SharpDX.RectangleF _stLbl = new SharpDX.RectangleF(_lmBgX + _lmPad, _lry, _latencyThreshMinusRect.X - _lmBgX - _lmPad, _lmRowH);
									DrawTextBoth(chartControl, chartScale, "Slow Threshold", MainTextLeft ?? CellFormat, _stLbl, ChartTextBrushDX);
									continue;
								}

								// Per-action copy-event readout: typical accounts per event and the
								// ms-per-account (event worst latency / accounts).
								if (_lr.StartsWith("__STAT:"))
								{
									string _action = _lr.Substring(7, _lr.Length - 9);
									int _evtN, _msAcct;
									string _statVal = !pLatencyDispatch ? "dispatch off" : (LatActionEventStats(_action, out _evtN, out _msAcct) ? (_evtN + " acct   " + _msAcct + " ms/acct") : "no data");
									float _saLblW = (float)Math.Round(60f * dpiScaleY, 0);
									SharpDX.RectangleF _saLblR = new SharpDX.RectangleF(_lmBgX + _lmPad, _lry, _saLblW, _lmRowH);
									SharpDX.RectangleF _saValR = new SharpDX.RectangleF(_lmBgX + _lmPad + _saLblW, _lry, _lmBgW - _lmPad * 2 - _saLblW, _lmRowH);
									DrawTextBoth(chartControl, chartScale, _action, MainTextLeft ?? CellFormat, _saLblR, ChartTextBrushDX40 ?? ChartTextBrushDX);
									DrawTextBoth(chartControl, chartScale, _statVal, MainTextLeft ?? CellFormat, _saValR, ChartTextBrushDX);
									continue;
								}
								if (_lr == "__RESET__")
								{
									SharpDX.RectangleF _rsRect = new SharpDX.RectangleF(_lmBgX + _lmPad, _lry + 2, _lmBgW - _lmPad * 2, _lmRowH - 4);
									DrawRectBoth(chartControl, chartScale, _rsRect, ChartTextBrushDX40 ?? ChartTextBrushDX, 1);
									DrawTextBoth(chartControl, chartScale, "Reset Stats", MainTextCenter ?? CellFormat, _rsRect, ChartTextBrushDX);
									continue;
								}

								// Toggle (checkbox) rows.
								bool _lrOn = _lr == "Dispatch Latency" ? pLatencyDispatch : pLatencyConfirmation;
								float _cbX = _lmBgX + _lmPad;
								float _cbY = _lry + (_lmRowH - _lmCbSz) * 0.5f;
								SharpDX.RectangleF _cbRect = new SharpDX.RectangleF(_cbX, _cbY, _lmCbSz, _lmCbSz);
								DrawRectBoth(chartControl, chartScale, _cbRect, ChartTextBrushDX40 ?? ChartTextBrushDX, 1);
								if (_lrOn)
								{
									SharpDX.RectangleF _cbIn = new SharpDX.RectangleF(_cbRect.X + 2, _cbRect.Y + 2, _cbRect.Width - 4, _cbRect.Height - 4);
									FillRectBoth(chartControl, chartScale, _cbIn, ChartTextBrushDX);
								}
								SharpDX.RectangleF _lrTxt = new SharpDX.RectangleF(_cbX + _lmCbSz + _lmCbGap, _lry, _lmBgW - (_lmPad + _lmCbSz + _lmCbGap + _lmPad), _lmRowH);
								DrawTextBoth(chartControl, chartScale, _lr, MainTextLeft ?? CellFormat, _lrTxt, ChartTextBrushDX);
							}
						}

						// --- Profile picker popup ---
						if (_profilePickerOpen
							&& ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
							&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null)
						{
							_profilePickerItemRects.Clear();
							_profilePickerItemNames.Clear();
							_profilePickerDeleteRects.Clear();
							_hoveredProfileItem = -1;

							// Scan saved profiles with timestamps
							List<string> _profileNames = new List<string>();
							Dictionary<string, string> _profileTimestamps = new Dictionary<string, string>();
							try
							{
								if (_profilesDir != "" && System.IO.Directory.Exists(_profilesDir))
								{
									foreach (string f in System.IO.Directory.GetFiles(_profilesDir, "*.xml"))
									{
										string _pfName = System.IO.Path.GetFileNameWithoutExtension(f);
										_profileNames.Add(_pfName);
										try
										{
											DateTime _lwt = System.IO.File.GetLastWriteTime(f);
											_profileTimestamps[_pfName] = _lwt.ToString("M/d h:mmtt").ToLower();
										}
										catch { }
									}
								}
							}
							catch { }

							// Build item list: active profile first (pinned), remaining sorted alphabetically
							_profileNames.Sort(StringComparer.OrdinalIgnoreCase);
							List<string> _items = new List<string>();
							if (!string.IsNullOrEmpty(_activeProfileName) && _profileNames.Contains(_activeProfileName))
								_items.Add(_activeProfileName);
							foreach (string p in _profileNames)
								if (p != _activeProfileName)
									_items.Add(p);
							_items.Add("---"); // always show separator above action items
							_items.Add("Save New Profile");
							if (!string.IsNullOrEmpty(_activeProfileName))
								_items.Add("Update Current Profile");
							// "Properties" removed — the gear icon in the top button row
							// now opens the properties window.

							// Account state lives in accounts.xml (machine-local) and is
							// intentionally NOT part of profile XML — switching profiles
							// won't change hidden accounts, master, or selections. Expose
							// a small reset surface here so users have an explicit way to
							// clear that state without hunting in the file system.
							_items.Add("---");
							_items.Add("Reset Hidden Accounts");
							_items.Add("Reset Account Selections");

							float _pRowH = (float)Math.Round(18f * dpiScaleY, 0);
							float _pPadL = (float)Math.Round(8f * dpiScaleY, 0);
							float _pPadR = (float)Math.Round(10f * dpiScaleY, 0);
							float _pCharW = (float)Math.Round(7f * dpiScaleY, 0);

							// Width sized to longest content on any single row:
							// profile name + timestamp, or longest action label.
							// Timestamps use a narrower effective char width (~5px)
							// since digits/colons are tighter than letters — keeps
							// the menu from getting overly wide.
							float _maxNameW = 0;
							float _tsGap = _pCharW;                 // 1 char gap between name and timestamp
							float _tsCharW = _pCharW * 0.72f;       // timestamp glyphs are tighter
							foreach (string _nm in _items)
							{
								if (_nm == "---") continue;
								float _nw = _nm.Length * _pCharW;
								string _ts;
								if (_profileTimestamps.TryGetValue(_nm, out _ts))
									_nw += _tsGap + _ts.Length * _tsCharW;
								if (_nw > _maxNameW) _maxNameW = _nw;
							}
							// Reserve space for the delete X on saved profile rows.
							float _pDelResW = (float)Math.Round(18f * dpiScaleY, 0);
							float _pBgW = _pPadL + _maxNameW + _pDelResW + _pPadR;
							float _pBgH = _pRowH * _items.Count + 6f;

							// Position above the button, right-aligned
							float _pBgX = _profilePickerX - _pBgW + 30;
							float _pBgY = _profilePickerY - _pBgH;
							if (_pBgX + _pBgW > ChartPanel.W - 6) _pBgX = ChartPanel.W - _pBgW - 6;
							if (_pBgX < MinX + 6) _pBgX = MinX + 6;
							if (_pBgY < MinY + 6) _pBgY = MinY + 6;

							_profilePickerBgRect = new SharpDX.RectangleF(_pBgX, _pBgY, _pBgW, _pBgH);
							DrawOverlayGlow(chartControl, chartScale, _profilePickerBgRect);
							FillRectBoth(chartControl, chartScale, _profilePickerBgRect, ChartBackgroundBrushDX);
							FillRectBoth(chartControl, chartScale, _profilePickerBgRect, TableHeaderBackgroundBrushDX);
							DrawRectBoth(chartControl, chartScale, _profilePickerBgRect, TableHeaderBorderBrushDX, 1);

							for (int _pi = 0; _pi < _items.Count; _pi++)
							{
								string _pn = _items[_pi];
								float _py = _pBgY + 3 + _pi * _pRowH;
								SharpDX.RectangleF _pItemRect = new SharpDX.RectangleF(_pBgX + 2, _py, _pBgW - 4, _pRowH);

								if (_pn == "---")
								{
									// Horizontal separator line between saved profiles and action items.
									float _sepY = _py + _pRowH * 0.5f;
									SharpDX.RectangleF _sepRect = new SharpDX.RectangleF(
										_pBgX + _pPadL, _sepY, _pBgW - _pPadL - _pPadR, 1);
									FillRectBoth(chartControl, chartScale, _sepRect, ChartTextBrushDX40 ?? ChartTextBrushDX);
									// Store the real rect so the re-draw pass can reuse it.
									// Name "---" tells click handler to skip it.
									_profilePickerItemRects.Add(_sepRect);
									_profilePickerItemNames.Add("---");
									_profilePickerDeleteRects.Add(new SharpDX.RectangleF(0, 0, 0, 0));
									continue;
								}

								_profilePickerItemNames.Add(_pn);

									bool _pIsAction = (_pn == "Save New Profile" || _pn == "Update Current Profile" || _pn == "Properties" || _pn == "Reset Hidden Accounts" || _pn == "Reset Account Selections");
									bool _pIsActive = (!_pIsAction && _pn == _activeProfileName && !_profileDirty);

									// Delete X for saved profiles (not action items)
									float _delSz = _pRowH - 4;
									SharpDX.RectangleF _pDelRect = new SharpDX.RectangleF(0, 0, 0, 0);
									if (!_pIsAction)
									{
										_pDelRect = new SharpDX.RectangleF(
											_pBgX + _pBgW - _pPadR - _delSz + 2, _py + 2, _delSz, _delSz);
										bool _delHov = MouseIn(_pDelRect, 0, 0);
										DrawTextBoth(chartControl, chartScale, "\u2715",
											MainTextCenter ?? CellFormat, _pDelRect,
											_delHov ? ChartTextBrushDX : (ChartTextBrushDX40 ?? ChartTextBrushDX));
									}
									_profilePickerDeleteRects.Add(_pDelRect);

									// Text rect sized to actual text width for click/hover hit testing
									float _pTxtW = _pn.Length * _pCharW;
									SharpDX.RectangleF _pTxtRect = new SharpDX.RectangleF(
										_pBgX + _pPadL, _py, _pTxtW, _pRowH);
									_profilePickerItemRects.Add(_pTxtRect);

									bool _pMouseHover = MouseIn(_pTxtRect, 0, 0);
									if (_pMouseHover)
									{
										_hoveredProfileItem = _pi;
										// Mouse movement over a different item clears keyboard selection
										if (_kbSelectedProfileItem != _pi) _kbSelectedProfileItem = -1;
									}
									bool _pKbSelected = (_kbSelectedProfileItem == _pi);
									bool _pHovered = _pMouseHover || _pKbSelected;

									SharpDX.Direct2D1.Brush _pBrush = (_pHovered || _pIsActive)
										? ChartTextBrushDX
										: (ChartTextBrushDX40 ?? ChartTextBrushDX);

									DrawTextBoth(chartControl, chartScale, _pn,
										MainTextLeft ?? CellFormat, _pTxtRect, _pBrush);

									// Last-saved timestamp render disabled — visually busy and
									// mostly not useful once you know the profile names. The
									// _profileTimestamps dict is still populated so the hover
									// "diff summary" tooltip can still compare current state
									// against saved state, and re-enabling is a one-block
									// uncomment if we decide to bring it back.
									// string _pTs;
									// if (!_pIsAction && _profileTimestamps.TryGetValue(_pn, out _pTs))
									// {
									// 	float _tsLeft  = _pBgX + _pPadL;
									// 	float _tsRight = _pBgX + _pBgW - _pPadR - _pDelResW;
									// 	if (_tsRight > _tsLeft)
									// 	{
									// 		SharpDX.RectangleF _tsRect = new SharpDX.RectangleF(
									// 			_tsLeft, _py, _tsRight - _tsLeft, _pRowH);
									// 		DrawTextBoth(chartControl, chartScale, _pTs,
									// 			QrgSmallFormat ?? MainTextLeft ?? CellFormat, _tsRect, ChartTextBrushDX40 ?? ChartTextBrushDX);
									// 	}
									// }
							}

							// Profile diff tooltip on hover — DISABLED FOR NOW (wrapped in
							// `if (false)` rather than deleted so the code can be reactivated
							// later by flipping the gate back to a pTooltipsProfileDiff flag).
							int _tipIdx = _kbSelectedProfileItem >= 0 ? _kbSelectedProfileItem : _hoveredProfileItem;
							if (false && _tipIdx >= 0 && _tipIdx < _profilePickerItemNames.Count)
							{
								string _hpn = _profilePickerItemNames[_tipIdx];
								if (_hpn != "---" && _hpn != "Save New Profile" && _hpn != "Update Current Profile" && _hpn != "Properties" && _hpn != "Reset Hidden Accounts" && _hpn != "Reset Account Selections")
								{
									if (_profileHoverTipName != _hpn)
									{
										_profileHoverTipName = _hpn;
										_profileHoverTipText = null;
										_profileHoverStartT = DateTime.Now;
										try
										{
											string _hpPath = System.IO.Path.Combine(_profilesDir, _hpn + ".xml");
											if (System.IO.File.Exists(_hpPath))
											{
												var _hpDoc = System.Xml.Linq.XDocument.Load(_hpPath);
												var _hpElem = _hpDoc.Descendants("aiDuplicateAccountActions").FirstOrDefault();
												if (_hpElem != null)
												{
													Type _hpType = this.GetType();
													PropertyInfo[] _hpProps = _hpType.GetProperties(BindingFlags.Public | BindingFlags.Instance);
													Dictionary<string, PropertyInfo> _hpPropMap = new Dictionary<string, PropertyInfo>();
													foreach (PropertyInfo _pm in _hpProps)
														if (_pm.CanRead && !_hpPropMap.ContainsKey(_pm.Name))
															_hpPropMap[_pm.Name] = _pm;

													List<string> _diffs = new List<string>();
													foreach (var _xp in _hpElem.Elements())
													{
														// Only diff scalar leaf elements — complex serialized
														// objects (brushes, fonts, lists) have child elements
														// and would produce false positives from .Value concat.
														if (_xp.HasElements) continue;
														string _xn = _xp.Name.LocalName;
														string _xv = _xp.Value;
														if (_xn == "ThisMasterAccount" || _xn == "LicensingEmailAddress"
															|| _xn == "Name" || _xn == "ActiveProfileName_Saved"
															|| _xn == "ColumnWidthOverrides_Saved" || _xn == "SavedScrollPosition"
															|| _xn == "HiddenColumns_Saved" || _xn == "IsVisible"
															|| _xn == "Calculate" || _xn == "BarsPeriodSerializable"
															|| _xn == "BarsToLoad" || _xn == "InstrumentDeserialized"
															|| _xn == "IndicatorId" || _xn == "ChartHashCodeDeserialized"
															|| _xn == "FirstLoadIsDone" || _xn == "PreviousVersionName"
															|| _xn == "IsCopyBasicFunctionsPermission" || _xn == "IsRiskFunctionsPermission") continue;

														PropertyInfo _hp;
														if (!_hpPropMap.TryGetValue(_xn, out _hp)) continue;
														Type _pt = _hp.PropertyType;
														// Only compare types the loader can parse (matches profile load logic)
														bool _supported = (_pt == typeof(string) || _pt == typeof(bool)
															|| _pt == typeof(int) || _pt == typeof(double)
															|| _pt == typeof(float) || _pt.IsEnum);
														if (!_supported) continue;
														// Only diff real user settings — tagged with NinjaScriptProperty
														// or a visible Display group. Skip internal runtime properties
														// that serialize but aren't "settings" (caches, computed state).
														// Use .GroupName (raw string) not .GetGroupName() which throws
														// when ResourceType is set but the group-name key isn't in the resource file.
														bool _isUserSetting = false;
														try
														{
															object[] _npAttrs = _hp.GetCustomAttributes(typeof(NinjaScriptPropertyAttribute), true);
															if (_npAttrs != null && _npAttrs.Length > 0) _isUserSetting = true;
															else
															{
																object[] _dispAttrs = _hp.GetCustomAttributes(typeof(System.ComponentModel.DataAnnotations.DisplayAttribute), true);
																if (_dispAttrs != null && _dispAttrs.Length > 0)
																{
																	var _da = _dispAttrs[0] as System.ComponentModel.DataAnnotations.DisplayAttribute;
																	if (_da != null && _da.GroupName != "Hidden") _isUserSetting = true;
																}
															}
														}
														catch { }
														if (!_isUserSetting) continue;
														try
														{
															object _cur = _hp.GetValue(this);
															string _curStr;
															string _xvNorm = _xv;
															if (_cur == null) _curStr = "";
															else if (_pt == typeof(bool))
															{
																// NT serializes bools lowercase ("true"/"false") but
																// bool.ToString() returns capitalized ("True"/"False").
																_curStr = ((bool)_cur) ? "true" : "false";
																_xvNorm = _xv.ToLowerInvariant();
															}
															else if (_pt == typeof(double))
																_curStr = ((double)_cur).ToString(System.Globalization.CultureInfo.InvariantCulture);
															else if (_pt == typeof(float))
																_curStr = ((float)_cur).ToString(System.Globalization.CultureInfo.InvariantCulture);
															else _curStr = _cur.ToString();
															if (_curStr != _xvNorm)
															{
																string _shortName = _xn.StartsWith("p") && _xn.Length > 1 && char.IsUpper(_xn[1])
																	? _xn.Substring(1) : _xn;
																_diffs.Add(_shortName + ": " + _curStr + " \u2192 " + _xv);
															}
														}
														catch { }
													}
													if (_diffs.Count == 0)
														_profileHoverTipText = "Matches current settings";
													else if (_diffs.Count <= 10)
														_profileHoverTipText = _diffs.Count + " difference" + (_diffs.Count == 1 ? "" : "s") + ":\n" + string.Join("\n", _diffs.ToArray());
													else
													{
														string[] _first = new string[10];
														for (int _di = 0; _di < 10; _di++) _first[_di] = _diffs[_di];
														_profileHoverTipText = _diffs.Count + " differences \u2014 showing first 10:\n" + string.Join("\n", _first) + "\n\u2026";
													}
												}
											}
										}
										catch { _profileHoverTipText = null; }
									}
									if (!string.IsNullOrEmpty(_profileHoverTipText) && _tipIdx < _profilePickerItemRects.Count
										&& (DateTime.Now - _profileHoverStartT).TotalMilliseconds >= ProfileHoverDelayMs)
