				// Re-draw the profile picker ON TOP of messages. The first render pass
				// at ~line 25637 computed all rects and stored them in _profilePickerBgRect
				// / _profilePickerItemRects / _profilePickerItemNames. Here we just re-draw
				// the visuals so the picker occludes any status messages beneath it.
				if (_profilePickerOpen && _profilePickerBgRect.Width > 0 && _profilePickerBgRect.Height > 0
					&& ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
					&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null)
				{
					// Rebuild timestamps map (first pass's local dictionary went out of scope).
					Dictionary<string, string> _rpTimestamps = new Dictionary<string, string>();
					try
					{
						if (_profilesDir != "" && System.IO.Directory.Exists(_profilesDir))
						{
							foreach (string _f in System.IO.Directory.GetFiles(_profilesDir, "*.xml"))
							{
								string _fn = System.IO.Path.GetFileNameWithoutExtension(_f);
								try
								{
									DateTime _lwt = System.IO.File.GetLastWriteTime(_f);
									_rpTimestamps[_fn] = _lwt.ToString("M/d h:mmtt").ToLower();
								}
								catch { }
							}
						}
					}
					catch { }
					float _rpCharW = (float)Math.Round(7f * dpiScaleY, 0);

					DrawOverlayGlow(chartControl, chartScale, _profilePickerBgRect);
