					FillRectBoth(chartControl, chartScale, _profilePickerBgRect, TableHeaderBackgroundBrushDX);
					DrawRectBoth(chartControl, chartScale, _profilePickerBgRect, TableHeaderBorderBrushDX, 1);
					for (int _rpI = 0; _rpI < _profilePickerItemRects.Count && _rpI < _profilePickerItemNames.Count; _rpI++)
					{
						string _rpn = _profilePickerItemNames[_rpI];
						SharpDX.RectangleF _rpR = _profilePickerItemRects[_rpI];
						if (_rpn == "---")
						{
							// First pass stored the actual 1px separator rect in _rpR.
							if (_rpR.Width > 0 && _rpR.Height > 0)
								FillRectBoth(chartControl, chartScale, _rpR, ChartTextBrushDX40 ?? ChartTextBrushDX);
							continue;
						}
						if (_rpR.Width <= 0) continue;
						bool _rpHov = MouseIn(_rpR, 0, 0);
						bool _rpIsAction = (_rpn == "Save New Profile" || _rpn == "Update Current Profile" || _rpn == "Properties" || _rpn == "Reset Hidden Accounts" || _rpn == "Reset Account Selections");
						bool _rpIsActive = (!_rpIsAction && _rpn == _activeProfileName && !_profileDirty);
						SharpDX.Direct2D1.Brush _rpBrush = (_rpHov || _rpIsActive)
							? ChartTextBrushDX
							: (ChartTextBrushDX40 ?? ChartTextBrushDX);

						// Re-draw delete X for saved profiles
						if (!_rpIsAction && _rpI < _profilePickerDeleteRects.Count
							&& _profilePickerDeleteRects[_rpI].Width > 0)
