							SharpDX.RectangleF _rpDelR = _profilePickerDeleteRects[_rpI];
							bool _rpDelHov = MouseIn(_rpDelR, 0, 0);
							DrawTextBoth(chartControl, chartScale, "\u2715",
								MainTextCenter ?? CellFormat, _rpDelR,
								_rpDelHov ? ChartTextBrushDX : (ChartTextBrushDX40 ?? ChartTextBrushDX));
						}

						DrawTextBoth(chartControl, chartScale, _rpn, MainTextLeft ?? CellFormat, _rpR, _rpBrush);

						// Timestamp render disabled — see matching comment on the
						// first-pass render site near line 29084.
						// string _rpTs;
						// if (!_rpIsAction && _rpTimestamps.TryGetValue(_rpn, out _rpTs))
						// {
						// 	float _rpTsX = _rpR.X + _rpR.Width + _rpCharW;
						// 	SharpDX.RectangleF _rpTsR = new SharpDX.RectangleF(
						// 		_rpTsX, _rpR.Y, _rpTs.Length * _rpCharW, _rpR.Height);
						// 	DrawTextBoth(chartControl, chartScale, _rpTs,
						// 		MainTextLeft ?? CellFormat, _rpTsR,
						// 		ChartTextBrushDX40 ?? ChartTextBrushDX);
						// }
					}
				}
				

				
				
				
						AllowRedraw = false;
			 
								
					}
					else
					{
						
						//Print("ThisR 99");
						// draw everything	
						
						//Print("drawingsaved");
						
						foreach(Drawings DD in AllDrawings)
						{
							
							
							       
							if (DD.Name == "FillRectangle")	
								RenderTarget.FillRectangle(DD.Rect, DD.ThisB); // new
	
							else if (DD.Name == "DrawRectangle")	
								RenderTarget.DrawRectangle(DD.Rect, DD.ThisB, DD.Width); // new
							else if (DD.Name == "FillEllipse")	
								RenderTarget.FillEllipse(DD.EE, DD.ThisB); // new
							else if (DD.Name == "DrawEllipse")	
								RenderTarget.DrawEllipse(DD.EE, DD.ThisB);
							else if (DD.Name == "DrawText")
								RenderTarget.DrawText(DD.Text, DD.ThisTextFormat, DD.Rect, DD.ThisB,
									DD.Switch ? SharpDX.Direct2D1.DrawTextOptions.None : SharpDX.Direct2D1.DrawTextOptions.Clip);
							else if (DD.Name == "Aliased")	
								RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.Aliased;
							else if (DD.Name == "PerPrimitive")	
								RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;
											
							
								   
							
						}
								
				
						
					}
				
					
					
					//Print("ThisR 100");
					
					if (!RenderEfficient)
						AllowRedraw = true;
				
				
				
			
			
			FirstLoadAccountData = false;
			
				
				
				

			// Deferred top-row button tooltip — captured during the top-row button
			// render loop, drawn here AFTER the table so it sits on top of everything.
			if (pTooltipsButtons && !string.IsNullOrEmpty(_deferredTopBtnTipText) && _deferredTopBtnTipRect.Width > 0
				&& ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
				&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null && CellFormat != null)
			{
				// Use a TextLayout with 320px max width so long tooltips wrap to
				// multiple lines instead of stretching the tooltip panel offscreen.
				using (var _ttLayout = new TextLayout(Core.Globals.DirectWriteFactory, _deferredTopBtnTipText, CellFormat, 320, 1000))
				{
					float _btW2 = _ttLayout.Metrics.Width + 14;
					float _btH2 = _ttLayout.Metrics.Height + 8;
					float _btX2 = _deferredTopBtnTipRect.X;
					float _btY2 = _deferredTopBtnTipRect.Top - _btH2 - ButtonTooltipGapPx;
					if (_btY2 < 0)
						_btY2 = _deferredTopBtnTipRect.Bottom + ButtonTooltipGapPx;
					// Clamp to the TABLE's right edge so top-button tooltips line
					// up with the table, but NEVER past the visible chart panel.
					float _btRightLimit2 = (_tableMaxX > 0) ? _tableMaxX + 1 : ChartPanel.W;
					if (_btRightLimit2 > ChartPanel.W) _btRightLimit2 = ChartPanel.W;
					float _btLeftLimit2  = (_tableMinX > 0) ? _tableMinX : 0;
					if (_btLeftLimit2 < 0) _btLeftLimit2 = 0;
					if (_btX2 + _btW2 > _btRightLimit2) _btX2 = _btRightLimit2 - _btW2;
					if (_btX2 < _btLeftLimit2) _btX2 = _btLeftLimit2;
					SharpDX.RectangleF _btRect2 = new SharpDX.RectangleF(_btX2, _btY2, _btW2, _btH2);
					SharpDX.RectangleF _btTxtR2 = new SharpDX.RectangleF(_btX2 + 7, _btY2 + 4, _btW2 - 14, _btH2 - 8);
					DrawOverlayGlow(chartControl, chartScale, _btRect2);
					FillRectBoth(chartControl, chartScale, _btRect2, ChartBackgroundBrushDX);
					FillRectBoth(chartControl, chartScale, _btRect2, TableHeaderBackgroundBrushDX);
					DrawRectBoth(chartControl, chartScale, _btRect2, TableHeaderBorderBrushDX, 1);
					DrawTextBoth(chartControl, chartScale, _deferredTopBtnTipText, CellFormat, _btTxtR2, ChartTextBrushDX);
				}
			}

			// Deferred bottom-row button tooltip — same pattern as top-row but placed
			// ABOVE the button (bottom-row buttons sit at the chart floor).
			if (pTooltipsButtons && !string.IsNullOrEmpty(_deferredBotBtnTipText) && _deferredBotBtnTipRect.Width > 0
				&& ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
				&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null && CellFormat != null)
			{
				// Use a TextLayout with 320px max width so long tooltips wrap.
				using (var _bbLayout = new TextLayout(Core.Globals.DirectWriteFactory, _deferredBotBtnTipText, CellFormat, 320, 1000))
				{
					float _bbW = _bbLayout.Metrics.Width + 14;
					float _bbH = _bbLayout.Metrics.Height + 8;
					float _bbX = _deferredBotBtnTipRect.X;
					float _bbY = _deferredBotBtnTipRect.Top - _bbH - ButtonTooltipGapPx;
					if (_bbY < 6)
						_bbY = _deferredBotBtnTipRect.Bottom + ButtonTooltipGapPx;
					// Line the tooltip's right edge up with the rightmost bottom
					// button (e.g. the "?" key) — MINUS a glow-radius inset so
					// the 5-px drop-shadow/halo on the tooltip isn't clipped by
					// the chart edge. Falls back to table edge, then panel.
					float _bbGlowInset = (float)(6.0 * dpiScaleY);
					float _bbRightLimit = (_bottomRowRightEdge > 0) ? _bottomRowRightEdge
										: (_tableMaxX > 0)         ? _tableMaxX + 1
										                           : ChartPanel.W - 6;
					_bbRightLimit -= _bbGlowInset;
					if (_bbRightLimit > ChartPanel.W - _bbGlowInset) _bbRightLimit = ChartPanel.W - _bbGlowInset;
					float _bbLeftLimit  = (_tableMinX > 0) ? _tableMinX : 6;
					if (_bbLeftLimit < 0) _bbLeftLimit = 0;
					if (_bbX + _bbW > _bbRightLimit) _bbX = _bbRightLimit - _bbW;
					if (_bbX < _bbLeftLimit) _bbX = _bbLeftLimit;
					SharpDX.RectangleF _bbRect = new SharpDX.RectangleF(_bbX, _bbY, _bbW, _bbH);
					SharpDX.RectangleF _bbTxtR = new SharpDX.RectangleF(_bbX + 7, _bbY + 4, _bbW - 14, _bbH - 8);
					DrawOverlayGlow(chartControl, chartScale, _bbRect);
					FillRectBoth(chartControl, chartScale, _bbRect, ChartBackgroundBrushDX);
					FillRectBoth(chartControl, chartScale, _bbRect, TableHeaderBackgroundBrushDX);
					DrawRectBoth(chartControl, chartScale, _bbRect, TableHeaderBorderBrushDX, 1);
					DrawTextBoth(chartControl, chartScale, _deferredBotBtnTipText, CellFormat, _bbTxtR, ChartTextBrushDX);
				}
			}

			// Cell-level hover tooltip — captured during cell render in specific
			// columns (X, Size, Type, Mode, Fade, Auto Exit/Close, Daily Goal/Loss).
			// Positioned just below the hovered cell, right-aligned to it.
			// Suppressed ONLY when the current tooltip's rect overlaps the
			// clicked cell's rect (_cellTipSuppressRect), so tooltips don't
			// flash back onto the clicked cell (e.g. Type column cycling).
			// The size-scroll suppression is handled at the per-cell set-site
			// for the Size column and its row-mates, not here.
			bool _cellTipSuppressed = false;
			if (_cellTipSuppressRect.Width > 0 && _cellTipRect.Width > 0)
			{
				bool _overlap = _cellTipRect.Right > _cellTipSuppressRect.X
							 && _cellTipRect.X < _cellTipSuppressRect.Right
							 && _cellTipRect.Bottom > _cellTipSuppressRect.Y
							 && _cellTipRect.Y < _cellTipSuppressRect.Bottom;
				if (_overlap) _cellTipSuppressed = true;
			}
			// Suppress tooltips while an active drag is in progress (column-header
			// reorder, total-row reorder) — the drag already has its own visual
			// affordances (source tint + insertion marker) and the tooltip would
			// follow the cursor and clutter the screen.
			bool _dragInProgress = (_columnDragArmed && _columnDragActivated)
				|| (_draggingTotalRowPrefix != null && _totalRowDragActivated);
			// Suppress all cell tooltips when any scroll-to-adjust cell is active
			// (Size / Mode / Daily Goal / Daily Loss) — the scroll-active highlight
			// is the relevant affordance; the tooltip would just get in the way.
			bool _scrollActive = !string.IsNullOrEmpty(SelectedMultiplierAccount)
				|| !string.IsNullOrEmpty(SelectedATMAccount)
				|| !string.IsNullOrEmpty(SelectedDailyGoalAccount)
				|| !string.IsNullOrEmpty(SelectedDailyLossAccount);
			if (pTooltipsCells && !_cheatSheetOpen && !_colPickerOpen && !_profilePickerOpen && !_instPickerOpen && !_cellTipSuppressed && !_dragInProgress && !_scrollActive && !string.IsNullOrEmpty(_cellTipText) && _cellTipRect.Width > 0
				&& ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
				&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null && CellTipFormat != null)
			{
				// All layout constants DPI-scaled so tooltips keep proportional
				// padding and gaps at 125 / 150 / 200% Windows scaling.
				float _tipPadX      = (float)(7.0 * dpiScaleY);       // horizontal text inset
				float _tipPadY      = (float)(4.0 * dpiScaleY);       // vertical text inset
				float _tipGap       = (float)(ButtonTooltipGapPx * dpiScaleY);
				float _tipEdgePad   = (float)(6.0 * dpiScaleY);
				float _tipMinW      = (float)(180.0 * dpiScaleY);
				float _tipMaxCap    = (float)(360.0 * dpiScaleY);

				// Cap tooltip width to ~60% of chart panel (min 180dip, max 360dip)
				// and force word-wrapping so long descriptions flow to multiple
				// lines instead of overflowing a single row off-panel. Use
				// CellTipFormat (wrap-enabled) — CellFormat has NoWrap and
				// DrawText ignores the layout's wrap setting, so passing the
				// wrong format spills text off the right edge of the box.
				float _tipMaxW = ChartPanel.W * 0.6f;
				if (_tipMaxW < _tipMinW)   _tipMaxW = _tipMinW;
				if (_tipMaxW > _tipMaxCap) _tipMaxW = _tipMaxCap;
				using (var _ctLayout = new TextLayout(Core.Globals.DirectWriteFactory, _cellTipText, CellTipFormat, _tipMaxW, 1000))
				{
					float _ctW = _ctLayout.Metrics.Width  + _tipPadX * 2;
					float _ctH = _ctLayout.Metrics.Height + _tipPadY * 2;
					float _ctX = _cellTipRect.X;
					float _ctY = _cellTipRect.Bottom + _tipGap;
					if (_ctY + _ctH > ChartPanel.H - _tipEdgePad)
						_ctY = _cellTipRect.Top - _ctH - _tipGap;
					// Clamp to the TABLE's right edge (_tableMaxX + 1, matching the
					// outer border at line ~25839) so tooltips line up with the
					// table — but NEVER past the visible chart panel edge, and
					// leave a 6-px glow inset (DPI-scaled, matches DrawOverlayGlow's
					// 5-px halo) so the tooltip's drop-shadow isn't clipped.
					float _ctGlowInset = (float)(6.0 * dpiScaleY);
					float _ctRightLimit = (_tableMaxX > 0) ? _tableMaxX + 1 : ChartPanel.W - _tipEdgePad;
					_ctRightLimit -= _ctGlowInset;
					if (_ctRightLimit > ChartPanel.W - _ctGlowInset) _ctRightLimit = ChartPanel.W - _ctGlowInset;
					float _ctLeftLimit  = (_tableMinX > 0) ? _tableMinX : _tipEdgePad;
					if (_ctLeftLimit < 0) _ctLeftLimit = 0;
					if (_ctX + _ctW > _ctRightLimit) _ctX = _ctRightLimit - _ctW;
					if (_ctX < _ctLeftLimit) _ctX = _ctLeftLimit;
					SharpDX.RectangleF _ctR = new SharpDX.RectangleF(_ctX, _ctY, _ctW, _ctH);
					SharpDX.RectangleF _ctTxtR = new SharpDX.RectangleF(_ctX + _tipPadX, _ctY + _tipPadY, _ctW - _tipPadX * 2, _ctH - _tipPadY * 2);
					DrawOverlayGlow(chartControl, chartScale, _ctR);
					FillRectBoth(chartControl, chartScale, _ctR, ChartBackgroundBrushDX);
					FillRectBoth(chartControl, chartScale, _ctR, TableHeaderBackgroundBrushDX);
					DrawRectBoth(chartControl, chartScale, _ctR, TableHeaderBorderBrushDX, 1);
					DrawTextBoth(chartControl, chartScale, _cellTipText, CellTipFormat, _ctTxtR, ChartTextBrushDX);
				}
			}

			// Deferred instrument picker overlay — styled to match profile/column pickers.
			// Positioned above the instrument mode button, left-aligned.
			// Clicks apply immediately (no OK/Cancel).
			if (_instPickerOpen && ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
				&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null && CellFormat != null)
			{
				_instPickerItemRects.Clear();
				_instPickerItemNames.Clear();

				float _ipRowH = (float)Math.Round(18f * dpiScaleY, 0);
				float _ipPadL = (float)Math.Round(8f * dpiScaleY, 0);
				float _ipPadR = (float)Math.Round(10f * dpiScaleY, 0);
				float _ipCbSz = (float)Math.Round(11f * dpiScaleY, 0);
				float _ipCbGap = (float)Math.Round(5f * dpiScaleY, 0);
				float _ipCharW = (float)Math.Round(7f * dpiScaleY, 0);

				List<string> _ipItems = new List<string>();
				List<string> _ipItemKeys = new List<string>();
				for (int _fi = 0; _fi < CommonFutures.Length; _fi++)
				{
					string _miniSym = CommonFutures[_fi];
					string _microSym = GetMicroSymbol(_miniSym);
					string _display = (_miniSym != _microSym) ? _miniSym + " / " + _microSym : _miniSym;
					_ipItems.Add(_display);
					_ipItemKeys.Add(_miniSym); // backing key for selection
				}

				// Width from longest item name + checkbox
				float _ipMaxNameW = 0;
				for (int _mi = 0; _mi < _ipItems.Count; _mi++)
				{
					float _nw = _ipItems[_mi].Length * _ipCharW;
					if (_nw > _ipMaxNameW) _ipMaxNameW = _nw;
				}
				float _ipW = _ipPadL + _ipCbSz + _ipCbGap + _ipMaxNameW + _ipPadR;
				if (_ipW < 160) _ipW = 160;
				float _ipH = _ipRowH * _ipItems.Count + 6f;

				// Position above the instrument mode button, left-aligned
				float _ipX = _instModeButtonRect.Left;
				float _ipY = _instModeButtonRect.Top - _ipH - ButtonTooltipGapPx;
				if (_ipX + _ipW > ChartPanel.W) _ipX = ChartPanel.W - _ipW - 2;
				if (_ipX < 0) _ipX = 2;
				if (_ipY < 0) _ipY = _instModeButtonRect.Bottom + ButtonTooltipGapPx;

				_instPickerBgRect = new SharpDX.RectangleF(_ipX, _ipY, _ipW, _ipH);
				// Glow + background + border — direct render for correct z-order
				DrawOverlayGlowDirect(_instPickerBgRect);
				RenderTarget.FillRectangle(_instPickerBgRect, ChartBackgroundBrushDX);
				RenderTarget.FillRectangle(_instPickerBgRect, TableHeaderBackgroundBrushDX);
				RenderTarget.DrawRectangle(_instPickerBgRect, TableHeaderBorderBrushDX, 1);

				for (int _ii = 0; _ii < _ipItems.Count; _ii++)
				{
					string _ipn = _ipItems[_ii];
					string _ipKey = _ipItemKeys[_ii];
					float _iy = _ipY + 3 + _ii * _ipRowH;
					SharpDX.RectangleF _itemR = new SharpDX.RectangleF(_ipX + 2, _iy, _ipW - 4, _ipRowH);
					_instPickerItemRects.Add(_itemR);
					_instPickerItemNames.Add(_ipKey);

					// Hover highlight
					bool _ipHov = MouseIn(_itemR, 0, 0);
					if (_ipHov && DragTintBrushDX != null)
						RenderTarget.FillRectangle(_itemR, DragTintBrushDX);

					// Checkbox
					float _icbX = _ipX + _ipPadL;
					float _icbY = _iy + (_ipRowH - _ipCbSz) * 0.5f;
					SharpDX.RectangleF _icbR = new SharpDX.RectangleF(_icbX, _icbY, _ipCbSz, _ipCbSz);
					RenderTarget.DrawRectangle(_icbR, ChartTextBrushDX40 ?? ChartTextBrushDX, 1);
					bool _isSel = _instPickerPendingSet.Contains(_ipKey);
					if (_isSel)
					{
						SharpDX.RectangleF _icbInner = new SharpDX.RectangleF(_icbR.X + 2, _icbR.Y + 2, _icbR.Width - 4, _icbR.Height - 4);
						RenderTarget.FillRectangle(_icbInner, ChartTextBrushDX);
					}

					// Label
					SharpDX.RectangleF _itxtR = new SharpDX.RectangleF(
						_icbX + _ipCbSz + _ipCbGap, _iy, _ipW - (_ipPadL + _ipCbSz + _ipCbGap + _ipPadR), _ipRowH);
					RenderTarget.DrawText(_ipn, MainTextLeft ?? CellFormat, _itxtR, ChartTextBrushDX);
				}
			}

			// Only one button tooltip at a time — instrument mode vs other buttons.
			if (_instModeTooltipReady)
				_deferredTopBtnTipText = null;
			if (!string.IsNullOrEmpty(_deferredTopBtnTipText))
				_instModeTooltipReady = false;

			// Deferred instrument mode tooltip — drawn last so it's on top of everything.
			// Gated on pTooltipsButtons like the other button tooltips; the
			// "Main Button Tooltips" checkbox must disable this too.
			if (pTooltipsButtons && _instModeTooltipReady && _instModeButtonRect.Width > 0
				&& ChartBackgroundBrushDX != null && TableHeaderBackgroundBrushDX != null
				&& TableHeaderBorderBrushDX != null && ChartTextBrushDX != null && CellFormat != null)
			{
				string tipText2 = GetInstrumentModeTooltip();
				if (_instModeTooltipLayout == null || _instModeTooltipText != tipText2)
				{
					if (_instModeTooltipLayout != null) _instModeTooltipLayout.Dispose();
					_instModeTooltipLayout = new TextLayout(Core.Globals.DirectWriteFactory, tipText2, CellFormat, 320, 1000);
					_instModeTooltipText = tipText2;
				}
				float tipW2 = _instModeTooltipLayout.Metrics.Width + 14;
				float tipH2 = _instModeTooltipLayout.Metrics.Height + 8;
				float tipX2 = _instModeButtonRect.Left;
				float tipY2 = _instModeButtonRect.Top - tipH2 - ButtonTooltipGapPx;
				if (tipX2 + tipW2 > ChartPanel.W) tipX2 = ChartPanel.W - tipW2;
				if (tipX2 < 0) tipX2 = 0;
				if (tipY2 < 0) tipY2 = _instModeButtonRect.Bottom + ButtonTooltipGapPx;
				SharpDX.RectangleF tipRect2 = new SharpDX.RectangleF(tipX2, tipY2, tipW2, tipH2);
				SharpDX.RectangleF tipTextRect2 = new SharpDX.RectangleF(tipX2 + 7, tipY2 + 4, tipW2 - 14, tipH2 - 8);
				// Draw directly to RenderTarget (not *Both) so it's always on top
				// and doesn't leak into the AllDrawings replay cache.
				DrawOverlayGlowDirect(tipRect2);
				RenderTarget.FillRectangle(tipRect2, ChartBackgroundBrushDX);
				RenderTarget.FillRectangle(tipRect2, TableHeaderBackgroundBrushDX);
				RenderTarget.DrawRectangle(tipRect2, TableHeaderBorderBrushDX, 1);
				RenderTarget.DrawText(tipText2, CellFormat, tipTextRect2, ChartTextBrushDX);
			}

			// seems to blow up the code

			if (CellLayout != null)
				CellLayout.Dispose();
		
			
			
			
			if (lastrightside == 0)
				InvalidateVis(21);
			
			
						
						
	
	
				
	
//			bitmapRenderTarget.EndDraw();

//        cachedBitmap?.Dispose();
//       	cachedBitmap = bitmapRenderTarget.Bitmap;


			} // end outer try
			catch (Exception _orex)
			{
				// NRE during chart reload / data-feed reconnect. Don't rethrow —
				// NT's handler would freeze the chart and surface a banner.
				// The next frame almost always succeeds. Log once-per-session
				// per distinct message for debugging without log spam.
				try
				{
					if (_diagLog != null && _orex != null)
					{
						string _key = _orex.GetType().Name + ":" + (_orex.Message ?? "");
						if (_onRenderLoggedErrors == null)
							_onRenderLoggedErrors = new HashSet<string>();
						if (_onRenderLoggedErrors.Add(_key))
							_diagLog.Log("RENDER", "ONRENDER_ERR", "Type=" + _orex.GetType().Name + "|Msg=" + (_orex.Message ?? ""));
					}
				}
				catch { }
			}
		}

		// Dedup set for OnRender exception logging — one diag entry per distinct
		// exception per session so repeated reload NREs don't flood the log.
		private HashSet<string> _onRenderLoggedErrors;

		
