		// Cached connected account lookup — rebuilt when cache is invalidated
		private Dictionary<string, Account> _connectedAccountCache = new Dictionary<string, Account>();
		private DateTime _accountCacheExpiry = DateTime.MinValue;

		private Account AccountFromName(string name)
		{
			// Rebuild cache every 2 seconds or when empty
			DateTime now = DateTime.Now;
			if (now > _accountCacheExpiry || _connectedAccountCache.Count == 0)
			{
				_connectedAccountCache.Clear();
				foreach (Account acct in Account.All.ToList())
				{
					if (acct.ConnectionStatus == ConnectionStatus.Connected)
						_connectedAccountCache[acct.Name] = acct;
				}
				_accountCacheExpiry = now.AddSeconds(2);
			}

			Account result;
			_connectedAccountCache.TryGetValue(name, out result);
			return result;
		}
		
		
		// Cached account data lookup — avoids scanning 300-element array + Split per call
		private Dictionary<string, string[]> _accountDataCache = new Dictionary<string, string[]>();
		private DateTime _accountDataCacheExpiry = DateTime.MinValue;

		// Text width measurement cache — keyed by text string, reset per-frame.
		// Eliminates ~750 TextLayout allocations per frame in the column width loop
		// where the same text strings appear many times (account names, "AA", "A", etc.)
		private Dictionary<string, int> _columnWidthMeasureCache = new Dictionary<string, int>();

		// Button text measurement cache — keyed by button label, cleared per-frame.
		// Eliminates ~50-100 TextLayout allocations per frame in the button layout
		// loop where the same labels (Copy, Risk, Flatten, APEX) are measured
		// repeatedly. Uses SharpDX.Size2F (struct, no alloc).
		private Dictionary<string, SharpDX.Size2F> _buttonMeasureCache = new Dictionary<string, SharpDX.Size2F>(32);

		// Reusable scratch collections for column-order rebuild — avoids 6 List/HashSet
		// allocations per frame in the column-display-order logic.
		private HashSet<int> _colOrderUsed = new HashSet<int>();
		private List<int> _colOrderByNames = new List<int>();
		private List<int> _colOrderEarly = new List<int>();
		private List<int> _colOrderRest = new List<int>();
		private List<int> _colOrderFinal = new List<int>();
		private List<int> _colOrderValid = new List<int>();

		private SharpDX.Size2F MeasureButtonText(string text, SharpDX.DirectWrite.TextFormat fmt)
		{
			SharpDX.Size2F sz;
			if (_buttonMeasureCache.TryGetValue(text, out sz)) return sz;
			using (var tl = new TextLayout(Core.Globals.DirectWriteFactory, text, fmt, 10000, 10000))
			{
				sz = new SharpDX.Size2F(tl.Metrics.Width, tl.Metrics.Height);
			}
			_buttonMeasureCache[text] = sz;
			return sz;
		}

		private string[] GetAccountDataCached(string name)
		{
			DateTime now = DateTime.Now;
			if (now > _accountDataCacheExpiry || _accountDataCache.Count == 0)
			{
				_accountDataCache.Clear();
				foreach (string s in pAllAccountData)
				{
					if (s != string.Empty)
					{
						string[] parts = s.Split('|');
						if (parts.Length > 0 && parts[0] != string.Empty)
							_accountDataCache[parts[0]] = parts;
					}
				}
				_accountDataCacheExpiry = now.AddSeconds(1);
			}

			string[] result;
			_accountDataCache.TryGetValue(name, out result);
			return result;
		}

		private string _lastMasterAccountChangeSig = null;
		private void UpdateMasterAccount(string inputaccount)
		{
			if (_diagLog != null)
			{
				string prev = (PreviousMasterAccount != null) ? PreviousMasterAccount.Name : "none";
				// Skip logging when nothing changed — this fires on every UI/account-list redraw and
				// produces "NewMaster=|PreviousMaster=none" or "NewMaster=X|PreviousMaster=X" spam
				// that drowns the actually-meaningful changes.
				bool _isNoOp = (string.IsNullOrEmpty(inputaccount) && prev == "none")
					|| (inputaccount == prev);
				string _sig = "NewMaster=" + inputaccount + "|PreviousMaster=" + prev;
				if (!_isNoOp && _sig != _lastMasterAccountChangeSig)
				{
					_lastMasterAccountChangeSig = _sig;
					_diagLog.Log("CONFIG", "MASTER_ACCOUNT_CHANGE", _sig);
				}
			}

			if (inputaccount == string.Empty)
			{
				//CurrentMasterAccount = null;
				return;

			}
			
			Account aaaa = null;
			
				
		
				foreach (Account acct in Account.All.ToList())
				{
					
					string accccnnnn = acct.Name;
					
					if (AllHideAccounts.Contains(accccnnnn))
						continue;

					if (accccnnnn == "Backtest")
						continue;
					

					
					if (acct.Name == inputaccount)
					if (acct.ConnectionStatus == ConnectionStatus.Connected) // added to avoid connected error
					{
						
					
						
//						Print(inputaccount + "  " + acct.Name);
						
//						double addaa =  acct.Get(AccountItem.CashValue, Currency.UsDollar);
						
//						Print(addaa);
						
						aaaa = acct;
						
					
						
					}
					
					
					
				}
               				
				if (aaaa != null)
				{
					
					
					//Print("adding events");
					
					
//					Print("aaaa.MaxOrderSize " + aaaa.MaxOrderSize);
//					Print("aaaa.MaxPositionSize " + aaaa.MaxPositionSize);
			
					
					
					
					CurrentMasterAccount = aaaa;

					if (PreviousMasterAccount != null)
					{
						PreviousMasterAccount.AccountItemUpdate -= OnAccountItemUpdate3;
						PreviousMasterAccount.ExecutionUpdate -= OnExecutionUpdate3;
						PreviousMasterAccount.OrderUpdate -= OnOrderUpdate3;
						PreviousMasterAccount.PositionUpdate -= OnPositionUpdate3;
					}

								
					
					// Subscribe to new account subscriptions
					//aaaa.AccountStatusUpdate -= OnAccountStatusUpdate3;				
					CurrentMasterAccount.AccountItemUpdate   += OnAccountItemUpdate3;
					CurrentMasterAccount.ExecutionUpdate     += OnExecutionUpdate3;
					CurrentMasterAccount.OrderUpdate         += OnOrderUpdate3;
					CurrentMasterAccount.PositionUpdate      += OnPositionUpdate3;
					
					PreviousMasterAccount = CurrentMasterAccount;
					// Subscribe follower PositionUpdate so we cancel orphan target/stop when follower goes flat (e.g. Buy Mkt, Sell Mkt)
					foreach (Account fa in FollowerAccountsWithPositionUpdateSubscribed)
					{
						try { fa.PositionUpdate -= OnPositionUpdate3; } catch { }
					try { fa.OrderUpdate -= OnFollowerLatencyOrderUpdate; } catch { }
					}
					FollowerAccountsWithPositionUpdateSubscribed.Clear();
					foreach (string acctName in AllDuplicateAccounts)
					{
						Account facct = AccountFromName(acctName);
						if (facct != null && facct != CurrentMasterAccount && !FollowerAccountsWithPositionUpdateSubscribed.Contains(facct))
						{
							facct.PositionUpdate += OnPositionUpdate3;
							facct.OrderUpdate += OnFollowerLatencyOrderUpdate;
							FollowerAccountsWithPositionUpdateSubscribed.Add(facct);
						}
					}
					
				}
				else
				{
					
					CurrentMasterAccount = null;
					if (PreviousMasterAccount != null)
					{
						PreviousMasterAccount.AccountItemUpdate -= OnAccountItemUpdate3;
						PreviousMasterAccount.ExecutionUpdate -= OnExecutionUpdate3;
						PreviousMasterAccount.OrderUpdate -= OnOrderUpdate3;
						PreviousMasterAccount.PositionUpdate -= OnPositionUpdate3;
						
					}
					foreach (Account fa in FollowerAccountsWithPositionUpdateSubscribed)
					{
						try { fa.PositionUpdate -= OnPositionUpdate3; } catch { }
					try { fa.OrderUpdate -= OnFollowerLatencyOrderUpdate; } catch { }
					}
					FollowerAccountsWithPositionUpdateSubscribed.Clear();
					
				}

		
			
			
		}
		
		
