		private Dictionary<Instrument, DateTime> MasterFlatInstTime = new Dictionary<Instrument, DateTime>();
		
		
		
		
		private void CheckRithmicAccounts(Instrument iii)
		{
		if (_diagLog != null)
				_diagLog.Log("RITHMIC", "CHECK_ACCOUNTS", "Instrument=" + (iii != null ? iii.FullName : "?") + "|AccountCount=" + AllRithmicAccountsCheck.Count);
			//Print("CheckRithmicAccounts");

			
			
			
			foreach (Account acct in AllRithmicAccountsCheck.ToList())
			{
				
			
				
				 bool hasposition = !IsAccountFlatI(acct, iii);
				
				//Print("checking " + acct.Name);
				
				if (hasposition)
				{
					if (PrintRithmic) Print(acct.Name + " has lingering fake position");
				if (_diagLog != null)
						_diagLog.Log("RITHMIC", "LINGERING_POSITION", "Account=" + acct.Name + "|Instrument=" + (iii != null ? iii.FullName : "?"));
					// store list of instrument, then list of accounts and time
				
					AccountsAndDetails Z = new AccountsAndDetails();
						
					Z.StartTime = DateTime.Now;
					Z.AllAccounts = new List<Account>();
					Z.AllAccounts.Add(acct);
					
					
					
					
					if (RithmicAccountsAndDetails.ContainsKey(iii))
					{
						RithmicAccountsAndDetails[iii].AllAccounts.Add(acct);
						
					}
					else
					{
					
						RithmicAccountsAndDetails.Add(iii, Z);
						
					}
					
					
					// update Flatten all color
					//if (RithmicAccountsAndDetails.Count > 0)
					InvalidateVis(45);
					
					
					
					
				}
				
				
				//RefreshPositionsClickedOrders = 0;
				//AllInstrumentsWithPositions.Clear();
	
				
				
			}
			
			
		}
		
		
		private void OnPositionUpdate3 (object sender, PositionEventArgs e)
	    {
			// Skip historical replays — chart reload fires these for every
			// position event of the day, which the indicator doesn't act on.
			if (_diagLog != null && State == State.Realtime)
			{
				try
				{
					var p = e.Position;
					// Dedupe — PositionUpdate fires on every price tick even when
					// qty/direction haven't changed. Only log actual state changes.
					string key = p.Account.Name + "|" + (p.Instrument != null ? p.Instrument.FullName : "?");
					string state = p.MarketPosition + "|" + p.Quantity;
					string lastState;
					if (!_diagLastPositionState.TryGetValue(key, out lastState) || lastState != state)
					{
						_diagLastPositionState[key] = state;
						string isMaster = (CurrentMasterAccount != null && p.Account == CurrentMasterAccount) ? "Master" : "Follower";
						_diagLog.Log("POSITION", "UPDATE",
							"Role=" + isMaster
							+ "|Account=" + p.Account.Name
							+ "|Instrument=" + (p.Instrument != null ? p.Instrument.FullName : "?")
							+ "|MarketPos=" + p.MarketPosition
							+ "|Qty=" + p.Quantity
							+ "|AvgPrice=" + p.AveragePrice);
					}
				}
				catch { }
			}

			// Reconcile the master-position tally against NinjaTrader's own
			// authoritative PositionUpdate. The execution-fed accumulator in
			// ProcessMasterExecution can drift (a missed/double-counted fill, or a
			// connection whose GetPosition() reports the post-fill qty in the seed
			// path); a stale tally then sizes the next trade's follower orders and
			// can flip their direction (Jason Vicente 2026-05-21: tracker said +3
			// while the master was -1, followers bought 3 on a short). Running here
			// heals any drift within a tick of the master settling, instead of
			// waiting up to 5s for the OnTimerTick3 idle resync. Realtime only — a
			// chart reload replays historical position events.
			if (State == State.Realtime
				&& CurrentMasterAccount != null
				&& e.Position != null
				&& e.Position.Account == CurrentMasterAccount)
			{
				ReconcileTrackedMasterFromPositionUpdate(e.Position);
			}

			// Auto-clear-on-observed-flat is intentionally NOT wired up here.
			// The ClearGoalLossLatch helper exists and is logged; it can be called
			// from a future entry point (manual unlatch button, end-of-day reset)
			// without needing to re-introduce the auto-clear behavior. Reverted
			// 2026-05-04 because automatic clearing weakens the "stay benched
			// after goal/loss" safety mechanism in subtle ways that need more
			// validation than a 10-day-absence pre-flight allows.

			if (pRithmicEnabled)
			if (AllRithmicAccounts.Count > 0)
			if (IsAccountFlatI(CurrentMasterAccount, e.Position.Instrument))
			{
			
				Instrument NewFlat = e.Position.Instrument;
				
				if (!MasterFlatInstTime.ContainsKey(NewFlat))
					MasterFlatInstTime.Add(NewFlat, DateTime.Now);

				if (PrintRithmic) Print("new instrument flat " + NewFlat);
			if (_diagLog != null)
					_diagLog.Log("RITHMIC", "MASTER_FLAT_DETECTED", "Instrument=" + (NewFlat != null ? NewFlat.FullName : "?"));
				
				
				
				
				
			}
			
			
			if (IsAccountFlatI(CurrentMasterAccount, e.Position.Instrument))
			{
				Instrument flatInstrument = e.Position.Instrument;
				// After a scale-in sequence closes on master, flatten any follower still holding
				// position and cancel any follower ATM brackets still resting (covers the case where
				// a target never filled and the follower looks flat but has an orphan order parked).
				// Manual trades without an ATM owner are not touched: CancelOrphanATMExitOrdersForInstrument
				// filters to AtmStrategy-owned orders and FlattenInstrument is instrument-scoped.
				if (OnMasterFlatAfterScalingCloseFollowers && pCopierMode == "Orders" && InstrumentsWithScalingInEffect.Contains(flatInstrument))
				{
					InstrumentsWithScalingInEffect.Remove(flatInstrument);
					if (_diagLog != null)
						_diagLog.Log("SCALE_IN_TRACKING", "REMOVE",
							"Instrument=" + (flatInstrument != null ? flatInstrument.FullName : "?")
							+ "|Reason=MasterFlat");
					foreach (string acctName in AllDuplicateAccounts)
					{
						try
						{
							Account follower = AccountFromName(acctName);
							if (follower == null || follower == CurrentMasterAccount) continue;

							Position fp = follower.GetPosition(flatInstrument.Id);
							bool followerHasPosition = fp != null
								&& fp.MarketPosition != MarketPosition.Flat
								&& fp.Quantity > 0;

							// Account for in-flight closing market/stop-market orders the
							// order-copier just submitted. Without this, FlattenInstrument
							// stacks on top of the pending Sell and reverses the position.
							int netPendingClose       = 0;
							int signedPos             = 0;
							int pendingCloseSigned    = 0;
							int recentCloseSigned     = 0;
							int ordersExamined        = 0;
							string recentFillIds      = "";
							if (followerHasPosition)
							{
								signedPos = fp.MarketPosition == MarketPosition.Long ? fp.Quantity : -fp.Quantity;
								DateTime _now = DateTime.Now;
								foreach (Order o in follower.Orders)
								{
									if (o.Instrument == null || flatInstrument == null || o.Instrument.Id != flatInstrument.Id) continue;
									if (o.OrderType != OrderType.Market && o.OrderType != OrderType.StopMarket) continue;
									ordersExamined++;

									bool isPending = o.OrderState == OrderState.Submitted
												  || o.OrderState == OrderState.Accepted
												  || o.OrderState == OrderState.Working
												  || o.OrderState == OrderState.PartFilled;

									int qty = 0;
									bool countedAsRecent = false;
									if (isPending)
									{
										qty = o.Quantity - o.Filled;
									}
									else if (o.OrderState == OrderState.Filled
											 && o.Time != DateTime.MinValue
											 && (_now - o.Time).TotalMilliseconds < 750)
									{
										// Race guard: NT can clear a recently-filled close out of follower.Orders'
										// Working/Accepted/Submitted/PartFilled buckets before its matching position
										// update propagates. Without this, the snapshot shows signedPos > 0 with
										// netPendingClose == 0 and we double-flatten, leaving the follower with an
										// inverted position (e.g. Long 10 -> Short 10). Only credit closing-direction
										// fills so a close-then-reopen cycle within the window doesn't false-skip.
										bool isClosingDir = (signedPos > 0)
											? (o.OrderAction == OrderAction.Sell || o.OrderAction == OrderAction.SellShort)
											: (o.OrderAction == OrderAction.Buy  || o.OrderAction == OrderAction.BuyToCover);
										if (isClosingDir)
										{
											qty = o.Filled;
											countedAsRecent = true;
											double ageMs = (_now - o.Time).TotalMilliseconds;
											string idTag = (o.OrderId != null ? o.OrderId : (o.Name != null ? o.Name : "?"))
												+ ":" + qty + "@" + ageMs.ToString("F0") + "ms";
											recentFillIds = (recentFillIds.Length == 0 ? idTag : recentFillIds + "," + idTag);
										}
									}

									if (qty <= 0) continue;
									int signedQty = (o.OrderAction == OrderAction.Sell || o.OrderAction == OrderAction.SellShort)
										? -qty : qty;
									netPendingClose += signedQty;
									if (countedAsRecent) recentCloseSigned  += signedQty;
									else                 pendingCloseSigned += signedQty;
								}
								if (signedPos + netPendingClose == 0)
								{
									if (_diagLog != null)
										_diagLog.Log("ACTION", "SKIP_FLATTEN_INFLIGHT_CLOSE",
											"Account=" + follower.Name
											+ "|Instrument=" + (flatInstrument != null ? flatInstrument.FullName : "?")
											+ "|SignedPos=" + signedPos
											+ "|NetPendingClose=" + netPendingClose
											+ "|PendingCloseSigned=" + pendingCloseSigned
											+ "|RecentCloseSigned=" + recentCloseSigned
											+ "|OrdersExamined=" + ordersExamined
											+ "|RecentFills=" + (recentFillIds.Length > 0 ? recentFillIds : "none"));
									followerHasPosition = false;
								}
							}

							if (followerHasPosition)
							{
								// Capture the full decision snapshot BEFORE issuing flatten so a
								// post-mortem can reconstruct what the indicator saw at decision
								// time. The generic FLATTEN_INSTRUMENT log inside FlattenInstrument()
								// loses this context. If a follower ever ends up reversed instead of
								// flat, this is the line to grep for — pair it with the surrounding
								// POSITION/ORDER lines for the same account to reconstruct the race.
								if (_diagLog != null)
									_diagLog.Log("ACTION", "FLATTEN_DECIDE",
										"Account=" + follower.Name
										+ "|Instrument=" + (flatInstrument != null ? flatInstrument.FullName : "?")
										+ "|SignedPos=" + signedPos
										+ "|NetPendingClose=" + netPendingClose
										+ "|PendingCloseSigned=" + pendingCloseSigned
										+ "|RecentCloseSigned=" + recentCloseSigned
										+ "|OrdersExamined=" + ordersExamined
										+ "|RecentFills=" + (recentFillIds.Length > 0 ? recentFillIds : "none"));
								FlattenInstrument(follower, flatInstrument);
							}

							// Always call - helper no-ops when the follower has no orphan ATM exits.
							CancelOrphanATMExitOrdersForInstrument(follower, flatInstrument);

							if (pDebugOrderMatching)
								Print("[DAA OrdersMode] Master flat for "
									+ (flatInstrument.MasterInstrument != null ? flatInstrument.MasterInstrument.Name : flatInstrument.FullName)
									+ "; follower '" + follower.Name
									+ "' position=" + (fp != null && fp.MarketPosition != MarketPosition.Flat ? fp.Quantity.ToString() : "0")
									+ " netPendingClose=" + netPendingClose);
						}
						catch (Exception cleanupEx)
						{
							// Print("[DAA OrdersMode] Master-flat cleanup exception for '" + acctName + "': " + cleanupEx.Message);
						}
					}
					AddOnATMAdjustExitOrders.Clear(); // only fires when scaling cleanup actually ran (previously unconditional)
				}
				
				// When master goes flat for this instrument (e.g. Buy Mkt then Sell Mkt), cancel any lingering ATM target/stop on all followers for that instrument
//				foreach (string acctName in AllDuplicateAccounts)
//				{
//					Account follower = AccountFromName(acctName);
//					if (follower != null && follower != CurrentMasterAccount)
//						CancelOrphanATMExitOrdersForInstrument(follower, flatInstrument);
//				}
				
				
				
				
			}
			// When a follower goes flat, cancel any lingering ATM target/stop orders on that follower (backup in case follower PositionUpdate fires)
//			if (e.Position.Account != null && AllDuplicateAccounts.Contains(e.Position.Account.Name))
//			if (e.Position.MarketPosition == MarketPosition.Flat)
//				CancelOrphanATMExitOrdersForInstrument(e.Position.Account, e.Position.Instrument);
			
			//Print(e.Quantity);
			
			//Print("OnPositionUpdate3 " + IgnoreExecutionUntilFlat);
			
			// this did not work
			
//			if (e.MarketPosition == MarketPosition.Flat)
//			{
//				IgnoreExecutionUntilFlat = false;
				
				//Print(e.MarketPosition + "  " + IgnoreExecutionUntilFlat);
//			}
			
		}
		
		
		private bool IsAccountFlatI(Account ThisAccount, Instrument iii)
		{
			if (ThisAccount == null)
				return false;
			
		
				if (ThisAccount.GetPosition(iii.Id) == null)
				//if (CurrentMasterAccount.GetPosition(Instrument.Id).MarketPosition == MarketPosition.Flat)
					return true;
			
		
			return false;
		}
		
		
		
		
		
		// Cooldown window after a Flatten All click. During this window:
		//   - additional Flatten All clicks are ignored (with a user-visible message)
		//   - copier SendExecutionModeOrders paths skip execution copies (line ~38147)
		//   - GoalLossFlattenTime uses the same window
		// Bumped from 1000ms → 3000ms: Rithmic position-refresh lag can be several seconds,
		// during which followers look "still holding" even though copier orders are in flight.
		// 1s wasn't long enough to stop panic-clicks from stacking multiple flattens (seen
		// 04-24 customer report where 9 clicks landed inside the lag window).
		private int pMilliSFE = 3000;
		
		
		private string messageoff = "You are placing trades on the Master account, while Duplicate Account Actions is disabled. Click the button in the top left corner of this window, to begin duplicating trades across Follower accounts. It will say 'ON' to indicate that it is ready.";

		// True while a Flatten All / goal-loss flatten is recent enough that a
		// freshly appearing master "Close" order is almost certainly that
		// flatten's product. Generous: it only needs to span the gap from the
		// flatten call to the order's first OrderUpdate (~ms), NOT the fill
		// latency — so a slow or partially-filling close is still captured.
		private bool IsRecentFlatten()
		{
			DateTime _n = DateTime.Now;
			return (FlattenEverythingClickedTime != DateTime.MinValue
						&& _n < FlattenEverythingClickedTime.AddSeconds(10))
				|| (GoalLossFlattenTime != DateTime.MinValue
						&& _n < GoalLossFlattenTime.AddSeconds(10));
		}

		// True if this order is one of the master's flatten-initiated "Close"
		// orders, whose fills must never be copied. See _masterFlattenCloseOrders.
		private bool IsMasterFlattenCloseOrder(Order o)
		{
			if (o == null) return false;
			lock (_masterFlattenCloseOrders) { return _masterFlattenCloseOrders.Contains(o); }
		}

		private void SendExecutionModeOrders (Instrument SendInstrument, MarketPosition SendMarketPosition, Order SendOrder, bool IsNewEntry)
		{
			if (_diagLog != null)
				_diagLog.Log("COPIER", "SEND_EXEC_MODE_ORDERS", "Instrument=" + (SendInstrument != null ? SendInstrument.FullName : "?") + "|Position=" + SendMarketPosition + "|OrderName=" + (SendOrder != null ? SendOrder.Name : "?") + "|IsNewEntry=" + IsNewEntry);

			string SendName = SendOrder.Name;
			
			
			// do not process partially filled orders
					
			if (SendOrder.OrderState == OrderState.PartFilled)
				return;
			
			int SendQuantity = SendOrder.Filled;
			
			
			
			
			
			//Print(SendOrder.Filled);
			
			//Print("OnExecutionUpdate3 " + IgnoreExecutionUntilFlat);
			
			
			//Print("DDDD1");
			
			if (!IsInActiveWorkspace && pDisableInActiveWorkspace)
				return;
			
			if (!pCopierIsEnabled)
			{
					ChartControl.Dispatcher.InvokeAsync((Action)(() =>
					{
						AddMessage(messageoff, 20, Brushes.Goldenrod);
					}));
				return;
			}
			
			if (pThisMasterAccount == string.Empty)
				return;
		
//			if (!pAllInstruments && SendInstrument != Instrument)
//				return;
			
			if (IgnoreExecutionUntilFlat)
			{
				if (_diagLog != null)
					_diagLog.Log("COPIER", "EXECUTION_BLOCKED_IGNORE_FLAG", "Reason=IgnoreExecutionUntilFlat");
				return;
			}

			// Order-scoped flatten suppression: the master's own flatten "Close"
			// order is never a tradeable signal. Unbounded by time, unlike the
			// pMilliSFE window below — a slow or partial close can't outrun it.
			if (IsMasterFlattenCloseOrder(SendOrder))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FlattenCloseOrder", "OrderId=" + (SendOrder != null ? SendOrder.OrderId : "?") + "|Name=" + (SendOrder != null ? SendOrder.Name : "?")); } catch { } }
				return;
			}

			if (DateTime.Now < FlattenEverythingClickedTime.AddMilliseconds(pMilliSFE))
			{
				return;
			}
			if (DateTime.Now < GoalLossFlattenTime.AddMilliseconds(pMilliSFE))
			{
				// Print("GUARD: Blocking execution copy — Goal/Loss/Funded flatten in progress. GoalLossFlattenTime=" + GoalLossFlattenTime);
				return;
			}
			else
			{
				
			}
				
				
				
				
				
			//Print("DDDD2");
			
			//Print(e.Execution.Order.Name);
			
			// prevent loop - basically do NOT copy master account orders that have DAA on them
			
			if (SendName.Contains(MarketOrderName))
				return;
			
			if (SendName.Contains(OneTradeOrderName))
				return;	
			
			if (SendName.Contains(RefreshOrderName))
				return;			
			
			
			
			//Print();
			
			int MasterExQty = SendQuantity;
			// List<string> fractionalWarningAccounts = new List<string>();
			
			
	
				
			
			Instrument MasterExInstrument = SendInstrument;
			Instrument SlaveExInstrument = SendInstrument;
		
			
			string thisexinstr = SendInstrument.FullName;
			
			
			Instrument	MicroInstrument = GetTheInstrument(thisexinstr, "Micro", false);
			Instrument	MiniInstrument = GetTheInstrument(thisexinstr, "Mini", false);				
								
//			Instrument MicroInstrument = null;
//			Instrument MiniInstrument = null;
			
				if (!IsInstrumentTracked(SendInstrument)) return;
				
				
			
			
			foreach (string sssss in AllDuplicateAccounts)
			{
				
				
				Account SlaveAccount = AccountFromName(sssss);
				// Ensure we're subscribed to this follower's PositionUpdate so we can cancel orphan target/stop when they go flat (lazy subscribe if list was empty when master was set)
				if (SlaveAccount != null && SlaveAccount != CurrentMasterAccount && !FollowerAccountsWithPositionUpdateSubscribed.Contains(SlaveAccount))
				{
					SlaveAccount.PositionUpdate += OnPositionUpdate3;
					SlaveAccount.OrderUpdate += OnFollowerLatencyOrderUpdate;
					FollowerAccountsWithPositionUpdateSubscribed.Add(SlaveAccount);
				}
						
						
				if (IsAccountFinishedAndFlat(sssss))
					continue;
						
						
						
				if (pIsATMSelectEnabled)
				{
					string currentaccountmode = GetAccountMode(sssss);
				
					bool IsNotExecutionMode = false;
					
//					if (currentaccountmode == "Executions")
//						continue;
					
					if (currentaccountmode == "Default")
					{
						if (pCopierMode != "Executions")
							IsNotExecutionMode = true;
					}
					else if (currentaccountmode != "Executions")
					{
						IsNotExecutionMode = true;
					}
					
					if (IsNotExecutionMode)
						continue;	
					
					
							
//					if (currentaccountmode == "Orders")
//						continue;			
					
//					if (currentaccountmode == "Default" && pCopierMode == "Orders")
//						continue;							
					
				}
				

				
					
					
				
				
				
				if (SlaveAccount.ConnectionStatus == ConnectionStatus.Disconnected)
				
				{
					// remove account from saved list completely
					
					
					//bool RemoveDisco
					
					if (!AllConnectedAccounts.Contains(SlaveAccount.Name))
					{
						int i = 0;
						int found = 0;
						foreach(string s in pAllAccountData)
						{
							if (s.Contains(sssss))
							{
								
								found = i;
								
								//s = "";
							}
							
							i++;
						}
						
						pAllAccountData[found] = "";
						
					}
						
						
						
					
					
					continue;
				}
				
				
				
				
				if (SlaveAccount ==  null)
					continue;
				
				
				
				
				if (IsAccountFlat(SlaveAccount))
				if (!IsNewEntry)
					continue;
				
				
				
				//Print("IsNewEntry " + SlaveAccount.Name);
				
				double SlaveExMultiplier = 0;
				int SlaveExQty = MasterExQty;
				
				if (pIsXEnabled)
				{
					
					SlaveExMultiplier = Convert.ToDouble(GetAccountMultiplier(sssss));
										
						if (SlaveExMultiplier == 0)
							SlaveExMultiplier = 0.50;
						if (SlaveExMultiplier == -1)
							SlaveExMultiplier = 0.33;
						if (SlaveExMultiplier == -2)
							SlaveExMultiplier = 0.25;
						if (SlaveExMultiplier == -3)
							SlaveExMultiplier = 0.20;		
					
					if (pMultiplierMode == "Multiplier")
						SlaveExQty = RoundFollowerQtyForExecutionsMode(MasterExQty * SlaveExMultiplier);
					else
						SlaveExQty = (int) SlaveExMultiplier;
					
					SlaveExQty = Math.Max(SlaveExQty, 1);
					
					// if (IsFractionalMultiplier(SlaveExMultiplier) && FractionalDoesNotDivideOut(MasterExQty, SlaveExMultiplier, out int _))
					// 	fractionalWarningAccounts.Add(sssss + " (" + FractionalMultiplierLabel(SlaveExMultiplier) + ": master " + MasterExQty + " → follower " + SlaveExQty + " rounded)");
					
				}
					
				
				SlaveExInstrument = MasterExInstrument;

				if (pIsCrossEnabled)
				{
				
					MicroInstrument = GetTheInstrument(thisexinstr, "Micro", true);
					MiniInstrument = GetTheInstrument(thisexinstr, "Mini", true);				
					
					

							SlaveExInstrument = MicroInstrument;
							if (AllCrossAccounts.Contains(sssss))
							{

								SlaveExInstrument = MiniInstrument;
							}								
							
					
				}						
				
				
		
				
				// trying to make quantity mode work executions mode
							
//						if (SendName.Contains("Close"))
//						{
						
							
//							SlaveExQty = (int) SlaveAccount.GetPosition(SlaveExInstrument.Id).Quantity;
							
							
//						}				
				
				
				
				
				if (SlaveAccount == CurrentMasterAccount)
					continue;

				
				
				bool dofade = false;
				
				if (pIsFadeEnabled)
				{
					string ssssfade = GetAccountFade(sssss);
					
					
					if (ssssfade == "Yes")
						dofade = true;
					
					
				
				}
				
				if (dofade)
				{
					if (SendMarketPosition == MarketPosition.Long)
						SellMarket(SlaveExQty, SlaveExInstrument, SlaveAccount);
					
					if (SendMarketPosition == MarketPosition.Short)
						BuyMarket(SlaveExQty, SlaveExInstrument, SlaveAccount);					
						
				}
				else
				{
					if (SendMarketPosition == MarketPosition.Long)
						BuyMarket(SlaveExQty, SlaveExInstrument, SlaveAccount);
					
					if (SendMarketPosition == MarketPosition.Short)
						SellMarket(SlaveExQty, SlaveExInstrument, SlaveAccount);
		
				}
				
				
				
			}
			
			// if (fractionalWarningAccounts.Count > 0)
			// {
			// 	string msg = "Fractional multiplier: Master order quantity " + MasterExQty + " does not divide evenly. Affected follower account(s) will receive rounded quantity — " + string.Join("; ", fractionalWarningAccounts) + ".";
			// 	AddMessage(msg, 12, Brushes.Goldenrod);
			// }
			
			//Print(e.Execution.Account.Name + " " + e.Execution.Quantity + " " + e.Execution.MarketPosition);
			
							
			
			
			
			
			
		}
		
		
