		private static Random random = new Random();
		
		public static string RandomString(int length)
		{
			//const string chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
		    const string chars = "abcdefghijklmnopqrstuvwxyz0123456789";
		    return new string(Enumerable.Repeat(chars, length)
		        .Select(s => s[random.Next(s.Length)]).ToArray());
		}	

		private SortedDictionary<string, int> TotalAPI = new SortedDictionary<string, int>();
		
		// Tradovate API actions counter: rolling 60-second and 60-minute windows (80/min, 5000/hour limits; 429 block ~20-30 sec)
		private const int TradovateLimitPerMinute = 80;
		private const int TradovateLimitPerHour = 5000;
		private const int TradovateBlockDurationSeconds = 25;
		private const string TradovateAPIButtonString = "API";
		private object TradovateAPILock = new object();
		private SortedDictionary<string, List<(DateTime Time, string ActionType)>> TradovateAPIActionLog = new SortedDictionary<string, List<(DateTime, string)>>();
		
		// Tradovate detection: connection type is exactly "Tradovate" after normalizing TypeName (strip "NinjaTrader.Cbi." and "Options").
		private static string NormalizeConnectionTypeName(string typeName)
		{
			if (string.IsNullOrEmpty(typeName)) return "";
			return typeName.Replace("NinjaTrader.Cbi.", "").Replace("Options", "");
		}
		private static bool IsTradovateConnectionType(string typeName)
		{
			return NormalizeConnectionTypeName(typeName ?? "") == "Tradovate";
		}
		private bool HasTradovateConnectionConnected()
		{
			foreach (Account acct in Account.All.ToList())
			{
				if (acct.Connection?.Options == null) continue;
				if (IsTradovateConnectionType(acct.Connection.Options.TypeName?.ToString()) && acct.ConnectionStatus == ConnectionStatus.Connected)
					return true;
			}
			return false;
		}
		// True if master or any follower (non-sim) is a Tradovate account. Simulated accounts do not count.
		private bool HasTradovateMasterOrFollower()
		{
			foreach (Account acct in Account.All.ToList())
			{
				if (acct.Provider == Provider.Simulator) continue;
				if (acct.Connection?.Options == null) continue;
				if (!IsTradovateConnectionType(acct.Connection.Options.TypeName?.ToString())) continue;
				if (acct.Name == pThisMasterAccount || AllDuplicateAccounts.Contains(acct.Name))
					return true;
			}
			return false;
		}
		
