		// https://ninjatrader.com/support/helpGuides/nt8/NT%20HelpGuide%20English.html?connection_class.htm
		
		
		
    private Connection Connect(string connectionName)
    {
        // Output the execution
        try
        {
              // Get the configured account connection
              ConnectOptions connectOptions = null;
              lock (Core.Globals.ConnectOptions)
                  connectOptions = Core.Globals.ConnectOptions.FirstOrDefault(o => o.Name == connectionName);
 
              if (connectOptions == null)
              {
                  NinjaTrader.Code.Output.Process("Could not connect. No connection found.", PrintTo.OutputTab1);
                  return null;
              }
 
              // If connection is not already connected, connect.
              lock (Connection.Connections)
                  if (Connection.Connections.FirstOrDefault(c => c.Options.Name == connectionName) == null)
                  {
                        Connection connect = Connection.Connect(connectOptions);
 
                        // Only return connection if successfully connected
                        if (connect.Status == ConnectionStatus.Connected)
                            return connect;
                        else
                            return null;
                  }
 
              return null;
        }
        catch (Exception error)
        {
              NinjaTrader.Code.Output.Process("Connect exception: " + error.ToString(), PrintTo.OutputTab1);
              return null;
        }
    }
	
	
	
		private void RecordTradovateAPIAction(Order order, OrderState state)
		{
			if (order?.Account?.Connection?.Options == null) return;
			if (!IsTradovateConnectionType(order.Account.Connection.Options.TypeName?.ToString())) return;
			// TriggerPending (e.g. MIT/stop), Working (place/accept), Cancelled, ChangePending (move/modify), CancelPending (cancel request — Tradovate counts these toward rate limit).
			bool countAction = state == OrderState.TriggerPending || state == OrderState.Working || state == OrderState.Cancelled || state == OrderState.ChangePending || state == OrderState.CancelPending;
			if (!countAction) return;
			string connName = order.Account.Connection.Options.Name ?? "";
			if (string.IsNullOrEmpty(connName)) return;
			lock (TradovateAPILock)
			{
				if (!TradovateAPIActionLog.ContainsKey(connName))
					TradovateAPIActionLog.Add(connName, new List<(DateTime, string)>());
				TradovateAPIActionLog[connName].Add((DateTime.Now, state.ToString()));
				// Prune older than 60 minutes to avoid unbounded growth
				var list = TradovateAPIActionLog[connName];
				DateTime cutoff = DateTime.Now.AddMinutes(-60);
				for (int i = list.Count - 1; i >= 0; i--)
					if (list[i].Time < cutoff) list.RemoveAt(i);
			}
		}
		
		private int GetTradovateCommandsMinuteCount()
		{
			int count = 0;
			DateTime cutoff = DateTime.Now.AddSeconds(-60);
			lock (TradovateAPILock)
			{
				foreach (var list in TradovateAPIActionLog.Values)
					foreach (var t in list)
						if (t.Time >= cutoff) count++;
			}
			return count;
		}
		
		private int GetTradovateCommandsHourCount()
		{
			int count = 0;
			DateTime cutoff = DateTime.Now.AddMinutes(-60);
			lock (TradovateAPILock)
			{
				foreach (var list in TradovateAPIActionLog.Values)
					foreach (var t in list)
						if (t.Time >= cutoff) count++;
			}
			return count;
		}
		
		private int GetTradovateCommandsSafeInSeconds()
		{
			int minuteCount = GetTradovateCommandsMinuteCount();
			int hourCount = GetTradovateCommandsHourCount();
			if (minuteCount < TradovateLimitPerMinute && hourCount < TradovateLimitPerHour) return 0;
			int safeIn = 0;
			DateTime now = DateTime.Now;
			lock (TradovateAPILock)
			{
				if (minuteCount >= TradovateLimitPerMinute)
				{
					DateTime cutoff60s = now.AddSeconds(-60);
					DateTime? oldestInMinute = null;
					foreach (var list in TradovateAPIActionLog.Values)
						foreach (var t in list)
							if (t.Time >= cutoff60s && (!oldestInMinute.HasValue || t.Time < oldestInMinute.Value))
								oldestInMinute = t.Time;
					if (oldestInMinute.HasValue)
						safeIn = Math.Max(safeIn, (int)(60 - (now - oldestInMinute.Value).TotalSeconds));
				}
				if (hourCount >= TradovateLimitPerHour)
				{
					DateTime cutoff60m = now.AddMinutes(-60);
					DateTime? oldestInHour = null;
					foreach (var list in TradovateAPIActionLog.Values)
						foreach (var t in list)
							if (t.Time >= cutoff60m && (!oldestInHour.HasValue || t.Time < oldestInHour.Value))
								oldestInHour = t.Time;
					if (oldestInHour.HasValue)
						safeIn = Math.Max(safeIn, (int)(3600 - (now - oldestInHour.Value).TotalSeconds));
				}
			}
			return Math.Max(safeIn, TradovateBlockDurationSeconds);
		}
		
		/// <summary>Minutes from now until the hourly action count falls below the limit (0 if already under).</summary>
		private int GetTradovateCommandsSafeInMinutesForHour()
		{
			int hourCount = GetTradovateCommandsHourCount();
			if (hourCount < TradovateLimitPerHour) return 0;
			DateTime now = DateTime.Now;
			DateTime cutoff60m = now.AddMinutes(-60);
			DateTime? oldestInHour = null;
			lock (TradovateAPILock)
			{
				foreach (var list in TradovateAPIActionLog.Values)
					foreach (var t in list)
						if (t.Time >= cutoff60m && (!oldestInHour.HasValue || t.Time < oldestInHour.Value))
							oldestInHour = t.Time;
			}
			if (!oldestInHour.HasValue) return 0;
			double minutesUntilOldestFallsOff = 60 - (now - oldestInHour.Value).TotalMinutes;
			return Math.Max(1, (int)Math.Ceiling(minutesUntilOldestFallsOff));
		}
		
		/// <summary>Next time actions drop off the hourly window (oldest + 60 min), and how many actions drop off (those in the same minute as oldest).</summary>
		private void GetTradovateNextDropOff(out DateTime? nextDropOffTime, out int countDroppingOff)
		{
			nextDropOffTime = null;
			countDroppingOff = 0;
			DateTime now = DateTime.Now;
			DateTime cutoff60m = now.AddMinutes(-60);
			DateTime? oldestInHour = null;
			int dropCount = 0;
			DateTime? dropTime = null;
			lock (TradovateAPILock)
			{
				foreach (var list in TradovateAPIActionLog.Values)
					foreach (var t in list)
						if (t.Time >= cutoff60m && (!oldestInHour.HasValue || t.Time < oldestInHour.Value))
							oldestInHour = t.Time;
				if (oldestInHour.HasValue)
				{
					DateTime oldestMinuteStart = oldestInHour.Value.Date.AddHours(oldestInHour.Value.Hour).AddMinutes(oldestInHour.Value.Minute);
					DateTime oldestMinuteEnd = oldestMinuteStart.AddMinutes(1);
					foreach (var list in TradovateAPIActionLog.Values)
						foreach (var t in list)
							if (t.Time >= cutoff60m && t.Time >= oldestMinuteStart && t.Time < oldestMinuteEnd)
								dropCount++;
					dropTime = oldestInHour.Value.AddMinutes(60);
				}
			}
			nextDropOffTime = dropTime;
			countDroppingOff = dropCount;
		}
		
		private string GetTradovateActionBreakdown()
		{
			DateTime cutoff = DateTime.Now.AddMinutes(-60);
			var byType = new SortedDictionary<string, int>(StringComparer.Ordinal);
			lock (TradovateAPILock)
			{
				foreach (var list in TradovateAPIActionLog.Values)
					foreach (var t in list)
						if (t.Time >= cutoff)
						{
							if (!byType.ContainsKey(t.ActionType)) byType.Add(t.ActionType, 0);
							byType[t.ActionType]++;
						}
			}
			if (byType.Count == 0) return "No Tradovate API actions in the last 60 minutes.";
			var sb = new System.Text.StringBuilder();
			foreach (var kv in byType)
				sb.Append(kv.Key).Append(": ").Append(kv.Value).Append("; ");
			return sb.ToString().TrimEnd(' ', ';');
		}
		
		/// <summary>Rebuild Tradovate API action log from order history (run once on load). Keeps totals accurate and restores after window reload without looping on every OrderUpdate.</summary>
		private void RebuildTradovateAPIActionLogFromHistory()
		{
			DateTime cutoff = DateTime.Now.AddMinutes(-60);
			var newLog = new SortedDictionary<string, List<(DateTime Time, string ActionType)>>(StringComparer.Ordinal);
			foreach (Account acct in Account.All.ToList())
			{
				if (acct.Provider == Provider.Simulator || acct.Connection?.Options == null) continue;
				if (!IsTradovateConnectionType(acct.Connection.Options.TypeName?.ToString())) continue;
				string connName = acct.Connection.Options.Name ?? "";
				if (string.IsNullOrEmpty(connName)) continue;
				if (!newLog.ContainsKey(connName))
					newLog.Add(connName, new List<(DateTime, string)>());
				var list = newLog[connName];
				foreach (Order or in acct.Orders.ToList())
				{
					foreach (OrderEventArgs orrrr in or.OrderUpdates.ToList())
					{
						bool countIt = orrrr.OrderState == OrderState.TriggerPending || orrrr.OrderState == OrderState.Working || orrrr.OrderState == OrderState.Cancelled || orrrr.OrderState == OrderState.ChangePending || orrrr.OrderState == OrderState.CancelPending;
						if (!countIt || orrrr.Time < cutoff) continue;
						list.Add((orrrr.Time, orrrr.OrderState.ToString()));
					}
				}
			}
			lock (TradovateAPILock)
			{
				TradovateAPIActionLog = newLog;
			}
		}
		
