		/// <summary>Find and move/cancel the follower order that matches the master order. For target/stop orders, masterAtmNameForTargetStop ensures we only match orders belonging to the same ATM strategy instance.</summary>
		private void LookupFollowerAccountOrder (Account aaaa, Instrument iiii, int SlaveQty, Order MasterOrder, double thisp, string action, string masterAtmNameForTargetStop)
		{
		if (_diagLog != null)
				_diagLog.Log("FOLLOWER", "LOOKUP_ORDER", "Account=" + (aaaa != null ? aaaa.Name : "?") + "|Instrument=" + (iiii != null ? iiii.FullName : "?") + "|Qty=" + SlaveQty + "|Price=" + thisp + "|Action=" + action + "|MasterOrder=" + (MasterOrder != null ? MasterOrder.Name : "?"));
			// For target/stop with multiple same-name instances: get master's "current" price (what follower has before this move) for fallback match when follower OCO differs. Use last non-change event so we track after multiple moves.
			double masterOriginalLimitForMatch = -1;
			double masterOriginalStopForMatch = -1;
			if (!string.IsNullOrEmpty(masterAtmNameForTargetStop) && (MasterOrder.Name.Contains("Target") || MasterOrder.Name.Contains("Stop")) && CountMasterATMsWithName(masterAtmNameForTargetStop) > 1)
			{
				foreach (OrderEventArgs ev in MasterOrder.OrderUpdates.ToList())
				{
					// Only take prices from "stable" states (not change-in-flight); last one = current level = what follower order has
					bool stable = ev.OrderState != OrderState.ChangePending && ev.OrderState != OrderState.ChangeSubmitted;
					if (stable)
					{
						if (ev.LimitPrice != 0) masterOriginalLimitForMatch = ev.LimitPrice;
						if (ev.StopPrice != 0) masterOriginalStopForMatch = ev.StopPrice;
					}
				}
				if (masterOriginalLimitForMatch < 0) masterOriginalLimitForMatch = MasterOrder.LimitPrice;
				if (masterOriginalStopForMatch < 0) masterOriginalStopForMatch = MasterOrder.StopPrice;
			}

			// When multiple same-name instances: precompute index-matched follower order so we can match when OCO and price both differ (e.g. different entry fills)
			Order indexMatchedFollowerOrder = null;
			if (!string.IsNullOrEmpty(masterAtmNameForTargetStop) && (MasterOrder.Name.Contains("Target") || MasterOrder.Name.Contains("Stop")) && CountMasterATMsWithName(masterAtmNameForTargetStop) > 1)
				indexMatchedFollowerOrder = GetFollowerOrderByIndexMatch(aaaa, iiii, MasterOrder, masterAtmNameForTargetStop, true);

			// Track match statistics for diagnostic logging when no match is found.
			bool _anyMatched = false;
			int _scannedCount = 0;
			int _instrumentMatchCount = 0;

			foreach (Order or in aaaa.Orders.ToList())
			{
				_scannedCount++;
				if (or.Instrument == null || iiii == null || or.Instrument.Id != iiii.Id)
					continue;
				_instrumentMatchCount++;
				
				bool multiInstanceMatchedByIndexOnly = false;
				// For target/stop orders, only consider follower orders that belong to the same ATM strategy as the master. When multiple same-name instances exist, match by OCO, then price, then index.
				if (!string.IsNullOrEmpty(masterAtmNameForTargetStop) && (MasterOrder.Name.Contains("Target") || MasterOrder.Name.Contains("Stop")))
				{
					object owner = or.GetOwnerStrategy();
					if (owner != null && owner.GetType() == typeof(AtmStrategy))
					{
						AtmStrategy slaveATM = (AtmStrategy)owner;
						string slaveAtmFullName = slaveATM.DisplayNameExtended ?? slaveATM.DisplayName ?? "";
						if (!AtmNamesMatchForSync(slaveAtmFullName, masterAtmNameForTargetStop))
							continue;
						// When multiple instances: require OCO match, or price match, or index match (same position when prices differ e.g. different fills)
						if (CountMasterATMsWithName(masterAtmNameForTargetStop) > 1)
						{
							bool ocoMatch = !string.IsNullOrEmpty(MasterOrder.Oco) && !string.IsNullOrEmpty(or.Oco) && or.Oco.StartsWith(MasterOrder.Oco);
							if (!ocoMatch)
							{
								double tick = iiii.MasterInstrument.TickSize;
								double tol = Math.Max(tick * 2, 1e-8);
								bool priceMatch = false;
								if (MasterOrder.Name.Contains("Target") && !MasterOrder.Name.Contains("Stop"))
									priceMatch = masterOriginalLimitForMatch >= 0 && Math.Abs(or.LimitPrice - masterOriginalLimitForMatch) <= tol;
								else if (MasterOrder.Name.Contains("Stop"))
									priceMatch = masterOriginalStopForMatch >= 0 && Math.Abs(or.StopPrice - masterOriginalStopForMatch) <= tol;
								if (!priceMatch)
								{
									if (indexMatchedFollowerOrder != null && or == indexMatchedFollowerOrder)
										multiInstanceMatchedByIndexOnly = true;
									else
										continue;
								}
							}
						}
					}
					else
						continue;
				}
				
			//	Print("one order " + or.OrderState);
				
				bool ordertypeok = or.OrderState == OrderState.Accepted || or.OrderState == OrderState.Working || or.OrderState == OrderState.TriggerPending || or.OrderState == OrderState.PartFilled;
				
				if (pEnabledTradingViewFix)
					ordertypeok = or.OrderState == OrderState.Accepted || or.OrderState == OrderState.Working || or.OrderState == OrderState.TriggerPending || or.OrderState == OrderState.PartFilled || or.OrderState == OrderState.ChangePending || or.OrderState == OrderState.ChangeSubmitted;
					
				
				//if (or.OrderState == OrderState.ChangeSubmitted || or.OrderState == OrderState.CancelSubmitted)
				if (ordertypeok) // added change states for tradingview
				{
			
					
					
					//Print("-LooookupFollowerAccountOrder 1");
					
					//bool foundmatch = or.Oco.Contains(ocococ);
					//bool foundmatch = or.Oco.Contains(ocococ) && or.Oco != string.Empty;
					
					bool foundmatch = false;
					
					bool YesName = or.Name == MasterOrder.Name;
					
					
					double MasterStopPrice = MasterOrder.StopPrice;
					double MasterLimitPrice = MasterOrder.LimitPrice;
							
					DateTime OriginalTime = DateTime.MinValue;
					double OriginalStopPrice = -1;
					double OriginalLimitPrice = -1;
					
					//Print("-LooookupFollowerAccountOrder 2");
					
					if (action == "move") // uncommended for tradovate and tradingview compatability, seems to be unnneeded
						
					foreach (OrderEventArgs orrrr in MasterOrder.OrderUpdates.ToList()) //.Reverse()) // loop through all events
					{
						if (orrrr.OrderState == OrderState.ChangePending) // get prices the last time change was pending
						{					
							MasterLimitPrice = orrrr.LimitPrice;
							MasterStopPrice = orrrr.StopPrice;
						}
						
						if (OriginalTime == DateTime.MinValue)
							OriginalTime = orrrr.Time;
						
						if (OriginalStopPrice == -1)
							OriginalStopPrice = orrrr.StopPrice;
						if (OriginalLimitPrice == -1)
							OriginalLimitPrice = orrrr.LimitPrice;						
						
						
						//Print(orrrr.OrderState + " " + orrrr.Time);
						

					}
					 
					//Print("-LooookupFollowerAccountOrder " + MasterOrder.Name);
					//Print("MasterLimitPrice " + MasterLimitPrice);
					
					
					//Print("-LooookupFollowerAccountOrder 3");
					
					// How to move exit orders when orders are not in sync because it was a market entry?

					bool YesTimeMatch = false;
					
					double OriginalStopPrice2 = -1;
					double OriginalLimitPrice2 = -1;
					
					if (YesName)
					if (MasterOrder.Name.Contains("Target") || MasterOrder.Name.Contains("Stop"))
					{
						DateTime OriginalTime2 = DateTime.MinValue;	
						foreach (OrderEventArgs orrrr in or.OrderUpdates.ToList()) //.Reverse()) // loop through all events
						{
							// get the original time that the follower order was placed
							OriginalTime2 = orrrr.Time;	
							OriginalStopPrice2 = orrrr.StopPrice;
							OriginalLimitPrice2 = orrrr.LimitPrice;
							
							break;
						}
						
						int seccccc = 4;
						
					
						if (OriginalTime2 < OriginalTime.AddSeconds(seccccc) && OriginalTime2 > OriginalTime.AddSeconds(-1*seccccc))
						{
							YesTimeMatch = true;
							
						}
						
						//TimeSpan pR4Time = OriginalTime2 - OriginalTime;

						//pR4Time = pR4Time.
						
					//	Print(pR4Time);
//						Print(OriginalTime);
//						Print(MasterOrder.Time);
						
						
					}
									
			
					
					
					
					
					if (pCopierMode == "Orders")
					{
						//if (or.OrderType == OrderType.Limit)
						
							double finalorderprice = or.LimitPrice;
									
									if (or.StopPrice != 0)
										finalorderprice = or.StopPrice;
									
									
									
						if (finalorderprice != thisp)
						{
	
							
							
							SwitchPriceOfSync(finalorderprice, thisp);
							
				
							
//							DateTime
//							LimitPriceToTimeOutOfSync.Remove(
						}
					}
											
					
					//Print("-LooookupFollowerAccountOrder 2");
					
					
					
					bool YesStopPrice = or.StopPrice == MasterStopPrice;
					bool YesLimitPrice = or.LimitPrice == MasterLimitPrice;
					bool YesInstrument = or.Instrument != null && iiii != null && or.Instrument.Id == iiii.Id;
					bool YesQty = or.Quantity == SlaveQty;
					bool YesOrderType = or.OrderType == MasterOrder.OrderType;
					
					
					
					
					YesQty = true;  // updated this so it still updates orders when only quantity has changed
					
					
					
					
					if (or.OrderState == OrderState.PartFilled)
						YesQty = true;
					
					
					// Capture which branch set foundmatch so the diagnostic print (below) can show the
					// reason without re-deriving it. Only populated when pDebugOrderMatching is on.
					string matchReason = null;
					foundmatch = YesStopPrice && YesLimitPrice && YesInstrument && YesQty && YesName;
					if (foundmatch && pDebugOrderMatching) matchReason = "full-match (price+name+instrument+qty)";
					bool isTargetOrStop = MasterOrder.Name.Contains("Target") || MasterOrder.Name.Contains("Stop");
					bool isATMExitOrder = !string.IsNullOrEmpty(masterAtmNameForTargetStop) && isTargetOrStop;
					// When we matched by index (multiple instances, different fills = different prices), still allow move/cancel so we sync the same instance
					if (!foundmatch && multiInstanceMatchedByIndexOnly && YesName && YesInstrument)
					{
						foundmatch = true;
						if (pDebugOrderMatching) matchReason = "multi-instance-by-index";
					}
					// Single instance or scaled-in: only one target/stop per bracket name on follower — match by name + instrument so move still tracks when prices differ (e.g. follower moved manually or different fills)
					if (!foundmatch && action == "move" && isATMExitOrder && CountMasterATMsWithName(masterAtmNameForTargetStop) <= 1 && YesName && YesInstrument)
					{
						foundmatch = true;
						if (pDebugOrderMatching) matchReason = "atm-single-name-relaxed-move";
					}
					// Apply the same relaxed matching for cancel so ATM exit cancels copy even when follower price differs
					if (!foundmatch && action == "cancel" && isATMExitOrder && CountMasterATMsWithName(masterAtmNameForTargetStop) <= 1 && YesName && YesInstrument)
					{
						foundmatch = true;
						if (pDebugOrderMatching) matchReason = "atm-single-name-relaxed-cancel";
					}
					
					// for exit orders only where prices do NOT match
				
//					Print(YesStopPrice + " " + YesLimitPrice  + " " +  YesInstrument  + " " +  YesQty  + " " +  YesName);
//					Print("YesStopPrice " + or.StopPrice + " " + MasterStopPrice);
//					Print("YesLimitPrice " + or.LimitPrice + " " + MasterLimitPrice);
					
					
					// suspended
					
					
					
					
					int countssss = 0;
						int CurrentSuspended = 0;
						foreach (OrderEventArgs orrrr in MasterOrder.OrderUpdates.ToList()) //.Reverse()) // loop through all events
						{
							countssss++;
							
							//Print(countssss + " " + orrrr.OrderState);
							
							if (orrrr.OrderState == OrderState.Suspended) // get prices the last time change was pending
							{		
								CurrentSuspended = countssss;
								
//								if (CurrentSuspended == 1)
//									break;
								//Print("Found Suspended " + CurrentSuspended);
							}
							
						
							
							
						}
						
				
						if (CurrentSuspended != 0)
						{
							
						
							//Print("TV STOP OR TARGET MOVED CHECK ENTRY");
							
							
						}
				
			
					//Print("foundmatch   "    + foundmatch + "    YesTimeMatch   "+ YesTimeMatch);
					
						
					
						
						
						
					if (!foundmatch && CurrentSuspended == 0) // make sure it is NOT a trading view take profit or stop loss order being moved when matching orders by time only
					{
						bool usetime = false;

						// only use time if original prices do not match up between master order and follower account order

						if (OriginalLimitPrice != OriginalLimitPrice2)
							usetime = true;

						if (OriginalStopPrice != OriginalStopPrice2)
							usetime = true;

							if (usetime)
						if (YesTimeMatch && YesInstrument && YesQty && YesOrderType)
						{
							foundmatch = true;
							if (pDebugOrderMatching) matchReason = "time-fallback";
						}

					}
					
					
					//Print("YesTimeMatch " + YesTimeMatch);
					
					//Print(or.LimitPrice + "  " + "or.LimitPrice" + "  " + LimitPrice + "  " + "LimitPrice");
					
					
					//Print(YesStopPrice + "  " + YesLimitPrice + "  " + YesInstrument + "  " + YesQty);
					
					
					//Print("foundmatch " + or.OrderState + "  " + or.Oco + "  " + ocococ + "  " + foundmatch);

					////Print("Cancel 4" + or.Account + " " + or.Name + "  " + foundmatch);



					// Log which match branch fired, using the reason captured at the match site above.
					if (pDebugOrderMatching && foundmatch)
					{
						Print("[DAA Match] " + action + " master '" + MasterOrder.Name
							+ "' @ " + (MasterOrder.LimitPrice != 0 ? MasterOrder.LimitPrice.ToString() : MasterOrder.StopPrice.ToString())
							+ " -> follower '" + aaaa.Name + "' order '" + or.Name + "' @ "
							+ (or.LimitPrice != 0 ? or.LimitPrice.ToString() : or.StopPrice.ToString())
							+ " via: " + (matchReason ?? "unknown"));
					}

					if (foundmatch)
					{
						_anyMatched = true;

						//Print("foundmatch " + or.Account + " " + or.OrderState + "  " + or.Oco + "  " + foundmatch);

						if (action == "move")
						{
							bool allowmove = true;
							
							if (pEnabledTradingViewFix)
							if (or.OrderState == OrderState.ChangePending)
							{
								allowmove = false;
								// redo master order move 
								ResubmitTradingViewMove = true;
									
			
//								Print("ResubmitTradingViewMove");
//								Print(thisp);
				
								double asfsdgdf = 0;
								
								
									foreach (OrderEventArgs orrrr in MasterOrder.OrderUpdates.ToList()) //.Reverse()) // loop through all events
									{
										if (orrrr.OrderState == OrderState.Working) // get prices the last time change was pending
										{					
											asfsdgdf = orrrr.StopPrice;
											
											if (orrrr.Order.OrderType == OrderType.Limit)
												asfsdgdf = orrrr.LimitPrice;
											
										}
										
									
									}
								
								
								//Print(asfsdgdf);
										
									
								MovePrice = asfsdgdf;
								NewPrice = thisp;
								
							}
							
							
							//allowmove = true;
							
							
//							if (or.OrderType == OrderType.Limit && or.LimitPrice == thisp) // why was this added?????
//								allowmove = false;
							
							//Print("allowmove " + allowmove);
						
							//Print("move " + thisp);
								
							if (allowmove)
							{
								//MoveOrder(or, thisp, 0, aaaa, SlaveQty);
								
								
								//Print("move order " + aaaa.Name + " " + MasterOrder.StopPrice.ToString() + or.Oco);
								
								MoveOrder2(or, MasterOrder.LimitPrice, MasterOrder.StopPrice, thisp, 0, aaaa, SlaveQty);
								// Latency: this is the follower-move dispatch point — detect
								// (master ChangeSubmitted) -> follower change submitted.
								RecordCopierLatency(aaaa.Name, or, "Move");
								return; // one master order = one follower order; stop after first match so we don't move other instances' orders
							}
						}
						else
						{
							
							bool DoSkipForStrategyExitOrders = false;
							
							
							
							// this was prevents cancel commands on targets and stops. need to improve it and fix
							
//							if (MasterOrder.Oco != string.Empty)
//							{
							
//								if (!or.Oco.Contains(MasterOrder.Oco))
//									DoSkipForStrategyExitOrders = true;
								
								
//							}
							
							
							// removed requirement
							//if (IsPendingEntryOrder(or)) 
							
							//if (!or.Name.Contains("Target")) 
							
							if (!DoSkipForStrategyExitOrders)
							{
								////Print("Cancel 5" + or.Account + " " + or.Name);
								
								
								aaaa.Cancel(new[] { or });
								RecordCopierLatency(aaaa.Name, or, "Cancel");
								//Print("Cancel 13");
							}
							
						}
						
						//return true;
					
						
						// after finding one qualifying order, then exit the loop
						// commented this out because it wasn't moving stop loss orders at the same price
						
						//break;

					}
				}
			}

			// C1: Diagnostic - if the matching loop walked every follower order without finding one,
			// log it so support tickets about "my follower didn't get updated" can be traced. Only fires
			// when pDebugOrderMatching is on, so normal runs stay silent.
			if (pDebugOrderMatching && !_anyMatched)
			{
				string _mp = MasterOrder.LimitPrice != 0 ? MasterOrder.LimitPrice.ToString() : MasterOrder.StopPrice.ToString();
				Print("[DAA Match] NO MATCH FOUND - " + action + " master '" + MasterOrder.Name
					+ "' @ " + _mp + " on " + (aaaa != null ? aaaa.Name : "?")
					+ " (scanned " + _scannedCount + " follower orders, " + _instrumentMatchCount + " on same instrument"
					+ (string.IsNullOrEmpty(masterAtmNameForTargetStop) ? "" : ", atmName='" + masterAtmNameForTargetStop + "'")
					+ ")");
			}

			//return false;

		}


	
		
		
		double OldStopLossPrice = 0;		
		bool SkipNextChangeSubmittedCommand = false;
		
		bool LongExitOK = false;
		bool ShortExitOK = false;
		
		string LastAddATMName = string.Empty;
		
		//List<List<string>> AddOnATMAdjustExitOrders = new List<List<string>>();
		
			
		//private SortedDictionary<string, List<string>> AddOnATMAdjustExitOrders = new SortedDictionary<string, List<string>>();
		
		private SortedDictionary<string, SortedList<string, List<string>>> AddOnATMAdjustExitOrders = new SortedDictionary<string, SortedList<string, List<string>>>();
		
		// When scaling in/out in Orders mode, track which instruments had scaling so we can close follower positions when master goes flat
		private HashSet<Instrument> InstrumentsWithScalingInEffect = new HashSet<Instrument>();
		// Switch (code only, not an input): when true, on master flat after scaling we clean up followers for that instrument.
		// Default on to fix sim ATM target/stop sync issues. Intentionally hidden from the user interface for now.
		private bool OnMasterFlatAfterScalingCloseFollowers = true;

		// Diagnostic flag - when true, LookupFollowerAccountOrder and the master-flat cleanup log which
		// match branch fired / which follower was touched. Off by default to keep the NT Output tab clean.
		// Flip to true temporarily when investigating follower moved to the wrong price issues.
		private bool pDebugOrderMatching = false;

		// Deferred bracket verification after scale-in — ensures follower exit orders match master after entry fills
		private DateTime _scaleInVerifyTime = DateTime.MinValue;
		private Order _scaleInVerifyMasterOrder = null;
		
		
