		bool pUseAnthonyCode = false;
		
		private void OnOrderUpdate3 (object sender, OrderEventArgs  e)
		{


			//Print(e.Order.Account.Name + "    " + e.AverageFillPrice);

			if (State != State.Realtime)
				return;

			// Session-membership tracking for OnExecutionUpdate3. Record every
			// master-account OrderId that transitions through any post-Initialized
			// state in THIS realtime session. The execution gate uses this set to
			// admit only fills from orders the indicator originated here, so
			// reconnect/replay fills (whose orders never went through Submitted
			// in this session) are rejected without any timezone math.
			//
			// Skip Initialized — it can fire pre-flight while the order is being
			// constructed. Submitted onward proves NT actually pushed the order.
			try
			{
				if (CurrentMasterAccount != null && e.Order != null
					&& e.Order.Account == CurrentMasterAccount
					&& e.OrderState != OrderState.Initialized
					&& !string.IsNullOrEmpty(e.Order.OrderId))
				{
					lock (_sessionLiveOrderIds)
					{
						// First sighting of this master order this realtime session —
						// stamp the detection time so Orders-mode dispatch latency
						// measures from here. (Executions mode stamps it in
						// OnExecutionUpdate3 instead, off the fill.)
						if (_sessionLiveOrderIds.Add(e.Order.OrderId))
							_copierLatencyMasterT = DateTime.Now;
						else if (e.OrderState == OrderState.ChangeSubmitted
							  || e.OrderState == OrderState.CancelSubmitted)
							// Master order MOVE or CANCEL detected: re-stamp so the follower
							// change's dispatch / confirmation latency measures from here.
							_copierLatencyMasterT = DateTime.Now;
						// Cap to prevent unbounded growth across long sessions.
						// Same pattern as _diagLoggedOrderStates above.
						if (_sessionLiveOrderIds.Count > 10000)
						{
							_sessionLiveOrderIds.Clear();
							_sessionLiveOrderIds.Add(e.Order.OrderId);
						}
					}
				}
			}
			catch { }

			// Capture master flatten-Close orders. NT's Account.Flatten() — run
			// by our Flatten All and goal-loss flatten — names its close orders
			// "Close". Recording the Order here lets the copy paths skip every
			// fill of it for the order's whole life. The fixed pMilliSFE window
			// cannot: a large/slow close fills in partials that outrun it, and
			// those late partials were copied to the already-flat followers as a
			// brand-new opposite position (reversal — Michael Weprin 2026-05-21).
			try
			{
				if (CurrentMasterAccount != null && e.Order != null
					&& e.Order.Account == CurrentMasterAccount
					&& string.Equals(e.Order.Name, "Close", StringComparison.OrdinalIgnoreCase)
					&& IsRecentFlatten())
				{
					lock (_masterFlattenCloseOrders)
					{
						// Session-long safety valve; flatten-close orders are rare
						// and any capped entry is long terminal anyway.
						if (_masterFlattenCloseOrders.Count > 500)
							_masterFlattenCloseOrders.Clear();
						if (_masterFlattenCloseOrders.Add(e.Order) && _diagLog != null)
						{
							try { _diagLog.Log("COPIER", "FLATTEN_CLOSE_ORDER_TRACKED", "OrderId=" + e.Order.OrderId + "|Instrument=" + (e.Order.Instrument != null ? e.Order.Instrument.FullName : "?") + "|Qty=" + e.Order.Quantity); }
							catch { }
						}
					}
				}
			}
			catch { }

			// Logged AFTER the realtime gate — otherwise chart reload replays all
			// historical orders for the day and floods the log with events the
			// indicator itself is about to ignore.
			if (_diagLog != null)
			{
				try
				{
					Order o = e.Order;
					string isMaster = (CurrentMasterAccount != null && o.Account == CurrentMasterAccount) ? "Master" : "Follower";
					// Skip noisy intermediate states. Submitted/PartFilled/Filled/Rejected/
					// Cancelled/CancelPending/ChangeSubmitted carry the meaningful
					// transitions; Initialized/Accepted/Working/ChangePending fire
					// multiple times per order and we already see the terminal state.
					bool _skipState = e.OrderState == OrderState.Initialized
						|| e.OrderState == OrderState.Accepted
						|| e.OrderState == OrderState.Working
						|| e.OrderState == OrderState.ChangePending;
					// Dedupe duplicate callbacks for the same (OrderId, State).
					string _orderStateKey = o.OrderId + "|" + e.OrderState;
					bool _alreadyLogged = _diagLoggedOrderStates.ContainsKey(_orderStateKey);
					if (!_skipState && !_alreadyLogged)
					{
						_diagLoggedOrderStates[_orderStateKey] = 1;
						// Cap the dedupe set so it can't grow unbounded across a session.
						if (_diagLoggedOrderStates.Count > 5000)
							_diagLoggedOrderStates.Clear();
					_diagLog.Log("ORDER", "UPDATE",
						"Role=" + isMaster
						+ "|Account=" + o.Account.Name
						+ "|State=" + e.OrderState
						+ "|Name=" + o.Name
						+ "|Action=" + o.OrderAction
						+ "|Type=" + o.OrderType
						+ "|Qty=" + o.Quantity
						+ "|Limit=" + o.LimitPrice
						+ "|Stop=" + o.StopPrice
						+ "|AvgFill=" + e.AverageFillPrice
						+ "|OrderId=" + o.OrderId
						+ "|Instrument=" + (o.Instrument != null ? o.Instrument.FullName : "?")
						+ "|Time=" + o.Time.ToString("HH:mm:ss.fff"));
					}

					// Dedicated FOLLOWER_FILL line (mirrors EXECUTION|MASTER_FILL).
					// Easier to grep than scanning ORDER|UPDATE for State=Filled.
					if (isMaster == "Follower"
						&& (e.OrderState == OrderState.Filled || e.OrderState == OrderState.PartFilled))
					{
						double _fillLatMs = -1.0;
						try { _fillLatMs = (DateTime.Now - o.Time).TotalMilliseconds; } catch { }
						_diagLog.Log("EXECUTION", "FOLLOWER_FILL",
							"Account=" + o.Account.Name
							+ "|Instrument=" + (o.Instrument != null ? o.Instrument.FullName : "?")
							+ "|Action=" + o.OrderAction
							+ "|Qty=" + o.Filled
							+ "|TotalQty=" + o.Quantity
							+ "|AvgFill=" + e.AverageFillPrice
							+ "|State=" + e.OrderState
							+ "|OrderName=" + o.Name
							+ "|OrderId=" + o.OrderId
							+ "|FillLatencyMs=" + _fillLatMs.ToString("F0"));
					}

					// Dedicated MASTER_REJECT / FOLLOWER_REJECT line carrying the broker's
					// reject reason. Without it we cannot distinguish "order rejected by the
					// broker" from "order silently dropped" when a position diverges.
					// See Ricky 2026-04-27 (follower entries sent but broker stayed at 0 for
					// 12 min) and the 2026-05-19 M2K storm (a master "Close" order rejected
					// 425x with no record of WHY NinjaTrader rejected it).
					// Master logs on Rejected only — cancels are normal master bracket churn
					// and are already captured by the ORDER|UPDATE line above.
					bool _logRejectReasonLine = e.OrderState == OrderState.Rejected
						|| (isMaster == "Follower" && (e.OrderState == OrderState.CancelPending || e.OrderState == OrderState.Cancelled));
					if (_logRejectReasonLine)
					{
						string _rejReason = "";
						try
						{
							var _nativeErr = o.GetType().GetProperty("NativeError")?.GetValue(o) as string;
							if (!string.IsNullOrEmpty(_nativeErr)) _rejReason += _nativeErr;
							var _orderErr = o.GetType().GetProperty("Error")?.GetValue(o);
							if (_orderErr != null) _rejReason += (_rejReason.Length > 0 ? "; " : "") + _orderErr.ToString();
							var _msgProp = e.GetType().GetProperty("Message")?.GetValue(e) as string;
							if (!string.IsNullOrEmpty(_msgProp)) _rejReason += (_rejReason.Length > 0 ? "; " : "") + _msgProp;
						}
						catch { }
						_diagLog.Log("EXECUTION", (isMaster == "Master" ? "MASTER_REJECT" : "FOLLOWER_REJECT"),
							"Account=" + o.Account.Name
							+ "|Instrument=" + (o.Instrument != null ? o.Instrument.FullName : "?")
							+ "|Action=" + o.OrderAction
							+ "|Qty=" + o.Quantity
							+ "|Filled=" + o.Filled
							+ "|State=" + e.OrderState
							+ "|OrderName=" + o.Name
							+ "|OrderId=" + o.OrderId
							+ "|Reason=" + (_rejReason.Length > 0 ? _rejReason.Replace("|", ";").Replace("\r", " ").Replace("\n", " ") : "(none)"));
					}
				}
				catch { }
			}
			
			
			
			//Print(e.OrderState);
			
			
			if (State == State.Realtime)
				RecordTradovateAPIAction(e.Order, e.OrderState);

			// When Tradovate shows "Rate limit exceeded" popup, show a friendly message on the dashboard that moving orders is blocked but FLATTEN ALL still works.
			if (e.OrderState == OrderState.Rejected && e.Order?.Account?.Connection?.Options != null && IsTradovateConnectionType(e.Order.Account.Connection.Options.TypeName?.ToString()))
			{
				string errText = "";
				try
				{
					var nativeErr = e.Order.GetType().GetProperty("NativeError")?.GetValue(e.Order) as string;
					if (!string.IsNullOrEmpty(nativeErr)) errText += " " + nativeErr;
					var orderError = e.Order.GetType().GetProperty("Error")?.GetValue(e.Order);
					if (orderError != null) errText += " " + orderError.ToString();
					var msgProp = e.GetType().GetProperty("Message")?.GetValue(e) as string;
					if (!string.IsNullOrEmpty(msgProp)) errText += " " + msgProp;
				}
				catch { }
				bool isRateLimit = errText.IndexOf("rate limit", StringComparison.OrdinalIgnoreCase) >= 0;
				if (!isRateLimit && GetTradovateCommandsHourCount() >= 4000)
					isRateLimit = true; // heuristic: rejection while count is very high is likely rate limit
				if (isRateLimit)
				{
					if (_diagLog != null)
						_diagLog.Log("RISK", "RATE_LIMIT", "Account=" + e.Order.Account.Name + "|Error=" + errText.Replace("|", ";"));

					string flattenLabel = string.IsNullOrEmpty(FlattenButton) ? "FLATTEN ALL" : FlattenButton;
					string rateLimitMsg = "Tradovate rate limit reached. You cannot move or modify orders right now. You can still close all positions and cancel pending orders using the " + flattenLabel + " button(s) if needed.";
					// OrderUpdate can fire on a connection thread; marshal to UI thread so the accounts dashboard actually shows the message.
					if (ChartControl != null && ChartControl.Dispatcher != null)
						ChartControl.Dispatcher.InvokeAsync(() => AddMessage(rateLimitMsg, 60, Brushes.Goldenrod));
					else
						AddMessage(rateLimitMsg, 60, Brushes.Goldenrod);
				}
			}

			// if (_pendingFractionalWarningOrdersMode != null && _pendingFractionalWarningOrdersMode.Count > 0)
			// {
			// 	string msg = "Fractional multiplier: Master order quantity did not divide evenly. Affected follower account(s) received rounded quantity — " + string.Join("; ", _pendingFractionalWarningOrdersMode) + ".";
			// 	AddMessage(msg, 12, Brushes.Goldenrod);
			// 	_pendingFractionalWarningOrdersMode = null;
			// }

			//Print(NewATM.Id);
			
			
			//return;
			
			
			
//			if (State != State.Realtime)
//				return;
			
//			if (e.Time.Ticks < DateTime.Now.AddSeconds(-3000).Ticks) // 50 minutes
//				return;
			
			//Print(e.Time);
			
			
			// prevent widening of stop loss
			
			if (pExitShieldFeaturesEnabled)
			if (pExitShieldIsEnabled)
			{
				if (pExitShieldStopLoss)
				if (e.Order.Name.Contains("Stop"))
				{
	
					if (e.OrderState == OrderState.ChangeSubmitted)
					{
						
						double OriginalStopPrice = e.Order.StopPrice;
							
						if (pUseOriginalLocation)
						foreach (OrderEventArgs orrrr in e.Order.OrderUpdates.ToList())
						{
							// get the original time that the follower order was placed
							OriginalStopPrice = orrrr.StopPrice;					
							break;
						}
							
						LongExitOK = e.Order.IsShort && OriginalStopPrice > e.Order.StopPriceChanged;
						ShortExitOK = e.Order.IsLong && OriginalStopPrice < e.Order.StopPriceChanged;
						
						if (LongExitOK || ShortExitOK)
						{
							SkipNextChangeSubmittedCommand = true;
							if (_diagLog != null)
								_diagLog.Log("EXITSHIELD", "STOP_WIDENING_BLOCKED", "Account=" + e.Order.Account.Name + "|Order=" + e.Order.Name + "|OrigStop=" + OriginalStopPrice + "|AttemptedStop=" + e.Order.StopPriceChanged + "|Side=" + (LongExitOK ? "Short" : "Long"));

							if (!MoveBackStopLoss.ContainsKey(e.Order.Oco))
							MoveBackStopLoss.Add(e.Order.Oco, OriginalStopPrice);
						}

					}


					if (e.OrderState == OrderState.Accepted)
					{
						
						string oooocc = e.Order.Oco;
						
						if (MoveBackStopLoss.ContainsKey(oooocc))
						{
							double prevprice = MoveBackStopLoss[oooocc];
							//TriggerCustomEvent(o =>
							//	   				{
								
							
							MoveOrder(e.Order, prevprice, 0, e.Order.Account, 0);		
										
							if (pExitShieldMessages)
							{
								if (!pUseOriginalLocation)
									AddMessage("Stop Loss was moved due to 'Exit Shield' features.", 6, Brushes.Goldenrod);
								else
									AddMessage("Stop Loss was moved back to its original location due to 'Exit Shield' features.", 6, Brushes.Goldenrod);
								
								
							}
							
							//					}, null);	
							
							MoveBackStopLoss.Remove(oooocc);
										
						}
				
					}	
				}
				
				if (pExitShieldProfitTarget)
				if (e.Order.Name.Contains("Target"))
				{
	
					if (e.OrderState == OrderState.ChangeSubmitted)
					{
						
						double OriginalStopPrice = e.Order.LimitPrice;
							
						if (pUseOriginalLocation)
						foreach (OrderEventArgs orrrr in e.Order.OrderUpdates.ToList())
						{
							// get the original time that the follower order was placed
							OriginalStopPrice = orrrr.LimitPrice;					
							break;
						}
						
						//Print("OriginalStopPrice" + OriginalStopPrice);
						//Print("e.Order.LimitPriceChanged" + e.Order.LimitPriceChanged);
							
						LongExitOK = e.Order.IsShort && OriginalStopPrice > e.Order.LimitPriceChanged;
						ShortExitOK = e.Order.IsLong && OriginalStopPrice < e.Order.LimitPriceChanged;
						
						//Print("LongExitOK" + LongExitOK);
						//Print("ShortExitOK" + ShortExitOK);
						
						if (LongExitOK || ShortExitOK)
						{
							SkipNextChangeSubmittedCommand = true;
							if (_diagLog != null)
								_diagLog.Log("EXITSHIELD", "TARGET_TIGHTENING_BLOCKED", "Account=" + e.Order.Account.Name + "|Order=" + e.Order.Name + "|OrigLimit=" + OriginalStopPrice + "|AttemptedLimit=" + e.Order.LimitPriceChanged + "|Side=" + (LongExitOK ? "Short" : "Long"));

							if (!MoveBackTarget.ContainsKey(e.Order.Oco))
							MoveBackTarget.Add(e.Order.Oco, OriginalStopPrice);
						}
			
					}
					
				
					if (e.OrderState == OrderState.Working)
					{
						
						string oooocc = e.Order.Oco;
						
						//Print("MoveBackTarget " + MoveBackTarget.Count);
						
						if (MoveBackTarget.ContainsKey(oooocc))
						{
							double prevprice = MoveBackTarget[oooocc];
							//TriggerCustomEvent(o =>
							//	   				{
											
							MoveOrder(e.Order, prevprice, 0, e.Order.Account, 0);		
													
							if (pExitShieldMessages)
							{
								if (!pUseOriginalLocation)
									AddMessage("Profit Target was moved due to 'Exit Shield' features.", 6, Brushes.Goldenrod);
								else
									AddMessage("Profit Target was moved back to its original location due to 'Exit Shield' features.", 6, Brushes.Goldenrod);
								
								
							}
							
							
							
							
										
						}
						
						MoveBackTarget.Remove(oooocc);
				
						//Print("MoveBackTarget3 " + MoveBackTarget.Count);
						
						
					}	
				}
				
								
			}
			
			
			
		
			
			
			if (pCopierMode == "Orders" || pIsATMSelectEnabled)
			{
				
				//NextCloseOrderDisableFollower = false;
				
				//Print(e.OrderState);
				
				
//				if (pCopierIsEnabled)
//				{			
					if (e.OrderState != OrderState.Initialized)
					{
						//Print(SkipNextChangeSubmittedCommand);
						
						if (!SkipNextChangeSubmittedCommand)
						{
						
							ManageDuplicateOrders(e.OrderState, e.Order);
							
							
						}
						SkipNextChangeSubmittedCommand = false;
						
					}
//				}
//				else
//				{
				
					
				if (!pCopierIsEnabled)
				if (e.OrderState == OrderState.Accepted || e.OrderState == OrderState.TriggerPending)
				ChartControl.Dispatcher.InvokeAsync((Action)(() =>
				{
					
	
			
					if (!e.Order.Name.Contains(OneTradeOrderName) && !e.Order.Name.Contains(RefreshOrderName))
						AddMessage(messageoff, 20, Brushes.Goldenrod);
				}));	
					
					
				
				
				
				
//				}
				
				
				
				return;
				
			}
			
			
			
			
			
			if (!pIsCopyBasicFunctionsEnabled)
				return;
			
			
		
			if (pEventToSend != "Order Update")
				return;			
			
	
			
			if (e.OrderState != OrderState.Filled)
				return;
			
			
			MarketPosition MasterExPosition = MarketPosition.Long;
			
			
			
			if (e.Order.IsLong)
				MasterExPosition = MarketPosition.Long;
			if (e.Order.IsShort)
				MasterExPosition = MarketPosition.Short;			
		
	
			
			if (IgnoreNextTradeDueToFillReplace)
			{
				IgnoreNextTradeDueToFillReplace = false;
				//Print("IgnoreNextTradeDueToFillReplace");
				return;
			}
				
						
			
			SendExecutionModeOrders(e.Order.Instrument, MasterExPosition, e.Order, true);
		
					
			
		}
				
		
		
