													}
													
			
			
			
		}
													
													
										
		private AtmStrategy ATMStrategyForFollower(Account aaaaaaa, AtmStrategy SlaveA)
		{
			
			//Print(SlaveA.Brackets.Length);
			
		
										//if (SlaveA.Brackets.Length > 1)
										{
											
											double SlaveExMultiplier = Convert.ToDouble(GetAccountMultiplier(aaaaaaa.Name));
						
											
											//Print(SlaveExMultiplier);
											
											
											if (SlaveExMultiplier == 0)
												SlaveExMultiplier = 0.50;
											if (SlaveExMultiplier == -1)
												SlaveExMultiplier = 0.33;
											if (SlaveExMultiplier == -2)
												SlaveExMultiplier = 0.25;
											if (SlaveExMultiplier == -3)
												SlaveExMultiplier = 0.20;	
						
											int SlaveExQty = 0;
											
											if (pMultiplierMode == "Multiplier")
												SlaveExQty = (int) Math.Round(MasterExQty * SlaveExMultiplier);
											else
												SlaveExQty = (int) SlaveExMultiplier;
											
											SlaveExQty = Math.Max(SlaveExQty, 1);
							
							
											
													double ratio = SlaveExMultiplier / MasterExQty;
															
											
													if (pMultiplierMode == "Multiplier")
													{
														ratio = SlaveExMultiplier;
														
													}
													
													if (ratio != 1)
													{
														
														
														//Print("ratio " + ratio);
														
																											
														
	//													foreach( Bracket bb in SlaveA.Brackets)
	//														totalqqqqq = totalqqqqq + bb.Quantity;
														
														int newq = 0;
														
														int remainingq = SlaveExQty;
														foreach( Bracket bb in SlaveA.Brackets)
														{			
																if (bb.Quantity != 0 && bb.Quantity != bb.Quantity*ratio)
																{	
																	newq = (int) Math.Round(bb.Quantity*ratio);
																	newq = Math.Max(newq,1);
																	newq = Math.Min(newq,remainingq);
																	
																	//Print(newq);
																	
																	bb.Quantity = newq;
																	
																	remainingq = remainingq - newq; 
																}
														}	
														
													}
													
													
//														//	if (SlaveExMultiplier >= 1)
//													foreach( Bracket bb in SlaveA.Brackets)
//													{			
														
//															double changed = bb.Quantity*SlaveExMultiplier;
//															bool isInt = changed == (int)changed;
															
//														if (isInt)
//															if (bb.Quantity != changed)
//															{
													
//																bb.Quantity = (int) changed;
																
//															}	
															
															
////															if (bb.Quantity != 0)
////															if (bb.Quantity != bb.Quantity*SlaveExMultiplier)
////															{														
////																bb.Quantity = bb.Quantity*(int)SlaveExMultiplier;
////															}
//													}	
		
										
										}
			
	
			return SlaveA;
			
			
		}
													
	
		
		private Order PreviousChangePendingOrder = null;
		private double PreviousChangePrice = 0;
		
		private double MovePrice = 0;
		private double NewPrice = 0;
		
		private int SuspendedCount = 0;
		
		private Order TradingViewExitOrder1 = null;
		private Order TradingViewExitOrder2 = null;
		
		private int IgnoreCommands = 0;
		
		
		// OCO strings to ignore cancel commands for (when master target/stop fills, prevent cascading follower exit cancels)
		// Uses Dictionary with timestamp for automatic cleanup of stale entries
		private Dictionary<string, DateTime> IgnoreTheseATMStrategyCancelCommands = new Dictionary<string, DateTime>();
		
		private HashSet<string> AllDuplicateAccountsDisconnected = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
					
		
		
		
		private void ManageDuplicateOrders(OrderState MasterOrderState, Order MasterOrder)
		{
			

			//Print("ManageDuplicateOrders");
			
			
			
			
			// Order-scoped flatten suppression: the master's own flatten "Close"
			// order is never a tradeable signal. Unbounded by time, unlike the
			// pMilliSFE window below — a slow or partial close can't outrun it.
			if (IsMasterFlattenCloseOrder(MasterOrder))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FlattenCloseOrder", "OrderId=" + (MasterOrder != null ? MasterOrder.OrderId : "?") + "|Name=" + (MasterOrder != null ? MasterOrder.Name : "?")); } catch { } }
				return;
			}

			if (DateTime.Now < FlattenEverythingClickedTime.AddMilliseconds(pMilliSFE))
			{
				return;
			}
			if (DateTime.Now < GoalLossFlattenTime.AddMilliseconds(pMilliSFE))
			{
				// Print("GUARD: Blocking order copy — Goal/Loss/Funded flatten in progress.");
				return;
			}
			else
			{
				
			}
			 
			
			//Print("___________ " + MasterOrder.LimitPrice + "  " + MasterOrder.StopPrice + "  " + MasterOrder.OrderState);
			
			
			
			// tradovate issues resolved when moving take profit and stop loss in trading view, whether you are copying trades or not
			
			if (pEnabledTradingViewFix)
			{
				if (MasterOrder.OrderState == OrderState.ChangePending)
				{
					
					PreviousChangePendingOrder = MasterOrder;
					
					if (MasterOrder.OrderType == OrderType.Limit)
					{
						PreviousChangePrice = MasterOrder.LimitPrice;
					}
					else
					{
						PreviousChangePrice = MasterOrder.StopPrice;
					}
					
					//Print(MasterOrder.OrderId);
					SuspendedCount = 0;
					
				}
				
				if (MasterOrder.OrderState == OrderState.Suspended)
					SuspendedCount++;
				
				
				if (MasterOrder.OrderState == OrderState.Working)
				{
					if (SuspendedCount == 1)
					{
					
						//Print("move order back " + PreviousChangePrice);
						
						
						MoveOrder(PreviousChangePendingOrder, PreviousChangePrice, 0, PreviousChangePendingOrder.Account, 0);
						
					}
					
					SuspendedCount = 0;
				}
				
			}
			
			
			
			if (!pCopierIsEnabled)
				return;
			
			
			// store atm for resubmitting rejected orders
			
			if (MasterOrder.OrderState == OrderState.Rejected)
			{
					ATMObject = 	MasterOrder.GetOwnerStrategy();	
				
					if (ATMObject != null)
					if (ATMObject.GetType() == typeof(AtmStrategy))
					//if (ATMObject != null)
					{
						LastNewOrderATM = (AtmStrategy) ATMObject;
						
					}
				
				
				
			}
		
			
		
			//MasterOrder.Rewind(MasterOrder.Account.Connection, "");
			
				Instrument SendInstrument = MasterOrder.Instrument;
					
				
				Instrument MasterExInstrument = SendInstrument;
				Instrument SlaveExInstrument = SendInstrument;
			
				 
				//string thisexinstr = SendInstrument.FullName;
				
			
			
				Instrument MicroInstrument = GetTheInstrument(SendInstrument.FullName, "Micro", false);
				Instrument MiniInstrument = GetTheInstrument(SendInstrument.FullName, "Mini", false);				
							

				
				if (!IsInstrumentTracked(SendInstrument)) return;
				
				 
				bool IsTargetOrStop = MasterOrder.Name.Contains("Stop") || MasterOrder.Name.Contains("Target");
				
				// Sync follower quantities only when master order is in a stable state (not moving, not cancelling)
				// Skip ChangeSubmitted/ChangePending so we don't treat a move as zero quantity and cancel the follower
				bool stableState = MasterOrderState == OrderState.Working || MasterOrderState == OrderState.Accepted;
				if (IsTargetOrStop && stableState && CurrentMasterAccount != null && MasterOrder.Account == CurrentMasterAccount)
				{
					object atmObj = MasterOrder.GetOwnerStrategy();
					if (atmObj != null && atmObj.GetType() == typeof(AtmStrategy))
						SyncATMStrategyExitOrdersToAllFollowers(MasterOrder);
				}
			
				bool CancelState = MasterOrderState == OrderState.CancelSubmitted;
				bool ChangeState = MasterOrderState == OrderState.ChangeSubmitted;
				
				
				
				CancelState = MasterOrderState == OrderState.Cancelled; // modified for tradingview and tradovate
				
				ChangeState = MasterOrderState == OrderState.ChangeSubmitted;				
				
				
				// might help with freezing situations when moving master account order, on simulated accounts
				
//				if (MasterOrder.Account.Provider == Provider.Simulator)
//				{			
//					CancelState = MasterOrderState == OrderState.CancelPending;
//					ChangeState = MasterOrderState == OrderState.ChangePending;
//				}
								
				
				
				
				
				bool FilledState = MasterOrderState == OrderState.Filled;
				
						
									
				
				if (CancelState)
				{
				
//					Print("MASTER " + MasterOrderState + "  " + MasterOrder.OrderId + "  " + MasterOrder.Name);
//					Print("MasterOrder.StopPrice " + MasterOrder.StopPrice);
//					Print("MasterOrder.LimitPrice " + MasterOrder.LimitPrice);		
	
				}
				
				
				
//				bool NewOrderDetected = e.OrderState == OrderState.Accepted || e.OrderState == OrderState.TriggerPending;
				
//				if (e.OrderState == OrderState.Accepted)
//					Print(e.Order.OrderUpdates.Count);
				
					
					
				//NewOrderDetected = e.OrderState == OrderState.Submitted || (e.OrderState == OrderState.TriggerPending && e.Order.OrderUpdates.Count == 2);
				
				
				// works for all order types, detecting the first time they are live
				
				bool AllNewOrders = MasterOrderState == OrderState.Accepted && MasterOrder.OrderUpdates.Count == 3;
				bool SLMNegativeOffsetOrders = MasterOrderState == OrderState.TriggerPending && MasterOrder.OrderUpdates.Count == 2;
				
				bool TradovateAndTradingViewPendingOrder = MasterOrderState == OrderState.Working && MasterOrder.OrderUpdates.Count == 1;
				bool TradovateAndTradingViewMarketOrder = MasterOrderState == OrderState.Filled && MasterOrder.OrderUpdates.Count == 1;
				
				bool TradovateAndTradingViewNewOrder = TradovateAndTradingViewMarketOrder || TradovateAndTradingViewPendingOrder;
				
				// Benedict Jules
				// Unmanaged strategy / generic broker: entry orders may use Accepted+2 or Working+2 instead of Chart Trader's Accepted+3.
				bool StrategyOrGenericEntryOrder = !MasterOrder.Name.Contains("Target") && !MasterOrder.Name.Contains("Stop")
					&& ((MasterOrderState == OrderState.Working && MasterOrder.OrderUpdates.Count == 2)
						|| (MasterOrderState == OrderState.Accepted && MasterOrder.OrderUpdates.Count == 2));
				
				
				if (AllNewOrders && IgnoreNextTradeDueToFillReplace)
				{
					IgnoreNextTradeDueToFillReplace = false;
					return;
				}
				
				
				if (TradovateAndTradingViewMarketOrder)
					FilledState = false;
				
				
				//Print(MasterOrder.OrderUpdates.Count);
				
				
				bool TradingViewNewTakeProfitOrStopLoss = false;
				int CurrentSuspended = 0;
				
				// 2 states after suspended goes into working, at that point we copy the orders
				
				if (pEnableTradingViewDetections)
				{
				
					int countssss = 0;
					
					foreach (OrderEventArgs orrrr in MasterOrder.OrderUpdates.ToList()) //.Reverse()) // loop through all events
					{
						countssss++;
						
						if (orrrr.OrderState == OrderState.Suspended) // get prices the last time change was pending
						{		
							CurrentSuspended = countssss;
							//Print("Found Suspended " + CurrentSuspended);
						}
						
					
						
						
					}
					
				}
				
				TradingViewNewTakeProfitOrStopLoss = CurrentSuspended != 0 && MasterOrderState == OrderState.Working && MasterOrder.OrderUpdates.Count == CurrentSuspended + 2;
				
			
				if (TradingViewNewTakeProfitOrStopLoss)
				{
					
					if (TradingViewExitOrder1 == null)
					{
						TradingViewExitOrder1 = MasterOrder;
					}
					else if (TradingViewExitOrder2 == null)
					{
						TradingViewExitOrder2 = MasterOrder;
					}					
				}
					
				
					// unable to set master account oco for orders, but may not be necessary
					
//									if (TradingViewNewTakeProfitOrStopLoss)
//									{
//										string TVOCO = "TV" + "-" + RandomString(10) + "-" + AccountNameToRandom[MasterOrder.Account.Name];
										
//										if (TradingViewExitOrders.ContainsKey(MasterOrder.Account.Name))
//										{
//											TVOCO = TradingViewExitOrders[MasterOrder.Account.Name];
//											TradingViewExitOrders.Remove(MasterOrder.Account.Name);
//										}
//										else
//										{
//											TradingViewExitOrders.Add(MasterOrder.Account.Name, TVOCO);
											
//										}
									
//										Print(TVOCO);
										
//										MasterOrder.Oco = TVOCO;
								
										
//									}
									
							
//				if (TradingViewNewTakeProfitOrStopLoss)
//				{
				
//					string TVOCO = pTVOCOPrefix + "-" + RandomString(10) + "-" + AccountNameToRandom[MasterOrder.Account.Name];
//					TVOCO = pTVOCOPrefix + "-" + RandomString(10);
					
//					CancelAndReplaceOrder(MasterOrder, TVOCO);
					
//					TradingViewNewTakeProfitOrStopLoss = false;					
					
					
//				}
				
				
				
				
				//if (TradovateAndTradingViewPendingOrder || TradingViewNewTakeProfitOrStopLoss)
				
				// convert pending orders in tradingview to target and stop loss orders  Xavier Tang <tangweichang@hotmail.com>
				
				
				if (pEnableTradingViewDetections)
				if (pTradingViewExitDetection != "None")
				if (TradovateAndTradingViewPendingOrder)
				{
				
					//Print("TradovateAndTradingViewPendingOrder" + MasterOrder.OrderType.ToString());
					
					Position CurrentPosition = MasterOrder.Account.GetPosition(MasterOrder.Instrument.Id);
					
					double CurrentAveragePrice = 0;
					double CurrentPositionSize = 0;
					
					double NewStopPrice = 0;
					int ThisStopTicks = 80;
					double TargetSize = 0;
					double existingstopprice = 0;
						
						
					if (CurrentPosition != null)
					{
						
						
						CurrentAveragePrice = CurrentPosition.AveragePrice;
						CurrentPositionSize = CurrentPosition.Quantity;
						
						OrderAction exitorderdir = OrderAction.Buy;
						
						if (CurrentPosition.MarketPosition == MarketPosition.Long)
						{
						
							exitorderdir = OrderAction.Sell;
						
						}
						if (CurrentPosition.MarketPosition == MarketPosition.Short)
						{
						
							
							
						}			
						
						
						int totalcurrentbrackets = TVTotalExitBrackets (MasterOrder.Account, exitorderdir);
						string stopname = "Stop" + (totalcurrentbrackets+1).ToString();
						string targetname = "Target" + (totalcurrentbrackets+1).ToString();
						
						if (pTradingViewExitDetection == "Limit")
						{
						
							// new limit order detection, with the first direction to be a target
							
							if (MasterOrder.OrderType == OrderType.Limit)
							if (MasterOrder.OrderAction == exitorderdir)
	
							{
								
								// check if total current position is still less than current targets + potential targets
								
								int totalpotentialtargetq = TVTargetQty (MasterOrder.Account, exitorderdir) + MasterOrder.Quantity;
								
								if (totalpotentialtargetq <= CurrentPositionSize)
								{
									
		
									TargetSize = CurrentAveragePrice - MasterOrder.LimitPrice;
									NewStopPrice = CurrentAveragePrice + TargetSize;
									
//									if (exitorderdir == OrderAction.Sell)
//									{
//										TargetSize = MasterOrder.LimitPrice - CurrentAveragePrice;
//										NewStopPrice = CurrentAveragePrice - TargetSize;
										
//										//NewStopPrice = CurrentAveragePrice - ThisStopTicks*MasterOrder.Instrument.MasterInstrument.TickSize;
										
//									}
//									if (exitorderdir == OrderAction.Buy)
//									{	
//										TargetSize = CurrentAveragePrice - MasterOrder.LimitPrice;
//										NewStopPrice = CurrentAveragePrice + TargetSize;
										
//										//NewStopPrice = CurrentAveragePrice + ThisStopTicks*MasterOrder.Instrument.MasterInstrument.TickSize;									
//									}	
									
									
									
									
									if (pMatchStopLossPrices)
									{
										existingstopprice = TVStopPrice(MasterOrder.Account, exitorderdir);
										
										
										if (existingstopprice != 0)
											NewStopPrice = existingstopprice;
									}
									
									string TVOCO = pTVOCOPrefix + "-" + RandomString(10) + "-" + GetAccountRandomSuffix(MasterOrder.Account.Name);
									TVOCO = pTVOCOPrefix + "-" + RandomString(10);

									//Print(NewStopPrice);
									
									
									
									CancelAndReplaceOrder(MasterOrder, TVOCO, targetname);
									PlaceTradingViewStopOrder(MasterOrder, NewStopPrice, TVOCO, stopname);
									
									TradovateAndTradingViewNewOrder = false;
									
								}
								
							}
						
							
						}
		
						
						if (pTradingViewExitDetection == "Bracket")
						{
						
							
							string ordertyp = "Limit";
							
						
							
							
							
							if (MasterOrder.OrderType == OrderType.Limit)
							{
								ordertyp = "Stop";
								
							}
							
							if (MasterOrder.OrderType == OrderType.StopMarket || MasterOrder.OrderType == OrderType.StopLimit)
							{
								
								ordertyp = "Limit";		
	
							}
							
							
							
							
							
							Order OrderFound = OrderExists(MasterOrder.Account, ordertyp, MasterOrder.Quantity, exitorderdir);
								
							if (OrderFound != null)
							{
								
								//Print("match found");
								
								
								string TVOCO = pTVOCOPrefix + "-" + RandomString(10) + "-" + GetAccountRandomSuffix(MasterOrder.Account.Name);
								TVOCO = pTVOCOPrefix + "-" + RandomString(10);
								
								// replace both orders, adding oco
								
								CancelAndReplaceOrder(OrderFound, TVOCO, targetname);
								CancelAndReplaceOrder(MasterOrder, TVOCO, targetname);
								
								TradovateAndTradingViewNewOrder = false;
								//TradingViewNewTakeProfitOrStopLoss = false;
						
									
							}		
							
							
						}
						
						
							
					}
					
					
					
				}
									
				
				bool NewOrderDetected = AllNewOrders || SLMNegativeOffsetOrders || TradovateAndTradingViewNewOrder || TradingViewNewTakeProfitOrStopLoss || StrategyOrGenericEntryOrder;
				//NewOrderDetected = AllNewOrders || SLMNegativeOffsetOrders || TradovateAndTradingViewNewOrder;
				
						// prevent loop - basically do NOT copy master account orders that have DAA on them
				
				if (MasterOrder.Name.Contains(MarketOrderName))
					NewOrderDetected = false;
				
				if (MasterOrder.Name.Contains(OneTradeOrderName))
					NewOrderDetected = false;
			
				if (MasterOrder.Name.Contains(RefreshOrderName))
					NewOrderDetected = false;				
					
							
				if (IgnoreExecutionUntilFlat)
				{
					NewOrderDetected = false;		
					CancelState = false;
					ChangeState = false;
					FilledState = false;					
				}
				
					
					
			//	NewOrderDetected = e.OrderState == OrderState.Initialized;
				
				
				//Print("NewOrderDetected " + NewOrderDetected);
				
				
				bool Simplify = true;
				
				
				bool IsTargetOrStopLive = IsTargetOrStop && (MasterOrderState == OrderState.Accepted || MasterOrderState == OrderState.Working);
				if (NewOrderDetected || CancelState || ChangeState || FilledState || IsTargetOrStopLive) // || e.OrderState == OrderState.Working)
				{
				
						
//					IgnoreCommands--;
			
//					if (IgnoreCommands >= 0)
//						return;
					
					
					// Print("NewOrderDetected");
					//
					//or = MasterOrder;
						
							
					NewOrder = null;
				
					ATMObject = 	MasterOrder.GetOwnerStrategy();	
					
					NewATM = null;
					
					if (ATMObject != null)
					if (ATMObject.GetType() == typeof(AtmStrategy))
						NewATM = (AtmStrategy) ATMObject;
					// When Buy Mkt clicked 2-3x quickly, order may fire Accepted before NinjaTrader links it to ATM. Resolve from master Strategies by matching InitialEntryOrder.
					if (NewATM == null && CurrentMasterAccount != null && MasterOrder.Account == CurrentMasterAccount)
					{
						foreach (object aaa in CurrentMasterAccount.Strategies.ToList())
						{
							if (aaa == null || aaa.GetType() != typeof(AtmStrategy)) continue;
							AtmStrategy atm = (AtmStrategy)aaa;
							if (atm.InitialEntryOrder == MasterOrder)
							{
								NewATM = atm;
								break;
							}
						}
						// "Switched ATM then clicked Buy/Sell Mkt": NT has just created a new ATM on the
						// master (ATM2) but hasn't linked this MasterOrder to it yet, so GetOwnerStrategy
						// returns null AND InitialEntryOrder is still null. Find the freshly-created
						// unattached ATM (iterate in reverse = most recent first) and use it. Without this
						// layer, the time-based fallback below picks up the PREVIOUS ATM (ATM1) because it
						// requires a non-null entry, and LastNewOrderATM is also stale.
						if (NewATM == null && !MasterOrder.Name.Contains("Target") && !MasterOrder.Name.Contains("Stop"))
						{
							var stratsSnap = CurrentMasterAccount.Strategies.ToList();
							for (int i = stratsSnap.Count - 1; i >= 0; i--)
							{
								object aaa = stratsSnap[i];
								if (aaa == null || aaa.GetType() != typeof(AtmStrategy)) continue;
								AtmStrategy atm = (AtmStrategy)aaa;
								Order entry = atm.InitialEntryOrder;
								// Unattached = no entry order yet, or entry still in a pre-working state.
								bool unattached = entry == null;
								if (!unattached)
								{
									OrderState es = entry.OrderState;
									unattached = (es == OrderState.Initialized || es == OrderState.Submitted);
								}
								if (unattached)
								{
									NewATM = atm;
									if (pDebugOrderMatching)
										Print("[DAA OrdersMode] Resolved NewATM via unattached-ATM fallback (ATM switch) for master order '" + MasterOrder.Name + "'");
									break;
								}
							}
						}
						// Last-resort fallback: most recent ATM on master for same instrument/action with a live entry.
						if (NewATM == null && !MasterOrder.Name.Contains("Target") && !MasterOrder.Name.Contains("Stop"))
						{
							AtmStrategy bestAtm = null;
							DateTime bestTime = DateTime.MinValue;
							foreach (object aaa in CurrentMasterAccount.Strategies.ToList())
							{
								if (aaa == null || aaa.GetType() != typeof(AtmStrategy)) continue;
								AtmStrategy atm = (AtmStrategy)aaa;
								Order entry = atm.InitialEntryOrder;
								if (entry == null || entry.Instrument == null || MasterOrder.Instrument == null || entry.Instrument.Id != MasterOrder.Instrument.Id || entry.OrderAction != MasterOrder.OrderAction) continue;
								if (entry.OrderState == OrderState.Cancelled || entry.OrderState == OrderState.Rejected) continue;
								if (entry.Time > bestTime) { bestTime = entry.Time; bestAtm = atm; }
							}
							if (bestAtm != null)
								NewATM = bestAtm;
						}
					}
					
					// Current order's ATM name — use this (not LastAddATMName) so each ATM's sync only touches that ATM's follower orders
					string currentAtmName = (NewATM != null) ? (NewATM.DisplayNameExtended ?? NewATM.DisplayName ?? "") : "";
					
					// is target or stop only if the order is attached to an ATM Strategy
					
					if (NewATM == null)
						IsTargetOrStop = false;
					
			
				//	Print("NewATM.Id " + NewATM.Id);
					
					
					// Print("NewOrderDetected 2");

					MasterExQty = MasterOrder.Quantity;
					
					
					//Print( "AAAAAAAAA MasterOrder.Name    " + MasterOrder.Name + " " + MasterOrder.Quantity);
									
			
					// added to store last quantity for orders generated from running strategy, seems to submit and not loop through slave accounts in a row
					
					//if (!Simplify)
					
					
					if (MasterOrderNameToQty.ContainsKey(MasterOrder.Name))
					{
						MasterOrderNameToQty[MasterOrder.Name] = MasterOrder.Quantity;
					}
					else
					{
						MasterOrderNameToQty.Add(MasterOrder.Name, MasterOrder.Quantity);
					
					}
					

					
					bool IsFundedOrAtDailyGoalLoss = false;
				
					
					
					NextOrderID = 0;
				
					//Print("NewOrderDetected 3");
					
					
					
					AllDuplicateAccountsDisconnected.Clear();
					
					
//					foreach (string sssss in AllDuplicateAccounts)
//					{
					
//						Account SlaveAccount = AccountFromName(sssss);
//						if (SlaveAccount.ConnectionStatus == ConnectionStatus.Connected)
						
//						{
//							AllDuplicateAccountsConnected.Add(sssss);
//						}
						
						
//					}
						
//					Print("AllDuplicateAccountsConnected " + AllDuplicateAccountsConnected.Count);
					
					// List<string> fractionalWarningOrdersMode = new List<string>();
//					foreach (string sssss in AllDuplicateAccountsConnected)
					foreach (string sssss in AllDuplicateAccounts)
					{
						// Safety pass: isolate per-follower failures so one bad account (disconnected mid-tick,
						// null ATM clone, rejected submit, etc.) cannot abort copies to the remaining accounts.
						try
						{


						//Print(sssss + " " + "1");

						Account SlaveAccount = AccountFromName(sssss);
						
						if (SlaveAccount == null)
						{
							AllDuplicateAccountsDisconnected.Add(sssss);
							continue;
						}
						
						
						
						// Goal/Loss/Funded latch — block NEW ENTRIES only. Exits (Stop/Target
						// orders attached to an ATM, or whose name carries "Stop"/"Target")
						// must still propagate so a latched follower's existing position can
						// be closed. Mirrors the executions-mode fix (Ron 2026-05-04 incident).
						if (HasFollowerHitGoalLossOrFunded(SlaveAccount))
						{
							if (!IsTargetOrStop)
							{
								if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_HitGoalLossFunded", "Account=" + sssss + "|Path=Orders"); } catch { } }
								continue;
							}
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "ALLOW_EXIT_DESPITE_HitGoalLossFunded", "Account=" + sssss + "|Path=Orders|OrderName=" + MasterOrder.Name); } catch { } }
						}
						// Check if this follower was flattened by a Goal/Loss/Funded trigger
						DateTime _latchTime;
						if (GoalLossFlattenLatch.TryGetValue(sssss, out _latchTime))
						{
							if (!IsTargetOrStop)
							{
								// Print("GUARD: Skipping order copy for " + sssss + " — account was flattened by Goal/Loss/Funded at " + _latchTime);
								if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_GoalLossLatch", "Account=" + sssss + "|Path=Orders|LatchedAt=" + _latchTime); } catch { } }
								continue;
							}
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "ALLOW_EXIT_DESPITE_GoalLossLatch", "Account=" + sssss + "|Path=Orders|LatchedAt=" + _latchTime + "|OrderName=" + MasterOrder.Name); } catch { } }
						}

						
						
//						if (IsAccountFinishedAndFlat(sssss))
//							continue;
						
						string currentaccountmode = string.Empty;					
		
						if (pIsATMSelectEnabled)
						{
							currentaccountmode = GetAccountMode(sssss);
							
