// Add this P/Invoke for native thread ID
//[System.Runtime.InteropServices.DllImport("kernel32.dll")]
//private static extern uint GetCurrentThreadId();



		private void FastSubmit2()
		{
			// Snapshot and clear immediately to avoid "Collection was modified; enumeration operation may not execute"
			// when re-entrant OrderUpdate adds to accountAtmMap during AsParallel().ForAll iteration.
			List<KeyValuePair<Order, (Account account, AtmStrategy thisatm)>> snapshot = accountAtmMap.ToList();
			accountAtmMap.Clear();
			if (snapshot.Count == 0)
				return;

			// Batch all ATM starts into a single Dispatcher call — avoids per-account
			// Dispatcher.Invoke overhead and eliminates Thread.Sleep delays.
			// ATM strategies must start on the UI thread to avoid being abandoned.
			Application.Current.Dispatcher.Invoke(() =>
			{
				foreach (var kvp in snapshot)
				{
					var order = kvp.Key;
					var (account, thisatm) = kvp.Value;

					if (thisatm != null)
						NewATMStrategyStart(thisatm, order);
					else
					{
						SetOrderToManual(order);
						account.Submit(new[] { order });
					}
					// Latency: the fast-submission path defers the real Submit to here,
					// so this is its dispatch endpoint / confirmation registration anchor.
					if (account != null)
						RecordCopierLatency(account.Name, order);
				}
			});
					

			

			

			
			
		}
				
		
		
		
		
		private readonly Queue<(Order order, AtmStrategy atmStrategy)> _atmQueue = new Queue<(Order, AtmStrategy)>();
		private volatile bool _isProcessing = false;

		private readonly object _atmLock = new object();

		private Dictionary<Order, (Account account, AtmStrategy thisatm)> accountAtmMap = 
   		new Dictionary<Order, (Account, AtmStrategy)>();
		private Dictionary<Order, AtmStrategy> _pendingAtmAttachments = new Dictionary<Order, AtmStrategy>();
		
	
		// Tracks expected follower positions to handle rapid executions before fills confirm.
		// Key: "AccountName::InstrumentFullName", Value: signed position (positive=long, negative=short)
		private ConcurrentDictionary<string, int> ExpectedFollowerPositions = new ConcurrentDictionary<string, int>();
		/// <summary>
		/// Latches to true when a follower is flattened by Daily Goal, Daily Loss, or Funded Goal.
		/// Prevents execution-copy orders from being sent to this account until the latch is cleared.
		/// Key = account name. Value = DateTime when the latch was set.
		/// Cleared when the user manually re-enables the goal/loss for the account.
		/// </summary>
		private ConcurrentDictionary<string, DateTime> GoalLossFlattenLatch = new ConcurrentDictionary<string, DateTime>();
		// Tracks master position internally from executions to avoid stale GetPosition() values.
		private Dictionary<string, int> TrackedMasterPosition = new Dictionary<string, int>();
		// UTC tick stamp of the last processed master execution. Drives the idle
		// gate for the TrackedMasterPosition resync (see ResyncTrackedMasterPositionFromLive).
		private long _lastMasterFillTicksUtc = 0;
		// The master must be quiet this long before an idle resync may read live
		// positions — long enough that no partial-fill burst is still in flight.
		private const long TrackerResyncIdleTicks = TimeSpan.TicksPerSecond * 5;
		// Master quiet-time required before a master PositionUpdate is trusted to
		// reconcile TrackedMasterPosition. Shorter than the idle-resync gate above:
		// OnPositionUpdate3 hands us the broker's own settled position, so we only
		// need to outlast a partial-fill burst's executions draining — not the
		// GetPosition() mid-burst ambiguity the 5s gate guards against.
		private const long TrackerReconcileSettleTicks = TimeSpan.TicksPerSecond * 1;
		// Throttle so the idle resync is evaluated at most every 2s.
		private DateTime _nextTrackerResync = DateTime.MinValue;

		// A follower still holding an instrument the master has exited is flattened
		// by the OnTimerTick3 backstop once the master has been flat and quiet this
		// long - long enough that any follower copy order the copier submitted for
		// the master's final fills has filled or terminated, so the follower's live
		// position is settled and the stranding unambiguous. Observed follower fill
		// latency in the field is ~130ms; 1500ms is a wide margin over that.
		private const long ExecBackstopMasterQuietTicks = TimeSpan.TicksPerMillisecond * 1500;
		// Per follower-account+instrument cooldown for the stranded-follower backstop
		// (key "AccountName@InstrumentId") so a flatten the broker rejects cannot
		// re-fire on every timer tick.
		private Dictionary<string, DateTime> _execBackstopLastFlatten = new Dictionary<string, DateTime>();

		// FIFO queue of master executions awaiting serialized processing.
		// OnExecutionUpdate3 enqueues, then a single drainer (guarded by _isDrainingMasterExecutions)
		// processes them strictly in arrival order. This removes the race where rapid events could
		// cause TrackedMasterPosition live-resync to snap to a stale/ahead GetPosition() value and
		// blow the follower delta math (classic "exit then reverse entry" bug).
		private readonly ConcurrentQueue<ExecutionEventArgs> _masterExecutionQueue = new ConcurrentQueue<ExecutionEventArgs>();
		private int _isDrainingMasterExecutions = 0;

		// Called anywhere we wipe the tracked master state (account switch, reset, flatten, shutdown).
		// Also drops any queued-but-unprocessed executions so we don't replay stale events against fresh state.
		// Suppress logging when both counters are 0 AND the previous reset was also 0,0 — those zero-state
		// resets fire 4× per startup from different sites and just pad the log without telling us anything.
		private int _lastResetTrackedCount = -1;
		private int _lastResetQueueCount = -1;
		private void ResetMasterExecutionState()
		{
			int _tc = TrackedMasterPosition.Count;
			int _qc = _masterExecutionQueue.Count;
			bool _suppress = (_tc == 0 && _qc == 0 && _lastResetTrackedCount == 0 && _lastResetQueueCount == 0);
			if (_diagLog != null && !_suppress)
				_diagLog.Log("COPIER", "RESET_MASTER_EXECUTION_STATE", "TrackedPositions=" + _tc + "|QueuePending=" + _qc);
			_lastResetTrackedCount = _tc;
			_lastResetQueueCount = _qc;
			TrackedMasterPosition.Clear();
			while (_masterExecutionQueue.TryDequeue(out _)) { }
			lock (_sessionLiveOrderIds) { _sessionLiveOrderIds.Clear(); }
		}

		// One-shot diagnostic dump of the host timezone configuration. Called
		// when the copier is armed and from the SKIP paths in OnExecutionUpdate3.
		// Without this we were inferring the user's zone from a 5h-on-the-nose
		// staleness delta, which only worked because the broker happened to
		// stamp times in EST. Belt-and-suspenders: surface ground truth so the
		// next time something like this comes in, the diag file already has it.
		private void LogTimezoneSnapshot(string context)
		{
			if (_diagLog == null) return;
			try
			{
				_diagLog.Log("COPIER", "TZ_SNAPSHOT",
					"Context=" + context
					+ "|LocalId=" + TimeZoneInfo.Local.Id
					+ "|BaseUtcOffset=" + TimeZoneInfo.Local.BaseUtcOffset
					+ "|UtcNow=" + DateTime.UtcNow.ToString("o")
					+ "|LocalNow=" + DateTime.Now.ToString("o"));
			}
			catch { }
		}

		// Re-seed TrackedMasterPosition from the master account's live positions.
		// Called when the copier is turned ON (main-button toggle, override-completed
		// transition) so that any open position the master is already holding is
		// reflected in the tracked state. Without this, toggling OFF then ON during
		// a trade leaves TrackedMasterPosition empty; when the master later exits,
		// the delta math computes IsFinalExit=false (tracked goes from 0 → -N
		// instead of +N → 0) and followers are never flattened.
		//
		// Idempotent: only populates entries that aren't already present, so if
		// the drainer has already stamped a value from a recent execution we don't
		// overwrite it with a potentially stale live-position snapshot.
		private void SeedTrackedMasterPositionFromLive()
		{
			try
			{
				if (CurrentMasterAccount == null) return;
				if (CurrentMasterAccount.Positions == null) return;

				int _seeded = 0;
				foreach (Position pp in CurrentMasterAccount.Positions)
				{
					if (pp == null || pp.Instrument == null) continue;
					if (pp.MarketPosition == MarketPosition.Flat) continue;

					string _key = pp.Instrument.FullName;
					if (TrackedMasterPosition.ContainsKey(_key)) continue;

					int _signed = pp.MarketPosition == MarketPosition.Short
						? -pp.Quantity
						: pp.Quantity;
					TrackedMasterPosition[_key] = _signed;
					_seeded++;

					if (_diagLog != null)
					{
						try
						{
							_diagLog.Log("COPIER", "SEED_TRACKED_POS",
								"Instrument=" + _key
								+ "|Signed=" + _signed
								+ "|RawQty=" + pp.Quantity
								+ "|Side=" + pp.MarketPosition);
						}
						catch { }
					}
				}

				if (_diagLog != null && _seeded > 0)
				{
					try { _diagLog.Log("COPIER", "SEED_COMPLETE", "Count=" + _seeded); } catch { }
				}
			}
			catch (Exception _seedEx)
			{
				try { if (_diagLog != null) _diagLog.Log("COPIER", "SEED_ERR", _seedEx.Message); } catch { }
			}
		}

		// Drift safety net. Snaps TrackedMasterPosition back to the master account's
		// actual live positions. Only ever called from OnTimerTick3 once the master
		// has been idle past TrackerResyncIdleTicks, so GetPosition() is guaranteed
		// settled (no partial-fill burst in flight). Takes the master-execution
		// drainer interlock so it can never race ProcessMasterExecution's writes,
		// and bails if any execution is queued so it can never double-count a fill
		// that landed in the same instant. Any drift, from any cause, therefore
		// self-heals within a few seconds of the master going quiet.
		private void ResyncTrackedMasterPositionFromLive()
		{
			if (Interlocked.CompareExchange(ref _isDrainingMasterExecutions, 1, 0) != 0)
				return;
			try
			{
				// A queued execution means the master isn't truly idle: a live read
				// now could include a fill the drainer is about to add again. Skip;
				// the next idle tick retries against a consistent state.
				if (!_masterExecutionQueue.IsEmpty)
					return;
				if (CurrentMasterAccount == null || CurrentMasterAccount.Positions == null)
					return;

				Dictionary<string, int> _live = new Dictionary<string, int>();
				foreach (Position mp in CurrentMasterAccount.Positions)
				{
					if (mp == null || mp.Instrument == null) continue;
					if (mp.MarketPosition == MarketPosition.Flat) continue;
					_live[mp.Instrument.FullName] =
						mp.MarketPosition == MarketPosition.Short ? -mp.Quantity : mp.Quantity;
				}

				// Re-check after the live read: if an execution enqueued while we
				// were snapshotting, the snapshot may straddle that fill — discard it.
				if (!_masterExecutionQueue.IsEmpty)
					return;

				// Correct every tracked entry that disagrees with live, including
				// stale non-zero entries for instruments the master is now flat in.
				foreach (string _key in new List<string>(TrackedMasterPosition.Keys))
				{
					int _liveVal;
					if (!_live.TryGetValue(_key, out _liveVal)) _liveVal = 0;
					int _tracked = TrackedMasterPosition[_key];
					if (_tracked != _liveVal)
					{
						TrackedMasterPosition[_key] = _liveVal;
						if (_diagLog != null)
						{
							try { _diagLog.Log("COPIER", "TRACKED_RESYNC", "Instrument=" + _key + "|Was=" + _tracked + "|Now=" + _liveVal); }
							catch { }
						}
					}
				}

				// Add entries for instruments the master holds but we never tracked.
				foreach (KeyValuePair<string, int> _kv in _live)
				{
					if (TrackedMasterPosition.ContainsKey(_kv.Key)) continue;
					TrackedMasterPosition[_kv.Key] = _kv.Value;
					if (_diagLog != null)
					{
						try { _diagLog.Log("COPIER", "TRACKED_RESYNC", "Instrument=" + _kv.Key + "|Was=untracked|Now=" + _kv.Value); }
						catch { }
					}
				}
			}
			catch { }
			finally
			{
				Interlocked.Exchange(ref _isDrainingMasterExecutions, 0);
			}

			// An execution may have enqueued while we held the interlock; its own
			// DrainMasterExecutionQueue call would have bailed on the busy flag.
			// Drain it now so it isn't stranded until the next master fill.
			if (!_masterExecutionQueue.IsEmpty)
				DrainMasterExecutionQueue();
		}

		// Reconcile TrackedMasterPosition against the master's own PositionUpdate —
		// NinjaTrader's authoritative, settled position for the account. Called
		// from OnPositionUpdate3 on every master position event. The idle resync
		// in OnTimerTick3 does the same job but only after 5s of silence; this
		// closes the window so an execution-accumulator drift cannot survive into
		// the next trade's follower sizing. Same interlock + queue guards as
		// ResyncTrackedMasterPositionFromLive so it can never race the execution
		// drainer or double-count a fill that is still in flight.
		private void ReconcileTrackedMasterFromPositionUpdate(Position mp)
		{
			if (mp == null || mp.Instrument == null) return;

			// Settle gate: while the master is actively filling, the accumulator in
			// ProcessMasterExecution is the live source of truth and a PositionUpdate
			// can lag a fill the drainer has already applied. Only trust the update
			// once fills have been quiet briefly.
			long _lastFill = Interlocked.Read(ref _lastMasterFillTicksUtc);
			if (_lastFill != 0 && (DateTime.UtcNow.Ticks - _lastFill) < TrackerReconcileSettleTicks)
				return;

			// Never race ProcessMasterExecution's writes. A busy drainer is already
			// updating the tracker — skip; the next position tick will retry.
			if (Interlocked.CompareExchange(ref _isDrainingMasterExecutions, 1, 0) != 0)
				return;
			try
			{
				// Only reconcile when no execution is queued: one in flight means the
				// snapshot could straddle a fill the drainer is about to apply on top
				// of whatever we write, double-counting it. Note we never return from
				// inside this try — the drain after the finally must always run so a
				// fill that enqueued while we held the interlock isn't stranded.
				if (_masterExecutionQueue.IsEmpty)
				{
					int _live = mp.MarketPosition == MarketPosition.Short ? -mp.Quantity : mp.Quantity;
					string _key = mp.Instrument.FullName;

					int _tracked;
					bool _have = TrackedMasterPosition.TryGetValue(_key, out _tracked);
					bool _needWrite = _have ? (_tracked != _live) : (_live != 0);

					// Re-check: a fill may have enqueued while we were reading. Its
					// ProcessMasterExecution applies on top of what we write, so
					// writing now would double-count it — skip, the next tick retries.
					if (_needWrite && _masterExecutionQueue.IsEmpty)
					{
						TrackedMasterPosition[_key] = _live;
						if (_diagLog != null)
						{
							try
							{
								_diagLog.Log("COPIER", "TRACKED_RESYNC_POSUPD",
									"Instrument=" + _key
									+ "|Was=" + (_have ? _tracked.ToString() : "untracked")
									+ "|Now=" + _live);
							}
							catch { }
						}
					}
				}
			}
			catch { }
			finally
			{
				Interlocked.Exchange(ref _isDrainingMasterExecutions, 0);
			}

			// A fill may have enqueued while we held the interlock; its own
			// DrainMasterExecutionQueue call would have bailed on the busy flag.
			if (!_masterExecutionQueue.IsEmpty)
				DrainMasterExecutionQueue();
		}

		private string GetExpectedPosKey(string accountName, string instrumentFullName)
		{
			return accountName + "::" + instrumentFullName;
		}
		/// <summary>
		/// Clears all ExpectedFollowerPositions entries for a given account name.
		/// Called when a Goal/Loss/Funded flatten resets the account to flat.
		/// </summary>
		private void ClearExpectedFollowerPositionsForAccount(string accountName)
		{
			foreach (var key in ExpectedFollowerPositions.Keys)
			{
				if (key.StartsWith(accountName + "::"))
				{
					ExpectedFollowerPositions[key] = 0;
				}
			}
		}

		private int GetTrackedMasterPosition(string instrumentFullName)
		{
			if (TrackedMasterPosition.TryGetValue(instrumentFullName, out int pos))
				return pos;
			return 0;
		}

		/// <summary>
		/// Set the Goal/Loss/Funded latch for an account and log the transition.
		/// Centralizes latch additions so every entry is observable in the diag log.
		/// </summary>
		private void SetGoalLossLatch(string accountName, string reason)
		{
			if (string.IsNullOrEmpty(accountName)) return;
			DateTime now = DateTime.Now;
			bool wasAlreadyLatched = GoalLossFlattenLatch.ContainsKey(accountName);
			GoalLossFlattenLatch[accountName] = now;
			if (_diagLog != null)
			{
				try
				{
					_diagLog.Log("RISK", "LATCH_ADD",
						"Account=" + accountName
						+ "|Reason=" + reason
						+ "|At=" + now.ToString("HH:mm:ss.fff")
						+ "|WasAlreadyLatched=" + wasAlreadyLatched);
				}
				catch { }
			}
		}

		/// <summary>
		/// Remove the Goal/Loss/Funded latch for an account and log the transition.
		/// Used by the auto-clear path in OnPositionUpdate3 once a latched account
		/// reaches flat (with a small grace window so a partial-fill flutter doesn't
		/// unlatch prematurely).
		/// </summary>
		private void ClearGoalLossLatch(string accountName, string reason)
		{
			if (string.IsNullOrEmpty(accountName)) return;
			DateTime latchedAt;
			if (!GoalLossFlattenLatch.TryRemove(accountName, out latchedAt)) return;
			if (_diagLog != null)
			{
				try
				{
					_diagLog.Log("RISK", "LATCH_REMOVE",
						"Account=" + accountName
						+ "|Reason=" + reason
						+ "|LatchedAt=" + latchedAt.ToString("HH:mm:ss.fff")
						+ "|HeldMs=" + (long)(DateTime.Now - latchedAt).TotalMilliseconds);
				}
				catch { }
			}
		}

		// Grace window before auto-clearing a latch on observed-flat. Avoids
		// unlatching during the same flatten flurry that set the latch (NT8 emits
		// multiple PositionUpdate events with Qty=0 transitions during a multi-leg
		// flatten — the first one shouldn't clear the latch).
		private const int LatchAutoClearGraceMs = 3000;
		
