		private void CloseExistingAtmStrategies(Account aaaaaaa)
		{
			
					
						TotalStrategies = 0;
			
			
						foreach (Account acct in Account.All.ToList())
						{
							bool ormaster = acct == CurrentMasterAccount && pResubmitMaster;
							if (ormaster || AllDuplicateAccounts.Contains(acct.Name))
							if (acct.Strategies.Count > 0)
							{
								
								int slot = 0;
								int slotremove = -1;
								AtmStrategy FinalATMStrategy2 = null;
								string eventt = acct.Name;
								foreach (object aaa in acct.Strategies)
								{								
									if (aaa.GetType() == typeof(AtmStrategy))
										FinalATMStrategy2 = (AtmStrategy) aaa;	
										bool AllFlat = true;
										bool TimeQ = true;
									
									
									//FinalATMStrategy2.close
									
										if (FinalATMStrategy2 != null)
										{
											
											
											foreach (Position PP in FinalATMStrategy2.Positions)
											{
													if (PP != null)
												if (PP.MarketPosition != MarketPosition.Flat)
												{
													AllFlat = false;
												}
											}
											if (FinalATMStrategy2.Executions.Count == 0)
												TimeQ = false;
											int brak = 1;
											if (TimeQ)
											{
												foreach( Bracket bb in FinalATMStrategy2.Brackets)
												{
													if (FinalATMStrategy2.GetTargetOrders(brak).Count != 0 || FinalATMStrategy2.GetStopOrders(brak).Count != 0)
													TimeQ = false;
													brak++;
												}
											}
											foreach (Execution EE in FinalATMStrategy2.Executions)
											{
												if (DateTime.Now.Ticks < EE.Time.AddSeconds(5).Ticks)
												{
													TimeQ = false;
												}
												break;		
											}
											
											
											AllFlat = true;
											TimeQ = true;
											
											if (AllFlat && TimeQ)
											{
												eventt = acct.Name + " " + FinalATMStrategy2.DisplayName;
												slotremove = slot;	
												TotalStrategies = TotalStrategies + 1;
											}
											
											//Print(eventt);
											
										}
										slot++;
									
								}			
								if (slotremove != -1)
								{				
									acct.Strategies.RemoveAt(slotremove);
								}
								if (TotalStrategies == 0)
								{
									PositionsZeroStartTime = DateTime.MinValue;
								}
							}
						}
			
			// Print("Total ATMs " + aaaaaaa.Name + " " + TotalStrategies);
			
		}		

		
				
			
					
		
		
		// Thin event handler: gate early, enqueue, then drain the queue on this thread if no other
		// thread is already draining. This guarantees strictly FIFO processing of master executions
		// (even when NT raises events on multiple provider threads in quick succession) and eliminates
		// the race where rapid events could cause the old drift-resync logic to snap to a stale or
		// ahead live position and corrupt the follower delta math.
		// Hard upper bound for the belt-and-suspenders sanity check in
		// OnExecutionUpdate3. The primary replay defense is the session-
		// membership gate (see _sessionLiveOrderIds) — this constant only
		// catches truly insane clock skew / corrupt timestamps. 24h is wide
		// enough that any realistic broker-zone vs OS-zone mismatch stays
		// inside the window, so users in any timezone configuration pass.
		private const double InsaneExecAgeSec = 86400.0;

		private void OnExecutionUpdate3 (object sender, ExecutionEventArgs e)
		{
			// Stamp the master execution time so downstream SlaveAccount.Submit
			// sites can measure the copier processing lag.
			_copierLatencyMasterT = DateTime.Now;

			if (State != State.Realtime)
				return;

			// Null-safety: replay events during reconnect can arrive with null
			// Execution / Order / Instrument / Account. Reject before we risk
			// NRE deep in ProcessMasterExecution.
			if (e == null || e.Execution == null
				|| e.Execution.Order == null
				|| e.Execution.Instrument == null
				|| e.Execution.Account == null)
			{
				if (_diagLog != null)
				{
					try
					{
						string _what = "e=" + (e == null ? "null" : "ok")
							+ "|Exec=" + (e != null && e.Execution != null ? "ok" : "null")
							+ "|Order=" + (e != null && e.Execution != null && e.Execution.Order != null ? "ok" : "null")
							+ "|Inst=" + (e != null && e.Execution != null && e.Execution.Instrument != null ? "ok" : "null")
							+ "|Acct=" + (e != null && e.Execution != null && e.Execution.Account != null ? "ok" : "null");
						_diagLog.Log("COPIER", "SKIP_NULL_EXEC", _what);
					}
					catch { }
				}
				return;
			}

			// Session-membership gate. Replaces the prior timezone-dependent
			// staleness check, which compared e.Execution.Time (broker zone)
			// against DateTime.UtcNow on the user's clock and rejected
			// legitimate fills for any user whose OS zone didn't match the
			// broker's stamp. We now act only on executions whose OrderId we
			// observed transition through a post-Initialized state in THIS
			// session (see OnOrderUpdate3 registration). Replays from feed
			// reconnects or workspace reloads carry IDs originated before the
			// indicator armed, so they are absent from the set and rejected
			// without any clock comparison.
			string _exOrderId = e.Execution.Order.OrderId;
			bool _idInSession;
			lock (_sessionLiveOrderIds) { _idInSession = !string.IsNullOrEmpty(_exOrderId) && _sessionLiveOrderIds.Contains(_exOrderId); }
			if (!_idInSession)
			{
				if (_diagLog != null)
				{
					try
					{
						int _setSize;
						lock (_sessionLiveOrderIds) { _setSize = _sessionLiveOrderIds.Count; }
						_diagLog.Log("COPIER", "SKIP_NOT_IN_SESSION",
							"OrderId=" + _exOrderId
							+ "|Account=" + e.Execution.Account.Name
							+ "|Instrument=" + e.Execution.Instrument.FullName
							+ "|Qty=" + e.Execution.Quantity
							+ "|ExecTime=" + e.Execution.Time
							+ "|ExecKind=" + e.Execution.Time.Kind
							+ "|UtcNow=" + DateTime.UtcNow.ToString("o")
							+ "|LocalNow=" + DateTime.Now.ToString("o")
							+ "|TzId=" + TimeZoneInfo.Local.Id
							+ "|TzOffset=" + TimeZoneInfo.Local.BaseUtcOffset
							+ "|ArmedUtc=" + (_copierArmedUtc == DateTime.MinValue ? "never" : _copierArmedUtc.ToString("o"))
							+ "|SessionSetSize=" + _setSize);
					}
					catch { }
				}
				return;
			}

			// Belt-and-suspenders sanity bound. Reject anything whose
			// Execution.Time is more than 24h off DateTime.UtcNow in either
			// direction. Catches truly insane clock skew or a corrupt feed
			// timestamp without depending on the broker's stamping zone —
			// 24h is wide enough that any realistic offset stays inside the
			// window. Logs the full TZ snapshot so future diagnosis doesn't
			// have to infer the user's zone from a delta.
			double _execAgeSecAbs = Math.Abs((DateTime.UtcNow - e.Execution.Time.ToUniversalTime()).TotalSeconds);
			if (_execAgeSecAbs > InsaneExecAgeSec)
			{
				if (_diagLog != null)
				{
					try
					{
						_diagLog.Log("COPIER", "SKIP_STALE_EXEC",
							"AgeSecAbs=" + _execAgeSecAbs.ToString("F1")
							+ "|ExecTime=" + e.Execution.Time
							+ "|ExecKind=" + e.Execution.Time.Kind
							+ "|Now=" + DateTime.Now
							+ "|UtcNow=" + DateTime.UtcNow
							+ "|TzId=" + TimeZoneInfo.Local.Id
							+ "|TzOffset=" + TimeZoneInfo.Local.BaseUtcOffset
							+ "|Account=" + e.Execution.Account.Name
							+ "|Instrument=" + e.Execution.Instrument.FullName
							+ "|OrderId=" + _exOrderId
							+ "|Qty=" + e.Execution.Quantity);
					}
					catch { }
				}
				return;
			}

			// Logged AFTER the realtime gate — chart reload replays historical
			// executions that the indicator itself ignores; don't log those.
			if (_diagLog != null)
			{
				try
				{
					var ex = e.Execution;
					// NT8 timing note: Account.GetPosition() inside OnExecutionUpdate
					// returns the position as it stood BEFORE this fill is applied —
					// the position update is dispatched after the execution event.
					// So _masterQtyBeforeFill is the pre-fill snapshot, and the
					// post-fill value is computed by adding the signed fill.
					int _masterQtyBeforeFill = 0;
					try
					{
						Position _curMP = ex.Account.GetPosition(ex.Instrument.Id);
						if (_curMP != null && _curMP.MarketPosition != MarketPosition.Flat)
							_masterQtyBeforeFill = _curMP.MarketPosition == MarketPosition.Long ? _curMP.Quantity : -_curMP.Quantity;
					}
					catch { }
					int _signedFill = (ex.Order.OrderAction == OrderAction.Sell || ex.Order.OrderAction == OrderAction.SellShort) ? -ex.Quantity : ex.Quantity;
					int _masterQtyAfterFill = _masterQtyBeforeFill + _signedFill;
					double _fillLatencyMs = -1.0;
					try { _fillLatencyMs = (ex.Time - ex.Order.Time).TotalMilliseconds; } catch { }
					_diagLog.Log("EXECUTION", "MASTER_FILL",
						"Account=" + ex.Account.Name
						+ "|Instrument=" + (ex.Instrument != null ? ex.Instrument.FullName : "?")
						+ "|Action=" + ex.Order.OrderAction
						+ "|Qty=" + ex.Quantity
						+ "|SignedFill=" + _signedFill
						+ "|Price=" + ex.Price
						+ "|ExecMarketPos=" + ex.MarketPosition
						+ "|IsEntry=" + ex.IsEntry
						+ "|OrderName=" + ex.Order.Name
						+ "|OrderId=" + ex.Order.OrderId
						+ "|MasterQtyBeforeFill=" + _masterQtyBeforeFill
						+ "|MasterQtyAfterFill=" + _masterQtyAfterFill
						+ "|FillLatencyMs=" + _fillLatencyMs.ToString("F0"));
				}
				catch { }
			}

			// Global mode / feature gates.
			// In Orders mode the copier replicates orders, not executions — so unless the ATM
			// Select column is on (which routes per-account ATM execution copying through this
			// same handler), there's nothing to do for an execution event.
			if (!pIsATMSelectEnabled && pCopierMode == "Orders")
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_OrdersMode_NoATM", "CopierMode=" + pCopierMode + "|ATMSelectEnabled=" + pIsATMSelectEnabled); } catch { } }
				return;
			}

			if (!pIsCopyBasicFunctionsEnabled)
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_BasicFunctionsDisabled", ""); } catch { } }
				return;
			}

			if (pEventToSend != "Execution Update")
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_EventToSendMismatch", "EventToSend=" + pEventToSend); } catch { } }
				return;
			}

			_masterExecutionQueue.Enqueue(e);
			DrainMasterExecutionQueue();
		}

		// Single-drainer guard: at most one thread inside the while loop at a time. Any thread that
		// arrives while another is draining just enqueues and returns — the active drainer will pick
		// up the new entry on its next loop iteration. This preserves strict FIFO ordering without a
		// dedicated worker thread.
		private void DrainMasterExecutionQueue()
		{
			if (Interlocked.CompareExchange(ref _isDrainingMasterExecutions, 1, 0) != 0)
				return;

			try
			{
				while (_masterExecutionQueue.TryDequeue(out ExecutionEventArgs evt))
				{
					try
					{
						ProcessMasterExecution(evt);
					}
					catch (Exception ex)
					{
						// Never let a single bad event kill the drainer — log and move on.
						// try { Print("ERROR in ProcessMasterExecution: " + ex.Message); } catch { }
					}
				}
			}
			finally
			{
				Interlocked.Exchange(ref _isDrainingMasterExecutions, 0);
			}

			// Guard against the classic enqueue/drain race: another thread may have enqueued
			// after our last TryDequeue but before we released the flag. If so, it saw the flag
			// set and bailed. Re-check and re-drain if work remains.
			if (!_masterExecutionQueue.IsEmpty)
				DrainMasterExecutionQueue();
		}

		// Generates a short unique tag for one master fill cycle. Threaded
		// through ProcessMasterExecution → SendExecutionModeOrders2 → all
		// follower-loop logs so a single grep on FillId=X recovers the entire
		// decision tree for one event in chronological order.
		private static int _fillIdCounter;
		private static string GenerateFillId()
		{
			int n = System.Threading.Interlocked.Increment(ref _fillIdCounter) & 0xFFFFFF;
			return n.ToString("X6");
		}

		private void ProcessMasterExecution(ExecutionEventArgs e)
		{
			// Defense-in-depth null-safety. OnExecutionUpdate3 already rejects
			// incomplete events, but this handler is also reachable from the
			// drain re-entry path — guard here too so a malformed event that
			// slips through can't crash the drainer.
			if (e == null || e.Execution == null
				|| e.Execution.Order == null
				|| e.Execution.Instrument == null
				|| e.Execution.Account == null)
			{
				return;
			}

			// FillId — one per execution that makes it past null-safety. Tags
			// every downstream log line in this fill cycle.
			string _fillId = GenerateFillId();

			// Defense-in-depth re-check inside the processor. The session-
			// membership gate at the intake side is the primary replay defense;
			// here we just enforce the 24h sanity bound again in case anything
			// somehow bypassed intake. No per-window staleness check — that's
			// what _sessionLiveOrderIds is for, and forcing a tight window here
			// reintroduces the timezone bug.
			double _drainAgeSecAbs = Math.Abs((DateTime.UtcNow - e.Execution.Time.ToUniversalTime()).TotalSeconds);
			if (_drainAgeSecAbs > InsaneExecAgeSec)
			{
				if (_diagLog != null)
				{
					try
					{
						_diagLog.Log("COPIER", "DROP_STALE_IN_DRAIN",
							"FillId=" + _fillId
							+ "|AgeSecAbs=" + _drainAgeSecAbs.ToString("F1")
							+ "|ExecKind=" + e.Execution.Time.Kind
							+ "|TzId=" + TimeZoneInfo.Local.Id
							+ "|TzOffset=" + TimeZoneInfo.Local.BaseUtcOffset
							+ "|OrderId=" + e.Execution.Order.OrderId);
					}
					catch { }
				}
				return;
			}

			// PROCESS_EXECUTION log removed — SEND_EXEC_MODE_ORDERS2_ENTRY (renamed
			// EXEC_INTAKE) below carries the same info plus TotalMasterPos /
			// IsFinalExit / FollowerCount, so the pair was redundant.

			bool IsNewEntry = false;

			if (e.Execution.IsEntry)
			{
				IsNewEntry = true;
			}

			int FinalQ = e.Execution.Quantity;

			int executionQuantity;
			if (e.Execution.Order.OrderAction == OrderAction.Buy || e.Execution.Order.OrderAction == OrderAction.BuyToCover)
				executionQuantity = e.Execution.Quantity;
			else
				executionQuantity = -e.Execution.Quantity;

			string instrumentKey = e.Execution.Instrument.FullName;
			bool isNewTrackedInstrument = !TrackedMasterPosition.ContainsKey(instrumentKey);
			int seedPos = 0;

			if (IsMasterFlattenCloseOrder(e.Execution.Order))
			{
				// A flatten-Close fill drives the master to flat. Pin the tracker
				// straight to 0 rather than seed/accumulate it: a flatten wipes the
				// tracker (RESET) first, so without this its own close fills get
				// counted as a fresh opposite position — leaving the tracker, and
				// the next real trade's follower sizing, off by the closed size
				// until the idle resync heals it. Copying of these fills is already
				// suppressed downstream (SKIP_FlattenCloseOrder).
				TrackedMasterPosition[instrumentKey] = 0;
			}
			else if (isNewTrackedInstrument)
			{
				if (e.Execution.Account != null)
				{
					var seedPosition = e.Execution.Account.GetPosition(e.Execution.Instrument.Id);
					if (seedPosition != null && seedPosition.Quantity != 0)
					{
						seedPos = seedPosition.MarketPosition == MarketPosition.Short
							? -seedPosition.Quantity
							: seedPosition.Quantity;
						// Some connections report pre-execution position in this callback.
						// Seed and then advance by this execution to avoid one-execution lag.
						TrackedMasterPosition[instrumentKey] = seedPos + executionQuantity;
					}
					else
					{
						TrackedMasterPosition[instrumentKey] = executionQuantity;
					}
				}
				else
				{
					TrackedMasterPosition[instrumentKey] = executionQuantity;
				}
			}
			else
			{
				TrackedMasterPosition[instrumentKey] += executionQuantity;
			}

			// Mark master activity for the idle-resync gate in OnTimerTick3.
			Interlocked.Exchange(ref _lastMasterFillTicksUtc, DateTime.UtcNow.Ticks);

			int totalmasterpos = GetTrackedMasterPosition(instrumentKey);
			bool IsFinalExit = totalmasterpos == 0 && !IsNewEntry;

			bool PrintInfo = false;

			// A "seeding double-count correction" was removed from here. Its test
			// (liveQty + executionQuantity == totalmasterpos) was a tautology on
			// NT8 — GetPosition() in OnExecutionUpdate reports the PRE-fill position,
			// the same value seedPos was built from — so it fired on every seeded
			// fill and snapped the tracker one execution into the past. Symptom:
			// flatten while in a position and every later fill was offset by the
			// closed size, doubling follower orders. The plain seed math is correct;
			// residual drift is repaired by ResyncTrackedMasterPositionFromLive.

			if (PrintInfo) Print("TrackedMasterPos=" + totalmasterpos + " instrument=" + instrumentKey + " execQty=" + executionQuantity);

			SendExecutionModeOrders2(e.Execution.Instrument, e.Execution.MarketPosition, e.Execution.Order, IsNewEntry, FinalQ, IsFinalExit, totalmasterpos, _fillId);
		}


		private void SendExecutionModeOrders2(Instrument SendInstrument, MarketPosition SendMarketPosition, Order SendOrder, bool IsNewEntry, int FinalQ, bool IsFinalExit, int totalmasterpos, string _fillId = null)
		{
			// Backwards-compat for any callsite that didn't get the FillId param
			if (_fillId == null) _fillId = GenerateFillId();

			// INTAKE_FOLLOWER_BASELINE — snapshot live broker positions for every
			// follower at the moment this master fill arrives. Combined with
			// DECISION_SUMMARY at the end of the loop, gives a "before/after" pair
			// for every fill cycle. Critical for diagnosing tracker drift (Ricky
			// 2026-04-27 incident: tracker said -40, broker said 0; this log would
			// have surfaced that divergence at the moment it mattered).
			if (_diagLog != null && SendInstrument != null && AllDuplicateAccounts != null)
			{
				try
				{
					var sb = new System.Text.StringBuilder(256);
					int idx = 0;
					foreach (string acctName in AllDuplicateAccounts)
					{
						Account a = AccountFromName(acctName);
						int signed = 0;
						string conn = "?";
						if (a != null)
						{
							conn = a.ConnectionStatus.ToString();
							try
							{
								Position p = a.GetPosition(SendInstrument.Id);
								if (p != null && p.MarketPosition != MarketPosition.Flat)
									signed = p.MarketPosition == MarketPosition.Short ? -p.Quantity : p.Quantity;
							}
							catch { }
						}
						if (idx++ > 0) sb.Append(',');
						sb.Append(acctName).Append('=').Append(signed);
						if (conn != "Connected") sb.Append('[').Append(conn).Append(']');
					}
					_diagLog.Log("COPIER", "INTAKE_FOLLOWER_BASELINE",
						"FillId=" + _fillId
						+ "|Instrument=" + SendInstrument.FullName
						+ "|MasterPos=" + totalmasterpos
						+ "|Followers=" + sb.ToString());
				}
				catch { }
			}

			if (_diagLog != null)
			{
				try
				{
					_diagLog.Log("COPIER", "EXEC_INTAKE",
						"FillId=" + _fillId
						+ "|Instrument=" + (SendInstrument != null ? SendInstrument.FullName : "?")
						+ "|Position=" + SendMarketPosition
						+ "|OrderName=" + (SendOrder != null ? SendOrder.Name : "?")
						+ "|IsNewEntry=" + IsNewEntry
						+ "|IsFinalExit=" + IsFinalExit
						+ "|TotalMasterPos=" + totalmasterpos
						+ "|Mode=" + pCopierMode
						+ "|FollowerCount=" + AllDuplicateAccounts.Count);
				}
				catch { }
			}






			string SendName = SendOrder.Name;


			// do not process partially filled orders

			//			if (SendOrder.OrderState == OrderState.PartFilled)
			//				return;

			int SendQuantity = SendOrder.Filled;


			SendQuantity = FinalQ;




			//			Print("IsNewEntry " + IsNewEntry);
			//			Print("FinalQ " + FinalQ);


			//Print(SendOrder.Filled);

			//Print("OnExecutionUpdate3 " + IgnoreExecutionUntilFlat);


			//Print("DDDD1");

			if (!IsInActiveWorkspace && pDisableInActiveWorkspace)
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_NotInActiveWorkspace", "IsInActiveWorkspace=" + IsInActiveWorkspace + "|pDisableInActiveWorkspace=" + pDisableInActiveWorkspace); } catch { } }
				return;
			}

			if (!pCopierIsEnabled)
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_CopierDisabled", ""); } catch { } }
				ChartControl.Dispatcher.InvokeAsync((Action)(() =>
				{
					AddMessage(messageoff, 20, Brushes.Goldenrod);
				}));
				return;
			}

			if (pThisMasterAccount == string.Empty)
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_NoMasterAccount", ""); } catch { } }
				return;
			}

			//			if (!pAllInstruments && SendInstrument != Instrument)
			//				return;

			if (IgnoreExecutionUntilFlat)
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_IgnoreUntilFlat", ""); } catch { } }
				return;
			}


			// Order-scoped flatten suppression: the master's own flatten "Close"
			// order is never a tradeable signal. Unbounded by time, unlike the
			// pMilliSFE window below — a slow or partially-filling close fills past
			// the window, and those late fills were driving the already-flat
			// followers into a fresh opposite position (reversal).
			if (IsMasterFlattenCloseOrder(SendOrder))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FlattenCloseOrder", "OrderId=" + (SendOrder != null ? SendOrder.OrderId : "?") + "|Name=" + (SendOrder != null ? SendOrder.Name : "?")); } catch { } }
				return;
			}

			if (DateTime.Now < FlattenEverythingClickedTime.AddMilliseconds(pMilliSFE))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FlattenWindow", "MsSince=" + (int)(DateTime.Now - FlattenEverythingClickedTime).TotalMilliseconds + "|WindowMs=" + pMilliSFE); } catch { } }
				return;
			}
			// Also block execution copies during Goal/Loss/Funded flatten window
			if (DateTime.Now < GoalLossFlattenTime.AddMilliseconds(pMilliSFE))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_GoalLossWindow", "MsSince=" + (int)(DateTime.Now - GoalLossFlattenTime).TotalMilliseconds + "|WindowMs=" + pMilliSFE); } catch { } }
				// Print("GUARD: Blocking execution copy — Goal/Loss/Funded flatten in progress. GoalLossFlattenTime=" + GoalLossFlattenTime);
				return;
			}
			else
			{

			}





			//Print("DDDD2");

			//Print(e.Execution.Order.Name);

			// prevent loop - basically do NOT copy master account orders that have DAA on them

			if (SendName.Contains(MarketOrderName))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_SelfOrderFilter_AI", "Name=" + SendName); } catch { } }
				return;
			}

			if (SendName.Contains(OneTradeOrderName))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_SelfOrderFilter_OneTr", "Name=" + SendName); } catch { } }
				return;
			}

			if (SendName.Contains(RefreshOrderName))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_SelfOrderFilter_RefPos", "Name=" + SendName); } catch { } }
				return;
			}



			//Print();

			int MasterExQty = SendQuantity;





			Instrument MasterExInstrument = SendInstrument;
			Instrument SlaveExInstrument = SendInstrument;


			string thisexinstr = SendInstrument.FullName;


			Instrument MicroInstrument = GetTheInstrument(thisexinstr, "Micro", false);
			Instrument MiniInstrument = GetTheInstrument(thisexinstr, "Mini", false);

			//			Instrument MicroInstrument = null;
			//			Instrument MiniInstrument = null;

			if (!IsInstrumentTracked(SendInstrument))
			{
				if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_InstrumentNotTracked", "Instrument=" + (SendInstrument != null ? SendInstrument.FullName : "?") + "|Mode=" + pInstrumentMode); } catch { } }
				return;
			}




			// Per-fill decision tally — drives the COPIER|DECISION_SUMMARY log at
			// the end of the loop. One summary line per master fill replaces the
			// chore of grepping ~10 lines (SUBMIT/SKIP_*) to figure out the loop
			// outcome. Detail lines still emit; this just adds an at-a-glance view.
			int _decSubmitted = 0;
			int _decZeroQty = 0;
			int _decDriftGuard = 0;
			int _decLatchSkipped = 0;
			int _decLatchAllowed = 0;
			int _decAlreadyFlat = 0;
			int _decDisconnected = 0;
			int _decSameAsMaster = 0;
			int _decAccountModeMismatch = 0;
			int _decNullAccount = 0;
			int _decOtherSkip = 0;
			System.Collections.Generic.List<string> _decSkippedAccts = new System.Collections.Generic.List<string>();

			foreach (string sssss in AllDuplicateAccounts)
			{
				// Per-iteration flag: true when drift-guard suppressed the submit
				// (which also forces SlaveExQty=0). Without this, the downstream
				// zero-qty branch would double-count the same skip in the summary.
				bool _decGuardSuppressedThisIter = false;

				// NT 8.1.7.0 regression diagnostics (2026-05-19): user reports
				// ~1s per follower on close path. Stopwatch + LOOP_STEP_TIMING
				// log at the bottom isolate whether GetPosition or the submit
				// is the slow step. Stopwatch is essentially free per-iter.
				System.Diagnostics.Stopwatch _swIter = System.Diagnostics.Stopwatch.StartNew();
				double _msGetPos1 = -1, _msGuardGetPos = -1, _msSubmit = -1;
				// Cache the first GetPosition so the drift guard can reuse it
				// when MasterExInstrument.Id == SlaveExInstrument.Id (the common
				// case; only diverges for FDAX cross-contract). Cuts a Cbi call
				// per follower on the close path — pure win, no behavior change.
				Position _cachedFollowerPos = null;
				bool _cachedFollowerPosValid = false;
				Instrument _cachedFollowerPosInstrument = null;


				Account SlaveAccount = AccountFromName(sssss);


				// no longer needed for this new method

				//				if (IsAccountFinishedAndFlat(sssss))
				//					continue;



				if (pIsATMSelectEnabled)
				{
					string currentaccountmode = GetAccountMode(sssss);

					bool IsNotExecutionMode = false;

					//					if (currentaccountmode == "Executions")
					//						continue;

					if (currentaccountmode == "Default")
					{
						if (pCopierMode != "Executions")
							IsNotExecutionMode = true;
					}
					else if (currentaccountmode != "Executions")
					{
						IsNotExecutionMode = true;
					}

					if (IsNotExecutionMode)
					{
						if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_AccountModeMismatch", "Account=" + sssss + "|AccountMode=" + currentaccountmode + "|CopierMode=" + pCopierMode); } catch { } }
						_decAccountModeMismatch++; _decSkippedAccts.Add(sssss);
						continue;
					}



					//					if (currentaccountmode == "Orders")
					//						continue;

					//					if (currentaccountmode == "Default" && pCopierMode == "Orders")
					//						continue;

				}








				if (SlaveAccount == null)
				{
					if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_NullAccount", "Account=" + sssss); } catch { } }
					_decNullAccount++; _decSkippedAccts.Add(sssss);
					continue;
				}

				if (SlaveAccount.ConnectionStatus == ConnectionStatus.Disconnected)
				{
					// remove account from saved list completely
					if (!AllConnectedAccounts.Contains(SlaveAccount.Name))
					{
						int i = 0;
						int found = 0;
						foreach (string s in pAllAccountData)
						{
							if (s.Contains(sssss))
							{
								found = i;
							}

							i++;
						}

						pAllAccountData[found] = "";
					}

					// Log once per session per account — Disconnected is a static fact
					// that doesn't change between executions; per-exec logging just
					// multiplies log volume. Trade-flow visibility unchanged: any
					// state change of this account (Disconnected→Connected, missing
					// fill, etc.) shows up in ACCOUNT|STATUS_CHANGE / ORDER|UPDATE.
					string _disconnKey = "DISC|" + sssss;
					if (_diagLog != null && !_diagLoggedFollowerStaticSkip.Contains(_disconnKey))
					{
						_diagLoggedFollowerStaticSkip.Add(_disconnKey);
						try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_Disconnected", "Account=" + sssss + "|LoggedOncePerSession=true"); } catch { }
					}
					_decDisconnected++; _decSkippedAccts.Add(sssss);

					continue;
				}

				// Goal/Loss/Funded latch handling.
				//
				// Historically these gates blocked ALL master execution copies for a
				// latched follower — including the master's EXITS that would close a
				// position the follower already had open. Ron 2026-05-04 incident: two
				// followers (TPT1943135, TPT6121969) tripped the goal latch *while*
				// holding a master-copied short. When the master Stop1 fired and tried
				// to flatten everyone, those two were skipped here and Ron had to click
				// Flatten All to clean them up.
				//
				// Fix: only block NEW ENTRIES. Master exits (IsNewEntry == false) bypass
				// the latch, then the position-delta math downstream handles them
				// correctly — a follower that's already flat will compute SlaveExQty=0
				// and emit no phantom order (~line 38788 safety check), while a follower
				// still holding a position will get the close it needs.
				if (HasFollowerHitGoalLossOrFunded(SlaveAccount))
				{
					if (IsNewEntry)
					{
						if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_HitGoalLossFunded", "FillId=" + _fillId + "|Account=" + sssss); } catch { } }
						_decLatchSkipped++; _decSkippedAccts.Add(sssss);
						continue;
					}
					else
					{
						if (_diagLog != null) { try { _diagLog.Log("COPIER", "ALLOW_EXIT_DESPITE_HitGoalLossFunded", "FillId=" + _fillId + "|Account=" + sssss + "|MasterPos=" + totalmasterpos); } catch { } }
						_decLatchAllowed++;
					}
				}
				// Check if this follower was flattened by a Goal/Loss/Funded trigger
				if (GoalLossFlattenLatch.ContainsKey(sssss))
				{
					if (IsNewEntry)
					{
						if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_GoalLossLatch", "FillId=" + _fillId + "|Account=" + sssss + "|LatchedAt=" + GoalLossFlattenLatch[sssss]); } catch { } }
						// Print("GUARD: Skipping execution copy for " + sssss + " — account was flattened by Goal/Loss/Funded at " + GoalLossFlattenLatch[sssss]);
						_decLatchSkipped++; _decSkippedAccts.Add(sssss);
						continue;
					}
					else
					{
						if (_diagLog != null) { try { _diagLog.Log("COPIER", "ALLOW_EXIT_DESPITE_GoalLossLatch", "FillId=" + _fillId + "|Account=" + sssss + "|LatchedAt=" + GoalLossFlattenLatch[sssss] + "|MasterPos=" + totalmasterpos); } catch { } }
						_decLatchAllowed++;
					}
				}

				// Already-flat exit guard.
				//
				// 2026-05-14 Joel incident: master was Long 1 with two followers also
				// Long 1. Both followers tripped DailyGoal -> FLATTEN_EVERYTHING reduced
				// them to flat. User then clicked Close on the master, which sent a
				// Sell. Copier ran the latch-bypass path above (correct), then mirrored
				// the Sell direction to both already-flat followers — opening rogue
				// shorts. Because UsePositionDelta=False (the default outside cross
				// mode), the downstream qty math doesn't reduce to zero on its own.
				//
				// Guard: on master exits, if the follower's broker position is flat
				// AND the tracker has no in-flight expected position, there is nothing
				// to close — skip. ExpectedFollowerPositions check preserves the
				// fill-latency case where broker hasn't yet reported a copier-sent
				// fill (we want that follow-up exit to go through).
				if (!IsNewEntry && SlaveAccount != null && MasterExInstrument != null)
				{
					bool _brokerFlat = false;
					try
					{
						long _tA = _swIter.ElapsedTicks;
						Position _fp = SlaveAccount.GetPosition(MasterExInstrument.Id);
						_msGetPos1 = (_swIter.ElapsedTicks - _tA) * 1000.0 / System.Diagnostics.Stopwatch.Frequency;
						_cachedFollowerPos = _fp;
						_cachedFollowerPosValid = true;
						_cachedFollowerPosInstrument = MasterExInstrument;
						_brokerFlat = (_fp == null || _fp.MarketPosition == MarketPosition.Flat);
					}
					catch { }

					if (_brokerFlat)
					{
						bool _hasExpectedPosition = false;
						foreach (var kvp in ExpectedFollowerPositions)
						{
							if (kvp.Key.StartsWith(sssss + "::") && kvp.Value != 0)
							{
								_hasExpectedPosition = true;
								break;
							}
						}
						if (!_hasExpectedPosition)
						{
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_AlreadyFlat", "FillId=" + _fillId + "|Account=" + sssss + "|Instrument=" + MasterExInstrument.FullName + "|MasterPos=" + totalmasterpos + "|OrderName=" + (SendOrder != null ? SendOrder.Name : "?")); } catch { } }
							_decAlreadyFlat++; _decSkippedAccts.Add(sssss);
							continue;
						}
					}
				}

				bool skpthis = false;

				if (skpthis)
					if (IsAccountFlat(SlaveAccount))
						if (!IsNewEntry)
						{
							// Before skipping, check if we have a pending expected position for this account.
							// Rapid executions can cause GetPosition to show flat before our sent order fills.
							bool hasExpectedPosition = false;
							foreach (var kvp in ExpectedFollowerPositions)
							{
								if (kvp.Key.StartsWith(sssss + "::") && kvp.Value != 0)
								{
									hasExpectedPosition = true;
									break;
								}
							}
							if (!hasExpectedPosition)
								continue;
						}



				//Print("IsNewEntry " + SlaveAccount.Name);



				SlaveExInstrument = MasterExInstrument;

				if (pIsCrossEnabled)
				{
					// MicroInstrument and MiniInstrument already computed before loop
					SlaveExInstrument = MicroInstrument;
					if (AllCrossAccounts.Contains(sssss))
					{

						SlaveExInstrument = MiniInstrument;
					}


				}


				double SlaveExMultiplier = 0;
				int SlaveExQty = MasterExQty;
				bool usePositionDelta = false;
				int positionDelta = 0;

				if (pIsXEnabled)
				{

					SlaveExMultiplier = Convert.ToDouble(GetAccountMultiplier(sssss));

					if (SlaveExMultiplier == 0)
						SlaveExMultiplier = 0.50;
					if (SlaveExMultiplier == -1)
						SlaveExMultiplier = 0.33;
					if (SlaveExMultiplier == -2)
						SlaveExMultiplier = 0.25;
					if (SlaveExMultiplier == -3)
						SlaveExMultiplier = 0.20;

					if (pMultiplierMode == "Multiplier")
					{
						SlaveExQty = RoundFollowerQtyForExecutionsMode(MasterExQty * SlaveExMultiplier);

						//


						// get rid of requirement for multiplier, use new calc for everything
						//if (SlaveExMultiplier < 1)
						{

							//							var position = SlaveAccount.GetPosition(SlaveExInstrument.Id);

							//							int SlaveNewPosition = (int) Math.Round(totalmasterpos * SlaveExMultiplier);

							//							Print("SlaveNewPosition " + SlaveNewPosition);

							//							if (position != null)
							//							{
							//								if (IsFinalExit)
							//								{
							//									SlaveExQty = position.Quantity;
							//								}

							//								SlaveExQty = Math.Max(0,SlaveNewPosition - position.Quantity);
							//							}

							// Position-delta approach: calculate desired follower position from master's total position
							//int desiredFollowerPos = IsFinalExit ? 0 : (int) Math.Round(totalmasterpos * SlaveExMultiplier);

							// By default, Math.Round in C# uses banker's rounding (MidpointRounding.ToEven), which rounds 2.5 to 2, 3.5 to 4, etc. Adding MidpointRounding.AwayFromZero makes it always round 0.5 values up — so 2.5 → 3, 3.5 → 4, and so on.

							int desiredFollowerPos = IsFinalExit ? 0 : RoundFollowerQtyForExecutionsMode(totalmasterpos * SlaveExMultiplier);


							// Use tracked expected position to avoid slow/unreliable GetPosition broker calls.
							// Only fall back to live query on first-seen follower+instrument (seeding).
							string expectedPosKey = GetExpectedPosKey(sssss, SlaveExInstrument.FullName);
							int currentFollowerPos;

							if (ExpectedFollowerPositions.TryGetValue(expectedPosKey, out int trackedPos))
							{
								// Tracked position exists — trust it, skip GetPosition entirely
								currentFollowerPos = trackedPos;
							}
							else
							{
								// First time seeing this follower+instrument — seed from live position
								int liveFollowerPos = 0;
								var slavePosition = SlaveAccount.GetPosition(SlaveExInstrument.Id);
								if (slavePosition != null && slavePosition.Quantity != 0)
								{
									liveFollowerPos = slavePosition.MarketPosition == MarketPosition.Short
										? -slavePosition.Quantity
										: slavePosition.Quantity;
								}
								currentFollowerPos = liveFollowerPos;
							}

							// Delta: positive = need to buy, negative = need to sell
							positionDelta = desiredFollowerPos - currentFollowerPos;

							SlaveExQty = Math.Abs(positionDelta);

							//Print(SlaveAccount.Name + "  " + SlaveExQty + "  " + positionDelta);
							//Print("SlaveExQty " + SlaveNewPosition);


							usePositionDelta = true;



							// SAFETY NET: If delta says close but tracker already shows flat, skip.
							// Also catches edge case where rounding produces qty=0 desired on a flat follower.
							if (desiredFollowerPos == 0 && currentFollowerPos == 0)
							{
								SlaveExQty = 0;
								positionDelta = 0;
							}

							// Update expected position AFTER safety check so it reflects
							// the actual action we're taking, not what we initially planned
							ExpectedFollowerPositions[expectedPosKey] = desiredFollowerPos;

							//Print("desiredFollowerPos " + desiredFollowerPos + " liveFollowerPos " + liveFollowerPos + " trackedFollowerPos " + currentFollowerPos + " positionDelta " + positionDelta + " SlaveExQty " + SlaveExQty + " account " + sssss);


							// =======================================================================
							// DRIFT GUARD — defensive subset of the broader reconciliation work.
							// Background: Ricky 2026-04-27 incident. Follower entry orders were
							// submitted but never reached the broker (rejected / capped without our
							// knowledge). The DRIFT watchdog at OnTimerTick3 logged the divergence
							// every 30s for 12 minutes. When the master SL fired, this code computed
							// positionDelta against the *tracked* expected position (-40) instead of
							// the *live* broker position (0), submitted Buy 40, and the followers
							// flipped from flat to long (capped at +16) — a reversal.
							//
							// The full fix is target-position reconciliation across all paths. That
							// requires reading and validating the cross-instrument and rounding math
							// end-to-end and is deferred. THIS guard is purely subtractive: when the
							// tracker has diverged from the live broker AND we are attempting to
							// reduce/flatten the (tracker's view of the) follower position AND the
							// proposed order would worsen the live position, skip the submit and
							// resync the tracker. Entries (when the tracker says we're growing the
							// position) are unaffected.
							// =======================================================================
							try
							{
								int _liveFollowerPosForGuard = 0;
								Position _slavePosForGuard;
								if (_cachedFollowerPosValid && _cachedFollowerPosInstrument != null
									&& SlaveExInstrument != null
									&& _cachedFollowerPosInstrument.Id == SlaveExInstrument.Id)
								{
									_slavePosForGuard = _cachedFollowerPos;
									_msGuardGetPos = 0;
								}
								else
								{
									long _tB = _swIter.ElapsedTicks;
									_slavePosForGuard = SlaveAccount.GetPosition(SlaveExInstrument.Id);
									_msGuardGetPos = (_swIter.ElapsedTicks - _tB) * 1000.0 / System.Diagnostics.Stopwatch.Frequency;
								}
								if (_slavePosForGuard != null && _slavePosForGuard.Quantity != 0)
								{
									_liveFollowerPosForGuard = _slavePosForGuard.MarketPosition == MarketPosition.Short
										? -_slavePosForGuard.Quantity
										: _slavePosForGuard.Quantity;
								}

								// In-flight reconciliation — Braxton 2026-05-20 incident.
								// On a fast TradingView scalp the master entry and exit fill
								// inside one broker round-trip. When the exit reaches this
								// guard the follower's own entry order is still in-flight: the
								// tracker already counts it but the follower's broker Position
								// has not caught up. The raw check mistook that gap for drift
								// and blocked the exit, stranding the follower in a naked
								// position. Fold the follower's pending market orders back in;
								// when they explain the gap exactly it is fill latency, not
								// drift. Subtractive — this can only clear a raw divergence,
								// never invent one, so nothing the raw check allowed is now
								// blocked.
								bool _rawDiverged = _liveFollowerPosForGuard != currentFollowerPos;
								int _inFlightFollowerQty = 0;
								int _effectiveLivePos = _liveFollowerPosForGuard;
								bool _inFlightExplainsGap = false;
								if (_rawDiverged)
								{
									_inFlightFollowerQty = GetInFlightFollowerQty(SlaveAccount, SlaveExInstrument);
									_effectiveLivePos = _liveFollowerPosForGuard + _inFlightFollowerQty;
									_inFlightExplainsGap = _effectiveLivePos == currentFollowerPos;
								}
								bool _trackerDiverged = _rawDiverged && !_inFlightExplainsGap;

								if (_inFlightExplainsGap && _diagLog != null)
								{
									try
									{
										_diagLog.Log("COPIER", "DRIFT_GUARD_INFLIGHT_OK",
											"FillId=" + _fillId
											+ "|Account=" + sssss
											+ "|Instrument=" + (SlaveExInstrument != null ? SlaveExInstrument.FullName : "?")
											+ "|TrackedPos=" + currentFollowerPos
											+ "|LivePos=" + _liveFollowerPosForGuard
											+ "|InFlightQty=" + _inFlightFollowerQty
											+ "|EffectiveLivePos=" + _effectiveLivePos
											+ "|DesiredPos=" + desiredFollowerPos
											+ "|ProposedDelta=" + positionDelta);
									}
									catch { }
								}

								bool _isReductionAttempt =
									(Math.Abs(desiredFollowerPos) < Math.Abs(currentFollowerPos))
									&& (desiredFollowerPos == 0 || Math.Sign(desiredFollowerPos) == Math.Sign(currentFollowerPos));

								if (_trackerDiverged && _isReductionAttempt)
								{
									// Compute the live broker effect of the order. Fade inverts
									// direction at submit (line ~38786), so check both possibilities;
									// only the relevant one matters but evaluating both is cheap and
									// keeps the guard correct regardless of fade configuration.
									int _liveAfter = _liveFollowerPosForGuard + positionDelta;
									int _liveAfterFaded = _liveFollowerPosForGuard - positionDelta;
									int _liveAfterEffective = pIsFadeEnabled ? _liveAfterFaded : _liveAfter;

									// "Bad" = position grew further from zero, OR crossed zero into
									// the opposite direction. Either way the live broker ends up in a
									// state worse than where it started while the tracker thought we
									// were reducing.
									bool _grewAway = Math.Abs(_liveAfterEffective) > Math.Abs(_liveFollowerPosForGuard);
									bool _crossedZero = _liveFollowerPosForGuard != 0
										&& _liveAfterEffective != 0
										&& Math.Sign(_liveAfterEffective) != Math.Sign(_liveFollowerPosForGuard);

									if (_grewAway || _crossedZero)
									{
										if (_diagLog != null)
										{
											try
											{
												_diagLog.Log("COPIER", "FOLLOWER_SKIP_DRIFT_GUARD",
													"FillId=" + _fillId
													+ "|Account=" + sssss
													+ "|Instrument=" + (SlaveExInstrument != null ? SlaveExInstrument.FullName : "?")
													+ "|TrackedPos=" + currentFollowerPos
													+ "|LivePos=" + _liveFollowerPosForGuard
													+ "|InFlightQty=" + _inFlightFollowerQty
													+ "|DesiredPos=" + desiredFollowerPos
													+ "|ProposedDelta=" + positionDelta
													+ "|LiveAfterIfSubmitted=" + _liveAfterEffective
													+ "|MasterPos=" + totalmasterpos
													+ "|FadeEnabled=" + pIsFadeEnabled
													+ "|Reason=" + (_grewAway ? "WouldGrowAwayFromZero" : "WouldCrossZero"));
											}
											catch { }
										}

										// Resync tracker to live so subsequent submits compute against
										// reality rather than the same stale value that triggered this.
										ExpectedFollowerPositions[expectedPosKey] = _liveFollowerPosForGuard;

										// Suppress this submit. The existing 'if (SlaveExQty != 0)'
										// gate downstream will short-circuit cleanly.
										SlaveExQty = 0;
										positionDelta = 0;
										_decDriftGuard++; _decSkippedAccts.Add(sssss);
										_decGuardSuppressedThisIter = true;

										// User-visible alert. Drift-guard activations are rare and
										// indicate broker-side rejection or manual intervention; the
										// user needs to know to manually reconcile.
										try
										{
											if (ChartControl != null && ChartControl.Dispatcher != null)
											{
												string _acctMsg = sssss;
												string _instMsg = SlaveExInstrument != null ? SlaveExInstrument.FullName : "?";
												int _trkMsg = currentFollowerPos;
												int _liveMsg = _liveFollowerPosForGuard;
												ChartControl.Dispatcher.InvokeAsync((Action)(() =>
												{
													AddMessage("Drift guard: blocked follower order on '" + _acctMsg
														+ "' (" + _instMsg + ") — tracker said " + _trkMsg
														+ ", broker shows " + _liveMsg
														+ ". Manual review recommended.", 60, Brushes.Red);
												}));
											}
										}
										catch { }
									}
								}
							}
							catch (Exception _drift_gex)
							{
								// Never let the guard kill the submit path. Log and continue.
								if (_diagLog != null)
								{
									try { _diagLog.Log("COPIER", "DRIFT_GUARD_EXCEPTION", "Account=" + sssss + "|Msg=" + _drift_gex.Message.Replace("|", ";")); }
									catch { }
								}
							}


						}


					}
					else
					{

						SlaveExQty = (int)SlaveExMultiplier;

					}



					// Enforce minimum 1 contract only for non-position-delta paths.
					// When usePositionDelta is true, qty of 0 means "no change needed"
					// and must not be forced to 1 (which would send a phantom order).
					if (!usePositionDelta)
						SlaveExQty = Math.Max(SlaveExQty, 1);

				}


				// trying to make quantity mode work executions mode

				//						if (SendName.Contains("Close"))
				//						{


				//							SlaveExQty = (int) SlaveAccount.GetPosition(SlaveExInstrument.Id).Quantity;


				//						}				




				if (SlaveAccount == CurrentMasterAccount)
				{
					// Log once per session per account — SameAsMaster is a static
					// configuration fact that doesn't change between executions.
					string _samemKey = "SAMEM|" + sssss;
					if (_diagLog != null && !_diagLoggedFollowerStaticSkip.Contains(_samemKey))
					{
						_diagLoggedFollowerStaticSkip.Add(_samemKey);
						try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_SameAsMaster", "Account=" + sssss + "|LoggedOncePerSession=true"); } catch { }
					}
					_decSameAsMaster++; _decSkippedAccts.Add(sssss);
					continue;
				}



				bool dofade = false;

				if (pIsFadeEnabled)
				{
					string ssssfade = GetAccountFade(sssss);


					if (ssssfade == "Yes")
						dofade = true;



				}

				if (SlaveExQty != 0)
				{
					_decSubmitted++;
					long _tC = _swIter.ElapsedTicks;

					if (usePositionDelta)
					{
						// Direction determined by position delta sign, not master's execution direction
						// Fade inverts the direction
						int adjustedDelta = dofade ? -positionDelta : positionDelta;

						if (adjustedDelta > 0)
						{
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT", "FillId=" + _fillId + "|Account=" + sssss + "|Instrument=" + (SlaveExInstrument != null ? SlaveExInstrument.FullName : "?") + "|Direction=Buy|Qty=" + SlaveExQty + "|UsePositionDelta=True|Fade=" + dofade + "|AcctNull=" + (SlaveAccount == null) + "|InstNull=" + (SlaveExInstrument == null) + "|Conn=" + (SlaveAccount != null ? SlaveAccount.ConnectionStatus.ToString() : "?")); } catch { } }
							try { BuyMarket(SlaveExQty, SlaveExInstrument, SlaveAccount); if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_RETURNED", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Buy|Qty=" + SlaveExQty); } catch { } } }
							catch (Exception _exSub) { if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_FAIL", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Buy|Qty=" + SlaveExQty + "|Ex=" + _exSub.GetType().Name + "|Msg=" + _exSub.Message); } catch { } } }
						}
						else if (adjustedDelta < 0)
						{
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT", "FillId=" + _fillId + "|Account=" + sssss + "|Instrument=" + (SlaveExInstrument != null ? SlaveExInstrument.FullName : "?") + "|Direction=Sell|Qty=" + SlaveExQty + "|UsePositionDelta=True|Fade=" + dofade + "|AcctNull=" + (SlaveAccount == null) + "|InstNull=" + (SlaveExInstrument == null) + "|Conn=" + (SlaveAccount != null ? SlaveAccount.ConnectionStatus.ToString() : "?")); } catch { } }
							try { SellMarket(SlaveExQty, SlaveExInstrument, SlaveAccount); if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_RETURNED", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Sell|Qty=" + SlaveExQty); } catch { } } }
							catch (Exception _exSub) { if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_FAIL", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Sell|Qty=" + SlaveExQty + "|Ex=" + _exSub.GetType().Name + "|Msg=" + _exSub.Message); } catch { } } }
						}
					}
					else
					{
						if (dofade)
						{
							if (SendMarketPosition == MarketPosition.Long)
							{
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT", "FillId=" + _fillId + "|Account=" + sssss + "|Instrument=" + (SlaveExInstrument != null ? SlaveExInstrument.FullName : "?") + "|Direction=Sell|Qty=" + SlaveExQty + "|UsePositionDelta=False|Fade=True|AcctNull=" + (SlaveAccount == null) + "|InstNull=" + (SlaveExInstrument == null) + "|Conn=" + (SlaveAccount != null ? SlaveAccount.ConnectionStatus.ToString() : "?")); } catch { } }
							try { SellMarket(SlaveExQty, SlaveExInstrument, SlaveAccount); if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_RETURNED", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Sell|Qty=" + SlaveExQty); } catch { } } }
							catch (Exception _exSub) { if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_FAIL", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Sell|Qty=" + SlaveExQty + "|Ex=" + _exSub.GetType().Name + "|Msg=" + _exSub.Message); } catch { } } }
							}

							if (SendMarketPosition == MarketPosition.Short)
							{
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT", "FillId=" + _fillId + "|Account=" + sssss + "|Instrument=" + (SlaveExInstrument != null ? SlaveExInstrument.FullName : "?") + "|Direction=Buy|Qty=" + SlaveExQty + "|UsePositionDelta=False|Fade=True|AcctNull=" + (SlaveAccount == null) + "|InstNull=" + (SlaveExInstrument == null) + "|Conn=" + (SlaveAccount != null ? SlaveAccount.ConnectionStatus.ToString() : "?")); } catch { } }
							try { BuyMarket(SlaveExQty, SlaveExInstrument, SlaveAccount); if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_RETURNED", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Buy|Qty=" + SlaveExQty); } catch { } } }
							catch (Exception _exSub) { if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_FAIL", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Buy|Qty=" + SlaveExQty + "|Ex=" + _exSub.GetType().Name + "|Msg=" + _exSub.Message); } catch { } } }
							}

						}
						else
						{
							if (SendMarketPosition == MarketPosition.Long)
							{
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT", "FillId=" + _fillId + "|Account=" + sssss + "|Instrument=" + (SlaveExInstrument != null ? SlaveExInstrument.FullName : "?") + "|Direction=Buy|Qty=" + SlaveExQty + "|UsePositionDelta=False|Fade=False|AcctNull=" + (SlaveAccount == null) + "|InstNull=" + (SlaveExInstrument == null) + "|Conn=" + (SlaveAccount != null ? SlaveAccount.ConnectionStatus.ToString() : "?")); } catch { } }
							try { BuyMarket(SlaveExQty, SlaveExInstrument, SlaveAccount); if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_RETURNED", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Buy|Qty=" + SlaveExQty); } catch { } } }
							catch (Exception _exSub) { if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_FAIL", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Buy|Qty=" + SlaveExQty + "|Ex=" + _exSub.GetType().Name + "|Msg=" + _exSub.Message); } catch { } } }
							}

							if (SendMarketPosition == MarketPosition.Short)
							{
							if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT", "FillId=" + _fillId + "|Account=" + sssss + "|Instrument=" + (SlaveExInstrument != null ? SlaveExInstrument.FullName : "?") + "|Direction=Sell|Qty=" + SlaveExQty + "|UsePositionDelta=False|Fade=False|AcctNull=" + (SlaveAccount == null) + "|InstNull=" + (SlaveExInstrument == null) + "|Conn=" + (SlaveAccount != null ? SlaveAccount.ConnectionStatus.ToString() : "?")); } catch { } }
							try { SellMarket(SlaveExQty, SlaveExInstrument, SlaveAccount); if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_RETURNED", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Sell|Qty=" + SlaveExQty); } catch { } } }
							catch (Exception _exSub) { if (_diagLog != null) { try { _diagLog.Log("COPIER", "FOLLOWER_SUBMIT_FAIL", "FillId=" + _fillId + "|Account=" + sssss + "|Direction=Sell|Qty=" + SlaveExQty + "|Ex=" + _exSub.GetType().Name + "|Msg=" + _exSub.Message); } catch { } } }
							}

						}
					}


					//					if (dofade)
					//					{
					//						if (SendMarketPosition == MarketPosition.Long)
					//							SellMarket(SlaveExQty, SlaveExInstrument, SlaveAccount);

					//						if (SendMarketPosition == MarketPosition.Short)
					//							BuyMarket(SlaveExQty, SlaveExInstrument, SlaveAccount);					

					//					}
					//					else
					//					{
					//						if (SendMarketPosition == MarketPosition.Long)
					//							BuyMarket(SlaveExQty, SlaveExInstrument, SlaveAccount);

					//						if (SendMarketPosition == MarketPosition.Short)
					//							SellMarket(SlaveExQty, SlaveExInstrument, SlaveAccount);

					//					}
					_msSubmit = (_swIter.ElapsedTicks - _tC) * 1000.0 / System.Diagnostics.Stopwatch.Frequency;
				}
				else
				{
					if (_diagLog != null) { try { _diagLog.Log("COPIER", "SKIP_FOLLOWER_ZeroQty", "FillId=" + _fillId + "|Account=" + sssss + "|UsePositionDelta=" + usePositionDelta + "|PositionDelta=" + positionDelta); } catch { } }
					if (!_decGuardSuppressedThisIter) _decZeroQty++;
				}

				// NT 8.1.7.0 latency diag (2026-05-19): one line per follower
				// per master fill. GetPos1Ms = already-flat broker check (master
				// exits only). GuardGetPosMs = drift-guard live broker read
				// (0 means served from cache — common case). SubmitMs = managed
				// BuyMarket/SellMarket call cost. TotalMs = whole iteration.
				// Any value -1 means that step did not run on this iteration.
				if (_diagLog != null)
				{
					try
					{
						_diagLog.Log("COPIER", "LOOP_STEP_TIMING",
							"FillId=" + _fillId
							+ "|Account=" + sssss
							+ "|IsNewEntry=" + IsNewEntry
							+ "|GetPos1Ms=" + _msGetPos1.ToString("F1")
							+ "|GuardGetPosMs=" + _msGuardGetPos.ToString("F1")
							+ "|SubmitMs=" + _msSubmit.ToString("F1")
							+ "|TotalMs=" + _swIter.Elapsed.TotalMilliseconds.ToString("F1"));
					}
					catch { }
				}

			}

			// One-line decision summary per master fill. Replaces the chore of
			// grepping ~10 SUBMIT/SKIP lines to figure out whether all followers
			// got the action. Detail logs above still emit; this is at-a-glance.
			// LatchAllowed = exits that bypassed a goal/loss/funded latch
			// (Ron 2026-05-04 fix). LatchSkipped = entries blocked by latch.
			if (_diagLog != null)
			{
				try
				{
					int _totalSkipped = _decZeroQty + _decDriftGuard + _decLatchSkipped
						+ _decAlreadyFlat + _decDisconnected + _decSameAsMaster
						+ _decAccountModeMismatch + _decNullAccount + _decOtherSkip;
					string _skippedAccts = _decSkippedAccts.Count == 0 ? "none" : string.Join(",", _decSkippedAccts);
					_diagLog.Log("COPIER", "DECISION_SUMMARY",
						"FillId=" + _fillId
						+ "|Instrument=" + (SendInstrument != null ? SendInstrument.FullName : "?")
						+ "|MasterPos=" + totalmasterpos
						+ "|IsFinalExit=" + IsFinalExit
						+ "|IsNewEntry=" + IsNewEntry
						+ "|FollowerCount=" + AllDuplicateAccounts.Count
						+ "|Submitted=" + _decSubmitted
						+ "|TotalSkipped=" + _totalSkipped
						+ "|ZeroQty=" + _decZeroQty
						+ "|DriftGuard=" + _decDriftGuard
						+ "|LatchSkipped=" + _decLatchSkipped
						+ "|LatchAllowed=" + _decLatchAllowed
						+ "|AlreadyFlat=" + _decAlreadyFlat
						+ "|Disconnected=" + _decDisconnected
						+ "|SameAsMaster=" + _decSameAsMaster
						+ "|ModeMismatch=" + _decAccountModeMismatch
						+ "|NullAccount=" + _decNullAccount
						+ "|SkippedAccts=" + _skippedAccts);
				}
				catch { }
			}

			//Print(e.Execution.Account.Name + " " + e.Execution.Quantity + " " + e.Execution.MarketPosition);







		}



		
		
		
		 private void OnAccountItemUpdate3 (object sender, AccountItemEventArgs e)
	    {
			if (_diagLog == null || State != State.Realtime) return;

			// Whitelist — only items that matter for troubleshooting order flow.
			// NT8 re-emits margin/liquidation values every price tick (overnight
			// spam was 3 lines/sec per account with identical values). Cash and
			// realized P&L only change on fills/commissions, so they're useful.
			if (e.AccountItem != AccountItem.CashValue
				&& e.AccountItem != AccountItem.RealizedProfitLoss
				&& e.AccountItem != AccountItem.GrossRealizedProfitLoss
				&& e.AccountItem != AccountItem.Commission)
				return;

			try
			{
				// Dedupe — skip when the value hasn't actually changed.
				string key = e.Account.Name + "|" + e.AccountItem;
				double last;
				if (_diagLastAccountItemValue.TryGetValue(key, out last) && last == e.Value)
					return;
				_diagLastAccountItemValue[key] = e.Value;

				_diagLog.Log("ACCOUNT", "ITEM_UPDATE",
					"Account=" + e.Account.Name
					+ "|Item=" + e.AccountItem
					+ "|Value=" + e.Value
					+ "|Currency=" + e.Currency);
			}
			catch { }
	    }

