		private bool IsAccountFlat(Account thisacct)
		{
			if (thisacct == null)
				return true;
			
			if (pInstrumentMode == "All")
			{
				if (thisacct.Positions.Count != 0)
					return false;
			}
			else if (pInstrumentMode == "Single")
			{
				string iname = pSingleInstrument;
				Instrument sMicro = GetTheInstrument(iname, "Micro", false);
				Instrument sMini = GetTheInstrument(iname, "Mini", false);
				if (sMicro != null && thisacct.GetPosition(sMicro.Id) != null)
					return false;
				if (sMini != null && thisacct.GetPosition(sMini.Id) != null)
					return false;
			}
			else // Selected
			{
				if (thisacct.Positions != null)
					foreach (Position pp in thisacct.Positions)
						if (IsInstrumentTracked(pp.Instrument) && pp.MarketPosition != MarketPosition.Flat)
							return false;
			}
			
		
			return true;
		}
		/// <summary>
		/// Central instrument filter — returns true if this instrument falls within the current tracking scope.
		/// </summary>
		private bool IsInstrumentTracked(Instrument ii)
		{
			if (ii == null) return false;
			if (pInstrumentMode == "All") return true;
			try
			{
				Instrument miniInst = GetTheInstrument(ii.FullName, "Mini", false);
				if (miniInst == null) return false;
				string miniName = miniInst.FullName;
				if (pInstrumentMode == "Single")
				{
					if (string.IsNullOrEmpty(pSingleInstrument)) return false;
					Instrument singleMini = GetTheInstrument(pSingleInstrument, "Mini", false);
					return singleMini != null && miniName == singleMini.FullName;
				}
				// "Selected" — match both full name and bare symbol
				int sp = miniName.IndexOf(' ');
				string bareMin = sp > 0 ? miniName.Substring(0, sp) : miniName;
				return pSelectedInstrumentSet.Contains(miniName) || pSelectedInstrumentSet.Contains(bareMin);
			}
			catch { return false; }
		}

		/// <summary>
		/// Returns the button label text for the current instrument mode.
		/// </summary>
		/// <summary>
		/// Safely gets the bare symbol from pSingleInstrument (e.g. "ES" from "ES 06-25" or "ES").
		/// </summary>
		private string GetSingleInstrumentBareSymbol()
		{
			if (string.IsNullOrEmpty(pSingleInstrument)) return "??";
			try
			{
				Instrument inst = GetTheInstrument(pSingleInstrument, "Mini", false);
				if (inst == null) { int sp0 = pSingleInstrument.IndexOf(' '); return sp0 > 0 ? pSingleInstrument.Substring(0, sp0) : pSingleInstrument; }
				string fn = inst.FullName;
				int sp = fn.IndexOf(' ');
				return sp > 0 ? fn.Substring(0, sp) : fn;
			}
			catch { int sp2 = pSingleInstrument.IndexOf(' '); return sp2 > 0 ? pSingleInstrument.Substring(0, sp2) : pSingleInstrument; }
		}

		/// <summary>
		/// Gets the bare micro symbol for a given bare mini symbol (e.g. "ES" → "MES").
		/// </summary>
		private string GetMicroSymbol(string miniSymbol)
		{
			if (string.IsNullOrEmpty(miniSymbol)) return miniSymbol;
			// Strip contract month if present (e.g. "ES 06-25" → "ES")
			int sp0 = miniSymbol.IndexOf(' ');
			string bare = sp0 > 0 ? miniSymbol.Substring(0, sp0) : miniSymbol;
			string micro;
			if (MiniToMicro.TryGetValue(bare, out micro))
				return micro;
			return bare;
		}

		private string GetInstrumentModeLabel()
		{
			if (pInstrumentMode == "All")
				return "All Instruments";
			if (pInstrumentMode == "Single")
			{
				string mini = GetSingleInstrumentBareSymbol();
				string micro = GetMicroSymbol(mini);
				if (mini != micro)
					return mini + " (" + micro + ")";
				return mini;
			}
			// "Selected" — show up to 3 mini names.
			// When only one is selected, render it as MINI (MICRO) just like Single mode.
			List<string> names = new List<string>(pSelectedInstrumentSet);
			names.Sort(StringComparer.OrdinalIgnoreCase);
			if (names.Count == 1)
			{
				string only = names[0];
				int sp1 = only.IndexOf(' ');
				string mini1 = sp1 > 0 ? only.Substring(0, sp1) : only;
				string micro1 = GetMicroSymbol(mini1);
				return (mini1 != micro1) ? mini1 + " (" + micro1 + ")" : mini1;
			}
			StringBuilder sb = new StringBuilder();
			for (int i = 0; i < names.Count; i++)
			{
				if (i > 0) sb.Append(", ");
				string n = names[i];
				int sp = n.IndexOf(' ');
				sb.Append(sp > 0 ? n.Substring(0, sp) : n);
			}
			return sb.ToString();
		}

		/// <summary>
		/// Builds the detailed "Instrument tracking updated" status message.
		/// Format: Instrument tracking updated - Copying trades from 'account' on ES (MES) & NQ (MNQ)
		/// </summary>
		private string BuildInstrumentScopeMessage()
		{
			string account = pThisMasterAccount ?? string.Empty;
			string accountPart = string.IsNullOrEmpty(account) ? "Master account" : "'" + account + "'";

			string instrumentsPart;
			if (pInstrumentMode == "All")
			{
				instrumentsPart = "all instruments";
			}
			else if (pInstrumentMode == "Single")
			{
				string mini = GetSingleInstrumentBareSymbol();
				string micro = GetMicroSymbol(mini);
				instrumentsPart = (mini != micro) ? mini + " (" + micro + ")" : mini;
			}
			else
			{
				List<string> names = new List<string>(pSelectedInstrumentSet);
				names.Sort(StringComparer.OrdinalIgnoreCase);
				List<string> pairs = new List<string>();
				for (int i = 0; i < names.Count; i++)
				{
					string n = names[i];
					int sp = n.IndexOf(' ');
					string bare = sp > 0 ? n.Substring(0, sp) : n;
					string micro = GetMicroSymbol(bare);
					pairs.Add((bare != micro) ? bare + " (" + micro + ")" : bare);
				}
				if (pairs.Count == 0)
					instrumentsPart = "(no instruments selected)";
				else if (pairs.Count == 1)
					instrumentsPart = pairs[0];
				else
				{
					StringBuilder sbp = new StringBuilder();
					for (int i = 0; i < pairs.Count; i++)
					{
						if (i > 0)
							sbp.Append(i == pairs.Count - 1 ? " & " : ", ");
						sbp.Append(pairs[i]);
					}
					instrumentsPart = sbp.ToString();
				}
			}
			return "Instrument tracking updated - Copying trades from " + accountPart + " on " + instrumentsPart;
		}

		/// <summary>
		/// Returns tooltip text for the instrument mode button.
		/// </summary>
		private string GetInstrumentModeTooltip()
		{
			if (pInstrumentMode == "All")
				return IsKorean
					? "모든 상품: 마스터 계좌의 모든 상품 주문을 스캔하여 팔로워 계좌로 복사합니다. 클릭하여 '단일 상품' 모드로 전환."
					: "All Instruments: scanning the Master account for orders on every instrument and copying to Followers. Click to switch to 'Single Instrument' mode.";
			if (pInstrumentMode == "Single")
			{
				string mini = GetSingleInstrumentBareSymbol();
				string micro = GetMicroSymbol(mini);
				string pair = (mini != micro) ? mini + " and " + micro : mini;
				return IsKorean
					? "단일 상품: 마스터 계좌의 " + pair + " 주문만 스캔하여 팔로워 계좌로 복사합니다. 클릭하여 '선택된 상품' 모드로 전환."
					: "Single Instrument: scanning the Master account for " + pair + " orders only and copying to Followers. Click to switch to 'Selected Instruments' mode.";
			}
			// Selected
			List<string> names = new List<string>(pSelectedInstrumentSet);
			names.Sort(StringComparer.OrdinalIgnoreCase);
			StringBuilder pairs = new StringBuilder();
			for (int i = 0; i < names.Count; i++)
			{
				if (i > 0) pairs.Append(", ");
				string n = names[i];
				int sp = n.IndexOf(' ');
				string bare = sp > 0 ? n.Substring(0, sp) : n;
				string micro = GetMicroSymbol(bare);
				pairs.Append(bare);
				if (bare != micro) pairs.Append("/" + micro);
			}
			return IsKorean
				? "선택된 상품: 마스터 계좌의 " + pairs.ToString() + " 주문만 스캔하여 팔로워 계좌로 복사합니다. 클릭하여 '모든 상품' 모드로 전환."
				: "Selected Instruments: scanning the Master account for " + pairs.ToString() + " orders only and copying to Followers. Click to switch to 'All Instruments' mode.";
		}

		/// <summary>
		/// Returns the tab caption suffix for the current instrument mode.
		/// </summary>
		private string GetInstrumentScopeCaption()
		{
			if (pInstrumentMode == "All")
				return "All Instruments";
			if (pInstrumentMode == "Single")
			{
				string mini = GetSingleInstrumentBareSymbol();
				int sp = mini.IndexOf(' ');
				return sp > 0 ? mini.Substring(0, sp) : mini;
			}
			return GetInstrumentModeLabel();
		}

		/// <summary>
		/// Cycles instrument mode: All → Single → Selected → All.
		/// </summary>
		private string CycleInstrumentMode()
		{
			if (pInstrumentMode == "All")
				pInstrumentMode = "Single";
			else if (pInstrumentMode == "Single")
				pInstrumentMode = "Selected";
			else
				pInstrumentMode = "All";
			pAllInstruments = (pInstrumentMode == "All");
			return pInstrumentMode;
		}




		private bool HasFollowerHitGoalLossOrFunded(Account account)
		{
			if (account == null || string.IsNullOrEmpty(account.Name))
				return false;
			
			// Check the persistent latch first — this survives HitGoalOrLoss resets
			if (GoalLossFlattenLatch.ContainsKey(account.Name))
				return true;
			
			PNLStatistics stats;
			if (!FinalPNLStatistics.TryGetValue(account.Name, out stats))
				return false;
			return stats.HitGoalOrLoss != 0;
		}


		private bool AllMasterAndFollowersFlat()
		{
			if (CurrentMasterAccount != null && !IsAccountFlat(CurrentMasterAccount))
				return false;
			foreach (string name in AllDuplicateAccounts)
			{
				Account a = AccountFromName(name);
				if (a != null && !IsAccountFlat(a))
					return false;
			}
			return true;
		}
		
		private static bool AccountHasPendingOrders(Account acct)
		{
			if (acct?.Orders == null) return false;
			foreach (Order or in acct.Orders.ToList())
			{
				if (or.OrderState != OrderState.Filled && or.OrderState != OrderState.Cancelled && or.OrderState != OrderState.Rejected)
					return true;
			}
			return false;
		}
		
		private bool AnyMasterOrFollowerHasPendingOrders()
		{
			return CountMasterAndFollowersWithPendingOrders() > 0;
		}
		
		private int CountMasterAndFollowersWithPendingOrders()
		{
			int n = 0;
			if (CurrentMasterAccount != null && AccountHasPendingOrders(CurrentMasterAccount))
				n++;
			foreach (string name in AllDuplicateAccounts)
			{
				Account a = AccountFromName(name);
				if (a != null && AccountHasPendingOrders(a))
					n++;
			}
			return n;
		}
		
		private bool IsMasterAccountFlat()
		{
			if (CurrentMasterAccount == null)
				return true;
			
			if (pInstrumentMode == "All")
			{
				if (CurrentMasterAccount.Positions.Count == 0)
					return true;
			}
			else if (pInstrumentMode == "Single")
			{
				Instrument singleMini = GetTheInstrument(pSingleInstrument, "Mini", false);
				if (singleMini == null || CurrentMasterAccount.GetPosition(singleMini.Id) == null)
					return true;
			}
			else // Selected
			{
				bool anyTrackedPos = false;
				if (CurrentMasterAccount.Positions != null)
					foreach (Position pp in CurrentMasterAccount.Positions)
						if (IsInstrumentTracked(pp.Instrument) && pp.MarketPosition != MarketPosition.Flat)
							{ anyTrackedPos = true; break; }
				if (!anyTrackedPos) return true;
			}
			
		
			return false;
		}
	
				
