        internal void OnMouseUp(object sender, MouseButtonEventArgs e)
        {
			// IsDragging = false;

			// Stop the click-hold cursor reassert timer and do one final
			// reassert so the cursor is correct immediately on release.
			_mouseIsDown = false;
			if (_cursorHoldTimer != null)
				try { _cursorHoldTimer.Stop(); } catch { }
			ReassertDashCursor();

			// Release scrollbar drag
			if (IsDraggingScrollThumb)
			{
				IsDraggingScrollThumb = false;
				InvalidateVis(85);
			}
			// Release cheat sheet scrollbar drag
			if (_csDraggingThumb)
			{
				_csDraggingThumb = false;
				InvalidateVis(126);
			}

			// Release column resize drag
			if (_resizingColumnLogical >= 0)
			{
				_resizingColumnLogical = -1;
				SerializeColumnWidthOverridesNow();
				InvalidateVis(93);
			}

			// Apply deferred sort-by-column click: only if the user pressed down on a header
			// and released without activating a drag. A drag must not also sort.
			if (_pendingSortColumnClick != null && !_columnDragActivated)
			{
				string columns = _pendingSortColumnClick;
				if (pSelectedColumn == columns)
					pSelectedAscending = !pSelectedAscending;
				else
					pSelectedColumn = columns;
				IsSorted = false;
				InvalidateVis(26);
			}
			_pendingSortColumnClick = null;

			// Release column drag-to-reorder
			if (_columnDragArmed)
			{
				bool wasActivated = _columnDragActivated;
				_columnDragArmed = false;
				_columnDragActivated = false;
				_draggingColumnLogical = -1;
				_draggingColumnDisplayIdx = -1;
				_columnDragOrderSnapshot = null;
				// A real drag was in progress: OnMouseMove's drag branch returned early and
				// never updated the header-hover state. Reset it so the tooltip doesn't fire
				// instantly from the column where the drag started — the user must re-hover.
				if (wasActivated)
				{
					HoveredHeaderColumn = -1;
					HoveredHeaderStartTime = DateTime.MinValue;
					HoveredHeaderTooltipShown = false;
					if (TooltipCachedLayout != null) { TooltipCachedLayout.Dispose(); TooltipCachedLayout = null; TooltipCachedText = null; }
				}
				InvalidateVis(98);
			}

			// Release total-row drag-reorder: find which total-row rect the cursor
			// ended up over; if different from the one picked up, reorder via
			// userGroupOrder so the preference persists across refreshes. If the
			// cursor barely moved (< 4 px) AND ended up back on the same row,
			// treat it as a click-on-name and open the rename dialog.
			if (_draggingTotalRowPrefix != null)
			{
				string _src = _draggingTotalRowPrefix;
				string _dst = null;
				int _dstK = -1;
				for (int k = 0; k < _totalRowDragRects.Count; k++)
				{
					if (!MouseIn(_totalRowDragRects[k], 0, 0)) continue;
					_dst = _totalRowDragPrefixes[k];
					_dstK = k;
					break;
				}
				bool _movedEnough = Math.Abs((float)FinalYPixel - _totalRowDragStartY) > 2;

				if (_dst != null && _dst != _src && _movedEnough)
				{
					// Build full ordered list from all visible + all (unseen) hidden prefixes
					// so the reorder is stable. Start from current userGroupOrder, then append
					// any prefix we know about that isn't listed yet.
					var working = new List<string>(userGroupOrder);
					foreach (string _p in autoGroupPrefixes)
						if (!working.Contains(_p)) working.Add(_p);

					int si = working.IndexOf(_src);
					int di = working.IndexOf(_dst);
					if (si >= 0 && di >= 0 && si != di)
					{
						string _moved = working[si];
						working.RemoveAt(si);
						// Matches the insertion-marker visual:
						//   - Dragging UP   (di < si): marker at TOP of target → insert
						//     BEFORE target. RemoveAt(si) didn't shift di, so Insert(di,
						//     _moved) places the moved row right before the target.
						//   - Dragging DOWN (di > si): marker at BOTTOM of target →
						//     insert AFTER target. RemoveAt(si) shifted di down by one
						//     (target is now at di-1); inserting at di places the moved
						//     row AFTER the shifted target. Leaving di unchanged is what
						//     lets a drag-to-last-row actually land at the bottom.
						working.Insert(di, _moved);
						userGroupOrder = working;
						SerializeUserGroupOrderNow();
						ForceRefresh();
					}
				}
				// (Click-on-name rename was removed — rename is only via the
				// Actions-column "edit" button per user request.)

				_draggingTotalRowPrefix = null;
				_totalRowDragActivated = false;
				// Force an immediate redraw so the reordered rows appear on the
				// NEXT frame instead of waiting for the next mouse move.
				InvalidateVis(208);
			}
		}
		
		
		
		
			bool RithmicClicked = false;

		// Preview handlers for right-click: we need to cancel the chart's native
		// context menu when the user right-clicks a column header so our visibility
		// picker can be the sole response. PreviewMouseRightButton* fire BEFORE the
		// normal MouseDown/MouseUp, and ContextMenuOpening is the final chance to
		// cancel the menu. All three check MouseOverHeaderCell and mark e.Handled.
		private bool MouseIsOverHeaderCell()
		{
			try
			{
				if (this.ChartPanel == null) return false;
				if (HeaderColumnRects == null || HeaderColumnRects.Count == 0) return false;
				var mp = System.Windows.Input.Mouse.GetPosition(this.ChartPanel);
				double mx = mp.X * dpiScaleX;
				double my = mp.Y * dpiScaleY;
				for (int k = 0; k < HeaderColumnRects.Count; k++)
				{
					var r = HeaderColumnRects[k];
					if (mx >= r.X && mx <= r.Right && my >= r.Y && my <= r.Bottom)
						return true;
				}
			}
			catch { }
			return false;
		}

		internal void OnPreviewRightButtonDown(object sender, MouseButtonEventArgs e)
		{
			if (MouseIsOverHeaderCell())
			{
				// Open the picker right here (can't wait for MouseDown — that fires
				// AFTER the chart control has already decided to show its context menu
				// on up-release). OnMouseDown's right-click branch is idempotent, so
				// this just primes _colPickerOpen.
				try { OnMouseDown(sender, e); } catch { }
				e.Handled = true;
			}
		}

		internal void OnPreviewRightButtonUp(object sender, MouseButtonEventArgs e)
		{
			if (MouseIsOverHeaderCell())
				e.Handled = true;
		}

		internal void OnChartContextMenuOpening(object sender, System.Windows.Controls.ContextMenuEventArgs e)
		{
			if (MouseIsOverHeaderCell())
			{
				e.Handled = true;
				return;
			}

			try
			{
				if (!pHideChartMenuItems)
				{
					RestoreHiddenChartMenuItems();
					return;
				}

				var menu = FindChartContextMenu(sender, e);
				if (menu == null) return;
				HideTargetedChartMenuItems(menu);
				EnsureCustomChartMenuItems(menu);
			}
			catch { }
		}

		private static readonly string[] _chartMenuItemsToHide = new string[]
		{
			"Alerts",
			"Strategies",
			"Strategy Performance",
			"Drawing Tools",
			"Paste",
			"Zoom In",
			"Zoom Out",
			"Show Data Box",
			"Crosshair",
			"Instrument",
			"Intervals",
			"Show Indicators",
			"Data Series",
			"Properties",
			"Save Chart Image As",
			"Save Chart Image",
		};

		private System.Windows.Controls.ContextMenu FindChartContextMenu(object sender, System.Windows.Controls.ContextMenuEventArgs e)
		{
			var fe = sender as System.Windows.FrameworkElement;
			if (fe != null && fe.ContextMenu != null) return fe.ContextMenu;

			fe = e != null ? e.Source as System.Windows.FrameworkElement : null;
			while (fe != null)
			{
				if (fe.ContextMenu != null) return fe.ContextMenu;
				fe = System.Windows.Media.VisualTreeHelper.GetParent(fe) as System.Windows.FrameworkElement;
			}

			if (ChartControl != null && ChartControl.ContextMenu != null) return ChartControl.ContextMenu;
			return null;
		}

		private static string NormalizeMenuHeader(object header)
		{
			if (header == null) return string.Empty;
			string s = header.ToString();
			if (string.IsNullOrEmpty(s)) return string.Empty;
			s = s.Replace("_", "");
			int dotdot = s.IndexOf("...");
			if (dotdot >= 0) s = s.Substring(0, dotdot);
			return s.Trim();
		}

		private void HideTargetedChartMenuItems(System.Windows.Controls.ContextMenu menu)
		{
			if (menu == null || menu.Items == null) return;

			for (int i = 0; i < menu.Items.Count; i++)
			{
				var mi = menu.Items[i] as System.Windows.Controls.MenuItem;
				if (mi == null) continue;
				if (mi.Visibility != System.Windows.Visibility.Visible) continue;

				string h = NormalizeMenuHeader(mi.Header);
				if (string.IsNullOrEmpty(h)) continue;

				for (int t = 0; t < _chartMenuItemsToHide.Length; t++)
				{
					if (string.Equals(h, _chartMenuItemsToHide[t], StringComparison.OrdinalIgnoreCase))
					{
						mi.Visibility = System.Windows.Visibility.Collapsed;
						hiddenChartMenuItems.Add(mi);
						break;
					}
				}
			}

			// Collapse leading / adjacent separators left over from the hidden items.
			bool prevVisibleIsSeparator = true;
			for (int i = 0; i < menu.Items.Count; i++)
			{
				var sep = menu.Items[i] as System.Windows.Controls.Separator;
				if (sep != null)
				{
					if (sep.Visibility != System.Windows.Visibility.Visible) continue;
					if (prevVisibleIsSeparator)
					{
						sep.Visibility = System.Windows.Visibility.Collapsed;
						hiddenChartMenuSeparators.Add(sep);
					}
					else
					{
						prevVisibleIsSeparator = true;
					}
					continue;
				}

				var fe = menu.Items[i] as System.Windows.FrameworkElement;
				if (fe != null && fe.Visibility == System.Windows.Visibility.Visible)
					prevVisibleIsSeparator = false;
			}

			// Trailing separator: hide any visible separator at the end of the menu.
			for (int i = menu.Items.Count - 1; i >= 0; i--)
			{
				var sep = menu.Items[i] as System.Windows.Controls.Separator;
				if (sep != null)
				{
					if (sep.Visibility == System.Windows.Visibility.Visible)
					{
						sep.Visibility = System.Windows.Visibility.Collapsed;
						hiddenChartMenuSeparators.Add(sep);
					}
					continue;
				}

				var fe = menu.Items[i] as System.Windows.FrameworkElement;
				if (fe != null && fe.Visibility == System.Windows.Visibility.Visible) break;
			}
		}

		private void RestoreHiddenChartMenuItems()
		{
			try
			{
				for (int i = 0; i < hiddenChartMenuItems.Count; i++)
				{
					var mi = hiddenChartMenuItems[i];
					if (mi != null) mi.Visibility = System.Windows.Visibility.Visible;
				}
				hiddenChartMenuItems.Clear();

				for (int i = 0; i < hiddenChartMenuSeparators.Count; i++)
				{
					var sep = hiddenChartMenuSeparators[i];
					if (sep != null) sep.Visibility = System.Windows.Visibility.Visible;
				}
				hiddenChartMenuSeparators.Clear();
			}
			catch { }

			RemoveCustomChartMenuItems();
		}

		private static readonly string[] _customMenuHeaders = new string[]
		{
			"Duplicate Account Actions",
			"Account Risk Manager",
			"NinjaTrader Log Files",
			"NinjaTrader Trace Files",
			"NinjaTrader Templates",
			"Send Template to Affordable Indicators",
			"Send Information To Support",
			"Accounts Dashboard Properties",
			"Send Diagnostics",
			"Open NinjaTrader Log Folder",
			"Save Window Image",
		};

		private bool IsOurMenuItem(System.Windows.Controls.MenuItem mi)
		{
			return mi == _addedToggleCopy || mi == _addedToggleRisk
				|| mi == _addedSendTemplate || mi == _addedProperties
				|| mi == _addedSaveImage;
		}

		private bool IsOurSeparator(System.Windows.Controls.Separator sep)
		{
			return sep == _addedMenuSeparator || sep == _addedDiagSeparator;
		}

		private static string GetMenuItemHeaderText(System.Windows.Controls.MenuItem mi)
		{
			if (mi.Header == null) return "";
			if (mi.Header is string s) return s;
			// StackPanel header (Send Diagnostics) — walk children for text
			var sp = mi.Header as System.Windows.Controls.StackPanel;
			if (sp != null)
			{
				string result = "";
				for (int c = 0; c < sp.Children.Count; c++)
				{
					var tb = sp.Children[c] as System.Windows.Controls.TextBlock;
					if (tb != null) result += tb.Text;
				}
				return result.Trim();
			}
			return mi.Header.ToString();
		}

		private void PurgeStaleCustomMenuItems(System.Windows.Controls.ContextMenu menu)
		{
			// Remove items left behind by a previous indicator instance (e.g. after
			// NinjaScript reload) whose Terminated cleanup didn't run in time.
			for (int i = menu.Items.Count - 1; i >= 0; i--)
			{
				// Remove orphan separators that aren't ours
				var sep = menu.Items[i] as System.Windows.Controls.Separator;
				if (sep != null && !IsOurSeparator(sep))
				{
					// Check if neighbors are also separators or edges — collapse doubles
					bool prevIsSep = (i == 0) || (menu.Items[i - 1] is System.Windows.Controls.Separator);
					if (prevIsSep)
					{
						menu.Items.RemoveAt(i);
						continue;
					}
				}

				var mi = menu.Items[i] as System.Windows.Controls.MenuItem;
				if (mi == null) continue;
				// Skip items we own in this instance
				if (IsOurMenuItem(mi)) continue;

				string h = GetMenuItemHeaderText(mi);
				if (string.IsNullOrEmpty(h)) continue;

				for (int t = 0; t < _customMenuHeaders.Length; t++)
				{
					if (h.IndexOf(_customMenuHeaders[t], StringComparison.OrdinalIgnoreCase) >= 0)
					{
						menu.Items.RemoveAt(i);
						break;
					}
				}
			}
			// Remove orphaned separators at the start of the menu
			while (menu.Items.Count > 0 && menu.Items[0] is System.Windows.Controls.Separator)
				menu.Items.RemoveAt(0);
			// Remove orphaned separators at the end of the menu
			while (menu.Items.Count > 0 && menu.Items[menu.Items.Count - 1] is System.Windows.Controls.Separator)
				menu.Items.RemoveAt(menu.Items.Count - 1);
		}

		private void EnsureCustomChartMenuItems(System.Windows.Controls.ContextMenu menu)
		{
			if (menu == null || menu.Items == null) return;
			try
			{
				PurgeStaleCustomMenuItems(menu);

				// Items inserted at the top of the menu (index 0, 1, 2, 3)
				int idx = 0;

				if (_addedToggleCopy == null || !menu.Items.Contains(_addedToggleCopy))
				{
					_addedToggleCopy = new System.Windows.Controls.MenuItem();
					_addedToggleCopy.Header = "Duplicate Account Actions";
					_addedToggleCopy.IsCheckable = true;
					_addedToggleCopy.StaysOpenOnClick = false;
					_addedToggleCopy.Click += OnToggleCopyFunctionsClick;
					menu.Items.Insert(idx, _addedToggleCopy);
				}
				else
				{
					menu.Items.Remove(_addedToggleCopy);
					menu.Items.Insert(idx, _addedToggleCopy);
				}
				_addedToggleCopy.IsChecked = pIsCopyBasicFunctionsChecked;
				idx++;

				if (_addedToggleRisk == null || !menu.Items.Contains(_addedToggleRisk))
				{
					_addedToggleRisk = new System.Windows.Controls.MenuItem();
					_addedToggleRisk.Header = "Account Risk Manager";
					_addedToggleRisk.IsCheckable = true;
					_addedToggleRisk.StaysOpenOnClick = false;
					_addedToggleRisk.Click += OnToggleRiskFunctionsClick;
					menu.Items.Insert(idx, _addedToggleRisk);
				}
				else
				{
					menu.Items.Remove(_addedToggleRisk);
					menu.Items.Insert(idx, _addedToggleRisk);
				}
				_addedToggleRisk.IsChecked = pIsRiskFunctionsChecked;
				idx++;

				if (_addedDiagSeparator == null || !menu.Items.Contains(_addedDiagSeparator))
				{
					_addedDiagSeparator = new System.Windows.Controls.Separator();
					menu.Items.Insert(idx, _addedDiagSeparator);
				}
				idx++;

				if (_addedProperties == null || !menu.Items.Contains(_addedProperties))
				{
					_addedProperties = new System.Windows.Controls.MenuItem();
					_addedProperties.Header = "Accounts Dashboard Properties";
					_addedProperties.Click += OnPropertiesMenuClick;
					menu.Items.Insert(idx, _addedProperties);
				}
				else
				{
					menu.Items.Remove(_addedProperties);
					menu.Items.Insert(idx, _addedProperties);
				}
				idx++;

				// Insert "Save Window Image" after "Show Tabs"
				{
					int saveIdx = -1;
					for (int s = 0; s < menu.Items.Count; s++)
					{
						var smi = menu.Items[s] as System.Windows.Controls.MenuItem;
						if (smi == null) continue;
						string sh = NormalizeMenuHeader(smi.Header);
						if (string.Equals(sh, "Show Tabs", StringComparison.OrdinalIgnoreCase))
						{ saveIdx = s + 1; break; }
					}
					if (saveIdx < 0) saveIdx = menu.Items.Count;

					if (_addedSaveImage == null || !menu.Items.Contains(_addedSaveImage))
					{
						_addedSaveImage = new System.Windows.Controls.MenuItem();
						_addedSaveImage.Header = "Save Window Image";
						_addedSaveImage.Click += OnSaveWindowImageClick;
						menu.Items.Insert(saveIdx, _addedSaveImage);
					}
					else
					{
						menu.Items.Remove(_addedSaveImage);
						menu.Items.Insert(Math.Min(saveIdx, menu.Items.Count), _addedSaveImage);
					}
				}

				if (_addedSendTemplate == null || !menu.Items.Contains(_addedSendTemplate))
				{
					_addedSendTemplate = new System.Windows.Controls.MenuItem();
					var sp = new System.Windows.Controls.StackPanel { Orientation = System.Windows.Controls.Orientation.Horizontal };
					sp.Children.Add(new System.Windows.Controls.TextBlock { Text = "Send Diagnostics " });
					sp.Children.Add(new System.Windows.Controls.TextBlock { Text = "(Affordable Indicators)", Opacity = 0.5 });
					_addedSendTemplate.Header = sp;
					_addedSendTemplate.Click += OnSendTemplateClick;
					menu.Items.Insert(idx, _addedSendTemplate);
				}
				else
				{
					menu.Items.Remove(_addedSendTemplate);
					menu.Items.Insert(idx, _addedSendTemplate);
				}
				idx++;

				// Separator below our items
				if (_addedMenuSeparator == null || !menu.Items.Contains(_addedMenuSeparator))
				{
					_addedMenuSeparator = new System.Windows.Controls.Separator();
					menu.Items.Insert(idx, _addedMenuSeparator);
				}
				else
				{
					menu.Items.Remove(_addedMenuSeparator);
					menu.Items.Insert(idx, _addedMenuSeparator);
				}
			}
			catch { }
		}

		private void RemoveCustomChartMenuItems()
		{
			try
			{
				if (_addedToggleCopy != null)
				{
					_addedToggleCopy.Click -= OnToggleCopyFunctionsClick;
					var p = _addedToggleCopy.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_addedToggleCopy);
					_addedToggleCopy = null;
				}
				if (_addedToggleRisk != null)
				{
					_addedToggleRisk.Click -= OnToggleRiskFunctionsClick;
					var p = _addedToggleRisk.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_addedToggleRisk);
					_addedToggleRisk = null;
				}
				if (_addedProperties != null)
				{
					_addedProperties.Click -= OnPropertiesMenuClick;
					var p = _addedProperties.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_addedProperties);
					_addedProperties = null;
				}
				if (_addedSaveImage != null)
				{
					_addedSaveImage.Click -= OnSaveWindowImageClick;
					var p = _addedSaveImage.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_addedSaveImage);
					_addedSaveImage = null;
				}
				if (_addedSendTemplate != null)
				{
					_addedSendTemplate.Click -= OnSendTemplateClick;
					var p = _addedSendTemplate.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_addedSendTemplate);
					_addedSendTemplate = null;
				}
				if (_addedMenuSeparator != null)
				{
					var p = _addedMenuSeparator.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_addedMenuSeparator);
					_addedMenuSeparator = null;
				}
				if (_addedDiagSeparator != null)
				{
					var p = _addedDiagSeparator.Parent as System.Windows.Controls.ContextMenu;
					if (p != null) p.Items.Remove(_addedDiagSeparator);
					_addedDiagSeparator = null;
				}
			}
			catch { }
		}

