		private void OnSaveWindowImageClick(object sender, System.Windows.RoutedEventArgs e)
		{
			try
			{
				ChartControl.Dispatcher.InvokeAsync(new Action(() =>
				{
					try
					{
						Chart cw = chartWindow ?? (Window.GetWindow(ChartControl.Parent) as Chart);
						if (cw == null) return;

						var wih = new System.Windows.Interop.WindowInteropHelper(cw);
						IntPtr hwnd = wih.Handle;
						if (hwnd == IntPtr.Zero) return;

						SetForegroundWindow(hwnd);
						System.Threading.Thread.Sleep(100);

						AITR_RECT rc;
						GetWindowRect(hwnd, out rc);
						int width = rc.Right - rc.Left;
						int height = rc.Bottom - rc.Top;
						if (width <= 0 || height <= 0) return;

						IntPtr hdcScreen = GetDC(IntPtr.Zero);
						IntPtr hdcMem = CreateCompatibleDC(hdcScreen);
						IntPtr hBitmap = CreateCompatibleBitmap(hdcScreen, width, height);
						IntPtr hOld = SelectObject(hdcMem, hBitmap);

						BitBlt(hdcMem, 0, 0, width, height, hdcScreen, rc.Left, rc.Top, 0x00CC0020);

						SelectObject(hdcMem, hOld);

						var bmpSource = System.Windows.Interop.Imaging.CreateBitmapSourceFromHBitmap(
							hBitmap, IntPtr.Zero, System.Windows.Int32Rect.Empty,
							BitmapSizeOptions.FromEmptyOptions());

						DeleteObject(hBitmap);
						DeleteDC(hdcMem);
						ReleaseDC(IntPtr.Zero, hdcScreen);

						var dlg = new Microsoft.Win32.SaveFileDialog();
						dlg.Filter = "PNG Image|*.png";
						dlg.DefaultExt = ".png";
						dlg.FileName = "AccountsDashboard_" + DateTime.Now.ToString("yyyyMMdd_HHmmss");
						if (dlg.ShowDialog(cw) == true)
						{
							var encoder = new PngBitmapEncoder();
							encoder.Frames.Add(BitmapFrame.Create(bmpSource));
							using (var fs = new System.IO.FileStream(dlg.FileName, System.IO.FileMode.Create))
							{
								encoder.Save(fs);
							}
						}
					}
					catch { }
				}));
			}
			catch { }
		}

		private void OnSendTemplateClick(object sender, System.Windows.RoutedEventArgs e)
		{
			if (_isSendingTemplate) return;
			_isSendingTemplate = true;

			if (_diagLog != null)
				_diagLog.Log("UI", "SEND_DIAGNOSTICS", "Started=true");

			try
			{
				// --- Capture screenshot BEFORE showing toast, so the toast does not appear in the image ---
				// (BitBlt from screen captures DirectX rendered content)
				byte[] screenshotBytes = null;
				try
				{
					Chart cw = chartWindow ?? (Window.GetWindow(ChartControl.Parent) as Chart);
					if (cw != null)
					{
						var wih = new System.Windows.Interop.WindowInteropHelper(cw);
						IntPtr hwnd = wih.Handle;
						if (hwnd != IntPtr.Zero)
						{
							// Bring the chart window to front so nothing overlaps it
							SetForegroundWindow(hwnd);
							System.Threading.Thread.Sleep(100);

							AITR_RECT rc;
							GetWindowRect(hwnd, out rc);
							int width = rc.Right - rc.Left;
							int height = rc.Bottom - rc.Top;
							if (width > 0 && height > 0)
							{
								IntPtr hdcScreen = GetDC(IntPtr.Zero);
								IntPtr hdcMem = CreateCompatibleDC(hdcScreen);
								IntPtr hBitmap = CreateCompatibleBitmap(hdcScreen, width, height);
								IntPtr hOld = SelectObject(hdcMem, hBitmap);

								// SRCCOPY = 0x00CC0020 — copy directly from screen at window position
								BitBlt(hdcMem, 0, 0, width, height, hdcScreen, rc.Left, rc.Top, 0x00CC0020);

								SelectObject(hdcMem, hOld);

								var bmpSource = System.Windows.Interop.Imaging.CreateBitmapSourceFromHBitmap(
									hBitmap, IntPtr.Zero, System.Windows.Int32Rect.Empty,
									BitmapSizeOptions.FromEmptyOptions());

								var encoder = new PngBitmapEncoder();
								encoder.Frames.Add(BitmapFrame.Create(bmpSource));
								using (var ms = new System.IO.MemoryStream())
								{
									encoder.Save(ms);
									screenshotBytes = ms.ToArray();
								}

								DeleteObject(hBitmap);
								DeleteDC(hdcMem);
								ReleaseDC(IntPtr.Zero, hdcScreen);
							}
						}
					}
				}
				catch { }

				// Show toast only after screenshot is captured
				AddMessage("Sending information to the Affordable Indicators team...", 10, Brushes.Goldenrod);

				// --- Capture chart template XML via reflection ---
				byte[] templateBytes = null;
				try
				{
					Chart cw = chartWindow ?? (Window.GetWindow(ChartControl.Parent) as Chart);
					if (cw != null)
					{
						System.Xml.Linq.XDocument doc = new System.Xml.Linq.XDocument(new System.Xml.Linq.XElement("NinjaTrader"));
						bool saved = false;

						// Try 3-param: Save(XDocument, XElement, bool)
						System.Reflection.MethodInfo saveMethod = typeof(Chart).GetMethod("Save",
							System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance,
							null, new Type[] { typeof(System.Xml.Linq.XDocument), typeof(System.Xml.Linq.XElement), typeof(bool) }, null);
						if (saveMethod != null)
						{
							saveMethod.Invoke(cw, new object[] { doc, doc.Root, true });
							saved = true;
						}

						// Fallback: 2-param Save(XDocument, XElement)
						if (!saved)
						{
							saveMethod = typeof(Chart).GetMethod("Save",
								System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance,
								null, new Type[] { typeof(System.Xml.Linq.XDocument), typeof(System.Xml.Linq.XElement) }, null);
							if (saveMethod != null)
							{
								saveMethod.Invoke(cw, new object[] { doc, doc.Root });
								saved = true;
							}
						}

						if (saved)
						{
							string xml = doc.ToString();
							if (xml.Length > 50)
								templateBytes = System.Text.Encoding.UTF8.GetBytes(xml);
						}
					}
				}
				catch { }

				// Flush ADS diagnostic log on UI thread; zipping happens off-UI below
				try { if (_diagLog != null) _diagLog.Flush(); } catch { }
				string adsDiagLogDir = (_diagLog != null) ? _diagLog.LogDirectory : null;
				string userDataDir = NinjaTrader.Core.Globals.UserDataDir;

				// --- Upload + zip on background thread so the window stays interactive ---
				string email = pLicensingEmailAddress ?? "";
				string machineId = NinjaTrader.Cbi.License.MachineId ?? "";
				string version = pCurrentVersionName ?? "";
				string product = ThisName ?? "";

				System.Threading.Tasks.Task.Run(() =>
				{
					try
					{
						// --- Zip log files (background thread) ---
						byte[] logsZipBytes = null;
						try
						{
							string logPath = System.IO.Path.Combine(userDataDir, "log");
							if (System.IO.Directory.Exists(logPath))
								logsZipBytes = ZipDirectoryContents(logPath);
						}
						catch { }

						// --- Zip trace files ---
						byte[] traceZipBytes = null;
						try
						{
							string tracePath = System.IO.Path.Combine(userDataDir, "trace");
							if (System.IO.Directory.Exists(tracePath))
								traceZipBytes = ZipDirectoryContents(tracePath);
						}
						catch { }

						// --- Zip ADS diagnostic log files ---
						byte[] diagLogZipBytes = null;
						try
						{
							if (!string.IsNullOrEmpty(adsDiagLogDir) && System.IO.Directory.Exists(adsDiagLogDir))
								diagLogZipBytes = ZipDirectoryContents(adsDiagLogDir);
						}
						catch { }

						// --- Zip ECT diagnostic logs (sibling indicator) ---
						byte[] ectLogsZipBytes = null;
						try
						{
							string ectLogPath = System.IO.Path.Combine(
								userDataDir,
								"Affordable Indicators", "Enhanced Chart Trader", "log");
							if (System.IO.Directory.Exists(ectLogPath))
								ectLogsZipBytes = ZipDirectoryContents(ectLogPath);
						}
						catch { }

						if (screenshotBytes == null && templateBytes == null && logsZipBytes == null && traceZipBytes == null && diagLogZipBytes == null && ectLogsZipBytes == null)
						{
							try
							{
								ChartControl.Dispatcher.InvokeAsync(() =>
								{
									RemoveMessage("Sending information");
									AddMessage("Nothing to send — capture failed.", 8, Brushes.Red);
								});
							}
							catch { }
							return;
						}

						string boundary = "----AiTemplateBoundary" + DateTime.Now.Ticks.ToString("x");
						string dateStr = DateTime.UtcNow.ToString("yyyy-MM-dd");
						string apiKey = GenerateSendTemplateApiKey(email, machineId, dateStr);

						try { System.Net.ServicePointManager.SecurityProtocol = System.Net.SecurityProtocolType.Tls12; } catch { }

						HttpWebRequest request = (HttpWebRequest)WebRequest.Create(_sendTemplateEndpoint);
						request.Method = "POST";
						request.ContentType = "multipart/form-data; boundary=" + boundary;
						request.UserAgent = "NinjaTrader-aiDuplicateAccountActions/" + version;
						request.Timeout = 120000;
						request.ReadWriteTimeout = 120000;
						request.Headers.Add("X-AI-Api-Key", apiKey);
						request.Headers.Add("X-AI-Date", dateStr);
						try { request.Proxy = System.Net.WebRequest.GetSystemWebProxy(); if (request.Proxy != null) request.Proxy.Credentials = System.Net.CredentialCache.DefaultNetworkCredentials; } catch { request.Proxy = null; }

						using (var requestStream = request.GetRequestStream())
						{
							WriteMultipartField(requestStream, boundary, "email", email);
							WriteMultipartField(requestStream, boundary, "machine_id", machineId);
							WriteMultipartField(requestStream, boundary, "version", version);
							WriteMultipartField(requestStream, boundary, "product", product);
							WriteMultipartField(requestStream, boundary, "timestamp", DateTime.UtcNow.ToString("o"));

							if (screenshotBytes != null)
								WriteMultipartFile(requestStream, boundary, "screenshot", "chart_screenshot.png", "image/png", screenshotBytes);

							if (templateBytes != null)
								WriteMultipartFile(requestStream, boundary, "template", "chart_template.xml", "application/xml", templateBytes);

							if (logsZipBytes != null)
								WriteMultipartFile(requestStream, boundary, "logs", "logs.zip", "application/zip", logsZipBytes);

							if (traceZipBytes != null)
								WriteMultipartFile(requestStream, boundary, "trace", "trace.zip", "application/zip", traceZipBytes);

								if (diagLogZipBytes != null)
									WriteMultipartFile(requestStream, boundary, "custom_ads", "custom_ads.zip", "application/zip", diagLogZipBytes);

								if (ectLogsZipBytes != null)
									WriteMultipartFile(requestStream, boundary, "custom_ect", "custom_ect.zip", "application/zip", ectLogsZipBytes);

							byte[] closingBytes = System.Text.Encoding.UTF8.GetBytes("--" + boundary + "--\r\n");
							requestStream.Write(closingBytes, 0, closingBytes.Length);
						}

						int maxRetries = 3;
						int retryDelayMs = 2000;
						bool success = false;
						for (int attempt = 1; attempt <= maxRetries && !success; attempt++)
						{
							try
							{
								using (HttpWebResponse response = (HttpWebResponse)request.GetResponse())
								using (StreamReader reader = new StreamReader(response.GetResponseStream()))
								{
									reader.ReadToEnd();
								}
								success = true;
							}
							catch
							{
								if (attempt < maxRetries)
									System.Threading.Thread.Sleep(retryDelayMs);
								else
									throw;
							}
						}

						try
						{
							ChartControl.Dispatcher.InvokeAsync(() =>
							{
								RemoveMessage("Sending information");
									AddMessage("Information sent successfully!", 8, Brushes.Green);
							});
						}
						catch { }
					}
					catch (Exception ex)
					{
						// Print("SendTemplate upload error: " + ex.Message);
						try
						{
							ChartControl.Dispatcher.InvokeAsync(() =>
							{
								RemoveMessage("Sending information");
									AddMessage("Send failed: " + ex.Message, 10, Brushes.Red);
							});
						}
						catch { }
					}
					finally
					{
						_isSendingTemplate = false;
					}
				});
			}
			catch (Exception ex)
			{
				// Print("SendTemplate error: " + ex.Message);
				RemoveMessage("Sending information");
				AddMessage("Send failed: " + ex.Message, 10, Brushes.Red);
				_isSendingTemplate = false;
			}
		}

		private byte[] ZipDirectoryContents(string dirPath)
		{
			// Build ZIP using System.IO.Packaging.ZipPackage (available in NT8 without extra references)
			string tempZip = System.IO.Path.Combine(System.IO.Path.GetTempPath(), "aitr_" + Guid.NewGuid().ToString("N") + ".zip");
			try
			{
				using (var package = System.IO.Packaging.Package.Open(tempZip, System.IO.FileMode.Create))
				{
					string[] files = System.IO.Directory.GetFiles(dirPath, "*", System.IO.SearchOption.TopDirectoryOnly);
					foreach (string filePath in files)
					{
						try
						{
							string entryName = System.IO.Path.GetFileName(filePath);
							// ZipPackage requires URI-formatted part names starting with /
							Uri partUri = new Uri("/" + Uri.EscapeDataString(entryName), UriKind.Relative);
							var part = package.CreatePart(partUri, "application/octet-stream", System.IO.Packaging.CompressionOption.Fast);
							using (var partStream = part.GetStream())
							using (var fs = new System.IO.FileStream(filePath, System.IO.FileMode.Open, System.IO.FileAccess.Read, System.IO.FileShare.ReadWrite))
							{
								fs.CopyTo(partStream);
							}
						}
						catch { } // skip files locked by NT8
					}
				}
				return System.IO.File.ReadAllBytes(tempZip);
			}
			finally
			{
				try { if (System.IO.File.Exists(tempZip)) System.IO.File.Delete(tempZip); } catch { }
			}
		}

		private string GenerateSendTemplateApiKey(string email, string machineId, string dateStr)
		{
			string message = email + "|" + machineId + "|" + dateStr;
			byte[] keyBytes = System.Text.Encoding.UTF8.GetBytes(_sendTemplateSecret);
			byte[] messageBytes = System.Text.Encoding.UTF8.GetBytes(message);
			using (var hmac = new System.Security.Cryptography.HMACSHA256(keyBytes))
			{
				byte[] hash = hmac.ComputeHash(messageBytes);
				return BitConverter.ToString(hash).Replace("-", "").ToLowerInvariant();
			}
		}

		private void WriteMultipartField(System.IO.Stream stream, string boundary, string name, string value)
		{
			string header = "--" + boundary + "\r\n"
				+ "Content-Disposition: form-data; name=\"" + name + "\"\r\n\r\n"
				+ value + "\r\n";
			byte[] headerBytes = System.Text.Encoding.UTF8.GetBytes(header);
			stream.Write(headerBytes, 0, headerBytes.Length);
		}

		private void WriteMultipartFile(System.IO.Stream stream, string boundary, string fieldName, string fileName, string mimeType, byte[] data)
		{
			string header = "--" + boundary + "\r\n"
				+ "Content-Disposition: form-data; name=\"" + fieldName + "\"; filename=\"" + fileName + "\"\r\n"
				+ "Content-Type: " + mimeType + "\r\n\r\n";
			byte[] headerBytes = System.Text.Encoding.UTF8.GetBytes(header);
			stream.Write(headerBytes, 0, headerBytes.Length);
			stream.Write(data, 0, data.Length);
			byte[] newline = System.Text.Encoding.UTF8.GetBytes("\r\n");
			stream.Write(newline, 0, newline.Length);
		}

		// Freeze-diagnostic: PreviewMouseDown observers kept as no-ops so the
		// AddHandler subscriptions stay in the visual tree (RemoveFreezeHandlers
		// relies on stable delegate references to unsubscribe). Flip
		// _freezeDebugEnabled on to resurrect the logging bodies.
		private void OnPreviewMouseDownDiag(object sender, MouseButtonEventArgs e) { }
		private void OnPreviewMouseDownDiagCtl(object sender, MouseButtonEventArgs e) { }
		private void OnPreviewMouseDownDiagWin(object sender, MouseButtonEventArgs e) { }

        internal void OnMouseDown(object sender, MouseButtonEventArgs e)
        {
			AllowRedraw = true;

			// Pin the custom cursor for the duration of the click hold so NT's
			// default cursor doesn't flash through between mouse-down and
			// mouse-up. Reassert immediately, then keep reasserting every
			// ~16ms via a short-lived DispatcherTimer until MouseUp.
			_mouseIsDown = true;
			ReassertDashCursor();
			if (_cursorHoldTimer == null && ChartControl != null)
			{
				try
				{
					ChartControl.Dispatcher.InvokeAsync(() =>
					{
						if (_cursorHoldTimer == null)
						{
							_cursorHoldTimer = new System.Windows.Threading.DispatcherTimer
								{ Interval = TimeSpan.FromMilliseconds(16) };
							_cursorHoldTimer.Tick += (s, ev) =>
							{
								if (_mouseIsDown) ReassertDashCursor();
								else { try { _cursorHoldTimer.Stop(); } catch { } }
							};
							_cursorHoldTimer.Start();
						}
					});
				}
				catch { }
			}
			else if (_cursorHoldTimer != null)
			{
				try { _cursorHoldTimer.Start(); } catch { }
			}

			// Any click dismisses an active cell tooltip.
			// Also capture the tooltip's rect as a "suppress zone" — while the
			// mouse remains inside this rect the tooltip won't be shown again
			// (prevents it reappearing one frame later on the cell you just
			// clicked). Cleared once the mouse exits the rect.
			if (_cellTipRect.Width > 0)
			{
				_cellTipSuppressRect = _cellTipRect;
				_cellTipSuppressExpiry = DateTime.Now.AddMilliseconds(1500);
			}
			_cellTipText = null;
			_cellTipAnchorX = -1;
			_cellTipAnchorY = -1;

			try
			{

				if (e.ChangedButton == MouseButton.Right)
				{
					// Right-click on a header cell opens the column visibility picker.
					// Right-click anywhere else closes an open picker (but does not
					// otherwise affect mouse-down state).
					this.MP = e.GetPosition(this.ChartPanel);
					FinalXPixel = MP.X * dpiScaleX;
					FinalYPixel = MP.Y * dpiScaleY;

					// Right-click on a profile picker item → rename
					if (_profilePickerOpen)
					{
						for (int _rpi = 0; _rpi < _profilePickerItemRects.Count; _rpi++)
						{
							if (_profilePickerItemRects[_rpi].Width > 0 && MouseIn(_profilePickerItemRects[_rpi], 0, 0))
							{
								string _oldName = _profilePickerItemNames[_rpi];
								if (_oldName == "---" || _oldName == "Save New Profile" || _oldName == "Update Current Profile" || _oldName == "Properties" || _oldName == "Reset Hidden Accounts" || _oldName == "Reset Account Selections")
									break;
								_profilePickerOpen = false;
								ChartControl.Dispatcher.InvokeAsync(() =>
								{
									try
									{
										string newName = "";
										NTWindow _renWin = new NTWindow { Caption = "Rename Profile", Width = 320, Height = 180, WindowStartupLocation = WindowStartupLocation.CenterScreen, ResizeMode = ResizeMode.NoResize, Topmost = true };
										try { _renWin.Owner = Window.GetWindow(ChartControl.Parent); } catch { }
										StackPanel _rsp = new StackPanel { Margin = new Thickness(12) };
										_rsp.Children.Add(new TextBlock { Text = "Rename '" + _oldName + "' to:", Margin = new Thickness(0, 0, 0, 8), Foreground = System.Windows.Media.Brushes.White, TextWrapping = TextWrapping.Wrap });
										TextBox _rtb = new TextBox { Text = _oldName };
										_rsp.Children.Add(_rtb);
										Button _renOk = new Button { Content = "Rename", Width = 80, Margin = new Thickness(0, 10, 0, 0), HorizontalAlignment = HorizontalAlignment.Right };
										_renOk.Click += (s4, e4) => { newName = _rtb.Text; _renWin.Close(); };
										_rsp.Children.Add(_renOk);
										_renWin.Content = _rsp;
										_renWin.ShowDialog();
										if (!string.IsNullOrEmpty(newName) && newName != _oldName)
										{
											foreach (char c in System.IO.Path.GetInvalidFileNameChars())
												newName = newName.Replace(c, '_');
											string _srcPath = System.IO.Path.Combine(_profilesDir, _oldName + ".xml");
											string _dstPath = System.IO.Path.Combine(_profilesDir, newName + ".xml");
											if (System.IO.File.Exists(_srcPath))
											{
												System.IO.File.Move(_srcPath, _dstPath);
												AddMessage("Profile renamed to '" + newName + "'.", 6, Brushes.Goldenrod);
												if (_activeProfileName == _oldName)
													_activeProfileName = newName;
											}
										}
									}
									catch (Exception ex) { AddMessage("Rename error: " + ex.Message, 10, Brushes.Red); }
								});
								InvalidateVis(107);
								return;
							}
						}
					}

					bool _openedPicker = false;
					if (HeaderColumnRects != null && HeaderColumnRects.Count > 0)
					{
						for (int _rk = 0; _rk < HeaderColumnRects.Count; _rk++)
						{
							if (MouseIn(HeaderColumnRects[_rk], 0, 0))
							{
								_colPickerOpen = true;
								_colPickerJustOpened = true; // tells the next render frame to reset _pickerSortAlphabetical → canonical order on each open
								_colPickerX = (float)FinalXPixel;
								// +6 below header row matches the tooltip + filter overlay
								// vertical offset so all three popups line up consistently.
								_colPickerY = HeaderColumnRects[_rk].Bottom + ButtonTooltipGapPx;
								_openedPicker = true;
								InvalidateVis(102);
								break;
							}
						}
					}
					if (!_openedPicker && _colPickerOpen)
					{
						_colPickerOpen = false;
						InvalidateVis(103);
					}
					return;
				}

			}
			catch (Exception ex)
			{



			}
	
		
			
		
			//ResetAllTimers();
			
			
			
            this.MP = e.GetPosition(this.ChartPanel);


			FinalXPixel = MP.X * dpiScaleX;
			FinalYPixel = MP.Y * dpiScaleY;

			// Cheat sheet overlay: intercept left-clicks on the close (X) button BEFORE
			// any other mouse-down handling so it works regardless of what's underneath.
			if (_cheatSheetOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& _cheatSheetCloseRect.Width > 0 && _cheatSheetCloseRect.Height > 0
				&& MouseIn(_cheatSheetCloseRect, 0, 0))
			{
				_cheatSheetOpen = false;
				InvalidateVis(122);
				return;
			}

			// Cheat sheet hyperlink lines — open the URL in the default browser
			// when the user clicks a [text](url) line from the remote Google Doc.
			if (_cheatSheetOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& _qrgLinkRects != null && _qrgLinkRects.Count > 0)
			{
				for (int _qi = 0; _qi < _qrgLinkRects.Count && _qi < _qrgLinkUrls.Count; _qi++)
				{
					if (MouseIn(_qrgLinkRects[_qi], 0, 0))
					{
						try { System.Diagnostics.Process.Start(_qrgLinkUrls[_qi]); } catch { }
						return;
					}
				}
			}

			// Cheat sheet tooltip-toggle checkboxes — flip the matching flag.
			if (_cheatSheetOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed)
			{
				if (_csTipsHeadersRect.Width > 0 && MouseIn(_csTipsHeadersRect, 0, 0))
				{
					pTooltipsColumnHeaders = !pTooltipsColumnHeaders;
					InvalidateVis(125);
					return;
				}
				if (_csTipsCellsRect.Width > 0 && MouseIn(_csTipsCellsRect, 0, 0))
				{
					pTooltipsCells = !pTooltipsCells;
					InvalidateVis(126);
					return;
				}
				if (_csTipsButtonsRect.Width > 0 && MouseIn(_csTipsButtonsRect, 0, 0))
				{
					pTooltipsButtons = !pTooltipsButtons;
					InvalidateVis(127);
					return;
				}
			}

			// Cheat sheet video link click — opens the tutorial in the default browser.
			if (_cheatSheetOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& _csVideoLinkRect.Width > 0 && _csVideoLinkRect.Height > 0
				&& MouseIn(_csVideoLinkRect, 0, 0))
			{
				try { System.Diagnostics.Process.Start("https://youtu.be/klrWtrUP7y4"); } catch { }
				return;
			}

			// Cheat sheet scrollbar: thumb drag + track page-jump (same pattern as main table).
			if (_cheatSheetOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& _csScrollTrackRect.Width > 0 && _csScrollTrackRect.Height > 0)
			{
				if (MouseIn(_csScrollThumbRect, 0, 0))
				{
					_csDraggingThumb = true;
					_csDragStartMouseY = (float)FinalYPixel;
					_csDragStartOffset = _csScrollOffset;
					return;
				}
				else if (MouseIn(_csScrollTrackRect, 0, 0))
				{
					// Click on track above/below thumb — page jump.
					if (FinalYPixel < _csScrollThumbRect.Top)
						_csScrollOffset = Math.Max(0, _csScrollOffset - 10);
					else if (FinalYPixel > _csScrollThumbRect.Bottom)
						_csScrollOffset = _csScrollOffset + 10;
					InvalidateVis(124);
					return;
				}
			}

			// Cheat sheet: click anywhere OUTSIDE the overlay closes it.
			// Must come after all other cheat-sheet handlers (close X, checkboxes,
			// hyperlink lines, video link, scrollbar) so intra-overlay clicks get
			// their chance to handle the event first.
			if (_cheatSheetOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& _csBgRect.Width > 0 && _csBgRect.Height > 0
				&& !MouseIn(_csBgRect, 0, 0))
			{
				_cheatSheetOpen = false;
				InvalidateVis(129);
				return;
			}

			// Profile picker: intercept left-clicks on delete X buttons
			if (_profilePickerOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed)
			{
				for (int _dpi = 0; _dpi < _profilePickerDeleteRects.Count; _dpi++)
				{
					if (_profilePickerDeleteRects[_dpi].Width > 0 && MouseIn(_profilePickerDeleteRects[_dpi], 0, 0))
					{
						string _delName = _profilePickerItemNames[_dpi];
						// Keep picker open so the user sees the result immediately after confirming/cancelling.
						// Run dialog synchronously (we're on the UI thread here) — no Dispatcher.InvokeAsync lag.
						try
						{
							NTWindow _confirmWin = new NTWindow { Caption = "Delete Profile", Width = 360, Height = 170, WindowStartupLocation = WindowStartupLocation.CenterScreen, ResizeMode = ResizeMode.NoResize, Topmost = true };
							try { _confirmWin.Owner = Window.GetWindow(ChartControl.Parent); } catch { }
							bool _confirmed = false;

							// Match the Accounts Dashboard Properties window pattern:
							// content grid with a body row (auto) and a bottom button bar
							// separated by a 1px divider.
							var _root = new Grid();
							_root.RowDefinitions.Add(new RowDefinition { Height = new GridLength(1, GridUnitType.Star) });
							_root.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });

							var _body = new StackPanel { Margin = new Thickness(12) };
							_body.Children.Add(new TextBlock { Text = "Delete profile '" + _delName + "'?", Foreground = System.Windows.Media.Brushes.White, TextWrapping = TextWrapping.Wrap });
							Grid.SetRow(_body, 0);
							_root.Children.Add(_body);

							var _separator = new Separator
							{
								Margin = new Thickness(0),
								Background = FrozenRgbBrush(61, 61, 66),
								Height = 1
							};
							var _buttonBar = new StackPanel
							{
								Orientation = Orientation.Horizontal,
								HorizontalAlignment = HorizontalAlignment.Right,
								Margin = new Thickness(0, 21, 7, 7)
							};
							Button _yesBtn = new Button { Content = "Delete", MinWidth = 86, MinHeight = 27, Margin = new Thickness(0, 0, 7, 0) };
							_yesBtn.Click += (s3, e3) => { _confirmed = true; _confirmWin.Close(); };
							Button _noBtn = new Button { Content = "Cancel", MinWidth = 86, MinHeight = 27, Margin = new Thickness(0), IsCancel = true };
							_noBtn.Click += (s3, e3) => { _confirmWin.Close(); };
							_buttonBar.Children.Add(_yesBtn);
							_buttonBar.Children.Add(_noBtn);

							var _bottomPanel = new StackPanel { Orientation = Orientation.Vertical };
							_bottomPanel.Children.Add(_separator);
							_bottomPanel.Children.Add(_buttonBar);
							Grid.SetRow(_bottomPanel, 1);
							_root.Children.Add(_bottomPanel);

							_confirmWin.Content = _root;
							_confirmWin.ShowDialog();
							if (_confirmed)
							{
								string _delPath = System.IO.Path.Combine(_profilesDir, _delName + ".xml");
								if (System.IO.File.Exists(_delPath))
								{
									if (_diagLog != null)
										_diagLog.Log("CONFIG", "PROFILE_DELETE", "Name=" + _delName);
									System.IO.File.Delete(_delPath);
									AddMessage("Profile '" + _delName + "' deleted.", 6, Brushes.Goldenrod);
									if (_activeProfileName == _delName)
										_activeProfileName = "";
								}
							}
						}
						catch (Exception ex)
						{
							AddMessage("Error deleting profile: " + ex.Message, 10, Brushes.Red);
						}
						InvalidateVis(106);
						return;
					}
				}
			}

			// Profile picker: intercept left-clicks on items
			if (_profilePickerOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed)
			{
				bool _clickedProfileItem = false;
				for (int _pi = 0; _pi < _profilePickerItemRects.Count; _pi++)
				{
					if (_profilePickerItemRects[_pi].Width > 0 && MouseIn(_profilePickerItemRects[_pi], 0, 0))
					{
						string _clickedName = _profilePickerItemNames[_pi];
						if (_clickedName == "---") continue;
						ActivateProfileMenuItem(_clickedName);
						_clickedProfileItem = true;
						break;
					}
				}

				// Click outside the popup closes it
				if (!_clickedProfileItem && !MouseIn(_profilePickerBgRect, 0, 0))
				{
					_profilePickerOpen = false;
				}
				InvalidateVis(131);
				if (_clickedProfileItem || !MouseIn(_profilePickerBgRect, 0, 0))
					return;
			}


			// --- Latency menu popup: handle clicks ---
			// Runs before the button-click loop, so the click that OPENS the menu
			// (menu still closed here) passes through untouched.
			if (_latencyMenuOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed)
			{
				if (_latencyThreshMinusRect.Width > 0 && MouseIn(_latencyThreshMinusRect, 0, 0))
					LatencySlowThresholdMs = pLatencySlowThresholdMs - 25;
				else if (_latencyThreshPlusRect.Width > 0 && MouseIn(_latencyThreshPlusRect, 0, 0))
					LatencySlowThresholdMs = pLatencySlowThresholdMs + 25;
				else
				{
					for (int _lmi = 0; _lmi < _latencyMenuItemRects.Count && _lmi < _latencyMenuItemNames.Count; _lmi++)
					{
						if (_latencyMenuItemRects[_lmi].Width <= 0 || !MouseIn(_latencyMenuItemRects[_lmi], 0, 0))
							continue;
						string _lmn = _latencyMenuItemNames[_lmi];
						if (_lmn == "Dispatch Latency")          pLatencyDispatch     = !pLatencyDispatch;
						else if (_lmn == "Confirmation Latency") pLatencyConfirmation = !pLatencyConfirmation;
						else if (_lmn == "__RESET__") { _latActionStats.Clear(); }
						break;
					}
				}
				// A click outside the panel closes the menu; either way the click is
				// swallowed so it can't fall through to the dashboard row beneath.
				if (!MouseIn(_latencyMenuBgRect, 0, 0))
					_latencyMenuOpen = false;
				InvalidateVis(132);
				return;
			}

			// Embedded edit icon inside the instrument mode button — toggle picker.
			if (e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& _instEditSubRect.Width > 0 && MouseIn(_instEditSubRect, 0, 0))
			{
				_instPickerOpen = !_instPickerOpen;
				if (_instPickerOpen)
				{
					_instPickerX = _instModeButtonRect.Left;
					_instPickerY = _instModeButtonRect.Top - ButtonTooltipGapPx;
					_instPickerPendingSet.Clear();
					if (pInstrumentMode == "Single" && !string.IsNullOrEmpty(pSingleInstrument))
						_instPickerPendingSet.Add(GetSingleInstrumentBareSymbol());
					else if (pInstrumentMode == "Selected")
					{
						foreach (string s in pSelectedInstrumentSet)
						{
							int sp = s.IndexOf(' ');
							_instPickerPendingSet.Add(sp > 0 ? s.Substring(0, sp) : s);
						}
					}
				}
				InvalidateVis(98);
				return;
			}

			// Instrument picker: intercept left-clicks on the open popup.
			// Single mode: click selects instrument, applies immediately, closes picker.
			// Selected mode: click toggles checkbox, stays open (like column picker).
			if (_instPickerOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed)
			{
				bool _ipHandled = false;
				for (int _pi = 0; _pi < _instPickerItemRects.Count && _pi < _instPickerItemNames.Count; _pi++)
				{
					if (MouseIn(_instPickerItemRects[_pi], 0, 0))
					{
						string _ipn = _instPickerItemNames[_pi];
						if (pInstrumentMode == "Single")
						{
							// Single mode: select this instrument, apply, and close.
							pSingleInstrument = _ipn;
							_instPickerPendingSet.Clear();
							_instPickerPendingSet.Add(_ipn);
							_instPickerOpen = false;
							RemoveMessage("Instrument tracking updated");
							RemoveMessage("Instrument scope");
							if (!IsKorean)
								AddMessage(BuildInstrumentScopeMessage(), 10, Brushes.Goldenrod);
							else
							{
								string modeLabel = GetInstrumentModeLabel();
								AddMessage("종목 범위가 업데이트되었습니다: " + modeLabel + " 추적 중.", 10, Brushes.Goldenrod);
							}
						}
						else
						{
							// Selected/All mode: toggle checkbox, max 3, stay open.
							bool _instSetChanged = false;
							if (_instPickerPendingSet.Contains(_ipn))
							{
								// In Selected mode, at least one instrument must remain checked.
								if (pInstrumentMode == "Selected" && _instPickerPendingSet.Count <= 1)
								{
									RemoveMessage("at least one instrument");
									AddMessage("You must have at least one instrument selected.", 5, Brushes.Red);
									_ipHandled = true;
									break;
								}
								_instPickerPendingSet.Remove(_ipn);
								_instSetChanged = true;
							}
							else if (_instPickerPendingSet.Count < 3)
							{
								_instPickerPendingSet.Add(_ipn);
								_instSetChanged = true;
							}
							else
							{
								RemoveMessage("Maximum of 3");
								AddMessage("Maximum of 3 instruments can be selected.", 5, Brushes.Red);
							}
							// Apply immediately to the backing set
							pSelectedInstrumentSet.Clear();
							List<string> sorted = new List<string>(_instPickerPendingSet);
							sorted.Sort(StringComparer.OrdinalIgnoreCase);
							StringBuilder sb = new StringBuilder();
							for (int si = 0; si < sorted.Count; si++)
							{
								if (si > 0) sb.Append(";");
								sb.Append(sorted[si]);
								pSelectedInstrumentSet.Add(sorted[si]);
							}
							pSelectedInstrumentList = sb.ToString();

							if (_instSetChanged)
							{
								RemoveMessage("Instrument tracking updated");
								RemoveMessage("Instrument scope");
								if (!IsKorean)
									AddMessage(BuildInstrumentScopeMessage(), 10, Brushes.Goldenrod);
								else
								{
									string modeLabel = GetInstrumentModeLabel();
									AddMessage("종목 범위가 업데이트되었습니다: " + modeLabel + " 추적 중.", 10, Brushes.Goldenrod);
								}
							}
						}
						_ipHandled = true;
						break;
					}
				}
				// Click outside picker closes it
				if (!_ipHandled && _instPickerBgRect.Width > 0 && !MouseIn(_instPickerBgRect, 0, 0))
					_instPickerOpen = false;
				InvalidateVis(97);
				return;
			}

			// Column visibility picker: intercept left-clicks on the open popup BEFORE
			// any other mouse-down handling. Clicks on an item toggle that column's
			// visibility; Shift-click moves the clicked column UP in display order,
			// Ctrl-click moves it DOWN. Clicks outside close the popup.
			if (_colPickerOpen && e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed)
			{
				// Alphabetical sort toggle (top-right of picker bg) — flip state and
				// stay open so the user immediately sees the re-sorted picker.
				if (_pickerSortToggleRect.Width > 0 && MouseIn(_pickerSortToggleRect, 0, 0))
				{
					_pickerSortAlphabetical = !_pickerSortAlphabetical;
					InvalidateVis(120);
					return;
				}

				// Preset slot row — empty slot click saves current layout into it,
				// filled slot click loads it. Picker stays OPEN so user can see
				// the effect and toggle more if needed.
				for (int _ps = 0; _ps < _presetSlotRects.Count; _ps++)
				{
					if (!MouseIn(_presetSlotRects[_ps], 0, 0)) continue;
					string _existing = GetPresetSlotString(_ps);
					if (string.IsNullOrEmpty(_existing))
						SetPresetSlotString(_ps, BuildLayoutSnapshot());
					else
						ApplyLayoutSnapshot(_existing);
					InvalidateVis(121);
					return;
				}

				// "Reset Widths" button — clears only column width overrides. Stays open.
				if (_resetWidthsRect.Width > 0 && MouseIn(_resetWidthsRect, 0, 0))
				{
					if (ColumnWidthOverrides != null) ColumnWidthOverrides.Clear();
					if (_pendingColumnWidthOverridesByName != null) _pendingColumnWidthOverridesByName.Clear();
					_columnWidthOverridesNeedApply = false;
					pColumnWidthOverrides = "";
					InvalidateVis(122);
					return;
				}

				// "Reset All" button — full layout reset (order, widths, hidden, toggles, sort). Stays open.
				if (_resetAllRect.Width > 0 && MouseIn(_resetAllRect, 0, 0))
				{
					ResetColumnLayout();
					InvalidateVis(123);
					return;
				}

				bool _clickedItem = false;
				int  _hitIdx = -1;
				for (int _pi = 0; _pi < _colPickerItemRects.Count && _pi < _colPickerItemNames.Count; _pi++)
				{
					if (MouseIn(_colPickerItemRects[_pi], 0, 0))
					{
						_hitIdx = _pi;
						_clickedItem = true;
						break;
					}
				}
				if (_clickedItem)
				{
					string _cn = _colPickerItemNames[_hitIdx];
					// Reset Layout footer — sentinel name bypasses the normal
					// column-toggle path and wipes all layout customizations.
					if (_cn == "__RESET_LAYOUT__")
					{
						ResetColumnLayout();
						_colPickerOpen = false;
						InvalidateVis(117);
						return;
					}
					bool _shiftDown = (Keyboard.Modifiers & ModifierKeys.Shift) == ModifierKeys.Shift;
					bool _ctrlDown  = (Keyboard.Modifiers & ModifierKeys.Control) == ModifierKeys.Control;
					if ((_shiftDown || _ctrlDown) && !string.IsNullOrEmpty(_cn) && ColumnDisplayOrderList != null && ColumnNumberToName != null)
					{
						// Find the logical id for this column name.
						int _targetLogical = -1;
						foreach (var _kv in ColumnNumberToName)
						{
							if (_kv.Value == _cn) { _targetLogical = _kv.Key; break; }
						}
						int _displayIdx = (_targetLogical >= 0) ? ColumnDisplayOrderList.IndexOf(_targetLogical) : -1;
						if (_displayIdx >= 0)
						{
							int _newIdx = _shiftDown ? _displayIdx - 1 : _displayIdx + 1;
							// Don't move past locked columns at either end.
							if (_newIdx >= 0 && _newIdx < ColumnDisplayOrderList.Count)
							{
								string _neighborName = GetColumnNameByDisplayIndex(_newIdx);
								if (!string.IsNullOrEmpty(_neighborName) && !IsColumnLockedNoScroll(_neighborName))
								{
									int _tmp = ColumnDisplayOrderList[_displayIdx];
									ColumnDisplayOrderList[_displayIdx] = ColumnDisplayOrderList[_newIdx];
									ColumnDisplayOrderList[_newIdx] = _tmp;
									SyncColumnDisplayOrderNames();
								}
							}
						}
						InvalidateVis(104);
						return;
					}
					if (!string.IsNullOrEmpty(_cn) && !IsColumnLockedNoScroll(_cn))
					{
						// Feature-toggle columns (Size/Type/Mode/Fade/Actions) flip
						// both pIs*ColumnEnabled AND pIs*Enabled so the column and
						// its copier feature toggle in lockstep.
						if (IsFeatureToggleColumn(_cn))
						{
							SetFeatureToggleState(_cn, !GetFeatureToggleState(_cn));
						}
						// Columns gated by a master property (Payout, Avg Price,
						// Realized, Cash Value, Commissions, etc.) — flip the
						// master directly so the column is added to / removed
						// from AllColumns on the next frame.
						else if (HasColumnMasterProperty(_cn))
						{
							SetColumnMasterPropertyState(_cn, !GetColumnMasterPropertyState(_cn));
						}
						// Everything else is a plain display-visibility toggle
						// stored in _hiddenColumns.
						else
						{
							if (_hiddenColumns.Contains(_cn)) _hiddenColumns.Remove(_cn);
							else _hiddenColumns.Add(_cn);
							SerializeHiddenColumnsNow();
						}
					}
					InvalidateVis(104);
					return; // stay open so user can toggle multiple
				}
				// Click outside any item (but on the bg rect) — stay open; outside the
				// bg rect entirely closes the picker AND swallows the click so the
				// underlying row buttons don't fire. Without this swallow, clicking
				// "anywhere" to close the picker would also send the click to the
				// account row beneath it (e.g. flatten the wrong account).
				if (!MouseIn(_colPickerBgRect, 0, 0))
				{
					_colPickerOpen = false;
					InvalidateVis(105);
					return;
				}
				else
				{
					return;
				}
			}

			// Column resize — start drag (or double-click reset) if hovering a column border
			if (e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& _hoveredResizeColumnLogical >= 0)
			{
				// Double-click a resize divider resets the column to its default
				// auto-computed width — just clear the user override and let the
				// next frame's measurement pass decide the width from cell content.
				if (e.ClickCount >= 2)
				{
					if (ColumnWidthOverrides.ContainsKey(_hoveredResizeColumnLogical))
					{
						ColumnWidthOverrides.Remove(_hoveredResizeColumnLogical);
						SerializeColumnWidthOverridesNow();
					}
					InvalidateVis(96);
					return;
				}

				// Single click — start a drag
				_resizingColumnLogical = _hoveredResizeColumnLogical;
				_resizeDragStartMouseX = (float)FinalXPixel;
				int currentWidth;
				if (!ColumnNumberToWidth.TryGetValue(_resizingColumnLogical, out currentWidth))
					currentWidth = 50;
				_resizeDragStartWidth = currentWidth;
				return;
			}

			// Scrollbar interaction — click thumb to drag, click track to jump
			if (e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& ScrollTrackRect.Width > 0 && ScrollTrackRect.Height > 0)
			{
				if (MouseIn(ScrollThumbRect, 0, 0))
				{
					IsDraggingScrollThumb = true;
					ScrollDragStartMouseY = (float)FinalYPixel;
					ScrollDragStartAdjustmentRows = AdjustmentRows;
					return;
				}
				else if (MouseIn(ScrollTrackRect, 0, 0))
				{
					// Click on track above/below thumb — page jump with momentum
					if (FinalYPixel < ScrollThumbRect.Top)
					{
						ScrollBy(-MaximumAccountRows);
					}
					else if (FinalYPixel > ScrollThumbRect.Bottom)
					{
						ScrollBy(MaximumAccountRows);
					}
					InvalidateVis(84);
					return;
				}
			}

			// Arm column drag-to-reorder if user clicked on a column header (not a resize border).
			// Drag activates after the mouse moves more than ColumnDragActivationDistance pixels,
			// distinguishing a click (sort/select) from a drag (reorder).
			if (e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& HeaderColumnRects != null && HeaderColumnRects.Count > 0
				&& ColumnDisplayOrderList != null)
			{
				// HeaderColumnRects is COMPACTED (only visible columns). Resolve
				// each rect to its logical id via the parallel HeaderColumnLogicalIds,
				// then find that logical id's position in ColumnDisplayOrderList —
				// that's the actual display index the drag code should track.
				for (int k = 0; k < HeaderColumnRects.Count && k < HeaderColumnLogicalIds.Count; k++)
				{
					if (!MouseIn(HeaderColumnRects[k], 0, 0)) continue;
					int logicalId = HeaderColumnLogicalIds[k];
					int displayIdx = ColumnDisplayOrderList.IndexOf(logicalId);
					if (displayIdx < 0) break;
					string colName;
					if (!ColumnNumberToName.TryGetValue(logicalId, out colName)) break;
					// Don't allow drag from locked columns
					if (string.IsNullOrEmpty(colName) || IsColumnLockedNoScroll(colName)) break;
					_columnDragArmed = true;
					_columnDragActivated = false;
					_draggingColumnLogical = logicalId;
					_draggingColumnDisplayIdx = displayIdx;
					_columnDragStartX = (float)FinalXPixel;
					_columnDragStartY = (float)FinalYPixel;
					_columnDragCurrentX = (float)FinalXPixel;
					// Snapshot order so ESC can roll back an in-progress drag
					_columnDragOrderSnapshot = new List<int>(ColumnDisplayOrderList);
					break;
				}
			}

			// Arm total-row drag-reorder: mouse down on a total-row Account cell.
			// Ghost rows (visible while the restore drawer is expanded) are
			// draggable so users can reorder them alongside normal rows.
			if (e.ChangedButton == MouseButton.Left && e.ButtonState == MouseButtonState.Pressed
				&& !_columnDragArmed && _draggingTotalRowPrefix == null
				&& pAutoGroupAccounts)
			{
				for (int k = 0; k < _totalRowDragRects.Count; k++)
				{
					if (!MouseIn(_totalRowDragRects[k], 0, 0)) continue;
					string _prefix = _totalRowDragPrefixes[k];
					_draggingTotalRowPrefix = _prefix;
					_totalRowDragStartY = (float)FinalYPixel;
					_totalRowDragCurrentY = (float)FinalYPixel;
					_totalRowDragActivated = false;
					InvalidateVis(206);
					break;
				}
			}

