			if (AllErrorMessages.Count > 0)
			{
				// Clicked the explicit "X" dismiss button — close without opening URL.
				if (_errorBannerDismissRect.Width > 0 && MouseIn(_errorBannerDismissRect, 0, 0))
				{
					AllErrorMessages.Clear();
					_errorBannerDismissRect = new SharpDX.RectangleF(0, 0, 0, 0);
					InvalidateVis(113);
					return;
				}

				bool _wasEmailPromptBanner = false;
