								double defaultDailyLoss = (Math.Ceiling(pnlAdjust / pAdjustmentDollars) - 1) * pAdjustmentDollars;
								
								ThisInitial = defaultDailyLoss;
								//ThisInitial = Math.Min(pInitialLoss, defaultDailyLoss);
								
								
								
								//ThisInitial = pInitialLoss;
								
								if (LastDailyLossNumber != 0)
									ThisInitial = LastDailyLossNumber;
								
								if (current == DefaultForZero)
