		// Fired when the mouse cursor leaves the ChartPanel bounds. Clear every
		// tooltip-related state so nothing lingers on screen while the user is
		// away. Next OnMouseMove will re-populate state as needed.
		internal void OnPanelMouseLeave(object sender, System.Windows.Input.MouseEventArgs e)
		{
			// Cell-level tooltip
			_cellTipText = null;
			_cellTipAnchorX = -1;
			_cellTipAnchorY = -1;

			// Button tooltips (top + bottom rows)
			_deferredTopBtnTipText = null;
			_deferredBotBtnTipText = null;

			// Column-header tooltip
			HoveredHeaderColumn = -1;
			HoveredHeaderStartTime = DateTime.MinValue;
			HoveredHeaderTooltipShown = false;

			// Instrument mode button tooltip
			_instModeButtonHovered = false;
			_instModeTooltipShown = false;
			_instModeButtonHoverStart = DateTime.MinValue;

			// Profile picker diff tooltip (currently disabled but clear anyway)
			_profileHoverTipName = null;
			_profileHoverTipText = null;

			try { InvalidateVis(209); } catch { }
		}

		internal void OnMouseMove(object sender, System.Windows.Input.MouseEventArgs e)
    	{
			// Keep crosshair forced off whenever this indicator is applied —
			// the right-click menu's Crosshair toggle is hidden but the keyboard
			// shortcut and other code paths can still re-enable it. Cheap
			// idempotent check on every mouse move ensures it stays off.
			if (pHideChartMenuItems && myProperties != null)
			{
				try
				{
					if (myProperties.CrosshairCrosshairType != CrosshairType.Off)
						myProperties.CrosshairCrosshairType = CrosshairType.Off;
				}
				catch { }
			}


//			chartWindow.Focus();
//			ChartControl.Focus();


            this.MP = e.GetPosition(this.ChartPanel);

			FinalXPixel = MP.X * dpiScaleX;
			FinalYPixel = MP.Y * dpiScaleY;

			// Hidden-groups pill hover-change → immediate redraw so the hover colors
			// don't lag the cursor. Only invalidates when the state actually flips.
			if (_hiddenGroupsPillRect.Width > 0 && _hiddenGroupsPillRect.Height > 0)
			{
				bool _hgHovNow = MouseIn(_hiddenGroupsPillRect, 0, 0);
				if (_hgHovNow != _hgPrevHov)
				{
					_hgPrevHov = _hgHovNow;
					InvalidateVis(202);
				}
			}
			else if (_hgPrevHov)
			{
				_hgPrevHov = false;
			}

			// Total-row Account-cell hover → hand cursor.
			bool _trAcctHovNow = false;
			for (int _trI = 0; _trI < _totalRowDragRects.Count; _trI++)
			{
				if (MouseIn(_totalRowDragRects[_trI], 0, 0))
				{
					_trAcctHovNow = true;
					break;
				}
			}
			if (_trAcctHovNow != _anyTotalRowAcctHovered)
			{
				_anyTotalRowAcctHovered = _trAcctHovNow;
				InvalidateVis(205);
			}

			// Restore-drawer auto-collapse timer: refresh the deadline whenever
			// the mouse moves over the pill itself or ANY total row rect — the
			// drawer stays open as long as the user is interacting with totals.
			if (_hiddenRowsExpanded)
			{
				bool _anyTotalHov = _trAcctHovNow
					|| (_hiddenGroupsPillRect.Width > 0 && MouseIn(_hiddenGroupsPillRect, 0, 0));
				// MaxY (the render-loop's table-bottom tracker) is scoped to
				// OnRender, so fall back to ChartPanel.H as the lower bound
				// for "is the cursor in the totals band".
				float _totalsMaxY = (ChartPanel != null) ? (float)ChartPanel.H : float.MaxValue;
				if (!_anyTotalHov && _totalRowTops != null && _totalRowTops.Count > 0
					&& FinalYPixel >= _totalRowTops[0] && FinalYPixel <= _totalsMaxY)
				{
					// Activity anywhere in the totals band (e.g. approaching the
					// restore button in the Actions column) keeps the drawer open.
					_anyTotalHov = true;
				}
				if (_anyTotalHov)
					_hiddenRowsExpireAt = DateTime.Now.AddSeconds(HiddenRowsAutoCollapseSec);
			}

			// Total-row drag-reorder: track drag activation + current Y. Activates
			// on any meaningful mouse movement (2-px) so a small drag isn't lost.
			if (_draggingTotalRowPrefix != null)
			{
				_totalRowDragCurrentY = (float)FinalYPixel;
				if (!_totalRowDragActivated
					&& Math.Abs(_totalRowDragCurrentY - _totalRowDragStartY) > 2)
				{
					_totalRowDragActivated = true;
					InvalidateVis(206);
				}
				// Continuously invalidate so the source tint + insertion marker
				// track the cursor smoothly, even if the source row's row index
				// changes mid-drag due to the user dragging over the target.
				InvalidateVis(207);
			}

			// Auto-close the column visibility picker when the mouse wanders more
			// than ColPickerAutoCloseSlackPx pixels outside the picker's bg rect.
			// Without this, the picker can stick around indefinitely if the user
			// changes their mind and starts doing something else on the chart.
			// Also invalidates ON every move over the picker's bg rect so the
			// per-item hover tint refreshes under the cursor — without this the
			// hover state only updates when some other code happens to fire a
			// redraw, making the menu feel laggy.
			if (_colPickerOpen && _colPickerBgRect.Width > 0 && _colPickerBgRect.Height > 0)
			{
				// 25px is enough on the L/R/B sides; the TOP slack has to swallow
				// (a) the 6px gap between the header row and the picker, and
				// (b) the full header row height (~20px or more at high DPI / large
				// row density), so a right-click at the very top of the header
				// doesn't immediately fall outside the slack zone and auto-close
				// the menu before the user can move into it.
				const float ColPickerAutoCloseSlackPx = 100f;
				const float ColPickerAutoCloseSlackTopPx = 100f;
				float _slackL = _colPickerBgRect.X - ColPickerAutoCloseSlackPx;
				float _slackR = _colPickerBgRect.Right + ColPickerAutoCloseSlackPx;
				float _slackT = _colPickerBgRect.Y - ColPickerAutoCloseSlackTopPx;
				float _slackB = _colPickerBgRect.Bottom + ColPickerAutoCloseSlackPx;
				if (FinalXPixel < _slackL || FinalXPixel > _slackR
					|| FinalYPixel < _slackT || FinalYPixel > _slackB)
				{
					_colPickerOpen = false;
					InvalidateVis(115);
				}
				else
				{
					// Mouse is inside the slack zone (which covers the entire picker
					// bg, preset slot row, reset footer, and sort toggle) — refresh
					// every move so hover tints on ALL interactive elements track the
					// cursor smoothly. The previous check only invalidated inside the
					// bg rect, which missed the footer/preset areas.
					InvalidateVis(116);
				}
			}

			// Auto-close the profile picker when mouse wanders away
			if (_profilePickerOpen && _profilePickerBgRect.Width > 0 && _profilePickerBgRect.Height > 0)
			{
				const float _ppSlack = 80f;
				if (FinalXPixel < _profilePickerBgRect.X - _ppSlack || FinalXPixel > _profilePickerBgRect.Right + _ppSlack
					|| FinalYPixel < _profilePickerBgRect.Y - _ppSlack || FinalYPixel > _profilePickerBgRect.Bottom + _ppSlack)
				{
					_profilePickerOpen = false;
					InvalidateVis(132);
				}
				else
				{
					InvalidateVis(133);
				}
			}

			// Cheat sheet scrollbar drag — same pattern as main table thumb drag.
			if (_csDraggingThumb && _csScrollTrackRect.Height > 0)
			{
				float _csTrackH = _csScrollTrackRect.Height;
				float _csThumbH = _csScrollThumbRect.Height;
				float _csTravelRange = _csTrackH - _csThumbH;
				if (_csTravelRange > 0)
				{
					float _csMouseDelta = (float)FinalYPixel - _csDragStartMouseY;
					// Compute max scroll from bg rect + line height (same formula as render).
					float _csLineHEst = (float)Math.Round(16f * dpiScaleY, 0);
					float _csPadEst = (float)Math.Round(12f * dpiScaleY, 0);
					int _csVisLines = (int)((_csBgRect.Height - _csPadEst * 2) / _csLineHEst);
					// Use a generous total (75 lines) — render clamps anyway.
					int _csTotalEst = 75;
					int _csMaxScr = Math.Max(1, _csTotalEst - _csVisLines);
					float _csPxPerRow = _csTravelRange / (float)_csMaxScr;
					if (_csPxPerRow > 0)
					{
						int rowDelta = (int)Math.Round(_csMouseDelta / _csPxPerRow);
						_csScrollOffset = Math.Max(0, Math.Min(_csMaxScr, _csDragStartOffset + rowDelta));
						InvalidateVis(125);
					}
				}
				return;
			}

			// Scrollbar drag — update AdjustmentRows based on how far the mouse moved
			if (IsDraggingScrollThumb && ScrollTrackRect.Height > 0 && MaximumAccountRows > 0 && TotalAccounts > MaximumAccountRows)
			{
				float trackH = ScrollTrackRect.Height;
				float thumbH = ScrollThumbRect.Height;
				float travelRange = trackH - thumbH;
				if (travelRange > 0)
				{
					float mouseDelta = (float)FinalYPixel - ScrollDragStartMouseY;
					int maxScroll = TotalAccounts - MaximumAccountRows;
					float pxPerRow = travelRange / (float)maxScroll;
					if (pxPerRow > 0)
					{
						int rowDelta = (int)Math.Round(mouseDelta / pxPerRow);
						// Drag bypasses momentum — set position immediately
						int _prevDrag = AdjustmentRows;
						SetScrollImmediate(ScrollDragStartAdjustmentRows + rowDelta);
						if (AdjustmentRows != _prevDrag)
							AllowRedraw = true;
						InvalidateVis(86);
					}
				}
				return;
			}

			// Column resize drag — update the override width based on mouse delta
			if (_resizingColumnLogical >= 0)
			{
				float deltaX = (float)FinalXPixel - _resizeDragStartMouseX;
				int newWidth = Math.Max(20, _resizeDragStartWidth + (int)deltaX);
				ColumnWidthOverrides[_resizingColumnLogical] = newWidth;
				SerializeColumnWidthOverridesNow();
				InvalidateVis(92);
				return;
			}

			// Column drag-to-reorder
			if (_columnDragArmed)
			{
				_columnDragCurrentX = (float)FinalXPixel;
				float dragDist = Math.Abs(_columnDragCurrentX - _columnDragStartX);
				if (dragDist > ColumnDragActivationDistance)
				{
					// Mark the drag as activated — this suppresses the deferred sort-by-column
					// click on mouse up, and tells the renderer to draw drag visuals (ghost, marker).
					if (!_columnDragActivated)
					{
						_columnDragActivated = true;
						InvalidateVis(99);
					}
					// Find which header rect the mouse is over, then resolve to the
					// actual display-order index (position in ColumnDisplayOrderList)
					// via HeaderColumnLogicalIds. We MUST work in display-order terms,
					// not rect-index terms, because HeaderColumnRects is compacted to
					// visible columns only and hidden columns still occupy slots in
					// ColumnDisplayOrderList.
					int hoverRectIdx = -1;
					int hoverDisplayIdx = -1;
					SharpDX.RectangleF hoverRect = default(SharpDX.RectangleF);
					if (HeaderColumnRects != null)
					{
						for (int k = 0; k < HeaderColumnRects.Count && k < HeaderColumnLogicalIds.Count; k++)
						{
							if (MouseIn(HeaderColumnRects[k], 0, 0))
							{
								hoverRectIdx = k;
								int _tmpDispIdx;
							hoverDisplayIdx = _colLogicalToDisplayIdx.TryGetValue(HeaderColumnLogicalIds[k], out _tmpDispIdx) ? _tmpDispIdx : -1;
								hoverRect = HeaderColumnRects[k];
								break;
							}
						}
					}

					// If hovering a different column than the one we're dragging, swap them —
					// but only when the mouse has crossed the MIDPOINT of the target column in
					// the direction of the swap. Without this guard, mismatched column widths
					// cause the swap to re-trigger on the next frame as the cursor ends up
					// hovering the just-swapped column again, producing a visible bounce.
					if (hoverDisplayIdx >= 0 && hoverDisplayIdx != _draggingColumnDisplayIdx
						&& ColumnDisplayOrderList != null && hoverDisplayIdx < ColumnDisplayOrderList.Count
						&& _draggingColumnDisplayIdx < ColumnDisplayOrderList.Count
						&& hoverRectIdx >= 0)
					{
						string targetColName;
						ColumnNumberToName.TryGetValue(HeaderColumnLogicalIds[hoverRectIdx], out targetColName);
						// Don't allow dropping ON a locked column
						if (!string.IsNullOrEmpty(targetColName) && !IsColumnLockedNoScroll(targetColName))
						{
							float targetMidX = hoverRect.X + hoverRect.Width * 0.5f;
							bool crossedMidpoint =
								(hoverDisplayIdx > _draggingColumnDisplayIdx && _columnDragCurrentX > targetMidX) ||
								(hoverDisplayIdx < _draggingColumnDisplayIdx && _columnDragCurrentX < targetMidX);

							if (crossedMidpoint)
							{
								// Simple swap of the two display positions
								int temp = ColumnDisplayOrderList[_draggingColumnDisplayIdx];
								ColumnDisplayOrderList[_draggingColumnDisplayIdx] = ColumnDisplayOrderList[hoverDisplayIdx];
								ColumnDisplayOrderList[hoverDisplayIdx] = temp;
								// The column we just swapped INTO the dragged slot is the "displaced"
								// one — flash it briefly at its new resting position so the user sees
								// where it landed. (We use its logical id so the render loop can find it.)
								_swapFlashLogical = temp;
								_swapFlashTime    = DateTime.Now;
								_draggingColumnDisplayIdx = hoverDisplayIdx;
								SyncColumnDisplayOrderNames();
								InvalidateVis(97);
							}
						}
					}
				}
				return;
			}

			// Column border hover detection — show east-west resize cursor when hovering a border
			int newHoveredBorder = -1;
			if (HeaderColumnBorderRects != null && HeaderColumnBorderRects.Count > 0)
			{
				for (int k = 0; k < HeaderColumnBorderRects.Count; k++)
				{
					if (MouseIn(HeaderColumnBorderRects[k], 0, 0))
					{
						newHoveredBorder = HeaderColumnBorderLogicalIds[k];
						break;
					}
				}
			}
			if (newHoveredBorder != _hoveredResizeColumnLogical)
			{
				_hoveredResizeColumnLogical = newHoveredBorder;
				InvalidateVis(94);
			}

			// Scrollbar hover highlighting
			bool nowHoveringScrollbar = ScrollTrackRect.Width > 0 && MouseIn(ScrollTrackRect, 0, 0);
			if (nowHoveringScrollbar != IsHoveringScrollbar)
			{
				IsHoveringScrollbar = nowHoveringScrollbar;
				InvalidateVis(87);
			}

			if (HeaderColumnRects != null)
			{
				int currentHover = -1;
				for (int k = 0; k < HeaderColumnRects.Count; k++)
					if (MouseIn(HeaderColumnRects[k], 0, 0)) { currentHover = k; break; }

				// Track hovered header for tooltip rendering
				if (currentHover != HoveredHeaderColumn)
				{
					// If moving from one header column to another (both >= 0),
					// keep HoveredHeaderTooltipShown = true so the tooltip
					// appears immediately without the 300ms delay. Only reset
					// when the mouse leaves the header row entirely.
					bool _wasInHeader = HoveredHeaderColumn >= 0;
					bool _nowInHeader = currentHover >= 0;
					HoveredHeaderColumn = currentHover;
					HoveredHeaderStartTime = DateTime.Now;
					if (!_wasInHeader || !_nowInHeader)
						HoveredHeaderTooltipShown = false;
					// Invalidate cached tooltip layout so it re-measures for the new column
					if (TooltipCachedLayout != null) { TooltipCachedLayout.Dispose(); TooltipCachedLayout = null; TooltipCachedText = null; }
					InvalidateVis(80);
				}

				if (currentHover >= 0)
				{
					// currentHover is an index into HeaderColumnRects. Resolve to the
					// logical column id via the parallel list, then look up the name.
					string hoverColName = "";
					if (currentHover < HeaderColumnLogicalIds.Count && ColumnNumberToName != null)
						ColumnNumberToName.TryGetValue(HeaderColumnLogicalIds[currentHover], out hoverColName);
					if (hoverColName == null) hoverColName = "";
					bool lockedNoScroll = hoverColName == "–" || hoverColName == "Connected Status" || hoverColName == "Auto Exit" || hoverColName == "Auto Close";
					ColumnScrollTarget = lockedNoScroll ? -1 : currentHover;
				}
				else
				{
					ColumnScrollTarget = -1;
					ColumnScrollAnchorValid = false;
				}
			}
         
			
			bool DoRefreshAtEnd = false;
			
			
			//Print("FinalXPixel "+ FinalXPixel);
			
			//int ThisHoveredButton = 0;
			
			
			
			

			// row titles
			HoveredButton3 = 0;
			
			foreach (KeyValuePair<double, PendingDetails> kvp in LimitPriceToTimeOutOfSync2.ToList())
			{
					
				bool hoverednew = MouseIn(kvp.Value.RectCancel, 0, 0);	
				
				double price = kvp.Key;
				
				
				
				if (hoverednew)
				{
					HoveredButton3++;
					//CancelOrdersAtPrice(price);
					
					
					//Print("RectCancel");
					break;	
				}
					
				hoverednew = MouseIn(kvp.Value.RectFill, 0, 0);	
					
				if (hoverednew)
				{
					HoveredButton3++;
					//FillOrdersAtPrice(price);
					
					//Print("RectFill");
					
					break;
				}
				
				hoverednew = MouseIn(kvp.Value.RectPlus, 0, 0);	
					
				if (hoverednew)
				{
					HoveredButton3++;
					
					//MoveOrdersAtPrice(price);
					
					//Print("RectPlus");
					break;	
				}			
					
			}
			
				
				
				foreach (MessageAlerts D in AllMessages.ToList())
				{
					if (MouseIn(D.Rect,0,0))// || MouseIn(thisbutton.Rect,exmbl,exmbl))
						{
							
							if (D.Switch)
							{
								HoveredButton3++;
								
								//doneeee = D.Name;
							}
							
							
						}
					
				}
				
				
				
			
		
			if (HoveredButton3P != HoveredButton3)
				DoRefreshAtEnd = true;
				
			HoveredButton3P = HoveredButton3;	
				
		
			
			
			HoveredButton = 0;
			bool _anyButtonZ5Hovered = false;

			if (pHighlightHoverButtons && !_colPickerOpen)
            foreach (ButtonBOT thisbutton in AllButtonZ5)
            {

				bool hoverednew = MouseIn(thisbutton.Rect, 0, 0);

				HoveredButton++;

				if (hoverednew)
				{
					_anyButtonZ5Hovered = true;
					break;
				}


			}
		
			if (HoveredButtonP != HoveredButton)
				DoRefreshAtEnd = true;
				
			HoveredButtonP = HoveredButton;	
				
		
			
			
			

			//ThisHoveredButton = 0;
			HoveredButton2 = 0;
			bool _anyButtonZ7Hovered = false;

			if (pHighlightHoverButtons && !_colPickerOpen)
            foreach (ButtonBOT thisbutton in AllButtonZ7)
            {

				bool hoverednew = MouseIn(thisbutton.Rect, 0, 0);

				HoveredButton2++;

				if (hoverednew)
				{
					_anyButtonZ7Hovered = true;
					break;
				}


			}
		
			if (HoveredButton2P != HoveredButton2)
				DoRefreshAtEnd = true;
				
			HoveredButton2P = HoveredButton2;	
			
			
			
			
					
			
			//int ThisHoveredRow = 0;
			 
			HoveredRow = 0;
			bool NoRow = true;

			// Suppress row hover detection entirely while the column visibility
			// picker or quick reference overlay is open — otherwise the rows
			// underneath still register hover and produce a confusing double-highlight.
			if (pHighlightHoverCells && !_colPickerOpen && !_cheatSheetOpen && !_profilePickerOpen && !_instPickerOpen && !_latencyMenuOpen)
			if (FinalXPixel <= rightoftable)
			foreach (ButtonBOT thisbutton in AllButtonZ6)
           // foreach (KeyValuePair<double, ButtonZ> thisbutton in AllButtonZ6)
                {
						
					
					//Print(thisbutton.Rect.Top);


                    bool hoverednew = MouseIn(thisbutton.Rect, 0, 0);
                  //  bool hoverednow = thisbutton.Hovered;

					//HoveredRow = HoveredRow + 1;
					
					HoveredRow = (int) thisbutton.Key;
					
                    if (hoverednew)
                    {
                       
						NoRow = false;
						break;
						
					}
					
					
						
					

                }
				
				if (NoRow)
					HoveredRow = 0;
				
				if (HoveredRowP != HoveredRow)
				{
					DoRefreshAtEnd = true;
				}
				
			HoveredRowP = HoveredRow;	
				
				
			
            foreach (KeyValuePair<double, ButtonZ> thisbutton in AllButtonZ)
                {
                    bool hoverednew = MouseIn(thisbutton.Value.Rect, 2, 2);
                    bool hoverednow = thisbutton.Value.Hovered;

                    if (hoverednew && !hoverednow)
                    {
                        thisbutton.Value.Hovered = true;
                        InvalidateVis(31);
						
						//Print("ref");
                    }
                    if (!hoverednew && hoverednow)
                    {
                        thisbutton.Value.Hovered = false;
                        InvalidateVis(32);
						
						//Print("ref");
						
                    }

                }

				// Track hover on the instrument mode button for tooltip.
				bool _instBtnNowHovered = (_instModeButtonRect.Width > 0 && MouseIn(_instModeButtonRect, 2, 2));
				if (_instBtnNowHovered && !_instModeButtonHovered)
				{
					_instModeButtonHovered = true;
					_instModeButtonHoverStart = DateTime.Now;
					_instModeTooltipShown = false;
				}
				else if (!_instBtnNowHovered && _instModeButtonHovered)
				{
					_instModeButtonHovered = false;
					_instModeTooltipShown = false;
				}
				// Continuously invalidate while hovering the instrument mode button
				// so the embedded edit icon hover highlight updates in real time.
				if (_instBtnNowHovered)
					InvalidateVis(99);
				// Fire a single invalidation once the tooltip delay has expired.
				if (_instModeButtonHovered && !_instModeTooltipShown && _instModeButtonHoverStart != DateTime.MinValue)
				{
					if ((DateTime.Now - _instModeButtonHoverStart).TotalMilliseconds > 300)
					{
						_instModeTooltipShown = true;
						InvalidateVis(95);
					}
				}

				// Close instrument picker if user clicks outside it.
				if (_instPickerOpen && _instPickerBgRect.Width > 0 && _instPickerBgRect.Height > 0)
				{
					if (!MouseIn(_instPickerBgRect, 8, 8) && !MouseIn(_instModeButtonRect, 2, 2))
					{
						_instPickerOpen = false;
						InvalidateVis(96);
					}
				}

                InMenuP = InMenu;
                InMenu = MouseIn(B2, 8, 8);

				if (InMenu != InMenuP)
					DoRefreshAtEnd = true;

				// Force a redraw on every mouse move while the Quick Reference
				// Guide overlay is open so hover tints on the checkboxes, close
				// button, and link rows stay in sync with the cursor.
				if (_cheatSheetOpen)
					DoRefreshAtEnd = true;

				// Safety timeout: if the QRG was requested to open but the
				// remote fetch has taken longer than 2.5 seconds (or failed
				// silently), open anyway with whatever content is available
				// so the user isn't stuck clicking '?' with no response.
				if (_qrgOpenPending && (DateTime.Now - _qrgOpenPendingStart).TotalSeconds > 2.5)
				{
					_qrgOpenPending = false;
					_cheatSheetOpen = true;
					_csScrollOffset = 0;
					DoRefreshAtEnd = true;
				}

				if (DoRefreshAtEnd)
				{


					InvalidateVis(33);
				}

				// Cursor logic — resize takes precedence, then hand for clickable, else default arrow.
				// Only checks REAL "is something hovered" booleans, not iteration counters.
				bool shouldBeSizeWE = (_hoveredResizeColumnLogical >= 0) || (_resizingColumnLogical >= 0);
				bool shouldBeHand = false;
				if (!shouldBeSizeWE)
				{
					// _anyButtonZ5Hovered = action cells (close, hide, mode, etc.)
					// _anyButtonZ7Hovered = column header sort buttons
					// HoveredButton3 = sync order buttons (only ++d on real hit)
					// HoveredHeaderColumn >= 0 = column header (-1 if not hovering)
					// IsHoveringScrollbar = scrollbar track (only true if mouse in track rect)
					// InMenu = top-left menu button
					if (_anyButtonZ5Hovered || _anyButtonZ7Hovered || HoveredButton3 > 0)
						shouldBeHand = true;
					else if (HoveredHeaderColumn >= 0)
						shouldBeHand = true;
					else if (IsHoveringScrollbar)
						shouldBeHand = true;
					// Hidden-groups pill is clickable — show hand cursor when hovered.
					else if (_hiddenGroupsPillRect.Width > 0 && _hiddenGroupsPillRect.Height > 0
						&& MouseIn(_hiddenGroupsPillRect, 0, 0))
						shouldBeHand = true;
					// Total-row Account cell is click-to-rename + drag-to-reorder.
					else if (_anyTotalRowAcctHovered)
						shouldBeHand = true;
					// Quick Reference Guide interactive elements: close (X),
					// 3 tooltip-toggle checkboxes, and any [text](url) link rows.
					else if (_cheatSheetOpen && (
						(_cheatSheetCloseRect.Width > 0 && MouseIn(_cheatSheetCloseRect, 0, 0))
						|| (_csTipsHeadersRect.Width > 0 && MouseIn(_csTipsHeadersRect, 0, 0))
						|| (_csTipsCellsRect.Width > 0 && MouseIn(_csTipsCellsRect, 0, 0))
						|| (_csTipsButtonsRect.Width > 0 && MouseIn(_csTipsButtonsRect, 0, 0))))
						shouldBeHand = true;
					else if (_cheatSheetOpen && _qrgLinkRects != null && _qrgLinkRects.Count > 0)
					{
						for (int _lki = 0; _lki < _qrgLinkRects.Count; _lki++)
						{
							if (_qrgLinkRects[_lki].Width > 0 && MouseIn(_qrgLinkRects[_lki], 0, 0))
							{
								shouldBeHand = true;
								break;
							}
						}
					}
					// Profile picker: text rows (non-separator) and delete X buttons are clickable
					else if (_profilePickerOpen)
					{
						for (int _cI = 0; _cI < _profilePickerItemRects.Count; _cI++)
						{
							if (_profilePickerItemRects[_cI].Width > 0
								&& _profilePickerItemNames[_cI] != "---"
								&& _profilePickerItemNames[_cI] != null
								&& MouseIn(_profilePickerItemRects[_cI], 0, 0))
							{
								shouldBeHand = true;
								break;
							}
						}
						if (!shouldBeHand)
						{
							for (int _cI = 0; _cI < _profilePickerDeleteRects.Count; _cI++)
							{
								if (_profilePickerDeleteRects[_cI].Width > 0
									&& MouseIn(_profilePickerDeleteRects[_cI], 0, 0))
								{
									shouldBeHand = true;
									break;
								}
							}
						}
					}
					// Column visibility picker: column toggle rows, alphabetical-sort
					// toggle, the 4 layout/preset slot buttons, and the footer "Reset
					// Widths" / "Reset All" buttons are all clickable.
					else if (_colPickerOpen)
					{
						for (int _cI = 0; _cI < _colPickerItemRects.Count; _cI++)
						{
							if (_colPickerItemRects[_cI].Width > 0 && MouseIn(_colPickerItemRects[_cI], 0, 0))
							{
								shouldBeHand = true;
								break;
							}
						}
						if (!shouldBeHand && _pickerSortToggleRect.Width > 0 && MouseIn(_pickerSortToggleRect, 0, 0))
							shouldBeHand = true;
						if (!shouldBeHand && _presetSlotRects != null)
						{
							for (int _ps = 0; _ps < _presetSlotRects.Count; _ps++)
							{
								if (_presetSlotRects[_ps].Width > 0 && MouseIn(_presetSlotRects[_ps], 0, 0))
								{
									shouldBeHand = true;
									break;
								}
							}
						}
						if (!shouldBeHand && _resetWidthsRect.Width > 0 && MouseIn(_resetWidthsRect, 0, 0))
							shouldBeHand = true;
						if (!shouldBeHand && _resetAllRect.Width > 0 && MouseIn(_resetAllRect, 0, 0))
							shouldBeHand = true;
					}
					// Instrument picker: each item row toggles selection / picks the
					// single instrument — all rows are clickable.
					else if (_instPickerOpen)
					{
						for (int _pi = 0; _pi < _instPickerItemRects.Count; _pi++)
						{
							if (_instPickerItemRects[_pi].Width > 0 && MouseIn(_instPickerItemRects[_pi], 0, 0))
							{
								shouldBeHand = true;
								break;
							}
						}
					}
					// InMenu removed from hand-cursor check — B2 uses a 10000×10000
					// rect that covers the entire chart below the button row, causing
					// a spurious hand cursor everywhere below the table. The per-button
					// .Hovered check in AllButtonZ below already covers each button
					// individually so InMenu is redundant here.
					else
					{
						// Check top-bar buttons (AllButtonZ) — these track per-button .Hovered properly
						foreach (KeyValuePair<double, ButtonZ> thisbutton in AllButtonZ)
						{
							if (thisbutton.Value.Hovered)
							{
								shouldBeHand = true;
								break;
							}
						}
					}
				}

				// Always re-apply cursor every mouse move — NinjaTrader takes ownership
				// of the cursor on click events, so we have to keep re-asserting it.
				try
				{
					System.Windows.Input.Cursor cursorToSet;
					if (shouldBeSizeWE)
						cursorToSet = System.Windows.Input.Cursors.SizeWE;
					else if (shouldBeHand)
						cursorToSet = System.Windows.Input.Cursors.Hand;
					else
						cursorToSet = null; // Let NinjaTrader's default cursor through

					if (ChartPanel != null && this.ChartPanel.Cursor != cursorToSet)
						this.ChartPanel.Cursor = cursorToSet;
					if (ChartControl != null && ChartControl.Cursor != cursorToSet)
						ChartControl.Cursor = cursorToSet;
				}
				catch { }
				_dashCursorIsSizeWE = shouldBeSizeWE;
				_dashCursorIsHand = shouldBeHand;

		}

		// Push our most-recent cursor choice (Hand / SizeWE / default) onto
		// ChartPanel and ChartControl. Called from OnMouseMove, OnMouseDown,
		// OnMouseUp, and the click-hold timer to keep the custom cursor
		// pinned through NT's default-cursor resets during click events.
		private void ReassertDashCursor()
		{
			try
			{
				System.Windows.Input.Cursor c;
				if (_dashCursorIsSizeWE) c = System.Windows.Input.Cursors.SizeWE;
				else if (_dashCursorIsHand) c = System.Windows.Input.Cursors.Hand;
				else c = null;
				if (ChartPanel != null && this.ChartPanel.Cursor != c)
					this.ChartPanel.Cursor = c;
				if (ChartControl != null && ChartControl.Cursor != c)
					ChartControl.Cursor = c;
			}
			catch { }
		}

        private bool MouseIn(SharpDX.RectangleF RR, int XF, int YF)
        {
            //Print(RR.Left);
            
			if (FinalXPixel != 0)
            if (FinalXPixel >= RR.Left - XF && FinalXPixel <= RR.Right + XF && FinalYPixel >= RR.Top - YF && FinalYPixel <= RR.Bottom + YF)
                return true;
           
                return false;

        }

