		// All *Both helpers gate AddXDrawing on (RenderEfficient && AllowRedraw).
		// AllowRedraw is true ONLY during a build pass (which clears AllDrawings first
		// at L17717 and refills it). In replay frames AllowRedraw=false so the cache
		// is left untouched. This prevents pre-clear and error-banner *Both calls from
		// leaking entries into the cache across frames, which over a 5-hour soak would
		// otherwise grow AllDrawings without bound and accumulate stale brush refs.

		private void FillEllipseBoth(ChartControl chartControl, ChartScale chartScale, SharpDX.Direct2D1.Ellipse EE, SharpDX.Direct2D1.Brush BrushZ)
		{
			RenderTarget.FillEllipse(EE, BrushZ);

			if (RenderEfficient && AllowRedraw)
				AddEDrawing(AllDrawings,"FillEllipse", EE, BrushZ, 0);
		}

		private void DrawEllipseBoth(ChartControl chartControl, ChartScale chartScale, SharpDX.Direct2D1.Ellipse EE, SharpDX.Direct2D1.Brush BrushZ)
		{
			RenderTarget.DrawEllipse(EE, BrushZ);

			if (RenderEfficient && AllowRedraw)
				AddEDrawing(AllDrawings,"DrawEllipse", EE, BrushZ, 0);
		}



		private void FillRectBoth(ChartControl chartControl, ChartScale chartScale, SharpDX.RectangleF RR, SharpDX.Direct2D1.Brush BrushZ)
		{
			RenderTarget.FillRectangle(RR, BrushZ);

			if (RenderEfficient && AllowRedraw)
				AddDrawing(AllDrawings,"FillRectangle", RR, BrushZ, 0);
		}




		private void DrawRectBoth(ChartControl chartControl, ChartScale chartScale, SharpDX.RectangleF RR, SharpDX.Direct2D1.Brush BrushZ, float wid)
		{
			RenderTarget.DrawRectangle(RR, BrushZ, wid);

			if (RenderEfficient && AllowRedraw)
				AddDrawing(AllDrawings,"DrawRectangle", RR, BrushZ, wid);
		}

		private void AntialiasMode(ChartControl chartControl, ChartScale chartScale, string sssssss)
		{
			if (sssssss == "Aliased")
				RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.Aliased;
			else
				RenderTarget.AntialiasMode = SharpDX.Direct2D1.AntialiasMode.PerPrimitive;

			if (RenderEfficient && AllowRedraw)
				AddAliasDrawing(AllDrawings,sssssss);
		}





		//RenderTarget.DrawText(txt, CenterText, ExpandRect(CenterRect,-10,0), ChartTextBrushDX);

		private void DrawTextBoth(ChartControl chartControl, ChartScale chartScale, string txt, SharpDX.DirectWrite.TextFormat CenterText, SharpDX.RectangleF RR, SharpDX.Direct2D1.Brush BrushZ, bool clipToRect = true)
		{
			// Default: DrawTextOptions.Clip so text that overflows the layout rect (e.g.
			// when a user resizes a column narrower than its content) gets clipped at the
			// cell edge instead of bleeding into adjacent columns. Pass clipToRect=false
			// to allow the glyph to render past the layout rect — used by the X / Auto
			// Exit / Auto Close lock columns where the cell is intentionally tighter
			// than the natural glyph width and we want the full glyph visible.
			SharpDX.Direct2D1.DrawTextOptions _opts = clipToRect
				? SharpDX.Direct2D1.DrawTextOptions.Clip
				: SharpDX.Direct2D1.DrawTextOptions.None;
			RenderTarget.DrawText(txt, CenterText, RR, BrushZ, _opts);

			if (RenderEfficient && AllowRedraw)
				AddTextDrawing(AllDrawings,"DrawText", RR, BrushZ, txt, CenterText, !clipToRect);
		}
		
		
       private void AddTextDrawing( List<Drawings> ThisList, string iText, SharpDX.RectangleF Rect2, SharpDX.Direct2D1.Brush BrushZ, string txt, SharpDX.DirectWrite.TextFormat CenterText, bool noClip = false)
        {


            Drawings Z = new Drawings();
            Z.Text = txt;
            Z.Name = iText;
            //Z.Width = iWidth;
            // Repurposed: Switch = noClip flag, used by the AllDrawings replay
            // path so cached text draws honor the same clip option that the
            // live render used. Without this, text rendered without clip looks
            // correct while the mouse is moving but reverts to the clipped
            // version once the cache replays.
            Z.Switch = noClip;
            Z.Rect = Rect2;
           // Z.Hovered = false;
			//Z.Location = iLocation;
			Z.ThisB = BrushZ;
			Z.ThisTextFormat = CenterText;

            ThisList.Add(Z);

        }
		
