        {
            Drawings Z = new Drawings();
           // Z.Text = iText;
            Z.Name = iText;
            Z.Width = wid;
           // Z.Switch = iSwitch;
            Z.Rect = Rect2;
           // Z.Hovered = false;
			//Z.Location = iLocation;
			Z.ThisB = BrushZ;
            ThisList.Add(Z);

        }
			
				
