		// --- Latency Analysis ---
		// Copier-latency tracking, driven entirely by the optional "Latency"
		// column (add it from the right-click column picker). Two metrics:
		//   * "Dispatch Latency"     — master order action (place / move) detected
		//                              -> follower change submitted. Copier overhead.
		//   * "Confirmation Latency" — master order action detected -> follower order
		//                              confirmed live at the broker (Working /
		//                              Accepted, or Filled for market orders).
		// Both metrics and the threshold are tuned from the in-chart latency menu.
		// Latency is shown only in the optional "Latency" column; "Slow Threshold"
		// is the latency (ms) at/above which a follower reads as slow (red).
		private bool pLatencyDispatch = true;
		[Display(ResourceType = typeof(Custom.Resource), Name = "Dispatch Latency", Description = "Track DISPATCH latency: the time from the indicator detecting a Master order action — a new order, or moving an existing one — to the moment it applies the matching change to the Follower account. This is the copier's own processing overhead, measured on one clock, so it is stable and low-noise — but it does NOT include any broker-side delay after the change is sent.", GroupName = "Latency Analysis", Order = 2)]
		public bool LatencyDispatch
		{
			get { return pLatencyDispatch; }
			set { pLatencyDispatch = value; }
		}

		private bool pLatencyConfirmation = false;
		[Display(ResourceType = typeof(Custom.Resource), Name = "Confirmation Latency", Description = "Track CONFIRMATION latency: the time from detecting a Master order action — a new order, or moving an existing one — to the Follower order being confirmed live at the broker (Working/Accepted, or Filled for a market order). This is the full mirroring pipeline including the Follower broker's round-trip — the most honest 'how far behind is my Follower' number, but noisier than Dispatch.", GroupName = "Latency Analysis", Order = 3)]
		public bool LatencyConfirmation
		{
			get { return pLatencyConfirmation; }
			set { pLatencyConfirmation = value; }
		}

		// Latency at or above this many milliseconds reads as "slow" — drives the
		// red tier of the Latency column. Half this value is the amber (elevated)
		// tier boundary.
		private int pLatencySlowThresholdMs = 250;
		[Display(ResourceType = typeof(Custom.Resource), Name = "Slow Threshold (ms)", Description = "Copier latency at or above this many milliseconds is treated as slow (red) in the Latency column. Half this value is the amber/elevated boundary.", GroupName = "Latency Analysis", Order = 4)]
		public int LatencySlowThresholdMs
		{
			get { return pLatencySlowThresholdMs; }
			set { pLatencySlowThresholdMs = Math.Max(10, value); }
		}

