		private bool pLatencyColumn = false;
		[Display(ResourceType = typeof(Custom.Resource), Name = "Column - Latency", Description = "Show the Latency column on the dashboard.", GroupName = "Latency Analysis", Order = 6)]
		public bool LatencyColumn
		{
			get { return pLatencyColumn; }
			set { pLatencyColumn = value; }
		}

		// --- Quick Reference Source ---
		// When enabled, the Quick Reference Guide overlay pulls its body content
		// from a Google Doc published / shared as "Anyone with the link: Viewer".
		// The Doc's plain-text export is fetched in the background (5s timeout,
		// 5-min TTL cache) and parsed for headers, body lines, and [text](url)
		// hyperlinks. Falls back to the hard-coded default content if fetching
		// fails or the toggle is off.
		// Hardcoded Doc ID + remote-on by default. The properties remain on the
		// class (and are hidden from the Inputs grid via DeleteThese) so the
		// render/fetch code paths keep working without config churn.
		private bool pQrgUseRemote = true;
