		// the overlay is never empty or "wrong" at first open.
		private string pQrgCache = "";
		[Display(ResourceType = typeof(Custom.Resource), Name = "Quick Reference Cache", Description = "Internal — last fetched Quick Reference content, kept for offline display.", GroupName = "Quick Reference Source", Order = 3)]
		[Browsable(false)]
		[XmlIgnore]
		public string QrgCache
		{
			get { return pQrgCache; }
			set { pQrgCache = value ?? ""; }
		}


