		private bool pAllInstruments = true;
        [Display(ResourceType = typeof(Custom.Resource), Name = "AllInstruments", Description = "Include all instruments in the list; when off, only selected instruments are shown.", GroupName = "All Instruments", Order = -100)]
        public bool AllInstruments
        {
            get { return pInstrumentMode == "All"; }
            set
			{
				// Migration shim — old workspaces serialize this bool.
				// Map true → "All", false → "Single" (the old "off" behavior).
				if (string.IsNullOrEmpty(pInstrumentMode) || pInstrumentMode == "All" || pInstrumentMode == "Single")
				{
					string prev = pInstrumentMode;
					pInstrumentMode = value ? "All" : "Single";
					if (_isRegistered && prev != pInstrumentMode) ForceConflictRecheck();
				}
			}
        }

