		private HashSet<string> pSelectedInstrumentSet = new HashSet<string>();
		// Remember mode before risk-only forced All, so re-enabling Copy restores it.
		private string pInstrumentModePreviousForRiskAuto = "";

		private void RebuildSelectedInstrumentSet()
		{
			pSelectedInstrumentSet.Clear();
			if (!string.IsNullOrEmpty(pSelectedInstrumentList))
			{
				string[] parts = pSelectedInstrumentList.Split(';');
				for (int i = 0; i < parts.Length; i++)
				{
					string s = parts[i].Trim();
					if (s.Length > 0) pSelectedInstrumentSet.Add(s);
				}
			}
		}

		
		
		
		
