		// Hidden columns, persisted as a pipe-delimited name list. The right-click
		// column picker toggles entries in and out. Locked columns are never hidden.
		private HashSet<string> _hiddenColumns = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		private string pHiddenColumnsSaved = "";
		[Display(ResourceType = typeof(Custom.Resource), Name = "Hidden Columns", GroupName = "Hidden", Order = -98)]
		public string HiddenColumns_Saved
		{
			get { return pHiddenColumnsSaved; }
			set
			{
				pHiddenColumnsSaved = value ?? "";
				_hiddenColumns.Clear();
				if (!string.IsNullOrEmpty(pHiddenColumnsSaved))
				{
					foreach (string _nm in pHiddenColumnsSaved.Split('|'))
						if (!string.IsNullOrWhiteSpace(_nm)) _hiddenColumns.Add(_nm.Trim());
				}
			}
		}
		private void SerializeHiddenColumnsNow()
		{
			pHiddenColumnsSaved = (_hiddenColumns == null || _hiddenColumns.Count == 0)
				? ""
				: string.Join("|", _hiddenColumns);
		}

		// Compute the pixel width needed for one column of the picker, sized by
		// the widest name between index fromIdx (inclusive) and toIdx (exclusive).
		// Padding + checkbox + gap + rough text width + right pad.
		private float ComputePickerColWidth(List<string> names, int fromIdx, int toIdx,
			float charW, float padL, float cbSz, float cbGap, float padR)
		{
			// Measure each name with the real label TextFormat (MainTextLeft) so the
			// column shrinks to fit the actual rendered text width. The old char-count
			// heuristic over-estimated by ~7 px per char and left a noticeable gap
			// between the two columns / past "Total PNL".
			SharpDX.DirectWrite.TextFormat _measureFmt = MainTextLeft ?? CellFormat;
			float maxTextW = 0f;
			if (_measureFmt != null)
			{
				for (int i = fromIdx; i < toIdx && i < names.Count; i++)
				{
					string nm = names[i];
					if (string.IsNullOrEmpty(nm)) continue;
					using (var tl = new SharpDX.DirectWrite.TextLayout(
						NinjaTrader.Core.Globals.DirectWriteFactory, nm, _measureFmt, 10000, _measureFmt.FontSize))
					{
						float w = (float)Math.Ceiling(tl.Metrics.Width);
						if (w > maxTextW) maxTextW = w;
					}
				}
			}
			else
			{
				// Fallback: char-count heuristic if no TextFormat is available yet.
				int maxChars = 0;
				for (int i = fromIdx; i < toIdx && i < names.Count; i++)
					if (names[i].Length > maxChars) maxChars = names[i].Length;
				maxTextW = maxChars * charW;
			}
			return padL + cbSz + cbGap + maxTextW + padR;
		}

		// Reset every user-customized layout state back to the fresh-install
		// defaults: column order, per-column width overrides, hidden columns,
		// the persisted workspace keys that feed them, AND every column-
		// visibility property field in the indicator. The initializer values
		// listed below are copied directly from the `private bool pXxx = ...;`
		// declarations elsewhere in the file — if any default changes there,
		// update it here too.
		//
		// Default ON:  Size, Type, Mode, Actions, X, Pos, Qty,
		//              Unrealized, Gross Realized, Net Liquidation, Total PNL,
		//              From Funded, Auto Close, Auto Liquidate, From Closed,
		//              DD, Daily Goal, Daily Loss
		// Default OFF: Fade, Payout, Avg Price, Realized, Cash Value, Commissions
		private void ResetColumnLayout()
		{
			_renderCacheDirty = true;
			if (_hiddenColumns != null) _hiddenColumns.Clear();
			if (ColumnWidthOverrides != null) ColumnWidthOverrides.Clear();
			if (_pendingColumnWidthOverridesByName != null) _pendingColumnWidthOverridesByName.Clear();
			_columnWidthOverridesNeedApply = false;
			// Order: rebuild 1..NumOfColumns next frame. Clearing forces the
			// initial-load path at ~line 20422 to rebuild from default order.
			if (ColumnDisplayOrderList != null) ColumnDisplayOrderList.Clear();

			// --- Feature toggles (pIs*ColumnEnabled + pIs*Enabled paired) ---
			pIsXColumnEnabled     = true;  pIsXEnabled         = true;  // Size
			pIsCrossColumnEnabled = true;  pIsCrossEnabled     = true;  // Type
			pIsATMColumnEnabled   = true;  pIsATMSelectEnabled = true;  // Mode
			pIsFadeColumnEnabled  = false; pIsFadeEnabled      = false; // Fade (OFF)
			pActionsColumnEnabled = true;                                // Actions

			// --- X (close button column) ---
			pCloseButtonEnabled = true;

			// --- Account Risk Manager column gates ---
			pColumnFromFund        = true;
			pIsEvalCloseEnabled    = true;  // Auto Close
			pColumnAutoLiquidate   = true;
			pColumnRemaining       = true;  // From Closed
			pColumnDDType          = true;  // DD
			pColumnDailyGoal       = true;  // display only (enforcement is decoupled)
			pColumnDailyLoss       = true;  // display only (enforcement is decoupled)
			pColumnProfitRequested = false; // Payout (OFF)

			// --- Columns input-group gates ---
			pShowAvgPrice          = false; // OFF
			pUnRealized2Column     = true;
			pRealized2Column       = false; // OFF
			pGrossRealized2Column  = true;
			pCashValueColumn       = false; // OFF
			pNetLiquidationColumn  = true;
			pQtyColumn2            = true;
			pCommissionsColumn     = false; // OFF
			pTotalPNLColumn        = true;

			// --- Sort column + direction ---
			// Reset to the field defaults (see pSelectedColumn / pSelectedAscending
			// property declarations). IsSorted = false forces the next frame to
			// re-sort with the restored column/direction.
			pSelectedColumn    = "Account";
			pSelectedAscending = true;
			IsSorted           = false;

			// Persistence
			pHiddenColumnsSaved = "";
			pColumnWidthOverrides = "";
			pColumnDisplayOrderNames = "";
		}

		// ──────────────────────────────────────────────────────────────────
		// LAYOUT PRESET SNAPSHOTS
		// Build / apply / persist a single delimited string capturing the
		// FULL set of layout state that ResetColumnLayout() touches above.
		// Format:
		//   v=1;order=1,3,5;hidden=Avg Price|Payout;widths=Account:120|Net Liquidation:90;
		//   flags=pIsXColumnEnabled:1|pIsXEnabled:1|...|pSelectedAscending:1;sort=Account
		// Sections separated by ';', key/value by '=', repeated entries by '|',
		// sub-key/sub-value by ':'. v=1 is a schema version for future migration.
		// ──────────────────────────────────────────────────────────────────

		// Single source of truth for the boolean fields captured in a snapshot.
		// Each entry: name → (getter, setter). Build / apply iterate this list,
		// so adding a new flag only needs one new line here.
		private List<Tuple<string, Func<bool>, Action<bool>>> _layoutSnapshotFlags;
		private List<Tuple<string, Func<bool>, Action<bool>>> GetLayoutSnapshotFlags()
		{
			if (_layoutSnapshotFlags != null) return _layoutSnapshotFlags;
			_layoutSnapshotFlags = new List<Tuple<string, Func<bool>, Action<bool>>>
			{
				// Feature toggles (paired pIs*ColumnEnabled + pIs*Enabled)
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsXColumnEnabled",     () => pIsXColumnEnabled,     v => pIsXColumnEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsXEnabled",           () => pIsXEnabled,           v => pIsXEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsCrossColumnEnabled", () => pIsCrossColumnEnabled, v => pIsCrossColumnEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsCrossEnabled",       () => pIsCrossEnabled,       v => pIsCrossEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsATMColumnEnabled",   () => pIsATMColumnEnabled,   v => pIsATMColumnEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsATMSelectEnabled",   () => pIsATMSelectEnabled,   v => pIsATMSelectEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsFadeColumnEnabled",  () => pIsFadeColumnEnabled,  v => pIsFadeColumnEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsFadeEnabled",        () => pIsFadeEnabled,        v => pIsFadeEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pActionsColumnEnabled", () => pActionsColumnEnabled, v => pActionsColumnEnabled = v),
				// X close button
				Tuple.Create<string, Func<bool>, Action<bool>>("pCloseButtonEnabled",   () => pCloseButtonEnabled,   v => pCloseButtonEnabled = v),
				// Risk manager column gates
				Tuple.Create<string, Func<bool>, Action<bool>>("pColumnFromFund",       () => pColumnFromFund,       v => pColumnFromFund = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pIsEvalCloseEnabled",   () => pIsEvalCloseEnabled,   v => pIsEvalCloseEnabled = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pColumnAutoLiquidate",  () => pColumnAutoLiquidate,  v => pColumnAutoLiquidate = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pColumnRemaining",      () => pColumnRemaining,      v => pColumnRemaining = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pColumnDDType",         () => pColumnDDType,         v => pColumnDDType = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pColumnDailyGoal",      () => pColumnDailyGoal,      v => pColumnDailyGoal = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pColumnDailyLoss",      () => pColumnDailyLoss,      v => pColumnDailyLoss = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pColumnProfitRequested",() => pColumnProfitRequested,v => pColumnProfitRequested = v),
				// Columns input-group gates
				Tuple.Create<string, Func<bool>, Action<bool>>("pShowAvgPrice",         () => pShowAvgPrice,         v => pShowAvgPrice = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pUnRealized2Column",    () => pUnRealized2Column,    v => pUnRealized2Column = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pRealized2Column",      () => pRealized2Column,      v => pRealized2Column = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pGrossRealized2Column", () => pGrossRealized2Column, v => pGrossRealized2Column = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pCashValueColumn",      () => pCashValueColumn,      v => pCashValueColumn = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pNetLiquidationColumn", () => pNetLiquidationColumn, v => pNetLiquidationColumn = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pQtyColumn2",           () => pQtyColumn2,           v => pQtyColumn2 = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pCommissionsColumn",    () => pCommissionsColumn,    v => pCommissionsColumn = v),
				Tuple.Create<string, Func<bool>, Action<bool>>("pTotalPNLColumn",       () => pTotalPNLColumn,       v => pTotalPNLColumn = v),
				// Sort direction (sort COLUMN itself goes in the dedicated sort= section
				// because it's a string, not a bool)
				Tuple.Create<string, Func<bool>, Action<bool>>("pSelectedAscending",    () => pSelectedAscending,    v => pSelectedAscending = v),
			};
			return _layoutSnapshotFlags;
		}

		// Capture the current layout into a delimited snapshot string.
		private string BuildLayoutSnapshot()
		{
			try
			{
				var sb = new System.Text.StringBuilder(512);
				sb.Append("v=1");

				// order — comma-list of logical column ids in display order
				sb.Append(";order=");
				if (ColumnDisplayOrderList != null && ColumnDisplayOrderList.Count > 0)
				{
					for (int i = 0; i < ColumnDisplayOrderList.Count; i++)
					{
						if (i > 0) sb.Append(',');
						sb.Append(ColumnDisplayOrderList[i]);
					}
				}

				// hidden — pipe-list of column NAMES
				sb.Append(";hidden=");
				if (_hiddenColumns != null && _hiddenColumns.Count > 0)
				{
					bool _first = true;
					foreach (var nm in _hiddenColumns)
					{
						if (!_first) sb.Append('|');
						sb.Append(nm);
						_first = false;
					}
				}

				// widths — pipe-list of name:width pairs (resolve logical id → name)
				sb.Append(";widths=");
				if (ColumnWidthOverrides != null && ColumnWidthOverrides.Count > 0
					&& ColumnNumberToName != null)
				{
					bool _first = true;
					foreach (var kv in ColumnWidthOverrides)
					{
						string nm;
						if (!ColumnNumberToName.TryGetValue(kv.Key, out nm) || string.IsNullOrEmpty(nm)) continue;
						if (!_first) sb.Append('|');
						sb.Append(nm).Append(':').Append(kv.Value);
						_first = false;
					}
				}

				// flags — pipe-list of name:0_or_1
				sb.Append(";flags=");
				var _flags = GetLayoutSnapshotFlags();
				for (int i = 0; i < _flags.Count; i++)
				{
					if (i > 0) sb.Append('|');
					sb.Append(_flags[i].Item1).Append(':').Append(_flags[i].Item2() ? '1' : '0');
				}

				// sort — column name being sorted (direction is in flags above)
				sb.Append(";sort=").Append(pSelectedColumn ?? "");

				return sb.ToString();
			}
			catch
			{
				return "";
			}
		}

		// Apply a snapshot string back to the runtime state. Inverse of BuildLayoutSnapshot.
		private void ApplyLayoutSnapshot(string snapshot)
		{
			if (string.IsNullOrEmpty(snapshot)) return;
			try
			{
				// Parse top-level "key=value;key=value;..."
				var sections = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
				foreach (string raw in snapshot.Split(';'))
				{
					int eq = raw.IndexOf('=');
					if (eq <= 0) continue;
					sections[raw.Substring(0, eq).Trim()] = raw.Substring(eq + 1);
				}

				// order
				string _orderStr;
				if (sections.TryGetValue("order", out _orderStr) && !string.IsNullOrEmpty(_orderStr))
				{
					if (ColumnDisplayOrderList == null) ColumnDisplayOrderList = new List<int>();
					ColumnDisplayOrderList.Clear();
					foreach (string idStr in _orderStr.Split(','))
					{
						int id;
						if (int.TryParse(idStr.Trim(), out id) && id > 0)
							ColumnDisplayOrderList.Add(id);
					}
					SyncColumnDisplayOrderNames();
				}

				// hidden
				string _hiddenStr;
				if (sections.TryGetValue("hidden", out _hiddenStr))
				{
					if (_hiddenColumns == null) _hiddenColumns = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
					_hiddenColumns.Clear();
					if (!string.IsNullOrEmpty(_hiddenStr))
					{
						foreach (string nm in _hiddenStr.Split('|'))
							if (!string.IsNullOrWhiteSpace(nm)) _hiddenColumns.Add(nm.Trim());
					}
					SerializeHiddenColumnsNow();
				}

				// widths — apply via the pending-by-name map so the next render
				// resolves names → logical ids the same way the workspace-load
				// path does.
				string _widthsStr;
				if (sections.TryGetValue("widths", out _widthsStr))
				{
					if (ColumnWidthOverrides == null) ColumnWidthOverrides = new Dictionary<int, int>();
					ColumnWidthOverrides.Clear();
					if (_pendingColumnWidthOverridesByName == null)
						_pendingColumnWidthOverridesByName = new Dictionary<string, int>();
					_pendingColumnWidthOverridesByName.Clear();
					if (!string.IsNullOrEmpty(_widthsStr))
					{
						foreach (string entry in _widthsStr.Split('|'))
						{
							int colon = entry.LastIndexOf(':');
							if (colon <= 0 || colon >= entry.Length - 1) continue;
							string nm = entry.Substring(0, colon);
							int wid;
							if (int.TryParse(entry.Substring(colon + 1), out wid) && wid > 0)
								_pendingColumnWidthOverridesByName[nm] = wid;
						}
					}
					_columnWidthOverridesNeedApply = _pendingColumnWidthOverridesByName.Count > 0;
					SerializeColumnWidthOverridesNow();
				}

				// flags
				string _flagsStr;
				if (sections.TryGetValue("flags", out _flagsStr) && !string.IsNullOrEmpty(_flagsStr))
				{
					var _setters = new Dictionary<string, Action<bool>>(StringComparer.Ordinal);
					foreach (var t in GetLayoutSnapshotFlags())
						_setters[t.Item1] = t.Item3;
					foreach (string entry in _flagsStr.Split('|'))
					{
						int colon = entry.IndexOf(':');
						if (colon <= 0 || colon >= entry.Length - 1) continue;
						string nm = entry.Substring(0, colon);
						string val = entry.Substring(colon + 1).Trim();
						Action<bool> setter;
						if (_setters.TryGetValue(nm, out setter))
							setter(val == "1" || val.Equals("true", StringComparison.OrdinalIgnoreCase));
					}
				}

				// sort column (sort direction came from flags above as pSelectedAscending)
				string _sortStr;
				if (sections.TryGetValue("sort", out _sortStr))
					pSelectedColumn = string.IsNullOrEmpty(_sortStr) ? "Account" : _sortStr;

				// Force the next render to re-sort with the restored column + direction
				IsSorted = false;
			}
			catch
			{
				// Swallow — bad snapshot string just leaves the existing layout in place.
			}
		}

		// Get/set helpers — index slot 0..2 to the three persistent string properties.
		private string GetPresetSlotString(int slot)
		{
			switch (slot)
			{
				case 0: return pLayoutSlot1Saved ?? "";
				case 1: return pLayoutSlot2Saved ?? "";
				case 2: return pLayoutSlot3Saved ?? "";
				case 3: return pLayoutSlot4Saved ?? "";
				default: return "";
			}
		}
		private void SetPresetSlotString(int slot, string value)
		{
			value = value ?? "";
			switch (slot)
			{
				case 0: pLayoutSlot1Saved = value; break;
				case 1: pLayoutSlot2Saved = value; break;
				case 2: pLayoutSlot3Saved = value; break;
				case 3: pLayoutSlot4Saved = value; break;
			}
		}

		// Draws two concentric halo rects behind a floating overlay (column picker,
		// filter box, tooltip) for a soft "lifted" look. Outer rect is larger and
		// Draws a pixel-clean gear icon centered inside the given button rect.
		// Built from primitives (disc + teeth + center dot + hollow hole) so it
		// renders consistently across systems instead of depending on whatever
		// font the OS picked for U+2699. Shifted up 1px to visually balance
		// against the top-row text buttons that have internal ascender height.
		private void DrawGearIcon(ChartControl chartControl, ChartScale chartScale, SharpDX.RectangleF rect, SharpDX.Direct2D1.Brush brush)
		{
			if (brush == null) return;

			// Dim the gear by preferring the 40% brush over the full-strength one.
			// Matches the other top-row button labels which appear dimmed against
			// the button fill.
			SharpDX.Direct2D1.Brush gearBrush = ChartTextBrushDX40 ?? brush;

			// True center of the button rect — no pixel shift. The previous -1px
			// lift made the gear sit too high in its box.
			float cx = rect.X + rect.Width * 0.5f;
			float cy = rect.Y + rect.Height * 0.5f;
			// Shrink by 4px total (2px inset per side) so the gear doesn't crowd
			// the button edge.
			float size = Math.Min(rect.Width, rect.Height) - 4f;
			if (size < 6f) size = 6f;
			float rBody  = size * 0.28f;
			float rHole  = size * 0.15f;
			float toothLen = size * 0.13f;
			float toothHalfW = Math.Max(0.9f, size * 0.07f);

			// Smooth edges — enable PerPrimitive antialiasing for this draw block,
			// restore Aliased mode afterward so the rest of the UI keeps crisp edges.
			AntialiasMode(chartControl, chartScale, "PerPrimitive");

			// Solid body disc — single ellipse for perfectly round outline.
			SharpDX.Direct2D1.Ellipse body = new SharpDX.Direct2D1.Ellipse(new SharpDX.Vector2(cx, cy), rBody, rBody);
			FillEllipseBoth(chartControl, chartScale, body, gearBrush);

			// 8 teeth as small filled ellipses around the perimeter. Circle-shaped
			// teeth AA cleanly at any angle, avoiding the stairstep look that
			// rectangles produce at 45° rotations. Overlaps the body disc slightly
			// so the outline looks like one solid gear silhouette.
			float toothR = rBody + toothLen * 0.5f;
			for (int t = 0; t < 8; t++)
			{
				double a = t * Math.PI / 4.0;
				float tx = cx + (float)Math.Cos(a) * toothR;
				float ty = cy + (float)Math.Sin(a) * toothR;
				SharpDX.Direct2D1.Ellipse tooth = new SharpDX.Direct2D1.Ellipse(new SharpDX.Vector2(tx, ty), toothHalfW * 1.3f, toothHalfW * 1.3f);
				FillEllipseBoth(chartControl, chartScale, tooth, gearBrush);
			}

			// Punch out the center hole — first fill with the solid background
			// brush (so the gear body underneath fully clears), then overlay a
			// 20% text-color disc so the hole doesn't read as pitch-black.
			// End result: a soft gray center that's clearly lighter than the
			// gear body but darker than the gear itself.
			if (rHole > 0.5f && ChartBackgroundBrushDX != null)
			{
				SharpDX.Direct2D1.Ellipse hole = new SharpDX.Direct2D1.Ellipse(new SharpDX.Vector2(cx, cy), rHole, rHole);
				FillEllipseBoth(chartControl, chartScale, hole, ChartBackgroundBrushDX);
				if (ChartTextBrushDX20 != null)
					FillEllipseBoth(chartControl, chartScale, hole, ChartTextBrushDX20);
			}

			// Restore aliased mode for downstream rendering.
			AntialiasMode(chartControl, chartScale, "Aliased");
		}

		// lighter; inner rect is 1px closer to the real background. Call before
		// filling the overlay's own background rect.
		private void DrawOverlayGlow(ChartControl chartControl, ChartScale chartScale, SharpDX.RectangleF r)
		{
			if (OverlayGlowBrushDX2 == null) return;
			// Five-step soft halo around the overlay rect, drawn as four EDGE
			// STRIPS per ring (top / bottom / left / right) instead of full
			// concentric rectangles. The corners are handled separately, with
			// progressively smaller fill so the diagonal pixels fade out faster
			// than the edge pixels — produces a chamfered "rounded" feel
			// without per-frame geometry creation.
			//
			// Brushes: 2% (outer) → 3% → 5% → 7% → 10% (inner). Each ring's
			// strip is 1 px thick, sitting one pixel further out than the next.
			float L = r.X, T = r.Y, R = r.Right, B = r.Bottom;
			float W = r.Width, H = r.Height;

			// Edge strips: ring i is i+1 pixels out from the rect, 1 px thick.
			// Strips DON'T cover the corner squares — those are filled below
			// with progressively-shrinking alpha so the corners look rounded.
			// Inline helper would be ideal but we keep it flat for clarity.
			// --- ring 5 (outermost, 2%) ---
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 4, T - 5, W + 8, 1), OverlayGlowBrushDX2); // top
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 4, B + 4, W + 8, 1), OverlayGlowBrushDX2); // bottom
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 5, T - 4, 1, H + 8), OverlayGlowBrushDX2); // left
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(R + 4, T - 4, 1, H + 8), OverlayGlowBrushDX2); // right

			// --- ring 4 (3%) ---
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 3, T - 4, W + 6, 1), OverlayGlowBrushDX3);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 3, B + 3, W + 6, 1), OverlayGlowBrushDX3);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 4, T - 3, 1, H + 6), OverlayGlowBrushDX3);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(R + 3, T - 3, 1, H + 6), OverlayGlowBrushDX3);

			// --- ring 3 (5%) ---
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 2, T - 3, W + 4, 1), OverlayGlowBrushDX5);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 2, B + 2, W + 4, 1), OverlayGlowBrushDX5);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 3, T - 2, 1, H + 4), OverlayGlowBrushDX5);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(R + 2, T - 2, 1, H + 4), OverlayGlowBrushDX5);

			// --- ring 2 (7%) ---
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 1, T - 2, W + 2, 1), OverlayGlowBrushDX7);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 1, B + 1, W + 2, 1), OverlayGlowBrushDX7);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 2, T - 1, 1, H + 2), OverlayGlowBrushDX7);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(R + 1, T - 1, 1, H + 2), OverlayGlowBrushDX7);

			// --- ring 1 (innermost, 10%) ---
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L,     T - 1, W,     1), OverlayGlowBrushDX10);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L,     B,     W,     1), OverlayGlowBrushDX10);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 1, T,     1,     H), OverlayGlowBrushDX10);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(R,     T,     1,     H), OverlayGlowBrushDX10);

			// Corner softeners — single pixels at each corner of each ring,
			// using the NEXT-OUTER brush (so the corner alpha is one step less
			// than the edge it sits in). This breaks up the hard 90° step at
			// the corner and reads as a chamfer.
			// Innermost corners (would be 10% on edges) get 7% fill.
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 1, T - 1, 1, 1), OverlayGlowBrushDX7);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(R,     T - 1, 1, 1), OverlayGlowBrushDX7);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(L - 1, B,     1, 1), OverlayGlowBrushDX7);
			FillRectBoth(chartControl, chartScale, new SharpDX.RectangleF(R,     B,     1, 1), OverlayGlowBrushDX7);
			// Outer corners get 2% (or nothing) — leaving them blank already
			// works because the edge strips don't reach them. The 2% outer
			// ring corners drawn by the strip overlap above are sparse enough
			// that the diagonal already reads as soft.
		}

		private void DrawOverlayGlowDirect(SharpDX.RectangleF r)
		{
			if (OverlayGlowBrushDX2 == null) return;
			// Five-step soft halo around the overlay rect, drawn as four EDGE
			// STRIPS per ring (top / bottom / left / right) instead of full
			// concentric rectangles. The corners are handled separately, with
			// progressively smaller fill so the diagonal pixels fade out faster
			// than the edge pixels — produces a chamfered "rounded" feel
			// without per-frame geometry creation.
			//
			// Brushes: 2% (outer) → 3% → 5% → 7% → 10% (inner). Each ring's
			// strip is 1 px thick, sitting one pixel further out than the next.
			float L = r.X, T = r.Y, R = r.Right, B = r.Bottom;
			float W = r.Width, H = r.Height;

			// Edge strips: ring i is i+1 pixels out from the rect, 1 px thick.
			// Strips DON'T cover the corner squares — those are filled below
			// with progressively-shrinking alpha so the corners look rounded.
			// Inline helper would be ideal but we keep it flat for clarity.
			// --- ring 5 (outermost, 2%) ---
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 4, T - 5, W + 8, 1), OverlayGlowBrushDX2); // top
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 4, B + 4, W + 8, 1), OverlayGlowBrushDX2); // bottom
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 5, T - 4, 1, H + 8), OverlayGlowBrushDX2); // left
			RenderTarget.FillRectangle(new SharpDX.RectangleF(R + 4, T - 4, 1, H + 8), OverlayGlowBrushDX2); // right

			// --- ring 4 (3%) ---
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 3, T - 4, W + 6, 1), OverlayGlowBrushDX3);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 3, B + 3, W + 6, 1), OverlayGlowBrushDX3);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 4, T - 3, 1, H + 6), OverlayGlowBrushDX3);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(R + 3, T - 3, 1, H + 6), OverlayGlowBrushDX3);

			// --- ring 3 (5%) ---
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 2, T - 3, W + 4, 1), OverlayGlowBrushDX5);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 2, B + 2, W + 4, 1), OverlayGlowBrushDX5);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 3, T - 2, 1, H + 4), OverlayGlowBrushDX5);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(R + 2, T - 2, 1, H + 4), OverlayGlowBrushDX5);

			// --- ring 2 (7%) ---
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 1, T - 2, W + 2, 1), OverlayGlowBrushDX7);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 1, B + 1, W + 2, 1), OverlayGlowBrushDX7);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 2, T - 1, 1, H + 2), OverlayGlowBrushDX7);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(R + 1, T - 1, 1, H + 2), OverlayGlowBrushDX7);

			// --- ring 1 (innermost, 10%) ---
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L,     T - 1, W,     1), OverlayGlowBrushDX10);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L,     B,     W,     1), OverlayGlowBrushDX10);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 1, T,     1,     H), OverlayGlowBrushDX10);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(R,     T,     1,     H), OverlayGlowBrushDX10);

			// Corner softeners — single pixels at each corner of each ring,
			// using the NEXT-OUTER brush (so the corner alpha is one step less
			// than the edge it sits in). This breaks up the hard 90° step at
			// the corner and reads as a chamfer.
			// Innermost corners (would be 10% on edges) get 7% fill.
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 1, T - 1, 1, 1), OverlayGlowBrushDX7);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(R,     T - 1, 1, 1), OverlayGlowBrushDX7);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(L - 1, B,     1, 1), OverlayGlowBrushDX7);
			RenderTarget.FillRectangle(new SharpDX.RectangleF(R,     B,     1, 1), OverlayGlowBrushDX7);
			// Outer corners get 2% (or nothing) — leaving them blank already
			// works because the edge strips don't reach them. The 2% outer
			// ring corners drawn by the strip overlap above are sparse enough
			// that the diagonal already reads as soft.
		}

		// Feature-toggle columns: Size / Type / Mode / Fade / Actions are gated by
		// pIs*ColumnEnabled / pActionsColumnEnabled properties. Toggling them from
		// the right-click picker is equivalent to unchecking those boxes — it
		// removes the column AND disables the underlying copier feature.
		// "Actions" no longer has a bottom-left button counterpart; the picker
		// is its only on/off control.
		private bool IsFeatureToggleColumn(string columnName)
		{
			if (string.IsNullOrEmpty(columnName)) return false;
			return columnName == sizecolname || columnName == "Size"
				|| columnName == "Type"
				|| columnName == modecoln || columnName == "Mode"
				|| columnName == "Fade"
				|| columnName == "Actions";
		}

		// Subset of feature-toggle columns that get the goldenrod accent strip
		// + label color in the picker. These four directly enable / disable
		// copier-side BEHAVIOR (size multiplier, cross-account type, ATM mode,
		// reverse-fade), so they need to stand out as "this changes how trades
		// are mirrored" entries. Actions is also a feature toggle, but it just
		// controls a column visibility / reset-buttons display — there's no
		// downstream copier behavior tied to it, so it stays styled as a
		// regular column entry.
		private bool IsFeatureColumnAccented(string columnName)
		{
			if (string.IsNullOrEmpty(columnName)) return false;
			return columnName == sizecolname || columnName == "Size"
				|| columnName == "Type"
				|| columnName == modecoln || columnName == "Mode"
				|| columnName == "Fade";
		}

		// Dispatch for every column whose visibility is gated by a master
		// property (the fields in the Columns / Window Display input group).
		// The right-click picker uses these to show ALL possible columns,
		// including ones that are currently off — otherwise a user who
		// disables a column once has no way to re-enable it from the picker.
		//
		// Feature-toggle columns (Size/Type/Mode/Fade/Actions) are handled
		// by IsFeatureToggleColumn / Get/SetFeatureToggleState and routed
		// separately — they also tweak pIs*Enabled for same-frame effect,
		// which regular master-property columns don't need.
		private bool HasColumnMasterProperty(string columnName)
		{
			if (string.IsNullOrEmpty(columnName)) return false;
			switch (columnName)
			{
				case "Qty":
				case "Avg Price":
				case "Unrealized":
				case "Realized":
				case "Gross Realized":
				case "Cash Value":
				case "Net Liquidation":
				case "From Funded":
				case "Auto Liquidate":
				case "From Closed":
				case "DD":
				case "Payout":
				case "Commissions":
				case "Total PNL":
				case "X":
				case "Latency":
					return true;
				// Daily Goal / Daily Loss deliberately NOT listed — their picker
				// toggle must go through _hiddenColumns (display-only), never
				// through pColumnDailyGoal/Loss, to keep the enforcement path
				// decoupled from the display flag. See the enforcement block
				// at ~line 12123 for the trade-safety reasoning.
				default:
					return false;
			}
		}

		private bool GetColumnMasterPropertyState(string columnName)
		{
			if (string.IsNullOrEmpty(columnName)) return false;
			switch (columnName)
			{
				case "Qty":             return pQtyColumn2;
				case "Avg Price":       return pShowAvgPrice;
				case "Unrealized":      return pUnRealized2Column;
				case "Realized":        return pRealized2Column;
				case "Gross Realized":  return pGrossRealized2Column;
				case "Cash Value":      return pCashValueColumn;
				case "Net Liquidation": return pNetLiquidationColumn;
				case "From Funded":     return pColumnFromFund;
				case "Auto Liquidate":  return pColumnAutoLiquidate;
				case "From Closed":     return pColumnRemaining;
				case "DD":              return pColumnDDType;
				case "Payout":          return pColumnProfitRequested;
				case "Commissions":     return pCommissionsColumn;
				case "Total PNL":       return pTotalPNLColumn;
				case "X":               return pCloseButtonEnabled;
				case "Latency":         return pLatencyColumn;
			}
			return false;
		}

		private void SetColumnMasterPropertyState(string columnName, bool enabled)
		{
			if (string.IsNullOrEmpty(columnName)) return;
			switch (columnName)
			{
				case "Qty":             pQtyColumn2 = enabled; break;
				case "Avg Price":       pShowAvgPrice = enabled; break;
				case "Unrealized":      pUnRealized2Column = enabled; break;
				case "Realized":        pRealized2Column = enabled; break;
				case "Gross Realized":  pGrossRealized2Column = enabled; break;
				case "Cash Value":      pCashValueColumn = enabled; break;
				case "Net Liquidation": pNetLiquidationColumn = enabled; break;
				case "From Funded":     pColumnFromFund = enabled; break;
				case "Auto Liquidate":  pColumnAutoLiquidate = enabled; break;
				case "From Closed":     pColumnRemaining = enabled; break;
				case "DD":              pColumnDDType = enabled; break;
				case "Payout":          pColumnProfitRequested = enabled; break;
				case "Commissions":     pCommissionsColumn = enabled; break;
				case "Total PNL":       pTotalPNLColumn = enabled; break;
				case "X":               pCloseButtonEnabled = enabled; break;
				case "Latency":         pLatencyColumn = enabled; break;
			}
		}

		private bool GetFeatureToggleState(string columnName)
		{
			if (string.IsNullOrEmpty(columnName)) return false;
			if (columnName == sizecolname || columnName == "Size") return pIsXColumnEnabled;
			if (columnName == "Type")                               return pIsCrossColumnEnabled;
			if (columnName == modecoln || columnName == "Mode")    return pIsATMColumnEnabled;
			if (columnName == "Fade")                               return pIsFadeColumnEnabled;
			if (columnName == "Actions")                            return pActionsColumnEnabled;
			return false;
		}

		private void SetFeatureToggleState(string columnName, bool enabled)
		{
			if (string.IsNullOrEmpty(columnName)) return;
			if (columnName == sizecolname || columnName == "Size") { pIsXColumnEnabled = enabled; pIsXEnabled = enabled; }
			else if (columnName == "Type")                          { pIsCrossColumnEnabled = enabled; pIsCrossEnabled = enabled; }
			else if (columnName == modecoln || columnName == "Mode") { pIsATMColumnEnabled = enabled; pIsATMSelectEnabled = enabled; }
			else if (columnName == "Fade")                          { pIsFadeColumnEnabled = enabled; pIsFadeEnabled = enabled; }
			else if (columnName == "Actions")
			{
				pActionsColumnEnabled = enabled;
				// Clear the legacy "hide" override so it can't fight the
				// picker's column-enabled state.
				pActions2HideColumnEnabled = false;
			}

			if (!enabled)
				CheckFeatureDisableWarning(columnName);
		}

		private void CheckFeatureDisableWarning(string columnName)
		{
			// AddMessage / RemoveMessage touch WPF. During workspace restore State.DataLoaded
			// can run on the data thread, so marshal via SafeDispatch to avoid throwing
			// "calling thread cannot access this object" mid-button-registration.
			SafeDispatch(() =>
			{
				if (columnName == "Type" || columnName == "Cross")
				{
					RemoveMessage("WARNING: The 'Type' column");
					if (AllDuplicateAccounts.Count > 0)
					{
						string instrumentHint = "";
						if (pInstrumentMode == "Single" && !string.IsNullOrEmpty(pSingleInstrument))
						{
							Instrument mini = GetTheInstrument(pSingleInstrument, "Mini", false);
							Instrument micro = GetTheInstrument(pSingleInstrument, "Micro", false);
							if (mini != null && micro != null)
								instrumentHint = " (e.g., " + mini.FullName + " → " + micro.FullName + ")";
						}
						else if (pInstrumentMode == "All" && Instrument != null)
						{
							Instrument mini = GetTheInstrument(Instrument.FullName, "Mini", false);
							Instrument micro = GetTheInstrument(Instrument.FullName, "Micro", false);
							if (mini != null && micro != null)
								instrumentHint = " (e.g., " + mini.FullName + " → " + micro.FullName + ")";
						}

						AddMessage("WARNING: The 'Type' column has been disabled. Instrument conversion" + instrumentHint + " is no longer active. Follower accounts will receive the same instrument as the Master account. Re-enable the 'Type' column to restore Mini/Micro conversion.", 60, Brushes.Goldenrod);
					}
				}
				else if (columnName == sizecolname || columnName == "Size")
				{
					RemoveMessage("WARNING: The 'Size' column");
					if (AllDuplicateAccounts.Count > 0)
					{
						AddMessage("WARNING: The 'Size' column has been disabled. Quantity multipliers are no longer active. Follower accounts will receive the same quantity as the Master account. Re-enable the 'Size' column to restore quantity adjustments.", 60, Brushes.Goldenrod);
					}
				}
			});
		}

		// Pool of reusable inner lists for AllColumns. The old pattern allocated a
		// fresh `new List<string>(TempRowN)` per column per frame (~30 allocations).
		// With this helper we keep a persistent pool, reuse the inner lists across
		// frames, and only the OUTER AllColumns list reference gets reshuffled on
		// Clear. Reset _allColumnsPoolIdx at the start of each frame before calling.
		private List<List<string>> _allColumnsPool = new List<List<string>>(40);
		private int _allColumnsPoolIdx = 0;
		private void AllColumnsAddReuse(List<string> src)
		{
			List<string> inner;
			if (_allColumnsPoolIdx < _allColumnsPool.Count)
			{
				inner = _allColumnsPool[_allColumnsPoolIdx];
				inner.Clear();
			}
			else
			{
				inner = new List<string>(src.Count + 4);
				_allColumnsPool.Add(inner);
			}
			_allColumnsPoolIdx++;
			// Pre-apply the text replacements that were previously done per-cell
			// in the render loop (~6000 string allocations/frame eliminated).
			for (int _si = 0; _si < src.Count; _si++)
			{
				string _s = src[_si];
				if (_s.Length > 5) // only bother checking strings long enough to match
				{
					if (_s.IndexOf("End Of Day", StringComparison.Ordinal) >= 0) _s = _s.Replace("End Of Day", "EOD");
					if (_s.IndexOf("Trailing", StringComparison.Ordinal) >= 0) _s = _s.Replace("Trailing", "Trail");
				}
				inner.Add(_s);
			}
			AllColumns.Add(inner);
		}

				// Records one latency sample: the per-follower latest value and a bounded
		// rolling history (drives the Latency column and its adaptive coloring).
		private void RecordLatencySample(bool isDispatch, string follower, double ms)
		{
			DateTime _now = DateTime.Now;
			Dictionary<string, double>       _curD  = isDispatch ? _copierLatencyMs    : _copierConfirmMs;
			Dictionary<string, DateTime>     _stD   = isDispatch ? _copierLatencyStamp : _copierConfirmStamp;
			Dictionary<string, List<double>> _histD = isDispatch ? _copierLatencyHist  : _copierConfirmHist;
			_curD[follower] = ms;
			_stD[follower]  = _now;
			List<double> _h;
			if (!_histD.TryGetValue(follower, out _h)) { _h = new List<double>(CopierLatencyHistoryLen); _histD[follower] = _h; }
			_h.Add(ms);
			if (_h.Count > CopierLatencyHistoryLen) _h.RemoveAt(0);
		}

		// Forces a chart redraw so a freshly recorded latency sample shows up even
		// when the market is quiet (no incoming ticks to drive OnRender). Marshals
		// to the UI thread; WPF coalesces repeats, so calling it once per follower
		// in a copy burst is fine.
		private void RequestLatencyRedraw()
		{
			try
			{
				var disp = ChartControl != null ? ChartControl.Dispatcher : null;
				if (disp == null) return;
				if (disp.CheckAccess())
					InvalidateVis(950);
				else
					disp.InvokeAsync(() => { try { InvalidateVis(950); } catch { } });
			}
			catch { }
		}

				// Called when the copier submits an order to a Follower. Records DISPATCH
		// latency, groups followers into copy events (accounts + ms/account), tags
		// flatten events, and registers the order for CONFIRMATION tracking.
		private void RecordCopierLatency(string followerAccountName, Order followerOrder, string actionLabel = "Place")
		{
			if (string.IsNullOrEmpty(followerAccountName) || _copierLatencyMasterT == DateTime.MinValue) return;
			if (!pLatencyColumn) return;
			DateTime _detected = _copierLatencyMasterT;
			if (pCopierMode == "Executions") actionLabel = "Execution";
			double ms = (DateTime.Now - _detected).TotalMilliseconds;

			// Copy-event grouping: every follower sharing one detection timestamp is
			// one copy event. Counts accounts and the event worst latency (the menu
			// ms-per-account), and tags the event "Flatten" when the master account
			// is flat -- the copier is closing followers out.
			if (_detected != _latEvtKey)
			{
				FinalizeLatEvent();
				_latEvtKey     = _detected;
				_latEvtFlatten = CurrentMasterAccount != null && IsAccountFlat(CurrentMasterAccount);
				_latEvtCount   = 0;
				_latEvtMaxMs   = 0;
			}
			if (_latEvtFlatten) actionLabel = "Flatten";
			_latEvtAction = actionLabel;
			_latEvtCount++;
			if (ms >= 0 && ms <= 60000 && ms > _latEvtMaxMs) _latEvtMaxMs = ms;

			if (pLatencyDispatch && ms >= 0 && ms <= 60000)
			{
				if (_diagLog != null)
					_diagLog.Log("PERF", "COPIER_LATENCY", "Follower=" + followerAccountName + "|Metric=Dispatch|Action=" + actionLabel + "|LatencyMs=" + ms.ToString("F1"));
				RecordLatencySample(true, followerAccountName, ms);
				RequestLatencyRedraw();
			}

			if (pLatencyConfirmation && followerOrder != null)
			{
				lock (_latencyPendingLock)
				{
					if (_latencyPendingConfirm.Count > 512) _latencyPendingConfirm.Clear();
					_latencyPendingConfirm[followerOrder] = new LatencyConfirmPending { Account = followerAccountName, Detected = _detected, Action = actionLabel };
				}
			}
		}

		// Follower-account OrderUpdate handler dedicated to CONFIRMATION latency.
		// Subscribed to every follower account alongside OnPositionUpdate3. A
		// Place/Move/Execution confirms when the follower order first goes live at
		// the broker; a Cancel confirms when it reaches Cancelled. Provider thread.
		private void OnFollowerLatencyOrderUpdate(object sender, OrderEventArgs e)
		{
			try
			{
				if (e == null || e.Order == null) return;
				LatencyConfirmPending _p = null;
				bool _resolved = false, _dropped = false;
				lock (_latencyPendingLock)
				{
					if (!_latencyPendingConfirm.TryGetValue(e.Order, out _p) || _p == null) return;
					if (_p.Action == "Cancel")
					{
						_resolved = e.OrderState == OrderState.Cancelled;
						_dropped  = e.OrderState == OrderState.Rejected;
					}
					else
					{
						_resolved = e.OrderState == OrderState.Accepted || e.OrderState == OrderState.Working
							 || e.OrderState == OrderState.PartFilled || e.OrderState == OrderState.Filled;
						_dropped  = e.OrderState == OrderState.Rejected || e.OrderState == OrderState.Cancelled;
					}
					if (!_resolved && !_dropped) return;
					_latencyPendingConfirm.Remove(e.Order);
				}
				if (_dropped) return;
				double ms = (DateTime.Now - _p.Detected).TotalMilliseconds;
				if (ms < 0 || ms > 60000) return;
				if (_diagLog != null)
					_diagLog.Log("PERF", "COPIER_LATENCY", "Follower=" + _p.Account + "|Metric=Confirmation|Action=" + (_p.Action ?? "?") + "|State=" + e.OrderState + "|LatencyMs=" + ms.ToString("F1"));
				RecordLatencySample(false, _p.Account, ms);
				RequestLatencyRedraw();
			}
			catch { }
		}

		// Drops _latencyPendingConfirm entries whose follower order never reported
		// a live/done state (e.g. the broker silently dropped it) so the map can't
		// leak. Called periodically from the dead-account cleanup pass.
		private void SweepStaleLatencyPending()
		{
			if (_latencyPendingConfirm.Count == 0) return;
			lock (_latencyPendingLock)
			{
				if (_latencyPendingConfirm.Count == 0) return;
				DateTime _now = DateTime.Now;
				List<Order> _dead = null;
				foreach (var _kv in _latencyPendingConfirm)
					if ((_now - _kv.Value.Detected).TotalSeconds > CopierLatencyStaleAfterSec)
					{
						if (_dead == null) _dead = new List<Order>();
						_dead.Add(_kv.Key);
					}
				if (_dead != null)
					foreach (Order _o in _dead) _latencyPendingConfirm.Remove(_o);
			}
		}

				// Latency column cell text: the ms of this follower latest sample (dispatch
		// or confirmation, whichever is newer) -- the latency of the most recent
		// copied action. The renderer dims a stale value; an en-dash means no
		// sample yet. Per-action averages live in the latency menu.
		private string GetLatencyCellText(string accountName)
		{
			if (string.IsNullOrEmpty(accountName)) return "–";
			double _dMs = 0, _cMs = 0;
			DateTime _dSt = DateTime.MinValue, _cSt = DateTime.MinValue;
			bool _hD = pLatencyDispatch     && _copierLatencyMs.TryGetValue(accountName, out _dMs) && _copierLatencyStamp.TryGetValue(accountName, out _dSt);
			bool _hC = pLatencyConfirmation && _copierConfirmMs.TryGetValue(accountName, out _cMs) && _copierConfirmStamp.TryGetValue(accountName, out _cSt);
			if (_hD && _hC) return (int)Math.Round(_cSt >= _dSt ? _cMs : _dMs) + "ms";
			if (_hD) return (int)Math.Round(_dMs) + "ms";
			if (_hC) return (int)Math.Round(_cMs) + "ms";
			return "–";
		}

				// Per-action menu stats: the average accounts per copy event, and the
		// average ms-per-account (event worst latency / accounts). Returns false
		// when the action has no completed copy event yet.
		private bool LatActionEventStats(string action, out int count, out int msPerAcct)
		{
			count = 0; msPerAcct = 0;
			LatActionStat _st;
			if (!_latActionStats.TryGetValue(action, out _st) || _st.EvtCountHist.Count == 0) return false;
			double _cSum = 0;
			for (int _i = 0; _i < _st.EvtCountHist.Count; _i++) _cSum += _st.EvtCountHist[_i];
			double _pSum = 0;
			for (int _i = 0; _i < _st.EvtPerAcctHist.Count; _i++) _pSum += _st.EvtPerAcctHist[_i];
			count = (int)Math.Round(_cSum / _st.EvtCountHist.Count);
			msPerAcct = (int)Math.Round(_pSum / Math.Max(1, _st.EvtPerAcctHist.Count));
			return true;
		}

		// Finalizes the in-progress copy event into its action rolling stats.
		// Called when a new event begins (a different detection timestamp).
		private void FinalizeLatEvent()
		{
			if (_latEvtCount <= 0 || string.IsNullOrEmpty(_latEvtAction)) return;
			LatActionStat _st;
			if (!_latActionStats.TryGetValue(_latEvtAction, out _st)) { _st = new LatActionStat(); _latActionStats[_latEvtAction] = _st; }
			_st.EvtCountHist.Add(_latEvtCount);
			if (_st.EvtCountHist.Count > CopierLatencyHistoryLen) _st.EvtCountHist.RemoveAt(0);
			_st.EvtPerAcctHist.Add(_latEvtMaxMs / _latEvtCount);
			if (_st.EvtPerAcctHist.Count > CopierLatencyHistoryLen) _st.EvtPerAcctHist.RemoveAt(0);
		}

		// A follower adaptive baseline for a metric: the mean of its recent latency
		// history. Returns -1 until LatencyBaselineMinSamples samples accumulate.
		private double LatencyBaseline(Dictionary<string, List<double>> histD, string acct)
		{
			List<double> _h;
			if (histD == null || !histD.TryGetValue(acct, out _h) || _h.Count < LatencyBaselineMinSamples) return -1;
			double _s = 0;
			for (int _i = 0; _i < _h.Count; _i++) _s += _h[_i];
			return _s / _h.Count;
		}

		// Executes a profile menu action — shared between mouse-click and
		// keyboard-Enter handlers in the profile picker.
		private void ActivateProfileMenuItem(string clickedName)
		{
			if (string.IsNullOrEmpty(clickedName) || clickedName == "---") return;

			if (clickedName == "Properties")
			{
				_profilePickerOpen = false;
				OnPropertiesMenuClick(null, null);
				return;
			}
			if (clickedName == "Reset Hidden Accounts")
			{
				_profilePickerOpen = false;
				ChartControl.Dispatcher.InvokeAsync(() =>
				{
					try
					{
						int prevCount = AllHideAccounts != null ? AllHideAccounts.Count : 0;
						ResetHiddenAccounts();
						if (_diagLog != null) _diagLog.Log("ACTION", "RESET_HIDDEN_ACCOUNTS", "Cleared=" + prevCount);
						AddMessage("Hidden accounts cleared (" + prevCount + " unhidden).", 6, Brushes.Goldenrod);
					}
					catch (Exception ex) { AddMessage("Error resetting hidden accounts: " + ex.Message, 10, Brushes.Red); }
				});
				return;
			}
			if (clickedName == "Reset Account Selections")
			{
				_profilePickerOpen = false;
				ChartControl.Dispatcher.InvokeAsync(() =>
				{
					try
					{
						ResetAccountSelections();
						if (_diagLog != null) _diagLog.Log("ACTION", "RESET_ACCOUNT_SELECTIONS", "");
						AddMessage("Account selections cleared.", 6, Brushes.Goldenrod);
					}
					catch (Exception ex) { AddMessage("Error resetting account selections: " + ex.Message, 10, Brushes.Red); }
				});
				return;
			}
			if (clickedName == "Save New Profile")
			{
				_profilePickerOpen = false;
				ChartControl.Dispatcher.InvokeAsync(() =>
				{
					try
					{
						string name = "";
						NTWindow _promptWin = new NTWindow { Caption = "Save Profile", Width = 320, Height = 180, WindowStartupLocation = WindowStartupLocation.CenterScreen, ResizeMode = ResizeMode.NoResize, Topmost = true };
						try { _promptWin.Owner = Window.GetWindow(ChartControl.Parent); } catch { }
						StackPanel _sp = new StackPanel { Margin = new Thickness(12) };
						_sp.Children.Add(new TextBlock { Text = "Enter a name for this profile:", Margin = new Thickness(0, 0, 0, 8), Foreground = System.Windows.Media.Brushes.White });
						TextBox _tb = new TextBox { Text = "My Profile" };
						_sp.Children.Add(_tb);
						Button _okBtn = new Button { Content = "Save", Width = 80, Margin = new Thickness(0, 10, 0, 0), HorizontalAlignment = HorizontalAlignment.Right };
						_okBtn.Click += (s2, e2) => { name = _tb.Text; _promptWin.Close(); };
						_sp.Children.Add(_okBtn);
						_promptWin.Content = _sp;
						_promptWin.ShowDialog();
						if (!string.IsNullOrEmpty(name))
						{
							foreach (char c in System.IO.Path.GetInvalidFileNameChars())
								name = name.Replace(c, '_');
							string savePath = System.IO.Path.Combine(_profilesDir, name + ".xml");
							if (_diagLog != null) _diagLog.Log("CONFIG", "PROFILE_SAVE", "Name=" + name);
							Chart cw = chartWindow ?? (Window.GetWindow(ChartControl.Parent) as Chart);
							if (cw != null)
							{
								System.Xml.Linq.XDocument doc = new System.Xml.Linq.XDocument(new System.Xml.Linq.XElement("NinjaTrader"));
								MethodInfo saveMethod = typeof(Chart).GetMethod("Save",
									BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance,
									null, new Type[] { typeof(System.Xml.Linq.XDocument), typeof(System.Xml.Linq.XElement), typeof(bool) }, null);
								if (saveMethod != null)
								{
									saveMethod.Invoke(cw, new object[] { doc, doc.Root, true });
									doc.Save(savePath);
									AddMessage("Profile '" + name + "' saved.", 6, Brushes.Goldenrod);
									_activeProfileName = name; _profileDirty = false;
								}
								else
								{
									saveMethod = typeof(Chart).GetMethod("Save",
										BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance,
										null, new Type[] { typeof(System.Xml.Linq.XDocument), typeof(System.Xml.Linq.XElement) }, null);
									if (saveMethod != null)
									{
										saveMethod.Invoke(cw, new object[] { doc, doc.Root });
										doc.Save(savePath);
										AddMessage("Profile '" + name + "' saved.", 6, Brushes.Goldenrod);
										_activeProfileName = name; _profileDirty = false;
									}
									else AddMessage("Profile save not supported on this NT8 version.", 10, Brushes.Red);
								}
							}
						}
					}
					catch (Exception ex) { AddMessage("Error saving profile: " + ex.Message, 10, Brushes.Red); }
				});
				return;
			}
			if (clickedName == "Update Current Profile" && !string.IsNullOrEmpty(_activeProfileName))
			{
				_profilePickerOpen = false;
				ChartControl.Dispatcher.InvokeAsync(() =>
				{
					try
					{
						string savePath = System.IO.Path.Combine(_profilesDir, _activeProfileName + ".xml");
						Chart cw = chartWindow ?? (Window.GetWindow(ChartControl.Parent) as Chart);
						if (cw != null)
						{
							System.Xml.Linq.XDocument doc = new System.Xml.Linq.XDocument(new System.Xml.Linq.XElement("NinjaTrader"));
							MethodInfo saveMethod = typeof(Chart).GetMethod("Save",
								BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance,
								null, new Type[] { typeof(System.Xml.Linq.XDocument), typeof(System.Xml.Linq.XElement), typeof(bool) }, null);
							if (saveMethod != null)
							{
								saveMethod.Invoke(cw, new object[] { doc, doc.Root, true });
								doc.Save(savePath);
							}
							else
							{
								saveMethod = typeof(Chart).GetMethod("Save",
									BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance,
									null, new Type[] { typeof(System.Xml.Linq.XDocument), typeof(System.Xml.Linq.XElement) }, null);
								if (saveMethod != null)
								{
									saveMethod.Invoke(cw, new object[] { doc, doc.Root });
									doc.Save(savePath);
								}
							}
							AddMessage("Profile '" + _activeProfileName + "' updated.", 6, Brushes.Goldenrod);
							_profileDirty = false;
						}
					}
					catch (Exception ex) { AddMessage("Error updating profile: " + ex.Message, 10, Brushes.Red); }
				});
				return;
			}

			// Otherwise: load a saved profile
			_profilePickerOpen = false;
			string profilePath = System.IO.Path.Combine(_profilesDir, clickedName + ".xml");
			if (!System.IO.File.Exists(profilePath)) return;
			if (_diagLog != null) _diagLog.Log("CONFIG", "PROFILE_LOAD", "Name=" + clickedName);
			try
			{
				System.Xml.Linq.XDocument xdoc = System.Xml.Linq.XDocument.Load(profilePath);
				System.Xml.Linq.XElement indElem = xdoc.Descendants("aiDuplicateAccountActions").FirstOrDefault();
				if (indElem == null)
				{
					AddMessage("Profile '" + clickedName + "' does not contain dashboard settings.", 10, Brushes.Red);
					return;
				}
				int applied = 0;
				Type myType = this.GetType();
				PropertyInfo[] props = myType.GetProperties(BindingFlags.Public | BindingFlags.Instance);
				foreach (System.Xml.Linq.XElement prop in indElem.Elements())
				{
					string xmlName = prop.Name.LocalName;
					string xmlVal = prop.Value;
					if (string.IsNullOrEmpty(xmlVal)) continue;
					if (xmlName == "ThisMasterAccount" || xmlName == "LicensingEmailAddress"
						|| xmlName == "IsCopyBasicFunctionsPermission" || xmlName == "IsRiskFunctionsPermission"
						|| xmlName == "FirstLoadIsDone" || xmlName == "PreviousVersionName"
						|| xmlName == "Name" || xmlName == "IsVisible" || xmlName == "Calculate"
						|| xmlName == "BarsPeriodSerializable" || xmlName == "BarsToLoad"
						|| xmlName == "InstrumentDeserialized" || xmlName == "IndicatorId"
						|| xmlName == "ChartHashCodeDeserialized"
						|| xmlName == "ActiveProfileName_Saved") continue;
					foreach (PropertyInfo pi in props)
					{
						if (pi.Name != xmlName || !pi.CanWrite) continue;
						try
						{
							object val = null;
							Type pt = pi.PropertyType;
							if (pt == typeof(string)) val = xmlVal;
							else if (pt == typeof(bool)) val = bool.Parse(xmlVal);
							else if (pt == typeof(int)) val = int.Parse(xmlVal);
							else if (pt == typeof(double)) val = double.Parse(xmlVal, System.Globalization.CultureInfo.InvariantCulture);
							else if (pt == typeof(float)) val = float.Parse(xmlVal, System.Globalization.CultureInfo.InvariantCulture);
							else if (pt.IsEnum) val = Enum.Parse(pt, xmlVal);
							if (val != null) { pi.SetValue(this, val); applied++; }
						}
						catch { }
						break;
					}
				}
				RemoveMessage("' loaded (");
				AddMessage("Profile '" + clickedName + "' loaded (" + applied + " settings applied).", 8, Brushes.Goldenrod);
				_activeProfileName = clickedName;
				_profileDirty = false;
				InvalidateVis(135);
			}
			catch (Exception ex) { AddMessage("Error loading profile: " + ex.Message, 10, Brushes.Red); }
		}

		// ---------------------------------------------------------------------
		// accounts.xml — machine-local account state, separate from profile XML.
		// Owns: master account, hidden-account list, Selected*Account names.
		// Read once in State.DataLoaded; written on every mutation of those
		// fields. Selected*Time DateTimes are NOT persisted (transient UI
		// timestamps) — they always start at DateTime.MinValue after restart.
		// ---------------------------------------------------------------------
		private void LoadAccountsXml()
		{
			try
			{
				if (string.IsNullOrEmpty(_profilesDir)) return;
				_accountsXmlPath = System.IO.Path.Combine(_profilesDir, "accounts.xml");
				_accountsXmlExisted = System.IO.File.Exists(_accountsXmlPath);
				if (!_accountsXmlExisted)
				{
					// First run after upgrade: leave AllHideAccounts empty for
					// now. InitializeAccountConfigs will populate it from the
					// legacy AllAccountData[5] flag, then a SaveAccountsXml call
					// at the end of State.DataLoaded captures the migration.
					_accountsXmlLoaded = true;
					return;
				}
				System.Xml.Linq.XDocument doc = System.Xml.Linq.XDocument.Load(_accountsXmlPath);
				System.Xml.Linq.XElement root = doc.Root;
				if (root == null) { _accountsXmlLoaded = true; return; }

				// Per-tab master fix: only seed pThisMasterAccount from the
				// shared accounts.xml if this instance has no master yet
				// (workspace deserialization runs before DataLoaded, so a
				// non-empty value here means this tab already had its own
				// master persisted in workspace XML — don't clobber it).
				System.Xml.Linq.XElement em = root.Element("MasterAccount");
				if (em != null && string.IsNullOrEmpty(pThisMasterAccount))
				{
					string seeded = em.Value ?? "";
					if (_diagLog != null)
						_diagLog.Log("MASTER", "XML_SEED", "Master=" + seeded);
					pThisMasterAccount = seeded;
				}
				else if (em != null && _diagLog != null)
				{
					_diagLog.Log("MASTER", "XML_SKIP", "FileMaster=" + (em.Value ?? "") + "|InMemMaster=" + pThisMasterAccount);
				}

				AllHideAccounts.Clear();
				System.Xml.Linq.XElement eh = root.Element("HideAccounts");
				if (eh != null)
				{
					foreach (System.Xml.Linq.XElement xa in eh.Elements("Account"))
					{
						string nm = xa.Value;
						if (!string.IsNullOrEmpty(nm) && !AllHideAccounts.Contains(nm))
							AllHideAccounts.Add(nm);
					}
				}

				System.Xml.Linq.XElement eatm = root.Element("SelectedATM");
				if (eatm != null) SelectedATMAccount = eatm.Value ?? string.Empty;
				System.Xml.Linq.XElement emul = root.Element("SelectedMultiplier");
				if (emul != null) SelectedMultiplierAccount = emul.Value ?? string.Empty;
				System.Xml.Linq.XElement edg = root.Element("SelectedDailyGoal");
				if (edg != null) SelectedDailyGoalAccount = edg.Value ?? string.Empty;
				System.Xml.Linq.XElement edl = root.Element("SelectedDailyLoss");
				if (edl != null) SelectedDailyLossAccount = edl.Value ?? string.Empty;
				System.Xml.Linq.XElement epa = root.Element("SelectedPayout");
				if (epa != null) SelectedPayoutAccount = epa.Value ?? string.Empty;

				// Timestamps stay at DateTime.MinValue — selections are remembered
				// but considered stale (no active-selection highlight on restart).

				if (_diagLog != null)
					_diagLog.Log("CONFIG", "ACCOUNTS_XML_LOAD", "Master=" + pThisMasterAccount + "|Hidden=" + AllHideAccounts.Count);
				_accountsXmlLoaded = true;
			}
			catch (Exception ex)
			{
				if (_diagLog != null) _diagLog.Log("CONFIG", "ACCOUNTS_XML_LOAD_ERR", ex.Message);
				_accountsXmlLoaded = true;
			}
		}

		// Off-thread, coalesced XML writes so rapid-fire hide-account clicks
		// (and other state mutations) don't each block the UI thread on a
		// synchronous disk write. The XDocument is built on the calling thread
		// from current state and stashed as "pending"; a single background
		// worker drains it. If a newer doc arrives mid-write, the worker loops
		// and saves the newest snapshot — earlier intermediate snapshots are
		// dropped, which is fine because each is a full state dump.
		private readonly object _accountsXmlSaveLock = new object();
		private System.Xml.Linq.XDocument _accountsXmlPending = null;
		private bool _accountsXmlWorkerRunning = false;

		private void SaveAccountsXml()
		{
			// Skip writes until the initial load has run, so a mutation during
			// State.SetDefaults / State.Configure (before _profilesDir is even
			// set up) doesn't write an empty/partial file over real data.
			if (!_accountsXmlLoaded) return;
			if (string.IsNullOrEmpty(_accountsXmlPath)) return;

			System.Xml.Linq.XDocument doc;
			try
			{
				System.Xml.Linq.XElement hideEl = new System.Xml.Linq.XElement("HideAccounts");
				if (AllHideAccounts != null)
				{
					foreach (string nm in AllHideAccounts)
						if (!string.IsNullOrEmpty(nm))
							hideEl.Add(new System.Xml.Linq.XElement("Account", nm));
				}

				doc = new System.Xml.Linq.XDocument(
					new System.Xml.Linq.XElement("AccountsState",
						new System.Xml.Linq.XElement("MasterAccount", pThisMasterAccount ?? ""),
						hideEl,
						new System.Xml.Linq.XElement("SelectedATM", SelectedATMAccount ?? ""),
						new System.Xml.Linq.XElement("SelectedMultiplier", SelectedMultiplierAccount ?? ""),
						new System.Xml.Linq.XElement("SelectedDailyGoal", SelectedDailyGoalAccount ?? ""),
						new System.Xml.Linq.XElement("SelectedDailyLoss", SelectedDailyLossAccount ?? ""),
						new System.Xml.Linq.XElement("SelectedPayout", SelectedPayoutAccount ?? "")
					));
			}
			catch (Exception ex)
			{
				if (_diagLog != null) _diagLog.Log("CONFIG", "ACCOUNTS_XML_BUILD_ERR", ex.Message);
				return;
			}

			string path = _accountsXmlPath;
			bool startWorker = false;
			lock (_accountsXmlSaveLock)
			{
				_accountsXmlPending = doc;
				if (!_accountsXmlWorkerRunning)
				{
					_accountsXmlWorkerRunning = true;
					startWorker = true;
				}
			}
			if (!startWorker) return;

			System.Threading.Tasks.Task.Run(() =>
			{
				while (true)
				{
					System.Xml.Linq.XDocument toSave;
					lock (_accountsXmlSaveLock)
					{
						toSave = _accountsXmlPending;
						_accountsXmlPending = null;
						if (toSave == null)
						{
							_accountsXmlWorkerRunning = false;
							return;
						}
					}
					try { toSave.Save(path); }
					catch (Exception ex)
					{
						if (_diagLog != null) _diagLog.Log("CONFIG", "ACCOUNTS_XML_SAVE_ERR", ex.Message);
					}
				}
			});
		}

		// Reset helpers exposed via the "Manage Account State" submenu.
		private void ResetHiddenAccounts()
		{
			AllHideAccounts.Clear();
			// Mirror the in-memory hide flag back to the workspace-persisted
			// AllAccountData rows so the dashboard re-render picks it up.
			if (pAllAccountData != null)
			{
				for (int i = 0; i < pAllAccountData.Length; i++)
				{
					string s = pAllAccountData[i];
					if (string.IsNullOrEmpty(s)) continue;
					string[] parts = s.Split('|');
					if (parts.Length > 5 && parts[5] == "Yes")
					{
						parts[5] = "No";
						pAllAccountData[i] = string.Join("|", parts);
					}
				}
			}
			SaveAccountsXml();
			InvalidateVis(136);
		}

		private void ResetAccountSelections()
		{
			SelectedATMAccount = string.Empty;
			SelectedATMTime = DateTime.MinValue;
			SelectedMultiplierAccount = string.Empty;
			SelectedMultiplerTime = DateTime.MinValue;
			SelectedDailyGoalAccount = string.Empty;
			SelectedDailyGoalTime = DateTime.MinValue;
			SelectedDailyLossAccount = string.Empty;
			SelectedDailyLossTime = DateTime.MinValue;
			SelectedPayoutAccount = string.Empty;
			SelectedPayoutTime = DateTime.MinValue;
			SaveAccountsXml();
			InvalidateVis(137);
		}

		// Record a PnL cell change so the render loop flashes it briefly. First call
		// for a given (account, column) pair just establishes the baseline (no flash).
		private void SortDashboardByDouble(Func<PNLStatistics, double> key, bool asc, bool forceTop)
		{
			SortedList2.Sort((a, b) =>
			{
				int c = forceTop
					? string.Compare(a.AudioStatus, b.AudioStatus, StringComparison.Ordinal)
					: string.Compare(a.MasterStatus, b.MasterStatus, StringComparison.Ordinal);
				if (c != 0) return c;
				c = key(a).CompareTo(key(b));
				if (!asc) c = -c;
				if (c != 0) return c;
				if (!forceTop)
					c = string.Compare(a.PrivateName, b.PrivateName, StringComparison.Ordinal);
				return c;
			});
		}

		private void SortDashboardByName(bool asc, bool forceTop)
		{
			SortedList2.Sort((a, b) =>
			{
				int c = forceTop
					? string.Compare(a.AudioStatus, b.AudioStatus, StringComparison.Ordinal)
					: string.Compare(a.MasterStatus, b.MasterStatus, StringComparison.Ordinal);
				if (c != 0) return c;
				c = string.Compare(a.PrivateName, b.PrivateName, StringComparison.Ordinal);
				if (!asc) c = -c;
				return c;
			});
		}

		// Subsequent calls with a different value trigger a CellFlashDurationMs-long
		// flash in the appropriate direction (up = green, down = red). Values within
		// 0.0001 are treated as unchanged to swallow float noise.
		private void RegisterCellFlash(string accountName, string columnName, double newValue)
		{
			if (string.IsNullOrEmpty(accountName) || string.IsNullOrEmpty(columnName)) return;
			Dictionary<string, double> acctLast;
			if (!_cellLastValue.TryGetValue(accountName, out acctLast))
			{
				acctLast = new Dictionary<string, double>(4);
				_cellLastValue[accountName] = acctLast;
			}
			double prev;
			if (acctLast.TryGetValue(columnName, out prev))
			{
				if (Math.Abs(newValue - prev) > 0.0001)
				{
					Dictionary<string, DateTime> acctEnd;
					if (!_cellFlashEnd.TryGetValue(accountName, out acctEnd))
					{
						acctEnd = new Dictionary<string, DateTime>(4);
						_cellFlashEnd[accountName] = acctEnd;
					}
					Dictionary<string, bool> acctUp;
					if (!_cellFlashUp.TryGetValue(accountName, out acctUp))
					{
						acctUp = new Dictionary<string, bool>(4);
						_cellFlashUp[accountName] = acctUp;
					}
					acctEnd[columnName] = DateTime.Now.AddMilliseconds(CellFlashDurationMs);
					acctUp[columnName]  = newValue > prev;
				}
			}
			acctLast[columnName] = newValue;
		}

