				pSavedScrollPosition = Math.Max(0, value);
				// NT8 calls this during workspace load before TotalAccounts is populated,
				// so defer the actual scroll until the table has rows.
				_pendingScrollRestoreValue = pSavedScrollPosition;
				_pendingScrollRestore      = true;
			}
		}

