		// Serialized column width overrides — keyed by COLUMN NAME (not logical index)
		// because logical indexes can shift when the user toggles columns on/off,
		// but column names are stable. Format: "Account:120|Cash Value:140|..."
		// Uses [Display] with GroupName="Hidden" because [Browsable(false)] alone
		// doesn't get serialized by NinjaTrader.
		private string pColumnWidthOverrides = "";
        [Display(ResourceType = typeof(Custom.Resource), Name = "Column Width Overrides", GroupName = "Hidden", Order = -100)]
		public string ColumnWidthOverrides_Saved
		{
			get { return pColumnWidthOverrides; }
			set
			{
				pColumnWidthOverrides = value ?? "";
				try
				{
					_pendingColumnWidthOverridesByName.Clear();
					if (!string.IsNullOrEmpty(pColumnWidthOverrides))
					{
						string[] entries = pColumnWidthOverrides.Split('|');
						foreach (string entry in entries)
						{
							int colonIdx = entry.LastIndexOf(':');
							if (colonIdx <= 0 || colonIdx >= entry.Length - 1) continue;
							string name = entry.Substring(0, colonIdx);
							int width;
							if (int.TryParse(entry.Substring(colonIdx + 1), out width) && width > 0)
								_pendingColumnWidthOverridesByName[name] = width;
						}
					}
					_columnWidthOverridesNeedApply = _pendingColumnWidthOverridesByName.Count > 0;
				}
				catch { }
			}
		}

		private bool _columnWidthOverridesNeedApply = false;
		// Pending overrides keyed by name, applied once ColumnNumberToName is populated
		private Dictionary<string, int> _pendingColumnWidthOverridesByName = new Dictionary<string, int>();

		// Immediately writes the current ColumnWidthOverrides dictionary to the backing field
		// pColumnWidthOverrides so the next workspace serialization picks up the latest values.
		// Called on every resize drag tick and on mouse up.
		private void SerializeColumnWidthOverridesNow()
		{
			try
			{
				if (ColumnWidthOverrides == null || ColumnWidthOverrides.Count == 0)
				{
					pColumnWidthOverrides = "";
					return;
				}
				var parts = new List<string>();
				foreach (var kvp in ColumnWidthOverrides)
				{
					string colName;
					if (ColumnNumberToName != null && ColumnNumberToName.TryGetValue(kvp.Key, out colName) && !string.IsNullOrEmpty(colName))
						parts.Add(colName + ":" + kvp.Value);
				}
				pColumnWidthOverrides = string.Join("|", parts);
			}
			catch { }
		}
		
		// Hidden auto-group prefixes persisted across sessions. Uses GroupName="Hidden"
		// (same pattern as ColumnWidthOverrides_Saved) because NT won't serialize
		// [Browsable(false)] alone. Format: "PREFIX1|PREFIX2|..."
		private string pHiddenGroupsCSV = "";
        [Display(ResourceType = typeof(Custom.Resource), Name = "Hidden Groups", GroupName = "Hidden", Order = -100)]
		public string HiddenGroups_Saved
		{
			get { return pHiddenGroupsCSV; }
			set
			{
				pHiddenGroupsCSV = value ?? "";
				hiddenAutoGroups.Clear();
				if (!string.IsNullOrEmpty(pHiddenGroupsCSV))
				{
					foreach (string s in pHiddenGroupsCSV.Split('|'))
						if (!string.IsNullOrEmpty(s)) hiddenAutoGroups.Add(s);
				}
				// Invalidate any auto-group state computed before the persisted
				// hidden set was loaded — without this, the first OnRender right
				// after workspace restore can briefly show the rows that should
				// be hidden. Cleared arrays cause the render to skip total rows
				// until the next GetAllPerformanceStats rebuilds them correctly.
				autoGroupPrefixes = new string[0];
				autoGroupGhost = new bool[0];
				lastAutoGroupPrefixes = new string[0];
			}
		}

		// Sync the HashSet back to the backing string so the next workspace save picks up changes.
		private void SerializeHiddenGroupsNow()
		{
			pHiddenGroupsCSV = string.Join("|", hiddenAutoGroups);
		}

