		private string pThisMasterAccount = "";

		[Display(ResourceType = typeof(Custom.Resource), GroupName = "License", Name = "Email Address", Order = 54, Description = "")]
        public string ThisMasterAccount
        {
            get { return pThisMasterAccount; }
            set
            {
                if (pThisMasterAccount != value)
                {
                    if (_diagLog != null)
                    {
                        try
                        {
                            _diagLog.Log("MASTER", "PROPERTY_SET",
                                "Old=" + (pThisMasterAccount ?? "") +
                                "|New=" + (value ?? "") +
                                "|State=" + State +
                                "|Stack=" + (Environment.StackTrace ?? "").Replace("\r", " ").Replace("\n", " ; "));
                        }
                        catch { }
                    }
                }
                pThisMasterAccount = value;
            }
        }	
		
		
		
		
		
