		// Persisted snapshot of the last auto-assigned Total Row prefixes.
		// Without this, lastAutoGroupPrefixes starts empty on every reload, which
		// makes firstAutoRun==true in the auto-naming pass and clobbers any user
		// rename of TotalRow1/2/3/...
		// Note: cannot use [Browsable(false)] — NT won't serialize that alone.
		// Same Display+GroupName="Hidden" pattern as HiddenGroups_Saved.
		// Stored in its own field (NOT lastAutoGroupPrefixes) because the
		// HiddenGroups_Saved setter zeros lastAutoGroupPrefixes during workspace
		// restore.
		private string pPriorAutoGroupSnapshot = "";
		// Same Display+GroupName="Hidden" pattern as HiddenGroups_Saved so NT
		// serializes it. Hidden from the Inputs grid by being added to
		// DeleteThese (Browsable(false) alone is not serialized).
		[Display(ResourceType = typeof(Custom.Resource), Name = "Prior Auto Groups", GroupName = "Hidden", Order = -99)]
		public string PriorAutoGroupSnapshot_Saved
		{
			get { return pPriorAutoGroupSnapshot ?? ""; }
			set { pPriorAutoGroupSnapshot = value ?? ""; }
		}

		// Per-prefix user rename map for auto-group total rows. Keys are the
		// auto-group prefix (e.g. "APEX"); values are the user's custom name.
		// Keyed by prefix (not slot) so that adding/removing accounts — which
		// reshuffles which prefix lands in which slot — never mis-applies a
		// rename to the wrong group. Format: "PREFIX1=NAME1|PREFIX2=NAME2|..."
		private string pTotalRowRenameMap = "";
		[Display(ResourceType = typeof(Custom.Resource), Name = "Total Row Renames", GroupName = "Hidden", Order = -98)]
		public string TotalRowRenameMap_Saved
		{
			get { return pTotalRowRenameMap ?? ""; }
			set { pTotalRowRenameMap = value ?? ""; ParseTotalRowRenameMap(); }
		}

		private Dictionary<string, string> _totalRowRenames = new Dictionary<string, string>(StringComparer.Ordinal);
		private bool _totalRowRenameMigrationDone = false;

		private void ParseTotalRowRenameMap()
		{
			_totalRowRenames.Clear();
			if (string.IsNullOrEmpty(pTotalRowRenameMap)) return;
			foreach (string entry in pTotalRowRenameMap.Split('|'))
			{
				int eq = entry.IndexOf('=');
				if (eq <= 0) continue;
				string k = entry.Substring(0, eq);
				string v = entry.Substring(eq + 1);
				if (!string.IsNullOrEmpty(k)) _totalRowRenames[k] = v;
			}
		}

		private void SerializeTotalRowRenameMap()
		{
			StringBuilder sb = new StringBuilder();
			foreach (KeyValuePair<string, string> kvp in _totalRowRenames)
			{
				if (sb.Length > 0) sb.Append('|');
				sb.Append(kvp.Key);
				sb.Append('=');
				sb.Append(kvp.Value);
			}
			pTotalRowRenameMap = sb.ToString();
		}

		// Look up the user's custom name for a prefix; fall back to the prefix itself.
		private string ResolveAutoSlotName(string prefix)
		{
			if (string.IsNullOrEmpty(prefix)) return "";
			string renamed;
			if (_totalRowRenames.TryGetValue(prefix, out renamed) && !string.IsNullOrEmpty(renamed))
				return renamed;
			return prefix;
		}

		// One-time migration of pre-existing slot-based renames into the per-prefix
		// map. Pairs the prior auto-prefix snapshot with the current pTotalNName values
		// — if a slot's name doesn't equal its prior prefix, treat it as a rename.
		private void MigrateLegacyTotalRowRenamesIfNeeded()
		{
			if (_totalRowRenameMigrationDone) return;
			_totalRowRenameMigrationDone = true;
			if (string.IsNullOrEmpty(pPriorAutoGroupSnapshot)) return;
			string[] snap = pPriorAutoGroupSnapshot.Split(';');
			string[] curNames = { pTotal1Name, pTotal2Name, pTotal3Name, pTotal5Name, pTotal6Name,
								  pTotal7Name, pTotal8Name, pTotal9Name, pTotal10Name, pTotal11Name,
								  pTotal12Name, pTotal13Name };
			bool dirty = false;
			for (int i = 0; i < Math.Min(snap.Length, curNames.Length); i++)
			{
				if (string.IsNullOrEmpty(snap[i]) || string.IsNullOrEmpty(curNames[i])) continue;
				if (curNames[i] != snap[i] && !_totalRowRenames.ContainsKey(snap[i]))
				{
					_totalRowRenames[snap[i]] = curNames[i];
					dirty = true;
				}
			}
			if (dirty) SerializeTotalRowRenameMap();
		}

		// Writes a resolved name to both the backing field and the runtime display field
		// for a given slot so renames are visible on the next render frame.
		private void ApplyResolvedSlotName(int slot, string name)
		{
			switch (slot)
			{
				case 0:  pTotal1Name  = name; Total1Name  = name; break;
				case 1:  pTotal2Name  = name; Total2Name  = name; break;
				case 2:  pTotal3Name  = name; Total3Name  = name; break;
				case 3:  pTotal5Name  = name; Total5Name  = name; break;
				case 4:  pTotal6Name  = name; Total6Name  = name; break;
				case 5:  pTotal7Name  = name; Total7Name  = name; break;
				case 6:  pTotal8Name  = name; Total8Name  = name; break;
				case 7:  pTotal9Name  = name; Total9Name  = name; break;
				case 8:  pTotal10Name = name; Total10Name = name; break;
				case 9:  pTotal11Name = name; Total11Name = name; break;
				case 10: pTotal12Name = name; Total12Name = name; break;
				case 11: pTotal13Name = name; Total13Name = name; break;
			}
		}
		
		
		
