private void SetupWindow()
{
    this.Caption = "Simple Input Window";
    this.Width = 330;
    this.Height = 375;  // Changed from 350 to 375 to accommodate new checkbox
    this.WindowStartupLocation = WindowStartupLocation.CenterScreen;
    this.ResizeMode = ResizeMode.NoResize;
    this.Topmost = true; 
    
    this.Loaded += (s, e) =>
    {
        this.Focus();
        textBox1.Focus();
    };
}

protected override void OnClosing(System.ComponentModel.CancelEventArgs e)
{
    e.Cancel = false; // Don't cancel the close
   // base.OnClosing(e);
}

private Color GetTextColor3(Brush bg2)
{
    Color bg = (bg2 as SolidColorBrush).Color;
    
    if (bg2.ToString() == "#00FFFFFF")
    {
        string skinname = NinjaTrader.Core.Globals.GeneralOptions.Skin.ToString();
        
        if (skinname == "NinjaTrader Dark" || skinname == "Dark" || skinname == "Slate Dark" || skinname == "Slate Gray")
        {
            return Color.FromRgb(220, 220, 220);
        }
        else
        {
            return Colors.Black;
        }
    }
    else
    {
        double a = 1 - (0.299 * bg.R + 0.587 * bg.G + 0.114 * bg.B) / 255;
        if (a < 0.5)
            return Colors.Black;
        else
            return Color.FromRgb(220, 220, 220);
    }
}



private Brush GetTextColor(Brush bg2)
{
    Color bg = (bg2 as SolidColorBrush).Color;
    
    if (bg2.ToString() == "#00FFFFFF")
    {
        string skinname = NinjaTrader.Core.Globals.GeneralOptions.Skin.ToString();
        
        if (skinname == "NinjaTrader Dark" || skinname == "Dark" || skinname == "Slate Dark" || skinname == "Slate Gray")
        {
           // return Brushes.WhiteSmoke;
			return new SolidColorBrush(Color.FromRgb(220, 220, 220));
        }
        else
        {
            return Brushes.Black;
        }
    }
    else
    {
        double a = 1 - (0.299 * bg.R + 0.587 * bg.G + 0.114 * bg.B) / 255;
        if (a < 0.5)
            return Brushes.Black;
        else
           // return Brushes.WhiteSmoke;
			return new SolidColorBrush(Color.FromRgb(220, 220, 220));
    }
}
		
		
		
private Brush GetThemeTextBrush()
{
    // Use transparent background to trigger skin detection
    return GetTextColor(Brushes.Transparent);
}

