private void CreateControls()
{
    // Get theme-aware colors
//    Brush textBrush = GetThemeTextBrush();
//    Brush backgroundBrush = GetThemeBackgroundBrush();
//    Brush borderBrush = GetThemeBorderBrush();
    
    Grid mainGrid = new Grid();
    mainGrid.Margin = new Thickness(0, 10, 0, 0);
    mainGrid.Background = Brushes.Transparent;  // Apply theme background
    this.Content = mainGrid;
    
    for (int i = 0; i < 12; i++)
    {
