private ComboBox CreateStyledComboBox()
{
    ComboBox comboBox = new ComboBox
    {
        Margin = new Thickness(5, 2, 5, 2),
        Height = 25,
        FontSize = 12,
        Padding = new Thickness(4, 3, 4, 2),
        VerticalContentAlignment = VerticalAlignment.Center,
       // Background = FrozenRgbBrush(51, 51, 55),
        //Foreground = Brushes.WhiteSmoke,
        //BorderBrush = FrozenRgbBrush(63, 63, 70),
        BorderThickness = new Thickness(1)
    };
    
    comboBox.Items.Add("Trailing");
    comboBox.Items.Add("End Of Day");
    comboBox.Items.Add("Static");
    comboBox.SelectedIndex = 0;
    
    // Trigger field changed event
    comboBox.SelectionChanged += (sender, e) =>
    {
        ComboBox cb = sender as ComboBox;
        if (cb != null && cb.SelectedItem != null)
        {
            OnFieldValueChanged(4, cb.SelectedItem.ToString());
        }
    };
    
    return comboBox;
}



public void SetFieldValue(int fieldNumber, string value)
{
    switch (fieldNumber)
    {
        case 1: // Daily Goal
            textBox1.Text = value ?? "";
            break;
        case 2: // Daily Loss
            textBox2.Text = value ?? "";
            break;
        case 3: // Max Decline
            textBox4.Text = value ?? "";
			if (value == "0")
				textBox4.Text = "";			
            break;
        case 4: // Drawdown Type (not applicable)
            SetDrawdownType(value);
            break;
        case 5: // (removed - was old Static checkbox)
            break;
        case 6: // Profit To Goal
            textBox5.Text = value ?? "";
			if (value == "0")
				textBox5.Text = "";
            break;
        case 7: // Account Size
            textBox6.Text = value ?? "";
            break;
        // case 8 is Funded checkbox, not a text field
    }
}



public void SetDrawdownType(string drawdownType)
{
    if (comboBoxDrawdownType == null) return;
    
    if (!string.IsNullOrEmpty(drawdownType))
    {
        // Try to find exact match
        for (int i = 0; i < comboBoxDrawdownType.Items.Count; i++)
        {
            if (comboBoxDrawdownType.Items[i].ToString() == drawdownType)
            {
                comboBoxDrawdownType.SelectedIndex = i;
                return;
            }
        }
    }
    
    // Default to Trailing if not found
    comboBoxDrawdownType.SelectedIndex = 0;
}



public void SetCheckBoxValue(int fieldNumber, bool value)
{
    switch (fieldNumber)
    {
        case 8: // Funded
            checkBox3.IsChecked = value;
            break;
    }
}



private Label CreateStatusLabel(int fieldNumber, bool isForCheckBox = false)
{
