    int topMargin = isForCheckBox ? 3 : 4;
    
    Label label = new Label
    {
        Content = "●",
        FontSize = 16,
        FontWeight = FontWeights.Bold,
        Width = 20,
        Height = 26,
        Padding = new Thickness(0, 0, 0, 8),
        Margin = new Thickness(5, topMargin, 0, 0),  // Changed left margin from 3 to 5 (2px closer)
        VerticalAlignment = VerticalAlignment.Center,
        HorizontalAlignment = HorizontalAlignment.Center,
        HorizontalContentAlignment = HorizontalAlignment.Center,
        VerticalContentAlignment = VerticalAlignment.Top,
        Cursor = Cursors.Hand,
        Visibility = Visibility.Visible,
        Foreground = Brushes.Transparent,
		Background = Brushes.Transparent  // Status labels use color-coded backgrounds	
    };
    
    label.MouseLeftButtonDown += (s, e) =>
    {
        StatusLabelClicked?.Invoke(this, new StatusLabelClickedEventArgs
        {
            FieldNumber = fieldNumber
        });
        e.Handled = true;
    };
    
    return label;
}

private void OnFieldValueChanged(int fieldNumber, string newValue)
{
    FieldValueChanged?.Invoke(this, new FieldValueChangedEventArgs
    {
        FieldNumber = fieldNumber,
        NewValue = newValue
    });
}


public void SetStatusLabel(int fieldNumber, bool isVisible, bool isGreen)
{
    Label statusLabel = GetStatusLabel(fieldNumber);
    if (statusLabel == null) return;
    
    // Set visibility first
    statusLabel.Visibility = isVisible ? Visibility.Visible : Visibility.Hidden;
    
    // Then set the color
    if (isVisible)
    {
        if (isGreen)
        {
            // Green checkmark
            statusLabel.Foreground = new SolidColorBrush(Color.FromRgb(0, 200, 0));
        }
        else
        {
            // Gray checkmark
            statusLabel.Foreground = new SolidColorBrush(Color.FromRgb(128, 128, 128));
        }
    }
}

public Label GetStatusLabel(int fieldNumber)
{
    switch (fieldNumber)
    {
        case 3: return statusLabel3; // Max Decline
        case 4: return statusLabel4; // Drawdown Type
        case 6: return statusLabel6; // Profit To Goal
        case 8: return statusLabel7; // Funded (changed from 7 to 8)
        default: return null;
    }
}



