private TextBox CreateStyledTextBox(int fieldNumber)  // Add fieldNumber parameter
{
    TextBox textBox = new TextBox 
    { 
        Margin = new Thickness(5, 2, 5, 2),
        Height = 25,
        FontSize = 12,
        Padding = new Thickness(4, 4, 4, 4),
        VerticalContentAlignment = VerticalAlignment.Center
    };
    
    textBox.PreviewTextInput += (sender, e) =>
    {
        TextBox tb = sender as TextBox;
        int caretIndex = tb.CaretIndex;
        string newText = tb.Text.Insert(caretIndex, e.Text);
        e.Handled = !IsValidInput(e.Text, newText, caretIndex);
    };
    
    textBox.TextChanged += (sender, e) =>
    {
        TextBox tb = sender as TextBox;
        if (tb != null && !IsValidNumber(tb.Text))
        {
            int caretPos = tb.CaretIndex;
            tb.Text = CleanNumericInput(tb.Text);
            tb.CaretIndex = Math.Min(caretPos, tb.Text.Length);
        }
        
        // Trigger field changed event
        OnFieldValueChanged(fieldNumber, tb.Text);
    };
    
    return textBox;
}


private bool IsValidInput(string input, string resultingText, int caretIndex)
{
    foreach (char c in input)
    {
        if (!char.IsDigit(c) && c != '.' && c != '-')
            return false;
    }
    
    // Allow minus only at the beginning
    if (input.Contains("-") && caretIndex != 0)
        return false;
    
    return true;
}

private bool IsValidNumber(string text)
{
    if (string.IsNullOrEmpty(text))
        return true;
    
    if (text == "-" || text == ".")
        return true;
        
    decimal result;
    return decimal.TryParse(text, out result);
}

private string CleanNumericInput(string input)
{
    if (string.IsNullOrEmpty(input))
        return "";
    
    string cleaned = "";
    bool hasDecimal = false;
    bool hasMinus = false;
    
    for (int i = 0; i < input.Length; i++)
    {
        char c = input[i];
        
        if (char.IsDigit(c))
        {
            cleaned += c;
        }
        else if (c == '.' && !hasDecimal)
        {
            cleaned += c;
            hasDecimal = true;
        }
        else if (c == '-' && !hasMinus && i == 0)
        {
            cleaned += c;
            hasMinus = true;
        }
    }
    
    return cleaned;
}

private CheckBox CreateStyledCheckBox(int fieldNumber)  // Add fieldNumber parameter
{
    CheckBox checkBox = new CheckBox 
    { 
        Margin = new Thickness(5, 2, 5, 2),
        VerticalAlignment = VerticalAlignment.Center,
        FontSize = 12
    };
    
    // Trigger field changed event
    checkBox.Checked += (sender, e) =>
    {
        OnFieldValueChanged(fieldNumber, "True");
    };
    
    checkBox.Unchecked += (sender, e) =>
    {
        OnFieldValueChanged(fieldNumber, "False");
    };
    
    return checkBox;
}


		
