private void SetDefaultValues()
{
    checkBox3.IsChecked = false;
    comboBoxDrawdownType.SelectedIndex = 2;  // Default to "Trailing"
    textBox1.Text = "";
    textBox2.Text = "";
    textBox3.Text = "";
    textBox4.Text = "";
    textBox5.Text = "";
    textBox6.Text = "";
}

public void SetValues(bool check3Value, string drawdownType, string field1, string field2, string field3, string field4, string field5, string field6)
{
    checkBox3.IsChecked = check3Value;
    
    // Set drawdown type
    if (!string.IsNullOrEmpty(drawdownType))
    {
        int index = comboBoxDrawdownType.Items.IndexOf(drawdownType);
        if (index >= 0)
            comboBoxDrawdownType.SelectedIndex = index;
    }
    else
    {
        comboBoxDrawdownType.SelectedIndex = 0; // Default to Trailing
    }
    
    textBox1.Text = field1 ?? "";
    textBox2.Text = field2 ?? "";
    textBox3.Text = field3 ?? "";
    textBox4.Text = field4 ?? "";
    textBox5.Text = field5 ?? "";
    textBox6.Text = field6 ?? "";
}

private void OkButton_Click(object sender, RoutedEventArgs e)
{
    e.Handled = true;
    
    CheckBox3Value = checkBox3.IsChecked ?? false;
    DrawdownTypeValue = comboBoxDrawdownType.SelectedItem?.ToString() ?? "Trailing";
    Field1Value = textBox1.Text;
    Field2Value = textBox2.Text;
    Field3Value = textBox3.Text;
    Field4Value = textBox4.Text;
    Field5Value = textBox5.Text;
    Field6Value = textBox6.Text;
    
    DialogResult = true;
    
    try
    {
        this.DialogResult = true;
    }
    catch
    {
        this.Close();
    }
    
    Dispatcher.BeginInvoke(new Action(() =>
    {
        this.Close();
    }), System.Windows.Threading.DispatcherPriority.Background);
}


    private void CancelButton_Click(object sender, RoutedEventArgs e)
    {
	    e.Handled = true;
	    DialogResult = false;
	    
	    Dispatcher.BeginInvoke(new Action(() =>
	    {
	        this.Close();
	    }), System.Windows.Threading.DispatcherPriority.Background);
    }


public static SimplePopupWindow ShowPopup(string windowTitle = "Simple Input Window",
    bool check3Value = false, string drawdownType = "Trailing",
    string field1 = "", string field2 = "", string field3 = "", string field4 = "", string field5 = "", string field6 = "")
{
    SimplePopupWindow window = new SimplePopupWindow();
    window.Caption = windowTitle;
    window.SetValues(check3Value, drawdownType, field1, field2, field3, field4, field5, field6);
    
    try
    {
        window.Show();
    }
    catch
    {
        window.DialogResult = false;
    }
    
    return window;
}
	
	
	
	
	
	
