	public class aiDuplicateAccountActionsEmailEntryWindow : NTWindow, IWorkspacePersistence
	{
		public IndicatorBase selectedIndicator;
		public string EnteredEmail { get; private set; }
		public bool Confirmed { get; private set; }
		private TextBox _emailTextBox;

		public aiDuplicateAccountActionsEmailEntryWindow()
		{
			Caption = "Affordable Indicators - Enter Email Address";
			Width = 420;
			Height = 200;
			WindowStartupLocation = WindowStartupLocation.CenterScreen;
			Content = BuildContent();
			Loaded += OnWindowLoaded;
		}

		private void OnWindowLoaded(object sender, RoutedEventArgs e)
		{
			if (WorkspaceOptions == null)
				WorkspaceOptions = new WorkspaceOptions("aiDuplicateAccountActionsEmailEntryWindow" + Guid.NewGuid().ToString("N"), this);

			// Pre-fill with existing email (if any) so the user can correct it.
			if (_emailTextBox != null && selectedIndicator != null)
			{
				try
				{
					PropertyInfo pi = selectedIndicator.GetType().GetProperty("LicensingEmailAddress",
						BindingFlags.Public | BindingFlags.Instance);
					if (pi != null)
					{
						object v = pi.GetValue(selectedIndicator);
						if (v != null) _emailTextBox.Text = v.ToString();
					}
				}
				catch { }
				_emailTextBox.Focus();
				_emailTextBox.SelectAll();
			}
		}

		private UIElement BuildContent()
		{
			var root = new Grid { Margin = new Thickness(15) };
			root.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });
			root.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });
			root.RowDefinitions.Add(new RowDefinition { Height = new GridLength(1, GridUnitType.Star) });
			root.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });

			var label = new TextBlock
			{
				Text = "Please enter the 'Email Address' connected to your Affordable Indicators, Inc. website account:",
				TextWrapping = TextWrapping.Wrap,
				Margin = new Thickness(0, 0, 0, 10),
				Foreground = new System.Windows.Media.SolidColorBrush(System.Windows.Media.Color.FromRgb(0xCC, 0xCC, 0xCC))
			};
			Grid.SetRow(label, 0);
			root.Children.Add(label);

			_emailTextBox = new TextBox
			{
				MinHeight = 26,
				FontSize = 13,
				Padding = new Thickness(4, 2, 4, 2),
				Margin = new Thickness(0, 0, 0, 10)
			};
			_emailTextBox.KeyDown += (s, ea) =>
			{
				if (ea.Key == System.Windows.Input.Key.Enter)
				{
					ea.Handled = true;
					ConfirmAndClose();
				}
			};
			Grid.SetRow(_emailTextBox, 1);
			root.Children.Add(_emailTextBox);

			var buttonBar = new StackPanel
			{
				Orientation = Orientation.Horizontal,
				HorizontalAlignment = HorizontalAlignment.Right
			};

			var okBtn = new Button
			{
				Content = "OK",
				MinWidth = 86,
				MinHeight = 27,
				Margin = new Thickness(0),
				IsDefault = true
			};
			okBtn.Click += (s, ea) => ConfirmAndClose();
			buttonBar.Children.Add(okBtn);

			Grid.SetRow(buttonBar, 3);
			root.Children.Add(buttonBar);

			return root;
		}

		private void ConfirmAndClose()
		{
			Confirmed = true;
			EnteredEmail = _emailTextBox != null ? (_emailTextBox.Text ?? "").Trim() : "";

			if (selectedIndicator != null)
			{
				try
				{
					PropertyInfo pi = selectedIndicator.GetType().GetProperty("LicensingEmailAddress",
						BindingFlags.Public | BindingFlags.Instance);
					if (pi != null && pi.CanWrite)
						pi.SetValue(selectedIndicator, EnteredEmail);
				}
				catch { }
			}

			Close();
		}

		public void Restore(XDocument document, XElement element) { }
		public void Save(XDocument document, XElement element) { }
		public WorkspaceOptions WorkspaceOptions { get; set; }
	}

	public class aiDuplicateAccountActionsPropertyGridWindow : NTWindow, IWorkspacePersistence
	{
		public PropertyGrid propertyGrid;
		public IndicatorBase selectedIndicator;
		private Dictionary<string, object> _openValues = new Dictionary<string, object>();

		public aiDuplicateAccountActionsPropertyGridWindow()
		{
			Caption = "Accounts Dashboard Properties";
			Width = 600;
			Height = 800;
			WindowStartupLocation = WindowStartupLocation.CenterScreen;
			Content = BuildContent();
			Loaded += OnWindowLoaded;
		}

		private void OnWindowLoaded(object sender, RoutedEventArgs e)
		{
			if (WorkspaceOptions == null)
				WorkspaceOptions = new WorkspaceOptions("aiDuplicateAccountActionsPropertyGridWindow" + Guid.NewGuid().ToString("N"), this);

			if (selectedIndicator == null) return;

			propertyGrid.PropertyValueChanged += OnPropertyValueChanged;
			propertyGrid.SelectedObject = selectedIndicator;

			Action applyDefaults = () =>
			{
				foreach (CategoryItem ci in propertyGrid.Categories)
					ci.IsExpanded = !IsCategoryCollapsedByDefault(ci);
			};
			applyDefaults();
			Dispatcher.BeginInvoke(applyDefaults, System.Windows.Threading.DispatcherPriority.Loaded);

			CaptureSnapshot();
		}

		// CategoryItem doesn't expose a stable strongly-typed name property
		// across NT8 versions, so inspect common candidates via reflection.
		// Returns true if this category should start collapsed.
		private static bool IsCategoryCollapsedByDefault(CategoryItem ci)
		{
			if (ci == null) return false;
			string name = null;
			try
			{
				var t = ci.GetType();
				var pn = t.GetProperty("Name") ?? t.GetProperty("CategoryName")
					?? t.GetProperty("DisplayName") ?? t.GetProperty("Header");
				if (pn != null) name = pn.GetValue(ci) as string;
				if (string.IsNullOrEmpty(name)) name = ci.ToString();
			}
			catch { }
			return name == "Account Name Adjustments";
		}

		private static PropertyInfo SafeGetProperty(Type type, string name)
		{
			try { return type.GetProperty(name, BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly); }
			catch { }
			try { return type.GetProperty(name, BindingFlags.Public | BindingFlags.Instance); }
			catch { }
			return null;
		}

		private void CaptureSnapshot()
		{
			_openValues.Clear();
			if (selectedIndicator == null) return;
			var type = selectedIndicator.GetType();
			foreach (var pi in type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
			{
				if (!pi.CanRead || !pi.CanWrite) continue;
				if (pi.GetIndexParameters().Length > 0) continue;
				try { _openValues[pi.Name] = pi.GetValue(selectedIndicator); } catch { }
			}
		}

		private UIElement BuildContent()
		{
			var root = new Grid();
			root.RowDefinitions.Add(new RowDefinition { Height = new GridLength(1, GridUnitType.Star) });
			root.RowDefinitions.Add(new RowDefinition { Height = GridLength.Auto });

			// --- PropertyGrid in ScrollViewer ---
			propertyGrid = new PropertyGrid();

			var resetMenuItem = new MenuItem { Header = "Reset to Default" };
			resetMenuItem.Click += OnResetSelectedClick;
			var pgContextMenu = new ContextMenu();
			pgContextMenu.Items.Add(resetMenuItem);
			propertyGrid.ContextMenu = pgContextMenu;

			var scrollViewer = new ScrollViewer
			{
				Content = propertyGrid,
				HorizontalAlignment = HorizontalAlignment.Stretch,
				VerticalAlignment = VerticalAlignment.Stretch
			};
			Grid.SetRow(scrollViewer, 0);
			root.Children.Add(scrollViewer);

			// --- Bottom button bar (matches NT Indicators window) ---
			var separator = new Separator
			{
				Margin = new Thickness(0),
				Background = new SolidColorBrush(System.Windows.Media.Color.FromRgb(61, 61, 66)),
				Height = 1
			};

			var buttonBar = new StackPanel
			{
				Orientation = Orientation.Horizontal,
				HorizontalAlignment = HorizontalAlignment.Right,
				Margin = new Thickness(0, 21, 0, 0)
			};

			var cancelBtn = new Button
			{
				Content = "Cancel",
				MinWidth = 86,
				MinHeight = 27,
				Margin = new Thickness(0, 0, 7, 0),
				IsCancel = true
			};
			cancelBtn.Click += OnCancelClick;

			var closeBtn = new Button
			{
				Content = "OK",
				MinWidth = 86,
				MinHeight = 27,
				Margin = new Thickness(0),
				IsDefault = true
			};
			closeBtn.Click += (s, ea) => Close();

			buttonBar.Children.Add(cancelBtn);
			buttonBar.Children.Add(closeBtn);

			var bottomPanel = new StackPanel { Orientation = Orientation.Vertical };
			bottomPanel.Children.Add(separator);
			bottomPanel.Children.Add(buttonBar);

			Grid.SetRow(bottomPanel, 1);
			root.Children.Add(bottomPanel);

			return root;
		}

		private void OnPropertyValueChanged(object sender, RoutedEventArgs e)
		{
			if (selectedIndicator == null) return;
			MethodInfo mi = selectedIndicator.GetType().GetMethod("UpdateFromPropertyWindow",
				BindingFlags.Public | BindingFlags.Instance);
			if (mi != null) mi.Invoke(selectedIndicator, null);
		}

		private string GetSelectedPropertyName()
		{
			try
			{
				var selectedPropInfo = propertyGrid.GetType().GetProperty("SelectedProperty");
				if (selectedPropInfo == null) return null;
				var propItem = selectedPropInfo.GetValue(propertyGrid);
				if (propItem == null) return null;

				var pdProp = propItem.GetType().GetProperty("PropertyDescriptor");
				if (pdProp != null)
				{
					var pd = pdProp.GetValue(propItem) as PropertyDescriptor;
					if (pd != null) return pd.Name;
				}

				var nameProp = propItem.GetType().GetProperty("Name");
				if (nameProp != null) return nameProp.GetValue(propItem) as string;
			}
			catch { }
			return null;
		}

		private void OnResetSelectedClick(object sender, RoutedEventArgs e)
		{
			string propName = GetSelectedPropertyName();
			if (propName == null || !_openValues.ContainsKey(propName)) return;
			ResetProperty(propName);
		}

		private void ResetProperty(string name)
		{
			if (!_openValues.ContainsKey(name)) return;
			var pi = SafeGetProperty(selectedIndicator.GetType(), name);
			if (pi == null || !pi.CanWrite) return;
			try
			{
				pi.SetValue(selectedIndicator, _openValues[name]);
				RefreshGrid();
				OnPropertyValueChanged(null, null);
			}
			catch { }
		}

		private void OnResetAllClick(object sender, RoutedEventArgs e)
		{
			var type = selectedIndicator.GetType();
			foreach (var kvp in _openValues)
			{
				var pi = SafeGetProperty(type, kvp.Key);
				if (pi != null && pi.CanWrite)
				{
					try { pi.SetValue(selectedIndicator, kvp.Value); } catch { }
				}
			}
			RefreshGrid();
			OnPropertyValueChanged(null, null);
		}

		private void OnCancelClick(object sender, RoutedEventArgs e)
		{
			OnResetAllClick(null, null);
			Close();
		}

		private void RefreshGrid()
		{
			propertyGrid.SelectedObject = null;
			propertyGrid.SelectedObject = selectedIndicator;
			foreach (CategoryItem ci in propertyGrid.Categories)
				ci.IsExpanded = !IsCategoryCollapsedByDefault(ci);
		}

		public void Restore(XDocument document, XElement element)
		{
			if (MainTabControl != null) MainTabControl.RestoreFromXElement(element);
		}

		public void Save(XDocument document, XElement element)
		{
			if (MainTabControl != null) MainTabControl.SaveToXElement(element);
		}

		public WorkspaceOptions WorkspaceOptions { get; set; }
	}
}

